INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('67244743-0518-4779-a377-1a12a00e7a92', 'Which choice completes the text with the most logical and precise word or phrase?', 'Marine biologist Dr. Elena Ruiz studies how coral reefs recover after storms. She has found that some reefs bounce back quickly, while others take decades. In her latest paper, she argues that the speed of recovery depends largely on whether young coral can ______ the damaged areas. Reefs where new coral settles and grows rapidly tend to heal within just a few years.', NULL, '[{"id":"A","text":"recolonize","is_correct":true,"explanation":"Correct: the text says new coral must ''settle and grow'' in damaged areas, which is precisely recolonizing them."},{"id":"B","text":"abandon","is_correct":false,"explanation":"Reverse: abandoning damaged areas would prevent the recovery the text describes."},{"id":"C","text":"measure","is_correct":false,"explanation":"No evidence: the text is about coral settling and growing, not measuring areas."},{"id":"D","text":"photograph","is_correct":false,"explanation":"No evidence: nothing in the text involves photographing the reef."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text explains that fast-healing reefs are ones where {{yellow:new coral settles and grows rapidly}}.
Step 2 — Match the word
For young coral to settle and grow in damaged areas is to recolonize them, so ''recolonize'' fits precisely.
Distractor analysis:
- B: ''Abandon'' is the reverse of settling and growing, so it contradicts the clue.
- C: ''Measure'' has no support; the passage is about coral growth, not measurement.
- D: ''Photograph'' is unsupported and unrelated to coral settling.', 'Look at the next sentence: what do young coral do in areas that heal quickly?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6353aa1d-d641-4fb6-b5a5-d851a30e05a9', 'Which choice completes the text with the most logical and precise word or phrase?', 'When the young pianist walked onto the stage, the audience fell silent. Critics had praised her technical skill for years, but tonight she played with a new warmth that surprised everyone. The cold precision of her earlier performances was gone. Instead, every note seemed ______, as if she were speaking directly to each listener in the hall.', NULL, '[{"id":"A","text":"mechanical","is_correct":false,"explanation":"Reverse: ''mechanical'' matches the ''cold precision'' she had abandoned, not her new warmth."},{"id":"B","text":"heartfelt","is_correct":true,"explanation":"Correct: ''warmth'' and ''speaking directly to each listener'' point to emotionally sincere, heartfelt playing."},{"id":"C","text":"rushed","is_correct":false,"explanation":"No evidence: nothing suggests she played too fast."},{"id":"D","text":"quiet","is_correct":false,"explanation":"Too narrow: silence describes the audience, not the emotional quality of her notes."}]'::jsonb, 'B', 'Step 1 — Find the clue
The text says she now played with {{yellow:a new warmth that surprised everyone}} and that the cold precision was gone.
Step 2 — Match the word
Warmth that feels like speaking directly to listeners is heartfelt, sincere playing, so ''heartfelt'' fits.
Distractor analysis:
- A: ''Mechanical'' describes the cold precision she left behind, the opposite of warmth.
- C: ''Rushed'' has no support in the passage.
- D: ''Quiet'' describes the audience''s silence, not the emotional character of the notes.', 'Contrast it with the ''cold precision'' she used to have.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
