INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e6cba512-969a-4bef-b830-e6adde62ec8f', 'Which choice completes the text with the most logical and precise word or phrase?', 'During the long winter, the frontier settlers faced a serious shortage of food. Their stored grain was nearly gone, and hunting had become difficult in the deep snow. The town council decided to ______ the remaining supplies, giving each family only a small, measured portion each week so that the food would last until spring.', NULL, '[{"id":"A","text":"waste","is_correct":false,"explanation":"Reverse: wasting supplies contradicts the goal of making food last."},{"id":"B","text":"ration","is_correct":true,"explanation":"Correct: giving each family a small, measured weekly portion to make food last is rationing."},{"id":"C","text":"sell","is_correct":false,"explanation":"No evidence: the council distributes food to families, not sells it."},{"id":"D","text":"hide","is_correct":false,"explanation":"No evidence: the supplies are openly distributed, not concealed."}]'::jsonb, 'B', 'Step 1 — Find the clue
The text says the council gave {{yellow:each family only a small, measured portion each week}} so the food would last.
Step 2 — Match the word
Limiting people to small measured portions to stretch a scarce supply is the definition of rationing.
Distractor analysis:
- A: ''Waste'' is the reverse of making the food last.
- C: ''Sell'' has no support; the food is distributed to families.
- D: ''Hide'' is unsupported, since the portions are openly given out.', 'What word means giving out limited amounts so a supply lasts longer?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('60384366-7128-4a25-9432-2d208c4e9de0', 'Which choice completes the text with the most logical and precise word or phrase?', 'Astronomers once believed the universe was completely still. In the 1920s, however, Edwin Hubble noticed that distant galaxies were moving away from us. The farther away a galaxy was, the faster it seemed to be retreating. This observation suggested that the universe is not static at all but is steadily ______ in every direction.', NULL, '[{"id":"A","text":"expanding","is_correct":true,"explanation":"Correct: galaxies moving away from us in every direction means the universe is growing larger, or expanding."},{"id":"B","text":"shrinking","is_correct":false,"explanation":"Reverse: shrinking would mean galaxies moving closer, not away."},{"id":"C","text":"cooling","is_correct":false,"explanation":"No evidence: the passage describes motion, not temperature."},{"id":"D","text":"spinning","is_correct":false,"explanation":"No evidence: galaxies retreating outward is not the same as the universe spinning."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text states that {{yellow:distant galaxies were moving away from us}} and farther ones retreated faster.
Step 2 — Match the word
A universe in which everything moves apart in every direction is expanding, contradicting the old ''static'' view.
Distractor analysis:
- B: ''Shrinking'' reverses the clue; galaxies move away, not closer.
- C: ''Cooling'' has no support; the passage is about motion, not heat.
- D: ''Spinning'' is unsupported and does not match outward retreat.', 'If galaxies move away in every direction, the universe is getting what?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b0651fb7-b0e2-4de1-b32d-b01e0c56d848', 'Which choice completes the text with the most logical and precise word or phrase?', 'The new manager was known for being honest, but few people expected her to be so ______. In her first meeting, she told the team plainly that the company had lost money and that some projects would end. She did not soften the news or hide behind vague language. Her colleagues respected how openly she shared even difficult truths.', NULL, '[{"id":"A","text":"secretive","is_correct":false,"explanation":"Reverse: she shares difficult truths openly, the opposite of secretive."},{"id":"B","text":"cheerful","is_correct":false,"explanation":"No evidence: delivering bad news plainly is not about cheerfulness."},{"id":"C","text":"blunt","is_correct":true,"explanation":"Correct: telling the team plainly without softening or vague language is being blunt."},{"id":"D","text":"careless","is_correct":false,"explanation":"True-but-irrelevant trap: being direct is deliberate, not careless."}]'::jsonb, 'C', 'Step 1 — Find the clue
The text says she {{yellow:did not soften the news or hide behind vague language}} and told the team plainly.
Step 2 — Match the word
Delivering hard truths plainly and without softening is being blunt or direct.
Distractor analysis:
- A: ''Secretive'' reverses the clue; she shares truths openly.
- B: ''Cheerful'' is unsupported and clashes with delivering bad news.
- D: ''Careless'' wrongly implies carelessness, but her directness is intentional.', 'She told the team plainly and did not soften the news.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('970730ad-7291-4f8b-a851-1be11ce07239', 'As used in the text, the word "conserve" most nearly means to do what to energy? (Which choice completes the text with the most logical and precise word or phrase?)', 'Hummingbirds have an unusually fast metabolism, which means they must eat almost constantly. To survive cold nights when food is unavailable, they enter a state called torpor. During torpor, their heart rate and body temperature drop dramatically, allowing them to ______ energy until morning. By slowing their bodies down, they avoid starving overnight.', NULL, '[{"id":"A","text":"save","is_correct":true,"explanation":"Correct: slowing the body to avoid starving means saving energy until morning."},{"id":"B","text":"waste","is_correct":false,"explanation":"Reverse: wasting energy would cause starving, the opposite of the goal."},{"id":"C","text":"create","is_correct":false,"explanation":"No evidence: torpor reduces use of energy; it does not generate it."},{"id":"D","text":"release","is_correct":false,"explanation":"Reverse: releasing energy contradicts slowing the body down."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text says slowing their bodies lets them survive when food is unavailable and they {{yellow:avoid starving overnight}}.
Step 2 — Match the word
Reducing heart rate and temperature to avoid starving means saving energy, so ''save'' fits the blank.
Distractor analysis:
- B: ''Waste'' reverses the clue; wasting energy would lead to starving.
- C: ''Create'' is unsupported; torpor lowers energy use, not production.
- D: ''Release'' contradicts the idea of slowing the body to retain energy.', 'Slowing down to avoid starving means doing what with their limited energy?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d612a9d4-c598-43ce-b35e-4e77d9449705', 'Which choice completes the text with the most logical and precise word or phrase?', 'In ancient Rome, public speakers were trained to win over crowds. A skilled orator did not simply state facts; he chose his words to stir emotion and move people to action. The historian Tacitus admired one senator whose speeches were so ______ that even his opponents found themselves nodding in agreement before they realized it.', NULL, '[{"id":"A","text":"confusing","is_correct":false,"explanation":"Reverse: confusing speeches would not win nodding agreement."},{"id":"B","text":"persuasive","is_correct":true,"explanation":"Correct: speeches that make even opponents agree are highly persuasive."},{"id":"C","text":"brief","is_correct":false,"explanation":"No evidence: the text never mentions the length of the speeches."},{"id":"D","text":"quiet","is_correct":false,"explanation":"No evidence: volume is not discussed; the point is winning agreement."}]'::jsonb, 'B', 'Step 1 — Find the clue
The text says the senator''s speeches made {{yellow:even his opponents found themselves nodding in agreement}}.
Step 2 — Match the word
Convincing even your opponents to agree is the mark of persuasive speech.
Distractor analysis:
- A: ''Confusing'' reverses the clue; confusion would not produce agreement.
- C: ''Brief'' has no support; length is never mentioned.
- D: ''Quiet'' is unsupported; the passage is about effect, not volume.', 'Opponents agreeing shows the speeches were very what?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1713661e-563c-4521-93ac-ad5235c6137d', 'Which choice completes the text with the most logical and precise word or phrase?', 'Glaciers act like slow-moving rivers of ice. As they creep downhill over thousands of years, they carry rocks and grind against the land beneath them. This grinding can ______ deep valleys into solid mountain rock. Some of the world''s most dramatic landscapes, including wide U-shaped valleys, were shaped entirely by the steady pressure of moving ice.', NULL, '[{"id":"A","text":"carve","is_correct":true,"explanation":"Correct: grinding that shapes deep valleys into rock is carving them."},{"id":"B","text":"fill","is_correct":false,"explanation":"Reverse: the ice cuts valleys out, not fills them in."},{"id":"C","text":"paint","is_correct":false,"explanation":"No evidence: nothing involves coloring or painting the rock."},{"id":"D","text":"warm","is_correct":false,"explanation":"No evidence: temperature is not the cause discussed; grinding pressure is."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text says glaciers {{yellow:grind against the land beneath them}} and shaped wide U-shaped valleys.
Step 2 — Match the word
Grinding that shapes deep valleys into solid rock is carving them, so ''carve'' fits precisely.
Distractor analysis:
- B: ''Fill'' reverses the clue; the ice cuts valleys out, not in.
- C: ''Paint'' is unsupported and unrelated to grinding rock.
- D: ''Warm'' has no support; the cause is grinding pressure, not heat.', 'Grinding that forms deep valleys in rock does what to the rock?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b9642356-e228-447f-b494-215ff39d6bd7', 'Which choice completes the text with the most logical and precise word or phrase?', 'Although the small bookstore had survived for thirty years, the arrival of a giant online retailer threatened to end it. Sales dropped sharply, and the owner feared closing. But the community refused to let it die. Loyal customers organized events and spread the word, helping the beloved shop ______ a crisis that had ruined many similar stores.', NULL, '[{"id":"A","text":"cause","is_correct":false,"explanation":"Reverse: the crisis threatens the shop; the shop does not cause it."},{"id":"B","text":"ignore","is_correct":false,"explanation":"No evidence: the community actively responded rather than ignoring the threat."},{"id":"C","text":"survive","is_correct":true,"explanation":"Correct: community help let the shop get through a crisis that ruined others, meaning survive it."},{"id":"D","text":"begin","is_correct":false,"explanation":"No evidence: the crisis already exists; the shop does not start it."}]'::jsonb, 'C', 'Step 1 — Find the clue
The text says loyal customers helped the shop through a crisis {{yellow:that had ruined many similar stores}}.
Step 2 — Match the word
Getting through a crisis that destroyed other stores means surviving it, so ''survive'' fits.
Distractor analysis:
- A: ''Cause'' reverses the clue; the crisis threatens the shop, not the reverse.
- B: ''Ignore'' contradicts the community''s active response.
- D: ''Begin'' is unsupported; the crisis is already underway.', 'The shop got through a crisis that ruined other stores.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5c6249bd-92d2-4105-9db1-5efb479d46e9', 'Which choice completes the text with the most logical and precise word or phrase?', 'Bees communicate the location of flowers through a special movement called the waggle dance. By moving in a figure-eight pattern and shaking their bodies, a returning bee tells the others exactly where to find food. The direction and length of the dance ______ the angle and distance to the flowers, allowing the hive to gather nectar efficiently.', NULL, '[{"id":"A","text":"hide","is_correct":false,"explanation":"Reverse: the dance reveals information rather than hiding it."},{"id":"B","text":"indicate","is_correct":true,"explanation":"Correct: a dance that tells others where food is indicates the angle and distance."},{"id":"C","text":"taste","is_correct":false,"explanation":"No evidence: the dance conveys directions, not flavor."},{"id":"D","text":"delay","is_correct":false,"explanation":"No evidence: the dance speeds gathering; it does not cause delay."}]'::jsonb, 'B', 'Step 1 — Find the clue
The text says the bee {{yellow:tells the others exactly where to find food}}.
Step 2 — Match the word
If the dance tells others exactly where to go, its direction and length indicate the angle and distance.
Distractor analysis:
- A: ''Hide'' reverses the clue; the dance reveals, not conceals.
- C: ''Taste'' is unsupported and unrelated to direction.
- D: ''Delay'' contradicts the efficient gathering the dance enables.', 'The dance tells the other bees where the flowers are.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('054e72ac-d0c6-44f2-b1ae-28a16b107e80', 'As used in the text, the word "clear" most nearly means (which choice completes the text with the most logical and precise word or phrase?)', 'The river that runs through the city was once heavily polluted. For decades, factories dumped waste into the water, and fish nearly disappeared. After strict new laws were passed, however, the water slowly grew clean again. Today the river is so ______ that residents can see straight down to the smooth stones resting on the bottom.', NULL, '[{"id":"A","text":"transparent","is_correct":true,"explanation":"Correct: being able to see down to the bottom stones means the water is transparent."},{"id":"B","text":"obvious","is_correct":false,"explanation":"Wrong sense: ''clear'' here means see-through, not easy to understand."},{"id":"C","text":"loud","is_correct":false,"explanation":"No evidence: sound is not discussed in the passage."},{"id":"D","text":"muddy","is_correct":false,"explanation":"Reverse: muddy water would prevent seeing the bottom stones."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text says residents can {{yellow:see straight down to the smooth stones resting on the bottom}}.
Step 2 — Match the word
Water you can see all the way through to the bottom is transparent, the meaning of ''clear'' here.
Distractor analysis:
- B: ''Obvious'' uses a different sense of clear that does not fit visible water.
- C: ''Loud'' has no support; sound is never mentioned.
- D: ''Muddy'' reverses the clue, since muddy water hides the bottom.', 'Residents can see all the way to the stones on the bottom.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a194c915-1d22-42ca-b255-77543557506b', 'Which choice completes the text with the most logical and precise word or phrase?', 'The detective studied the case for weeks. At first, the many clues seemed to point in different directions, and nothing made sense. Then she noticed a single detail that tied everything together. Suddenly the confusing facts became ______, and she understood exactly how the crime had happened from start to finish.', NULL, '[{"id":"A","text":"coherent","is_correct":true,"explanation":"Correct: facts that suddenly fit together so she understands fully have become coherent."},{"id":"B","text":"scattered","is_correct":false,"explanation":"Reverse: scattered describes the earlier confusing state, not the new understanding."},{"id":"C","text":"missing","is_correct":false,"explanation":"No evidence: the facts are present and understood, not missing."},{"id":"D","text":"boring","is_correct":false,"explanation":"No evidence: the passage addresses clarity, not how interesting the facts are."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text says after one detail tied things together, she {{yellow:understood exactly how the crime had happened}}.
Step 2 — Match the word
Facts that now fit together into full understanding have become coherent, the opposite of confusing.
Distractor analysis:
- B: ''Scattered'' reverses the clue, describing the earlier confused state.
- C: ''Missing'' is unsupported; the facts are present and understood.
- D: ''Boring'' has no support; the passage is about clarity, not interest.', 'The once-confusing facts now fit together so she fully understood.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bf2e5c27-6da6-4556-a14c-bed2d816d81c', 'Which choice completes the text with the most logical and precise word or phrase?', 'In the novel, the young apprentice keeps her plans hidden from everyone in the village. She tells no one of her hopes to one day open her own bakery. Only her grandmother knows about her ______ ambition, kept quiet for fear that the other shopkeepers might laugh.', NULL, '[{"id":"A","text":"secret","is_correct":true,"explanation":"Correct: the text says she keeps her plans hidden and tells no one, which directly defines a secret ambition."},{"id":"B","text":"famous","is_correct":false,"explanation":"Incorrect: famous is the reverse of an ambition that is hidden and told to no one."},{"id":"C","text":"expensive","is_correct":false,"explanation":"Incorrect: cost is never mentioned; this introduces a quality with no support in the text."},{"id":"D","text":"shared","is_correct":false,"explanation":"Incorrect: she tells no one, so the ambition is not shared, contradicting the text."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text states she {{yellow:keeps her plans hidden from everyone in the village}} and tells no one of her hopes.
Step 2 — Match the word
An ambition kept hidden and told to no one is by definition a secret one.
Distractor analysis:
- B: ''famous'' reverses the meaning; the ambition is hidden, not widely known.
- C: ''expensive'' has no evidence; cost is never discussed.
- D: ''shared'' contradicts the statement that she tells no one.', 'Look at what she does with her plans: she keeps them hidden and tells no one.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('19d024c9-2886-4ceb-bdf6-0217a6763756', 'Which choice completes the text with the most logical and precise word or phrase?', 'Marine biologists studying the reef noticed that some fish change color when threatened. By shifting from bright orange to a dull gray, the fish blends into the rocky seafloor. This ability to ______ with the surroundings helps the fish avoid predators that hunt by sight.', NULL, '[{"id":"A","text":"blend in","is_correct":true,"explanation":"Correct: the text says the fish ''blends into the rocky seafloor,'' restating the same idea."},{"id":"B","text":"stand out","is_correct":false,"explanation":"Incorrect: standing out is the opposite of blending into the seafloor to avoid being seen."},{"id":"C","text":"swim faster","is_correct":false,"explanation":"Incorrect: speed is never mentioned; the passage is about color and hiding."},{"id":"D","text":"compete","is_correct":false,"explanation":"Incorrect: competition is not discussed; the fish is avoiding predators, not rivals."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text explains that by shifting to dull gray the fish {{yellow:blends into the rocky seafloor}}.
Step 2 — Match the word
The blank restates this idea, so ''blend in'' with the surroundings fits exactly.
Distractor analysis:
- B: ''stand out'' is the reverse; the fish is trying not to be seen.
- C: ''swim faster'' introduces speed, which the text never mentions.
- D: ''compete'' has no support; the threat is predators, not competitors.', 'The sentence before tells you the fish blends into the seafloor.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7977393f-c7a6-4fc3-9cdd-76dac5f1e7e2', 'Which choice completes the text with the most logical and precise word or phrase?', 'After the long drought, the harvest was far smaller than usual. With so little grain to sell, the farming families had very little money. The region''s once-busy markets grew quiet as the ______ farmers could no longer afford the goods they had bought freely in better years.', NULL, '[{"id":"A","text":"poor","is_correct":true,"explanation":"Correct: the text says the families ''had very little money,'' which defines being poor."},{"id":"B","text":"wealthy","is_correct":false,"explanation":"Incorrect: wealthy reverses the meaning; the families had very little money."},{"id":"C","text":"lazy","is_correct":false,"explanation":"Incorrect: there is no evidence of laziness; the cause is a drought, not effort."},{"id":"D","text":"famous","is_correct":false,"explanation":"Incorrect: fame is never mentioned and does not connect to affording goods."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text states that after the small harvest the families {{yellow:had very little money}} and could no longer afford goods.
Step 2 — Match the word
Having very little money and being unable to afford things describes farmers who are poor.
Distractor analysis:
- B: ''wealthy'' is the reverse of having very little money.
- C: ''lazy'' has no support; the cause is drought, not effort.
- D: ''famous'' is irrelevant to affording goods.', 'The farmers had very little money and could not afford goods.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
