INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('21d88fb7-c3be-4b65-9c57-ec82278291ed', 'Which choice completes the text with the most logical and precise word or phrase?', 'The desert traveler had walked for hours without water. By midday his lips had cracked and his throat felt dry as sand. When he finally reached the oasis, he drank deeply, for he was desperately ______ after the long, hot journey.', NULL, '[{"id":"A","text":"thirsty","is_correct":true,"explanation":"Correct: the text describes a dry throat and walking for hours without water, which means thirsty."},{"id":"B","text":"sleepy","is_correct":false,"explanation":"Incorrect: sleepiness is not described; the details are about lack of water."},{"id":"C","text":"bored","is_correct":false,"explanation":"Incorrect: boredom is unrelated to the dry throat and drinking deeply."},{"id":"D","text":"satisfied","is_correct":false,"explanation":"Incorrect: satisfied reverses the need that drives him to drink deeply."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text says he walked without water and his {{yellow:throat felt dry as sand}}, then drank deeply.
Step 2 — Match the word
A dry throat after hours without water and drinking deeply describes being thirsty.
Distractor analysis:
- B: ''sleepy'' has no support; the details concern water, not rest.
- C: ''bored'' is irrelevant to the physical thirst described.
- D: ''satisfied'' reverses his need to drink.', 'His throat was dry as sand and he had no water for hours.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2293ba2a-6975-416b-9a28-9f81c0ccc5a5', 'Which choice completes the text with the most logical and precise word or phrase?', 'Historians note that the ancient bridge has lasted more than two thousand years. Wars, floods, and earthquakes have struck the city, yet the stone arches still stand. Engineers admire how ______ the structure is, remaining solid while newer bridges nearby have crumbled and fallen.', NULL, '[{"id":"A","text":"durable","is_correct":true,"explanation":"Correct: the text says the bridge has lasted two thousand years and still stands, which means durable."},{"id":"B","text":"fragile","is_correct":false,"explanation":"Incorrect: fragile contradicts a bridge that survives wars, floods, and earthquakes."},{"id":"C","text":"modern","is_correct":false,"explanation":"Incorrect: the bridge is ancient, contrasted with newer bridges that fell."},{"id":"D","text":"colorful","is_correct":false,"explanation":"Incorrect: appearance is not discussed; the focus is on lasting through disasters."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text states the bridge has {{yellow:lasted more than two thousand years}} and still stands after disasters.
Step 2 — Match the word
A structure that lasts thousands of years through wars and quakes is durable.
Distractor analysis:
- B: ''fragile'' contradicts surviving so many disasters.
- C: ''modern'' is wrong; the bridge is ancient.
- D: ''colorful'' addresses appearance, which is never mentioned.', 'The bridge has lasted thousands of years and still stands.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7c5d20c1-5cbb-4c5c-a593-7204f8fdaa5e', 'Which choice completes the text with the most logical and precise word or phrase?', 'In the play, the merchant promises to pay back every coin he borrows. He keeps careful records and returns money exactly when he says he will. His neighbors trust him completely, describing him as an ______ man whose word can always be believed.', NULL, '[{"id":"A","text":"honest","is_correct":true,"explanation":"Correct: the text says his word can always be believed and he repays exactly, which means honest."},{"id":"B","text":"dishonest","is_correct":false,"explanation":"Incorrect: dishonest reverses the trust and reliable repayment described."},{"id":"C","text":"angry","is_correct":false,"explanation":"Incorrect: temper is not mentioned; the text is about trust and repayment."},{"id":"D","text":"wealthy","is_correct":false,"explanation":"Incorrect: wealth is not the point; neighbors trust his word, not his riches."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text says the merchant''s {{yellow:word can always be believed}} and he repays exactly as promised.
Step 2 — Match the word
A man whose word is always believed and who keeps his promises is honest.
Distractor analysis:
- B: ''dishonest'' reverses the meaning entirely.
- C: ''angry'' introduces a trait with no support.
- D: ''wealthy'' is irrelevant; trust comes from his word, not money.', 'His word can always be believed and he repays exactly.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
