INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f9389914-e884-452d-adb6-aedb8dbc13e3', 'Which choice completes the text with the most logical and precise word or phrase?', 'The science teacher wanted the room to be calm during the experiment. She asked the students to lower their voices and move slowly so nothing would spill. Soon the once-noisy classroom became ______, with everyone working silently and carefully at their stations.', NULL, '[{"id":"A","text":"quiet","is_correct":true,"explanation":"Correct: the text says everyone was ''working silently,'' which restates quiet."},{"id":"B","text":"loud","is_correct":false,"explanation":"Incorrect: loud contradicts students working silently after lowering their voices."},{"id":"C","text":"messy","is_correct":false,"explanation":"Incorrect: they moved carefully so nothing would spill, the opposite of messy."},{"id":"D","text":"crowded","is_correct":false,"explanation":"Incorrect: the number of people is not discussed; the change is about noise."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text describes everyone {{yellow:working silently and carefully at their stations}} after lowering their voices.
Step 2 — Match the word
A classroom where everyone works silently has become quiet.
Distractor analysis:
- B: ''loud'' contradicts the silent work described.
- C: ''messy'' is wrong; they worked carefully so nothing spilled.
- D: ''crowded'' addresses numbers, which the text never discusses.', 'Everyone was working silently after lowering their voices.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('27fcf504-ebe4-43ac-b0c0-c86a3c78462e', 'Which choice completes the text with the most logical and precise word or phrase?', 'The first explorers to map the river had no guides and no charts. No one had recorded these waters before, and the surrounding forest appeared on no map. Reaching this ______ territory, where no traveler had set foot, filled the team with both fear and wonder.', NULL, '[{"id":"A","text":"unexplored","is_correct":true,"explanation":"Correct: the text says no one had recorded these waters and no traveler had set foot there, meaning unexplored."},{"id":"B","text":"familiar","is_correct":false,"explanation":"Incorrect: familiar reverses a place where no traveler had ever been."},{"id":"C","text":"crowded","is_correct":false,"explanation":"Incorrect: no people are present; no traveler had set foot there."},{"id":"D","text":"ruined","is_correct":false,"explanation":"Incorrect: damage is not mentioned; the land is simply never visited before."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text states this is land {{yellow:where no traveler had set foot}} and appeared on no map.
Step 2 — Match the word
Territory no one had recorded or visited is unexplored.
Distractor analysis:
- B: ''familiar'' contradicts a place never visited.
- C: ''crowded'' is wrong; no traveler had been there.
- D: ''ruined'' adds damage with no support in the text.', 'No traveler had set foot there and it appeared on no map.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c1aa551b-b554-4376-bfe9-cf483df47c4e', 'Which choice completes the text with the most logical and precise word or phrase?', 'The young pianist practiced the same difficult passage every day for a year. Even when his fingers ached and progress felt slow, he refused to quit. His teacher praised his ______ effort, noting that he never gave up no matter how hard the piece became.', NULL, '[{"id":"A","text":"persistent","is_correct":true,"explanation":"Correct: the text says he ''never gave up'' and practiced every day, which means persistent."},{"id":"B","text":"careless","is_correct":false,"explanation":"Incorrect: careless contradicts daily practice and refusing to quit."},{"id":"C","text":"brief","is_correct":false,"explanation":"Incorrect: brief reverses the year of daily practice described."},{"id":"D","text":"selfish","is_correct":false,"explanation":"Incorrect: selfishness is not discussed; the praise is for not giving up."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text notes that the pianist {{yellow:never gave up no matter how hard the piece became}} and practiced every day.
Step 2 — Match the word
Effort that continues daily and never gives up is persistent.
Distractor analysis:
- B: ''careless'' contradicts steady, dedicated practice.
- C: ''brief'' reverses the year-long daily effort.
- D: ''selfish'' has no support in the text.', 'He never gave up and practiced the same passage every day for a year.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1227bcae-9e87-49af-b947-d440304a45a0', 'Which choice completes the text with the most logical and precise word or phrase?', 'After the storm, volunteers arrived to help the flooded neighborhood. They handed out food and blankets to strangers without asking for anything in return. Reporters described the workers as ______ people, willing to give their time and supplies freely to those in need.', NULL, '[{"id":"A","text":"generous","is_correct":true,"explanation":"Correct: the text says they gave food, blankets, time, and supplies freely without asking anything in return, which is generous."},{"id":"B","text":"greedy","is_correct":false,"explanation":"Incorrect: greedy reverses giving freely without asking for anything in return."},{"id":"C","text":"shy","is_correct":false,"explanation":"Incorrect: shyness is not described; the focus is on giving to strangers."},{"id":"D","text":"wealthy","is_correct":false,"explanation":"Incorrect: wealth is not stated; the volunteers are defined by what they give, not what they own."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text says volunteers gave food and blankets {{yellow:without asking for anything in return}} and gave their time and supplies freely.
Step 2 — Match the word
People who give freely without expecting anything back are generous.
Distractor analysis:
- B: ''greedy'' is the opposite of giving freely.
- C: ''shy'' has no support; they actively helped strangers.
- D: ''wealthy'' is unsupported; the text describes giving, not riches.', 'They gave time and supplies freely without asking for anything in return.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('95502cb5-30fe-4129-a50e-ebff28f13a7b', 'Which choice completes the text with the most logical and precise word or phrase?', 'The new bridge design had to support heavy trucks crossing all day long. Earlier models had bent and sagged under such loads, but this one held firm without bending an inch. Engineers reported that the beams were remarkably ______, easily bearing weights that had broken the old design.', NULL, '[{"id":"A","text":"strong","is_correct":true,"explanation":"Correct: the text says the beams held firm and bore heavy weights without bending, which means strong."},{"id":"B","text":"weak","is_correct":false,"explanation":"Incorrect: weak contradicts beams that held firm under loads that broke the old design."},{"id":"C","text":"cheap","is_correct":false,"explanation":"Incorrect: cost is not discussed; the point is bearing heavy weight."},{"id":"D","text":"narrow","is_correct":false,"explanation":"Incorrect: width is not mentioned; the beams are described by how much weight they bear."}]'::jsonb, 'A', 'Step 1 — Find the clue
The text says this design {{yellow:held firm without bending an inch}} and bore weights that broke the old one.
Step 2 — Match the word
Beams that hold firm and bear heavy loads without bending are strong.
Distractor analysis:
- B: ''weak'' contradicts holding firm under heavy loads.
- C: ''cheap'' addresses cost, which is never mentioned.
- D: ''narrow'' addresses width, not the load-bearing ability described.', 'The beams held firm and bore heavy weights without bending.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c252ed4e-f8dd-433b-99f2-b005326ac92c', 'Which choice completes the text with the most logical and precise word or phrase?', 'When the volcanic island first emerged from the sea, it was barren rock. Yet within a few decades, lichens and hardy grasses had colonized its slopes. These first arrivals were not delicate; they thrived precisely where richer plants would have withered, anchoring themselves in cracks and surviving on almost nothing. Botanists describe such species as ______ organisms, capable of establishing themselves in the most forbidding conditions.', NULL, '[{"id":"A","text":"pioneering","is_correct":true,"explanation":"Correct: the lichens and grasses were the first to colonize forbidding bare rock, matching the sense of being trailblazing organisms."},{"id":"B","text":"ornamental","is_correct":false,"explanation":"The passage stresses survival in harsh conditions, not decorative or aesthetic value."},{"id":"C","text":"parasitic","is_correct":false,"explanation":"The species survive on bare rock independently; nothing indicates they feed on a host."},{"id":"D","text":"endangered","is_correct":false,"explanation":"The text emphasizes that they thrive and spread, not that they are at risk of dying out."}]'::jsonb, 'A', 'Step 1 — Find the clue
The passage says these species were the {{yellow:first arrivals}} that colonized barren rock where richer plants would wither.
Step 2 — Match the word
Being the first to establish in forbidding conditions is exactly what "pioneering" means.
Distractor analysis:
- B: "Ornamental" suggests decoration, but the focus is hardiness and survival, not beauty.
- C: "Parasitic" implies feeding on a host, which the rock setting contradicts.
- D: "Endangered" reverses the meaning; the organisms thrive and spread.', 'What word describes organisms that are the first to settle a harsh, empty place?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('258f80de-a487-4ffa-ad97-7b96c9776fd7', 'Which choice completes the text with the most logical and precise word or phrase?', 'The senator''s reputation for honesty had taken years to build, but a single leaked memo nearly destroyed it overnight. To his supporters, the document seemed damning. Only later did investigators reveal that the memo had been altered before its release. With the forgery exposed, the senator''s standing was ______, and crowds that had jeered him weeks earlier now cheered.', NULL, '[{"id":"A","text":"restored","is_correct":true,"explanation":"Correct: with the forgery exposed and crowds cheering again, his standing returned to its former good state."},{"id":"B","text":"questioned","is_correct":false,"explanation":"His standing is no longer in doubt once the forgery is exposed and crowds cheer."},{"id":"C","text":"exaggerated","is_correct":false,"explanation":"Nothing suggests his reputation was overstated; it was wrongly damaged and then recovered."},{"id":"D","text":"abandoned","is_correct":false,"explanation":"This reverses the outcome; his standing recovers rather than being given up."}]'::jsonb, 'A', 'Step 1 — Find the clue
After the forgery was exposed, {{yellow:crowds that had jeered him weeks earlier now cheered}}.
Step 2 — Match the word
The reversal back to cheering shows his good standing was brought back, i.e., restored.
Distractor analysis:
- B: "Questioned" fits the moment of doubt, but that doubt ends once the forgery is revealed.
- C: "Exaggerated" has no support; the text never says his reputation was overblown.
- D: "Abandoned" contradicts the cheering crowds who return to his side.', 'After the lie is exposed and crowds cheer again, what happened to his reputation?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e1a766ec-6be4-41d8-b1c8-41454805153c', 'Which choice completes the text with the most logical and precise word or phrase?', 'Early mapmakers often filled unexplored regions with imaginative beasts and decorative flourishes. As surveying instruments improved, however, cartographers grew unwilling to draw what they could not verify. Blank spaces began to appear where dragons once roamed. This new ______ marked a shift in the profession: a mapmaker''s authority now rested on admitting the limits of knowledge rather than disguising them.', NULL, '[{"id":"A","text":"restraint","is_correct":true,"explanation":"Correct: refusing to draw the unverified and leaving blanks reflects deliberate self-restraint."},{"id":"B","text":"extravagance","is_correct":false,"explanation":"This describes the earlier decorative style the new mapmakers rejected."},{"id":"C","text":"carelessness","is_correct":false,"explanation":"Leaving honest blanks is a careful, disciplined choice, not negligence."},{"id":"D","text":"ambition","is_correct":false,"explanation":"The passage shows holding back, not striving for more; nothing signals heightened ambition."}]'::jsonb, 'A', 'Step 1 — Find the clue
Cartographers grew {{yellow:unwilling to draw what they could not verify}}, leaving blank spaces.
Step 2 — Match the word
Deliberately holding back from unverified embellishment is restraint.
Distractor analysis:
- B: "Extravagance" describes the old dragon-filled style they abandoned, the opposite.
- C: "Carelessness" misreads disciplined honesty as negligence.
- D: "Ambition" implies reaching for more, but the shift is toward limiting claims.', 'What quality is shown by refusing to draw what cannot be verified?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c4ef7b36-d4f0-4adf-85e6-65bb725aff1a', 'Which choice completes the text with the most logical and precise word or phrase?', 'In her later essays, the philosopher refused to settle questions she had once answered confidently. Where younger readers wanted firm conclusions, she offered carefully balanced doubts, weighing each position against its rivals without declaring a winner. Critics who craved certainty found this ______ frustrating; admirers, however, saw in her unwillingness to commit a deeper intellectual honesty.', NULL, '[{"id":"A","text":"tentativeness","is_correct":true,"explanation":"Correct: weighing positions without declaring a winner and refusing to commit is the essence of tentativeness."},{"id":"B","text":"dogmatism","is_correct":false,"explanation":"Dogmatism means rigid certainty, the opposite of her balanced, uncommitted doubts."},{"id":"C","text":"eloquence","is_correct":false,"explanation":"Her style of speaking is not at issue; the frustration concerns her refusal to conclude."},{"id":"D","text":"hostility","is_correct":false,"explanation":"Nothing indicates aggression; she is hesitant and balanced, not antagonistic."}]'::jsonb, 'A', 'Step 1 — Find the clue
She offered {{yellow:carefully balanced doubts, weighing each position against its rivals without declaring a winner}}.
Step 2 — Match the word
Refusing to commit to a conclusion is precisely tentativeness.
Distractor analysis:
- B: "Dogmatism" reverses the meaning; she avoids firm certainty entirely.
- C: "Eloquence" is true-but-irrelevant; the issue is her conclusions, not her phrasing.
- D: "Hostility" has no support; her doubts are balanced, not aggressive.', 'What word names her refusal to commit to firm conclusions?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5ba94485-6e71-42e2-9d07-03dd2b6f02be', 'Which choice completes the text with the most logical and precise word or phrase?', 'The new factory manager inherited a workforce demoralized by years of broken promises. Rather than issue sweeping declarations, he began with small, reliable acts: a repaired break room, a paycheck never late, a complaint actually answered. Workers who had learned to distrust management watched these gestures accumulate. Slowly, almost imperceptibly, their ______ toward him eroded, replaced by a cautious willingness to listen.', NULL, '[{"id":"A","text":"wariness","is_correct":true,"explanation":"Correct: workers who learned to distrust management felt wariness, which eroded as he proved reliable."},{"id":"B","text":"enthusiasm","is_correct":false,"explanation":"Enthusiasm eroding would contradict the move toward willingness to listen; they began distrustful."},{"id":"C","text":"loyalty","is_correct":false,"explanation":"Loyalty fits admirers, but these workers started out distrustful, not loyal."},{"id":"D","text":"indifference","is_correct":false,"explanation":"They were not unconcerned; they actively distrusted management, which is more than indifference."}]'::jsonb, 'A', 'Step 1 — Find the clue
These were workers who {{yellow:had learned to distrust management}}.
Step 2 — Match the word
The feeling that eroded as he proved reliable must be their distrust, i.e., wariness.
Distractor analysis:
- B: "Enthusiasm" reverses the situation; distrustful workers had no eagerness to lose.
- C: "Loyalty" contradicts their established distrust.
- D: "Indifference" understates active distrust, and indifference would not be replaced by willingness to listen.', 'Distrustful workers feel what, which then fades as the manager proves reliable?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4b80059f-feaa-412e-8047-bcb30327e90b', 'Which choice completes the text with the most logical and precise word or phrase?', 'The coral reef appears permanent, but its survival depends on a fragile partnership. Tiny algae live within the coral''s tissue, supplying food through photosynthesis; in return, the coral offers shelter. When ocean temperatures rise even slightly, the coral expels its algae, and both partners suffer. Marine biologists emphasize how ______ this relationship is, sustained only within a narrow band of conditions.', NULL, '[{"id":"A","text":"precarious","is_correct":true,"explanation":"Correct: sustained only within a narrow band of conditions and disrupted by slight warming describes a precarious balance."},{"id":"B","text":"abundant","is_correct":false,"explanation":"Abundance is unrelated; the point is fragility, not plenty."},{"id":"C","text":"adversarial","is_correct":false,"explanation":"The algae and coral cooperate; the relationship is mutualistic, not hostile."},{"id":"D","text":"permanent","is_correct":false,"explanation":"The text opens by noting the reef only appears permanent, then stresses its fragility."}]'::jsonb, 'A', 'Step 1 — Find the clue
The relationship is {{yellow:sustained only within a narrow band of conditions}} and collapses with slight warming.
Step 2 — Match the word
A bond easily upset and dependent on narrow conditions is precarious.
Distractor analysis:
- B: "Abundant" addresses quantity, not the fragility the passage describes.
- C: "Adversarial" contradicts the cooperative, mutually beneficial partnership.
- D: "Permanent" is the appearance the text explicitly undercuts.', 'A bond that survives only in a narrow range and breaks with slight change is what?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ecbd55ff-b554-4332-bf13-92bb2bd6e582', 'Which choice completes the text with the most logical and precise word or phrase?', 'The young composer was praised for melodies that seemed to arrive effortlessly. Few listeners knew how many discarded drafts preceded each finished piece, or how often she reworked a single phrase for weeks. The ease audiences heard was not a gift but an achievement; her apparent spontaneity ______ an exacting and laborious process hidden from view.', NULL, '[{"id":"A","text":"concealed","is_correct":true,"explanation":"Correct: the laborious process was hidden from view, so her apparent ease concealed it."},{"id":"B","text":"revealed","is_correct":false,"explanation":"Revealed reverses the meaning; the labor was hidden, not shown, by her apparent ease."},{"id":"C","text":"required","is_correct":false,"explanation":"The spontaneity did not demand the labor; it disguised labor that came beforehand."},{"id":"D","text":"replaced","is_correct":false,"explanation":"The labor still occurred behind the scenes; it was not substituted away by the ease."}]'::jsonb, 'A', 'Step 1 — Find the clue
The exacting and laborious process was {{yellow:hidden from view}}.
Step 2 — Match the word
If the apparent ease kept that labor hidden, the ease concealed it.
Distractor analysis:
- B: "Revealed" contradicts "hidden from view."
- C: "Required" misstates the logic; the ease masks labor rather than demanding it.
- D: "Replaced" is wrong because the labor genuinely happened; it was disguised, not eliminated.', 'If the hard work was hidden from view, what did her apparent ease do to it?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7e434747-fb9f-4035-9783-f25007c31ebe', 'Which choice completes the text with the most logical and precise word or phrase?', 'Eighteenth-century etiquette manuals offered rules so detailed that they verged on the absurd, dictating the precise angle of a bow or the words for refusing a second helping. Yet historians argue these codes served a purpose. In a society anxious about rank, such elaborate prescriptions made social encounters ______, sparing participants the discomfort of improvising in moments where a misstep could cause real offense.', NULL, '[{"id":"A","text":"predictable","is_correct":true,"explanation":"Correct: detailed rules removed the need to improvise, making encounters reliably scripted and predictable."},{"id":"B","text":"spontaneous","is_correct":false,"explanation":"The rules spared people from improvising, the opposite of making encounters spontaneous."},{"id":"C","text":"competitive","is_correct":false,"explanation":"The codes eased discomfort and offense; nothing frames encounters as contests."},{"id":"D","text":"meaningless","is_correct":false,"explanation":"The historians argue the codes served a purpose, so encounters became orderly, not meaningless."}]'::jsonb, 'A', 'Step 1 — Find the clue
The rules spared participants {{yellow:the discomfort of improvising}} where a misstep could offend.
Step 2 — Match the word
Removing improvisation makes outcomes scripted and known in advance: predictable.
Distractor analysis:
- B: "Spontaneous" reverses the point; the codes eliminated improvisation.
- C: "Competitive" has no support; the aim was easing tension, not rivalry.
- D: "Meaningless" contradicts the claim that the codes served a real purpose.', 'If detailed rules removed the need to improvise, encounters became what?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6ff623f0-4b65-4a56-b755-918e8480dbb1', 'Which choice completes the text with the most logical and precise word or phrase?', 'The defense attorney did not deny that her client had been present at the scene. Instead, she chipped away at the prosecution''s timeline, noting a clock that ran fast, a witness who had been drinking, and a streetlight reportedly out for repairs. She offered no grand alternative theory. Her strategy was simply to ______ the certainty the jury was being asked to accept.', NULL, '[{"id":"A","text":"undermine","is_correct":true,"explanation":"Correct: chipping away at the timeline''s reliability weakens the certainty the jury was asked to accept."},{"id":"B","text":"confirm","is_correct":false,"explanation":"She is attacking the prosecution''s certainty, not supporting it."},{"id":"C","text":"summarize","is_correct":false,"explanation":"She does more than restate; she actively casts doubt on the certainty."},{"id":"D","text":"exaggerate","is_correct":false,"explanation":"She reduces confidence in the case rather than overstating it."}]'::jsonb, 'A', 'Step 1 — Find the clue
She spent her effort {{yellow:chipping away at the prosecution''s timeline}} by exposing flaws.
Step 2 — Match the word
Weakening the jury''s certainty by exposing flaws is to undermine it.
Distractor analysis:
- B: "Confirm" reverses her aim; she attacks the certainty.
- C: "Summarize" ignores that she actively raises doubts, not merely recaps.
- D: "Exaggerate" misdirects; she diminishes confidence rather than inflating anything.', 'By exposing flaws in the timeline, what was she doing to the jury''s certainty?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c1bb5197-f7a4-43d4-a434-db870b86b04f', 'Which choice completes the text with the most logical and precise word or phrase?', 'Most readers assume that a dictionary fixes the meaning of words for all time. Lexicographers know better. Each new edition records meanings that have drifted, narrowed, or reversed since the last. A word praised as a compliment a century ago may now sting as an insult. Far from being a monument, the dictionary is a ______ record, perpetually revised to track a language that never stops moving.', NULL, '[{"id":"A","text":"provisional","is_correct":true,"explanation":"Correct: perpetually revised to track a moving language describes a temporary, provisional record."},{"id":"B","text":"definitive","is_correct":false,"explanation":"Definitive implies a final fixed authority, which the passage explicitly rejects."},{"id":"C","text":"inaccurate","is_correct":false,"explanation":"The dictionary tracks meanings faithfully; it is changeable, not wrong."},{"id":"D","text":"ancient","is_correct":false,"explanation":"Age is irrelevant; the point is that the record keeps changing."}]'::jsonb, 'A', 'Step 1 — Find the clue
The dictionary is {{yellow:perpetually revised to track a language that never stops moving}}.
Step 2 — Match the word
A record that is always being revised and never final is provisional.
Distractor analysis:
- B: "Definitive" contradicts the rejection of the dictionary as a permanent monument.
- C: "Inaccurate" is wrong; the record is accurate but temporary.
- D: "Ancient" introduces age, which the passage never makes the issue.', 'A record that is perpetually revised and never final is best called what?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8df9341b-0377-49c0-b7e2-092b9b6feb1e', 'Which choice completes the text with the most logical and precise word or phrase?', 'The river that powered the mill town had always seemed generous, but the engineer studying its flow grew uneasy. Records showed long stretches of plenty broken by sudden, severe droughts. The town had built its prosperity assuming the water would behave consistently. In truth, the river''s supply was deeply ______, lavish one year and nearly dry the next, a pattern the founders had failed to anticipate.', NULL, '[{"id":"A","text":"erratic","is_correct":true,"explanation":"Correct: lavish one year and nearly dry the next describes an unpredictable, erratic supply."},{"id":"B","text":"steady","is_correct":false,"explanation":"Steady contradicts the swing between plenty and severe drought."},{"id":"C","text":"plentiful","is_correct":false,"explanation":"Plentiful captures only the good years and ignores the droughts that worried the engineer."},{"id":"D","text":"polluted","is_correct":false,"explanation":"Water quality is never mentioned; the concern is variability in quantity."}]'::jsonb, 'A', 'Step 1 — Find the clue
The supply was {{yellow:lavish one year and nearly dry the next}}.
Step 2 — Match the word
Swinging unpredictably between extremes is what erratic means.
Distractor analysis:
- B: "Steady" is the false assumption the engineer disproves.
- C: "Plentiful" describes only the good years, ignoring the droughts.
- D: "Polluted" concerns quality, not the quantity variation at issue.', 'A supply that is lavish one year and dry the next is best described as what?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fbcab60f-bf4a-4ee8-9c15-5422b9e85d48', 'Which choice completes the text with the most logical and precise word or phrase?', 'The biographer admired her subject but refused to flatter him. Where earlier accounts had smoothed over the inventor''s cruelty to collaborators and his habit of claiming others'' ideas, she set these failings beside his genius without apology. Some readers wanted a hero; she gave them a ______ portrait instead, one that honored the man''s brilliance while refusing to hide the conduct that diminished it.', NULL, '[{"id":"A","text":"unflinching","is_correct":true,"explanation":"Correct: refusing to hide failings and setting them beside genius without apology is an unflinching portrait."},{"id":"B","text":"flattering","is_correct":false,"explanation":"The passage states she refused to flatter him, the opposite of this choice."},{"id":"C","text":"incomplete","is_correct":false,"explanation":"She included both brilliance and faults, making the portrait fuller, not incomplete."},{"id":"D","text":"affectionate","is_correct":false,"explanation":"Though she admired him, the emphasized quality is her refusal to soften his faults, not warmth."}]'::jsonb, 'A', 'Step 1 — Find the clue
She set his failings beside his genius {{yellow:without apology}}, refusing to hide them.
Step 2 — Match the word
Facing unpleasant truths directly and without softening is unflinching.
Distractor analysis:
- B: "Flattering" contradicts her stated refusal to flatter him.
- C: "Incomplete" is wrong because she adds the faults others omitted, making it fuller.
- D: "Affectionate" captures admiration but misses the emphasized refusal to hide faults.', 'A portrait that refuses to hide a subject''s faults is described as what?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d3eeca15-8f2d-4be5-860e-d952cd53ae1f', 'Which choice completes the text with the most logical and precise word or phrase?', 'When archaeologists first uncovered the buried granary, they assumed its builders had been a wealthy elite. Closer study of the surrounding dwellings overturned that view. The homes were modest and nearly identical, suggesting that the stored grain was shared rather than hoarded. Far from signaling concentrated power, the granary appears to have been a ______ resource, maintained collectively for the benefit of the entire settlement.', NULL, '[{"id":"A","text":"communal","is_correct":true,"explanation":"Correct: grain that is shared and maintained collectively for the whole settlement is communal."},{"id":"B","text":"contested","is_correct":false,"explanation":"Nothing in the passage indicates conflict over the resource; it was shared peacefully."},{"id":"C","text":"perishable","is_correct":false,"explanation":"The passage discusses ownership, not how quickly the grain spoiled."},{"id":"D","text":"luxurious","is_correct":false,"explanation":"This reverses the point; the homes were modest, not luxurious."}]'::jsonb, 'A', 'Step 1 — Find the clue
The passage explains the grain was {{yellow:shared rather than hoarded}} and the granary was {{yellow:maintained collectively for the benefit of the entire settlement}}.
Step 2 — Match the word
A resource shared and maintained collectively is a communal one, so ''communal'' fits precisely.
Distractor analysis:
- B: ''Contested'' implies conflict, but the grain was shared peacefully.
- C: ''Perishable'' describes spoilage, irrelevant to the question of ownership.
- D: ''Luxurious'' contradicts the modest dwellings described.', 'What word matches grain that is shared collectively by everyone in the settlement?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c323bc06-f139-438a-99af-0214596e3a93', 'Which choice completes the text with the most logical and precise word or phrase?', 'Critics initially dismissed the composer''s late symphony as chaotic. Subsequent analysis revealed an underlying logic invisible to early listeners. Each apparently random outburst, scholars showed, restated a single motif in disguised form. What had seemed disorder was in fact a tightly ______ design, in which every fragment derived from one source.', NULL, '[{"id":"A","text":"unified","is_correct":true,"explanation":"Correct: a design in which every fragment derives from one source is unified."},{"id":"B","text":"improvised","is_correct":false,"explanation":"Improvisation suggests spontaneity, but the passage shows deliberate underlying logic."},{"id":"C","text":"conventional","is_correct":false,"explanation":"The work surprised critics; nothing marks it as ordinary or conventional."},{"id":"D","text":"fragmentary","is_correct":false,"explanation":"This reverses the meaning; the point is coherence beneath apparent fragments."}]'::jsonb, 'A', 'Step 1 — Find the clue
Scholars showed each outburst {{yellow:restated a single motif in disguised form}} and that {{yellow:every fragment derived from one source}}.
Step 2 — Match the word
A design whose every part traces to one source is unified, so ''unified'' fits.
Distractor analysis:
- B: ''Improvised'' implies spontaneity, contradicting the deliberate logic uncovered.
- C: ''Conventional'' ignores that the work seemed chaotic and surprising.
- D: ''Fragmentary'' reverses the intended sense of underlying coherence.', 'If every part comes from one source, the design is held together how?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4e80223a-a0b1-4faa-8015-ea7019ac3af4', 'Which choice completes the text with the most logical and precise word or phrase?', 'The senator was known for refusing to commit to positions until pressured. When a reporter pressed her on the proposed tax, she neither endorsed nor rejected it, offering instead a string of cautious qualifications. Aides admitted privately that her response had been deliberately ______, designed to keep every faction guessing about where she truly stood.', NULL, '[{"id":"A","text":"evasive","is_correct":true,"explanation":"Correct: a response that avoids commitment to keep factions guessing is evasive."},{"id":"B","text":"forthright","is_correct":false,"explanation":"This is the opposite; a forthright answer would state her position plainly."},{"id":"C","text":"hostile","is_correct":false,"explanation":"Her tone was cautious, not aggressive or hostile toward anyone."},{"id":"D","text":"detailed","is_correct":false,"explanation":"Qualifications that obscure her stance are not the same as a detailed answer."}]'::jsonb, 'A', 'Step 1 — Find the clue
She {{yellow:neither endorsed nor rejected it}} and the answer was {{yellow:designed to keep every faction guessing about where she truly stood}}.
Step 2 — Match the word
Deliberately avoiding a clear stance to keep people guessing is being evasive.
Distractor analysis:
- B: ''Forthright'' contradicts her refusal to take a position.
- C: ''Hostile'' misreads her cautious, noncommittal tone.
- D: ''Detailed'' confuses vague qualifications with substantive specifics.', 'What word describes dodging a clear answer to keep people uncertain?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('475586f2-8eb6-4282-bb0a-d273fecb65ba', 'Which choice completes the text with the most logical and precise word or phrase?', 'Early naturalists believed coral reefs grew steadily and predictably. Modern reef studies tell a more complicated story. A reef may expand for decades, then collapse abruptly after a single storm or heat wave, only to rebuild along a different line. Growth, researchers now stress, is not smooth but ______, advancing in fits and starts shaped by sudden disturbance.', NULL, '[{"id":"A","text":"erratic","is_correct":true,"explanation":"Correct: growth advancing in fits and starts shaped by sudden disturbance is erratic."},{"id":"B","text":"continuous","is_correct":false,"explanation":"This contradicts ''not smooth'' and the described collapses and restarts."},{"id":"C","text":"rapid","is_correct":false,"explanation":"The passage stresses irregularity, not overall speed of growth."},{"id":"D","text":"reversible","is_correct":false,"explanation":"Reefs rebuild along new lines rather than simply reversing; the point is unevenness."}]'::jsonb, 'A', 'Step 1 — Find the clue
The passage says growth is {{yellow:not smooth}} and {{yellow:advancing in fits and starts shaped by sudden disturbance}}.
Step 2 — Match the word
Movement in unpredictable fits and starts is erratic, matching the described pattern.
Distractor analysis:
- A is correct.
- B: ''Continuous'' directly contradicts ''not smooth'' and the abrupt collapses.
- C: ''Rapid'' addresses speed, not the irregularity emphasized.
- D: ''Reversible'' misdescribes growth that rebuilds along different lines.', 'What word fits growth that comes in unpredictable fits and starts?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2c7ed5bd-af1f-4160-b5fa-b1914a90a71f', 'Which choice completes the text with the most logical and precise word or phrase?', 'The young apprentice expected the master potter to praise originality. Instead, the older woman insisted that he copy classic forms exactly, hundreds of times, before inventing anything. Only by absorbing inherited technique, she argued, could real innovation arise. Her teaching was thus deeply ______: she valued tradition not as a cage but as the very ground from which new work could grow.', NULL, '[{"id":"A","text":"conservative","is_correct":true,"explanation":"Correct: valuing and preserving inherited tradition as a foundation is conservative."},{"id":"B","text":"rebellious","is_correct":false,"explanation":"This contradicts her insistence on copying classic forms and honoring tradition."},{"id":"C","text":"careless","is_correct":false,"explanation":"Her demand for hundreds of exact copies shows great care, not carelessness."},{"id":"D","text":"theoretical","is_correct":false,"explanation":"Her teaching was hands-on practice, not abstract theory."}]'::jsonb, 'A', 'Step 1 — Find the clue
She insisted he {{yellow:copy classic forms exactly}} and valued {{yellow:tradition not as a cage but as the very ground from which new work could grow}}.
Step 2 — Match the word
Valuing inherited tradition as a foundation is a conservative approach to teaching.
Distractor analysis:
- B: ''Rebellious'' contradicts her devotion to classic forms.
- C: ''Careless'' clashes with her demand for hundreds of exact copies.
- D: ''Theoretical'' ignores the hands-on, practice-based method.', 'What word describes prizing inherited tradition as a foundation?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('01862d70-32df-42a1-b8dc-dc0775679817', 'The drug does not destroy the tumor outright. In trials, it instead halted the division of cancerous cells, freezing the mass at its current size. Patients showed no shrinkage, yet scans taken months apart looked identical. By acting to arrest further growth, the treatment bought time even when it could not reverse the disease.', 'As used in the text, the word "arrest" most nearly means', NULL, '[{"id":"A","text":"stop","is_correct":true,"explanation":"Correct: arresting growth means stopping or halting it, as the cells'' division was halted."},{"id":"B","text":"capture","is_correct":false,"explanation":"This is the legal sense of ''arrest,'' not the halting sense the medical context requires."},{"id":"C","text":"accelerate","is_correct":false,"explanation":"This reverses the meaning; the drug slowed, not sped up, growth."},{"id":"D","text":"detect","is_correct":false,"explanation":"The scans detect the tumor, but ''arrest'' refers to halting growth, not finding it."}]'::jsonb, 'A', 'Step 1 — Find the clue
The drug {{yellow:halted the division of cancerous cells, freezing the mass at its current size}}.
Step 2 — Match the word
To ''arrest further growth'' is to stop or halt it, matching ''halted'' and ''freezing.''
Distractor analysis:
- B: ''Capture'' is the unrelated legal sense of arrest.
- C: ''Accelerate'' reverses the meaning entirely.
- D: ''Detect'' confuses the scans'' role with the act of halting growth.', 'In a medical context, what does it mean to ''arrest'' the growth of a tumor?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ac59f0e3-94de-44c8-8be8-81fe330713c1', 'Which choice completes the text with the most logical and precise word or phrase?', 'Voters had been promised that the new highway would relieve congestion. Years after its completion, traffic was worse than ever. Planners had not anticipated that easier driving would lure thousands of new commuters onto the road. The project''s chief benefit, it turned out, was largely ______: the very improvement it offered drew enough extra cars to cancel itself out.', NULL, '[{"id":"A","text":"illusory","is_correct":true,"explanation":"Correct: a benefit that cancels itself out and never materializes is illusory."},{"id":"B","text":"permanent","is_correct":false,"explanation":"This contradicts the benefit being cancelled out; it did not last."},{"id":"C","text":"expensive","is_correct":false,"explanation":"Cost is not the issue; the passage concerns whether the benefit was real."},{"id":"D","text":"gradual","is_correct":false,"explanation":"The problem was that the benefit vanished, not that it arrived slowly."}]'::jsonb, 'A', 'Step 1 — Find the clue
The passage says {{yellow:the very improvement it offered drew enough extra cars to cancel itself out}}.
Step 2 — Match the word
A benefit that cancels itself out and never truly materializes is illusory.
Distractor analysis:
- B: ''Permanent'' contradicts a benefit that was undone.
- C: ''Expensive'' raises cost, which the passage does not address here.
- D: ''Gradual'' misframes the issue as timing rather than unreality.', 'What word fits a benefit that cancels itself out and was never really there?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0ba59b8a-d4e6-4d43-b76a-7687934357a6', 'Which choice completes the text with the most logical and precise word or phrase?', 'The novel''s narrator claims to recount events exactly as they happened. Yet small contradictions accumulate: dates shift, minor characters change names, and the narrator confesses to a poor memory. Attentive readers come to doubt his account. The author, it seems, has made the storyteller deliberately ______, inviting us to question every fact we are told.', NULL, '[{"id":"A","text":"unreliable","is_correct":true,"explanation":"Correct: a narrator whose account readers come to doubt is unreliable."},{"id":"B","text":"omniscient","is_correct":false,"explanation":"An omniscient narrator knows all; this one confesses to a poor memory."},{"id":"C","text":"sympathetic","is_correct":false,"explanation":"Likability is not at issue; the passage concerns the trustworthiness of his account."},{"id":"D","text":"anonymous","is_correct":false,"explanation":"The passage addresses whether to believe him, not whether his name is known."}]'::jsonb, 'A', 'Step 1 — Find the clue
Contradictions accumulate and {{yellow:readers come to doubt his account}}, with the narrator confessing to a poor memory.
Step 2 — Match the word
A storyteller whose account cannot be trusted is unreliable.
Distractor analysis:
- B: ''Omniscient'' contradicts his admitted poor memory.
- C: ''Sympathetic'' concerns likability, not trustworthiness.
- D: ''Anonymous'' addresses identity, not credibility.', 'What word describes a narrator whose account readers learn not to trust?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('54f645d9-396d-41a7-aec5-9afa277b5ef7', 'Which choice completes the text with the most logical and precise word or phrase?', 'The committee''s report ran to four hundred pages, yet readers struggled to extract its central recommendation. Each finding was hedged, every claim buried under exceptions and cross-references. A frustrated reviewer noted that a document meant to guide policy had instead become so ______ that no clear directive could be drawn from it at all.', NULL, '[{"id":"A","text":"convoluted","is_correct":true,"explanation":"Correct: a report so tangled that no clear directive emerges is convoluted."},{"id":"B","text":"concise","is_correct":false,"explanation":"This contradicts a four-hundred-page report buried under exceptions."},{"id":"C","text":"persuasive","is_correct":false,"explanation":"The report failed to convince anyone of a directive; it confused readers."},{"id":"D","text":"controversial","is_correct":false,"explanation":"The issue is that no clear claim could be found, not that claims sparked dispute."}]'::jsonb, 'A', 'Step 1 — Find the clue
Every claim was {{yellow:buried under exceptions and cross-references}} so that {{yellow:no clear directive could be drawn from it at all}}.
Step 2 — Match the word
A document so tangled and overcomplicated that no clear meaning emerges is convoluted.
Distractor analysis:
- B: ''Concise'' contradicts the four-hundred-page sprawl.
- C: ''Persuasive'' is wrong since the report convinced no one of anything.
- D: ''Controversial'' implies dispute, but the problem was unintelligibility.', 'What word fits a report so tangled that no clear meaning can be drawn?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('300c3f7d-2944-4f0c-b100-5d786cb7d646', 'Which choice completes the text with the most logical and precise word or phrase?', 'The negotiator''s reputation rested on a single trait. Where others grew rattled by insults or sudden demands, she remained unmoved, her voice level even when a deal seemed about to collapse. Colleagues marveled at how she could absorb pressure without losing focus. Her ______ in tense rooms, more than any clever tactic, secured the agreements others had thought impossible.', NULL, '[{"id":"A","text":"composure","is_correct":true,"explanation":"Correct: remaining unmoved and level under pressure is composure."},{"id":"B","text":"ambition","is_correct":false,"explanation":"Drive for advancement is not described; the trait is calm under stress."},{"id":"C","text":"eloquence","is_correct":false,"explanation":"Her success came from calm, not from persuasive speech or clever tactics."},{"id":"D","text":"impatience","is_correct":false,"explanation":"This reverses the point; she stayed calm rather than restless or irritable."}]'::jsonb, 'A', 'Step 1 — Find the clue
She {{yellow:remained unmoved, her voice level even when a deal seemed about to collapse}} and could {{yellow:absorb pressure without losing focus}}.
Step 2 — Match the word
Staying calm and level under intense pressure is composure.
Distractor analysis:
- B: ''Ambition'' names a drive not described in the passage.
- C: ''Eloquence'' credits speech, but the text emphasizes calm over tactics.
- D: ''Impatience'' reverses her steady, unflustered manner.', 'What word names staying calm and level when others get rattled?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5ab5d356-4cee-4516-af6f-4d56d9ee75c3', 'Which choice completes the text with the most logical and precise word or phrase?', 'At first the king''s new tax seemed a minor adjustment. But its design quietly shifted the burden from nobles onto merchants, who had long funded the crown''s wars. Historians argue the measure was anything but trivial. Beneath a modest surface, it ______ the old alliance between throne and aristocracy, reshaping who truly held power for a century to come.', NULL, '[{"id":"A","text":"transformed","is_correct":true,"explanation":"Correct: reshaping who held power and the old alliance for a century means it transformed them."},{"id":"B","text":"preserved","is_correct":false,"explanation":"This contradicts ''reshaping who truly held power''; the order changed."},{"id":"C","text":"described","is_correct":false,"explanation":"The tax acted on the alliance rather than merely depicting it."},{"id":"D","text":"postponed","is_correct":false,"explanation":"The change took effect and lasted a century; it was not delayed."}]'::jsonb, 'A', 'Step 1 — Find the clue
The measure was {{yellow:anything but trivial}} and ended up {{yellow:reshaping who truly held power for a century to come}}.
Step 2 — Match the word
An action that reshapes power and an old alliance for a century has transformed them.
Distractor analysis:
- B: ''Preserved'' contradicts the reshaping of power.
- C: ''Described'' wrongly makes the tax passive rather than causal.
- D: ''Postponed'' ignores that the change took hold and endured.', 'What word fits a tax that reshaped power and the old alliance for a century?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fa44620f-07ba-4405-979e-93f522c351fb', 'The editorial board''s first draft condemned the policy in absolute terms. Wiser heads on the board worried that such sweeping language would alienate readers who agreed only in part. In the final version, they chose to temper the harshest claims, softening accusations into measured criticisms that more readers could accept.', 'As used in the text, the word "temper" most nearly means', NULL, '[{"id":"A","text":"moderate","is_correct":true,"explanation":"Correct: to temper the claims is to moderate or soften them, as the board softened accusations."},{"id":"B","text":"strengthen","is_correct":false,"explanation":"This reverses the meaning; the board softened rather than intensified the claims."},{"id":"C","text":"harden","is_correct":false,"explanation":"This is the metallurgical sense and opposes the softening described."},{"id":"D","text":"organize","is_correct":false,"explanation":"The board changed the intensity of the claims, not their arrangement."}]'::jsonb, 'A', 'Step 1 — Find the clue
The board chose to {{yellow:soften accusations into measured criticisms that more readers could accept}}.
Step 2 — Match the word
To ''temper'' the harshest claims here means to moderate or soften them, matching ''softening.''
Distractor analysis:
- B: ''Strengthen'' reverses the intended softening.
- C: ''Harden'' is the metallurgical sense, opposite to the context.
- D: ''Organize'' confuses intensity with arrangement.', 'If the board softened harsh claims, what does ''temper'' mean here?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('24b004e3-3047-4202-8be2-31a481ab8eda', 'Which choice completes the text with the most logical and precise word or phrase?', 'When the river delta first formed, botanists assumed its mangroves would remain confined to the brackish shallows where they had taken root. Yet over three decades, the trees advanced steadily inland, colonizing soils that earlier surveys had judged too dry. What had seemed a fixed boundary proved instead to be ______, shifting as the species adapted to conditions no one had predicted.', NULL, '[{"id":"A","text":"permeable","is_correct":false,"explanation":"Permeable describes a barrier allowing passage through it, but the passage stresses that the boundary moved, not that things passed through a stationary line."},{"id":"B","text":"mutable","is_correct":true,"explanation":"Mutable means subject to change, matching the boundary that ''shifted'' and proved not ''fixed.''"},{"id":"C","text":"arbitrary","is_correct":false,"explanation":"Arbitrary implies the boundary was set without reason, but the text emphasizes that it changed over time, not that it was randomly chosen."},{"id":"D","text":"indistinct","is_correct":false,"explanation":"Indistinct means unclear or blurry, yet the boundary was clearly observed advancing; the issue is movement, not visibility."}]'::jsonb, 'B', 'Step 1 — Find the contrast
The passage opposes a {{yellow:fixed boundary}} with something that was instead changing as the trees {{yellow:advanced steadily inland}}.
Step 2 — Match the meaning
If the boundary was not fixed but moved over decades, it was changeable, so ''mutable'' is the precise fit.
Distractor analysis:
- A: Permeable refers to passage through a barrier, not the barrier''s own movement.
- C: Arbitrary describes how a line is chosen, not that it shifts over time.
- D: Indistinct means unclear, but the boundary''s change—not its visibility—is the point.', 'The blank contrasts with ''a fixed boundary''—look for a word meaning capable of changing.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('65623076-e393-4556-aa3a-c81d35ee1866', 'Which choice completes the text with the most logical and precise word or phrase?', 'Critics initially dismissed the novelist''s later style as careless, pointing to sentences that broke off mid-thought and paragraphs that abandoned their subjects. Closer study, however, revealed that each apparent lapse served a purpose: the fractured prose mirrored the disordered memories of her narrators. What readers had taken for negligence was in fact ______, every gap placed with care.', NULL, '[{"id":"A","text":"deliberate","is_correct":true,"explanation":"Deliberate means done on purpose, matching gaps that were ''placed with care'' to mirror the narrators'' memories."},{"id":"B","text":"conventional","is_correct":false,"explanation":"Conventional means ordinary or traditional, but the prose was unusual and fractured, not standard."},{"id":"C","text":"spontaneous","is_correct":false,"explanation":"Spontaneous suggests unplanned impulse, the opposite of the careful, purposeful placement the text describes."},{"id":"D","text":"ambiguous","is_correct":false,"explanation":"Ambiguous means open to multiple meanings, but the point is that the gaps were intentional, not that they were unclear."}]'::jsonb, 'A', 'Step 1 — Identify the reversal
The passage corrects an impression: each lapse {{yellow:served a purpose}} and every gap was {{yellow:placed with care}}.
Step 2 — Match the meaning
If the gaps were purposeful and carefully placed, the prose was intentional, so ''deliberate'' fits precisely.
Distractor analysis:
- B: Conventional contradicts the unusual, fractured nature of the style.
- C: Spontaneous implies the opposite of careful planning.
- D: Ambiguous addresses unclear meaning, not intentionality, which is the passage''s focus.', 'The blank replaces ''negligence''—the text says gaps were ''placed with care,'' so find its opposite.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d9a12d50-763c-48e1-8ff6-de01094b4dc7', 'Which choice completes the text with the most logical and precise word or phrase?', 'Eighteenth-century guild records suggest that master craftsmen guarded their techniques jealously, refusing to record certain methods even in private notebooks. Apprentices learned only by watching, since the masters feared that written instructions might spread beyond the workshop. Knowledge of these crafts therefore remained ______, passing from hand to hand rather than from page to page.', NULL, '[{"id":"A","text":"obsolete","is_correct":false,"explanation":"Obsolete means outdated, but the passage says the knowledge was actively transmitted, not abandoned."},{"id":"B","text":"theoretical","is_correct":false,"explanation":"Theoretical implies abstract concepts, yet these were practical crafts learned by hands-on watching."},{"id":"C","text":"unwritten","is_correct":true,"explanation":"Unwritten captures knowledge passed ''from hand to hand rather than from page to page,'' never set down on paper."},{"id":"D","text":"specialized","is_correct":false,"explanation":"Specialized is true but irrelevant here; the text''s emphasis is that the knowledge was never recorded, not that it was narrow."}]'::jsonb, 'C', 'Step 1 — Locate the clue
The masters refused to record methods, so knowledge passed {{yellow:from hand to hand rather than from page to page}}.
Step 2 — Match the meaning
Knowledge that never reaches a page is unwritten, so ''unwritten'' is the precise completion.
Distractor analysis:
- A: Obsolete wrongly suggests the knowledge died out rather than being transmitted.
- B: Theoretical contradicts the practical, observed nature of the crafts.
- D: Specialized is true but misses the point about the absence of written records.', 'The blank is explained by ''hand to hand rather than from page to page''—find a word meaning not recorded.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d6992185-a42b-4866-a756-2a50a7256d31', 'Which choice completes the text with the most logical and precise word or phrase?', 'The committee expected the new water-treatment plan to face fierce resistance, given how often earlier proposals had collapsed under public outcry. Instead, residents accepted it with surprising calm, and several council members who had braced for weeks of debate found the vote settled in a single evening. The plan''s passage was unexpectedly ______.', NULL, '[{"id":"A","text":"uneventful","is_correct":true,"explanation":"Uneventful matches a vote ''settled in a single evening'' without the expected weeks of debate or outcry."},{"id":"B","text":"controversial","is_correct":false,"explanation":"Controversial is the reverse of what occurred; residents accepted the plan calmly."},{"id":"C","text":"prolonged","is_correct":false,"explanation":"Prolonged contradicts the vote being settled quickly in one evening."},{"id":"D","text":"decisive","is_correct":false,"explanation":"Decisive describes a clear outcome but misses the contrast with expected conflict; the point is the lack of drama, not the margin."}]'::jsonb, 'A', 'Step 1 — Set up the surprise
Despite expected resistance, residents reacted {{yellow:with surprising calm}} and the vote was {{yellow:settled in a single evening}}.
Step 2 — Match the meaning
A calm, quickly settled process lacking the anticipated turmoil is uneventful, so ''uneventful'' fits.
Distractor analysis:
- B: Controversial reverses the calm acceptance the text describes.
- C: Prolonged contradicts the single-evening resolution.
- D: Decisive notes a clear result but ignores the key contrast with expected conflict.', 'Combine ''surprising calm'' and ''settled in a single evening''—the passage was free of expected drama.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('01984d3a-db16-4dfc-a74a-95ba93825d76', 'Which choice completes the text with the most logical and precise word or phrase?', 'Astronomers once treated the faint glow between galaxies as mere background noise, an artifact of imperfect instruments. Newer telescopes, however, traced the light to vast clouds of stripped gas drifting in intergalactic space. The signal that had been ignored as meaningless turned out to be ______, carrying information about how galaxies lose their material.', NULL, '[{"id":"A","text":"faint","is_correct":false,"explanation":"Faint repeats a detail already given and does not capture the reversal that the signal now matters."},{"id":"B","text":"informative","is_correct":true,"explanation":"Informative matches a signal ''carrying information about how galaxies lose their material,'' reversing its dismissal as meaningless."},{"id":"C","text":"deceptive","is_correct":false,"explanation":"Deceptive implies the signal misleads, but the text says it reveals genuine information."},{"id":"D","text":"constant","is_correct":false,"explanation":"Constant addresses steadiness, which the passage never discusses; the focus is the signal''s meaningfulness."}]'::jsonb, 'B', 'Step 1 — Find the reversal
The glow, once dismissed as meaningless noise, turned out to be something {{yellow:carrying information about how galaxies lose their material}}.
Step 2 — Match the meaning
A signal that carries information is informative, so ''informative'' is the precise fit.
Distractor analysis:
- A: Faint merely restates a detail and ignores the reversal in significance.
- C: Deceptive wrongly implies the signal misleads rather than informs.
- D: Constant introduces steadiness, a quality the passage does not address.', 'The blank is explained by ''carrying information''—find a synonym that reverses ''meaningless.''', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('79e3ab30-28b3-461c-b1a7-3faa5489c28c', 'Which choice completes the text with the most logical and precise word or phrase?', 'In her memoir, the diplomat recalls negotiations in which a single misplaced word could unravel months of careful work. She learned to weigh every phrase, choosing language that revealed nothing she did not intend to reveal. Colleagues admired how ______ her statements were, never offering an opponent more than she had decided to give.', NULL, '[{"id":"A","text":"guarded","is_correct":true,"explanation":"Guarded means cautious and revealing little, matching statements that gave ''never more than she had decided to give.''"},{"id":"B","text":"eloquent","is_correct":false,"explanation":"Eloquent praises fluent expression, but the text stresses restraint in disclosure, not polished delivery."},{"id":"C","text":"candid","is_correct":false,"explanation":"Candid means openly frank, the opposite of revealing nothing unintended."},{"id":"D","text":"concise","is_correct":false,"explanation":"Concise refers to brevity, but the point is controlled disclosure, not short length."}]'::jsonb, 'A', 'Step 1 — Locate the behavior
The diplomat chose language that {{yellow:revealed nothing she did not intend to reveal}}, giving opponents only what she decided.
Step 2 — Match the meaning
Statements that carefully withhold information are guarded, so ''guarded'' fits precisely.
Distractor analysis:
- B: Eloquent praises fluency, not the restraint the passage emphasizes.
- C: Candid means frank and open, contradicting her controlled disclosure.
- D: Concise concerns brevity, not the careful limiting of what she revealed.', 'She ''revealed nothing she did not intend''—find a word meaning cautious about disclosure.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
