INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5c813046-8cb3-4d1e-8b38-0dbf67d93adf', 'Which choice completes the text with the most logical and precise word or phrase?', 'The economist''s early model assumed that consumers always act on complete information, comparing every option before deciding. Field studies told a different story: shoppers relied on habit, rough guesses, and the first acceptable choice they encountered. Confronted with this evidence, she came to ______ her original assumption, replacing it with a theory built on limited reasoning.', NULL, '[{"id":"A","text":"defend","is_correct":false,"explanation":"Defend means to support, but she replaced the assumption rather than upholding it."},{"id":"B","text":"abandon","is_correct":true,"explanation":"Abandon means to give up, matching her ''replacing it with a theory built on limited reasoning.''"},{"id":"C","text":"clarify","is_correct":false,"explanation":"Clarify means to make clearer, but she discarded the assumption rather than explaining it more fully."},{"id":"D","text":"publish","is_correct":false,"explanation":"Publish concerns releasing work, unrelated to whether she kept or dropped the assumption."}]'::jsonb, 'B', 'Step 1 — Trace the change
The field evidence led her to act on her assumption by {{yellow:replacing it with a theory built on limited reasoning}}.
Step 2 — Match the meaning
To replace an assumption with a new theory is to abandon the old one, so ''abandon'' fits.
Distractor analysis:
- A: Defend reverses her response, since she gave up the assumption.
- C: Clarify implies keeping and refining it, not discarding it.
- D: Publish is unrelated to whether she retained the assumption.', 'She ended up ''replacing it'' with a new theory—find a verb meaning to give up the old one.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ecafeb6a-be83-4e03-b63f-5d50887dbfe2', 'Which choice completes the text with the most logical and precise word or phrase?', 'Folklorists studying the coastal villages noticed that the same tale appeared in dozens of forms, each settlement adding details drawn from its own harbor, weather, and trades. No single version could be called the original; the story existed only as the sum of its retellings. Its identity was thus ______, shaped anew by every community that told it.', NULL, '[{"id":"A","text":"fixed","is_correct":false,"explanation":"Fixed means unchanging, contradicting a story ''shaped anew by every community.''"},{"id":"B","text":"obscure","is_correct":false,"explanation":"Obscure means little known, but the tale was widespread and the point is its variability, not its fame."},{"id":"C","text":"fluid","is_correct":true,"explanation":"Fluid means changeable and flowing, matching a story reshaped by each retelling with no fixed original."},{"id":"D","text":"ancient","is_correct":false,"explanation":"Ancient describes age, which the passage does not emphasize; the focus is on the story''s changing form."}]'::jsonb, 'C', 'Step 1 — Find the evidence
The tale had no single original and was {{yellow:shaped anew by every community that told it}}.
Step 2 — Match the meaning
An identity reshaped by each retelling is changeable, so ''fluid'' is the precise fit.
Distractor analysis:
- A: Fixed directly contradicts the constant reshaping described.
- B: Obscure concerns fame, not the variability the passage emphasizes.
- D: Ancient addresses age, a detail the text does not stress.', 'The story was ''shaped anew by every community''—find a word meaning constantly changing.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ddd81868-1291-4297-be36-a610e16e3b87', 'Which choice completes the text with the most logical and precise word or phrase?', 'Reviewers of the orchestra''s debut struggled to describe its sound, which seemed to change character from one movement to the next. A passage of icy restraint would give way to sudden warmth, then to something almost playful. No single mood held for long, and audiences left unable to summarize what they had heard. The performance was strikingly ______.', NULL, '[{"id":"A","text":"monotonous","is_correct":false,"explanation":"Monotonous means dull and unvarying, the opposite of music that shifted moods constantly."},{"id":"B","text":"rehearsed","is_correct":false,"explanation":"Rehearsed concerns preparation, not the shifting character the passage describes."},{"id":"C","text":"mournful","is_correct":false,"explanation":"Mournful names one mood, but the text stresses that no single mood held for long."},{"id":"D","text":"varied","is_correct":true,"explanation":"Varied means full of changes, matching a sound that shifted from restraint to warmth to playfulness."}]'::jsonb, 'D', 'Step 1 — Gather the clue
The sound moved from restraint to warmth to playfulness, and {{yellow:no single mood held for long}}.
Step 2 — Match the meaning
A performance of constantly changing moods is varied, so ''varied'' fits precisely.
Distractor analysis:
- A: Monotonous contradicts the constant shifting of moods.
- B: Rehearsed addresses preparation, not the music''s changing character.
- C: Mournful fixes on one mood, but the passage stresses many.', 'Moods shifted and ''no single mood held for long''—find a word meaning full of changes.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3a7b2e60-300f-482e-a786-d60c39432f83', 'Which choice completes the text with the most logical and precise word or phrase?', 'The young king inherited a treasury his advisers described as bottomless, yet within a decade the wars he favored had drained it. To fund new campaigns he borrowed against future taxes, then borrowed again to pay the interest. By the end of his reign, the once-vast wealth had grown so ______ that even routine repairs to the palace went unpaid.', NULL, '[{"id":"A","text":"abundant","is_correct":false,"explanation":"Abundant means plentiful, contradicting wealth too small to cover routine repairs."},{"id":"B","text":"scarce","is_correct":true,"explanation":"Scarce means in short supply, matching wealth so reduced that ''routine repairs went unpaid.''"},{"id":"C","text":"hidden","is_correct":false,"explanation":"Hidden implies the wealth was concealed, but the text says it was spent and depleted, not hidden."},{"id":"D","text":"disputed","is_correct":false,"explanation":"Disputed suggests a quarrel over the wealth, which the passage never mentions; the issue is depletion."}]'::jsonb, 'B', 'Step 1 — Track the depletion
The treasury was drained and borrowed against until {{yellow:even routine repairs to the palace went unpaid}}.
Step 2 — Match the meaning
Wealth too small to cover basic repairs has become scarce, so ''scarce'' fits precisely.
Distractor analysis:
- A: Abundant reverses the depletion the passage describes.
- C: Hidden implies concealment, but the wealth was actually spent.
- D: Disputed introduces a conflict the text never mentions.', 'The wealth shrank until ''routine repairs went unpaid''—find a word meaning in short supply.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('32b6812e-1cf8-41b1-bbfa-08d2a4866820', 'Which choice completes the text with the most logical and precise word or phrase?', 'Linguists tracking the dialect found that its grammar resisted every attempt at tidy classification. Features they expected to appear together turned up in unrelated combinations, and rules that held in one village failed in the next. After years of fieldwork, they conceded that the dialect was too ______ to be captured by a single set of rules.', NULL, '[{"id":"A","text":"irregular","is_correct":true,"explanation":"Irregular means lacking consistent pattern, matching features that appeared in unrelated combinations and rules that failed from village to village."},{"id":"B","text":"primitive","is_correct":false,"explanation":"Primitive implies underdeveloped, but the passage describes inconsistency, not simplicity."},{"id":"C","text":"widespread","is_correct":false,"explanation":"Widespread concerns geographic spread, not the resistance to classification the text emphasizes."},{"id":"D","text":"elegant","is_correct":false,"explanation":"Elegant suggests refined orderliness, the opposite of a grammar that resisted tidy rules."}]'::jsonb, 'A', 'Step 1 — Find the disorder
The dialect''s features appeared in {{yellow:unrelated combinations}} and rules that held in one village failed in the next.
Step 2 — Match the meaning
A grammar without consistent pattern is irregular, so ''irregular'' fits precisely.
Distractor analysis:
- B: Primitive implies simplicity, but the issue is inconsistency.
- C: Widespread addresses spread, not resistance to classification.
- D: Elegant suggests orderliness, the reverse of what was found.', 'Rules ''held in one village failed in the next''—find a word meaning lacking a consistent pattern.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d2dab459-1f21-40d0-a6f0-f2128ae80e39', 'Which choice completes the text with the most logical and precise word or phrase?', 'Ecologists once praised the introduced beetle as a perfect solution, since it devoured the weeds choking local farms. Within years, though, the beetle turned to native plants once the weeds thinned, and its numbers exploded beyond any natural check. The remedy hailed as ideal had become ______, doing harm that outweighed the good it was meant to perform.', NULL, '[{"id":"A","text":"indispensable","is_correct":false,"explanation":"Indispensable means essential, contradicting a remedy now doing more harm than good."},{"id":"B","text":"temporary","is_correct":false,"explanation":"Temporary concerns duration, but the text stresses the beetle''s harm, not its brevity."},{"id":"C","text":"counterproductive","is_correct":true,"explanation":"Counterproductive means having an effect opposite to the one intended, matching a remedy ''doing harm that outweighed the good.''"},{"id":"D","text":"costly","is_correct":false,"explanation":"Costly suggests expense, but the passage describes ecological harm, not financial cost."}]'::jsonb, 'C', 'Step 1 — Find the reversal
The beetle attacked native plants and bred unchecked, so the remedy ended up {{yellow:doing harm that outweighed the good it was meant to perform}}.
Step 2 — Match the meaning
A remedy that produces the opposite of its intended effect is counterproductive, so ''counterproductive'' fits.
Distractor analysis:
- A: Indispensable reverses the failure the passage describes.
- B: Temporary addresses duration, not the harm done.
- D: Costly implies financial expense, but the harm is ecological.', 'The remedy did ''harm that outweighed the good''—find a word meaning it worked against its purpose.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e7057bf3-fcbb-4c46-bf4a-555ac53000e8', 'Which choice completes the text with the most logical and precise word or phrase?', 'Marine biologist Dr. Imani Okafor studies coral that survives in water far warmer than most reefs can tolerate. She has documented colonies thriving near volcanic vents where temperatures spike unpredictably each afternoon. Rather than treating these survivors as flukes, Okafor argues that their genetic makeup is ______: the very traits that let them endure today''s heat may help reefs worldwide withstand the warming oceans of coming decades.', NULL, '[{"id":"A","text":"instructive","is_correct":true,"explanation":"Correct: the survivors'' genes teach a broader lesson about how reefs might endure future warming."},{"id":"B","text":"delicate","is_correct":false,"explanation":"Contradicts the passage, which stresses these corals are unusually tough, not fragile."},{"id":"C","text":"ordinary","is_correct":false,"explanation":"Reverses the meaning; Okafor treats them as exceptional, not commonplace."},{"id":"D","text":"decorative","is_correct":false,"explanation":"Irrelevant; the passage concerns survival and warming, not appearance."}]'::jsonb, 'A', 'Step 1 — Find the lesson
Okafor says the corals'' traits {{yellow:may help reefs worldwide withstand the warming oceans of coming decades}}.
Step 2 — Match the word
Because the genes offer a useful lesson for other reefs, calling them "instructive" fits precisely.
Distractor analysis:
- B: "Delicate" contradicts the corals'' documented toughness.
- C: "Ordinary" reverses the point that they are treated as exceptional, not flukes.
- D: "Decorative" is unrelated to the survival argument.', 'What does she think the survivors can teach us about other reefs?', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a15c7521-a7ed-4c2b-8c7f-7a1b6eb4d79c', 'Which choice completes the text with the most logical and precise word or phrase?', 'When the new mayor took office, residents expected sweeping reforms after her fiery campaign speeches. Instead, she spent her first year quietly auditing departments, meeting with veteran staff, and postponing every major announcement. Critics called her timid, but supporters insisted the approach was merely ______: she was gathering knowledge before acting so that her eventual policies would not collapse under their own haste.', NULL, '[{"id":"A","text":"prudent","is_correct":true,"explanation":"Correct: gathering knowledge before acting to avoid haste is the essence of prudence."},{"id":"B","text":"reckless","is_correct":false,"explanation":"Contradicts the passage, which describes careful preparation, not recklessness."},{"id":"C","text":"secretive","is_correct":false,"explanation":"No evidence; she audits and meets openly, and the point is caution, not concealment."},{"id":"D","text":"indifferent","is_correct":false,"explanation":"Contradicts her active auditing and meetings, which show engagement."}]'::jsonb, 'A', 'Step 1 — Locate the motive
Supporters say she was {{yellow:gathering knowledge before acting so that her eventual policies would not collapse under their own haste}}.
Step 2 — Match the word
Deliberate caution to avoid hasty failure defines "prudent."
Distractor analysis:
- B: "Reckless" reverses the careful, anti-haste behavior described.
- C: "Secretive" lacks support; her meetings and audits are not framed as concealment.
- D: "Indifferent" contradicts her visible, active engagement.', 'Supporters defend the delay as wise preparation, not weakness.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('698a0dae-2c86-4f22-a906-6ac6263d2f34', 'Which choice completes the text with the most logical and precise word or phrase?', 'The novelist''s later diaries reveal a man at war with his own fame. In public he accepted awards with gracious smiles and warm anecdotes, charming every audience. Yet the same evenings, he confided to the page a gnawing contempt for the literary establishment that praised him. His public warmth, the diaries suggest, was wholly ______, a performance maintained even as private resentment deepened.', NULL, '[{"id":"A","text":"feigned","is_correct":true,"explanation":"Correct: the contrast between public warmth and private contempt shows the warmth was faked."},{"id":"B","text":"spontaneous","is_correct":false,"explanation":"Contradicts the diaries, which reveal the warmth was a maintained performance."},{"id":"C","text":"celebrated","is_correct":false,"explanation":"True-but-irrelevant; his charm pleased audiences, but the blank concerns its sincerity."},{"id":"D","text":"reluctant","is_correct":false,"explanation":"No evidence of hesitation; he smiled and charmed readily despite hidden feelings."}]'::jsonb, 'A', 'Step 1 — Spot the contrast
The diaries show his public warmth coexisted with {{yellow:a gnawing contempt for the literary establishment}} and was {{yellow:a performance maintained even as private resentment deepened}}.
Step 2 — Match the word
Warmth that masks real contempt is "feigned."
Distractor analysis:
- B: "Spontaneous" contradicts a deliberate, maintained performance.
- C: "Celebrated" is true but does not address sincerity.
- D: "Reluctant" lacks support since he charmed easily.', 'His smiles hid contempt, so the warmth was not real.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bac684f4-3203-44bf-ae9d-b09d0d05c063', 'Which choice completes the text with the most logical and precise word or phrase?', 'Early astronomers assumed comets appeared at random, harbingers without pattern. Edmond Halley rejected this view. Studying records of bright comets across centuries, he noticed that one returned at strikingly regular intervals. What others had dismissed as chaotic, Halley showed to be ______: the comet obeyed a predictable orbit, and he correctly forecast the year of its next appearance.', NULL, '[{"id":"A","text":"periodic","is_correct":true,"explanation":"Correct: regular intervals and a predictable orbit make the comet''s returns periodic."},{"id":"B","text":"invisible","is_correct":false,"explanation":"Irrelevant; the comet was visibly bright, and the issue is regularity, not visibility."},{"id":"C","text":"destructive","is_correct":false,"explanation":"No evidence; the passage discusses timing and orbit, not damage."},{"id":"D","text":"erratic","is_correct":false,"explanation":"Reverses the meaning; Halley proved the comet was regular, not erratic."}]'::jsonb, 'A', 'Step 1 — Find the proof of order
Halley showed {{yellow:the comet obeyed a predictable orbit}} returning at {{yellow:strikingly regular intervals}}.
Step 2 — Match the word
Returning on a regular schedule means the comet was "periodic."
Distractor analysis:
- B: "Invisible" contradicts the bright, observed comet.
- C: "Destructive" introduces unsupported harm.
- D: "Erratic" reverses the regularity Halley demonstrated.', 'Regular intervals and a predictable orbit point to one word.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3abbbeba-4ce7-420a-bfa8-e5c3f88c9d5a', 'Which choice completes the text with the most logical and precise word or phrase?', 'The committee had expected the engineer''s report to favor one bridge design over the others. Her testimony refused to oblige. She praised the cable-stayed plan''s elegance, then noted its untested foundations; she admired the arch design''s strength, then warned of its cost. On every question she remained carefully ______, presenting the merits and flaws of each option without ever endorsing a single one.', NULL, '[{"id":"A","text":"noncommittal","is_correct":true,"explanation":"Correct: weighing merits and flaws without endorsing any option is being noncommittal."},{"id":"B","text":"enthusiastic","is_correct":false,"explanation":"Contradicts her refusal to endorse any single design."},{"id":"C","text":"dishonest","is_correct":false,"explanation":"No evidence; she presents accurate merits and flaws, not falsehoods."},{"id":"D","text":"hostile","is_correct":false,"explanation":"Contradicts her praise of each plan''s strengths."}]'::jsonb, 'A', 'Step 1 — Read her stance
She gave merits and flaws of each design {{yellow:without ever endorsing a single one}}.
Step 2 — Match the word
Declining to commit to any choice makes her "noncommittal."
Distractor analysis:
- B: "Enthusiastic" contradicts her refusal to endorse anything.
- C: "Dishonest" lacks support; her assessments are accurate.
- D: "Hostile" contradicts the praise she offers each design.', 'She balanced pros and cons but backed nobody.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ed18c457-bab5-45e0-8a1d-5d4ca93b612e', 'Which choice completes the text with the most logical and precise word or phrase?', 'Anthropologist Lars Henriksen warns against romanticizing the past. Popular books often portray ancient foragers as living in effortless harmony, free from the stresses of modern life. Henriksen finds this picture ______: the archaeological record shows seasons of hunger, frequent injury, and short lifespans. To call such existence idyllic, he argues, ignores the very hardships the evidence makes plain.', NULL, '[{"id":"A","text":"misleading","is_correct":true,"explanation":"Correct: the harsh record shows the harmonious picture gives a false impression."},{"id":"B","text":"verifiable","is_correct":false,"explanation":"Reverses the meaning; Henriksen says the rosy picture conflicts with the evidence."},{"id":"C","text":"incomplete","is_correct":false,"explanation":"Too narrow; he says the picture is false, not merely missing details."},{"id":"D","text":"fascinating","is_correct":false,"explanation":"No evidence; the passage critiques the picture''s accuracy, not its interest."}]'::jsonb, 'A', 'Step 1 — Find the contradiction
The record shows {{yellow:seasons of hunger, frequent injury, and short lifespans}}, against the harmonious portrayal.
Step 2 — Match the word
A portrayal that the evidence proves false is "misleading."
Distractor analysis:
- B: "Verifiable" reverses his point that evidence contradicts the picture.
- C: "Incomplete" understates his claim that the picture is wrong, not merely partial.
- D: "Fascinating" ignores his focus on accuracy.', 'The evidence of hardship shows the rosy view is false.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d4ad49fe-d7f0-4a8d-bcea-5d826afbaa23', 'Which choice completes the text with the most logical and precise word or phrase?', 'In her study of urban beekeeping, Dr. Priya Nandakumar found that hives in dense city centers often outproduced rural ones. The reason surprised her. Cities offered a steady patchwork of garden flowers, park blossoms, and balcony planters blooming in overlapping seasons. This floral ______ meant bees rarely faced the sudden scarcities that struck monoculture farmland after a single crop finished flowering.', NULL, '[{"id":"A","text":"variety","is_correct":true,"explanation":"Correct: a patchwork of many different flower sources is floral variety."},{"id":"B","text":"scarcity","is_correct":false,"explanation":"Contradicts the steady, abundant supply that prevented shortages."},{"id":"C","text":"uniformity","is_correct":false,"explanation":"Reverses the meaning; the city offered many kinds of flowers, unlike monoculture."},{"id":"D","text":"fragrance","is_correct":false,"explanation":"No evidence; the passage concerns the range of sources, not their smell."}]'::jsonb, 'A', 'Step 1 — Identify the floral mix
Cities offered {{yellow:a steady patchwork of garden flowers, park blossoms, and balcony planters blooming in overlapping seasons}}.
Step 2 — Match the word
Many different overlapping sources describe floral "variety," which prevented scarcity.
Distractor analysis:
- B: "Scarcity" contradicts the abundance that protected the bees.
- C: "Uniformity" reverses the diverse patchwork, matching the monoculture it is contrasted with.
- D: "Fragrance" addresses smell, not the range of sources.', 'A patchwork of many flower types is contrasted with single-crop farmland.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('20e75353-5529-41b4-97b0-b16df936bafe', 'Which choice completes the text with the most logical and precise word or phrase?', 'The retired diplomat was famous for defusing standoffs that others thought hopeless. Colleagues recalled that he never raised his voice, never issued threats, and never let an insult provoke him. Even when negotiations turned bitter and rivals hurled accusations across the table, he stayed ______, answering each outburst with the same unhurried calm that eventually wore his opponents down.', NULL, '[{"id":"A","text":"composed","is_correct":true,"explanation":"Correct: unhurried calm under provocation is being composed."},{"id":"B","text":"agitated","is_correct":false,"explanation":"Contradicts his unhurried calm and refusal to be provoked."},{"id":"C","text":"withdrawn","is_correct":false,"explanation":"No evidence; he actively answered each outburst rather than retreating."},{"id":"D","text":"vindictive","is_correct":false,"explanation":"Contradicts his refusal to threaten or retaliate."}]'::jsonb, 'A', 'Step 1 — Note his demeanor
He answered each outburst with {{yellow:the same unhurried calm that eventually wore his opponents down}}.
Step 2 — Match the word
Staying calm and self-controlled amid provocation means he remained "composed."
Distractor analysis:
- B: "Agitated" reverses his unhurried calm.
- C: "Withdrawn" contradicts his active replies.
- D: "Vindictive" contradicts his refusal to threaten or retaliate.', 'He met every provocation with the same steady calm.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('45575491-08ba-40e6-91d9-b0faa27e60bf', 'Which choice completes the text with the most logical and precise word or phrase?', 'Geologists once believed that the canyon had been carved slowly, grain by grain, over tens of millions of years. New dating of the sediment overturned that assumption. The layers suggested that a single catastrophic flood, unleashed when an ancient lake breached its rim, had gouged most of the gorge in mere weeks. The canyon, it turned out, was less the product of patience than of ______.', NULL, '[{"id":"A","text":"sudden upheaval","is_correct":true,"explanation":"Correct: a catastrophic flood carving the gorge in weeks is sudden upheaval."},{"id":"B","text":"gradual erosion","is_correct":false,"explanation":"This is the rejected old view of slow, grain-by-grain carving."},{"id":"C","text":"human design","is_correct":false,"explanation":"No evidence; the cause is a natural flood, not human action."},{"id":"D","text":"steady rainfall","is_correct":false,"explanation":"Too mild; the passage describes a single violent flood, not ongoing rain."}]'::jsonb, 'A', 'Step 1 — Identify the new cause
The gorge was gouged by {{yellow:a single catastrophic flood, unleashed when an ancient lake breached its rim}} in {{yellow:mere weeks}}.
Step 2 — Match the phrase
The canyon is contrasted with patience, so it resulted from "sudden upheaval."
Distractor analysis:
- B: "Gradual erosion" is the discredited slow theory, the opposite of the new finding.
- C: "Human design" has no support; the cause is natural.
- D: "Steady rainfall" is too gentle for the violent, rapid flood described.', 'The new dating points to a violent flood, not slow patience.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9135b6a9-194c-452a-917d-da9c554fc168', 'Which choice completes the text with the most logical and precise word or phrase?', 'Throughout the trade negotiations, the smaller nation''s envoy seemed to hold no cards worth playing. Yet she secured terms far better than anyone predicted. Observers later realized her apparent weakness had been ______: by letting the larger powers underestimate her, she lured them into concessions they would never have offered to an opponent they took seriously.', NULL, '[{"id":"A","text":"a calculated pose","is_correct":true,"explanation":"Correct: deliberately letting others underestimate her was a strategic act, a calculated pose."},{"id":"B","text":"a genuine handicap","is_correct":false,"explanation":"Contradicts the reveal that her weakness was deliberate and advantageous."},{"id":"C","text":"a public embarrassment","is_correct":false,"explanation":"No evidence; she won better terms, so there was no humiliation."},{"id":"D","text":"an honest mistake","is_correct":false,"explanation":"Contradicts the deliberate, planned nature of the strategy."}]'::jsonb, 'A', 'Step 1 — Reveal the strategy
Observers saw that {{yellow:by letting the larger powers underestimate her, she lured them into concessions}}.
Step 2 — Match the phrase
Weakness deliberately staged for advantage is "a calculated pose."
Distractor analysis:
- B: "A genuine handicap" reverses the point that the weakness was feigned.
- C: "A public embarrassment" contradicts her successful outcome.
- D: "An honest mistake" contradicts the deliberate planning.', 'Her weakness was a trick to make rivals lower their guard.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5fa17fce-73dd-43da-aaf6-a4e5a8a72234', 'Which choice completes the text with the most logical and precise word or phrase?', 'The composer''s final symphony puzzled audiences at its premiere. Earlier works had built toward thunderous, triumphant finales, but this one dissolved into a hushed, unresolved chord that simply faded. Some listeners felt cheated. Critics today, however, read the ending as ______ rather than incomplete: the composer, dying as he wrote it, chose quiet ambiguity over false triumph, leaving the question of resolution deliberately open.', NULL, '[{"id":"A","text":"intentional","is_correct":true,"explanation":"Correct: the composer deliberately chose the open, quiet ending, making it intentional."},{"id":"B","text":"accidental","is_correct":false,"explanation":"Contradicts the deliberate choice the critics describe."},{"id":"C","text":"triumphant","is_correct":false,"explanation":"Contradicts the hushed, unresolved ending that replaced false triumph."},{"id":"D","text":"conventional","is_correct":false,"explanation":"Contradicts how the ending broke from his earlier triumphant finales."}]'::jsonb, 'A', 'Step 1 — Read the critics'' view
They say the composer {{yellow:chose quiet ambiguity over false triumph, leaving the question of resolution deliberately open}}.
Step 2 — Match the word
A deliberate, chosen ending, opposed to "incomplete," is "intentional."
Distractor analysis:
- B: "Accidental" reverses the deliberate choice described.
- C: "Triumphant" contradicts the hushed, unresolved chord.
- D: "Conventional" contradicts how the ending departed from his usual finales.', 'Critics oppose the ending to ''incomplete''; he chose it on purpose.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0938ab1d-1a40-4b44-9733-5a81d308654b', 'Which choice completes the text with the most logical and precise word or phrase?', 'Software designer Theo Marsh believes most apps fail by offering too much. His own programs strip away menus, options, and settings until only the essential function remains. A photo app he built does nothing but crop, yet it has millions of users. Marsh insists this ______ is a strength: by refusing to add features, he spares users the confusion that buries simpler tools in clutter.', NULL, '[{"id":"A","text":"minimalism","is_correct":true,"explanation":"Correct: stripping away everything but the essential function is minimalism."},{"id":"B","text":"complexity","is_correct":false,"explanation":"Reverses the meaning; he removes features rather than adding intricacy."},{"id":"C","text":"popularity","is_correct":false,"explanation":"True-but-irrelevant; the blank names his design approach, not its success."},{"id":"D","text":"imitation","is_correct":false,"explanation":"No evidence; he pioneers a sparse style rather than copying others."}]'::jsonb, 'A', 'Step 1 — Identify his approach
Marsh strips programs until {{yellow:only the essential function remains}} and refuses {{yellow:to add features}}.
Step 2 — Match the word
A design reduced to bare essentials is "minimalism."
Distractor analysis:
- B: "Complexity" reverses his feature-removing philosophy.
- C: "Popularity" names a result, not the design trait the blank requires.
- D: "Imitation" lacks support; his approach is original.', 'He keeps only the essential function and adds nothing.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('eca43f75-edd4-49fb-9281-50d36edac71f', 'As used in the text, "severity" most nearly means', 'In her later novellas, Okonkwo refused to let her narrators editorialize. Where earlier writers might have paused to lament a character''s downfall, she withheld comment entirely, trusting the bare sequence of events to indict her subjects without her help. Critics initially mistook this restraint for indifference, but it was in fact a calculated severity: by declining to soften the record, she made the silence itself accusatory.', NULL, '[{"id":"A","text":"harshness of climate","is_correct":false,"explanation":"This sense of severity (weather) is unrelated to the narrative technique under discussion."},{"id":"B","text":"unadorned strictness","is_correct":true,"explanation":"The text frames the author''s refusal to soften or comment as a deliberate, stripped-down rigor, matching this sense."},{"id":"C","text":"physical pain","is_correct":false,"explanation":"No bodily suffering is described; the term refers to an aesthetic stance."},{"id":"D","text":"seriousness of illness","is_correct":false,"explanation":"There is no medical context in the passage."}]'::jsonb, 'B', 'Step 1 — Pin the clue
The author''s method is described as {{yellow:by declining to soften the record}}, an austere, comment-free approach.
Step 2 — Match the sense
"Severity" here names that calculated, unadorned strictness rather than weather, pain, or sickness.
Distractor analysis:
- A: ''harshness of climate'' uses an irrelevant weather sense.
- C: ''physical pain'' imports a bodily meaning absent from the text.
- D: ''seriousness of illness'' applies a medical sense with no support.', 'The word describes an aesthetic choice to strip away commentary, not weather or pain.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('276e8d31-5566-47e3-b792-311924875642', 'Which choice completes the text with the most logical and precise word or phrase?', 'The reformer''s pamphlets were celebrated for their clarity, yet his private letters reveal a man who could ______ even his closest allies, recasting yesterday''s firm promises as misunderstandings whenever a new advantage beckoned. Colleagues who reread their correspondence found that commitments they had treated as settled had quietly dissolved, leaving them to wonder whether any of his assurances had ever been meant to bind him at all.', NULL, '[{"id":"A","text":"finance","is_correct":false,"explanation":"Nothing in the passage concerns providing money to allies."},{"id":"B","text":"equivocate with","is_correct":true,"explanation":"Recasting firm promises as misunderstandings to escape them is precisely equivocating, using ambiguity to evade commitment."},{"id":"C","text":"console","is_correct":false,"explanation":"He betrays rather than comforts his allies, the opposite of consoling."},{"id":"D","text":"outrank","is_correct":false,"explanation":"No hierarchy of rank is described; the issue is broken promises."}]'::jsonb, 'B', 'Step 1 — Identify the behavior
The text says he kept {{yellow:recasting yesterday''s firm promises as misunderstandings whenever a new advantage beckoned}}.
Step 2 — Match the verb
Using slippery ambiguity to escape commitments is the definition of equivocating with someone.
Distractor analysis:
- A: ''finance'' introduces money, which is irrelevant.
- C: ''console'' reverses his actual treatment of allies.
- D: ''outrank'' invents a rank-based reading unsupported by the text.', 'Look for a word meaning to use deliberate vagueness to dodge a commitment.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a767ce10-9a4e-4b19-8786-c2a1b0d1be37', 'Which choice completes the text with the most logical and precise word or phrase?', 'The enzyme does not destroy the toxin so much as ______ it: by binding to a single site, it holds the molecule in an inert configuration, suspending its activity without breaking it apart. Should the enzyme later release its grip, the toxin can resume its original function unchanged, which is why researchers describe the interaction as a pause rather than a defeat.', NULL, '[{"id":"A","text":"arrest","is_correct":true,"explanation":"Holding the toxin inert and suspending its activity without destroying it is exactly to arrest it, in the sense of halting."},{"id":"B","text":"dissolve","is_correct":false,"explanation":"The text stresses the toxin is not broken apart, contradicting dissolving."},{"id":"C","text":"amplify","is_correct":false,"explanation":"Amplifying would increase activity, but the enzyme suspends it."},{"id":"D","text":"detect","is_correct":false,"explanation":"Mere detection does not capture the holding-inert action described."}]'::jsonb, 'A', 'Step 1 — Find the action
The enzyme is said to hold the molecule {{yellow:suspending its activity without breaking it apart}}.
Step 2 — Choose the precise verb
"Arrest" carries the secondary sense of halting or stopping, which fits suspension without destruction.
Distractor analysis:
- B: ''dissolve'' contradicts the statement that the toxin is not broken apart.
- C: ''amplify'' reverses the effect, which is to suspend activity.
- D: ''detect'' is too weak, naming only sensing, not halting.', 'A common word for ''stop'' has a secondary sense that fits halting without destroying.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f48443f3-f302-426f-aef5-6ef3f8cd7cbe', 'Which choice completes the text with the most logical and precise word or phrase?', 'Geologists once assumed that a fault, once locked, would remain so until catastrophic failure. Newer models suggest instead that the crust retains a surprising ______: under sustained stress it can deform slowly, accommodating strain through countless tiny adjustments rather than a single rupture. This capacity to yield gradually, it turns out, explains why some regions store far less seismic energy than their tectonic setting would predict.', NULL, '[{"id":"A","text":"opacity","is_correct":false,"explanation":"Opacity (resistance to light or understanding) is unrelated to gradual deformation."},{"id":"B","text":"plasticity","is_correct":true,"explanation":"The crust''s ability to deform slowly and yield gradually is precisely plasticity."},{"id":"C","text":"rigidity","is_correct":false,"explanation":"Rigidity is the opposite of the gradual yielding the passage describes."},{"id":"D","text":"luminosity","is_correct":false,"explanation":"Brightness has no relevance to the mechanical behavior of rock."}]'::jsonb, 'B', 'Step 1 — Locate the clue
The crust is said to have a {{yellow:capacity to yield gradually}} under stress.
Step 2 — Match the noun
"Plasticity" names exactly this ability to deform slowly and permanently rather than snap.
Distractor analysis:
- A: ''opacity'' applies an optical sense irrelevant here.
- C: ''rigidity'' reverses the meaning, naming stiffness instead of yielding.
- D: ''luminosity'' is unrelated to mechanical deformation.', 'The word names the ability of a material to deform gradually rather than fracture.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f6519354-f6a5-44e9-9668-5bab9a6fc17e', 'Which choice completes the text with the most logical and precise word or phrase?', 'The senator''s gift for ______ served him well in committee. Faced with a divisive bill, he would propose adding qualifications and exceptions until the measure was so hedged that no faction felt threatened by it. Opponents complained that the resulting law accomplished little, but the senator regarded a softened, survivable statute as far preferable to a bold one that died on the floor.', NULL, '[{"id":"A","text":"temporizing","is_correct":false,"explanation":"Temporizing means stalling for time, but the senator acts decisively to amend bills, not delay."},{"id":"B","text":"qualification","is_correct":true,"explanation":"Adding limiting clauses and exceptions to soften a bill is exactly qualification in its modifying sense."},{"id":"C","text":"oratory","is_correct":false,"explanation":"His skill lies in revising text, not in eloquent speech."},{"id":"D","text":"provocation","is_correct":false,"explanation":"He defuses conflict rather than provoking it, the reverse of this word."}]'::jsonb, 'B', 'Step 1 — Identify the skill
The senator would {{yellow:propose adding qualifications and exceptions until the measure was so hedged}}.
Step 2 — Match the noun
"Qualification" in its sense of adding limiting conditions names this exact tactic.
Distractor analysis:
- A: ''temporizing'' wrongly implies delay rather than active amendment.
- C: ''oratory'' points to speech, not the textual hedging described.
- D: ''provocation'' reverses his aim, which is to soothe factions.', 'The word shares a root with ''qualify'' in the sense of limiting or hedging a claim.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('71db23cd-a23b-486a-bd12-37951685ec26', 'Which choice completes the text with the most logical and precise word or phrase?', 'Medieval chroniclers rarely distinguished rumor from record. A monk copying an annal might insert a marvel he had heard at market beside a verified royal decree, granting both the same sober authority. Modern historians must therefore ______ such sources: not discarding them, but weighing each entry against independent evidence to determine which claims the manuscript can actually be trusted to support.', NULL, '[{"id":"A","text":"celebrate","is_correct":false,"explanation":"The passage calls for critical evaluation, not praise, of the sources."},{"id":"B","text":"interrogate","is_correct":true,"explanation":"Weighing each entry against independent evidence to test its reliability is precisely to interrogate the source."},{"id":"C","text":"transcribe","is_correct":false,"explanation":"Mere copying is what the monks did; historians must instead assess the content."},{"id":"D","text":"abandon","is_correct":false,"explanation":"The text explicitly says ''not discarding them,'' contradicting abandonment."}]'::jsonb, 'B', 'Step 1 — Find the task
Historians must, the text says, weigh entries {{yellow:not discarding them, but weighing each entry against independent evidence}}.
Step 2 — Match the verb
"Interrogate," in its sense of critically questioning a source, captures this testing.
Distractor analysis:
- A: ''celebrate'' wrongly implies approval rather than scrutiny.
- C: ''transcribe'' describes the monks'' copying, not the historians'' analysis.
- D: ''abandon'' directly contradicts ''not discarding them.''', 'The word means to question critically, not to copy or discard.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1b22d5b3-a379-48b8-a086-f818a7d6f2d7', 'As used in the text, "enlarge" most nearly means', 'Whitman''s catalogs can exhaust a reader, but their length is not mere accumulation. Each added image slightly ______ the meaning of those before it, so that a line about a laborer, once joined to lines about a sailor and a mother, comes to stand for a whole democratic multitude. The poet builds significance not by isolating a single figure but by letting the list quietly enlarge what any one of its members can mean.', NULL, '[{"id":"A","text":"physically expand","is_correct":false,"explanation":"No physical growth is involved; the change is in meaning, not size."},{"id":"B","text":"broadens the significance of","is_correct":true,"explanation":"The list makes each image come to stand for more, broadening its meaning, which the passage states explicitly."},{"id":"C","text":"prints in bigger type","is_correct":false,"explanation":"Typography is irrelevant to the poem''s accumulating sense."},{"id":"D","text":"sets free from prison","is_correct":false,"explanation":"This unrelated sense of enlarge (to release) does not apply."}]'::jsonb, 'B', 'Step 1 — Track the effect
The text says the poet lets the list {{yellow:quietly enlarge what any one of its members can mean}}.
Step 2 — Match the sense
"Enlarge" here means to broaden or expand significance, not size or typeface.
Distractor analysis:
- A: ''physically expand'' misreads a figurative effect as literal.
- C: ''prints in bigger type'' invents a typographic sense.
- D: ''sets free from prison'' uses an archaic, irrelevant meaning.', 'The growth here is one of meaning, not physical size.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
