INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f443e1a5-8b6f-43c8-afd6-276ae97ae7c9', 'Which choice completes the text with the most logical and precise word or phrase?', 'The cellist''s interpretation was praised for its restraint, but restraint here meant the opposite of timidity. She could have indulged every swell the score permitted; instead she ______ her dynamics, releasing the largest sounds only at the rare moments that could bear their weight. The effect was paradoxical: by spending her power so sparingly, she made each climax land with greater force than any unrelenting performance could.', NULL, '[{"id":"A","text":"tempered","is_correct":true,"explanation":"Moderating her dynamics, holding back power to release it selectively, is exactly to temper them."},{"id":"B","text":"abandoned","is_correct":false,"explanation":"She controls her dynamics deliberately rather than giving them up."},{"id":"C","text":"transcribed","is_correct":false,"explanation":"Copying notation is unrelated to her interpretive control of volume."},{"id":"D","text":"exaggerated","is_correct":false,"explanation":"Exaggerating reverses the restraint the passage emphasizes."}]'::jsonb, 'A', 'Step 1 — Find the behavior
The cellist is described as {{yellow:releasing the largest sounds only at the rare moments that could bear their weight}}.
Step 2 — Match the verb
"Tempered," meaning to moderate or hold in check, captures this disciplined control.
Distractor analysis:
- B: ''abandoned'' contradicts her deliberate control.
- C: ''transcribed'' wrongly imports a notation sense.
- D: ''exaggerated'' reverses the restraint described.', 'A common verb for ''moderate'' fits her holding power in reserve.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2d9d13a9-d94c-460b-b3fa-1d0691196d29', 'Which choice completes the text with the most logical and precise word or phrase?', 'Early ecologists treated a meadow as a fixed community, a roster of species that belonged together. Field studies have since ______ that assumption. The same plot, watched over decades, hosts a shifting cast as soils acidify, grazers come and go, and chance dispersals introduce newcomers. What looked like a stable membership turns out to be a temporary truce among organisms with no special loyalty to one another.', NULL, '[{"id":"A","text":"confirmed","is_correct":false,"explanation":"The evidence overturns the old assumption rather than confirming it."},{"id":"B","text":"unsettled","is_correct":true,"explanation":"Showing the community to be shifting and temporary undermines, or unsettles, the fixed-roster assumption."},{"id":"C","text":"catalogued","is_correct":false,"explanation":"Listing species does not capture the act of overturning a belief."},{"id":"D","text":"financed","is_correct":false,"explanation":"Funding is irrelevant to how studies treated the assumption."}]'::jsonb, 'B', 'Step 1 — Find the contrast
The text reveals that {{yellow:What looked like a stable membership turns out to be a temporary truce}}.
Step 2 — Match the verb
The studies undermine the fixed assumption, so "unsettled" fits the act of destabilizing it.
Distractor analysis:
- A: ''confirmed'' reverses the meaning; the assumption is overturned.
- C: ''catalogued'' names mere listing, not refutation.
- D: ''financed'' is irrelevant to the studies'' epistemic effect.', 'The studies overturn the old belief, so pick a verb meaning to destabilize it.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a1b9b4c2-fd9b-4eef-a55a-5c6fdb67bf96', 'Which choice completes the text with the most logical and precise word or phrase?', 'The treaty''s drafters prized ambiguity. A clause that committed each nation to act "as circumstances warrant" could be read as an iron pledge in one capital and a polite nothing in another. This calculated vagueness was not a flaw but a ______: it let signatories endorse the same words while privately reserving incompatible intentions, and so allowed an agreement that precise language would have made impossible.', NULL, '[{"id":"A","text":"expedient","is_correct":true,"explanation":"The vagueness is a useful device that made agreement possible, the exact sense of an expedient."},{"id":"B","text":"liability","is_correct":false,"explanation":"The text calls the vagueness ''not a flaw,'' contradicting liability."},{"id":"C","text":"transcript","is_correct":false,"explanation":"A transcript is a record, not a strategic device, and does not fit."},{"id":"D","text":"miscalculation","is_correct":false,"explanation":"The vagueness was deliberate and effective, the opposite of a miscalculation."}]'::jsonb, 'A', 'Step 1 — Find the framing
The text says the vagueness {{yellow:allowed an agreement that precise language would have made impossible}}.
Step 2 — Match the noun
An "expedient" is a convenient means to an end, exactly what the useful ambiguity served as.
Distractor analysis:
- B: ''liability'' contradicts ''not a flaw.''
- C: ''transcript'' names a record, not a strategic device.
- D: ''miscalculation'' reverses the deliberate success described.', 'The word names a convenient device that achieves a goal, with the phrase ''not a flaw but a ___'' signaling something positive.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('69b6e5e2-1d05-4032-bbd7-8183760fcb67', 'Which choice completes the text with the most logical and precise word or phrase?', 'Faraday''s notebooks show a mind unwilling to ______ a result before he could reproduce it. Where rivals raced to publish a striking observation, he would repeat the experiment under altered conditions, suspecting that a single lucky outcome proved nothing. Only when the effect survived his attempts to make it vanish did he allow himself to call it real, a discipline that spared him the retractions his hastier contemporaries endured.', NULL, '[{"id":"A","text":"credit","is_correct":true,"explanation":"Refusing to believe or accept a result until reproduced is exactly being unwilling to credit it."},{"id":"B","text":"finance","is_correct":false,"explanation":"Funding has no bearing on his refusal to accept unverified results."},{"id":"C","text":"publish","is_correct":false,"explanation":"Though related, the sentence concerns internal acceptance (''before he could reproduce it''), not publication, which appears separately."},{"id":"D","text":"discard","is_correct":false,"explanation":"He withholds belief, not the result itself; discard reverses the logic."}]'::jsonb, 'A', 'Step 1 — Find the discipline
The text says only after a result survived testing did he {{yellow:allow himself to call it real}}.
Step 2 — Match the verb
"Credit," meaning to accept as true, fits his refusal to believe an unreproduced result.
Distractor analysis:
- B: ''finance'' imports an irrelevant money sense.
- C: ''publish'' is tempting but the clause concerns belief before reproduction, distinct from publishing.
- D: ''discard'' reverses the action; he withholds belief, not the data.', 'The verb means to accept as true, parallel to ''call it real'' later in the passage.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5c0f145a-d371-4a75-a53b-2ebaa03b516c', 'As used in the text, "founding" most nearly means', 'Antebellum reformers often found their movements ______ by their own success. A society organized to abolish a single evil would, once that goal seemed near, splinter into factions over what to pursue next, each certain its cause was the true heir of the founding spirit. The very unity that had made the early campaign formidable proved impossible to sustain when the original enemy began to fall.', NULL, '[{"id":"A","text":"sinking of a ship","is_correct":false,"explanation":"The maritime sense of foundering is unrelated to the movement''s origins."},{"id":"B","text":"originating","is_correct":true,"explanation":"The ''founding spirit'' is the movement''s original animating purpose, matching this sense."},{"id":"C","text":"melting of metal","is_correct":false,"explanation":"The metallurgical sense of founding has no relevance here."},{"id":"D","text":"discovering by chance","is_correct":false,"explanation":"Nothing is found accidentally; the word points to the movement''s inception."}]'::jsonb, 'B', 'Step 1 — Locate the phrase
Factions each claimed to be {{yellow:the true heir of the founding spirit}}.
Step 2 — Match the sense
The ''founding spirit'' is the original, originating purpose of the movement.
Distractor analysis:
- A: ''sinking of a ship'' confuses founding with foundering.
- C: ''melting of metal'' uses an irrelevant casting sense.
- D: ''discovering by chance'' has no support in the passage.', 'Think of the sense in ''founding members'' or ''founding spirit,'' not ships or metal.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3c6c3f51-d516-420a-b9f5-2384efe4d12e', 'Which choice completes the text with the most logical and precise word or phrase?', 'In her revisionist account of the Dutch Golden Age, the historian declines to treat its painters as untroubled celebrants of commercial wealth. The very canvases that seem to glory in heaped fruit and gleaming silver, she argues, often ______ that abundance, embedding warnings about decay and vanity within the display itself. What looks like praise, in her reading, is shadowed by reproach.', NULL, '[{"id":"A","text":"qualify","is_correct":true,"explanation":"Correct: \"qualify\" means to limit or temper a claim, matching the canvases tempering their own abundance with warnings."},{"id":"B","text":"amplify","is_correct":false,"explanation":"Incorrect: amplifying abundance contradicts the text''s point that the works undercut, not heighten, their display."},{"id":"C","text":"itemize","is_correct":false,"explanation":"Incorrect: itemizing means merely listing the contents, which ignores the embedded warning the historian stresses."},{"id":"D","text":"counterfeit","is_correct":false,"explanation":"Incorrect: counterfeit implies forgery or faking, which is unsupported and not the relationship described."}]'::jsonb, 'A', 'Step 1 — Find the tension
The paintings only "seem to glory" in wealth while {{embedding warnings about decay and vanity within the display itself}}, so they undercut their own abundance.
Step 2 — Match the word
To "qualify" abundance is to limit or temper that praise with reservations, exactly the shadowing the historian describes.
Distractor analysis:
- B: "amplify" reverses the meaning by heightening the abundance the text says is undercut.
- C: "itemize" only means to list, missing the embedded reproach.
- D: "counterfeit" introduces forgery, an idea with no support in the passage.', 'The works "seem to glory" but actually carry warnings—look for a word meaning to limit or temper a claim.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1c59cfc7-4d80-4e8c-9a8d-1ae023712e65', 'Which choice completes the text with the most logical and precise word or phrase?', 'The ecologist warned the council that the wetland''s apparent stability was misleading. Years of upstream damming had not killed the marsh outright but had quietly ______ its capacity to flush out pollutants, so that toxins now lingered where seasonal floods had once swept them away. The damage was real but had announced itself only in slow accumulation.', NULL, '[{"id":"A","text":"arrested","is_correct":true,"explanation":"Correct: \"arrested\" here means halted or checked, fitting the loss of the marsh''s flushing capacity."},{"id":"B","text":"detained","is_correct":false,"explanation":"Incorrect: detained implies temporarily holding something in place, not stopping a capacity."},{"id":"C","text":"prosecuted","is_correct":false,"explanation":"Incorrect: prosecuted is the legal sense of arrest and makes no sense applied to a capacity."},{"id":"D","text":"accelerated","is_correct":false,"explanation":"Incorrect: accelerated reverses the meaning, since the marsh lost rather than gained capacity."}]'::jsonb, 'A', 'Step 1 — Identify the effect
The damming meant {{toxins now lingered where seasonal floods had once swept them away}}, so the marsh''s cleansing capacity was stopped, not destroyed outright.
Step 2 — Match the word
"Arrested" in its sense of halted or checked captures a capacity that has been brought to a stop.
Distractor analysis:
- B: "detained" suggests holding briefly, not ending an ongoing capacity.
- C: "prosecuted" invokes the courtroom sense of arrest, which is irrelevant here.
- D: "accelerated" contradicts the loss the passage describes.', 'A common word with a secondary sense meaning ''halted'' or ''checked'' fits the loss of flushing capacity.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('30a1dc30-500a-428f-a27e-4192091178df', 'Which choice completes the text with the most logical and precise word or phrase?', 'Critics long dismissed the poet''s late work as a falling-off, all polish drained away. A recent biographer resists this verdict. The roughness, she contends, is not failure but design: having mastered smoothness early, the poet deliberately ______ his line, roughening the meter so that readers would feel each syllable''s weight rather than glide past it.', NULL, '[{"id":"A","text":"coarsened","is_correct":true,"explanation":"Correct: \"coarsened\" means made rougher, matching the deliberate roughening of the meter."},{"id":"B","text":"refined","is_correct":false,"explanation":"Incorrect: refined means smoothed, the opposite of the roughness the biographer describes."},{"id":"C","text":"abandoned","is_correct":false,"explanation":"Incorrect: he reworked his line rather than giving it up, so abandoned is unsupported."},{"id":"D","text":"shortened","is_correct":false,"explanation":"Incorrect: shortening the line is about length, not the roughness emphasized in the text."}]'::jsonb, 'A', 'Step 1 — Locate the design
The biographer says the poet was {{roughening the meter so that readers would feel each syllable''s weight}}, a deliberate move toward roughness.
Step 2 — Match the word
"Coarsened" means made rough or harsh, precisely the intended effect on the line.
Distractor analysis:
- B: "refined" reverses the meaning toward smoothness.
- C: "abandoned" wrongly says he dropped the line rather than reshaping it.
- D: "shortened" addresses length, not the roughness at issue.', 'He ''roughened the meter'' on purpose—find the verb meaning to make rougher.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bb7b5901-e7de-48e3-a7f3-9e530cbfbeda', 'As used in the text, the word "plasticity" most nearly means', 'Developmental neuroscientists once assumed the adult brain was fixed, its wiring set in youth. Studies of stroke recovery overturned that view. When one region is damaged, neighboring areas can take over its functions, a flexibility researchers credit to the brain''s enduring plasticity. The capacity to be reshaped by experience, it turns out, never fully disappears.', NULL, '[{"id":"A","text":"adaptability","is_correct":true,"explanation":"Correct: \"adaptability\" captures the brain''s capacity to be reshaped, as the text states directly."},{"id":"B","text":"artificiality","is_correct":false,"explanation":"Incorrect: artificiality concerns being synthetic, unrelated to reshaping by experience."},{"id":"C","text":"fragility","is_correct":false,"explanation":"Incorrect: fragility suggests weakness, contradicting the resilient flexibility described."},{"id":"D","text":"transparency","is_correct":false,"explanation":"Incorrect: transparency has no bearing on the capacity to be reshaped."}]'::jsonb, 'A', 'Step 1 — Use the gloss
The text defines the trait as {{The capacity to be reshaped by experience}}, which never fully disappears.
Step 2 — Match the word
"Plasticity" here names that adaptability, the brain''s ability to change and reorganize.
Distractor analysis:
- B: "artificiality" confuses the everyday plastic with neural plasticity.
- C: "fragility" contradicts the resilient recovery the passage celebrates.
- D: "transparency" is unrelated to reshaping.', 'The text itself names ''the capacity to be reshaped by experience''—pick the synonym.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7b39e8f8-ca84-4069-9602-37f0f8b54da6', 'Which choice completes the text with the most logical and precise word or phrase?', 'The diplomat''s memoir is admired less for what it reveals than for what it withholds. Faced with a crisis that might have justified fury, she chose restraint, and her prose mirrors that choice. Where another writer would rage, she ______ her judgments, cooling each accusation until it reads as measured observation rather than complaint.', NULL, '[{"id":"A","text":"tempers","is_correct":true,"explanation":"Correct: \"tempers\" means to moderate or soften, matching the cooling of accusations into measured observation."},{"id":"B","text":"forges","is_correct":false,"explanation":"Incorrect: forges concerns creating or shaping, not the moderating action the text describes."},{"id":"C","text":"hardens","is_correct":false,"explanation":"Incorrect: hardens reverses the meaning, since she softens rather than sharpens her judgments."},{"id":"D","text":"conceals","is_correct":false,"explanation":"Incorrect: she states her judgments in measured form rather than hiding them, so conceals overshoots."}]'::jsonb, 'A', 'Step 1 — Read the action
She is described as {{cooling each accusation until it reads as measured observation}}, a softening of force.
Step 2 — Match the word
"Tempers" means to moderate or soften, exactly that cooling of judgment.
Distractor analysis:
- B: "forges" suggests making or shaping, not moderating.
- C: "hardens" reverses the meaning toward sharper accusation.
- D: "conceals" claims she hides judgments, but she states them in restrained form.', 'She cools each accusation into measured observation—find the verb meaning to moderate or soften.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4fc26410-2383-4dd2-a231-d640bb8f2bab', 'Which choice completes the text with the most logical and precise word or phrase?', 'Economic historians debate why some medieval guilds endured while others vanished. One theory points to flexibility: rigid guilds, jealous of their monopolies, refused to admit new trades and slowly suffocated. The survivors, by contrast, kept their charters ______, periodically rewriting rules to absorb crafts the founders had never imagined.', NULL, '[{"id":"A","text":"elastic","is_correct":true,"explanation":"Correct: \"elastic\" means flexible and adaptable, matching charters rewritten to absorb new crafts."},{"id":"B","text":"obsolete","is_correct":false,"explanation":"Incorrect: obsolete means outdated, contradicting the surviving guilds'' adaptiveness."},{"id":"C","text":"confidential","is_correct":false,"explanation":"Incorrect: confidential concerns secrecy, irrelevant to flexibility of rules."},{"id":"D","text":"lucrative","is_correct":false,"explanation":"Incorrect: lucrative means profitable, a true-but-irrelevant trait not tied to the rewriting clue."}]'::jsonb, 'A', 'Step 1 — Find the contrast
Unlike rigid guilds, survivors were {{periodically rewriting rules to absorb crafts the founders had never imagined}}, showing flexibility.
Step 2 — Match the word
"Elastic" names that capacity to stretch and adapt, fitting charters that bend to new trades.
Distractor analysis:
- B: "obsolete" wrongly implies the charters were outdated.
- C: "confidential" introduces secrecy with no support.
- D: "lucrative" is true of guilds generally but unconnected to the rewriting clue.', 'They rewrote rules to absorb new crafts—look for a word meaning flexible or stretchable.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('79e753b8-977c-4972-a771-639203b7585f', 'Which choice completes the text with the most logical and precise word or phrase?', 'The novel''s narrator is an unreliable charmer, and reviewers warned readers not to trust his warmth. His confessions of guilt, one critic noted, are themselves a strategy: by appearing to ______ his own faults so freely, he disarms suspicion and secures the very sympathy a more guarded man would forfeit. Candor, in his hands, is a tool of manipulation.', NULL, '[{"id":"A","text":"concede","is_correct":true,"explanation":"Correct: \"concede\" means to admit or acknowledge, matching his freely confessed faults."},{"id":"B","text":"contest","is_correct":false,"explanation":"Incorrect: contest means to dispute, the opposite of the admission the text describes."},{"id":"C","text":"magnify","is_correct":false,"explanation":"Incorrect: magnify shifts to exaggeration, not the candid acknowledgment that disarms suspicion."},{"id":"D","text":"inherit","is_correct":false,"explanation":"Incorrect: inherit is unrelated; he is admitting faults, not receiving them."}]'::jsonb, 'A', 'Step 1 — Read the strategy
His "confessions of guilt" and {{Candor, in his hands, is a tool of manipulation}} show he openly admits faults to disarm doubt.
Step 2 — Match the word
To "concede" faults is to acknowledge them, the candid admission the passage centers on.
Distractor analysis:
- B: "contest" reverses the meaning toward dispute.
- C: "magnify" implies exaggeration rather than acknowledgment.
- D: "inherit" is unrelated to admitting faults.', 'His candor means openly admitting faults—find the verb meaning to acknowledge or grant.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('19c9c5b4-153a-4d79-89bf-1d76ec9b6b7c', 'Which choice completes the text with the most logical and precise word or phrase?', 'Field biologists studying alpine plants have noticed a paradox. Species crowded at a mountain''s base, where conditions are mild, often show less variety than those clinging to harsh upper slopes. Severe environments, it seems, do not merely cull the weak; they ______ diversity, since each microhabitat of rock and snow favors a slightly different survivor.', NULL, '[{"id":"A","text":"foster","is_correct":true,"explanation":"Correct: \"foster\" means to encourage or promote, matching harsh slopes generating more variety."},{"id":"B","text":"forbid","is_correct":false,"explanation":"Incorrect: forbid means to prevent, contradicting the increased diversity the text reports."},{"id":"C","text":"mimic","is_correct":false,"explanation":"Incorrect: mimic means to imitate, which does not describe the slopes producing diversity."},{"id":"D","text":"deplete","is_correct":false,"explanation":"Incorrect: deplete means to reduce, reversing the text''s claim that harsh slopes have more variety."}]'::jsonb, 'A', 'Step 1 — Track the paradox
The harsh slopes show more variety because {{each microhabitat of rock and snow favors a slightly different survivor}}, so severity promotes diversity.
Step 2 — Match the word
"Foster" means to encourage or nurture, the role severe environments play here.
Distractor analysis:
- B: "forbid" reverses the meaning by blocking diversity.
- C: "mimic" introduces imitation, which is irrelevant.
- D: "deplete" contradicts the greater variety reported on harsh slopes.', 'Each microhabitat favors a different survivor, so harsh slopes increase variety—pick the verb meaning to promote.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3ac75f9d-ee13-4744-85b7-95817ddcb009', 'As used in the text, the word "loose" most nearly means', 'The reformer''s speeches struck contemporaries as dangerously vague, but his strategists understood the design. A platform stated too precisely would alienate one faction or another; left ______, it let listeners hear their own hopes in his words. Ambiguity was not carelessness but craft, broad enough to gather a coalition that sharper language would have split.', NULL, '[{"id":"A","text":"unspecified","is_correct":true,"explanation":"Correct: \"unspecified\" fits a platform kept deliberately imprecise so listeners read their own hopes into it."},{"id":"B","text":"slack","is_correct":false,"explanation":"Incorrect: slack as in physically loose does not fit a platform''s wording."},{"id":"C","text":"immoral","is_correct":false,"explanation":"Incorrect: the moral sense of loose is unsupported by the passage about vagueness."},{"id":"D","text":"liberated","is_correct":false,"explanation":"Incorrect: liberated means freed, which misreads the intended imprecision."}]'::jsonb, 'A', 'Step 1 — Find the gloss
The platform is contrasted with one "stated too precisely"; left this way, {{it let listeners hear their own hopes in his words}}, signaling deliberate vagueness.
Step 2 — Match the word
"Loose" here means unspecified or imprecise, the quality enabling a broad coalition.
Distractor analysis:
- B: "slack" uses a physical sense that does not fit wording.
- C: "immoral" invokes the moral sense of loose, unsupported here.
- D: "liberated" misreads the term as freedom rather than imprecision.', 'A platform ''stated too precisely'' is contrasted with this—pick the meaning ''imprecise/vague.''', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e096d161-63e0-44ef-a1c5-c8adc7986458', 'Which choice completes the text with the most logical and precise word or phrase?', 'Archaeologists excavating the trading port found no grand monuments, and early reports called the site minor. A later team disagreed. The absence of palaces, they argued, was itself ______: it marked a community governed not by kings but by merchant councils, whose power left ledgers and warehouses rather than thrones. What seemed like poverty of evidence was evidence of a different order.', NULL, '[{"id":"A","text":"telling","is_correct":true,"explanation":"Correct: \"telling\" means revealing or significant, matching an absence that itself discloses the social order."},{"id":"B","text":"trivial","is_correct":false,"explanation":"Incorrect: trivial means unimportant, contradicting the team''s claim that the absence is meaningful."},{"id":"C","text":"deceptive","is_correct":false,"explanation":"Incorrect: deceptive implies the evidence misleads, but the team says it accurately reveals the order."},{"id":"D","text":"customary","is_correct":false,"explanation":"Incorrect: customary means usual, which misses the point that the absence carries specific meaning."}]'::jsonb, 'A', 'Step 1 — Read the reversal
The later team says the absence of palaces {{marked a community governed not by kings but by merchant councils}}, so the gap is meaningful.
Step 2 — Match the word
"Telling" means revealing or significant, fitting an absence that discloses the social structure.
Distractor analysis:
- B: "trivial" reverses the meaning toward unimportant.
- C: "deceptive" wrongly says the evidence misleads rather than reveals.
- D: "customary" misses the specific significance the team assigns.', 'The absence of palaces reveals a merchant-council order—find the word meaning ''significant/revealing.''', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9449e7f9-ddd8-490f-a40a-91aa2d339254', 'Which choice completes the text with the most logical and precise word or phrase?', 'In Austen''s hands, politeness is rarely innocent. Characters who master its forms can wound without ever raising their voices, folding insult into a compliment so smoothly that the victim feels the sting only later. The novel''s cruelest exchanges are the most ______ ones, conducted in tones of perfect courtesy that disguise the malice they carry.', NULL, '[{"id":"A","text":"decorous","is_correct":true,"explanation":"Correct: \"decorous\" means proper and courteous, matching cruelty disguised in perfect manners."},{"id":"B","text":"raucous","is_correct":false,"explanation":"Incorrect: raucous means loud and rough, contradicting the quiet courtesy the text emphasizes."},{"id":"C","text":"candid","is_correct":false,"explanation":"Incorrect: candid means frank, but the cruelty here is hidden, not openly stated."},{"id":"D","text":"trivial","is_correct":false,"explanation":"Incorrect: trivial means unimportant, missing that these exchanges are the cruelest."}]'::jsonb, 'A', 'Step 1 — Read the disguise
The cruelest exchanges are {{conducted in tones of perfect courtesy that disguise the malice they carry}}, so they appear most proper.
Step 2 — Match the word
"Decorous" means marked by propriety and courtesy, fitting insults wrapped in flawless manners.
Distractor analysis:
- B: "raucous" reverses the meaning toward loud and rough.
- C: "candid" implies openness, but the malice is concealed.
- D: "trivial" understates exchanges the text calls cruelest.', 'The cruelest lines use ''perfect courtesy''—pick the word meaning proper and well-mannered.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7bbcdc7d-55d2-4227-a2cc-60b57e88d2a7', 'Which choice completes the text with the most logical and precise word or phrase?', 'Public-health officials initially treated the rumor as harmless noise. The sociologist studying the outbreak disagreed: misinformation, she found, does not merely spread alongside disease but actively ______ it, since people who believe false cures abandon proven precautions. The belief, in other words, was not a side effect of the epidemic but one of its engines.', NULL, '[{"id":"A","text":"propagates","is_correct":true,"explanation":"Correct: \"propagates\" means to spread or promote, matching misinformation driving the disease forward."},{"id":"B","text":"contains","is_correct":false,"explanation":"Incorrect: contains means to limit, reversing the text''s claim that the belief fuels the epidemic."},{"id":"C","text":"chronicles","is_correct":false,"explanation":"Incorrect: chronicles means to record, but the belief acts as a cause, not a record."},{"id":"D","text":"diagnoses","is_correct":false,"explanation":"Incorrect: diagnoses concerns identifying illness, not spreading it as the text describes."}]'::jsonb, 'A', 'Step 1 — Read the mechanism
The belief is called {{one of its engines}} because people who trust false cures abandon real precautions, so it drives the disease.
Step 2 — Match the word
"Propagates" means to spread or further, fitting misinformation that actively advances the epidemic.
Distractor analysis:
- B: "contains" reverses the meaning toward limiting the disease.
- C: "chronicles" wrongly makes the belief a record rather than a cause.
- D: "diagnoses" misreads the belief as identifying illness.', 'The belief is called ''one of its engines'' that drives disease—find the verb meaning to spread or promote.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7994373f-b20c-4ee0-a5f1-45fa02bdaa9b', 'Which choice completes the text with the most logical and precise word or phrase?', 'In her late notebooks, the poet Marianne Moore returned obsessively to the work of her early years, not to celebrate it but to ______ it. She struck out adjectives she had once prized, shortened lines, and in several cases reduced an entire stanza to a single image, as though her mature taste could only be satisfied by subtraction.', NULL, '[{"id":"A","text":"pare","is_correct":true,"explanation":"Correct: the cutting of adjectives, lines, and stanzas is an act of trimming away, which ''pare'' precisely names."},{"id":"B","text":"praise","is_correct":false,"explanation":"Wrong: the text explicitly says she returned ''not to celebrate it,'' contradicting praise."},{"id":"C","text":"preserve","is_correct":false,"explanation":"Wrong: striking out and reducing material is the opposite of preserving it."},{"id":"D","text":"expand","is_correct":false,"explanation":"Wrong: ''satisfied by subtraction'' signals reduction, the reverse of expansion."}]'::jsonb, 'A', 'Step 1 — Find the action
The blank must match what Moore actually does: she ''struck out adjectives,'' ''shortened lines,'' and reduced a stanza to a single image, {{yellow:as though her mature taste could only be satisfied by subtraction}}.
Step 2 — Match the meaning
''Pare'' means to trim or cut away, which exactly captures this work of subtraction.
Distractor analysis:
- B: The text says she returned ''not to celebrate it,'' so ''praise'' contradicts the passage.
- C: ''Preserve'' reverses the meaning; she is removing material, not keeping it intact.
- D: ''Expand'' is the opposite of the ''subtraction'' the passage emphasizes.', 'The blank must match cutting adjectives, shortening lines, and ''satisfaction by subtraction.''', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fd97cd6c-52e0-4fd9-b48d-5714c06d7259', 'Which choice completes the text with the most logical and precise word or phrase?', 'The treaty''s drafters believed that listing every contingency would prevent future disputes. In practice the opposite occurred: each added clause introduced new terms whose meaning later parties contested, so that the document''s very thoroughness ______ the conflicts it was meant to forestall. Diplomats afterward favored shorter agreements, trusting general principles over exhaustive enumeration.', NULL, '[{"id":"A","text":"resolved","is_correct":false,"explanation":"Wrong: the clauses produced disputes rather than settling them, so ''resolved'' contradicts the outcome."},{"id":"B","text":"bred","is_correct":true,"explanation":"Correct: ''each added clause introduced new terms whose meaning later parties contested'' shows thoroughness generated more conflict."},{"id":"C","text":"recorded","is_correct":false,"explanation":"Wrong: merely noting conflicts is too weak; the text says thoroughness actively caused them."},{"id":"D","text":"postponed","is_correct":false,"explanation":"Wrong: the conflicts arose immediately from the added clauses, not delayed to a later time."}]'::jsonb, 'B', 'Step 1 — Track the irony
The passage says ''the opposite occurred'' and that {{yellow:each added clause introduced new terms whose meaning later parties contested}}, so thoroughness produced conflict.
Step 2 — Match the meaning
''Bred'' means to give rise to or generate, fitting a thoroughness that created the very conflicts it aimed to prevent.
Distractor analysis:
- A: ''Resolved'' reverses the result; the document caused, not settled, disputes.
- C: ''Recorded'' is too weak and passive; the text says thoroughness actively caused conflict.
- D: ''Postponed'' implies delay, but disputes arose directly from the added clauses.', '''The opposite occurred''—the thoroughness actively produced conflict, not just noted or delayed it.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cf155b37-f391-41e9-8fd8-2d0b0440d14e', 'Which choice completes the text with the most logical and precise word or phrase?', 'Critics treated the novelist''s sudden plainness as a failure of imagination, but his letters reveal a deliberate strategy. Having found that ornate prose let readers admire his sentences while ignoring his arguments, he chose a style so unadorned that nothing could ______ the reader''s attention from the ideas themselves. Simplicity, for him, was not poverty but discipline.', NULL, '[{"id":"A","text":"sharpen","is_correct":false,"explanation":"Wrong: he wanted attention fixed on ideas, not sharpened generally; this misses the diversion he feared."},{"id":"B","text":"reward","is_correct":false,"explanation":"Wrong: ''reward attention'' does not fit the danger he sought to remove."},{"id":"C","text":"divert","is_correct":true,"explanation":"Correct: ornate prose had let readers admire sentences ''while ignoring his arguments,'' so plainness prevents attention from being drawn away."},{"id":"D","text":"demand","is_correct":false,"explanation":"Wrong: nothing ''demanding'' attention is the issue; the concern is attention being pulled off the ideas."}]'::jsonb, 'C', 'Step 1 — Find the danger
Ornate prose let readers {{yellow:admire his sentences while ignoring his arguments}}, so he feared anything pulling attention away from the ideas.
Step 2 — Match the meaning
''Divert'' means to draw attention away, exactly the distraction his unadorned style was meant to eliminate.
Distractor analysis:
- A: ''Sharpen'' would aid attention, but the sentence needs a word for losing it (''nothing could ___'').
- B: ''Reward'' makes no sense as a threat the plain style removes.
- D: ''Demand'' attention is desirable, not the harm he guards against.', 'He feared style pulling attention OFF the ideas; ''nothing could ___'' needs a negative outcome.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5be5df1f-8ffb-41c0-ad26-a1ea955634bb', 'Which choice completes the text with the most logical and precise word or phrase?', 'Engineers once assumed that a bridge''s strength lay entirely in its rigidity. Modern designs reverse this premise: by allowing controlled flexion, the structure can ______ the energy of high winds and seismic shocks rather than resisting them outright. A beam that bends a little survives forces that snap a stiffer one, a lesson borrowed from the resilient stems of grasses.', NULL, '[{"id":"A","text":"absorb","is_correct":true,"explanation":"Correct: ''allowing controlled flexion'' lets the structure take in energy ''rather than resisting,'' which ''absorb'' names."},{"id":"B","text":"reflect","is_correct":false,"explanation":"Wrong: reflecting energy is a form of resisting it outright, which the design explicitly avoids."},{"id":"C","text":"generate","is_correct":false,"explanation":"Wrong: the bridge handles external energy from winds and shocks; it does not produce it."},{"id":"D","text":"measure","is_correct":false,"explanation":"Wrong: ''measure'' is true-but-irrelevant; the point is managing forces, not quantifying them."}]'::jsonb, 'A', 'Step 1 — Find the contrast
The design works by {{yellow:allowing controlled flexion}} so the structure manages energy ''rather than resisting them outright.''
Step 2 — Match the meaning
Taking energy in through bending is best named by ''absorb,'' which contrasts with rigid resistance.
Distractor analysis:
- B: ''Reflect'' bounces energy back, a kind of resistance the passage rejects.
- C: ''Generate'' wrongly makes the bridge a source of energy rather than a recipient.
- D: ''Measure'' is irrelevant; the sentence is about handling forces, not gauging them.', 'Flexion lets the structure take energy IN ''rather than resisting''—not bounce it back or create it.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('09af04a8-2705-4c44-b491-135fd44e2f44', 'As used in the text, the word "qualify" most nearly means', 'As used in the text, the word "qualify" most nearly means

The biographer is careful never to let admiration harden into worship. Whenever the evidence permits a flattering conclusion, she pauses to qualify it, noting the contradictory letter, the unflattering memoir, the inconvenient date. The portrait that emerges is dimmer than a hagiography but far more trustworthy.', NULL, '[{"id":"A","text":"certify","is_correct":false,"explanation":"Wrong: certifying would strengthen the flattering conclusion, but she undercuts it with contrary evidence."},{"id":"B","text":"limit","is_correct":true,"explanation":"Correct: she adds contradictory letters and inconvenient dates to restrict a flattering conclusion, making the portrait ''dimmer.''"},{"id":"C","text":"train","is_correct":false,"explanation":"Wrong: ''train'' is a common but irrelevant sense of qualify; nothing here concerns preparing or certifying a person."},{"id":"D","text":"praise","is_correct":false,"explanation":"Wrong: the whole point is to resist letting admiration ''harden into worship,'' so ''praise'' reverses the meaning."}]'::jsonb, 'B', 'Step 1 — Locate the behavior
When flattering conclusions arise she pauses to qualify them, {{yellow:noting the contradictory letter, the unflattering memoir, the inconvenient date}}.
Step 2 — Match the meaning
Adding such counterweights restricts or moderates the claim, so ''qualify'' here means ''limit.''
Distractor analysis:
- A: ''Certify'' would confirm the claim, but she weakens it.
- C: ''Train'' is the wrong, person-preparing sense of qualify with no support here.
- D: ''Praise'' reverses her aim of preventing admiration from hardening into worship.', 'She adds contrary evidence to flattering claims, making the portrait ''dimmer''—she restricts them.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c4eb50c3-7dd5-42ff-b9a1-37d60cbe75a3', 'As used in the text, the word "arrest" most nearly means', 'As used in the text, the word "arrest" most nearly means

The new drug does not cure the disease; in trials it merely arrested the progression of symptoms, holding patients at whatever stage they had reached when treatment began. For some this was a reprieve; for others, who started late, it meant a lifetime fixed at the threshold of severe disability.', NULL, '[{"id":"A","text":"reverse","is_correct":false,"explanation":"Wrong: patients were held ''at whatever stage they had reached,'' not improved, so reversal is contradicted."},{"id":"B","text":"detain","is_correct":false,"explanation":"Wrong: ''detain'' (a legal seizing of a person) is a different sense; here it is a process being stopped."},{"id":"C","text":"halt","is_correct":true,"explanation":"Correct: ''holding patients at whatever stage they had reached'' shows the disease''s advance was stopped, which ''halt'' names."},{"id":"D","text":"accelerate","is_correct":false,"explanation":"Wrong: accelerating progression is the opposite of holding symptoms fixed in place."}]'::jsonb, 'C', 'Step 1 — Locate the effect
The drug ''merely arrested the progression of symptoms,'' {{yellow:holding patients at whatever stage they had reached when treatment began}}.
Step 2 — Match the meaning
Holding the disease''s advance in place means stopping it, so ''arrest'' here means ''halt.''
Distractor analysis:
- A: ''Reverse'' would mean improvement, but patients merely stayed fixed.
- B: ''Detain'' is the legal sense applied to people, not a process being stopped.
- D: ''Accelerate'' is the contradiction; progression was stopped, not sped up.', 'Symptoms were held at their current stage—not reversed, sped up, or a person seized.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1f4fd149-2f5a-4710-86d3-06e6df9081f4', 'As used in the text, the word "plastic" most nearly means', 'As used in the text, the word "plastic" most nearly means

Neuroscientists once believed the adult brain was essentially fixed, its circuits set in youth. Studies of stroke recovery overturned this view: deprived of a damaged region, the surrounding tissue reorganizes, recruiting neighboring cells to assume lost functions. The mature brain, it turns out, remains remarkably plastic, reshaping itself in response to injury and demand.', NULL, '[{"id":"A","text":"synthetic","is_correct":false,"explanation":"Wrong: ''synthetic'' invokes the material sense of plastic, irrelevant to brain tissue''s adaptability."},{"id":"B","text":"adaptable","is_correct":true,"explanation":"Correct: the brain ''reorganizes'' and reshapes ''in response to injury and demand,'' which ''adaptable'' captures."},{"id":"C","text":"fragile","is_correct":false,"explanation":"Wrong: the passage stresses resilient reorganization, not fragility."},{"id":"D","text":"rigid","is_correct":false,"explanation":"Wrong: ''rigid'' matches the old ''fixed'' view the studies overturned, the reverse of the intended meaning."}]'::jsonb, 'B', 'Step 1 — Locate the behavior
The surrounding tissue ''reorganizes,'' and the brain remains plastic, {{yellow:reshaping itself in response to injury and demand}}.
Step 2 — Match the meaning
Reshaping in response to circumstances is the mark of being ''adaptable.''
Distractor analysis:
- A: ''Synthetic'' is the material sense of plastic, with no support here.
- C: ''Fragile'' contradicts the resilient recovery the passage describes.
- D: ''Rigid'' restates the discredited ''fixed'' view, the opposite of the new finding.', 'The brain reorganizes and reshapes itself—it is flexible, the opposite of the old ''fixed'' view.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0ba6f6bf-9bf3-457d-90e8-74bda1f859cf', 'As used in the text, the word "temper" most nearly means', 'As used in the text, the word "temper" most nearly means

The editor''s gift was for balance. Where a young writer''s prose ran to either icy detachment or feverish sentiment, she would temper the excess, cooling the overheated passages and warming the cold ones until the whole achieved an even, habitable tone. Her authors rarely noticed the adjustment, only that their work read better.', NULL, '[{"id":"A","text":"moderate","is_correct":true,"explanation":"Correct: ''cooling the overheated passages and warming the cold ones'' to an ''even'' tone is the act of moderating extremes."},{"id":"B","text":"strengthen","is_correct":false,"explanation":"Wrong: she reduces excess to achieve balance, not intensify it."},{"id":"C","text":"harden","is_correct":false,"explanation":"Wrong: ''harden'' draws on the metallurgical sense of temper, irrelevant to softening prose extremes."},{"id":"D","text":"shorten","is_correct":false,"explanation":"Wrong: nothing in the text concerns length; the adjustment is to tone, not size."}]'::jsonb, 'A', 'Step 1 — Locate the action
Facing extremes of detachment or sentiment, she would temper the excess, {{yellow:cooling the overheated passages and warming the cold ones}} toward an even tone.
Step 2 — Match the meaning
Bringing both extremes toward an even middle is to ''moderate'' them.
Distractor analysis:
- B: ''Strengthen'' would heighten the excess she is reducing.
- C: ''Harden'' is the metallurgy sense of temper, unsupported here.
- D: ''Shorten'' concerns length, but the passage is about tone.', 'She cools the hot and warms the cold toward an ''even'' tone—softening extremes, not length.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('959a1e3d-85a8-4f79-82db-ba118042b8b4', 'Which choice completes the text with the most logical and precise word or phrase?', 'Historians of cartography note that early maps of unexplored coasts were rarely blank where knowledge failed. Instead, mapmakers ______ the gaps, filling them with plausible bays and mountains inferred from sailors'' rumors. These confident fabrications, copied from chart to chart, often hardened into accepted geography long before any expedition confirmed or refuted them.', NULL, '[{"id":"A","text":"omitted","is_correct":false,"explanation":"Wrong: the maps were ''rarely blank,'' and mapmakers filled gaps, so they did not omit them."},{"id":"B","text":"surveyed","is_correct":false,"explanation":"Wrong: surveying implies real measurement, but these features were invented from rumor."},{"id":"C","text":"conjectured","is_correct":true,"explanation":"Correct: ''filling them with plausible bays and mountains inferred from sailors'' rumors'' is conjecture, supplying features by guesswork."},{"id":"D","text":"erased","is_correct":false,"explanation":"Wrong: erasing contradicts the act of adding invented features to the gaps."}]'::jsonb, 'C', 'Step 1 — Find the method
Rather than leaving gaps blank, mapmakers filled them {{yellow:with plausible bays and mountains inferred from sailors'' rumors}}.
Step 2 — Match the meaning
Supplying features by inference and rumor is to ''conjecture'' them, fitting ''confident fabrications.''
Distractor analysis:
- A: ''Omitted'' contradicts ''rarely blank'' and the filling of gaps.
- B: ''Surveyed'' implies real measurement, but the features were invented.
- D: ''Erased'' reverses the act of adding inferred features.', 'They filled gaps with invented features from rumor—supplying them by guesswork, not real measurement.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e52cb8f9-8cfe-4104-973b-7e8d19885a94', 'Which choice completes the text with the most logical and precise word or phrase?', 'The committee praised the report for its candor, but a closer reading shows how artfully its frankness was ______. Each admission of failure was paired with a mitigating circumstance, each criticism immediately softened by a note of progress, so that the appearance of honesty cost the authors almost nothing. It confessed much and conceded little.', NULL, '[{"id":"A","text":"calculated","is_correct":true,"explanation":"Correct: admissions paired with mitigations so honesty ''cost almost nothing'' shows the frankness was deliberately engineered."},{"id":"B","text":"spontaneous","is_correct":false,"explanation":"Wrong: ''artfully'' and the careful pairing of each admission contradict spontaneity."},{"id":"C","text":"insufficient","is_correct":false,"explanation":"Wrong: the report ''confessed much''; the issue is its design, not the amount of candor."},{"id":"D","text":"forced","is_correct":false,"explanation":"Wrong: nothing suggests compulsion; the candor was strategically chosen, not coerced."}]'::jsonb, 'A', 'Step 1 — Find the design
The frankness was ''artfully'' managed: {{yellow:Each admission of failure was paired with a mitigating circumstance}}, so honesty cost almost nothing.
Step 2 — Match the meaning
Such deliberate engineering of candor for minimal cost is best named ''calculated.''
Distractor analysis:
- B: ''Spontaneous'' contradicts ''artfully'' and the careful pairing.
- C: ''Insufficient'' misreads; the report ''confessed much,'' so candor was not lacking.
- D: ''Forced'' implies coercion, but the frankness was strategically chosen.', '''Artfully''—each admission was paired with a softening note so honesty cost nothing. It was engineered.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('880ea1e7-b859-41f3-bfbc-af1fdebe704d', 'As used in the text, the word "check" most nearly means', 'As used in the text, the word "check" most nearly means

In a healthy republic, the framers argued, no single branch should act unopposed. The legislature''s ambition would meet the executive''s resistance, and the judiciary would in turn check both, so that each power, straining against the others, kept the whole machine from lurching toward tyranny. Friction, paradoxically, was the guarantee of liberty.', NULL, '[{"id":"A","text":"verify","is_correct":false,"explanation":"Wrong: ''verify'' is a common sense of check but ignores the passage''s theme of opposing power."},{"id":"B","text":"restrain","is_correct":true,"explanation":"Correct: branches ''straining against the others'' to keep the machine from tyranny shows the judiciary holds the others back."},{"id":"C","text":"inspect","is_correct":false,"explanation":"Wrong: inspection is passive examination, not the active counterforce the passage describes."},{"id":"D","text":"abandon","is_correct":false,"explanation":"Wrong: ''abandon'' contradicts the active opposition that ''check'' supplies among the branches."}]'::jsonb, 'B', 'Step 1 — Locate the dynamic
The judiciary checks both other branches, with {{yellow:each power, straining against the others}}, keeping the machine from tyranny.
Step 2 — Match the meaning
This active opposition that holds power back is what ''check'' means here: ''restrain.''
Distractor analysis:
- A: ''Verify'' ignores the theme of opposing power.
- C: ''Inspect'' is passive examination, not active counterforce.
- D: ''Abandon'' reverses the opposition the branches exert.', 'Branches ''strain against'' each other to prevent tyranny—the judiciary holds the others back.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('02b10003-8447-4881-95a9-cad4ed9d82f0', 'Which choice completes the text with the most logical and precise word or phrase?', 'The philosopher distrusted systems that explained everything, for a theory immune to contradiction struck her as empty rather than profound. A claim that no possible observation could ______ was, she insisted, not a triumph of reasoning but a withdrawal from it: by ruling out every test, it forfeited any right to be believed. Better a fragile truth than an unfalsifiable one.', NULL, '[{"id":"A","text":"confirm","is_correct":false,"explanation":"Wrong: the problem is a claim that cannot be tested against evidence; ''confirm'' misses that it also rules out refutation."},{"id":"B","text":"refute","is_correct":true,"explanation":"Correct: a claim ''immune to contradiction'' that ''no possible observation could'' refute is exactly the unfalsifiable theory she rejects."},{"id":"C","text":"interest","is_correct":false,"explanation":"Wrong: ''interest'' is no-evidence synthesis; the issue is testability, not whether observations are interesting."},{"id":"D","text":"complicate","is_correct":false,"explanation":"Wrong: complication is unrelated to the falsifiability standard the passage builds."}]'::jsonb, 'B', 'Step 1 — Find the standard
She distrusts a theory ''immune to contradiction'' and prefers a ''fragile truth than an unfalsifiable one,'' since such a claim is {{yellow:a withdrawal from it: by ruling out every test}}.
Step 2 — Match the meaning
A claim no observation could refute is unfalsifiable, exactly her target, so ''refute'' fits.
Distractor analysis:
- A: ''Confirm'' misses the point; the flaw is that nothing could disprove the claim.
- C: ''Interest'' concerns appeal, not the testability standard.
- D: ''Complicate'' is unrelated to falsifiability.', '''Immune to contradiction'' and ''unfalsifiable''—the blank needs a word for what no observation could do: disprove.', 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('519d1739-9a22-4455-ae27-6109c85e9b00', 'Which choice best describes the overall structure of the text?', 'For decades, the small desert town of Aldous relied on a single underground spring for its water. Residents assumed the spring would never run dry, so they planted thirsty crops and built backyard pools. Then, after three drought years, the spring''s flow dropped sharply. Suddenly the town faced a choice it had ignored for generations: change how it lived or watch its water disappear. The crisis forced Aldous to confront a question that abundance had long allowed it to avoid.', NULL, '[{"id":"A","text":"It presents a long-held assumption and then describes an event that overturned it.","is_correct":true,"explanation":"Correct: the text states the comfortable assumption, then shows the drought that disrupted it."},{"id":"B","text":"It compares two desert towns that responded differently to drought.","is_correct":false,"explanation":"Only one town, Aldous, is discussed; no second town appears."},{"id":"C","text":"It lists several solutions the town adopted to conserve water.","is_correct":false,"explanation":"No solutions are listed; the text ends with an unresolved choice."},{"id":"D","text":"It argues that all desert towns will eventually run out of water.","is_correct":false,"explanation":"The text makes no general prediction about all desert towns."}]'::jsonb, 'A', 'Step 1 — Find the setup
The text first establishes the assumption: {{yellow:Residents assumed the spring would never run dry}}.
Step 2 — Find the reversal
The drought that dropped the flow overturns that belief, so the structure moves from a long-held assumption to the event that disrupted it.
Distractor analysis:
- B: Only Aldous is discussed; there is no second town to compare.
- C: No conservation solutions are listed; the passage ends on an unresolved choice.
- D: The text never predicts the fate of all desert towns; that is no-evidence synthesis.', 'Notice what the residents believed at the start versus what the drought revealed.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('055a31c7-c279-49ea-9d24-d98bd5eaaa5d', 'Which choice best describes the overall structure of the text?', 'The painter Iris Vance was long dismissed as a minor talent who merely copied her famous teacher. Recently, however, scholars examining her notebooks have found detailed sketches predating her teacher''s most celebrated works. These drawings suggest that several techniques credited to the teacher may have originated with Vance herself. While the evidence is not yet conclusive, it has prompted historians to reconsider whose innovations they have been celebrating all along.', NULL, '[{"id":"A","text":"It introduces a conventional view of an artist and then presents evidence that challenges it.","is_correct":true,"explanation":"Correct: the dismissive view is stated, then the notebooks provide evidence undermining it."},{"id":"B","text":"It traces the entire career of an artist from training to fame.","is_correct":false,"explanation":"No full career is traced; the text focuses on one reassessment."},{"id":"C","text":"It proves that Vance was a greater painter than her teacher.","is_correct":false,"explanation":"The text says the evidence is not conclusive, so nothing is proven."},{"id":"D","text":"It explains why artists often copy their teachers.","is_correct":false,"explanation":"The text does not generalize about why artists copy teachers."}]'::jsonb, 'A', 'Step 1 — Identify the established view
The text opens with the standard judgment: {{yellow:Iris Vance was long dismissed as a minor talent who merely copied her famous teacher}}.
Step 2 — Identify the challenge
The newly examined notebooks provide evidence that complicates that view, so the structure presents a conventional view and then evidence challenging it.
Distractor analysis:
- B: The passage does not trace a full career; it centers on one reassessment.
- C: It explicitly calls the evidence not conclusive, so nothing is proven.
- D: It makes no general claim about why artists copy their teachers.', 'Track the shift signaled by the word "however."', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e2ab86a9-bf5c-4652-9977-8a984806372b', 'Which choice best states the main purpose of the text?', 'Many people picture honeybees as the planet''s essential pollinators, the insects without which our crops would fail. It is true that honeybees pollinate many plants. Yet wild bees, flies, beetles, and even some birds quietly do enormous amounts of pollination too, often more efficiently than honeybees for certain plants. Focusing only on honeybees, researchers warn, can hide the importance of these lesser-known pollinators and the threats they face.', NULL, '[{"id":"A","text":"To broaden a common view of pollination by highlighting overlooked contributors.","is_correct":true,"explanation":"Correct: the text widens the honeybee-only picture to include other pollinators."},{"id":"B","text":"To prove that honeybees do not pollinate any crops.","is_correct":false,"explanation":"The text affirms that honeybees pollinate many plants, contradicting this."},{"id":"C","text":"To describe the life cycle of a typical wild bee.","is_correct":false,"explanation":"No life cycle is described."},{"id":"D","text":"To recommend that farmers stop relying on honeybees entirely.","is_correct":false,"explanation":"The text gives no recommendation to abandon honeybees."}]'::jsonb, 'A', 'Step 1 — Spot the common view
The text begins with the popular belief, then pivots: {{yellow:wild bees, flies, beetles, and even some birds quietly do enormous amounts of pollination too}}.
Step 2 — Connect to purpose
By adding these overlooked pollinators to the honeybee-only image, the text broadens a common view of pollination.
Distractor analysis:
- B: The text affirms honeybees pollinate many plants, contradicting this option.
- C: No life cycle of any insect is described.
- D: It never recommends that farmers abandon honeybees.', 'Ask what the text adds to the popular image of honeybees.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c34a5bda-5591-4f10-9329-97cae8e019d2', 'Which choice best describes the overall structure of the text?', 'When the new bridge opened across the Calder River, planners celebrated the shorter commute it offered. What they did not anticipate was how the bridge would reshape the town beyond traffic. Shops sprang up near the crossing, neighborhoods that had felt remote suddenly attracted families, and the old ferry landing fell silent. A project measured in saved minutes ended up redrawing the social map of the entire community.', NULL, '[{"id":"A","text":"It notes a project''s intended benefit and then describes its broader, unforeseen effects.","is_correct":true,"explanation":"Correct: the planned shorter commute is stated, then wider unexpected changes follow."},{"id":"B","text":"It lists the engineering steps required to build a bridge.","is_correct":false,"explanation":"No engineering steps are described."},{"id":"C","text":"It warns that the bridge harmed the town''s economy.","is_correct":false,"explanation":"The text describes growth, not harm, to the economy."},{"id":"D","text":"It compares the bridge with the old ferry''s efficiency.","is_correct":false,"explanation":"The ferry''s efficiency is never measured or compared."}]'::jsonb, 'A', 'Step 1 — Identify the intended benefit
The text opens with the goal: planners {{yellow:celebrated the shorter commute it offered}}.
Step 2 — Identify the wider effects
It then details unforeseen changes that redrew the social map, so the structure moves from intended benefit to broader unforeseen effects.
Distractor analysis:
- B: No engineering or construction steps are described.
- C: The town gains shops and families, so the effects are growth, not harm.
- D: The ferry is mentioned but its efficiency is never compared.', 'Compare what planners expected with what actually happened to the town.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f6fa11d4-9fe1-40c9-a145-0ad23085e1cf', 'Which choice best states the main purpose of the text?', 'In ancient Rome, public baths were often imagined as simple places to wash. In reality, they functioned as bustling social centers. Citizens met there to discuss business, exchange gossip, exercise, and even hear poetry read aloud. A wealthy senator and a common laborer might soak in the same pool. For many Romans, the baths were less about cleanliness than about belonging to the daily life of the city.', NULL, '[{"id":"A","text":"To correct a narrow impression of Roman baths by describing their wider social role.","is_correct":true,"explanation":"Correct: it replaces the wash-only image with the baths'' broader social functions."},{"id":"B","text":"To explain the plumbing technology used in Roman baths.","is_correct":false,"explanation":"No plumbing or technology is discussed."},{"id":"C","text":"To argue that Roman baths were unhygienic.","is_correct":false,"explanation":"The text does not claim the baths were unhygienic."},{"id":"D","text":"To compare Roman baths with modern gyms.","is_correct":false,"explanation":"No modern comparison appears in the text."}]'::jsonb, 'A', 'Step 1 — Identify the narrow impression
The text opens with the simple image, then pivots: {{yellow:they functioned as bustling social centers}}.
Step 2 — Connect to purpose
By detailing business, gossip, exercise, and poetry, the text corrects a narrow impression with the baths'' wider social role.
Distractor analysis:
- B: No plumbing or building technology is mentioned.
- C: The text never claims the baths were unhygienic.
- D: There is no comparison to modern gyms or any modern facility.', 'What everyday assumption about baths does the text push back against?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5c94bbb9-3801-4dad-b131-faeb7f7dc36d', 'Which choice best describes the overall structure of the text?', 'The young scientist had spent two years expecting her experiment to confirm a popular theory about how certain cells store energy. Instead, every trial pointed the other way. At first she suspected her equipment was faulty and repeated the tests again and again. Only after the same surprising result appeared a dozen times did she accept that the theory itself, not her method, might be wrong. Her doubt slowly hardened into a discovery.', NULL, '[{"id":"A","text":"It traces a researcher''s shift from doubting her own work to questioning an accepted theory.","is_correct":true,"explanation":"Correct: she first blames her equipment, then comes to doubt the theory itself."},{"id":"B","text":"It explains how cells store energy in detail.","is_correct":false,"explanation":"The mechanism of energy storage is never explained."},{"id":"C","text":"It describes how the scientist designed her equipment.","is_correct":false,"explanation":"Equipment design is not described, only suspicion that it was faulty."},{"id":"D","text":"It celebrates a theory that her experiment confirmed.","is_correct":false,"explanation":"Her results contradicted the theory rather than confirming it."}]'::jsonb, 'A', 'Step 1 — Locate the initial doubt
The scientist first turns suspicion on herself: {{yellow:At first she suspected her equipment was faulty}}.
Step 2 — Locate the shift
After repeated results she instead doubts the theory, so the structure traces a shift from doubting her own work to questioning the accepted theory.
Distractor analysis:
- B: The actual mechanism of energy storage is never explained.
- C: Equipment design is not described; she only suspects faults.
- D: Her results contradicted the theory, so nothing is confirmed.', 'Notice what she suspected first and what she eventually accepted.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5b245623-64e9-452b-89c6-54172e1c6a9e', 'Which choice best states the main purpose of the text?', 'Maps once showed a vast blank space across the center of a certain continent, labeled simply "unknown." Travelers filled this emptiness with rumors of golden cities and impassable swamps. As explorers and, later, local guides shared firsthand accounts, the blank slowly filled with rivers, villages, and trade routes. The mysterious gap had never been empty at all; it had only been empty on European maps.', NULL, '[{"id":"A","text":"To suggest that a region''s apparent emptiness reflected the limits of mapmakers, not the land itself.","is_correct":true,"explanation":"Correct: the closing line shows the gap was an absence of knowledge, not of people."},{"id":"B","text":"To describe the golden cities discovered in the continent''s center.","is_correct":false,"explanation":"The golden cities are rumors, not described discoveries."},{"id":"C","text":"To explain how to draw an accurate map.","is_correct":false,"explanation":"No mapmaking instructions are given."},{"id":"D","text":"To argue that early travelers were more reliable than later guides.","is_correct":false,"explanation":"The text credits guides with filling in real detail, reversing this claim."}]'::jsonb, 'A', 'Step 1 — Find the key reversal
The text ends by reframing the blank: {{yellow:it had only been empty on European maps}}.
Step 2 — Connect to purpose
That line shows the emptiness reflected mapmakers'' ignorance, not the land, which is the main purpose.
Distractor analysis:
- B: The golden cities are merely rumors, never described as real discoveries.
- C: The text gives no instructions for drawing maps.
- D: It credits later guides with real detail, contradicting this option.', 'Pay attention to the final sentence''s twist on the word "empty."', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c81058b6-957f-4db8-a388-995b53b5337a', 'Which choice best describes the overall structure of the text?', 'At first glance, the novel seems to be a simple adventure story about a sailor crossing a stormy sea. As the chapters unfold, though, the storms come to mirror the sailor''s inner turmoil, and the distant shore he seeks stands for a peace he cannot find within himself. By the final page, the voyage reads less like a journey across water than a journey through a troubled mind.', NULL, '[{"id":"A","text":"It begins with a surface reading of a novel and then reveals a deeper, symbolic meaning.","is_correct":true,"explanation":"Correct: the literal adventure gives way to a symbolic reading of inner turmoil."},{"id":"B","text":"It summarizes the plot events of the novel in order.","is_correct":false,"explanation":"It interprets the novel rather than recounting plot events."},{"id":"C","text":"It criticizes the novel for being too simple.","is_correct":false,"explanation":"The text praises the novel''s depth rather than criticizing it."},{"id":"D","text":"It compares the novel with another sea adventure.","is_correct":false,"explanation":"No other novel is mentioned for comparison."}]'::jsonb, 'A', 'Step 1 — Identify the surface reading
The text opens literally: the novel {{yellow:seems to be a simple adventure story about a sailor crossing a stormy sea}}.
Step 2 — Identify the deeper reading
It then reads the storms and shore as symbols of inner turmoil, moving from surface to symbolic meaning.
Distractor analysis:
- B: The text interprets symbolism rather than listing plot events in order.
- C: It admires the novel''s depth and never calls it too simple.
- D: No second novel appears, so there is no comparison.', 'Watch how the meaning deepens from a literal voyage to something inner.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7320b0f6-6a2f-472c-bc24-5e73517b75b2', 'Which choice best describes the overall structure of the text?', 'For years, city planners treated stormwater as a nuisance to be flushed away as quickly as possible through concrete channels. A new approach turns this thinking around. Instead of rushing water out, designers now build gardens, ponds, and permeable pavements that slow water down and let it soak into the ground. What was once a problem to be removed is increasingly seen as a resource to be kept.', NULL, '[{"id":"A","text":"It contrasts an older method of handling stormwater with a newer, opposite approach.","is_correct":true,"explanation":"Correct: flushing water away is set against designs that slow and keep it."},{"id":"B","text":"It lists the materials used to build concrete channels.","is_correct":false,"explanation":"No list of channel-building materials appears."},{"id":"C","text":"It argues that stormwater can never be controlled.","is_correct":false,"explanation":"The text describes successful new control methods, contradicting this."},{"id":"D","text":"It explains how rain forms in the atmosphere.","is_correct":false,"explanation":"Rain formation is not discussed."}]'::jsonb, 'A', 'Step 1 — Identify the older method
The text first describes the traditional view: stormwater as {{yellow:a nuisance to be flushed away as quickly as possible}}.
Step 2 — Identify the new approach
It then describes designs that slow and keep water, so the structure contrasts an older method with a newer, opposite approach.
Distractor analysis:
- B: No materials for concrete channels are listed.
- C: The new methods control water effectively, contradicting this option.
- D: The text never explains how rain forms.', 'Set the old "flush it away" idea against the new "keep it" idea.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('471ef7b8-e62b-4272-963b-c471a08176c3', 'Which choice best states the main purpose of the text?', 'The diary of a colonial shopkeeper is often read for its lists of goods and prices. Yet between these entries lie brief notes about weather, illness, and quarrels with neighbors. Read together, these scattered remarks offer something the ledgers alone cannot: a glimpse of daily worry and hope in a small town. The account book, it turns out, doubles as a quiet record of one ordinary life.', NULL, '[{"id":"A","text":"To suggest that a business record also preserves a personal portrait of its keeper.","is_correct":true,"explanation":"Correct: the ledger''s stray notes reveal an ordinary life beyond the numbers."},{"id":"B","text":"To list the goods and prices recorded in the diary.","is_correct":false,"explanation":"The text mentions such lists but does not provide them."},{"id":"C","text":"To argue that colonial shopkeepers were unusually wealthy.","is_correct":false,"explanation":"Wealth is never discussed."},{"id":"D","text":"To explain how to keep an accurate account book.","is_correct":false,"explanation":"No bookkeeping instructions are given."}]'::jsonb, 'A', 'Step 1 — Find the reframing
The text shifts from prices to personal notes: {{yellow:a glimpse of daily worry and hope in a small town}}.
Step 2 — Connect to purpose
That glimpse shows the business record also preserves a personal portrait of its keeper, the main purpose.
Distractor analysis:
- B: The text refers to lists of goods and prices but never provides them.
- C: The shopkeeper''s wealth is never discussed.
- D: No instructions for bookkeeping are given.', 'Consider what the diary reveals beyond its goods and prices.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('847f90d9-c7ab-4f6a-8299-0db74eae6dae', 'Which choice best states the main purpose of the text?', 'Volcanic eruptions are usually remembered for the destruction they cause. The ash that buries fields and darkens skies, however, breaks down over time into unusually rich soil. Centuries after an eruption, the slopes around a volcano often hold some of the most fertile farmland in a region. The same force that ruins a landscape can, given enough time, renew it.', NULL, '[{"id":"A","text":"To qualify a common view of volcanoes by noting a long-term benefit of their eruptions.","is_correct":true,"explanation":"Correct: it tempers the destruction image with the eventual fertility of volcanic soil."},{"id":"B","text":"To explain the chemical makeup of volcanic ash in detail.","is_correct":false,"explanation":"No chemical makeup is detailed."},{"id":"C","text":"To warn farmers against settling near volcanoes.","is_correct":false,"explanation":"The text notes the farmland is fertile, not that settling is unwise."},{"id":"D","text":"To prove that eruptions cause no lasting harm.","is_correct":false,"explanation":"The text acknowledges destruction, so it does not deny harm."}]'::jsonb, 'A', 'Step 1 — Identify the common view
The text starts with destruction, then adds a benefit: ash {{yellow:breaks down over time into unusually rich soil}}.
Step 2 — Connect to purpose
That benefit qualifies the common view of volcanoes by noting a long-term advantage.
Distractor analysis:
- B: The chemical makeup of ash is never detailed.
- C: The text highlights fertile farmland, not a warning to avoid volcanoes.
- D: It openly acknowledges destruction, so it does not deny lasting harm.', 'Notice the "however" that adds an upside to the usual image of eruptions.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9f7397c4-683d-4a37-9625-81560e8d2a78', 'Which choice best states the main purpose of the text?', 'It is tempting to assume that the loudest voice in a meeting holds the most influence. Studies of group decisions suggest otherwise. Often the quietest member, by listening carefully and speaking only at the right moment, shapes the final choice more than anyone who dominated the conversation. Influence, these findings remind us, is not always measured by how much a person talks.', NULL, '[{"id":"A","text":"To challenge a common assumption about how influence works in groups.","is_correct":true,"explanation":"Correct: it disputes the idea that the loudest voice is the most influential."},{"id":"B","text":"To advise readers to stay silent during all meetings.","is_correct":false,"explanation":"The text praises well-timed speech, not total silence."},{"id":"C","text":"To describe how meetings are typically scheduled.","is_correct":false,"explanation":"Meeting scheduling is never mentioned."},{"id":"D","text":"To prove that loud people are usually wrong.","is_correct":false,"explanation":"The text does not claim loud people are wrong, only less influential than assumed."}]'::jsonb, 'A', 'Step 1 — Identify the assumption
The text opens with the tempting belief, then counters it: {{yellow:the quietest member ... shapes the final choice more than anyone who dominated the conversation}}.
Step 2 — Connect to purpose
That counterexample challenges a common assumption about how influence works in groups.
Distractor analysis:
- B: The text values well-timed speaking, not staying silent in all meetings.
- C: How meetings are scheduled is never mentioned.
- D: It never claims loud people are wrong, only that they are less influential than assumed.', 'Find the belief the studies are said to overturn.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9a97e56d-9938-4402-9651-dfd298f2fbe9', 'Which choice best describes the overall structure of the text?', 'For decades, the small desert town of Aldous relied on a single railway line to ship its harvested salt to distant markets. When the line was abandoned in the 1970s, many residents feared the town would empty out entirely. Instead, something unexpected happened. Artists, drawn by the cheap empty warehouses and the strange beauty of the dry flats, began arriving. Today, Aldous hosts a celebrated annual sculpture festival, and its population has tripled. The very feature that once seemed like a death sentence, its remoteness, has become the engine of its revival.', NULL, '[{"id":"A","text":"It presents a town''s apparent decline and then reverses that expectation by describing an unforeseen recovery.","is_correct":true,"explanation":"Correct: the text moves from feared emptying out to an unexpected revival, matching the rhetorical shift."},{"id":"B","text":"It compares two desert towns to argue that remoteness always harms growth.","is_correct":false,"explanation":"Wrong: only one town is discussed, and the text shows remoteness helping, not harming."},{"id":"C","text":"It traces the technical history of a railway line and its construction methods.","is_correct":false,"explanation":"Wrong: the railway is mentioned only as background, not as the focus."},{"id":"D","text":"It catalogs the artworks displayed at an annual sculpture festival.","is_correct":false,"explanation":"Wrong: the festival is named once and never described in detail."}]'::jsonb, 'A', 'Step 1 — Spot the shift
The passage sets up a fear that the town would empty out, then signals a turn with {{yellow:Instead, something unexpected happened}}.
Step 2 — Match the structure
The text first establishes an apparent decline, then reverses that expectation with an unforeseen recovery, so A is correct.
Distractor analysis:
- B: No second town is compared, and the text shows remoteness helping the town, a reversal of the claim.
- C: The railway is only background; no construction methods are discussed.
- D: The festival is mentioned but no artworks are cataloged.', 'Notice the word that signals a turn, then ask what changes before and after it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3c07035f-0ea7-40ed-9ba2-a6555660dbab', 'Which choice best states the main purpose of the text?', 'Honeybees were long assumed to navigate purely by the position of the sun, adjusting their flight as the sun moved across the sky. This explanation seemed complete until researchers noticed that bees could still find their way on heavily overcast days when the sun was invisible. Closer study revealed that bees also read patterns of polarized light scattered across the sky, an invisible compass humans cannot perceive. The discovery did not overturn the earlier view so much as enlarge it, showing that the bees'' navigation rests on more than one source of information.', NULL, '[{"id":"A","text":"To argue that the sun plays no role in how honeybees navigate.","is_correct":false,"explanation":"Wrong: the text says the discovery enlarged rather than overturned the sun-based view."},{"id":"B","text":"To explain how an accepted explanation was expanded by a new finding about bee navigation.","is_correct":true,"explanation":"Correct: the text shows the polarized-light finding enlarging the earlier sun-based view."},{"id":"C","text":"To describe the physical structure of a honeybee''s eye in detail.","is_correct":false,"explanation":"Wrong: no anatomy of the eye is described."},{"id":"D","text":"To warn that overcast weather endangers honeybee colonies.","is_correct":false,"explanation":"Wrong: the text never claims overcast weather is dangerous."}]'::jsonb, 'B', 'Step 1 — Find the key claim
The passage states the new finding {{yellow:did not overturn the earlier view so much as enlarge it}}.
Step 2 — Match the purpose
Because the discovery expands rather than replaces the accepted explanation, B captures the text''s purpose.
Distractor analysis:
- A: The sun''s role is enlarged, not eliminated, so this contradicts the text.
- C: The eye''s structure is never detailed.
- D: No danger from overcast weather is claimed; bees navigate fine in it.', 'Watch whether the new finding replaces the old idea or adds to it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bd01d1ab-ac11-45fa-8ad0-340bc41241c6', 'Which choice best describes the overall structure of the text?', 'In her debut novel, the narrator describes her grandmother''s kitchen in loving, almost reverent detail: the worn wooden spoons, the jars of spices labeled in a careful hand, the steam rising from a pot that always seemed to be simmering. For three pages, the prose lingers on these images as though time has stopped. Then, in a single sentence, the narrator notes that the house was sold years ago and the kitchen no longer exists. The abrupt closing line transforms the warm description into an act of mourning.', NULL, '[{"id":"A","text":"It offers a recipe and then evaluates how well the dish turned out.","is_correct":false,"explanation":"Wrong: no recipe or dish evaluation appears."},{"id":"B","text":"It lists complaints about an old house before proposing renovations.","is_correct":false,"explanation":"Wrong: the description is affectionate, not a list of complaints."},{"id":"C","text":"It develops an affectionate description that a closing detail recasts as grief.","is_correct":true,"explanation":"Correct: the warm description is transformed into mourning by the final line."},{"id":"D","text":"It argues that family kitchens should be preserved as historical sites.","is_correct":false,"explanation":"Wrong: the text makes no preservation argument."}]'::jsonb, 'C', 'Step 1 — Locate the turn
The passage builds warm imagery, then the final detail makes clear {{yellow:the kitchen no longer exists}}.
Step 2 — Match the structure
The affectionate description is recast as grief by that closing detail, so C is correct.
Distractor analysis:
- A: There is no recipe or evaluation of a dish.
- B: The tone is loving, not a list of complaints.
- D: No argument for preservation is made.', 'Ask how the last sentence changes the meaning of everything before it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('65a9102a-30f4-4355-9e59-fe273984f35c', 'Which choice best states the main purpose of the text?', 'When the printing press spread across Europe in the late fifteenth century, scholars often praised it as a tool that would simply make existing books cheaper and easier to copy. At first glance, that view seems reasonable. Yet the press did far more than reproduce old texts. By allowing identical copies to circulate widely, it let readers in different cities compare the very same page and point to the very same line, making large-scale scholarly debate possible for the first time. The press did not merely copy knowledge; it changed how knowledge could be discussed.', NULL, '[{"id":"A","text":"To qualify a common view of the printing press by showing its deeper effect on scholarship.","is_correct":true,"explanation":"Correct: the text grants the common view, then refines it to a deeper effect."},{"id":"B","text":"To list the materials used to build early printing presses.","is_correct":false,"explanation":"Wrong: no materials or construction details are given."},{"id":"C","text":"To prove that printed books were always cheaper than handwritten ones.","is_correct":false,"explanation":"Wrong: cost is mentioned only as the limited view the text moves beyond."},{"id":"D","text":"To argue that the printing press had no effect on scholarly debate.","is_correct":false,"explanation":"Wrong: the text says the press made large-scale debate possible."}]'::jsonb, 'A', 'Step 1 — Identify the concession and turn
The passage admits the cheaper-copies view, then asserts the press {{yellow:did far more than reproduce old texts}}.
Step 2 — Match the purpose
Granting a common view and refining it to a deeper effect is a qualification, so A is correct.
Distractor analysis:
- B: No construction materials are listed.
- C: Cost is the limited view the text moves past, not the point being proved.
- D: The text credits the press with enabling debate, the opposite of this.', 'Look for where the text accepts a view and then adds something more important.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('df509a52-6f03-4996-843e-a2b05c9c2699', 'Which choice best describes the overall structure of the text?', 'The tiny tardigrade, often called a water bear, looks almost comically harmless under a microscope, with its plump body and stubby legs. One might assume such a soft creature could survive only in gentle conditions. The truth is startling. Tardigrades can endure being frozen near absolute zero, boiled, crushed by deep-sea pressure, and even exposed to the vacuum of space. They achieve this by drying themselves into a dormant state in which their metabolism nearly halts. Far from fragile, the water bear is among the toughest animals known to science.', NULL, '[{"id":"A","text":"It raises a question about tardigrade reproduction and then answers it with new data.","is_correct":false,"explanation":"Wrong: reproduction is never discussed."},{"id":"B","text":"It sets up an assumption of fragility and then overturns it with evidence of extreme toughness.","is_correct":true,"explanation":"Correct: the harmless appearance is contradicted by the creature''s extreme durability."},{"id":"C","text":"It compares tardigrades to deep-sea fish to rank their survival skills.","is_correct":false,"explanation":"Wrong: no comparison to deep-sea fish is drawn."},{"id":"D","text":"It explains why tardigrades are dangerous to human health.","is_correct":false,"explanation":"Wrong: no danger to humans is mentioned."}]'::jsonb, 'B', 'Step 1 — Find the contrast
The passage notes the creature looks harmless but warns {{yellow:The truth is startling}}.
Step 2 — Match the structure
The assumption of fragility is overturned by evidence of extreme survival, so B is correct.
Distractor analysis:
- A: Reproduction is never mentioned.
- C: There is no comparison with deep-sea fish.
- D: No threat to human health is claimed.', 'Contrast the creature''s appearance with what the evidence actually shows.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('29120f04-6951-4216-ad8e-7f72db14d34f', 'Which choice best states the main purpose of the text?', 'Early maps of the ocean floor were drawn as if it were a flat, featureless plain, a vast muddy bottom stretching uniformly between continents. This picture went largely unquestioned because no one had a way to see beneath the deep water. The invention of sonar changed everything. Echoes bouncing off the seabed revealed towering underwater mountain ranges, deep trenches, and vast volcanic ridges. The ocean floor, it turned out, was as varied and dramatic as any landscape above the waves, a discovery that reshaped how scientists understood the planet.', NULL, '[{"id":"A","text":"To explain how a new technology replaced a mistaken picture of the ocean floor.","is_correct":true,"explanation":"Correct: sonar overturns the flat-plain image with a varied seabed."},{"id":"B","text":"To describe the daily routine of scientists who operate sonar equipment.","is_correct":false,"explanation":"Wrong: no daily routine is described."},{"id":"C","text":"To argue that the ocean floor is in fact mostly flat after all.","is_correct":false,"explanation":"Wrong: the text says the floor is varied and dramatic."},{"id":"D","text":"To list the names of major underwater trenches.","is_correct":false,"explanation":"Wrong: no specific trenches are named."}]'::jsonb, 'A', 'Step 1 — Spot the turning point
The passage describes the flat-plain belief, then states {{yellow:The invention of sonar changed everything}}.
Step 2 — Match the purpose
Sonar replaces the mistaken flat image with a varied seabed, so A captures the purpose.
Distractor analysis:
- B: No daily routine of scientists is described.
- C: The text contradicts this by revealing a dramatic, varied floor.
- D: No trenches are named specifically.', 'Find the sentence where a tool changes the old understanding.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('711c0601-950a-4932-8cc5-8ca205ec506e', 'Which choice best describes the overall structure of the text?', 'The new community library was designed to look impressive: a soaring glass atrium, a sweeping staircase, a wall of windows facing the plaza. Visitors admired the architecture in their first moments inside. But residents who came to actually read soon noticed a problem. The glare from all that glass made screens hard to see, the open atrium carried every footstep as an echo, and there was nowhere quiet to sit. The building, it seemed, had been designed to be photographed rather than used.', NULL, '[{"id":"A","text":"It praises a library''s design and recommends copying it elsewhere.","is_correct":false,"explanation":"Wrong: the text ends in criticism, not recommendation."},{"id":"B","text":"It introduces a building''s admired appearance and then details how it fails its users.","is_correct":true,"explanation":"Correct: the admired design is followed by practical failures for readers."},{"id":"C","text":"It traces the funding history of a community library project.","is_correct":false,"explanation":"Wrong: funding is never mentioned."},{"id":"D","text":"It compares two competing architectural firms'' proposals.","is_correct":false,"explanation":"Wrong: only one building is discussed."}]'::jsonb, 'B', 'Step 1 — Find the pivot
The passage admires the architecture, then turns with the complaint that {{yellow:residents who came to actually read soon noticed a problem}}.
Step 2 — Match the structure
The admired appearance is followed by an account of how it fails its users, so B is correct.
Distractor analysis:
- A: The text criticizes rather than recommends the design.
- C: No funding history is given.
- D: Only one building, not two firms'' proposals, is discussed.', 'Separate what visitors admired from what readers complained about.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('88a766ef-3f38-4b7f-b9d6-cda44d0cd824', 'Which choice best states the main purpose of the text?', 'In the play''s opening scene, the young king speaks with easy confidence, boasting that no rival could ever shake his throne. His courtiers nod and flatter him. The audience, however, has just watched a hooded messenger slip offstage carrying news the king has not yet heard. Every proud word the king utters is therefore shadowed by what we know and he does not. The scene''s power comes not from the king''s speech itself but from the gap between his certainty and the danger already moving toward him.', NULL, '[{"id":"A","text":"To analyze how a scene creates tension through the audience''s superior knowledge.","is_correct":true,"explanation":"Correct: the text locates the scene''s power in the gap between what the audience and king know."},{"id":"B","text":"To summarize the entire plot of the play from beginning to end.","is_correct":false,"explanation":"Wrong: only the opening scene is discussed."},{"id":"C","text":"To praise the actor who plays the young king.","is_correct":false,"explanation":"Wrong: no actor or performance is mentioned."},{"id":"D","text":"To criticize the king''s courtiers for flattering him.","is_correct":false,"explanation":"Wrong: the courtiers are background, not the focus of criticism."}]'::jsonb, 'A', 'Step 1 — Find the source of effect
The passage states the scene''s power comes from {{yellow:the gap between his certainty and the danger already moving toward him}}.
Step 2 — Match the purpose
That gap depends on the audience knowing more than the king, so A captures the purpose.
Distractor analysis:
- B: Only the opening scene is treated, not the whole plot.
- C: No actor is mentioned.
- D: The courtiers are background detail, not the target of the text.', 'Ask what the audience knows that the character does not, and why that matters.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('39d970f8-72d7-4c63-81c6-fe748854e9ff', 'Which choice best describes the overall structure of the text?', 'When the city first proposed planting trees along its busiest avenue, some officials objected that the project was merely decorative, a pleasant touch with no real benefit. Studies conducted after the planting told a different story. The rows of trees lowered summer temperatures on the sidewalk by several degrees, absorbed runoff during storms, and even reduced traffic noise for nearby apartments. What had been dismissed as ornamental turned out to deliver measurable practical gains for the people living along the street.', NULL, '[{"id":"A","text":"It describes a dismissive view of a project and then counters it with measured benefits.","is_correct":true,"explanation":"Correct: the decorative dismissal is countered by practical, measured gains."},{"id":"B","text":"It explains the biology of how trees absorb water and sound.","is_correct":false,"explanation":"Wrong: no biological mechanism is explained."},{"id":"C","text":"It argues that cities should stop planting trees on busy streets.","is_correct":false,"explanation":"Wrong: the text shows benefits, supporting planting."},{"id":"D","text":"It compares the costs of trees with the costs of streetlights.","is_correct":false,"explanation":"Wrong: no cost comparison appears."}]'::jsonb, 'A', 'Step 1 — Find the contrast
Officials called the project {{yellow:merely decorative}}, but studies told a different story.
Step 2 — Match the structure
The dismissive view is countered by measured practical benefits, so A is correct.
Distractor analysis:
- B: No biological mechanism for absorption is explained.
- C: The text supports planting by showing benefits.
- D: No cost comparison with streetlights is made.', 'Contrast the initial objection with what the studies later found.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8892fb82-e9c4-47ee-bb41-5f082773485f', 'Which choice best states the main purpose of the text?', 'The diary of the frontier teacher begins with brisk, businesslike entries: how many students attended, what lessons were taught, how much firewood remained. These early pages read like a simple record of duties. As the winter deepens, though, the entries change. The teacher begins writing about loneliness, about the silence of the snowbound prairie, about doubts she had never put into words before. By spring, the diary has become less a logbook than a quiet confession of an inner life she had not known she would reveal.', NULL, '[{"id":"A","text":"To trace how a diary shifts from a record of duties into a personal confession.","is_correct":true,"explanation":"Correct: the text follows the diary''s change from logbook to confession."},{"id":"B","text":"To describe the curriculum taught in frontier schools.","is_correct":false,"explanation":"Wrong: lessons are mentioned only as early, businesslike entries."},{"id":"C","text":"To explain the causes of harsh prairie winters.","is_correct":false,"explanation":"Wrong: weather is a setting detail, not the subject."},{"id":"D","text":"To argue that diaries are more reliable than official records.","is_correct":false,"explanation":"Wrong: no claim about reliability is made."}]'::jsonb, 'A', 'Step 1 — Find the shift
The diary starts as a simple record but by spring becomes {{yellow:a quiet confession of an inner life she had not known she would reveal}}.
Step 2 — Match the purpose
The text traces that movement from logbook of duties to personal confession, so A is correct.
Distractor analysis:
- B: The curriculum is only the early, businesslike content, not the focus.
- C: Winter is setting, not the explained subject.
- D: No comparison of reliability is made.', 'Notice how the diary''s content changes from the first pages to the last.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bd179944-bd0a-478d-9e16-13715c06b3af', 'Which choice best describes the overall structure of the text?', 'It is tempting to think of the smartphone as a wholly modern invention, a sudden leap that arrived in the early 2000s. But each of its core features has a long history. The touchscreen traces back to laboratory experiments of the 1960s; portable telephones were tested decades before they became common; even the idea of a pocket computer appeared in mid-century science writing. Seen this way, the smartphone is less a single burst of genius than the gathering of many older threads into one device.', NULL, '[{"id":"A","text":"It predicts which features future smartphones will include.","is_correct":false,"explanation":"Wrong: the text looks backward, not to future features."},{"id":"B","text":"It challenges the idea of the smartphone as sudden by tracing its features to older origins.","is_correct":true,"explanation":"Correct: the sudden-leap view is corrected by showing long histories for each feature."},{"id":"C","text":"It ranks smartphone brands by their technical achievements.","is_correct":false,"explanation":"Wrong: no brands are ranked."},{"id":"D","text":"It explains how to repair a smartphone touchscreen.","is_correct":false,"explanation":"Wrong: no repair instructions appear."}]'::jsonb, 'B', 'Step 1 — Find the correction
The text grants the tempting view, then concludes the smartphone is {{yellow:the gathering of many older threads into one device}}.
Step 2 — Match the structure
It challenges the sudden-invention idea by tracing each feature''s older origins, so B is correct.
Distractor analysis:
- A: The text examines the past, not future features.
- C: No brands are ranked.
- D: No repair instructions are given.', 'Contrast the ''sudden leap'' idea with what the histories of each feature show.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('950765b7-4d01-44c0-aadf-8003d8f34d2a', 'Which choice best states the main purpose of the text?', 'The senator''s speech opened with a familiar appeal to tradition, reminding the chamber of laws passed by earlier generations. For several minutes she seemed to be defending the existing system without reservation. Then her tone sharpened. She argued that honoring those earlier lawmakers meant continuing their work, not freezing it, and that they themselves had once overturned the customs of their own elders. By the close, her tribute to the past had become a call to change it, using respect for tradition as the very ground for reform.', NULL, '[{"id":"A","text":"To describe a speech that turns reverence for tradition into an argument for change.","is_correct":true,"explanation":"Correct: the tribute to the past becomes the basis for reform."},{"id":"B","text":"To list the specific laws the senator wanted to repeal.","is_correct":false,"explanation":"Wrong: no specific laws are named."},{"id":"C","text":"To argue that tradition should never be questioned.","is_correct":false,"explanation":"Wrong: the speech uses tradition to justify change, the opposite."},{"id":"D","text":"To compare the senator''s speaking style with that of earlier lawmakers.","is_correct":false,"explanation":"Wrong: no comparison of speaking styles is made."}]'::jsonb, 'A', 'Step 1 — Find the reversal
The speech opens defending tradition, then by the close her {{yellow:tribute to the past had become a call to change it}}.
Step 2 — Match the purpose
The text describes how reverence for tradition is turned into an argument for reform, so A is correct.
Distractor analysis:
- B: No specific laws are listed.
- C: The speech uses tradition to argue for change, contradicting this.
- D: No comparison of speaking styles appears.', 'Watch how respect for the past becomes the reason for change by the end.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('eb7b6b0c-2ef0-4f28-b5c2-f97e54de9f8f', 'Which choice best describes the overall structure of the text?', 'For decades, the axolotl was viewed mainly as a biological curiosity, a salamander that never outgrows its larval form. Today, however, the animal occupies a central place in laboratories worldwide. Researchers prize it for an unusual talent: it can regrow lost limbs, parts of its heart, and even sections of its brain. By studying how axolotl cells reactivate growth programs that most adult animals shut down, scientists hope to uncover principles that might one day inform human regenerative medicine.', NULL, '[{"id":"A","text":"It contrasts an older perception of an animal with its current scientific importance.","is_correct":true,"explanation":"Correct: the text moves from how the axolotl \"was viewed\" to the contrasting \"Today, however\" view of its scientific value."},{"id":"B","text":"It catalogs the full range of species capable of regenerating lost organs.","is_correct":false,"explanation":"Too broad: the text discusses only the axolotl, not a full range of species."},{"id":"C","text":"It argues that human regenerative medicine has already been transformed by axolotl research.","is_correct":false,"explanation":"Reverse/overstated: the text says scientists \"hope to uncover principles\" for the future, not that medicine is already transformed."},{"id":"D","text":"It explains the precise molecular steps by which axolotl cells rebuild a limb.","is_correct":false,"explanation":"No evidence: the text mentions regrowth but never details precise molecular steps."}]'::jsonb, 'A', 'Step 1 — Spot the shift
The text opens with how the axolotl "was viewed mainly as a biological curiosity" and then pivots with {{yellow:Today, however, the animal occupies a central place in laboratories worldwide}}.
Step 2 — Match the structure
That pivot sets an outdated perception against the creature''s present scientific importance, which choice A names precisely.
Distractor analysis:
- B: Too broad; only the axolotl is discussed, not a range of species.
- C: Reverse/overstated; researchers only "hope" to apply findings, so medicine is not already transformed.
- D: No evidence; the passage never lays out precise molecular steps.', 'Notice the turn signaled by "Today, however" and what it sets the old view against.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c0ac0ace-902a-45d2-afa7-5acc3441e37e', 'Which choice best describes the overall structure of the text?', 'In her debut novel, the narrator describes her childhood home as a place of comfort: warm kitchens, familiar voices, a garden she knew by heart. Midway through the chapter, though, her tone tightens. The same rooms begin to feel like a cage, the familiar voices like a chorus reminding her of who she is expected to become. By the final page, she packs a single suitcase, less in anger than in quiet resolve to discover a self the house could never contain.', NULL, '[{"id":"A","text":"It traces a shift in how the narrator experiences a single setting, ending in a decision.","is_correct":true,"explanation":"Correct: the home moves from comfort to confinement, and the narrator finally resolves to leave."},{"id":"B","text":"It compares the narrator''s home with the homes of other characters in the novel.","is_correct":false,"explanation":"No evidence: only the narrator''s home is described, not others''."},{"id":"C","text":"It explains the historical reasons families left rural homes for cities.","is_correct":false,"explanation":"True-but-irrelevant/no evidence: the text is personal narrative, not historical explanation."},{"id":"D","text":"It celebrates the lasting comfort the narrator finds within her childhood home.","is_correct":false,"explanation":"Contradiction: the home comes to feel like \"a cage,\" and she leaves it."}]'::jsonb, 'A', 'Step 1 — Track the change
The home first offers comfort, then {{yellow:The same rooms begin to feel like a cage}}, ending as she "packs a single suitcase."
Step 2 — Match the structure
The passage reframes one setting from comfort to confinement and closes on a decision to leave, exactly what choice A states.
Distractor analysis:
- B: No evidence; no other characters'' homes appear.
- C: True-but-irrelevant; this is personal narrative, not historical analysis.
- D: Contradiction; the home becomes a cage and she departs.', 'Watch how the feeling about the same rooms changes and where the narrator ends up.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8e84f290-f13f-4de3-b21a-31eb6fe790b3', 'Which choice best describes the overall structure of the text?', 'Conventional wisdom long held that the Great Wall of China was built all at once by a single emperor. The historical record tells a more layered story. Sections were raised by rival states centuries before unification, then connected, abandoned, rebuilt, and extended by successive dynasties over more than a thousand years. What we call "the" Great Wall is really a patchwork of walls, reflecting shifting borders, materials, and military needs across many eras.', NULL, '[{"id":"A","text":"It corrects a common misconception by presenting a more complicated history.","is_correct":true,"explanation":"Correct: the text replaces the \"all at once by a single emperor\" belief with a layered, multi-era account."},{"id":"B","text":"It ranks the dynasties according to how much wall each one constructed.","is_correct":false,"explanation":"No evidence: the text never ranks dynasties by amount built."},{"id":"C","text":"It defends the conventional view that one emperor built the entire wall.","is_correct":false,"explanation":"Reverse: the text refutes that view rather than defending it."},{"id":"D","text":"It describes the building materials used in a single section of the wall.","is_correct":false,"explanation":"Too narrow: the text spans many eras and walls, not one section''s materials."}]'::jsonb, 'A', 'Step 1 — Identify the claim being challenged
The text names a belief, then signals correction: {{yellow:The historical record tells a more layered story}}.
Step 2 — Match the structure
It overturns the single-builder myth with a complex multi-dynasty history, which choice A captures.
Distractor analysis:
- B: No evidence; no ranking of dynasties appears.
- C: Reverse; the text refutes, not defends, the one-emperor view.
- D: Too narrow; the focus is the whole layered history, not one section''s materials.', 'Find the sentence that signals the simple belief is being replaced.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2da3237c-707a-4802-9bb6-8c6cf558d3cc', 'Which choice best states the main purpose of the text?', 'It is tempting to assume that a louder advertisement is a more effective one. A recent study of online video ads complicates that assumption. While attention-grabbing volume did boost the number of viewers who noticed an ad, it also increased the number who skipped it within two seconds. The researchers caution that, for now, their findings apply only to short online clips and should not be stretched into a universal rule about advertising.', NULL, '[{"id":"A","text":"To present a study that qualifies a common assumption about advertising.","is_correct":true,"explanation":"Correct: the study both complicates the louder-is-better belief and limits its own scope."},{"id":"B","text":"To prove that loud advertisements are always less effective than quiet ones.","is_correct":false,"explanation":"Overstated: loud ads increased notice, so they are not \"always\" worse, and the study refuses universal claims."},{"id":"C","text":"To explain the technical methods used to measure ad volume.","is_correct":false,"explanation":"No evidence: the text never describes measurement methods."},{"id":"D","text":"To recommend that companies stop using online video advertising.","is_correct":false,"explanation":"No evidence: no recommendation to abandon online video is made."}]'::jsonb, 'A', 'Step 1 — Find the limiting move
The study both complicates the assumption and warns it {{yellow:should not be stretched into a universal rule about advertising}}.
Step 2 — Match the purpose
Presenting findings that complicate but also restrict a common belief is exactly to qualify that assumption, as choice A says.
Distractor analysis:
- B: Overstated; loud ads raised notice, and the text rejects universal claims.
- C: No evidence; methods are never described.
- D: No evidence; no call to stop online advertising appears.', 'The closing caution about scope hints at an abstract verb meaning ''to limit.''', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('dbeb0e90-4fa5-49b5-aeeb-de3a1f327336', 'Which choice best describes the overall structure of the text?', 'Honeybees are often celebrated as tireless workers, yet a single bee''s contribution can seem almost trivial. One forager may visit only a few hundred flowers in a day and produce a fraction of a teaspoon of honey in her lifetime. The colony''s power lies elsewhere: in coordination. Thousands of bees, each performing modest tasks and sharing information through dance, together pollinate vast fields and sustain a hive that no individual could maintain alone.', NULL, '[{"id":"A","text":"It contrasts the small output of one bee with the collective achievement of the colony.","is_correct":true,"explanation":"Correct: the text sets a single bee''s tiny contribution against what \"thousands of bees\" accomplish together."},{"id":"B","text":"It explains the chemical process by which bees convert nectar into honey.","is_correct":false,"explanation":"No evidence: no chemical process is described."},{"id":"C","text":"It argues that individual bees are more important than the colony as a whole.","is_correct":false,"explanation":"Reverse: the text emphasizes the colony''s collective power, not the individual."},{"id":"D","text":"It lists the dangers that threaten honeybee populations worldwide.","is_correct":false,"explanation":"No evidence: threats to bees are never mentioned."}]'::jsonb, 'A', 'Step 1 — Locate the pivot
After noting one bee''s trivial output, the text turns: {{yellow:The colony''s power lies elsewhere: in coordination}}.
Step 2 — Match the structure
That pivot contrasts an individual''s small contribution with the colony''s collective achievement, as choice A states.
Distractor analysis:
- B: No evidence; no chemistry of honey-making is given.
- C: Reverse; the colony, not the individual, is shown to matter most.
- D: No evidence; threats to bees are not discussed.', 'Compare what one bee does with what ''thousands of bees'' do together.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('26ab3da1-5bbf-4a0f-87fc-be59c281615f', 'Which choice best describes the overall structure of the text?', 'Maria''s grandmother had always spoken of the village fountain as the heart of town. When Maria finally visited, she expected something grand. Instead she found a small, weathered basin, its stone worn smooth, half-hidden behind a market stall. Yet as the afternoon passed, she watched neighbors pause there to gossip, children splash, and an old man fill his jug. Slowly she understood: the fountain mattered not for its size but for the lives that gathered around it.', NULL, '[{"id":"A","text":"It moves from a character''s disappointed expectation to a deeper understanding.","is_correct":true,"explanation":"Correct: Maria expects grandeur, finds a modest basin, then realizes its true significance."},{"id":"B","text":"It describes the engineering used to build old village fountains.","is_correct":false,"explanation":"No evidence: no engineering details appear."},{"id":"C","text":"It compares Maria''s village with the city where she grew up.","is_correct":false,"explanation":"No evidence: no city or comparison of two places is presented."},{"id":"D","text":"It argues that grand monuments are more meaningful than small ones.","is_correct":false,"explanation":"Contradiction: the text concludes the small fountain matters because of the people, not its size."}]'::jsonb, 'A', 'Step 1 — Find the realization
Maria expects grandeur but ends by grasping that {{yellow:the fountain mattered not for its size but for the lives that gathered around it}}.
Step 2 — Match the structure
The passage travels from a let-down expectation to a richer understanding, exactly what choice A describes.
Distractor analysis:
- B: No evidence; no engineering is mentioned.
- C: No evidence; no comparison to a city appears.
- D: Contradiction; the text values the small fountain for its community, not grandeur.', 'Track Maria''s expectation and what she finally comes to see.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('820ea941-707c-4daa-abfb-e5465be9ef12', 'Which choice best states the main purpose of the text?', 'Most people picture a desert as an endless expanse of empty sand. Biologists who study deserts see something quite different. Beneath the surface and within the brief windows after rain, deserts teem with seeds, dormant microbes, and animals that emerge only at night. Far from barren, these landscapes are finely tuned ecosystems whose inhabitants have evolved remarkable strategies for surviving heat and scarcity.', NULL, '[{"id":"A","text":"To challenge a popular image of deserts by emphasizing their hidden life.","is_correct":true,"explanation":"Correct: it sets the common ''empty sand'' picture against deserts that \"teem\" with life."},{"id":"B","text":"To compare the plant species of two different deserts.","is_correct":false,"explanation":"No evidence: no two deserts are compared."},{"id":"C","text":"To warn that deserts are spreading because of climate change.","is_correct":false,"explanation":"No evidence: desert spread or climate change is never mentioned."},{"id":"D","text":"To describe one night in the life of a single desert animal.","is_correct":false,"explanation":"Too narrow: the text spans whole ecosystems, not one animal''s night."}]'::jsonb, 'A', 'Step 1 — Identify the contrast
The common image is set against the biologists'' view: {{yellow:Far from barren, these landscapes are finely tuned ecosystems}}.
Step 2 — Match the purpose
The text exists to overturn the empty-desert picture by revealing hidden life, as choice A states.
Distractor analysis:
- B: No evidence; no two deserts are compared.
- C: No evidence; climate change and desert spread are absent.
- D: Too narrow; the focus is whole ecosystems, not one animal.', 'What popular picture does the passage push back against?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e8492e0b-1f75-4ae9-bc77-6a34a699a6c6', 'Which choice best states the main purpose of the text?', 'The inventor Granville Woods is sometimes remembered for a single device, but such a label undersells him. Over his career he secured dozens of patents covering telegraph systems, electrical brakes, and equipment that let moving trains communicate with stations. Before discussing any one invention in detail, it helps to recognize the sheer breadth of his work, which touched nearly every part of late nineteenth-century rail and communication technology.', NULL, '[{"id":"A","text":"To establish the wide range of an inventor''s work before any single device is examined.","is_correct":true,"explanation":"Correct: the text frames Woods''s broad output as context preceding closer discussion."},{"id":"B","text":"To explain in detail how Woods''s electrical brake operated.","is_correct":false,"explanation":"No evidence: no single device is explained in detail; the text precedes that."},{"id":"C","text":"To argue that Woods deserves credit for inventions made by others.","is_correct":false,"explanation":"No evidence: the text never claims others'' inventions for Woods."},{"id":"D","text":"To compare Woods''s patents with those of a rival inventor.","is_correct":false,"explanation":"No evidence: no rival inventor is mentioned."}]'::jsonb, 'A', 'Step 1 — Find the framing move
The text signals it is setting context: {{yellow:Before discussing any one invention in detail, it helps to recognize the sheer breadth of his work}}.
Step 2 — Match the purpose
That sentence establishes the scope of Woods''s output ahead of any closer look, which is exactly choice A.
Distractor analysis:
- B: No evidence; no device is explained in detail here.
- C: No evidence; the text never credits others'' work to him.
- D: No evidence; no rival inventor appears.', 'The phrase ''before discussing any one invention'' tells you what the text is doing first.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fb10cb86-9e71-494e-b1cf-875f85eb9941', 'Which choice best describes the overall structure of the text?', 'When the printing press reached a region, people often assumed books would simply become cheaper copies of what scribes had made by hand. The effects ran deeper. As identical texts spread widely, readers in distant towns could compare the same passages, spot errors, and debate ideas across borders. The press did more than lower costs; it created a shared body of knowledge that earlier, handwritten culture had never made possible.', NULL, '[{"id":"A","text":"It moves past a limited assumption to describe a more far-reaching effect.","is_correct":true,"explanation":"Correct: the text replaces the ''cheaper copies'' view with the press''s deeper effect of shared knowledge."},{"id":"B","text":"It explains the mechanical workings of an early printing press.","is_correct":false,"explanation":"No evidence: the machine''s mechanics are never described."},{"id":"C","text":"It claims the press had no greater effect than lowering book prices.","is_correct":false,"explanation":"Contradiction: the text says the press \"did more than lower costs.\""},{"id":"D","text":"It lists the regions the printing press reached in chronological order.","is_correct":false,"explanation":"No evidence: no chronological list of regions appears."}]'::jsonb, 'A', 'Step 1 — Spot the deepening claim
The text sets aside the cheaper-copies idea: {{yellow:The press did more than lower costs}}.
Step 2 — Match the structure
It moves beyond a narrow assumption to a broader effect, the shared body of knowledge, as choice A states.
Distractor analysis:
- B: No evidence; no mechanical workings are given.
- C: Contradiction; the text explicitly says the press did more than lower costs.
- D: No evidence; no chronological list of regions appears.', 'Find where the text says the press did more than the assumed thing.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('72f1c5d2-6ed3-429b-98f8-b9abd12ea107', 'Which choice best states the main purpose of the text?', 'Sleep is easy to dismiss as wasted time, hours simply lost to unconsciousness. Neuroscience suggests the opposite. During sleep, the brain consolidates memories, clears metabolic waste, and strengthens the connections that learning depends on. In this view, a night''s rest is not a pause in the day''s important work but one of the most productive stretches of it.', NULL, '[{"id":"A","text":"To overturn a dismissive view of sleep by presenting evidence of its function.","is_correct":true,"explanation":"Correct: the ''wasted time'' view is refuted by sleep''s active roles in the brain."},{"id":"B","text":"To recommend an ideal number of hours people should sleep each night.","is_correct":false,"explanation":"No evidence: no recommended sleep duration is given."},{"id":"C","text":"To describe the stages a sleeper passes through over a night.","is_correct":false,"explanation":"No evidence: sleep stages are not described."},{"id":"D","text":"To argue that memory consolidation also occurs while a person is awake.","is_correct":false,"explanation":"No evidence: the text ties consolidation to sleep, not waking."}]'::jsonb, 'A', 'Step 1 — Identify the reversal
The dismissive view meets a counter: {{yellow:a night''s rest is not a pause in the day''s important work but one of the most productive stretches of it}}.
Step 2 — Match the purpose
The text overturns the ''wasted time'' idea using evidence of sleep''s brain functions, exactly choice A.
Distractor analysis:
- B: No evidence; no ideal hours are recommended.
- C: No evidence; sleep stages are not described.
- D: No evidence; consolidation is tied to sleep, not waking.', 'What dismissive idea about sleep does the neuroscience reverse?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('50a4ec68-fa61-4cfa-95e9-8ae670ca3a60', 'Which choice best describes the overall structure of the text?', 'After the war, the small nation faced a familiar choice: rebuild its shattered factories exactly as they had been, or use the moment to start anew. Its leaders chose the harder path. Rather than restoring outdated mills, they invested in new industries, retrained workers, and rewrote trade agreements. The decision was risky and unpopular at first, but within a generation the country had transformed a crisis into the foundation of lasting prosperity.', NULL, '[{"id":"A","text":"It presents a choice a nation faced and traces the outcome of the path it took.","is_correct":true,"explanation":"Correct: the text lays out two options, notes the harder one was chosen, and follows its results."},{"id":"B","text":"It compares the recoveries of several nations after the same war.","is_correct":false,"explanation":"No evidence: only one nation''s recovery is discussed."},{"id":"C","text":"It argues that rebuilding factories exactly as before is always best.","is_correct":false,"explanation":"Contradiction: the nation rejected exact rebuilding and succeeded."},{"id":"D","text":"It lists the specific trade agreements the nation rewrote.","is_correct":false,"explanation":"Too narrow: trade agreements are mentioned once, not listed in detail."}]'::jsonb, 'A', 'Step 1 — Find the decision
The nation faced two options and {{yellow:Its leaders chose the harder path}}, then reaped lasting prosperity.
Step 2 — Match the structure
The text frames a choice and traces the consequences of the chosen path, as choice A states.
Distractor analysis:
- B: No evidence; only one nation is discussed.
- C: Contradiction; exact rebuilding was rejected and the new path succeeded.
- D: Too narrow; trade agreements are noted, not catalogued.', 'Identify the two options and follow what happened after one was picked.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a68d870e-4cd3-4e52-84ef-7119203bc514', 'Which choice best states the main purpose of the text?', 'Photographs are often treated as neutral records, as if a camera simply captures whatever stands before it. A closer look unsettles that idea. Every photograph reflects countless choices: where to point the lens, what to leave out of frame, when to press the shutter, how to light the scene. Far from passive mirrors, photographs are shaped at each step by the person making them, framing reality as much as recording it.', NULL, '[{"id":"A","text":"To complicate the idea that photographs are neutral records of reality.","is_correct":true,"explanation":"Correct: it sets the ''neutral record'' view against photographs as shaped by human choices."},{"id":"B","text":"To explain how camera lenses focus light onto film.","is_correct":false,"explanation":"No evidence: lens optics are not explained."},{"id":"C","text":"To trace the history of photography from its earliest inventors.","is_correct":false,"explanation":"No evidence: no history of photography is given."},{"id":"D","text":"To argue that photographs are completely useless as records.","is_correct":false,"explanation":"Overstated: the text says photographs record as well as frame, not that they are useless."}]'::jsonb, 'A', 'Step 1 — Locate the challenge
The neutral-record view is unsettled: {{yellow:Far from passive mirrors, photographs are shaped at each step by the person making them}}.
Step 2 — Match the purpose
The text exists to complicate the idea that photographs neutrally record reality, exactly choice A.
Distractor analysis:
- B: No evidence; lens optics are not explained.
- C: No evidence; no history of photography is given.
- D: Overstated; the text says photos record as well as frame, not that they are useless.', 'What assumption about photos being ''neutral'' does the text push back on?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('818f0e8f-fb0c-4b65-8b61-29eeb54df2fd', 'Which choice best describes the overall structure of the text?', 'For decades, biographers portrayed the poet Marianne Voss as a recluse who shunned public life entirely, citing her decision to leave the city at twenty-five. This image hardened into legend, repeated in every introduction to her collected works. Yet a cache of letters discovered in a relative''s attic complicates the story. In them, Voss corresponds warmly with dozens of editors, attends literary salons during frequent return visits, and even brokers publishing deals for younger writers. The recluse, it turns out, was an energetic networker who simply preferred to write in the quiet of the countryside. The legend, convenient and tidy, had obscured a far more sociable woman.', NULL, '[{"id":"A","text":"It presents a widely held characterization and then qualifies it using newly discovered evidence.","is_correct":true,"explanation":"Correct: the text states the recluse legend, then uses the discovered letters to revise it."},{"id":"B","text":"It describes a poet''s career and ranks her achievements against those of her contemporaries.","is_correct":false,"explanation":"No ranking against contemporaries occurs; the focus is on correcting an image."},{"id":"C","text":"It argues that biographers should never rely on a subject''s private correspondence.","is_correct":false,"explanation":"Reverse: the letters are used to improve the account, not dismissed."},{"id":"D","text":"It traces the gradual process by which Voss withdrew from public life.","is_correct":false,"explanation":"The text shows she did not actually withdraw, contradicting this option."}]'::jsonb, 'A', 'Step 1 — Identify the established view
The text opens with the legend that {{yellow:biographers portrayed the poet Marianne Voss as a recluse who shunned public life entirely}}.
Step 2 — Note the revision
The discovered letters show she was an energetic networker, so the text qualifies the earlier characterization with new evidence.
Distractor analysis:
- B: No comparison or ranking against contemporaries appears.
- C: Reverse of the passage, which relies on the letters to correct the record.
- D: Contradicts the text, which shows she did not actually withdraw.', 'What does the cache of letters do to the long-standing legend?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('abe1fe67-154d-4481-97c5-d333d3de5ad9', 'Which choice best states the main purpose of the text?', 'Engineers designing the new pedestrian bridge faced an unusual constraint: the river below freezes unevenly, expanding the ice against the supports each winter. A conventional fixed footing would crack under the seasonal pressure. So the team adopted a sliding-collar design, allowing each support to shift a few centimeters horizontally as the ice pushes. Sensors embedded in the collars track every movement, feeding data to a maintenance system. The result is a structure that does not resist the ice but accommodates it, flexing slightly and returning to position when the thaw arrives. By yielding where rigidity would fail, the design turns a destructive force into a manageable one.', NULL, '[{"id":"A","text":"To explain how a particular engineering design responds to an environmental challenge.","is_correct":true,"explanation":"Correct: it presents the ice problem and details the sliding-collar solution."},{"id":"B","text":"To compare several competing bridge designs and recommend the cheapest.","is_correct":false,"explanation":"Only one design is discussed and no cost comparison appears."},{"id":"C","text":"To warn readers about the dangers of building bridges over rivers.","is_correct":false,"explanation":"Too broad; the text describes a successful solution, not a warning."},{"id":"D","text":"To describe the daily routine of bridge maintenance workers.","is_correct":false,"explanation":"Maintenance staff routines are not the focus; the design is."}]'::jsonb, 'A', 'Step 1 — Find the problem
The text names the constraint that {{yellow:the river below freezes unevenly, expanding the ice against the supports each winter}}.
Step 2 — Match purpose to solution
It then explains the sliding-collar design that accommodates that force, so the purpose is to explain how the design responds to an environmental challenge.
Distractor analysis:
- B: Only one design is presented; no cost recommendation is made.
- C: Too broad and contradicts the constructive tone.
- D: Worker routines are never described.', 'Why is the sliding-collar design introduced at all?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0e3ba5ed-86c5-49d9-9d95-a6e9888febe8', 'Which choice best describes the overall structure of the text?', 'When the council first proposed converting the abandoned rail line into a public trail, residents near the route objected loudly, fearing noise and litter. The plan stalled for two years. Rather than abandon it, planners invited those same residents to help design the trail''s fencing, lighting, and entry points. The objectors became collaborators, and several now volunteer as trail stewards. The episode is often cited as a lesson in public works: opposition rooted in uncertainty can soften when residents are given a genuine role in shaping a project. What had begun as a standoff ended as a partnership.', NULL, '[{"id":"A","text":"It recounts a conflict and then explains how a change in approach resolved it.","is_correct":true,"explanation":"Correct: residents objected, planners involved them, and the conflict resolved."},{"id":"B","text":"It catalogs the technical features required to build a rail trail.","is_correct":false,"explanation":"Fencing and lighting are mentioned only as part of the resolution, not cataloged."},{"id":"C","text":"It predicts that future trail projects will face identical opposition.","is_correct":false,"explanation":"No prediction about future projects is offered."},{"id":"D","text":"It criticizes residents for delaying a beneficial public project.","is_correct":false,"explanation":"The text frames residents as eventual collaborators, not targets of blame."}]'::jsonb, 'A', 'Step 1 — Establish the conflict
The text opens with residents who {{yellow:objected loudly, fearing noise and litter}}, stalling the plan.
Step 2 — Trace the resolution
Planners gave residents a role, turning objectors into collaborators, so the structure moves from conflict to resolution.
Distractor analysis:
- B: Technical features appear only incidentally within the resolution.
- C: No future-oriented prediction is made.
- D: The text does not blame residents; it shows reconciliation.', 'How does the standoff at the start become a partnership by the end?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bf05ca88-df6a-465a-8a1f-71f92c66e43d', 'Which choice best describes the overall structure of the text?', 'The mantis shrimp''s eyes have long fascinated biologists for their sixteen types of color receptors, far more than the three found in humans. Researchers assumed such complexity must yield extraordinarily fine color discrimination. Recent behavioral tests, however, found the opposite: mantis shrimp distinguish colors no better than humans, and often worse. The receptors, it seems, do not compare wavelengths the way our brains do. Instead, each receptor delivers a quick, separate signal, letting the animal recognize colors rapidly without slow neural processing. The eye is built not for precision but for speed, an arrangement suited to a fast-striking predator.', NULL, '[{"id":"A","text":"It introduces an intuitive assumption, presents findings that contradict it, and offers an alternative explanation.","is_correct":true,"explanation":"Correct: assumption of fine discrimination, contradicting tests, then a speed-based account."},{"id":"B","text":"It compares the visual systems of several marine predators in detail.","is_correct":false,"explanation":"Only the mantis shrimp''s eye is examined, with humans as a brief reference."},{"id":"C","text":"It argues that color receptors are irrelevant to animal behavior.","is_correct":false,"explanation":"The text says the receptors enable rapid recognition, not that they are irrelevant."},{"id":"D","text":"It chronicles the history of research into human color vision.","is_correct":false,"explanation":"Human vision is only a comparison point, not the subject."}]'::jsonb, 'A', 'Step 1 — State the assumption
Researchers believed the eye''s complexity would {{yellow:yield extraordinarily fine color discrimination}}.
Step 2 — Track the reversal and explanation
Tests found the opposite, and the text proposes a speed-based mechanism, giving an assumption-contradiction-explanation structure.
Distractor analysis:
- B: No detailed multi-species comparison occurs.
- C: Reverse; receptors are shown to serve rapid recognition.
- D: Human color vision is only a comparison, not the focus.', 'What happens to the researchers'' initial assumption as the text proceeds?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f5a990e5-24eb-49a3-886f-69d1a4445616', 'Which choice best describes the overall structure of the text?', 'In the novel''s opening chapters, the narrator describes her childhood village in lavish, almost reverent detail: the smell of bread, the worn stone of the well, the names of every neighbor. The reader is lulled into a sense of warmth and permanence. Then, midway through the second chapter, a single sentence reveals that the village was flooded and abandoned decades earlier and exists now only in memory. The earlier abundance suddenly reads as elegy. Every loving description, the reader realizes, was a record of something already lost, and the warmth was the warmth of grief.', NULL, '[{"id":"A","text":"It establishes a vivid impression and then recasts its meaning through a single revelation.","is_correct":true,"explanation":"Correct: warm detail is reframed as elegy by the flood revelation."},{"id":"B","text":"It summarizes the plot of an entire novel from beginning to end.","is_correct":false,"explanation":"Only the opening chapters are discussed, not the whole plot."},{"id":"C","text":"It evaluates whether the narrator''s descriptions are factually accurate.","is_correct":false,"explanation":"Accuracy is not assessed; meaning and effect are."},{"id":"D","text":"It contrasts the village with a city the narrator later visits.","is_correct":false,"explanation":"No city or contrasting location appears in the text."}]'::jsonb, 'A', 'Step 1 — Note the initial impression
The narrator''s village is rendered in {{yellow:lavish, almost reverent detail}}, creating warmth and permanence.
Step 2 — Identify the recasting
A single sentence about the flood transforms that abundance into elegy, so the structure builds an impression and then reinterprets it.
Distractor analysis:
- B: Only the opening, not the full plot, is covered.
- C: Factual accuracy is never in question.
- D: No contrasting city is mentioned.', 'What does the flood revelation do to the earlier loving descriptions?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2bb243b6-180e-46b4-9d78-d8cae58339b3', 'Which choice best states the main purpose of the text?', 'Economists once treated household chores as economically invisible, excluded from measures of national output because no money changed hands. A growing body of research challenges that omission. By estimating the market value of cooking, cleaning, and caregiving performed without pay, analysts have shown that unpaid domestic labor can equal a substantial share of a nation''s measured economy. Including it would not change a single hour of work actually done, but it would change how that work is counted and valued. The point is not to invent new activity but to make visible labor that has always been there.', NULL, '[{"id":"A","text":"To explain why researchers seek to account for unpaid domestic labor that traditional measures omit.","is_correct":true,"explanation":"Correct: it identifies the omission and the case for counting such labor."},{"id":"B","text":"To argue that household chores should be performed for pay.","is_correct":false,"explanation":"The text addresses counting the labor, not paying for it."},{"id":"C","text":"To describe the daily schedule of an average household.","is_correct":false,"explanation":"No household schedule is described."},{"id":"D","text":"To claim that national output measures are entirely useless.","is_correct":false,"explanation":"Too extreme; the text proposes refining the measures, not discarding them."}]'::jsonb, 'A', 'Step 1 — Locate the omission
The text notes household chores were {{yellow:excluded from measures of national output because no money changed hands}}.
Step 2 — Identify the purpose
It then explains research aimed at counting that labor, so the purpose is to explain why researchers seek to account for it.
Distractor analysis:
- B: The aim is counting, not requiring payment.
- C: No daily schedule appears.
- D: Too extreme; measures are to be refined, not dismissed.', 'Why do the analysts want to estimate the value of unpaid work?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('513f5105-e34f-4429-8b20-4444fc475220', 'Which choice best describes the overall structure of the text?', 'Ancient Roman concrete has survived two thousand years in harbor waters that would crumble modern equivalents within decades. For a long time, this durability was treated simply as a curiosity of antiquity, admired but unexplained. Materials scientists have now traced the secret to the mixture itself: lumps of unmixed lime that, when cracks let in seawater, dissolve and recrystallize, sealing the breach. The concrete effectively heals itself. Far from a lost art beyond recovery, the technique points toward practical designs for self-repairing materials today. An ancient recipe, once a museum-piece marvel, is becoming a blueprint for future construction.', NULL, '[{"id":"A","text":"It presents a long-admired puzzle, supplies its explanation, and notes the explanation''s modern usefulness.","is_correct":true,"explanation":"Correct: durability puzzle, the lime mechanism, then modern application."},{"id":"B","text":"It laments that an ancient building technique can never be reproduced.","is_correct":false,"explanation":"Reverse: the text says the technique points toward modern designs."},{"id":"C","text":"It compares Roman harbors with modern ports in economic terms.","is_correct":false,"explanation":"No economic comparison of harbors occurs."},{"id":"D","text":"It lists the ingredients of modern concrete in technical detail.","is_correct":false,"explanation":"The focus is Roman concrete''s mechanism, not a modern ingredient list."}]'::jsonb, 'A', 'Step 1 — Note the puzzle
The concrete''s durability was long {{yellow:admired but unexplained}}.
Step 2 — Trace explanation and application
Scientists explain the self-healing lime, then point to modern self-repairing materials, giving a puzzle-explanation-application structure.
Distractor analysis:
- B: Reverse; the technique is shown to be useful today.
- C: No economic harbor comparison is made.
- D: Modern ingredients are not listed in detail.', 'What does the text do after explaining the self-healing mechanism?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4c614f4e-7bb2-425f-b49e-0915cc243f36', 'Which choice best states the main purpose of the text?', 'Conventional wisdom holds that early jazz musicians could not read music and relied purely on instinct. This image of untrained genius is romantic but misleading. Archival programs, lesson ledgers, and surviving sheet music show that many founding figures studied formally, played in disciplined ensembles, and prized technical mastery. Their improvisation was not a substitute for training but a product of it, built on a deep command of harmony that only study could provide. The myth of the wholly untaught player, however appealing, flattens a richer history in which rigorous learning and spontaneous invention worked together rather than apart.', NULL, '[{"id":"A","text":"To correct a popular misconception by showing that early jazz improvisation rested on formal training.","is_correct":true,"explanation":"Correct: it refutes the untrained-genius myth using archival evidence."},{"id":"B","text":"To argue that improvisation has no place in jazz performance.","is_correct":false,"explanation":"The text says improvisation and training worked together, not that improvisation is excluded."},{"id":"C","text":"To recommend a specific method for teaching music theory.","is_correct":false,"explanation":"No teaching method is recommended."},{"id":"D","text":"To trace the spread of jazz across different regions.","is_correct":false,"explanation":"Geographic spread is not discussed."}]'::jsonb, 'A', 'Step 1 — Name the misconception
The text cites the belief that early musicians {{yellow:could not read music and relied purely on instinct}}.
Step 2 — Identify the corrective purpose
Archival evidence shows their improvisation rested on training, so the purpose is to correct the misconception.
Distractor analysis:
- B: The text unites improvisation and training rather than rejecting improvisation.
- C: No teaching method is proposed.
- D: Regional spread is never addressed.', 'What is the text doing with the romantic image of untrained genius?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('750d928f-c285-4456-b530-eb4342d8c4fa', 'Which choice best states the main purpose of the text?', 'Most accounts of the printing press emphasize its role in spreading new ideas swiftly across Europe. That emphasis is fair but incomplete. The press was equally powerful as a tool of standardization: it fixed spellings, stabilized texts that scribes had once varied freely, and let distant readers consult identical pages. A scholar in one city could now cite a passage confident that a colleague hundreds of miles away held the very same words. This quieter consequence, less dramatic than the rapid circulation of novel arguments, shaped intellectual life just as deeply by making shared, reliable reference possible.', NULL, '[{"id":"A","text":"To highlight an underappreciated effect of the printing press alongside its familiar one.","is_correct":true,"explanation":"Correct: it adds standardization to the well-known idea-spreading effect."},{"id":"B","text":"To argue that the printing press had no role in spreading ideas.","is_correct":false,"explanation":"The text calls the idea-spreading account fair, not false."},{"id":"C","text":"To describe the mechanical workings of an early printing press.","is_correct":false,"explanation":"No mechanical details of the press are given."},{"id":"D","text":"To compare scribes'' wages with those of printers.","is_correct":false,"explanation":"Wages are not discussed at all."}]'::jsonb, 'A', 'Step 1 — Note the familiar account
The text grants that the press spread ideas but calls that emphasis {{yellow:fair but incomplete}}.
Step 2 — Identify the added effect
It then foregrounds standardization, so the purpose is to highlight an underappreciated effect alongside the familiar one.
Distractor analysis:
- B: The idea-spreading role is affirmed, not denied.
- C: No mechanical workings are described.
- D: Wages are never mentioned.', 'Why does the text say the usual emphasis is incomplete?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1c4c2c71-16b4-4e50-a7cb-b5ba9eadc9d7', 'Which choice best states the main purpose of the text?', 'Volunteers who clear invasive plants from the wetland reserve often expect quick, visible results. Reality is slower. Pulling one aggressive vine can free native seedlings, but those seedlings may take years to mature, and removed invaders frequently resprout from fragments left in the soil. Coordinators therefore frame the work as maintenance rather than rescue, returning to the same plots season after season. Progress here is measured not in a single dramatic clearing but in the gradual tipping of a balance, plot by plot, toward species that belong. Patience, not speed, is the discipline the reserve demands.', NULL, '[{"id":"A","text":"To explain why restoring the wetland is a gradual process rather than a quick fix.","is_correct":true,"explanation":"Correct: it contrasts expected speed with the slow reality of restoration."},{"id":"B","text":"To discourage volunteers from joining the reserve''s efforts.","is_correct":false,"explanation":"The text reframes the work as long-term, not as something to avoid."},{"id":"C","text":"To identify which invasive species is most harmful to wetlands.","is_correct":false,"explanation":"No single species is ranked as most harmful."},{"id":"D","text":"To celebrate a single dramatic clearing of the reserve.","is_correct":false,"explanation":"Reverse; the text rejects the idea of a single dramatic clearing."}]'::jsonb, 'A', 'Step 1 — Note the expectation
Volunteers {{yellow:often expect quick, visible results}}.
Step 2 — Identify the purpose
The text shows restoration is slow and ongoing, so its purpose is to explain why the work is gradual rather than a quick fix.
Distractor analysis:
- B: It reframes the work, not discourages participation.
- C: No species is singled out as most harmful.
- D: Reverse; a single dramatic clearing is explicitly rejected.', 'Why do coordinators call the work maintenance rather than rescue?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4efa1f7a-ea8b-4ed8-b45e-b950566295ff', 'Which choice best describes the overall structure of the text?', 'The committee''s report opens by praising the proposed observatory''s scientific promise: clearer skies, sharper instruments, and decades of potential discovery. A reader might expect an unqualified endorsement. The final section, however, introduces a caveat. The chosen mountaintop is sacred to communities who have gathered there for generations, and construction would disturb sites they have long protected. The report does not withdraw its support, but it insists that any approval depend on genuine consultation and shared stewardship. Scientific value, it concludes, cannot be weighed in isolation from the people for whom the place already holds meaning.', NULL, '[{"id":"A","text":"It praises a proposal and then qualifies that praise with an important condition.","is_correct":true,"explanation":"Correct: scientific promise is endorsed, then conditioned on consultation."},{"id":"B","text":"It rejects the observatory proposal as scientifically worthless.","is_correct":false,"explanation":"Reverse; the report supports the science and does not reject it."},{"id":"C","text":"It lists the technical specifications of the planned instruments.","is_correct":false,"explanation":"Instruments are mentioned only briefly, not specified technically."},{"id":"D","text":"It compares several candidate sites for the observatory.","is_correct":false,"explanation":"Only one site is discussed; no comparison occurs."}]'::jsonb, 'A', 'Step 1 — Note the praise
The report opens by praising the observatory''s {{yellow:clearer skies, sharper instruments, and decades of potential discovery}}.
Step 2 — Identify the qualification
It then conditions approval on consultation over a sacred site, so the structure praises and then qualifies.
Distractor analysis:
- B: Reverse; the science is endorsed, not dismissed.
- C: Instruments are not technically specified.
- D: Only one site appears; nothing is compared.', 'What does the final section add to the opening praise?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ea0262ea-5376-4664-9273-84e82bb5f61f', 'Which choice best describes the overall structure of the text?', 'When a colony of leafcutter ants strips a tree of foliage, an observer might assume the insects eat the leaves. They do not. The ants carry the fragments underground to cultivate a fungus, and it is the fungus, not the leaves, that nourishes the colony. The relationship runs deeper still: the fungus cannot survive without the ants'' tending, and the ants cannot digest leaves without the fungus. Each depends wholly on the other. What looks like simple foraging is in fact one half of an ancient partnership, a farming arrangement older than human agriculture by millions of years.', NULL, '[{"id":"A","text":"It corrects a likely assumption and then characterizes the relationship the correction reveals.","is_correct":true,"explanation":"Correct: it denies that ants eat leaves, then details the mutual dependence."},{"id":"B","text":"It warns that leafcutter ants threaten the survival of forests.","is_correct":false,"explanation":"No warning about forest destruction is offered."},{"id":"C","text":"It compares ant agriculture with human agriculture in detail.","is_correct":false,"explanation":"Human agriculture is a brief reference point, not a detailed comparison."},{"id":"D","text":"It traces the life cycle of the fungus from spore to maturity.","is_correct":false,"explanation":"No fungal life cycle is traced."}]'::jsonb, 'A', 'Step 1 — Identify the assumption
An observer might assume the ants {{yellow:eat the leaves}}, which the text denies.
Step 2 — Characterize the relationship
It then describes the mutual dependence of ants and fungus, so the structure corrects an assumption and characterizes what is revealed.
Distractor analysis:
- B: No warning about forests is given.
- C: Human agriculture is only a brief comparison point.
- D: The fungal life cycle is not traced.', 'What does the text do after stating that the ants do not eat the leaves?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3df9a4df-45f8-46a3-b713-dbfab44b25a7', 'Which choice best describes the overall structure of the text?', 'For decades, naturalists assumed that the brilliant plumage of male birds existed solely to attract mates, a straightforward case of evolutionary advertising. Recent fieldwork, however, complicates this tidy account. Researchers tracking populations of fairy-wrens found that some of the most vividly colored males were rarely chosen by females, while drabber rivals fathered more offspring. The brightness, it turns out, may signal status to other males, deterring fights before they begin. What once seemed a simple story of seduction now appears to involve negotiation among competitors as much as courtship. The feathers, in other words, speak to several audiences at once.', NULL, '[{"id":"A","text":"It presents a long-held explanation and then complicates it with findings that suggest a more layered account.","is_correct":true,"explanation":"Correct: the text states the old assumption, then introduces fieldwork that complicates it and points to multiple functions."},{"id":"B","text":"It traces the gradual abandonment of an idea that scientists now regard as entirely mistaken.","is_correct":false,"explanation":"Wrong: the text refines the idea rather than declaring it entirely mistaken."},{"id":"C","text":"It compares two competing research teams and endorses the conclusions of one.","is_correct":false,"explanation":"Wrong: no rival research teams are compared or endorsed."},{"id":"D","text":"It describes a method for tracking bird populations and evaluates its reliability.","is_correct":false,"explanation":"Wrong: tracking is mentioned only as evidence, not as the text''s subject or focus of evaluation."}]'::jsonb, 'A', 'Step 1 — Locate the shift
The text opens with a long-held view but pivots at {{yellow:Recent fieldwork, however, complicates this tidy account}}.
Step 2 — Identify the structure
It then offers findings showing the plumage serves several functions, so the structure presents an old explanation and complicates it toward a layered account.
Distractor analysis:
- B: The idea is refined, not deemed entirely mistaken.
- C: No two research teams are contrasted.
- D: Tracking is evidence, not the focus or an object of evaluation.', 'Find the sentence with ''however'' and ask whether the old idea is replaced or merely deepened.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ea29cf5b-618c-41de-bb66-8879de54e4e4', 'Which choice best states the main purpose of the text?', 'The poet Marianne Moore was famous for her habit of revision. Long after a poem appeared in print, she would return to it, trimming stanzas, swapping words, sometimes cutting a celebrated piece down to a few lines. Critics often lamented these changes, accusing her of mutilating her own best work. Moore was unmoved. For her, a published poem was never finished but merely paused, a draft that circumstances had interrupted. To revise was not to betray the original impulse but to keep faith with it, pursuing a precision the earlier version had only approximated. The poem on the page was, at most, a temporary truce with language.', NULL, '[{"id":"A","text":"To explain how Moore understood revision in a way that reframes a practice her critics misjudged.","is_correct":true,"explanation":"Correct: the text sets critics'' complaints against Moore''s own rationale, reframing revision as fidelity rather than damage."},{"id":"B","text":"To argue that Moore''s revised poems are superior to her published originals.","is_correct":false,"explanation":"Wrong: the text explains her view but never ranks the revised versions as superior."},{"id":"C","text":"To catalog the specific techniques Moore used when editing her stanzas.","is_correct":false,"explanation":"Wrong: techniques are mentioned in passing, not catalogued as the purpose."},{"id":"D","text":"To document the critical reception of Moore''s poetry over her career.","is_correct":false,"explanation":"Wrong: critics appear only as a foil; reception is not the text''s aim."}]'::jsonb, 'A', 'Step 1 — Find the reframing
The text gives Moore''s own logic: {{yellow:To revise was not to betray the original impulse but to keep faith with it}}.
Step 2 — Connect to purpose
That line answers the critics, so the purpose is to explain her understanding in a way that corrects their judgment.
Distractor analysis:
- B: No claim that revised poems are superior.
- C: Techniques are incidental, not the purpose.
- D: Reception is a foil, not the focus.', 'Ask what the writer wants you to understand about Moore, not what the critics thought.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('67da4788-9d52-4c6e-9f02-3ec4d68a7893', 'Which choice best describes the overall structure of the text?', 'When archaeologists uncovered the ruins of a small Bronze Age settlement, they expected to find the usual signs of a farming community. Instead, the storerooms held an unusual concentration of imported goods: obsidian from distant islands, copper ingots, and beads of foreign make. The houses, by contrast, were modest and uniform, offering no hint that any family had grown rich. This puzzle has led some scholars to propose that the village functioned less as a place of permanent residence than as a waystation, a hub where traveling merchants pooled and redistributed goods. The wealth passed through the settlement; it did not settle there.', NULL, '[{"id":"A","text":"It introduces an expectation, presents evidence that defies it, and offers an interpretation that reconciles the two.","is_correct":true,"explanation":"Correct: the text names the expectation, gives contrary finds, then proposes the waystation reading to reconcile them."},{"id":"B","text":"It contrasts two settlements to determine which was wealthier.","is_correct":false,"explanation":"Wrong: only one settlement is discussed."},{"id":"C","text":"It defends a traditional view of Bronze Age villages against new criticism.","is_correct":false,"explanation":"Wrong: the text departs from the traditional expectation rather than defending it."},{"id":"D","text":"It describes the dangers faced by traveling merchants in the Bronze Age.","is_correct":false,"explanation":"Wrong: merchant dangers are never discussed."}]'::jsonb, 'A', 'Step 1 — Spot the reversal
The expectation breaks at {{yellow:Instead, the storerooms held an unusual concentration of imported goods}}.
Step 2 — Trace the resolution
The waystation proposal then reconciles rich goods with modest houses, fitting expectation, contrary evidence, and interpretation.
Distractor analysis:
- B: Only one settlement appears.
- C: The text overturns, not defends, the expectation.
- D: Merchant dangers are absent.', 'Count the moves: what was expected, what was found, and how the gap is explained.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e652c4bb-3a3f-45b2-b0f5-414a2e41089d', 'Which choice best states the main purpose of the text?', 'It is tempting to picture the immune system as a standing army, ever vigilant against invaders. The metaphor captures something real, yet it can mislead. An army defends a fixed border, but the body has no single front line; threats arise within tissues, in the blood, even inside individual cells. Moreover, an army aims to destroy, whereas much immune activity involves tolerance, learning which cells and microbes to leave alone. A more accurate image might be a vast bureaucracy of surveillance and judgment, constantly deciding what belongs. The martial metaphor, useful for beginners, quietly distorts the cooperative and discriminating work the system actually performs.', NULL, '[{"id":"A","text":"To qualify a familiar metaphor by showing where it breaks down and proposing a more fitting one.","is_correct":true,"explanation":"Correct: the text grants the army image some truth, details its failures, and offers the bureaucracy image as more accurate."},{"id":"B","text":"To reject all metaphors as unsuitable for describing the immune system.","is_correct":false,"explanation":"Wrong: the text proposes a replacement metaphor, so it does not reject metaphor itself."},{"id":"C","text":"To explain in detail how immune cells distinguish harmful from harmless microbes.","is_correct":false,"explanation":"Wrong: tolerance is mentioned only to test the metaphor, not explained mechanistically."},{"id":"D","text":"To trace the history of how scientists have described the immune system.","is_correct":false,"explanation":"Wrong: no historical sequence of descriptions is given."}]'::jsonb, 'A', 'Step 1 — Note the concession and limit
The text concedes value but warns at {{yellow:The metaphor captures something real, yet it can mislead}}.
Step 2 — Tie to purpose
It then lists where the army image fails and proposes a better one, so the purpose is to qualify the metaphor and offer a replacement.
Distractor analysis:
- B: A new metaphor is offered, so metaphor is not rejected wholesale.
- C: Tolerance is illustrative, not the explanatory focus.
- D: No history of descriptions is traced.', 'Notice that the writer both criticizes the metaphor and suggests another one.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('64970c60-150a-415d-8b72-c74be67bcad0', 'Which choice best describes the overall structure of the text?', 'In the early nineteenth century, the city of Manchester grew faster than any plan could anticipate. Mills rose along the rivers, and with them came rows of crowded housing thrown up to shelter the workers who poured in from the countryside. Sanitation lagged hopelessly behind. Visitors recorded streets choked with refuse and air thick with smoke, conditions that bred recurring outbreaks of disease. Yet these same conditions, by their sheer visibility, eventually forced reformers and officials to confront urban poverty as a public problem rather than a private misfortune. The squalor that the city created became, in time, the very spur to the institutions designed to remedy it.', NULL, '[{"id":"A","text":"It describes a deteriorating situation and then explains how that situation prompted an unexpected response.","is_correct":true,"explanation":"Correct: the text details Manchester''s worsening conditions, then shows how their visibility spurred reform."},{"id":"B","text":"It lists the industries that made Manchester prosperous and evaluates each.","is_correct":false,"explanation":"Wrong: industries are not catalogued or evaluated; only mills are mentioned in passing."},{"id":"C","text":"It contrasts Manchester with a rival city that managed growth more wisely.","is_correct":false,"explanation":"Wrong: no rival city appears."},{"id":"D","text":"It argues that nineteenth-century reforms ultimately failed to improve the city.","is_correct":false,"explanation":"Wrong: the text credits the conditions with prompting remedies, not their failure."}]'::jsonb, 'A', 'Step 1 — Mark the pivot
After the grim description, the turn comes at {{yellow:Yet these same conditions, by their sheer visibility, eventually forced reformers and officials to confront urban poverty}}.
Step 2 — Name the structure
The text moves from a worsening situation to the response it provoked, an unexpected outcome.
Distractor analysis:
- B: Industries are not catalogued or evaluated.
- C: No rival city is introduced.
- D: The text emphasizes reform''s prompting, not its failure.', 'What does the word ''Yet'' set up after all the description of squalor?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0089ad0c-1b75-4787-9f5a-ff5dc4be462c', 'Which choice best describes the overall structure of the text?', 'The novel opens with Elena packing a single suitcase, narrating her departure with the brisk confidence of someone who has made up her mind. She lists what she will leave behind and what she refuses to carry, and the reader is invited to admire her resolve. Only in the final pages does the narration loosen its grip. We learn that the suitcase was repacked a dozen times, that Elena lingered at the door for hours, that her confident account was assembled long after the fact. The story she told us, it becomes clear, was less a record of her leaving than a defense she built to live with it.', NULL, '[{"id":"A","text":"It presents a character''s self-assured account and then reveals details that recast that account as a justification.","is_correct":true,"explanation":"Correct: the text shows Elena''s confident narration, then late revelations that reframe it as a self-justifying construction."},{"id":"B","text":"It compares two characters'' differing memories of the same departure.","is_correct":false,"explanation":"Wrong: only Elena''s account is at issue; no second character''s memory is given."},{"id":"C","text":"It summarizes a novel''s plot and praises its emotional realism.","is_correct":false,"explanation":"Wrong: the text analyzes the narration''s reliability rather than praising realism."},{"id":"D","text":"It explains why Elena ultimately decides not to leave home.","is_correct":false,"explanation":"Wrong: the text concerns how she narrates leaving, not a decision to stay."}]'::jsonb, 'A', 'Step 1 — Find the turn
The confident surface cracks at {{yellow:Only in the final pages does the narration loosen its grip}}.
Step 2 — Identify the structure
The later details recast Elena''s account as {{yellow:a defense she built to live with it}}, so the structure moves from self-assured account to reframing revelation.
Distractor analysis:
- B: There is no second character''s memory.
- C: The text analyzes reliability, not realism.
- D: She does leave; the issue is how she tells it.', 'Track how the meaning of Elena''s confident narration changes by the final pages.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('143994c0-78fe-4136-ae23-c5d29d9a2a17', 'Which choice best states the main purpose of the text?', 'Coral reefs are often praised as the rainforests of the sea, dazzling in their diversity. Less appreciated is the strange economy underlying that beauty. The reef-building corals are animals, yet they survive largely on sugars produced by algae living inside their tissues. The coral offers shelter and raw materials; the algae, in return, photosynthesize and share the food. When ocean temperatures climb, this partnership frays: stressed corals expel their algae and lose their color, a process called bleaching. The vivid reef, then, is not a single organism flaunting its health but a delicate bargain between two unlike partners, and the bargain holds only within a narrow band of conditions.', NULL, '[{"id":"A","text":"To explain that a reef''s visible vitality rests on a fragile partnership rather than on any single organism.","is_correct":true,"explanation":"Correct: the text reframes reef beauty as a temperature-sensitive bargain between coral and algae."},{"id":"B","text":"To describe the full range of species that inhabit a coral reef.","is_correct":false,"explanation":"Wrong: the diversity is noted only to set up the partnership; species are not catalogued."},{"id":"C","text":"To warn that rising ocean temperatures will soon eliminate all reefs.","is_correct":false,"explanation":"Wrong: bleaching is explained as evidence of fragility, not a prediction of total loss."},{"id":"D","text":"To compare coral reefs with tropical rainforests in detail.","is_correct":false,"explanation":"Wrong: the rainforest comparison is a brief opening phrase, not a sustained comparison."}]'::jsonb, 'A', 'Step 1 — Locate the reframing
The text recasts the reef at {{yellow:not a single organism flaunting its health but a delicate bargain between two unlike partners}}.
Step 2 — Connect to purpose
With bleaching showing how the bargain frays, the purpose is to explain that visible vitality rests on a fragile partnership.
Distractor analysis:
- B: Species are not catalogued.
- C: No claim that all reefs will soon vanish.
- D: The rainforest line is a brief opener, not a developed comparison.', 'What does the writer most want you to grasp about why the reef looks alive?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9d36a4eb-8c55-48df-85ee-f3591cc664d1', 'Which choice best states the main purpose of the text?', 'Conventional histories of jazz tend to credit a handful of celebrated soloists, the trumpeters and saxophonists whose names fill the record sleeves. This emphasis is understandable but incomplete. Behind nearly every famous solo stood arrangers who shaped the harmonies, rhythm players who set the groove, and club owners who decided which sounds reached an audience at all. To listen only for the soloist is to mistake a collaborative craft for a series of individual triumphs. A fuller account would distribute the credit, recognizing that the music we attribute to single geniuses was in truth assembled by many hands working in concert.', NULL, '[{"id":"A","text":"To qualify a common emphasis in jazz history by arguing for a more collaborative account of the music''s creation.","is_correct":true,"explanation":"Correct: the text concedes the soloist focus is understandable, then argues credit should be distributed among many contributors."},{"id":"B","text":"To rank the most influential jazz soloists of the twentieth century.","is_correct":false,"explanation":"Wrong: the text downplays the soloist focus rather than ranking soloists."},{"id":"C","text":"To explain how jazz arrangements are technically constructed.","is_correct":false,"explanation":"Wrong: arrangers are cited as overlooked contributors, not as a technical subject."},{"id":"D","text":"To argue that famous soloists deserve no credit for their recordings.","is_correct":false,"explanation":"Wrong: the text redistributes credit, not denies it to soloists."}]'::jsonb, 'A', 'Step 1 — Note the concession and turn
The text grants the soloist focus is reasonable but flags it at {{yellow:This emphasis is understandable but incomplete}}.
Step 2 — Connect to purpose
It then argues for distributing credit among arrangers, rhythm players, and others, so the purpose is to qualify the emphasis toward a collaborative account.
Distractor analysis:
- B: It downplays, not ranks, soloists.
- C: Arrangement technique is not explained.
- D: Credit is redistributed, not denied to soloists.', 'The phrase ''understandable but incomplete'' tells you the writer is adjusting, not destroying, a view.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9b485761-1e82-4eee-bada-048e9325f871', 'Which choice best describes the overall structure of the text?', 'When a star far more massive than our Sun exhausts its fuel, its core collapses in seconds, and the outer layers rebound in a titanic explosion called a supernova. For a few weeks the dying star can outshine an entire galaxy. Yet astronomers prize these cataclysms for more than their spectacle. The explosion forges and scatters heavy elements, the carbon, oxygen, and iron from which planets and living things are later built. A supernova is thus both an ending and a beginning, the violent close of one star''s life and the seedbed for everything that gathers from the wreckage. Destruction here is the price of fertility.', NULL, '[{"id":"A","text":"It describes a destructive event and then contextualizes it as a source of the materials for later life.","is_correct":true,"explanation":"Correct: the text portrays the supernova''s violence, then situates it as the origin of the elements that build planets and life."},{"id":"B","text":"It explains why our Sun will eventually explode as a supernova.","is_correct":false,"explanation":"Wrong: the text concerns stars far more massive than the Sun, not the Sun''s fate."},{"id":"C","text":"It compares supernovae with other kinds of stellar explosions.","is_correct":false,"explanation":"Wrong: no other type of explosion is introduced for comparison."},{"id":"D","text":"It questions whether supernovae truly produce heavy elements.","is_correct":false,"explanation":"Wrong: the text asserts that they forge heavy elements; it raises no doubt."}]'::jsonb, 'A', 'Step 1 — Mark the pivot
The text moves past spectacle at {{yellow:Yet astronomers prize these cataclysms for more than their spectacle}}.
Step 2 — Name the structure
It then frames the explosion as a {{yellow:seedbed for everything that gathers from the wreckage}}, so a destructive event is contextualized as a source of later life.
Distractor analysis:
- B: The Sun''s fate is not the subject.
- C: No other explosion type is compared.
- D: Heavy-element production is asserted, not doubted.', 'What larger role does the writer assign to the explosion after describing its violence?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('64964b19-321c-4b00-abe0-789cc659fa79', 'Which choice best states the main purpose of the text?', 'Eighteenth-century mapmakers prided themselves on accuracy, yet their maps of unexplored interiors were riddled with confident inventions: phantom mountain ranges, rivers that flowed the wrong way, kingdoms that existed only in rumor. These errors were not always careless. A blank space on a map unsettled patrons and suggested ignorance, so cartographers filled gaps with plausible guesses rather than admit how little was known. The maps thus served two masters at once, recording genuine knowledge while concealing its limits behind a veneer of completeness. To read such a map well is to ask not only what it shows but what its tidy surface was designed to hide.', NULL, '[{"id":"A","text":"To explain that historical maps blended real knowledge with invention in order to mask the extent of the unknown.","is_correct":true,"explanation":"Correct: the text shows that mapmakers filled gaps with guesses to hide ignorance, blending fact and fabrication."},{"id":"B","text":"To praise eighteenth-century cartographers for the precision of their instruments.","is_correct":false,"explanation":"Wrong: the text exposes their inventions rather than praising precision."},{"id":"C","text":"To describe the techniques used to survey unexplored interiors.","is_correct":false,"explanation":"Wrong: surveying techniques are not discussed."},{"id":"D","text":"To argue that all old maps are too unreliable to study.","is_correct":false,"explanation":"Wrong: the text urges reading such maps carefully, implying they remain worth studying."}]'::jsonb, 'A', 'Step 1 — Identify the key claim
The text states the maps served {{yellow:two masters at once, recording genuine knowledge while concealing its limits behind a veneer of completeness}}.
Step 2 — Connect to purpose
That dual role is the point: maps mixed real knowledge with invention to mask the unknown.
Distractor analysis:
- B: Instrument precision is not praised; inventions are exposed.
- C: Surveying techniques are absent.
- D: The text says to read such maps well, not to abandon them.', 'Why, according to the writer, did cartographers fill blank spaces with guesses?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6dbf9c35-f048-49dc-9455-57593ce689b4', 'Which choice best states the main purpose of the text?', 'The earthworm seems an unlikely candidate for influence, a soft, blind creature laboring out of sight. Yet Charles Darwin devoted his final book to demonstrating its quiet power. Over centuries, he argued, earthworms swallow soil, digest its organic matter, and deposit it as fine castings, slowly burying stones and ancient ruins beneath layers of their own making. A field that looks unchanged from year to year is, on the scale of generations, being steadily turned and renewed. Darwin''s point was not merely zoological. He wished to show how vast effects can arise from agents too small and too patient for any single observer to notice.', NULL, '[{"id":"A","text":"To use Darwin''s study of earthworms to illustrate how small, slow agents can produce large cumulative effects.","is_correct":true,"explanation":"Correct: the text presents the earthworm''s gradual work and ends with Darwin''s broader point about vast effects from tiny agents."},{"id":"B","text":"To summarize the contents of Darwin''s earlier books on evolution.","is_correct":false,"explanation":"Wrong: only his final book on earthworms is discussed."},{"id":"C","text":"To explain the digestive anatomy of the common earthworm.","is_correct":false,"explanation":"Wrong: digestion is mentioned only to show the worm''s effect on soil, not as an anatomical subject."},{"id":"D","text":"To argue that earthworms are the most important animals in any ecosystem.","is_correct":false,"explanation":"Wrong: the text makes no claim ranking earthworms above all other animals."}]'::jsonb, 'A', 'Step 1 — Find the larger point
The text states Darwin''s aim at {{yellow:He wished to show how vast effects can arise from agents too small and too patient for any single observer to notice}}.
Step 2 — Connect to purpose
The earthworm example illustrates that principle, so the purpose is to use it to show how small, slow agents produce large cumulative effects.
Distractor analysis:
- B: Earlier books are not summarized.
- C: Digestion is illustrative, not the focus.
- D: No ranking of earthworms above all animals is made.', 'The last sentence states Darwin''s broader aim; let it guide your answer.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6e6da4f9-22a6-457b-9401-5aec1f14e24b', 'Which choice best describes the overall structure of the text?', 'Folklorists once treated fairy tales as fixed inheritances, stories handed down unchanged from a distant past. Closer study has overturned that picture. The same tale, traced across regions, shifts its details with startling freedom: a wolf becomes a tiger, a cottage becomes a houseboat, a moral hardens or softens to suit the tellers'' world. What endures is not the surface but a deep skeleton of plot, around which each community arranges its own flesh. Far from being relics frozen in time, these stories are better understood as living frameworks, continually rebuilt by the people who pass them on.', NULL, '[{"id":"A","text":"It states an outdated view of fairy tales and then replaces it with one that emphasizes their ongoing adaptation.","is_correct":true,"explanation":"Correct: the text presents the old fixed-inheritance view, then overturns it with evidence that tales are continually rebuilt."},{"id":"B","text":"It lists the most popular fairy tales and explains their origins.","is_correct":false,"explanation":"Wrong: no specific tales are listed or traced to origins."},{"id":"C","text":"It defends the idea that fairy tales have remained unchanged over centuries.","is_correct":false,"explanation":"Wrong: the text rejects that idea rather than defending it."},{"id":"D","text":"It compares the work of two rival folklorists and judges between them.","is_correct":false,"explanation":"Wrong: no rival folklorists are named or compared."}]'::jsonb, 'A', 'Step 1 — Spot the overturning
The old view is displaced at {{yellow:Closer study has overturned that picture}}.
Step 2 — Name the structure
The text then shows tales as {{yellow:living frameworks, continually rebuilt by the people who pass them on}}, so it states an outdated view and replaces it with one stressing adaptation.
Distractor analysis:
- B: No tales are listed or traced to origins.
- C: The fixed view is rejected, not defended.
- D: No rival folklorists are compared.', 'What happens to the ''fixed inheritances'' view after the second sentence?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('989b8a65-b849-4084-af2a-18ff6f6e7457', 'Which choice best describes the overall structure of the text?', 'For decades, marine biologists assumed that the deep-sea anglerfish lured prey solely through the glow of its dangling bioluminescent organ. Recent footage captured by remotely operated submersibles complicates this tidy account. The recordings show certain anglerfish remaining motionless for hours, their lures dark, while small crustaceans drift unprompted toward their jaws. Researchers now suspect that the fish may release chemical signals that attract prey even when the lure is unlit. The bioluminescence, in this revised view, is only one tool among several, deployed selectively rather than constantly. The discovery does not overturn the older explanation so much as expose its incompleteness.', NULL, '[{"id":"A","text":"It presents a long-held scientific assumption and then introduces evidence that qualifies, rather than discards, that assumption.","is_correct":true,"explanation":"Correct: the text states the lure assumption, adds complicating footage, and concludes the new finding exposes incompleteness rather than overturning the old view."},{"id":"B","text":"It describes a scientific debate and then declares one side the clear winner.","is_correct":false,"explanation":"Wrong: no two competing camps are pitted against each other, and no winner is declared."},{"id":"C","text":"It defends a traditional explanation against critics who would abandon it entirely.","is_correct":false,"explanation":"Wrong: the text revises rather than defends the traditional explanation, and names no critics."},{"id":"D","text":"It catalogs the various hunting tools of the anglerfish in order of importance.","is_correct":false,"explanation":"Wrong: it does not rank tools; the focus is on revising an assumption."}]'::jsonb, 'A', 'Step 1 — Locate the shift
The passage opens with a settled belief but pivots to footage that {{yellow:complicates this tidy account}}.
Step 2 — Identify the resolution
It closes by saying the discovery {{yellow:does not overturn the older explanation so much as expose its incompleteness}}, so the new evidence qualifies the assumption.
Distractor analysis:
- B: There is no two-sided debate or declared winner.
- C: The text revises the old view rather than defending it, and cites no critics.
- D: It does not rank the fish''s tools by importance.', 'Notice that the final sentence says the new finding exposes incompleteness rather than overturning the old idea.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b116c286-a4ef-451c-bf84-0cc78e643113', 'Which choice best states the main purpose of the text?', 'The novelist Edith Hartwell was, by her own admission, a slow writer who distrusted inspiration. In letters to her sister she mocked the romantic image of the artist seized by sudden vision, calling it ''a flattering fiction.'' Her own method, she explained, resembled bricklaying: she set down a fixed quota of sentences each morning, revised them mechanically each afternoon, and rarely felt anything resembling excitement. Yet the finished novels, with their intricate plots and luminous descriptions, struck readers as effortless and spontaneous. Hartwell took quiet satisfaction in this gap, believing that the appearance of ease was precisely what disciplined labor was meant to produce.', NULL, '[{"id":"A","text":"To contrast a writer''s laborious working method with the spontaneous quality her finished work conveyed.","is_correct":true,"explanation":"Correct: the text sets her mechanical bricklaying method against novels that struck readers as effortless."},{"id":"B","text":"To argue that inspiration plays no role in any serious literary achievement.","is_correct":false,"explanation":"Wrong: it describes one writer''s view, not a universal claim about all literature."},{"id":"C","text":"To trace the development of Hartwell''s writing style over her career.","is_correct":false,"explanation":"Wrong: no chronological development of style is discussed."},{"id":"D","text":"To explain why Hartwell concealed her methods from her readers.","is_correct":false,"explanation":"Wrong: the text never says she concealed her methods; she took satisfaction in the gap."}]'::jsonb, 'A', 'Step 1 — Establish her method
Hartwell describes her writing as resembling {{yellow:bricklaying}}, done by quota and revised mechanically.
Step 2 — Contrast with the result
Despite this, the novels {{yellow:struck readers as effortless and spontaneous}}, so the passage contrasts labor with apparent ease.
Distractor analysis:
- B: It reports her personal view, not a sweeping claim about all literature.
- C: No development of style over a career is traced.
- D: Nothing indicates she concealed her methods.', 'Compare how she actually worked with how the finished novels seemed to readers.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bce0464a-3e11-4a7f-8278-164e1ca01c68', 'Which choice best describes the overall structure of the text?', 'When archaeologists unearthed a cache of bronze tools at the site, the initial interpretation was straightforward: the settlement had been a center of metalworking. The tools were finely made and showed little wear, suggesting local production. But further excavation revealed no furnaces, no slag, and no ore deposits anywhere nearby. The team reconsidered. Perhaps the tools had not been made there at all but acquired through trade and stored, unused, as a form of portable wealth. On this reading, the absence of manufacturing debris was not a puzzle to explain away but the very clue that reframed the site as a hub of exchange rather than of craft.', NULL, '[{"id":"A","text":"An initial interpretation is offered, undermined by new findings, and replaced by an alternative the same findings support.","is_correct":true,"explanation":"Correct: the metalworking reading is undermined by missing furnaces and reframed as trade, which the absence of debris supports."},{"id":"B","text":"Two archaeological teams reach opposing conclusions about a single site.","is_correct":false,"explanation":"Wrong: a single team revises its own view; there are no two opposing teams."},{"id":"C","text":"A widely accepted theory is shown to rest on a simple measurement error.","is_correct":false,"explanation":"Wrong: no measurement error is identified."},{"id":"D","text":"A site is described in detail to illustrate typical Bronze Age craftsmanship.","is_correct":false,"explanation":"Wrong: the passage''s point is reinterpretation, not illustrating craftsmanship."}]'::jsonb, 'A', 'Step 1 — Note the first reading
The tools first suggested the settlement was a {{yellow:center of metalworking}}.
Step 2 — Track the reversal
With {{yellow:no furnaces, no slag, and no ore deposits anywhere nearby}}, the team reframes the site as a hub of exchange that the same evidence supports.
Distractor analysis:
- B: One team revises itself; no rival team appears.
- C: No measurement error is mentioned.
- D: The aim is reinterpretation, not illustrating craftsmanship.', 'Watch how the missing furnaces turn from a problem into the key clue for a new explanation.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('27d588a3-b1b6-4f16-8bcc-b3692220641f', 'Which choice best states the main purpose of the text?', 'Urban planners have long treated traffic congestion as a problem of insufficient road capacity, to be solved by building wider highways. The logic seems unassailable: more lanes, more room, less crowding. Yet a phenomenon known as induced demand repeatedly frustrates the prediction. When new lanes open, drivers who previously avoided the route, or traveled at off-peak hours, flood back, and within a few years congestion returns to its former levels. The expanded highway has not eliminated the jam; it has merely raised the volume of traffic the jam contains. For a growing number of planners, this pattern suggests that capacity is not the lever it was assumed to be.', NULL, '[{"id":"A","text":"To present a conventional solution to congestion and explain why a recurring effect undermines it.","is_correct":true,"explanation":"Correct: the text gives the wider-highway solution, then shows induced demand undermines its logic."},{"id":"B","text":"To recommend that cities stop building highways altogether.","is_correct":false,"explanation":"Wrong: no such policy recommendation is made."},{"id":"C","text":"To define the technical term ''induced demand'' for transportation students.","is_correct":false,"explanation":"Wrong: the term is a tool in the argument, not the passage''s purpose."},{"id":"D","text":"To praise planners for finally solving the problem of urban congestion.","is_correct":false,"explanation":"Wrong: the passage shows the problem persists, not that it was solved."}]'::jsonb, 'A', 'Step 1 — State the conventional fix
Planners treat congestion as solvable by {{yellow:building wider highways}}.
Step 2 — Show the undermining effect
Because {{yellow:congestion returns to its former levels}}, the passage explains why induced demand undercuts that fix.
Distractor analysis:
- B: No call to stop building highways is made.
- C: Defining the term is a means, not the main purpose.
- D: The text shows persistence, not a solved problem.', 'The passage sets up a ''logical'' fix and then shows an effect that defeats it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ed243471-9d29-4020-bd29-740e307978d2', 'Which choice best describes the overall structure of the text?', 'The composer Lia Moreno is often described as a minimalist, and the label is not wholly wrong: her early pieces favor repeated phrases and a deliberately limited palette of notes. But applied to her recent work, the term begins to mislead. The newer compositions layer dozens of overlapping rhythmic lines, so that what sounds spare from a distance reveals, on closer listening, a dense interior. Moreno herself resists the minimalist tag, noting that her aim was never simplicity but the illusion of it. To call her a minimalist, then, is to capture her surface while missing her method.', NULL, '[{"id":"A","text":"It concedes the partial accuracy of a label and then qualifies it by showing where the label fails.","is_correct":true,"explanation":"Correct: the text grants minimalism fits early work, then shows it misleads for recent dense compositions."},{"id":"B","text":"It rejects a label outright as having no basis in the composer''s work.","is_correct":false,"explanation":"Wrong: the text grants the label is ''not wholly wrong,'' so it is not rejected outright."},{"id":"C","text":"It surveys the full range of musical styles available to contemporary composers.","is_correct":false,"explanation":"Wrong: it focuses on one composer and one label, not a survey of styles."},{"id":"D","text":"It explains the technical rules that define minimalist composition.","is_correct":false,"explanation":"Wrong: no rules of minimalism are laid out."}]'::jsonb, 'A', 'Step 1 — Grant the label
The passage admits the minimalist label is {{yellow:not wholly wrong}} for her early pieces.
Step 2 — Mark the limit
It then qualifies this, since the term {{yellow:begins to mislead}} for the layered recent work, capturing surface but missing method.
Distractor analysis:
- B: The label is partly granted, not rejected outright.
- C: No survey of many styles occurs.
- D: No definitional rules of minimalism are given.', 'The text agrees with the label up to a point, then shows where it stops fitting.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3a610961-4250-4550-b5e2-1f48ae07f6e3', 'Which choice best states the main purpose of the text?', 'In the decades after independence, the new republic faced a question its founders had deferred: who counted as a citizen? Early statutes spoke grandly of universal rights but quietly restricted the franchise to property holders. Reformers seized on the contradiction. If rights were truly universal, they argued, then property could not be their measure; and if property were the measure, then the language of universality was empty. Lawmakers, caught between principle and practice, spent a generation revising the statutes piecemeal. The eventual broadening of the franchise came less from a sudden change of heart than from the steady pressure of an argument the founding documents had themselves made possible.', NULL, '[{"id":"A","text":"To explain how a contradiction within a republic''s founding language drove the gradual expansion of citizenship.","is_correct":true,"explanation":"Correct: the text identifies the universal-rights versus property contradiction and traces how reformers used it to broaden the franchise."},{"id":"B","text":"To argue that the republic''s founders deliberately intended universal suffrage from the start.","is_correct":false,"explanation":"Wrong: the text says they restricted the franchise and deferred the question, not that they intended universal suffrage."},{"id":"C","text":"To describe the daily procedures by which early lawmakers drafted statutes.","is_correct":false,"explanation":"Wrong: drafting procedures are not the focus."},{"id":"D","text":"To compare the republic''s franchise laws with those of neighboring nations.","is_correct":false,"explanation":"Wrong: no comparison with other nations appears."}]'::jsonb, 'A', 'Step 1 — Pinpoint the tension
Statutes promised universal rights yet {{yellow:quietly restricted the franchise to property holders}}.
Step 2 — Trace the outcome
The broadening came from {{yellow:the steady pressure of an argument the founding documents had themselves made possible}}, so the contradiction drove gradual expansion.
Distractor analysis:
- B: The founders restricted, not intended universal, suffrage.
- C: Drafting procedures are not discussed.
- D: No comparison with other nations is made.', 'Focus on how the gap between ''universal rights'' and ''property holders'' fueled later reform.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('044422e5-f6c0-4546-9f12-f40902df5f58', 'Which choice best describes the overall structure of the text?', 'Conventional wisdom holds that bees navigate chiefly by the position of the sun. This is true, but it leaves a puzzle: bees forage efficiently even on heavily overcast days when the sun is invisible. The resolution lies in their perception of polarized light. Even when clouds obscure the sun''s disk, sunlight scattering through the atmosphere retains a polarization pattern keyed to the sun''s hidden position, and bees'' compound eyes can read it. So the sun-compass account is not so much wrong as underspecified: bees orient by the sun, yes, but by means subtler than the simple sighting the conventional picture implies.', NULL, '[{"id":"A","text":"It states a common belief, notes a difficulty it cannot explain, and supplies a refinement that resolves the difficulty.","is_correct":true,"explanation":"Correct: the sun-compass belief leaves the overcast-day puzzle, which polarized-light perception resolves as a refinement."},{"id":"B","text":"It debunks the claim that bees use the sun to navigate.","is_correct":false,"explanation":"Wrong: the text affirms bees orient by the sun, calling the view underspecified, not false."},{"id":"C","text":"It compares bee navigation with that of migratory birds.","is_correct":false,"explanation":"Wrong: no comparison with birds appears."},{"id":"D","text":"It argues that overcast weather makes foraging impossible for bees.","is_correct":false,"explanation":"Wrong: the text says bees forage efficiently even when overcast."}]'::jsonb, 'A', 'Step 1 — Name the puzzle
The sun-compass belief is challenged because bees forage well on {{yellow:heavily overcast days when the sun is invisible}}.
Step 2 — Supply the refinement
Polarized light resolves it, so the account is {{yellow:not so much wrong as underspecified}}.
Distractor analysis:
- B: The text affirms, not debunks, sun-based navigation.
- C: No bird comparison is made.
- D: Bees do forage when overcast, contradicting this.', 'The passage keeps the original idea but fills in a missing mechanism.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a7a292ce-533e-4ea8-87fc-69e1ff1f65e1', 'Which choice best states the main purpose of the text?', 'The short story collection opens with a narrator who insists on her own reliability, peppering her account with dates, measurements, and the precise wording of remembered conversations. A trusting reader might take her at her word. But as the stories accumulate, small discrepancies surface: a coat described as blue in one tale is brown in the next; an aunt said to have died young reappears, aged, three stories later. The author never flags these contradictions. The effect is to transfer the work of judgment to the reader, who must decide how much of the narrator''s confident precision to believe.', NULL, '[{"id":"A","text":"To explain how a narrator''s surface precision, undercut by quiet contradictions, shifts interpretive judgment onto the reader.","is_correct":true,"explanation":"Correct: the text shows the narrator''s confident detail, the unflagged discrepancies, and the resulting transfer of judgment to the reader."},{"id":"B","text":"To praise the collection as the author''s most autobiographical work.","is_correct":false,"explanation":"Wrong: nothing addresses autobiography."},{"id":"C","text":"To warn readers against trusting any first-person narrator.","is_correct":false,"explanation":"Wrong: the text analyzes one collection''s effect, not a general warning."},{"id":"D","text":"To summarize the plots of the collection''s individual stories.","is_correct":false,"explanation":"Wrong: it cites details to make a point, not to summarize plots."}]'::jsonb, 'A', 'Step 1 — Set up the precision
The narrator insists on reliability with {{yellow:dates, measurements, and the precise wording of remembered conversations}}.
Step 2 — Undercut and transfer
Unflagged discrepancies mean the effect is {{yellow:to transfer the work of judgment to the reader}}.
Distractor analysis:
- B: Autobiography is never mentioned.
- C: It analyzes one work, not all narrators.
- D: Details serve the argument, not a plot summary.', 'Track how the narrator''s confident detail and the slipups together affect the reader''s role.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('031116e3-543f-4010-b68b-18925eb0dfc5', 'Which choice best describes the overall structure of the text?', 'Economists once modeled consumers as relentlessly rational, always choosing the option that maximized measurable benefit. Experiments in behavioral economics have softened that portrait. People, it turns out, weigh losses more heavily than equivalent gains, cling to options merely because they already own them, and are swayed by how choices are framed. None of this means consumers are irrational in any sweeping sense; their departures from the old model are systematic, predictable, and often sensible given limited time and information. The revised view does not abandon rationality so much as relocate it, finding reason in patterns the earlier model had dismissed as noise.', NULL, '[{"id":"A","text":"It describes an older model, presents findings that complicate it, and recasts those findings as a refinement rather than a rejection.","is_correct":true,"explanation":"Correct: the rational-consumer model is complicated by behavioral findings, which the text recasts as relocating rather than abandoning rationality."},{"id":"B","text":"It proves that consumers behave entirely irrationally.","is_correct":false,"explanation":"Wrong: the text denies any sweeping irrationality, calling departures systematic and sensible."},{"id":"C","text":"It traces the careers of the economists who founded behavioral economics.","is_correct":false,"explanation":"Wrong: no economists'' careers are traced."},{"id":"D","text":"It lists shopping tips drawn from behavioral research.","is_correct":false,"explanation":"Wrong: it offers no consumer advice."}]'::jsonb, 'A', 'Step 1 — Old model
Consumers were modeled as {{yellow:relentlessly rational}}.
Step 2 — Refine, not reject
The revised view {{yellow:does not abandon rationality so much as relocate it}}, treating findings as a refinement.
Distractor analysis:
- B: Sweeping irrationality is explicitly denied.
- C: No careers are traced.
- D: No shopping tips are offered.', 'The ending insists the new findings relocate rationality rather than throw it out.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fa1f73f5-9e58-4b30-9db3-0d857cd4f452', 'Which choice best states the main purpose of the text?', 'The river delta had been mapped, surveyed, and declared stable for navigation. Pilots relied on charts that placed the main channel along the eastern bank. Then a single season of unusually heavy floods rearranged the riverbed overnight, silting up the old channel and carving a new one to the west. The charts, accurate the day they were printed, were now actively dangerous. Engineers drew a lesson broader than the delta itself: a map of a living river records not a permanent truth but a single moment, and the faith that a survey, once completed, can be trusted indefinitely is a faith the river does not share.', NULL, '[{"id":"A","text":"To use a delta''s sudden reshaping to illustrate the limits of treating a survey as permanently valid.","is_correct":true,"explanation":"Correct: the flood-shifted channel renders the charts dangerous, illustrating that a survey records only a moment."},{"id":"B","text":"To explain the engineering techniques used to dredge silted channels.","is_correct":false,"explanation":"Wrong: dredging techniques are not described."},{"id":"C","text":"To warn pilots that all river navigation is inherently unsafe.","is_correct":false,"explanation":"Wrong: the point concerns outdated maps, not blanket unsafety."},{"id":"D","text":"To celebrate the accuracy of the original delta survey.","is_correct":false,"explanation":"Wrong: the text stresses the survey became dangerous, not its lasting accuracy."}]'::jsonb, 'A', 'Step 1 — The reversal
Floods rearranged the riverbed so that the charts were {{yellow:now actively dangerous}}.
Step 2 — The broader lesson
Engineers conclude a river map {{yellow:records not a permanent truth but a single moment}}, illustrating the limits of trusting a survey indefinitely.
Distractor analysis:
- B: No dredging techniques appear.
- C: It targets outdated maps, not all navigation.
- D: It emphasizes the survey''s obsolescence, not lasting accuracy.', 'The specific delta story is told to make a general point about maps and time.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('93a69958-88bc-4b14-8734-700fb75b589c', 'Which choice best describes the overall structure of the text?', 'Historians of the medieval guild long portrayed it as a purely economic institution, a body for fixing prices and protecting trades. This account captures much, but it omits a dimension the records make plain. Guild registers devote as much space to funerals, feast days, and the care of widows as to wages and quality standards. Membership conferred not only the right to practice a craft but a place in a community that buried its dead and fed its poor. To see the guild only as an economic actor, then, is to read half its ledger and ignore the other half, where its social and ceremonial life was recorded with equal care.', NULL, '[{"id":"A","text":"It grants the value of a standard view and then broadens it by adding a dimension the records reveal.","is_correct":true,"explanation":"Correct: the economic account is granted as capturing much, then broadened by the guild''s social and ceremonial life."},{"id":"B","text":"It rejects the economic view of guilds as entirely mistaken.","is_correct":false,"explanation":"Wrong: the text says the economic account ''captures much,'' so it is not entirely rejected."},{"id":"C","text":"It compares medieval guilds with modern labor unions.","is_correct":false,"explanation":"Wrong: no comparison with unions appears."},{"id":"D","text":"It argues that guilds were never concerned with economic matters.","is_correct":false,"explanation":"Wrong: the text affirms guilds fixed prices and protected trades."}]'::jsonb, 'A', 'Step 1 — Grant the standard view
The economic portrayal {{yellow:captures much}} about guilds.
Step 2 — Broaden it
Registers cover {{yellow:funerals, feast days, and the care of widows}}, so the text adds a social dimension the records reveal.
Distractor analysis:
- B: The economic view is granted, not entirely rejected.
- C: No union comparison is made.
- D: The text affirms guilds'' economic role.', 'The passage keeps the economic reading but says it tells only half the story.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bf8df943-1f1c-4447-9322-7db99aeb03a4', 'Which choice best states the main purpose of the text?', 'A popular account of memory likens it to a video recording, faithfully storing events for later replay. Cognitive scientists find the metaphor doubly misleading. First, remembering is reconstructive: each recollection is rebuilt from fragments, and the act of recalling can alter the memory itself, so that no two replays are quite identical. Second, this very malleability serves a purpose. A memory that updates with new information is more useful for predicting the future than a rigid archive of the past would be. What the recording metaphor treats as a flaw, then, the science reframes as a feature, suited to a mind built less for storage than for anticipation.', NULL, '[{"id":"A","text":"To challenge a familiar metaphor for memory and recast the trait it faults as a functional advantage.","is_correct":true,"explanation":"Correct: the text rejects the recording metaphor and reframes memory''s malleability from flaw to purposeful feature."},{"id":"B","text":"To advise readers on techniques for improving memory accuracy.","is_correct":false,"explanation":"Wrong: no memory-improvement techniques are offered."},{"id":"C","text":"To prove that human memory cannot be trusted at all.","is_correct":false,"explanation":"Wrong: the text reframes malleability as useful, not as making memory wholly untrustworthy."},{"id":"D","text":"To trace the history of how scientists first studied memory.","is_correct":false,"explanation":"Wrong: no historical account of memory research is given."}]'::jsonb, 'A', 'Step 1 — Reject the metaphor
Scientists find the video-recording metaphor {{yellow:doubly misleading}} because remembering is reconstructive.
Step 2 — Recast the trait
The science reframes what the metaphor treats {{yellow:as a flaw, then, the science reframes as a feature}}, suited to anticipation.
Distractor analysis:
- B: No improvement techniques are given.
- C: Malleability is called useful, not wholly untrustworthy.
- D: No history of memory research is traced.', 'The final sentence flips a supposed flaw into a feature.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('40d99789-2195-4515-ba87-1a77d502bf4c', 'Which choice best describes the overall structure of the text?', 'For decades, naturalists assumed that the elaborate songs of humpback whales served only to attract mates during the breeding season. Recordings made from a single ocean basin seemed to confirm this view, since the songs were most frequent when females were present. More recent fieldwork, however, has complicated the picture. Researchers tracking males far from any breeding grounds discovered that solitary individuals continued to sing for hours, often when no other whales were within acoustic range. Such observations suggest that song may also function as a tool for spacing animals across vast distances or for advertising an individual''s location to distant rivals, purposes unrelated to immediate courtship.', NULL, '[{"id":"A","text":"It presents a long-held explanation and then introduces evidence that qualifies that explanation.","is_correct":true,"explanation":"Correct: the text states the traditional courtship assumption, then offers new observations that complicate and limit it."},{"id":"B","text":"It describes a scientific controversy and then resolves it definitively in favor of one side.","is_correct":false,"explanation":"The text says the new findings only \"suggest\" alternatives and never claims a definitive resolution."},{"id":"C","text":"It catalogs several competing theories without favoring any of them.","is_correct":false,"explanation":"Only one prior assumption is described, not several competing theories given equal weight."},{"id":"D","text":"It traces the chronological development of recording technology used to study whales.","is_correct":false,"explanation":"Technology is mentioned only incidentally; the focus is on the function of song, not the tools'' history."}]'::jsonb, 'A', 'Step 1 — Identify the established view
The passage opens by noting that naturalists assumed song {{yellow:served only to attract mates during the breeding season}}.
Step 2 — Track the shift
It then reports that solitary males kept singing far from breeding grounds, evidence that complicates and limits, rather than overturns, the original claim.
Distractor analysis:
- B: No definitive resolution occurs; the new data only "suggest" further functions.
- C: A single prior assumption is presented, not multiple competing theories.
- D: Recording technology is incidental background, not the organizing focus.', 'Notice the word ''however'' and whether the new evidence overturns or merely limits the old idea.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ef68854e-3aea-4375-b5c5-5ffc6274bb42', 'Which choice best describes the overall structure of the text?', 'The novel''s narrator insists, in its opening pages, that she remembers her childhood village with perfect clarity, listing the exact color of each shutter and the order of houses along the lane. As the chapters proceed, however, her account begins to betray itself. She describes the same well as both stone and brick, places a neighbor''s death before and after a festival, and admits, almost in passing, that she has not returned in forty years. By the novel''s midpoint, the reader can no longer take her descriptions at face value, and the village she so confidently mapped dissolves into something closer to longing than to fact.', NULL, '[{"id":"A","text":"It establishes a narrator''s claim of reliability and then accumulates details that undermine it.","is_correct":true,"explanation":"Correct: the text begins with the narrator''s claim of perfect memory, then gathers contradictions that erode it."},{"id":"B","text":"It compares two narrators with conflicting accounts of the same village.","is_correct":false,"explanation":"Only one narrator is discussed throughout the passage."},{"id":"C","text":"It defends the narrator''s memory against a reader''s skepticism.","is_correct":false,"explanation":"The text does the opposite, showing why the narrator should not be trusted."},{"id":"D","text":"It summarizes the plot events of the village''s history in order.","is_correct":false,"explanation":"The passage tracks the narrator''s credibility, not a chronological village history."}]'::jsonb, 'A', 'Step 1 — Note the opening claim
The narrator insists she remembers the village {{yellow:with perfect clarity}}, even listing each shutter''s color.
Step 2 — Track the contradictions
The text then piles up inconsistencies until the reader "can no longer take her descriptions at face value," undermining that claim.
Distractor analysis:
- B: There is only one narrator, not two.
- C: The text erodes rather than defends her memory.
- D: It analyzes reliability, not an ordered village history.', 'Watch what happens to the narrator''s confident opening claim as the details pile up.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5eb23dcc-acbd-4e11-aafd-f8a820ae0d4a', 'Which choice best states the main purpose of the text?', 'When archaeologists first excavated the abandoned settlement, the absence of defensive walls led many to conclude that its inhabitants had lived in unusual peace. The argument seemed reasonable: no ramparts, no warfare. Yet a closer reading of the evidence invites caution. Walls decay, are quarried for later building, or were never built of stone in the first place; their absence today says little about the past. Moreover, the settlement''s storage pits show signs of deliberate burning, and several skeletons bear healed fractures. Rather than proving tranquility, the missing walls may simply reflect the limits of what survives for us to find.', NULL, '[{"id":"A","text":"To challenge an inference drawn from absent evidence by noting what the evidence cannot establish.","is_correct":true,"explanation":"Correct: the text questions the peace conclusion by arguing that missing walls prove little."},{"id":"B","text":"To prove that the settlement was frequently attacked by neighboring groups.","is_correct":false,"explanation":"The text raises doubts but never proves the settlement was attacked; it says the burning \"may\" reflect limits of preservation."},{"id":"C","text":"To describe the standard methods archaeologists use to date settlements.","is_correct":false,"explanation":"Dating methods are not discussed; the focus is on interpreting absent walls."},{"id":"D","text":"To celebrate the discovery of an unusually peaceful ancient community.","is_correct":false,"explanation":"The text undercuts, rather than celebrates, the claim of peace."}]'::jsonb, 'A', 'Step 1 — Identify the inference under scrutiny
Many concluded the inhabitants {{yellow:had lived in unusual peace}} because no walls were found.
Step 2 — Explain the rebuttal
The text warns that walls decay or were never stone, so their absence "says little about the past," challenging the inference.
Distractor analysis:
- B: It only raises doubt; it never proves attacks occurred.
- C: No dating methods are described.
- D: The text undermines rather than celebrates the peace claim.', 'Ask whether the author accepts the ''no walls means peace'' reasoning or pushes back on it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8c2a8114-1894-4844-ba2d-55107b3036de', 'Which choice best describes the overall structure of the text?', 'Early economists treated household labor as if it lay outside the economy altogether, since cooking, cleaning, and childcare generated no wages and entered no ledgers. National accounts, built to measure market transactions, simply omitted such work. This framing persisted for generations. In recent years, however, scholars have begun to estimate the monetary value of unpaid domestic labor, and their figures are startling: when counted, this hidden work can rival a nation''s manufacturing output. By assigning a price to tasks once deemed invisible, these researchers do not merely add a number to a table; they force a reconsideration of what an economy is and whose contributions it records.', NULL, '[{"id":"A","text":"It describes a long-standing omission and then explains how recent work reframes its significance.","is_correct":true,"explanation":"Correct: the text shows household labor was long excluded, then how new estimates force a reconsideration."},{"id":"B","text":"It proposes a new method for calculating national manufacturing output.","is_correct":false,"explanation":"Manufacturing is a point of comparison, not the subject of a new method."},{"id":"C","text":"It argues that early economists were deliberately deceptive in their accounting.","is_correct":false,"explanation":"The text describes an omission rooted in how accounts were built, not deliberate deception."},{"id":"D","text":"It lists the daily tasks involved in maintaining a household.","is_correct":false,"explanation":"Tasks are mentioned only to illustrate the larger argument about measurement."}]'::jsonb, 'A', 'Step 1 — Establish the omission
Early economists treated household labor {{yellow:as if it lay outside the economy altogether}} because it produced no wages.
Step 2 — Show the reframing
Recent scholars price that work and "force a reconsideration of what an economy is," giving the omission new significance.
Distractor analysis:
- B: Manufacturing is only a comparison, not the topic of a new method.
- C: The text cites how accounts were built, not deliberate deception.
- D: Tasks merely illustrate the broader measurement point.', 'Track the move from ''this was left out'' to ''now its inclusion changes how we think.''', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('93aa13c2-b556-439d-a119-c9eea954e5b2', 'Which choice best describes the overall structure of the text?', 'The poem opens in a register of pure celebration, praising the orchard in bloom, the bees at their patient work, and the warmth of an afternoon that seems it might last forever. For three stanzas the speaker withholds any shadow. Then a single line interrupts: the gardener who planted these trees, we learn, died in the winter and will never see them fruit. The remaining stanzas do not abandon the orchard''s beauty, but they recast it. What had been simple delight becomes elegy, the blossoms now read as a kind of memorial, lovely precisely because someone is no longer present to enjoy them.', NULL, '[{"id":"A","text":"It describes a poem''s celebratory opening and then explains how a later revelation recasts that mood.","is_correct":true,"explanation":"Correct: the text presents the joyful opening, then shows how the gardener''s death transforms it into elegy."},{"id":"B","text":"It contrasts two different poems about the same orchard.","is_correct":false,"explanation":"Only one poem is discussed throughout."},{"id":"C","text":"It criticizes the poem for abandoning its initial beauty.","is_correct":false,"explanation":"The text states the later stanzas \"do not abandon the orchard''s beauty\" but recast it."},{"id":"D","text":"It explains the gardening techniques referenced in the poem.","is_correct":false,"explanation":"Gardening technique is not the focus; the shift in tone is."}]'::jsonb, 'A', 'Step 1 — Establish the opening mood
The poem begins {{yellow:in a register of pure celebration}}, praising the blooming orchard for three stanzas.
Step 2 — Track the recasting
The revelation of the gardener''s death turns "simple delight" into elegy, recasting the earlier beauty.
Distractor analysis:
- B: There is one poem, not two.
- C: The beauty is recast, not abandoned, per the text.
- D: Gardening technique is not the subject.', 'Find the single interrupting line and consider how it changes everything before it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3b1b992f-e9e2-403e-96ef-d349542181ec', 'Which choice best states the main purpose of the text?', 'Conventional wisdom holds that cities grow because they offer jobs, and that people move wherever wages are highest. This account explains a great deal, but it leaves a puzzle: some of the fastest-growing cities of the past decade pay no more, and sometimes less, than the regions migrants leave behind. Surveys of recent arrivals point toward an overlooked factor. Many cite milder climate, cultural amenities, or the simple presence of friends already settled there. None of this means wages are irrelevant; rather, it suggests that the wage-driven model captures one motive among several and cannot, on its own, account for where populations actually choose to settle.', NULL, '[{"id":"A","text":"To qualify a familiar explanation of urban growth by identifying motives it overlooks.","is_correct":true,"explanation":"Correct: the text limits the wage-driven model by pointing to non-wage motives it misses."},{"id":"B","text":"To reject the idea that wages influence migration at all.","is_correct":false,"explanation":"The text explicitly says \"None of this means wages are irrelevant.\""},{"id":"C","text":"To rank the world''s fastest-growing cities by population.","is_correct":false,"explanation":"No ranking of cities is offered."},{"id":"D","text":"To prove that climate is the single most important driver of migration.","is_correct":false,"explanation":"Climate is one of several cited motives, not proven to be the single most important."}]'::jsonb, 'A', 'Step 1 — State the familiar view
Conventional wisdom holds that {{yellow:people move wherever wages are highest}}.
Step 2 — Apply the qualification
The text adds non-wage motives and concludes the model "cannot, on its own, account for" settlement, qualifying rather than rejecting it.
Distractor analysis:
- B: The text says wages are not irrelevant, so it does not fully reject them.
- C: No ranking of cities appears.
- D: Climate is one motive among several, not proven supreme.', 'Decide whether the author throws out the wage model or just limits how much it explains.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c3353d30-a72d-486d-80c3-f16f1c8cfc47', 'Which choice best describes the overall structure of the text?', 'A common story about the printing press credits it with single-handedly spreading literacy across Europe. The image is appealing: a machine appears, and suddenly the masses read. The historical record, set in context, is less tidy. For more than a century after the press''s invention, books remained expensive, schools scarce, and most of the population unable to afford or decipher them. Literacy climbed only as paper grew cheaper, vernacular languages displaced Latin, and civic demand for reading expanded. The press was a necessary instrument, but it operated within a web of economic and social conditions that determined how quickly, and for whom, reading became possible.', NULL, '[{"id":"A","text":"It presents a simplified popular claim and then contextualizes it within broader conditions.","is_correct":true,"explanation":"Correct: the text states the press-equals-literacy claim, then situates it among economic and social factors."},{"id":"B","text":"It denies that the printing press had any effect on literacy.","is_correct":false,"explanation":"The text calls the press \"a necessary instrument,\" so it affirms an effect."},{"id":"C","text":"It explains the mechanical workings of early printing presses.","is_correct":false,"explanation":"The press''s mechanism is never described; its historical role is the subject."},{"id":"D","text":"It compares literacy rates in two different European countries.","is_correct":false,"explanation":"No comparison between specific countries is made."}]'::jsonb, 'A', 'Step 1 — Identify the popular claim
The common story credits the press with spreading literacy {{yellow:single-handedly}} across Europe.
Step 2 — Show the contextualizing move
The text then places the press within "a web of economic and social conditions," complicating the simple claim.
Distractor analysis:
- B: The press is called a necessary instrument, so its effect is not denied.
- C: No mechanical workings are described.
- D: No two-country comparison appears.', 'Notice how the author surrounds the press with other conditions rather than crediting it alone.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d9b769d1-9df1-4521-9d32-3e38b4a735d0', 'Which choice best describes the overall structure of the text?', 'When a new antibiotic enters use, it often seems miraculous, clearing infections that once proved fatal. Physicians in the 1940s greeted such drugs with understandable optimism, and some predicted that bacterial disease would soon be conquered. That confidence now reads as premature. Within a few years of widespread use, strains resistant to the drug began to appear, selected, ironically, by the very treatment meant to eliminate them. Each new antibiotic has tended to follow the same arc: dramatic early success, then a gradual erosion of effectiveness as resistant bacteria multiply. The pattern reframes resistance not as an occasional failure but as a predictable consequence of use itself.', NULL, '[{"id":"A","text":"It recounts an initial optimism and then explains a recurring pattern that tempers it.","is_correct":true,"explanation":"Correct: the text describes early optimism, then the resistance arc that reframes it as predictable."},{"id":"B","text":"It argues that antibiotics should no longer be prescribed to patients.","is_correct":false,"explanation":"The text never recommends abandoning antibiotics; it explains a pattern of resistance."},{"id":"C","text":"It details the chemical structure of a specific antibiotic.","is_correct":false,"explanation":"No chemical structure is described."},{"id":"D","text":"It celebrates the conquest of bacterial disease predicted in the 1940s.","is_correct":false,"explanation":"The text calls that confidence \"premature,\" undercutting the predicted conquest."}]'::jsonb, 'A', 'Step 1 — Establish the optimism
Physicians predicted that {{yellow:bacterial disease would soon be conquered}}.
Step 2 — Introduce the tempering pattern
The text then describes resistance emerging as a "predictable consequence of use itself," tempering that optimism.
Distractor analysis:
- B: It never advises against prescribing antibiotics.
- C: No chemical structure is given.
- D: The text labels the predicted conquest premature.', 'Look at how the early hope in the 1940s is reframed by the recurring resistance arc.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('679767f4-4e73-45ca-874c-e00f41f35bb0', 'Which choice best states the main purpose of the text?', 'The memoir''s author spends its first half portraying her father as a distant, forbidding figure, a man of silences and closed doors whose approval she could never seem to earn. The reader is primed to expect a familiar story of estrangement. Midway through, though, the author begins quoting from letters she discovered only after his death, letters in which he records, with awkward tenderness, his pride in her smallest achievements. The book''s second half does not erase the earlier distance, but it reinterprets it, suggesting that what the daughter read as coldness may have been a reticence the father never learned to overcome.', NULL, '[{"id":"A","text":"To show how a memoir''s later evidence reinterprets the relationship it first depicted.","is_correct":true,"explanation":"Correct: the discovered letters lead the author to reinterpret the father''s earlier distance."},{"id":"B","text":"To prove that the father never cared about his daughter.","is_correct":false,"explanation":"The letters reveal pride and tenderness, contradicting this claim."},{"id":"C","text":"To offer advice on repairing strained family relationships.","is_correct":false,"explanation":"No advice is offered; the text analyzes a memoir''s structure."},{"id":"D","text":"To compare two memoirs written about the same father.","is_correct":false,"explanation":"Only one memoir is discussed."}]'::jsonb, 'A', 'Step 1 — Establish the first impression
The first half portrays the father as {{yellow:a distant, forbidding figure}} whose approval she could not earn.
Step 2 — Show the reinterpretation
The discovered letters lead the author to reread that coldness as reticence, reinterpreting the relationship without erasing it.
Distractor analysis:
- B: The letters show pride, so he did care.
- C: No relationship advice is given.
- D: There is only one memoir.', 'Consider what the discovered letters do to the daughter''s earlier reading of her father.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fba493fa-c75c-4a3d-909f-3d3290342577', 'Which choice best states the main purpose of the text?', 'Visitors to the museum often assume that the gleaming marble statues of antiquity were meant to appear as they do now: pure white, austere, untouched by color. This assumption has shaped centuries of taste, inspiring artists to imitate a starkness that never existed. Yet traces of pigment, invisible to the naked eye, survive on many ancient surfaces and can be detected under ultraviolet light. Analysis reveals that these sculptures were once vividly painted, their robes crimson, their eyes lined, their hair gilded. The familiar white marble, far from being the artists'' intention, is merely what time and weathering have left behind.', NULL, '[{"id":"A","text":"To correct a widespread assumption by presenting evidence of the statues'' original appearance.","is_correct":true,"explanation":"Correct: the text overturns the white-marble assumption using pigment evidence revealing original color."},{"id":"B","text":"To explain how ultraviolet light is generated in laboratories.","is_correct":false,"explanation":"Ultraviolet light is a tool here, not the subject; its generation is not explained."},{"id":"C","text":"To argue that ancient sculptors were more skilled than modern ones.","is_correct":false,"explanation":"No comparison of skill across eras is made."},{"id":"D","text":"To trace how museum collections of marble statues were assembled.","is_correct":false,"explanation":"The text discusses appearance and pigment, not collection history."}]'::jsonb, 'A', 'Step 1 — State the assumption
Visitors assume the statues were meant to appear {{yellow:pure white, austere, untouched by color}}.
Step 2 — Present the correction
Detected pigment shows the sculptures were "once vividly painted," correcting the assumption.
Distractor analysis:
- B: UV light is merely a detection tool, not the topic.
- C: No cross-era skill comparison is made.
- D: Collection history is not discussed.', 'Identify the belief about white marble and what the pigment evidence does to it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('511b33e2-fda4-4bc4-90ea-59ad60ec3c5e', 'Which choice best states the main purpose of the text?', 'It is tempting to read the dramatic spike in a coral reef''s fish population one summer as a triumph for the new marine reserve established nearby. The timing aligns, and the conclusion flatters everyone involved. A marine biologist studying the site urges restraint. That same summer, she notes, an unusually warm current drove plankton into the area, drawing fish from far beyond the reserve''s boundaries. When the current shifted the following year, populations fell again, despite the reserve''s continued protection. The episode illustrates how a single favorable outcome can be mistaken for proof of a policy''s success when a transient natural event is doing the real work.', NULL, '[{"id":"A","text":"To use a specific case to warn against crediting a policy for an outcome a natural event produced.","is_correct":true,"explanation":"Correct: the reef example illustrates mistaking a transient current''s effect for the reserve''s success."},{"id":"B","text":"To recommend closing marine reserves that fail to raise fish populations.","is_correct":false,"explanation":"The text never recommends closing reserves; it warns about misattributing causes."},{"id":"C","text":"To describe the migratory patterns of plankton across oceans.","is_correct":false,"explanation":"Plankton movement is one detail in the example, not the text''s purpose."},{"id":"D","text":"To prove that marine reserves are entirely ineffective.","is_correct":false,"explanation":"The text questions one inference, not the general value of reserves."}]'::jsonb, 'A', 'Step 1 — Identify the tempting conclusion
It is tempting to read the population spike as {{yellow:a triumph for the new marine reserve}}.
Step 2 — Deliver the warning
The biologist shows a warm current, not the reserve, drove the fish, warning against the misattribution.
Distractor analysis:
- B: No recommendation to close reserves is made.
- C: Plankton movement is a supporting detail, not the purpose.
- D: The text targets one inference, not reserves in general.', 'Watch what the biologist''s warm-current explanation does to the ''reserve worked'' conclusion.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('92afc361-18e7-43c2-be7f-e4a5e5701987', 'Which choice best describes the overall structure of the text?', 'Histories of the railroad usually celebrate the speed it brought, collapsing journeys that once took days into a matter of hours. Speed, in these accounts, is the whole story. A subtler change, however, often goes unmentioned. Before the railroad, each town kept its own local time, set by the sun, so that noon in one city might be 12:15 in another. Coordinating train schedules across such a patchwork proved impossible, and railway companies imposed standardized time zones to make their timetables coherent. The clock on the station wall, in other words, was as much a product of the railroad as the engine itself, reshaping how people measured their days.', NULL, '[{"id":"A","text":"It notes the usual emphasis of railroad histories and then delineates a less-recognized effect.","is_correct":true,"explanation":"Correct: the text contrasts the standard focus on speed with the overlooked standardization of time."},{"id":"B","text":"It explains how steam engines were manufactured in the railroad era.","is_correct":false,"explanation":"Engine manufacturing is not discussed; standardized time is the focus."},{"id":"C","text":"It argues that railroads were slower than earlier forms of travel.","is_correct":false,"explanation":"The text affirms the railroad''s speed; it does not dispute it."},{"id":"D","text":"It lists the cities that first adopted standardized time zones.","is_correct":false,"explanation":"No list of specific adopting cities is provided."}]'::jsonb, 'A', 'Step 1 — State the usual emphasis
Histories usually celebrate the railroad''s speed, in which {{yellow:Speed, in these accounts, is the whole story}}.
Step 2 — Delineate the overlooked effect
The text then explains how railways imposed standardized time zones, a less-recognized consequence.
Distractor analysis:
- B: Engine manufacturing is never discussed.
- C: The text affirms, not disputes, the railroad''s speed.
- D: No list of adopting cities appears.', 'Find what the usual histories leave out and how the author foregrounds it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6ece8edc-5797-4c3d-afe4-2cb1cb19c5ff', 'Which choice best states the main purpose of the text?', 'For decades, the standard account held that the dramatic dark bands on Jupiter''s moon Europa were fractures stained by salts welling up from a subsurface ocean. A recent reanalysis does not dispute that an ocean exists, nor that the bands are fractures. Instead, it reexamines what fills them. Laboratory simulations suggest the staining material is not ocean salt at all but irradiated sulfur compounds delivered by Jupiter''s magnetosphere and chemically altered at the surface. The bands, on this view, record not the moon''s interior but its exposure to a hostile radiation environment. The ocean, long treated as the bands'' author, may be merely their canvas.', NULL, '[{"id":"A","text":"To prove that Europa''s subsurface ocean does not exist and never did","is_correct":false,"explanation":"The text explicitly says the reanalysis \"does not dispute that an ocean exists,\" so this reverses the passage."},{"id":"B","text":"To qualify a long-held explanation by relocating the source of a feature it described","is_correct":true,"explanation":"The reanalysis keeps the ocean and the fractures but reassigns the staining to radiation chemistry, narrowing rather than overturning the standard account."},{"id":"C","text":"To describe the laboratory techniques used to simulate Europa''s surface conditions","is_correct":false,"explanation":"Lab simulations are mentioned only as evidence; explaining their techniques is not the passage''s aim."},{"id":"D","text":"To argue that Jupiter''s magnetosphere is more scientifically important than its moons","is_correct":false,"explanation":"The text never ranks the magnetosphere above the moons; this is an unsupported synthesis."}]'::jsonb, 'B', 'Step 1 — Identify what survives the revision
The passage stresses the reanalysis {{yellow:does not dispute that an ocean exists, nor that the bands are fractures}}, so the core picture is retained, not destroyed.
Step 2 — Identify the narrow change
It only reassigns the staining material''s origin from ocean to radiation, which is a qualification of the old account rather than a rejection of it.
Distractor analysis:
- A: Reverses the text, which affirms the ocean still exists.
- C: Too narrow; lab methods are evidence, not the purpose.
- D: No-evidence synthesis; no ranking of magnetosphere over moons is made.', 'Notice how much of the old explanation the new analysis keeps versus what small piece it actually changes.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c812c0a3-d1e6-4186-945b-d5479d307b4e', 'Which choice best describes the overall structure of the text?', 'In her 1928 essays, the novelist Renata Vall insisted that a city could be read like a sentence, its avenues serving as clauses and its plazas as the pauses between them. Critics seized on the metaphor as proof that she viewed architecture as a kind of language. Yet Vall herself grew impatient with such literalism. In a late letter she clarified that the comparison was meant to fail at a certain point: a sentence ends, she wrote, but a city refuses closure, accumulating meanings no grammar can resolve. The metaphor''s value lay precisely in where it broke down.', NULL, '[{"id":"A","text":"It presents a writer''s metaphor, notes how it was interpreted, then records the writer''s own correction of that interpretation","is_correct":true,"explanation":"The passage moves from Vall''s city-as-sentence figure, to critics'' literal reading, to her letter limiting the metaphor."},{"id":"B","text":"It traces the gradual abandonment of a metaphor across a writer''s entire career","is_correct":false,"explanation":"Vall refines, not abandons, the metaphor; she affirms its value in its breakdown."},{"id":"C","text":"It contrasts two rival critics who disagreed about a novelist''s intentions","is_correct":false,"explanation":"Only one critical reading appears; there is no debate between rival critics."},{"id":"D","text":"It defends the claim that architecture is fundamentally a form of language","is_correct":false,"explanation":"Vall''s letter resists exactly this literal equation, so the text does not defend it."}]'::jsonb, 'A', 'Step 1 — Track the three moves
The text gives the metaphor, then the critics who took it as proof architecture is language, then Vall''s letter saying {{yellow:the comparison was meant to fail at a certain point}}.
Step 2 — Match the structure
That sequence is figure, reception, and authorial correction, which is exactly option A.
Distractor analysis:
- B: She refines rather than abandons; she affirms the metaphor''s value.
- C: There is one critical reading, not two rival critics.
- D: The text undercuts the literal language claim instead of defending it.', 'Count the distinct stages and ask whether the writer rejects or merely limits her own image.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('31449044-d557-454f-a2f6-9c7ad74346fd', 'Which choice best states the main purpose of the text?', 'Economists once treated the "paradox of thrift" as a curiosity: if every household saves more during a downturn, aggregate demand falls and incomes shrink, leaving total savings no higher. A newer line of work accepts the mechanism but disputes its scope. In economies where banks readily lend household savings to firms eager to invest, the paradox dissolves; saved funds re-enter circulation as investment. The paradox bites only when investment demand is itself depressed. What earlier theorists offered as a universal law thus reappears as a special case, valid under conditions that are common in slumps but far from guaranteed.', NULL, '[{"id":"A","text":"To reject the paradox of thrift as a logical error made by earlier economists","is_correct":false,"explanation":"The newer work \"accepts the mechanism,\" so the paradox is not rejected as an error."},{"id":"B","text":"To recount the historical origins of the paradox of thrift in detail","is_correct":false,"explanation":"The text gives no historical origin story; it focuses on the scope of the idea."},{"id":"C","text":"To recast a supposedly universal principle as one that holds only under specific conditions","is_correct":true,"explanation":"The passage keeps the mechanism but shows it applies only when investment demand is depressed, converting a law into a special case."},{"id":"D","text":"To recommend that households save less during economic downturns","is_correct":false,"explanation":"The text offers no policy advice to households; it analyzes when the paradox applies."}]'::jsonb, 'C', 'Step 1 — See what is preserved and what is limited
The newer work {{yellow:accepts the mechanism but disputes its scope}}, keeping the logic while restricting where it holds.
Step 2 — Name the move
Turning a universal law into a conditionally valid special case is precisely recasting a principle''s scope, option C.
Distractor analysis:
- A: The mechanism is accepted, not rejected as an error.
- B: No historical origins are recounted.
- D: No household savings advice is given.', 'The key phrase distinguishes the idea''s mechanism from its scope.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('78672286-9380-4bc2-af15-37483e3bab0b', 'Which choice best describes the overall structure of the text?', 'The conventional story of the Erie Canal credits engineering boldness for its success. A close look at the project''s first surveys complicates that triumphal narrative without denying the achievement. The early surveyors, lacking formal training, repeatedly miscalculated gradients, and several initial routes proved unbuildable. What saved the canal was not foresight but iteration: errors were caught, sections rerouted, and locks added where terrain refused the plan. The finished waterway, often cited as a monument to visionary design, is better understood as a monument to patient revision. Its grandeur was assembled mistake by corrected mistake.', NULL, '[{"id":"A","text":"It states a popular interpretation, then revises it by foregrounding a process the interpretation omits","is_correct":true,"explanation":"The text names the visionary-design story and replaces it with an account centered on iterative correction."},{"id":"B","text":"It disputes whether the Erie Canal was ever actually completed","is_correct":false,"explanation":"The text repeatedly calls it a finished, grand waterway; completion is never in question."},{"id":"C","text":"It catalogs the specific engineering tools used by the canal''s surveyors","is_correct":false,"explanation":"No tools are cataloged; the focus is on errors and revision, not equipment."},{"id":"D","text":"It praises the surveyors for their unusually rigorous formal training","is_correct":false,"explanation":"The text says the surveyors lacked formal training, contradicting this option."}]'::jsonb, 'A', 'Step 1 — Find the pivot
The passage reframes the canal as {{yellow:a monument to patient revision}} rather than visionary design.
Step 2 — Describe the shape
It offers the popular view and then revises it by spotlighting the omitted process of iteration, matching option A.
Distractor analysis:
- B: Completion is affirmed, never disputed.
- C: No tools are cataloged.
- D: The surveyors lacked formal training, the opposite of praised rigor.', 'What does the passage substitute for "visionary design" as the real cause?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('99cf1123-cf18-4f7c-993b-94cf702b8eec', 'Which choice best states the main purpose of the text?', 'Readers of the poet Aldous Finch have long admired his nature lyrics for their serenity. A reading of his notebooks unsettles that impression without overturning the poems'' surface calm. The drafts reveal that Finch repeatedly began each lyric in a register of panic—jagged lines about decay and loss—before sanding the language down to placidity over many revisions. The published serenity, then, is not the poet''s native temper but a hard-won suppression. The calm we praise is real, but it is the calm of a wound dressed, not a wound never received. The poems conceal the labor that produced them.', NULL, '[{"id":"A","text":"To reveal that a poet''s celebrated tranquility was effortfully constructed over a turbulent foundation","is_correct":true,"explanation":"The notebooks show the serene poems began in panic and were revised into calm, making the tranquility a hard-won construction."},{"id":"B","text":"To argue that Finch''s published poems are not actually calm at all","is_correct":false,"explanation":"The text affirms \"the calm we praise is real,\" so it does not deny the poems'' calm."},{"id":"C","text":"To provide a chronological biography of Finch''s publishing career","is_correct":false,"explanation":"No publishing chronology is offered; the focus is on the drafting process behind the calm."},{"id":"D","text":"To compare Finch''s nature lyrics with those of his contemporaries","is_correct":false,"explanation":"No contemporaries are mentioned, so no comparison is made."}]'::jsonb, 'A', 'Step 1 — Locate the hidden origin
The drafts show Finch''s calm poems were sanded from panic, so the serenity is {{yellow:a hard-won suppression}}.
Step 2 — State the purpose
The passage''s aim is to reveal that admired tranquility was effortfully built over turmoil, option A.
Distractor analysis:
- B: The calm is affirmed as real, not denied.
- C: No chronological biography is given.
- D: No contemporaries are compared.', 'The text grants the poems are calm but reinterprets where that calm comes from.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('42ac3a0b-21f7-47f3-84c4-13e9db765054', 'Which choice best describes the overall structure of the text?', 'It is tempting to praise the medieval guilds as early champions of worker solidarity. The records of one fourteenth-century weavers'' guild invite a more guarded assessment. The guild did protect its members—setting fair prices, insuring against fire, supporting widows—but it did so by rigidly excluding outsiders: women working at home, migrants, and unaffiliated laborers were barred from the trade entirely. The same charter that secured benefits for members codified the exclusion of everyone else. To call the guild a model of solidarity is to mistake a wall for an embrace; its generosity and its gatekeeping were two clauses of a single law.', NULL, '[{"id":"A","text":"It introduces a flattering label, then tempers it by showing the label rests on an inseparable exclusion","is_correct":true,"explanation":"The text grants the guild''s protections but ties them to barred outsiders, qualifying the solidarity label."},{"id":"B","text":"It denies that the weavers'' guild offered any benefits to its members","is_correct":false,"explanation":"The text lists fair prices, fire insurance, and widow support, so benefits are affirmed."},{"id":"C","text":"It traces how guild membership rules loosened over the fourteenth century","is_correct":false,"explanation":"No loosening over time is described; the charter''s exclusions are presented as fixed."},{"id":"D","text":"It celebrates the guild as a fully realized model of worker solidarity","is_correct":false,"explanation":"The text resists that celebration, calling it mistaking a wall for an embrace."}]'::jsonb, 'A', 'Step 1 — Spot the qualification
The passage says the guild''s benefits and barriers were {{yellow:two clauses of a single law}}, binding generosity to exclusion.
Step 2 — Describe the structure
It presents the flattering solidarity label and then tempers it by exposing an inseparable exclusion, matching A.
Distractor analysis:
- B: Benefits are explicitly listed, not denied.
- C: No change over time is traced.
- D: The text refuses to celebrate the guild this way.', 'The closing image links the guild''s help and its barriers as one thing.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('34a85b35-9b1b-40e8-a456-64550d21d0bd', 'Which choice best states the main purpose of the text?', 'Conservationists frequently invoke "pristine wilderness" as the goal of habitat restoration. Ecologist Mara Oduya''s fieldwork in the Pacific Northwest reframes that ideal rather than abandoning restoration itself. The forests prized as untouched, she shows, were in fact shaped for millennia by Indigenous burning practices that thinned undergrowth and favored certain species. Removing all human influence does not restore an original state; it produces a novel one the land has never known. Restoration, Oduya argues, should aim not at an imagined absence of people but at renewing a relationship. The wilderness ideal mistakes a particular human history for the lack of any history at all.', NULL, '[{"id":"A","text":"To abandon the practice of habitat restoration as scientifically incoherent","is_correct":false,"explanation":"The text says Oduya reframes the ideal \"rather than abandoning restoration itself.\""},{"id":"B","text":"To redefine a conservation goal by exposing a hidden human history within a supposedly untouched landscape","is_correct":true,"explanation":"Oduya shows the \"pristine\" forests were shaped by Indigenous burning, redirecting restoration toward renewed relationship."},{"id":"C","text":"To detail the specific tree species favored by Indigenous burning practices","is_correct":false,"explanation":"The text mentions favored species only in passing, not as its purpose."},{"id":"D","text":"To prove that human activity always harms forest ecosystems","is_correct":false,"explanation":"The text shows human burning sustained the forests, contradicting universal harm."}]'::jsonb, 'B', 'Step 1 — Find the buried history
Oduya shows the prized forests were {{yellow:shaped for millennia by Indigenous burning practices}}, so the wilderness ideal hides a human past.
Step 2 — Name the aim
The purpose is to redefine the conservation goal by exposing that hidden history, option B.
Distractor analysis:
- A: Restoration is reframed, not abandoned.
- C: Favored species are incidental, not the purpose.
- D: Burning sustained the forest, contradicting universal harm.', 'The ideal of "untouched" is undermined by what the fieldwork reveals about the land''s past.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('52ca4c1f-3c0e-41d9-a424-8fe1ce0b98f4', 'Which choice best describes the overall structure of the text?', 'The legend that the composer Hadrian Vex destroyed his early symphonies in a single bonfire has hardened into biographical fact. A surviving customs ledger forces a more cautious telling without dismissing the destruction outright. The ledger records crates of Vex''s manuscripts shipped abroad in the very year of the supposed fire, suggesting that some scores survived and circulated. The bonfire may have happened, but it cannot have consumed everything, as the tidy legend requires. What the romantic story presents as a clean act of artistic self-erasure looks, in the archive, like a partial and untidy one—loss mixed with quiet preservation.', NULL, '[{"id":"A","text":"It repeats a familiar legend, then uses an archival record to complicate, though not erase, that legend","is_correct":true,"explanation":"The customs ledger shows some scores survived, qualifying the bonfire story without denying a fire occurred."},{"id":"B","text":"It proves conclusively that the bonfire never took place","is_correct":false,"explanation":"The text says \"the bonfire may have happened,\" so it does not disprove the fire."},{"id":"C","text":"It evaluates the artistic merit of Vex''s surviving symphonies","is_correct":false,"explanation":"No assessment of the music''s quality appears; the focus is on whether scores survived."},{"id":"D","text":"It explains the customs procedures for shipping manuscripts abroad","is_correct":false,"explanation":"The ledger is evidence about survival, not a lesson in customs procedure."}]'::jsonb, 'A', 'Step 1 — Identify the complicating evidence
The ledger implies the fire {{yellow:cannot have consumed everything, as the tidy legend requires}}, softening but not erasing the story.
Step 2 — Describe the shape
The text repeats the legend and then uses an archive to complicate it, option A.
Distractor analysis:
- B: A fire may still have happened; it is not disproven.
- C: No musical merit is evaluated.
- D: Customs procedure is not explained.', 'Does the new evidence kill the legend or just make it messier?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b875b71e-82b9-4c85-9e72-eccf769b15f5', 'Which choice best states the main purpose of the text?', 'Popular accounts present the placebo effect as proof that belief can heal the body directly. A careful review of controlled trials urges a narrower reading without dismissing the phenomenon. Much of what looks like placebo healing, the review notes, is statistical: patients tend to enroll when symptoms peak, so they improve afterward regardless of treatment. Genuine placebo responses do occur, but mainly for subjective, fluctuating complaints like pain and nausea—not for tumor size or infection. The effect is real yet bounded, powerful over perception and modest over pathology. To treat it as evidence that thought commands biology is to overstate a limited truth.', NULL, '[{"id":"A","text":"To deny that placebo effects exist in any genuine form","is_correct":false,"explanation":"The text states \"genuine placebo responses do occur,\" so it does not deny them."},{"id":"B","text":"To explain the statistical methods used in modern clinical trials","is_correct":false,"explanation":"Statistics appear as one factor, not as the passage''s explanatory aim."},{"id":"C","text":"To delimit the placebo effect by distinguishing where it genuinely operates from where it does not","is_correct":true,"explanation":"The text bounds the effect to subjective complaints and denies it over pathology, restricting an overstated claim."},{"id":"D","text":"To recommend prescribing placebos for serious infections","is_correct":false,"explanation":"The text says placebos do not affect infection, so it would not recommend this."}]'::jsonb, 'C', 'Step 1 — Find the boundary
The review concludes the effect is {{yellow:powerful over perception and modest over pathology}}, drawing a sharp line.
Step 2 — State the purpose
The aim is to delimit where placebo genuinely works versus where it does not, option C.
Distractor analysis:
- A: Genuine responses are affirmed, not denied.
- B: Statistics are one factor, not the explanatory goal.
- D: Placebos are said not to help infection, so no such recommendation.', 'The passage neither denies nor inflates the effect; it draws a line around it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3234b9b7-18ad-4471-81fe-7c6e082359e6', 'Which choice best describes the overall structure of the text?', 'Histories of vaccination often open with Edward Jenner, as though immunization began with him. Records from eighteenth-century Constantinople call for a fuller frame rather than a new sole hero. Decades before Jenner, the practice of variolation—deliberately infecting people with mild smallpox to induce immunity—was widespread in the Ottoman world, observed and reported by European travelers. Jenner''s contribution was real: he substituted safer cowpox for live smallpox. But the underlying idea of inducing immunity was inherited, not invented. To begin the story with Jenner is not to tell a falsehood so much as to crop the picture, cutting away the longer tradition that made his refinement thinkable.', NULL, '[{"id":"A","text":"It identifies a customary starting point for a history, then situates that point within an older tradition it omits","is_correct":true,"explanation":"The text keeps Jenner''s contribution but places it after Ottoman variolation, contextualizing the usual origin."},{"id":"B","text":"It argues that Jenner made no genuine contribution to immunization","is_correct":false,"explanation":"The text calls Jenner''s contribution \"real,\" so it does not deny it."},{"id":"C","text":"It compares the relative safety of cowpox and smallpox in clinical detail","is_correct":false,"explanation":"Cowpox is mentioned only to specify Jenner''s refinement, not analyzed in clinical detail."},{"id":"D","text":"It claims that European travelers invented the practice of variolation","is_correct":false,"explanation":"Travelers observed and reported variolation; the text does not credit them with inventing it."}]'::jsonb, 'A', 'Step 1 — Find the reframing
The text says the idea of inducing immunity was {{yellow:inherited, not invented}}, placing Jenner within an older tradition.
Step 2 — Describe the structure
It names the customary starting point and then contextualizes it within an omitted tradition, option A.
Distractor analysis:
- B: Jenner''s contribution is called real.
- C: Cowpox is not analyzed in clinical detail.
- D: Travelers observed, not invented, variolation.', 'The closing metaphor of cropping a picture points to what the usual story leaves out.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1bcd1229-6af4-4050-af5b-db056d6949c6', 'Which choice best states the main purpose of the text?', 'The short stories of Junko Mariel are routinely called minimalist, prized for what they leave unsaid. A look at her revision habits suggests the label captures an effect while missing its cause. Mariel''s manuscripts show that her spare final texts grew out of enormous overwriting: she drafted long, explanatory passages and then deleted nearly all of them, leaving the silences charged with what had been removed. Her blankness is not emptiness but subtraction—each gap shaped by a sentence that once stood there. Calling her work minimalist describes the surface accurately while obscuring the maximalist labor beneath it.', NULL, '[{"id":"A","text":"To reject the description of Mariel''s stories as minimalist","is_correct":false,"explanation":"The text says the label \"captures an effect\" and \"describes the surface accurately,\" so it is not rejected."},{"id":"B","text":"To distinguish the accurate surface of a label from the hidden process the label conceals","is_correct":true,"explanation":"The text accepts minimalist as a surface description while revealing the maximalist subtraction beneath it."},{"id":"C","text":"To summarize the plots of several of Mariel''s short stories","is_correct":false,"explanation":"No plots are summarized; the focus is on her revision process."},{"id":"D","text":"To argue that overwriting always improves a finished story","is_correct":false,"explanation":"The text makes no general claim that overwriting improves stories."}]'::jsonb, 'B', 'Step 1 — Separate effect from cause
The label {{yellow:captures an effect while missing its cause}}, so the surface is accepted but the origin is hidden.
Step 2 — State the purpose
The aim is to distinguish the accurate label from the concealed maximalist process, option B.
Distractor analysis:
- A: The minimalist label is accepted as accurate on the surface.
- C: No plots are summarized.
- D: No general claim about overwriting is made.', 'The passage agrees the label fits the surface but points beneath it.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('db3fa506-c0a7-4a17-8799-d314c3239f66', 'Which choice best describes the overall structure of the text?', 'The Antikythera mechanism is often hailed as evidence that ancient Greeks possessed a lost "computer." A sober look at the device tempers the analogy without diminishing the achievement. The mechanism''s bronze gears did model astronomical cycles with startling precision, predicting eclipses and planetary positions. But it executed a single fixed sequence; it could not be reprogrammed, could not store input, could not branch. To call it a computer imports later concepts the object cannot bear. It is better understood as an extraordinary clockwork almanac—a triumph of mechanical calculation that nonetheless lacked the very flexibility the word "computer" implies.', NULL, '[{"id":"A","text":"It accepts a striking label and provides additional evidence confirming its full accuracy","is_correct":false,"explanation":"The text tempers the label, arguing the device \"could not be reprogrammed,\" so it does not confirm full accuracy."},{"id":"B","text":"It presents an arresting characterization, then narrows it by specifying capacities the object lacked","is_correct":true,"explanation":"The text grants the device''s precision but qualifies the \"computer\" label by listing what it could not do."},{"id":"C","text":"It denies that the Antikythera mechanism performed any astronomical function","is_correct":false,"explanation":"The text says it modeled astronomical cycles with precision, so this contradicts the passage."},{"id":"D","text":"It traces the modern rediscovery and excavation of the mechanism","is_correct":false,"explanation":"No rediscovery or excavation history appears in the text."}]'::jsonb, 'B', 'Step 1 — Identify the qualification
The text concedes the device''s precision but notes it {{yellow:could not be reprogrammed, could not store input, could not branch}}.
Step 2 — Describe the structure
It offers the arresting "computer" label and then narrows it by naming missing capacities, option B.
Distractor analysis:
- A: It tempers, not confirms, the label.
- C: Astronomical function is affirmed.
- D: No rediscovery history is traced.', 'The list of things the device could not do tells you whether the label is confirmed or narrowed.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0673c043-d6b8-459b-84c7-6df35906bd8b', 'Which choice best describes the overall structure of the text?', 'For decades, ecologists treated coral reefs as fragile constants, baselines against which to measure decline. Reefs were the standard, and any deviation from their lushness signified loss. Yet recent paleoecological surveys complicate this assumption. Sediment cores reveal that many reefs collapsed and regenerated repeatedly across millennia, their species composition shifting with each cycle. What earlier scientists read as a single stable state was, in fact, one frame in a long sequence of upheaval. The implication unsettles conservation orthodoxy: restoring a reef to its ''natural'' condition presumes a fixity the geological record does not support. The reef we mourn may be no more authentic than the reefs that came before it.', NULL, '[{"id":"A","text":"It presents an established interpretive premise, then introduces evidence that destabilizes the premise''s foundational assumption.","is_correct":true,"explanation":"Correct: the text first states the old baseline view, then uses core data to undermine its assumption of fixity."},{"id":"B","text":"It catalogs competing methods for measuring reef decline before endorsing the most rigorous one.","is_correct":false,"explanation":"No method is endorsed as most rigorous; the text questions a premise, not methodology rankings."},{"id":"C","text":"It traces the historical regeneration of a single reef to recommend a specific restoration protocol.","is_correct":false,"explanation":"No restoration protocol is recommended; the text in fact questions the premise behind restoration."},{"id":"D","text":"It defends conventional conservation goals against a recent paleoecological challenge.","is_correct":false,"explanation":"Reverse: the text advances the challenge rather than defending the conventional goals."}]'::jsonb, 'A', 'Step 1 — Locate the premise and its undoing
The text opens with the old view that reefs were {{yellow:fragile constants, baselines against which to measure decline}}, then cites cores showing reefs {{yellow:collapsed and regenerated repeatedly across millennia}}.
Step 2 — Map the structure
The new evidence directly attacks the assumption of fixity underlying the baseline view, so the structure presents an established premise and then destabilizes its foundation.
Distractor analysis:
- B: No competing measurement methods are catalogued or ranked; the focus is a premise, not methodology.
- C: No restoration protocol is recommended; the text actually questions the basis for restoration.
- D: Reverse of the text''s aim, which advances rather than rebuts the paleoecological challenge.', 'Track what the opening sentences assert versus what the ''Yet'' sentence does to that assertion.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0e1e9520-3561-4824-a514-cd9b88aa0d61', 'Which choice best states the main purpose of the text?', 'In her late notebooks, the novelist Aurelia Vance returns obsessively to a single image: a house glimpsed from a moving train. Critics once read this image as nostalgia, a longing for a fixed home she had lost. But the notebooks resist such tidiness. Vance never describes the house twice the same way; its windows multiply, its color drifts, its inhabitants vanish and reappear. The image, it becomes clear, is not a memory she is preserving but a problem she is testing—an experiment in how perception fails when its object refuses to hold still. To call it nostalgia is to mistake an inquiry for a yearning.', NULL, '[{"id":"A","text":"To argue that a recurring image in Vance''s notebooks functions as an investigation rather than the sentiment critics assumed.","is_correct":true,"explanation":"Correct: the text redefines the image as an ''inquiry,'' not the ''yearning'' critics named."},{"id":"B","text":"To establish that Vance regarded her lost home as the central subject of her mature fiction.","is_correct":false,"explanation":"The text disputes the lost-home reading rather than establishing it."},{"id":"C","text":"To compare Vance''s notebooks with the finished novels they eventually produced.","is_correct":false,"explanation":"No finished novels are compared; only the notebooks are discussed."},{"id":"D","text":"To document the inconsistencies in Vance''s prose as evidence of declining craft.","is_correct":false,"explanation":"The inconsistencies signal deliberate testing, not declining craft; no decline is claimed."}]'::jsonb, 'A', 'Step 1 — Identify the corrective move
Critics read the image as {{yellow:nostalgia, a longing for a fixed home she had lost}}, but the text recasts it as {{yellow:a problem she is testing}}.
Step 2 — State the purpose
The text''s aim is to replace the sentimental reading with one of active inquiry, so its purpose is to argue the image is an investigation, not a sentiment.
Distractor analysis:
- B: The text disputes the lost-home reading rather than establishing it as central.
- C: No finished novels appear; only notebooks are at issue, so no comparison is drawn.
- D: The shifting descriptions are framed as deliberate testing, not as evidence of declining craft.', 'Notice the contrast the word ''But'' sets up and where the passage lands at the end.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('46c5815c-8e1e-4bb5-9856-3f06c7bc6d21', 'Which choice best describes the overall structure of the text?', 'Economic historians have long credited the steam engine with launching sustained growth, treating it as the spark that ignited industrial takeoff. The narrative is seductive in its simplicity. A closer accounting, however, suggests the engine arrived as a latecomer to changes already underway. Decades before efficient steam power, gains in agricultural yield had freed labor, credit networks had deepened, and patent regimes had begun rewarding tinkerers. The engine did not create these conditions; it presupposed them. This is not to deny the engine''s force but to relocate it—from prime mover to amplifier of momentum a society had already generated.', NULL, '[{"id":"A","text":"It questions a familiar causal story, then reassigns the central object a more limited role within a prior sequence of developments.","is_correct":true,"explanation":"Correct: the text downgrades the engine from cause to amplifier of preexisting conditions."},{"id":"B","text":"It rejects the importance of the steam engine in favor of agricultural innovation alone.","is_correct":false,"explanation":"The text explicitly declines to deny the engine''s force, so it does not reject its importance."},{"id":"C","text":"It surveys multiple inventions to determine which most accelerated industrial growth.","is_correct":false,"explanation":"It does not survey inventions to rank accelerators; it reframes one object''s role."},{"id":"D","text":"It defends the conventional view of the steam engine against revisionist critics.","is_correct":false,"explanation":"Reverse: the text advances revision rather than defending the conventional view."}]'::jsonb, 'A', 'Step 1 — Find the reframing
The text opens by crediting the engine as {{yellow:the spark that ignited industrial takeoff}}, then argues it should move {{yellow:from prime mover to amplifier of momentum}}.
Step 2 — Map the structure
It questions the causal story and reassigns the engine a smaller role amid prior changes, matching choice A.
Distractor analysis:
- B: The text refuses to deny the engine''s force, so it does not exalt agriculture alone.
- C: No ranking survey of inventions occurs; one object is reframed.
- D: Reverse, since the text advances revision rather than defending the conventional view.', 'What does the ''however'' sentence do to the role assigned in the first sentence?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b73891ba-d34a-4bf1-b0ab-ab984b103a77', 'Which choice best describes the overall structure of the text?', 'The committee''s report on the river''s flooding reads, at first, like a straightforward chronicle: rainfall totals, levee heights, the hours each gauge crested. Page after page accumulates measurement without interpretation. Only in its final section does the report''s true work emerge. There, almost casually, it notes that every levee that failed had been certified under a standard the committee itself had approved a decade earlier. The dry recitation, it turns out, was never neutral. The numbers were arranged to lead, inexorably, to an admission the committee could not bring itself to state outright.', NULL, '[{"id":"A","text":"It characterizes a document''s apparent neutrality, then reveals that its accumulated detail was structured toward a concealed self-implication.","is_correct":true,"explanation":"Correct: the text shows the ''neutral'' recitation was arranged to reach a buried admission."},{"id":"B","text":"It praises the committee for transparently disclosing its earlier regulatory errors.","is_correct":false,"explanation":"The admission is concealed and unstated outright, so it is not praised as transparent disclosure."},{"id":"C","text":"It explains the engineering causes of the levee failures in technical sequence.","is_correct":false,"explanation":"Engineering causes are not explained; the focus is the report''s rhetorical design."},{"id":"D","text":"It contrasts two competing reports to determine which more accurately describes the flood.","is_correct":false,"explanation":"Only one report is discussed; no competing report is contrasted."}]'::jsonb, 'A', 'Step 1 — Spot the turn
The report seems to {{yellow:accumulate measurement without interpretation}}, but its final section reveals failed levees {{yellow:certified under a standard the committee itself had approved}}.
Step 2 — Map the structure
The apparent neutrality is exposed as a structure leading to a concealed self-implication, matching choice A.
Distractor analysis:
- B: The admission is one the committee {{yellow:could not bring itself to state outright}}, so it is not transparent praise.
- C: No engineering causes are explained; the focus is rhetorical design.
- D: Only one report appears; nothing is contrasted.', 'Decide whether the ''dry recitation'' stays neutral or is shown to have a hidden aim.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ab5f0cee-2892-4d9c-be6c-0ea9af7a8f56', 'Which choice best states the main purpose of the text?', 'When physicists first detected anomalies in galactic rotation, the obvious move was to posit unseen matter holding galaxies together. Dark matter became the default explanation, elegant in requiring no change to gravity itself. Yet a minority of theorists asked an inverted question: what if the anomaly indicts the law, not the inventory? Perhaps gravity behaves differently at the faint accelerations found in galactic outskirts. Their proposal has never matched dark matter''s broad success, and most physicists set it aside. Still, its value lies less in winning than in exposing an assumption the majority rarely examines—that when observation defies prediction, the universe, not the equation, must be hiding something.', NULL, '[{"id":"A","text":"To present a minority alternative chiefly for how it surfaces an unexamined assumption within the dominant explanation.","is_correct":true,"explanation":"Correct: the text values the alternative for exposing the majority''s hidden assumption."},{"id":"B","text":"To demonstrate that modified-gravity theories have decisively outperformed dark matter.","is_correct":false,"explanation":"The text says the alternative has never matched dark matter''s success, contradicting this."},{"id":"C","text":"To recount the experimental discovery of dark matter particles in galactic outskirts.","is_correct":false,"explanation":"No discovery of particles is recounted; dark matter remains a posited explanation."},{"id":"D","text":"To urge physicists to abandon the law of gravity in light of rotation anomalies.","is_correct":false,"explanation":"The text does not urge abandonment; it notes most physicists set the alternative aside."}]'::jsonb, 'A', 'Step 1 — Locate the stated value
The text concedes the alternative {{yellow:has never matched dark matter''s broad success}}, yet says {{yellow:its value lies less in winning than in exposing an assumption}}.
Step 2 — State the purpose
Its purpose is to present the minority view chiefly for surfacing the majority''s unexamined assumption, matching choice A.
Distractor analysis:
- B: Contradicts the text, which says the alternative never matched dark matter''s success.
- C: No particle discovery is recounted; dark matter stays a posited explanation.
- D: The text does not urge abandoning gravity; most physicists set the alternative aside.', 'The passage concedes the theory loses; ask what it says the theory is nonetheless good for.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cf2d6833-32ae-4af1-9427-899e810266a7', 'Which choice best describes the overall structure of the text?', 'Maps of the medieval world strike modern eyes as failures of accuracy. Coastlines bulge implausibly; Jerusalem squats at the center; sea monsters crowd the margins. Judged as navigational tools, they are nearly useless. But that judgment imports a purpose the maps never claimed. A mappa mundi was not built to guide a traveler from port to port; it was built to display a moral order, to show where humanity stood between paradise and peril. Its distortions are not errors at all but arguments. To fault it for poor geography is to grade a sermon by the rules of a timetable.', NULL, '[{"id":"A","text":"It recites a standard charge against an artifact, then redefines the artifact''s aim so the charge no longer applies.","is_correct":true,"explanation":"Correct: the text reframes the map''s purpose so ''inaccuracy'' becomes irrelevant."},{"id":"B","text":"It concedes that medieval maps were useless and recommends discarding them as historical sources.","is_correct":false,"explanation":"The text values the maps as moral arguments, not as discardable; no discarding is recommended."},{"id":"C","text":"It compares medieval and modern cartography to chart improvements in accuracy.","is_correct":false,"explanation":"No modern cartography is compared; accuracy improvement is not charted."},{"id":"D","text":"It explains the navigational techniques medieval sailors used despite imperfect maps.","is_correct":false,"explanation":"No navigational techniques are explained; the maps are said not to serve navigation."}]'::jsonb, 'A', 'Step 1 — Find the charge and the pivot
The maps seem {{yellow:nearly useless}} as navigation, but the text insists a mappa mundi {{yellow:was built to display a moral order}}.
Step 2 — Map the structure
By redefining the map''s aim, the inaccuracy charge ceases to apply, matching choice A.
Distractor analysis:
- B: The text treats the maps as meaningful arguments, not discardable sources.
- C: Modern cartography is not compared; no accuracy timeline is charted.
- D: No sailing techniques are explained; the maps are said not to serve travelers.', 'The ''But'' sentence changes the standard by which the maps should be judged.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4fbb5d52-4ed9-4a40-8d0e-c14e41e40939', 'Which choice best states the main purpose of the text?', 'The teenage protagonist of the new novel narrates her summer in flat, affectless sentences: she eats, she walks, she watches her parents argue. Reviewers have called the prose lifeless, evidence of an author with nothing to say. This reading mistakes the surface for the depth. The flatness is the girl''s, not the author''s—a deliberate rendering of a mind numbing itself against what it cannot afford to feel. When, in the final pages, a single sentence finally breaks into feeling, the effect is devastating precisely because of all the deadened prose before it. The style is not absence; it is suppression made audible.', NULL, '[{"id":"A","text":"To reinterpret a stylistic feature dismissed as a flaw as instead a calculated rendering of the narrator''s emotional state.","is_correct":true,"explanation":"Correct: the text recasts the flat prose as deliberate suppression, not authorial failure."},{"id":"B","text":"To establish that the novel''s author lacks the skill to write vivid prose.","is_correct":false,"explanation":"Reverse: the text attributes the flatness to craft, not lack of skill."},{"id":"C","text":"To summarize the events of the protagonist''s summer for prospective readers.","is_correct":false,"explanation":"The plot details serve the argument; summarizing events is not the purpose."},{"id":"D","text":"To compare this novel''s style with that of other contemporary coming-of-age fiction.","is_correct":false,"explanation":"No other novels are compared; only this one is discussed."}]'::jsonb, 'A', 'Step 1 — Spot the reinterpretation
Reviewers called the prose {{yellow:lifeless, evidence of an author with nothing to say}}, but the text says {{yellow:the flatness is the girl''s, not the author''s}}.
Step 2 — State the purpose
Its purpose is to reinterpret the dismissed flatness as a calculated rendering of the narrator''s numbed mind, matching choice A.
Distractor analysis:
- B: Reverse, since the text credits craft rather than lack of skill.
- C: Plot details serve the argument; summary is not the goal.
- D: No other novels are compared; only this one is discussed.', 'Whose flatness is it, according to the passage—the author''s or the character''s?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('685f1392-3bd2-4e6b-b61e-eb62160217d1', 'Which choice best describes the overall structure of the text?', 'It is often said that the printing press democratized knowledge, breaking the clergy''s monopoly on the written word. The slogan flatters our faith in technology. Early print runs, however, were small, costly, and aimed at the same Latin-reading elite who already controlled manuscripts. For its first decades, the press largely reproduced existing hierarchies rather than dissolving them. Only later, as vernacular printing and rising literacy converged, did anything resembling democratization occur—and even then unevenly. The press was less a cause than a tool whose effects depended on conditions it did not itself supply. We credit the machine for what societies, slowly, did with it.', NULL, '[{"id":"A","text":"It cites a popular claim, qualifies it with countervailing evidence, and recasts the subject as dependent on external conditions.","is_correct":true,"explanation":"Correct: the text qualifies the press''s role and makes its effects conditional on society."},{"id":"B","text":"It denies that the printing press had any influence on the spread of literacy.","is_correct":false,"explanation":"The text concedes later democratization occurred, so it does not deny all influence."},{"id":"C","text":"It chronicles the technical evolution of printing equipment across several centuries.","is_correct":false,"explanation":"No technical evolution of equipment is chronicled; the focus is social effect."},{"id":"D","text":"It endorses the popular claim by supplying additional supporting examples.","is_correct":false,"explanation":"Reverse: the text qualifies rather than endorses the popular claim."}]'::jsonb, 'A', 'Step 1 — Find the qualification
The popular claim that print {{yellow:democratized knowledge}} is checked by noting the press {{yellow:largely reproduced existing hierarchies rather than dissolving them}}.
Step 2 — Map the structure
The text qualifies the claim and recasts the press as {{yellow:a tool whose effects depended on conditions it did not itself supply}}, matching choice A.
Distractor analysis:
- B: It concedes later democratization, so it denies not all influence but the simple causal story.
- C: No equipment evolution is chronicled; the focus is social effect.
- D: Reverse, since the claim is qualified, not endorsed.', 'Does the passage flatly reject the slogan, or hedge it and shift the credit elsewhere?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b373ea7e-f7c8-4ac6-a457-a0b081301214', 'Which choice best describes the overall structure of the text?', 'The diplomat''s memoir devotes its opening chapters to her triumphs: treaties brokered, crises defused, adversaries charmed. The tone is assured, even self-congratulatory. Then, midway, the book changes register. Recounting a negotiation she had counted as a victory, she pauses to record what she learned only years afterward—that the agreement she prized had quietly doomed a population she never met. From that point the memoir''s confidence curdles into something graver. The early chapters, reread, take on an ironic cast: each triumph now shadowed by the possibility of an unseen cost. The book becomes less a record of achievement than an interrogation of how achievement is measured.', NULL, '[{"id":"A","text":"It describes a work''s confident initial stance, then traces a tonal shift that retroactively reframes that stance as questionable.","is_correct":true,"explanation":"Correct: the text shows the memoir''s confidence giving way and recoloring the early triumphs."},{"id":"B","text":"It praises the diplomat for the consistency of her self-assessment throughout the memoir.","is_correct":false,"explanation":"The text describes a change in register, not consistency."},{"id":"C","text":"It evaluates the long-term consequences of a specific treaty on a foreign population.","is_correct":false,"explanation":"The treaty''s consequence is a detail within the structural account, not the focus."},{"id":"D","text":"It contrasts the diplomat''s memoir with the official records of her negotiations.","is_correct":false,"explanation":"No official records are contrasted; only the memoir is discussed."}]'::jsonb, 'A', 'Step 1 — Locate the shift
The memoir begins {{yellow:assured, even self-congratulatory}}, then its {{yellow:confidence curdles into something graver}} after a belated revelation.
Step 2 — Map the structure
The shift retroactively reframes the early triumphs as questionable, so the structure matches choice A.
Distractor analysis:
- B: The text stresses a change of register, not consistency.
- C: The treaty''s effect is a detail serving the structural account, not its focus.
- D: No official records are contrasted; only the memoir appears.', 'What happens to the early chapters once the midpoint revelation arrives?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cef9cdd4-2209-4f3c-9476-2bf830212575', 'Which choice best states the main purpose of the text?', 'Neuroscientists studying memory once assumed that recalling an event simply retrieves a stored record, like opening a saved file. The metaphor was convenient and, for a time, productive. Experiments now suggest something stranger: each act of recollection rewrites the memory, subtly altering it before storing it anew. A memory recalled often is therefore not preserved but repeatedly revised, drifting from the event it purports to record. This finding does not merely refine the file metaphor; it dissolves it. If remembering is a form of editing, then the very faithfulness we attribute to vivid memories may be evidence of how thoroughly they have been remade.', NULL, '[{"id":"A","text":"To show that new findings overturn, rather than adjust, a long-held model of how memory works.","is_correct":true,"explanation":"Correct: the text says the findings dissolve the file metaphor, not merely refine it."},{"id":"B","text":"To recommend techniques for improving the accuracy of long-term recall.","is_correct":false,"explanation":"No recall-improvement techniques are recommended; the text describes how memory changes."},{"id":"C","text":"To trace the historical origins of the file metaphor in early neuroscience.","is_correct":false,"explanation":"The metaphor''s origins are not traced; its overturning is the focus."},{"id":"D","text":"To reconcile the file metaphor with experimental evidence of memory revision.","is_correct":false,"explanation":"Reverse: the text dissolves the metaphor rather than reconciling it with evidence."}]'::jsonb, 'A', 'Step 1 — Identify the claim''s force
The old model treated recall as retrieving {{yellow:a stored record, like opening a saved file}}, but the text says the new finding {{yellow:does not merely refine the file metaphor; it dissolves it}}.
Step 2 — State the purpose
Its purpose is to show the findings overturn rather than adjust the model, matching choice A.
Distractor analysis:
- B: No recall-improvement techniques are offered; the text explains how memory changes.
- C: The metaphor''s origins are not traced; its collapse is the focus.
- D: Reverse, since the metaphor is dissolved, not reconciled.', 'Weigh ''refine'' against the passage''s own verb for what the finding does to the metaphor.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8c56e52b-0be5-4b28-b860-ecfba3f0586d', 'Which choice best states the main purpose of the text?', 'A familiar account holds that the Roman roads were built to bind an empire commercially, knitting distant markets into one economy. There is truth in this, but it obscures the roads'' first allegiance. The earliest highways ran not toward the richest provinces but toward the most rebellious, laid down to move legions faster than news of revolt could travel. Trade followed, certainly, but as a beneficiary rather than a designer. To understand the network, one must read it as a circulatory system for force, onto which commerce was later grafted. The road that carried grain had first been built to carry soldiers.', NULL, '[{"id":"A","text":"To correct the emphasis of a common explanation by relocating the roads'' primary purpose from commerce to military control.","is_correct":true,"explanation":"Correct: the text shifts the roads'' first allegiance from trade to moving legions."},{"id":"B","text":"To deny that Roman roads ever served any commercial function.","is_correct":false,"explanation":"The text grants that trade followed, so it does not deny commercial function."},{"id":"C","text":"To detail the engineering methods used to construct Roman highways.","is_correct":false,"explanation":"No engineering methods are detailed; the focus is purpose, not construction."},{"id":"D","text":"To rank the provinces of the empire by their economic importance.","is_correct":false,"explanation":"No ranking of provinces by economy is offered; rebelliousness, not wealth, guided road placement."}]'::jsonb, 'A', 'Step 1 — Find the relocation
The familiar account says roads were built {{yellow:to bind an empire commercially}}, but the text says the earliest ran toward {{yellow:the most rebellious}} provinces to move legions.
Step 2 — State the purpose
Its purpose is to correct the emphasis and relocate the primary aim from commerce to military control, matching choice A.
Distractor analysis:
- B: The text grants trade followed, so it does not deny commerce entirely.
- C: No engineering methods are detailed; purpose is the focus.
- D: Roads went toward rebellious, not richest, provinces, so no economic ranking is made.', 'The passage concedes ''there is truth'' before pivoting—what does it move to the foreground instead?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('837234c7-c35f-4f34-ba85-0fa4ac4d25e6', 'Which choice best describes the overall structure of the text?', 'Champions of citizen science often present it as a pure democratization of research: anyone with a smartphone can now log a bird sighting or measure a stream''s clarity, and the data flow upward to professionals. The portrait is appealing, but it flattens an asymmetry. Volunteers supply observations; they rarely set the questions those observations answer, and almost never control how their labor is credited or used. What looks like a partnership of equals is, on inspection, a familiar division: many hands gather, a few minds direct. To celebrate the movement without naming this gap is to mistake wider participation for shared authority.', NULL, '[{"id":"A","text":"It summarizes an optimistic characterization, then complicates it by distinguishing participation from the authority the characterization implies.","is_correct":true,"explanation":"Correct: the text grants wide participation but separates it from genuine shared authority."},{"id":"B","text":"It argues that citizen science produces data too unreliable for professional use.","is_correct":false,"explanation":"Data reliability is never questioned; the issue is authority, not quality."},{"id":"C","text":"It proposes a new method for crediting volunteer contributions in research.","is_correct":false,"explanation":"No crediting method is proposed; the text only names a gap."},{"id":"D","text":"It celebrates citizen science as a genuine partnership of equals among researchers.","is_correct":false,"explanation":"Reverse: the text disputes the partnership-of-equals portrait rather than celebrating it."}]'::jsonb, 'A', 'Step 1 — Find the complication
The optimistic view calls citizen science {{yellow:a pure democratization of research}}, but the text notes volunteers {{yellow:rarely set the questions those observations answer}}.
Step 2 — Map the structure
The text complicates the portrait by separating participation from authority, warning against mistaking {{yellow:wider participation for shared authority}}, matching choice A.
Distractor analysis:
- B: Data reliability is never raised; the concern is authority, not quality.
- C: No crediting method is proposed; the text only identifies a gap.
- D: Reverse, since the text disputes the partnership-of-equals portrait.', 'The ''but'' sentence concedes one thing while withholding another—identify each.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('35648710-6cad-4820-a343-883130b0eafb', 'Which choice best describes the overall structure of the text?', 'Critics of the novelist Hannah Vell often praise her late works for a restraint absent from her early fiction, citing the spare, unadorned prose of her final trilogy. Yet this account mistakes a difference in subject for a difference in skill. Vell''s early novels, set amid the clamor of port cities, demanded dense, sensory language; her later books, confined to a single quiet farmhouse, simply had less to describe. To call the trilogy more disciplined is to credit the author for a thrift her chosen settings imposed on her. The maturity critics detect is, in truth, a property of the rooms she elected to write about.', NULL, '[{"id":"A","text":"It presents a widely held interpretation and then reattributes the quality that interpretation praises to a cause other than the one assumed.","is_correct":true,"explanation":"Correct: the text states the critics'' view and then relocates the source of the ''restraint'' from skill to setting."},{"id":"B","text":"It summarizes a debate among critics and concludes that both sides have overlooked the author''s intentions.","is_correct":false,"explanation":"Wrong: only one critical view is described, not two opposing camps, and intention is not the issue."},{"id":"C","text":"It traces the development of an author''s style and praises the increasing discipline of her later work.","is_correct":false,"explanation":"Wrong: the text disputes that the later work is more disciplined rather than praising it."},{"id":"D","text":"It defends a novelist against detractors who undervalue her early fiction.","is_correct":false,"explanation":"Wrong: the critics admire, not undervalue, and the early fiction is not what is being defended."}]'::jsonb, 'A', 'Step 1 — Identify the move
The critics praise a ''restraint'' they call skill, but the text says {{yellow:this account mistakes a difference in subject for a difference in skill}}.
Step 2 — Match the structure
The passage presents the common reading and then reassigns its praised quality to the settings, not the author''s discipline, which matches choice A.
Distractor analysis:
- B: There is one critical interpretation, not a two-sided debate, and intentions are never mentioned.
- C: The text rejects the claim that the later work is more disciplined rather than praising it.
- D: The critics praise, not undervalue, and the early novels are not being defended.', 'Look at what the second half does to the quality the critics named.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c0db23c0-322b-4280-92d9-2c48bed05bcf', 'Which choice best states the main purpose of the text?', 'When biologists first described the so-called ''cleaner'' shrimp that pick parasites from fish, they cast the arrangement as a tidy case of mutual aid: the shrimp eats, the fish is groomed. Recent observations complicate this portrait. In aquaria where parasites are scarce, the same shrimp will nip at healthy fish tissue, and fish in turn learn to avoid stations where such cheating occurs. The relationship, it seems, is not a fixed partnership but a negotiation policed by each party''s capacity to leave. What looked like cooperation is better understood as a truce sustained only so long as defection remains the costlier option.', NULL, '[{"id":"A","text":"To recommend that aquarium keepers monitor shrimp for signs of parasitic infection.","is_correct":false,"explanation":"Wrong: no recommendation to keepers is offered; the aquaria are evidence, not an audience."},{"id":"B","text":"To revise an established characterization of a relationship by showing it depends on shifting incentives rather than fixed cooperation.","is_correct":true,"explanation":"Correct: the text replaces the ''mutual aid'' portrait with a conditional truce governed by incentives."},{"id":"C","text":"To prove that the shrimp-fish relationship is fundamentally parasitic rather than mutual.","is_correct":false,"explanation":"Wrong: the text describes a conditional truce, not an outright parasitic relationship."},{"id":"D","text":"To compare the behavior of shrimp in the wild with their behavior in captivity.","is_correct":false,"explanation":"Wrong: captivity supplies evidence, but the contrast is not the central purpose."}]'::jsonb, 'B', 'Step 1 — Find the shift
The text opens with ''mutual aid'' but then says the bond is {{yellow:not a fixed partnership but a negotiation policed by each party''s capacity to leave}}.
Step 2 — State the purpose
The passage exists to qualify the earlier characterization by grounding the relationship in shifting incentives, which is choice B.
Distractor analysis:
- A: No advice is directed at aquarium keepers; the aquaria are merely where the evidence appears.
- C: The text calls it a conditional truce, not a flatly parasitic relationship.
- D: Wild-versus-captive comparison is incidental, not the main purpose.', 'Ask what the new observations do to the ''tidy case of mutual aid.''', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('99bf985a-4fdc-4eb7-b567-3a8855095656', 'Which choice best describes the overall structure of the text?', 'Historians of the early postal road tend to celebrate it as the spine of a unifying commerce, the channel along which a scattered settlement knit itself into a market. The ledgers of the road''s own toll houses suggest a narrower reality. For its first two decades, the road carried mostly empty wagons returning from the capital and official couriers paid from the treasury; private freight remained scarce until tributary lanes were cut. The artery, in other words, preceded the body it is said to have served. It was less the cause of integration than a wager on integration that only later paid out.', NULL, '[{"id":"A","text":"It introduces a celebrated claim and then uses documentary evidence to recast the road as anticipating, rather than producing, the integration credited to it.","is_correct":true,"explanation":"Correct: the ledgers reframe the road as a ''wager'' that preceded the commerce it supposedly caused."},{"id":"B","text":"It chronicles the construction of a postal road and the tributary lanes that extended it.","is_correct":false,"explanation":"Wrong: construction is not chronicled; the focus is on reinterpreting the road''s causal role."},{"id":"C","text":"It contrasts the views of historians with those of treasury officials about the road''s cost.","is_correct":false,"explanation":"Wrong: treasury officials'' views and the road''s cost are not the contrast at issue."},{"id":"D","text":"It argues that the postal road ultimately failed to integrate the scattered settlements.","is_correct":false,"explanation":"Wrong: the text says the wager ''later paid out,'' so integration is not denied."}]'::jsonb, 'A', 'Step 1 — Locate the reversal
The celebratory view is met by ledger evidence, and the text concludes {{yellow:The artery, in other words, preceded the body it is said to have served}}.
Step 2 — Match the structure
The passage presents a famous claim and then uses records to recast the road as anticipating integration rather than causing it, matching A.
Distractor analysis:
- B: No account of construction is given; the point is interpretive.
- C: Treasury officials and cost are not the framing contrast.
- D: The text affirms integration eventually arrived (''later paid out''), so failure is wrong.', 'Notice the claim about which came first, the road or the commerce.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('dc2ecb85-2f13-4591-b4c2-267481d04519', 'Which choice best states the main purpose of the text?', 'The poet Idris Mar is routinely filed among the nature lyricists, and the abundance of rivers, moors, and finches in his verse makes the label seem self-evident. A closer reading unsettles it. Mar''s landscapes are never observed for their own sake; each heron is a stand-in for a vanished friend, each flooded field a figure for grief he will not name directly. The natural world in his poems functions less as subject than as a discreet vocabulary for loss. To read him as a celebrant of the countryside is to mistake his instrument for his theme—to hear the lute and miss the elegy it is playing.', NULL, '[{"id":"A","text":"To rank Idris Mar above other nature lyricists of his generation.","is_correct":false,"explanation":"Wrong: no ranking against other poets is made."},{"id":"B","text":"To trace how Mar''s use of natural imagery changed over his career.","is_correct":false,"explanation":"Wrong: no chronological development of his imagery is discussed."},{"id":"C","text":"To challenge a common classification of a poet by arguing his natural imagery serves a different, unstated subject.","is_correct":true,"explanation":"Correct: the text resists the ''nature lyricist'' label, recasting the imagery as a vocabulary for loss."},{"id":"D","text":"To catalog the recurring natural images that appear throughout Mar''s poetry.","is_correct":false,"explanation":"Wrong: images are cited as evidence, not catalogued for their own sake."}]'::jsonb, 'C', 'Step 1 — Spot the reinterpretation
The text says the nature label seems obvious but then claims the imagery {{yellow:functions less as subject than as a discreet vocabulary for loss}}.
Step 2 — State the purpose
The passage''s aim is to contest the standard classification by showing the natural imagery points to an unnamed theme of grief, which is choice C.
Distractor analysis:
- A: No comparison or ranking against other poets occurs.
- B: There is no account of change over his career.
- D: The images are evidence for an argument, not an end in themselves.', 'What does the closing ''lute'' and ''elegy'' contrast tell you about the label?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0d9aef57-372c-4efb-960e-ee4053f4e135', 'Which choice best describes the overall structure of the text?', 'A familiar story about early thermometers holds that they made temperature objective, replacing vague talk of ''mild'' or ''sweltering'' air with hard numbers. The instruments'' early history tells against this. For decades, makers used incompatible scales fixed to local reference points—the cellar of one observatory, the blood heat of one physician—so that a reading meant little beyond the room that produced it. Objectivity arrived not with the device but with the slow, contentious agreement on shared fixed points. The number, far from settling the matter, merely relocated the argument from sensation to standardization, where it continued for a century.', NULL, '[{"id":"A","text":"It explains how thermometers were calibrated and why early scales differed from one another.","is_correct":false,"explanation":"Wrong: calibration detail is evidence, not the organizing structure."},{"id":"B","text":"It presents a common claim and then qualifies it by arguing the objectivity credited to the device actually came from later agreement on standards.","is_correct":true,"explanation":"Correct: the text moves the source of objectivity from the instrument to standardization."},{"id":"C","text":"It celebrates the invention of the thermometer as a decisive break with subjective impressions.","is_correct":false,"explanation":"Wrong: the text disputes that the instrument itself produced objectivity."},{"id":"D","text":"It argues that temperature can never be measured objectively at all.","is_correct":false,"explanation":"Wrong: the text says objectivity did arrive, just later and from agreement."}]'::jsonb, 'B', 'Step 1 — Find the qualification
The instrument-makes-it-objective story is countered: {{yellow:Objectivity arrived not with the device but with the slow, contentious agreement on shared fixed points}}.
Step 2 — Match the structure
The passage states the common claim and qualifies it by shifting the origin of objectivity to standardization, matching B.
Distractor analysis:
- A: How scales differed is supporting detail, not the overall structure.
- C: The text undercuts, rather than celebrates, the instrument''s role.
- D: Objectivity is affirmed as eventually achieved, not denied.', 'Where does the text say objectivity actually came from?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('faaacff2-bfc5-41ff-975a-2e97a3127a3b', 'Which choice best states the main purpose of the text?', 'Accounts of the guild''s decline usually blame the rise of the factory, picturing skilled members swept aside by cheaper machine labor. The guild''s surviving minute-books point elsewhere. Long before any factory opened nearby, the guild had quietly stopped admitting new masters, restricting membership to the sons of existing ones to keep wages high. By the time mechanized competition appeared, the guild was already an aging body too small to train replacements or defend its trade. The factory did not break a thriving institution; it inherited a chair its occupant had spent two generations declining to fill.', NULL, '[{"id":"A","text":"To argue that the guild''s decline owed more to its own membership policies than to factory competition.","is_correct":true,"explanation":"Correct: the minute-books relocate the cause of decline from factories to self-imposed exclusion."},{"id":"B","text":"To describe the working conditions of skilled laborers before mechanization.","is_correct":false,"explanation":"Wrong: working conditions are not the subject; causes of decline are."},{"id":"C","text":"To explain how factories recruited workers away from traditional guilds.","is_correct":false,"explanation":"Wrong: factory recruitment is not described; the guild''s internal policy is."},{"id":"D","text":"To show that the guild successfully resisted mechanization for two generations.","is_correct":false,"explanation":"Wrong: the guild weakened itself; it did not successfully resist."}]'::jsonb, 'A', 'Step 1 — Locate the reattribution
The factory explanation is set aside because the guild {{yellow:had quietly stopped admitting new masters}} long before mechanization.
Step 2 — State the purpose
The text''s aim is to assign the decline chiefly to the guild''s own exclusionary policy rather than to factories, which is choice A.
Distractor analysis:
- B: Working conditions are not discussed.
- C: Factory recruitment is never described; internal membership policy is.
- D: The guild undermined itself; it did not resist mechanization successfully.', 'What does the closing ''chair'' metaphor say about who emptied it?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('56b25ba9-a03a-44b7-9dd5-f03b8ca9bafb', 'Which choice best describes the overall structure of the text?', 'The phrase ''natural harbor'' suggests a gift of geography, a basin simply waiting for ships. The case of Port Anseln warns against the phrase. Its sheltered bay was for centuries useless: silt from an inland river kept the channel shallow, and only after engineers diverted that river and dredged a permanent cut could deep hulls enter at all. What guidebooks now call a natural harbor is the residue of a vast, deliberate intervention, its origins so thoroughly absorbed into the landscape that the work has come to look like luck. The harbor is natural only in the sense that we have forgotten making it.', NULL, '[{"id":"A","text":"It questions a familiar phrase by showing, through one case, that the feature it names was produced by human effort rather than given by nature.","is_correct":true,"explanation":"Correct: Port Anseln demonstrates that the ''natural harbor'' resulted from engineering, not geography."},{"id":"B","text":"It recounts the engineering history of Port Anseln for its own sake.","is_correct":false,"explanation":"Wrong: the history serves a larger point about a misleading phrase."},{"id":"C","text":"It contrasts two competing methods of building artificial harbors.","is_correct":false,"explanation":"Wrong: no two methods are compared."},{"id":"D","text":"It warns that dredged harbors are less reliable than naturally formed ones.","is_correct":false,"explanation":"Wrong: reliability is not the concern; the origin of the harbor is."}]'::jsonb, 'A', 'Step 1 — Identify the challenge
The phrase ''natural harbor'' is undercut: the bay became usable only after engineers acted, and {{yellow:What guidebooks now call a natural harbor is the residue of a vast, deliberate intervention}}.
Step 2 — Match the structure
The passage questions a familiar phrase and uses one case to show the feature was made, not given, matching A.
Distractor analysis:
- B: The history is a vehicle for the argument, not an end in itself.
- C: No two construction methods are contrasted.
- D: Reliability is never compared; the point concerns origin.', 'Read the final sentence''s definition of ''natural'' carefully.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4adeaa75-6fac-461d-9f39-07eb47d69efd', 'Which choice best states the main purpose of the text?', 'Memoirists are often advised to mistrust their earliest memories, on the assumption that the vivid scene recalled from age four must be largely invented. The novelist Tomas Erl turns this counsel on its head. He grants that his oldest memories are reconstructions, but insists the reconstruction is itself the truest record—not of what happened, but of what the event came to mean as he rebuilt it across decades. A memory faithfully preserved, he suggests, would tell us only about a vanished afternoon; a memory revised tells us about the person doing the revising. Accuracy, for Erl, is the least interesting thing a memory can offer.', NULL, '[{"id":"A","text":"To present a writer''s reversal of conventional advice, redefining the value of a memory as lying in its revision rather than its accuracy.","is_correct":true,"explanation":"Correct: Erl inverts the usual warning, locating a memory''s worth in what its reshaping reveals."},{"id":"B","text":"To warn memoirists that their earliest memories are unreliable and should be checked.","is_correct":false,"explanation":"Wrong: that is the advice Erl overturns, not the text''s purpose."},{"id":"C","text":"To explain the psychological mechanisms by which early memories are formed.","is_correct":false,"explanation":"Wrong: no mechanism of memory formation is explained."},{"id":"D","text":"To compare the memoirs of Tomas Erl with those of other novelists.","is_correct":false,"explanation":"Wrong: no other memoirs are compared."}]'::jsonb, 'A', 'Step 1 — Find the inversion
Erl accepts that memories are reconstructed but claims {{yellow:a memory revised tells us about the person doing the revising}}.
Step 2 — State the purpose
The text exists to present Erl''s reversal of standard advice, relocating a memory''s value from accuracy to revision, which is choice A.
Distractor analysis:
- B: That warning is the convention Erl rejects, not the passage''s aim.
- C: No psychological mechanism is described.
- D: No comparison with other memoirists is made.', 'What does Erl do with the advice in the first sentence?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4df142b0-67d2-4dd0-be50-62173180eac9', 'Which choice best describes the overall structure of the text?', 'Conservationists once treated the reintroduction of the marsh harrier as a simple success: bring back the predator, and the wetland heals. The recovery proved less obedient. As harriers returned, they thinned the population of a small gull whose abandoned nests had sheltered a rare beetle; the beetle declined even as the bird thrived. Restoring one link, it turned out, could sever another that no one had thought to count. The episode did not discredit reintroduction so much as expose the conceit beneath it—the belief that an ecosystem is a machine missing a part, rather than a web whose every thread is tied to the rest.', NULL, '[{"id":"A","text":"It recounts a case in which a conservation effort succeeded and recommends repeating it elsewhere.","is_correct":false,"explanation":"Wrong: the case revealed an unforeseen loss and recommends nothing."},{"id":"B","text":"It uses an unexpected outcome to expose a flawed assumption underlying a conservation practice.","is_correct":true,"explanation":"Correct: the beetle''s decline reveals the ''machine missing a part'' conceit behind reintroduction."},{"id":"C","text":"It argues that predator reintroduction should be abandoned as too dangerous.","is_correct":false,"explanation":"Wrong: the text says the episode did not discredit reintroduction."},{"id":"D","text":"It describes the life cycle of a rare beetle dependent on gull nests.","is_correct":false,"explanation":"Wrong: the beetle is an example, not the subject."}]'::jsonb, 'B', 'Step 1 — Find the assumption exposed
The surprising decline of the beetle reveals the {{yellow:belief that an ecosystem is a machine missing a part, rather than a web}}.
Step 2 — Match the structure
The text uses an unexpected outcome to expose the flawed assumption beneath reintroduction, matching B.
Distractor analysis:
- A: The outcome was a hidden loss, and nothing is recommended.
- C: The text explicitly says reintroduction was not discredited.
- D: The beetle is illustrative, not the topic.', 'What belief does the final sentence say the episode exposed?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ed65f740-4a34-4ae0-93f9-b416699db2f9', 'Which choice best states the main purpose of the text?', 'The reformer Cecil Donn is remembered as a champion of the secret ballot, and pamphlets of the period do show him demanding it from every platform. To leave the matter there, however, is to flatten a more awkward figure. Donn''s private letters reveal that he valued secrecy chiefly as a means of breaking the patronage networks that excluded men of his own party from office; universal privacy was, for him, a tactic against a particular rival, not a principle. The reform outlasted the feud that produced it, and we now honor as conviction what began as maneuver. History, it seems, often keeps the deed and discards the motive.', NULL, '[{"id":"A","text":"To complicate a reformer''s heroic reputation by distinguishing the principle he is credited with from the tactical motive behind it.","is_correct":true,"explanation":"Correct: the letters separate the celebrated principle from Donn''s actual strategic aim."},{"id":"B","text":"To argue that the secret ballot was a harmful reform that should be reconsidered.","is_correct":false,"explanation":"Wrong: the reform''s value is not questioned; only Donn''s motive is."},{"id":"C","text":"To trace the spread of the secret ballot across different countries.","is_correct":false,"explanation":"Wrong: no geographic spread is discussed."},{"id":"D","text":"To praise Donn for consistently acting on principle throughout his career.","is_correct":false,"explanation":"Wrong: the text says his stance began as maneuver, not principle."}]'::jsonb, 'A', 'Step 1 — Find the distinction
The public champion image is complicated by letters showing the ballot was {{yellow:a tactic against a particular rival, not a principle}}.
Step 2 — State the purpose
The text''s aim is to complicate Donn''s reputation by separating the credited principle from his tactical motive, which is choice A.
Distractor analysis:
- B: The reform itself is not criticized; only its motive is examined.
- C: No cross-national spread is discussed.
- D: The text says the stance was maneuver, contradicting consistent principle.', 'Notice the gap between what Donn demanded publicly and what his letters reveal.', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e62da738-4629-4686-a2e2-525ba1de801f', 'Which choice best describes the overall structure of the text?', 'Textbooks present the discovery of the planet Neptune as the triumph of pure calculation: an astronomer predicted where an unseen world must lie, and a telescope found it there. The fuller record is less clean. Two rival mathematicians produced overlapping predictions, observatories sat on the figures for months, and the telescope that succeeded was pointed at the right patch partly by luck, the predicted position being off by a degree that happened not to matter that night. None of this makes the prediction worthless; it makes the legend misleading. The planet was not so much deduced as it was deduced, delayed, disputed, and then, fortunately, stumbled upon.', NULL, '[{"id":"A","text":"It corrects an idealized account by detailing the contingencies that the familiar version of the discovery omits.","is_correct":true,"explanation":"Correct: the text replaces the ''pure calculation'' legend with rivalry, delay, and luck."},{"id":"B","text":"It argues that the prediction of Neptune''s location was ultimately worthless.","is_correct":false,"explanation":"Wrong: the text explicitly says the prediction was not worthless."},{"id":"C","text":"It explains the mathematical method used to predict Neptune''s position.","is_correct":false,"explanation":"Wrong: the method itself is not explained, only its messy reception."},{"id":"D","text":"It compares the telescopes used by competing observatories.","is_correct":false,"explanation":"Wrong: telescopes are mentioned but not compared as the structure."}]'::jsonb, 'A', 'Step 1 — Find the correction
The clean legend is set against a record of rivalry and luck: the planet {{yellow:was not so much deduced as it was deduced, delayed, disputed, and then, fortunately, stumbled upon}}.
Step 2 — Match the structure
The text corrects an idealized story by supplying the omitted contingencies, matching A.
Distractor analysis:
- B: The text says the prediction was not worthless.
- C: The mathematical method is not explained.
- D: Telescopes are not compared as the organizing move.', 'What does the text add that the textbook version leaves out?', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a77ec389-7957-400b-8ec3-3f5b4893dbac', 'Which choice best states the main purpose of the text?', 'It is tempting to read the abandonment of the hill town of Caere as a cautionary tale about drought, since the wells did run dry in its final years. But scarcity alone explains little; many neighboring towns survived worse and rebuilt. What distinguished Caere, the excavated granaries suggest, was a rule that grain reserves belonged to whichever family held the gate, a custom that turned shortage into hoarding and hoarding into flight. The drought was the occasion of the collapse, not its cause. Caere did not die of thirst; it died of an arrangement that ensured thirst would fall on some long before it fell on all.', NULL, '[{"id":"A","text":"To describe the agricultural techniques used to store grain in hill towns like Caere.","is_correct":false,"explanation":"Wrong: storage technique is not the subject; the ownership rule and its effect are."},{"id":"B","text":"To distinguish the immediate trigger of a town''s collapse from its underlying social cause.","is_correct":true,"explanation":"Correct: the text separates drought as ''occasion'' from the grain-control custom as true cause."},{"id":"C","text":"To argue that drought is the primary threat facing hill settlements.","is_correct":false,"explanation":"Wrong: the text downplays drought as the mere occasion, not the cause."},{"id":"D","text":"To compare Caere''s fate with that of towns that successfully rebuilt.","is_correct":false,"explanation":"Wrong: neighboring towns are mentioned only to isolate Caere''s distinctive flaw."}]'::jsonb, 'B', 'Step 1 — Find the separation
The text isolates a social cause from the weather, stating {{yellow:The drought was the occasion of the collapse, not its cause}}.
Step 2 — State the purpose
The passage exists to distinguish the immediate trigger from the deeper social custom that doomed the town, which is choice B.
Distractor analysis:
- A: Storage technique is not discussed; the ownership rule is.
- C: Drought is demoted to mere occasion, so this reverses the point.
- D: The comparison to other towns only serves to highlight Caere''s unique arrangement.', 'Distinguish what the text calls the ''occasion'' from what it calls the ''cause.''', 'Craft and Structure', 'Text Structure and Purpose', 'reading_writing', 'craft', 'TSP', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d85cf6ca-1161-4a76-9d81-54f6240980f7', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that plot is what keeps a book alive in the imagination?', 'Text 1
The novel''s true power lies in its plot. Readers turn pages because they want to know what happens next; a gripping sequence of events is what keeps a book alive in the imagination long after it is closed. Character and theme matter, but they are merely the scenery through which the engine of story drives.

Text 2
I find that the books I reread are not those with the cleverest plots but those with the most vivid people. Once I know how a story ends, suspense vanishes—yet I return again and again to characters who feel like old friends. It is they, not the events, who endure.', NULL, '[{"id":"A","text":"Plot is irrelevant to whether readers enjoy a novel at all.","is_correct":false,"explanation":"Too extreme; Text 2 says character endures more than plot, not that plot is irrelevant to enjoyment."},{"id":"B","text":"It is actually memorable characters, not events, that make a book last.","is_correct":true,"explanation":"Correct: Text 2 says the author returns to vivid characters who endure, directly countering Text 1''s emphasis on plot."},{"id":"C","text":"Gripping plots are the main reason readers reread books.","is_correct":false,"explanation":"Reverses Text 2''s view, which says suspense vanishes on rereading."},{"id":"D","text":"Theme is more important than either plot or character.","is_correct":false,"explanation":"No evidence; Text 2 discusses character versus events, not theme."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s claim
Text 2 states that the books worth rereading have {{yellow:the most vivid people}} rather than the cleverest plots.
Step 2 — Apply to Text 1
Since the author values enduring characters over events, they would counter Text 1''s plot-centered claim by saying characters are what truly last.
Distractor analysis:
- A: Too extreme—Text 2 never says plot is irrelevant to enjoyment.
- C: Reverses Text 2, which says suspense vanishes once the ending is known.
- D: No evidence—theme is never mentioned in Text 2.', 'What does Text 2 say it returns to again and again?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1ca2397e-d4ad-4440-b367-134a6cde89c7', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that productivity belongs to those who greet the dawn?', 'Text 1
Early risers have the advantage. By beginning the workday before others wake, they enjoy quiet hours of uninterrupted focus, finishing their hardest tasks while the office is still empty. Productivity, it seems, belongs to those who greet the dawn.

Text 2
Not everyone''s body keeps the same clock. Some people, often called night owls, simply think more sharply in the evening; forcing them to start at dawn only dulls their best hours. The key to focused work is not the hour on the clock but matching tasks to one''s natural rhythm.', NULL, '[{"id":"A","text":"Mornings are always the worst time for everyone to work.","is_correct":false,"explanation":"Too broad and reverses the point; Text 2 says some people do well in mornings, others at night."},{"id":"B","text":"Night owls should force themselves to wake earlier to be productive.","is_correct":false,"explanation":"Contradicts Text 2, which says forcing dawn starts dulls a night owl''s best hours."},{"id":"C","text":"Productivity depends on matching work to one''s natural rhythm, not the early hour.","is_correct":true,"explanation":"Correct: Text 2 says the key is matching tasks to one''s natural rhythm, not the time of day."},{"id":"D","text":"Quiet office hours are the only thing that matters for focus.","is_correct":false,"explanation":"True-but-irrelevant detail from Text 1; not Text 2''s response."}]'::jsonb, 'C', 'Step 1 — Find Text 2''s claim
Text 2 argues the key to focus is {{yellow:matching tasks to one''s natural rhythm}} rather than the hour on the clock.
Step 2 — Apply to Text 1
Because Text 2 ties productivity to personal rhythm, it would reject Text 1''s idea that the dawn itself confers the advantage.
Distractor analysis:
- A: Too broad and reverses Text 2, which allows some thrive in the morning.
- B: Contradicts Text 2''s warning that forcing dawn starts dulls night owls.
- D: Borrows Text 1''s quiet-hours point, which Text 2 does not endorse.', 'What does Text 2 say focus actually depends on?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ac940559-8844-43c8-a202-a7423a2281e5', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the extinction resulted from one swift, decisive blow?', 'Text 1
The extinction of the dinosaurs is best explained by a single catastrophic event: a massive asteroid struck the Earth, throwing up debris that blocked sunlight and collapsed food chains within years. The suddenness of the fossil record supports one swift, decisive blow.

Text 2
Giant volcanic eruptions in India were already poisoning the air for hundreds of thousands of years before any impact. The asteroid may have delivered a final shock, but the dinosaurs were a population long weakened by a slow environmental decline.', NULL, '[{"id":"A","text":"The asteroid impact never actually occurred.","is_correct":false,"explanation":"Contradicts Text 2, which grants the asteroid delivered a ''final shock.''"},{"id":"B","text":"A long environmental decline had already weakened the dinosaurs before the impact.","is_correct":true,"explanation":"Correct: Text 2 says the dinosaurs were weakened by a slow decline, qualifying the single-blow claim."},{"id":"C","text":"Volcanic eruptions had no effect on dinosaur populations.","is_correct":false,"explanation":"Reverses Text 2, which blames eruptions for poisoning the air."},{"id":"D","text":"The fossil record proves the extinction was instantaneous.","is_correct":false,"explanation":"This restates Text 1''s view, not Text 2''s response."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s claim
Text 2 states the dinosaurs were {{yellow:a population long weakened by a slow environmental decline}} before the impact.
Step 2 — Apply to Text 1
Because Text 2 emphasizes a gradual weakening from volcanism, it qualifies Text 1''s single-swift-blow explanation.
Distractor analysis:
- A: Contradicts Text 2, which accepts the impact as a ''final shock.''
- C: Reverses Text 2''s central point about eruptions poisoning the air.
- D: Restates Text 1 rather than responding from Text 2.', 'What does Text 2 say was happening before the asteroid struck?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e183a680-4b8d-40dd-8a1d-e5d737d8b376', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that a city''s greatness is measured by its monuments?', 'Text 1
A city''s greatness is measured by its monuments. The grand cathedrals, towering statues, and sweeping plazas are what visitors remember and what history records. A place without bold architecture leaves no lasting mark on the world.

Text 2
When I think of the cities I love, I do not picture statues. I remember a baker who knew my name, a square where neighbors gathered each evening, the rhythm of ordinary lives. A city''s soul lives in its people and their habits, not in its stone.', NULL, '[{"id":"A","text":"Monuments should be torn down to make room for markets.","is_correct":false,"explanation":"No evidence; Text 2 never calls for destroying monuments."},{"id":"B","text":"A city is best defined by its people and their daily lives, not its stone.","is_correct":true,"explanation":"Correct: Text 2 says a city''s soul lives in its people and habits, not in its stone."},{"id":"C","text":"Grand architecture is what visitors remember most.","is_correct":false,"explanation":"Restates Text 1, contradicting Text 2."},{"id":"D","text":"History only records cities with bold plazas.","is_correct":false,"explanation":"Echoes Text 1''s reasoning, not Text 2''s response."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s claim
Text 2 declares that {{yellow:A city''s soul lives in its people and their habits, not in its stone}}.
Step 2 — Apply to Text 1
Since Text 2 locates a city''s value in everyday human life, it would reject Text 1''s monument-based measure of greatness.
Distractor analysis:
- A: No evidence—Text 2 never advocates removing monuments.
- C: Restates Text 1''s claim, which Text 2 opposes.
- D: Echoes Text 1''s logic rather than Text 2''s.', 'Where does Text 2 say a city''s soul lives?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
