INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f3abb6c6-4098-43ef-9d99-0bddc4274d4f', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the city "was abandoned because invaders sacked it"?', 'Text 1
The ancient city was abandoned because invaders sacked it. Archaeologists have found scorched walls and shattered pottery, the unmistakable marks of a violent attack. A conquering army stormed the gates, drove out the inhabitants, and left the once-great settlement in ruins forever.

Text 2
Burn marks tell only part of the story. The same layers reveal that the city''s wells had run dry and its fields lay cracked from years of drought. People may well have fled the failing water supply before any army arrived; the fire could mark an empty city, not a conquered one.', NULL, '[{"id":"A","text":"By suggesting that drought may have emptied the city before any attack occurred.","is_correct":true,"explanation":"This matches Text 2''s point that people may have fled the failing water supply before an army arrived."},{"id":"B","text":"By agreeing that an invading army was certainly the sole cause of the abandonment.","is_correct":false,"explanation":"Text 2 offers drought as an alternative, contradicting this."},{"id":"C","text":"By denying that the city was ever abandoned.","is_correct":false,"explanation":"Text 2 accepts the city was abandoned; it disputes only the cause."},{"id":"D","text":"By claiming the burn marks were invented by archaeologists.","is_correct":false,"explanation":"Text 2 accepts the burn marks but reinterprets them; it does not call them fake."}]'::jsonb, 'A', 'Step 1 — Find Text 2''s alternative
Text 2 suggests {{yellow:People may well have fled the failing water supply before any army arrived}}.
Step 2 — Apply to Text 1''s claim
Text 1 blames invaders for the abandonment, but Text 2 proposes drought as the likelier cause, so it would challenge the invasion explanation.
Distractor analysis:
- B: Reverses Text 2, which offers a non-military cause.
- C: Text 2 accepts the abandonment, disputing only why.
- D: Text 2 reinterprets the burn marks rather than denying them.', 'Text 2 says the wells and fields reveal what other problem?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7663b80e-39ab-4913-8b2e-06ef3f242c3d', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that social media is an "isolating substitute"?', 'Text 1
Social media has made young people lonelier than ever. Instead of meeting face to face, teenagers now scroll through feeds alone in their rooms, comparing their lives to polished online images. This constant screen time has replaced genuine friendship with a hollow, isolating substitute.

Text 2
For some teenagers, social media is the opposite of isolating. A student who feels out of place at school may find, online, a community of others who share an unusual interest or background. For these young people, the screen is not a wall between friends but a bridge to people they could never have met nearby.', NULL, '[{"id":"A","text":"By agreeing that social media isolates every teenager who uses it.","is_correct":false,"explanation":"Text 2 argues it connects some teenagers, contradicting an absolute claim."},{"id":"B","text":"By arguing that for some teenagers social media connects them to communities they could not otherwise reach.","is_correct":true,"explanation":"This matches Text 2''s image of the screen as a bridge to distant people."},{"id":"C","text":"By insisting that face-to-face friendship has no value at all.","is_correct":false,"explanation":"Text 2 never dismisses in-person friendship; this is unsupported."},{"id":"D","text":"By claiming that no teenagers actually use social media.","is_correct":false,"explanation":"Both texts assume teenagers use social media; this contradicts them."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s counterexample
Text 2 describes the screen as {{yellow:a bridge to people they could never have met nearby}}.
Step 2 — Apply to Text 1''s claim
Text 1 calls social media isolating, but Text 2 shows it can connect lonely teens to communities, so it would dispute "isolating substitute."
Distractor analysis:
- A: Text 2 says some teens are connected, not all isolated.
- C: Unsupported; Text 2 never devalues face-to-face friendship.
- D: Contradicts both texts, which assume teens use social media.', 'Text 2 calls the screen a bridge rather than what?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('37400b6c-2bce-4329-bc91-be23c67b1824', 'Based on the texts, how would the author of Text 2 most likely respond to Banks''s claim in Text 1 that scenery is "decoration that can be swapped out"?', 'Text 1
The novelist Hira Banks insists that a story''s setting is mere backdrop. What truly moves readers, she argues, is character: a vivid person placed in any town, any century, will carry the reader along. Scenery, by contrast, is decoration that can be swapped out without altering the emotional core of a tale.

Text 2
Readers remember Wuthering Heights'' moors as keenly as they remember Heathcliff. A landscape can shape a character''s temper, limit her choices, and mirror her inner weather. Strip away the setting and you do not merely lose decoration; you lose the very forces that made the character who she is.', NULL, '[{"id":"A","text":"By agreeing that character matters most but adding that dialogue is also important.","is_correct":false,"explanation":"This concedes Banks''s main point and raises dialogue, which Text 2 never discusses."},{"id":"B","text":"By arguing that setting actively shapes character and so cannot be freely swapped out.","is_correct":true,"explanation":"Text 2 states setting shapes temper and choices, directly opposing the swappable-decoration claim."},{"id":"C","text":"By insisting that setting is more important than character in every novel.","is_correct":false,"explanation":"Text 2 says setting shapes character, not that it outranks character in all cases."},{"id":"D","text":"By conceding that scenery is decoration but praising its beauty.","is_correct":false,"explanation":"Text 2 explicitly rejects calling setting mere decoration."}]'::jsonb, 'B', 'Step 1 — Find Banks''s claim
Text 1 calls scenery {{yellow:decoration that can be swapped out without altering the emotional core of a tale}}.
Step 2 — Apply Text 2
Text 2 says a landscape can {{yellow:shape a character''s temper, limit her choices}}, so setting is not interchangeable and answer B follows.
Distractor analysis:
- A: Concedes Banks''s point and adds dialogue, which Text 2 never mentions.
- C: Overstates; Text 2 ties setting to character rather than ranking it above character everywhere.
- D: Reverses Text 2, which denies setting is mere decoration.', 'Find where Text 2 describes what a landscape does to a character, then compare that to Banks calling scenery swappable.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8869be39-864d-4e0f-ae2b-f133f8679ac8', 'Based on the texts, how would the author of Text 2 most likely respond to the conclusion in Text 1 that a higher minimum wage "must reduce the number of available jobs"?', 'Text 1
Some economists claim that raising a city''s minimum wage must reduce the number of available jobs. If employers are forced to pay more per worker, the reasoning goes, they will simply hire fewer workers to keep their total costs steady. The conclusion follows from basic cost accounting.

Text 2
In several cities that raised minimum wages, employment in affected industries held steady or even rose. Higher pay can lower costly worker turnover and put more spending money in customers'' pockets, both of which help businesses. The simple cost story leaves out these offsetting effects.', NULL, '[{"id":"A","text":"By agreeing fully and citing additional accounting principles.","is_correct":false,"explanation":"Text 2 disputes the conclusion rather than endorsing it."},{"id":"B","text":"By noting that the conclusion ignores offsetting effects that can keep jobs steady.","is_correct":true,"explanation":"Text 2 cites turnover and spending as effects the cost story omits."},{"id":"C","text":"By arguing that minimum wages always increase employment.","is_correct":false,"explanation":"Text 2 says employment held steady or rose, not that wages always raise jobs."},{"id":"D","text":"By conceding the point but saying fairness matters more than jobs.","is_correct":false,"explanation":"Text 2 disputes the jobs claim on evidence, not on fairness grounds."}]'::jsonb, 'B', 'Step 1 — Find Text 1''s conclusion
Text 1 claims a higher wage {{yellow:must reduce the number of available jobs}}.
Step 2 — Apply Text 2
Text 2 reports employment {{yellow:held steady or even rose}} and names offsetting effects, so it would say the conclusion overlooks them.
Distractor analysis:
- A: Text 2 opposes, not endorses, the conclusion.
- C: Overstates; Text 2 says steady or rose, not always increases.
- D: Introduces fairness, which Text 2 never raises.', 'Locate the evidence Text 2 gives about what actually happened to employment.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('64eb3776-8764-4354-9f6e-3ff76e70d8c2', 'Based on the texts, how would the author of Text 2 most likely respond to Pratt''s claim in Text 1 that the printing press "alone caused" the spread of ideas?', 'Text 1
The historian Owen Pratt argues that the printing press alone caused the rapid spread of new ideas across Renaissance Europe. Before the press, copying texts by hand was slow; once books could be printed, ideas traveled freely. The technology, in his view, was the decisive engine of change.

Text 2
Presses sat idle in regions with few literate readers and weak trade routes. Where roads, schools, and merchant networks were strong, printed ideas spread quickly; where they were absent, the same machines changed little. The press mattered, but only alongside the social conditions that carried its products.', NULL, '[{"id":"A","text":"By agreeing that the press was the single decisive cause.","is_correct":false,"explanation":"Text 2 denies that the press worked alone."},{"id":"B","text":"By arguing that the press spread ideas only where supporting social conditions existed.","is_correct":true,"explanation":"Text 2 says the press changed little without literacy and trade networks."},{"id":"C","text":"By claiming the press actually slowed the spread of ideas.","is_correct":false,"explanation":"Text 2 credits the press where conditions were right; it does not say it slowed ideas."},{"id":"D","text":"By insisting that ideas spread just as fast before printing existed.","is_correct":false,"explanation":"Text 2 makes no claim that pre-press spread was equally fast."}]'::jsonb, 'B', 'Step 1 — Find Pratt''s claim
Text 1 says the printing press {{yellow:alone caused the rapid spread of new ideas}}.
Step 2 — Apply Text 2
Text 2 states the press {{yellow:changed little}} without literate readers and trade, so it would qualify the "alone" claim with social conditions, giving B.
Distractor analysis:
- A: Contradicts Text 2''s whole point.
- C: Text 2 never says the press slowed ideas.
- D: No evidence about pre-press speed in Text 2.', 'See what Text 2 says happened where presses existed but trade and literacy did not.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cf95ba4c-7918-417a-964e-faee0092804d', 'Based on the texts, how would the author of Text 2 most likely respond to the wellness writer''s claim in Text 1 that everyone needs "exactly eight glasses of water each day"?', 'Text 1
A popular wellness writer claims that humans should drink exactly eight glasses of water each day, no matter their size or activity. This fixed number, she says, is the key to staying properly hydrated and should apply to everyone equally.

Text 2
Water needs vary widely. A large, active person in a hot climate loses far more fluid than a small, sedentary person in a cool one. Much of our water also comes from food. A single rule for all bodies ignores these real differences and can mislead more than it helps.', NULL, '[{"id":"A","text":"By agreeing but recommending nine glasses instead.","is_correct":false,"explanation":"Text 2 rejects a fixed number, not just the specific figure of eight."},{"id":"B","text":"By arguing that water needs vary, so a single fixed rule misleads.","is_correct":true,"explanation":"Text 2 says needs vary by body, climate, and activity, undercutting one rule for all."},{"id":"C","text":"By claiming that drinking water is unnecessary for most people.","is_correct":false,"explanation":"Text 2 acknowledges water needs; it disputes a uniform amount."},{"id":"D","text":"By agreeing that one rule fits all bodies if activity is moderate.","is_correct":false,"explanation":"Text 2 denies any single rule fits all bodies."}]'::jsonb, 'B', 'Step 1 — Find the claim
Text 1 says everyone needs {{yellow:exactly eight glasses of water each day, no matter their size or activity}}.
Step 2 — Apply Text 2
Text 2 states {{yellow:A single rule for all bodies ignores these real differences}}, so it would reject the fixed-eight claim, giving B.
Distractor analysis:
- A: Substitutes a different fixed number, but Text 2 opposes fixed numbers.
- C: Text 2 does not say water is unnecessary.
- D: Text 2 allows no single rule for any condition.', 'Find Text 2''s sentence about whether one rule can fit all bodies.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('494acaca-75ec-484d-bdf4-18d9c9653e70', 'Based on the texts, how would the author of Text 2 most likely respond to the critic''s claim in Text 1 that craft is "the only measure that counts"?', 'Text 1
An art critic argues that a painting''s worth lies entirely in the skill of its brushwork. If the technique is masterful, the work is great; if the technique is clumsy, no idea behind it can rescue the piece. Craft, he concludes, is the only measure that counts.

Text 2
Some of the most celebrated modern works are deliberately rough or even crude in execution, yet they move millions because of the ideas they express. A flawless surface with nothing to say leaves viewers cold. Meaning, not just craft, can make a painting matter.', NULL, '[{"id":"A","text":"By agreeing that technique alone determines a painting''s worth.","is_correct":false,"explanation":"Text 2 argues meaning also matters, contradicting craft-only."},{"id":"B","text":"By arguing that a work''s ideas can make it matter even when craft is rough.","is_correct":true,"explanation":"Text 2 cites crude works that move viewers through their ideas."},{"id":"C","text":"By claiming that brushwork is irrelevant to every painting.","is_correct":false,"explanation":"Text 2 says meaning matters too, not that craft is irrelevant."},{"id":"D","text":"By insisting that only abstract paintings have value.","is_correct":false,"explanation":"Text 2 makes no claim restricting value to abstract works."}]'::jsonb, 'B', 'Step 1 — Find the claim
Text 1 calls craft {{yellow:the only measure that counts}}.
Step 2 — Apply Text 2
Text 2 says works {{yellow:rough or even crude in execution}} still move millions through their ideas, so meaning also counts, giving B.
Distractor analysis:
- A: Endorses the view Text 2 rejects.
- C: Text 2 adds meaning rather than dismissing craft entirely.
- D: No mention of abstract works being uniquely valuable.', 'Look at the kind of works Text 2 says still move people despite their execution.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6b4d8466-2d4f-41f5-8d65-ccec6c3c6ae0', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the sun is a bee''s "single guiding compass"?', 'Text 1
A science writer claims that bees navigate purely by the position of the sun. On a clear day, she notes, a bee can fly straight to a flower and return to the hive, proving that the sun serves as its single guiding compass.

Text 2
Bees forage on overcast days when the sun is hidden, yet they still find their way home. Experiments show they read patterns of polarized light, recall landmarks, and even sense Earth''s magnetic field. The sun is one cue among several, not the whole story.', NULL, '[{"id":"A","text":"By agreeing that the sun is the only cue bees use.","is_correct":false,"explanation":"Text 2 lists several cues, contradicting a single compass."},{"id":"B","text":"By arguing that bees rely on several cues besides the sun.","is_correct":true,"explanation":"Text 2 names polarized light, landmarks, and magnetism as additional cues."},{"id":"C","text":"By claiming bees cannot navigate at all without the sun.","is_correct":false,"explanation":"Text 2 says bees navigate on overcast days, the opposite of this."},{"id":"D","text":"By insisting that bees navigate only by Earth''s magnetic field.","is_correct":false,"explanation":"Text 2 lists magnetism as one of several cues, not the sole one."}]'::jsonb, 'B', 'Step 1 — Find the claim
Text 1 calls the sun a bee''s {{yellow:single guiding compass}}.
Step 2 — Apply Text 2
Text 2 says bees {{yellow:read patterns of polarized light, recall landmarks, and even sense Earth''s magnetic field}}, so the sun is one cue among several, giving B.
Distractor analysis:
- A: Contradicts Text 2''s list of cues.
- C: Text 2 shows bees navigate without visible sun.
- D: Magnetism is only one of several cues in Text 2.', 'Count how many navigation cues Text 2 lists for bees.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('55901bc9-5bcc-4480-a811-ff15957b2a2c', 'Based on the texts, how would the author of Text 2 most likely respond to Cross''s claim in Text 1 that explaining a poem makes "that feeling dies"?', 'Text 1
The poet Delia Cross argues that a poem should never be explained. Its power, she says, lives in the reader''s private feeling; the moment a critic spells out a poem''s meaning, that feeling dies and the poem is reduced to a flat statement.

Text 2
A careful explanation can deepen rather than destroy a reader''s response. Pointing out a hidden pattern of sound or a buried allusion often opens a poem up, letting readers feel more, not less. Understanding and emotion need not be enemies.', NULL, '[{"id":"A","text":"By agreeing that explanation always destroys feeling.","is_correct":false,"explanation":"Text 2 argues explanation can deepen feeling, contradicting this."},{"id":"B","text":"By arguing that explanation can deepen a reader''s feeling rather than kill it.","is_correct":true,"explanation":"Text 2 says explanation can let readers feel more, not less."},{"id":"C","text":"By claiming that poems have no emotional power to begin with.","is_correct":false,"explanation":"Text 2 assumes poems move readers; it does not deny their power."},{"id":"D","text":"By insisting that only critics can truly appreciate poetry.","is_correct":false,"explanation":"Text 2 makes no claim that appreciation is limited to critics."}]'::jsonb, 'B', 'Step 1 — Find Cross''s claim
Text 1 says when a critic explains a poem {{yellow:that feeling dies and the poem is reduced to a flat statement}}.
Step 2 — Apply Text 2
Text 2 says explanation often {{yellow:letting readers feel more, not less}}, so it would deny that feeling dies, giving B.
Distractor analysis:
- A: Contradicts Text 2''s central claim.
- C: Text 2 assumes poems have emotional power.
- D: No mention of limiting appreciation to critics.', 'Find Text 2''s phrase about whether readers feel more or less after explanation.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('79b7d9ef-115e-42f4-b66a-62e123ff881b', 'Based on the texts, how would the author of Text 2 most likely respond to the planner''s claim in Text 1 that wider roads "cut traffic"?', 'Text 1
An urban planner argues that wider roads are the surest way to cut traffic. More lanes mean more space for cars, she reasons, so congestion must fall as the new capacity absorbs the existing flow of vehicles.

Text 2
When cities widen roads, the extra capacity often fills almost at once. Easier driving tempts more people to drive and to live farther away, generating new trips that erase the gains. Within a few years, the widened road can be as jammed as before.', NULL, '[{"id":"A","text":"By agreeing that added lanes reliably reduce congestion.","is_correct":false,"explanation":"Text 2 says new capacity often fills up, contradicting this."},{"id":"B","text":"By arguing that wider roads draw new trips that erase the expected gains.","is_correct":true,"explanation":"Text 2 says easier driving tempts more trips that fill the new lanes."},{"id":"C","text":"By claiming that narrowing roads is the only way to move cars.","is_correct":false,"explanation":"Text 2 critiques widening but never proposes narrowing as the only fix."},{"id":"D","text":"By insisting that traffic is caused entirely by poor signal timing.","is_correct":false,"explanation":"Text 2 attributes the problem to induced demand, not signal timing."}]'::jsonb, 'B', 'Step 1 — Find the claim
Text 1 says wider roads are the surest way to {{yellow:cut traffic}}.
Step 2 — Apply Text 2
Text 2 says new trips {{yellow:erase the gains}} so the widened road stays jammed, giving B.
Distractor analysis:
- A: Contradicts Text 2''s finding that capacity fills.
- C: Text 2 never proposes narrowing as the sole solution.
- D: Signal timing is not mentioned in Text 2.', 'See what Text 2 says happens to the new lanes after a few years.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('df4cf2ff-d235-413f-91f6-26572da14f6f', 'Based on the texts, how would the author of Text 2 most likely respond to the biographer''s claim in Text 1 that letters give "the most reliable picture" of an artist?', 'Text 1
A biographer claims that an artist''s letters reveal the true person behind the public work. Private correspondence, he argues, is honest and unguarded, so it gives us the most reliable picture of who the artist really was.

Text 2
Letters are written to specific readers and often shaped to please or persuade them. An artist may flatter a patron, hide a debt, or perform a mood for a friend. Far from a clear window, correspondence can be as carefully staged as any public work.', NULL, '[{"id":"A","text":"By agreeing that private letters are always honest and unguarded.","is_correct":false,"explanation":"Text 2 says letters can be staged, contradicting unguarded honesty."},{"id":"B","text":"By arguing that letters are shaped for their readers and can be as staged as public work.","is_correct":true,"explanation":"Text 2 says correspondence may flatter or perform and be carefully staged."},{"id":"C","text":"By claiming that biographies should rely only on public works.","is_correct":false,"explanation":"Text 2 questions letters'' reliability but does not say to use only public works."},{"id":"D","text":"By insisting that artists never write letters honestly.","is_correct":false,"explanation":"Text 2 says letters can be staged, not that they are always dishonest."}]'::jsonb, 'B', 'Step 1 — Find the claim
Text 1 says letters give {{yellow:the most reliable picture of who the artist really was}}.
Step 2 — Apply Text 2
Text 2 says correspondence can be {{yellow:as carefully staged as any public work}}, so it would doubt the reliability claim, giving B.
Distractor analysis:
- A: Contradicts Text 2''s staging point.
- C: Text 2 doubts letters but never restricts sources to public works.
- D: "Never honestly" overstates; Text 2 says letters can be staged.', 'Find Text 2''s comparison between letters and public work.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
