INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fc616e1a-78c1-443b-a163-1167f5590fba', 'Based on the texts, how would the author of Text 2 most likely respond to the commentator''s claim in Text 1 that classrooms will become "obsolete"?', 'Text 1
A technology commentator claims that online learning will soon make physical classrooms obsolete. Since lectures can be streamed to anyone anywhere, he argues, there is no longer any reason to gather students in a single room.

Text 2
Lectures are only part of education. Classrooms let students debate face to face, get instant help, and form the friendships that keep them motivated. Streaming a lecture cannot replace these, which is why many online programs still struggle to keep students enrolled.', NULL, '[{"id":"A","text":"By agreeing that streaming lectures replaces all classroom functions.","is_correct":false,"explanation":"Text 2 lists functions streaming cannot replace, contradicting this."},{"id":"B","text":"By arguing that classrooms provide interaction and motivation that streaming cannot replace.","is_correct":true,"explanation":"Text 2 cites debate, instant help, and friendships as irreplaceable benefits."},{"id":"C","text":"By claiming that lectures have no educational value at all.","is_correct":false,"explanation":"Text 2 calls lectures part of education, not valueless."},{"id":"D","text":"By insisting that online learning should be banned.","is_correct":false,"explanation":"Text 2 critiques the obsolescence claim but never calls for a ban."}]'::jsonb, 'B', 'Step 1 — Find the claim
Text 1 says online learning will make physical classrooms {{yellow:obsolete}}.
Step 2 — Apply Text 2
Text 2 says {{yellow:Streaming a lecture cannot replace these}}, naming debate, help, and friendships, so classrooms are not obsolete, giving B.
Distractor analysis:
- A: Contradicts Text 2''s list of irreplaceable functions.
- B: correct.
- C: Text 2 calls lectures part of education.
- D: No call for a ban appears in Text 2.', 'List the classroom benefits Text 2 says streaming cannot replace.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2b775838-99de-4584-8b04-4abdd0efeb04', 'Based on the texts, how would the author of Text 2 most likely respond to the ecologist''s claim in Text 1 that protecting one iconic species is "the best way to save an ecosystem"?', 'Text 1
An ecologist argues that protecting a single iconic species, such as the tiger, is the best way to save an ecosystem. Focus resources on the famous animal, she says, and the whole habitat around it will be protected as a side effect.

Text 2
Guarding one celebrated species can leave many others unprotected. Insects, plants, and fungi that hold an ecosystem together rarely attract funding, yet without them the habitat collapses even if the tiger survives. A whole-system approach protects more than a single-species focus.', NULL, '[{"id":"A","text":"By agreeing that saving the tiger automatically saves everything else.","is_correct":false,"explanation":"Text 2 says other species can stay unprotected, contradicting this."},{"id":"B","text":"By arguing that a whole-system focus protects more species than a single-species focus.","is_correct":true,"explanation":"Text 2 says less famous species are vital yet neglected, favoring a whole-system approach."},{"id":"C","text":"By claiming that iconic species deserve no protection.","is_correct":false,"explanation":"Text 2 does not say the tiger should go unprotected; it adds the rest of the system."},{"id":"D","text":"By insisting that only insects matter to an ecosystem.","is_correct":false,"explanation":"Text 2 names insects, plants, and fungi, not insects alone."}]'::jsonb, 'B', 'Step 1 — Find the claim
Text 1 says protecting one iconic species is {{yellow:the best way to save an ecosystem}}.
Step 2 — Apply Text 2
Text 2 says {{yellow:A whole-system approach protects more than a single-species focus}}, so it would reject the single-species claim, giving B.
Distractor analysis:
- A: Contradicts Text 2''s point about neglected species.
- C: Text 2 adds the rest of the system rather than dropping the tiger.
- D: Text 2 names several groups, not insects alone.', 'Find Text 2''s closing sentence comparing the two approaches.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e34a045c-5cf0-4a2e-b287-415f17787e42', 'Based on the texts, how would the author of Text 2 most likely respond to the author''s claim in Text 1 that workers who "never take breaks" are most productive?', 'Text 1
A management author claims that the most productive workers are those who never take breaks. Time spent away from a task, he argues, is time wasted, so the longer someone works without pausing, the more they will accomplish.

Text 2
Studies of focus show that attention fades after long stretches without rest. Short breaks let the mind recover, so workers who pause briefly often finish more, and with fewer errors, than those who push straight through. Rest is part of productivity, not its enemy.', NULL, '[{"id":"A","text":"By agreeing that pausing always reduces total output.","is_correct":false,"explanation":"Text 2 says brief pauses can increase output, contradicting this."},{"id":"B","text":"By arguing that brief breaks restore focus and can raise output and accuracy.","is_correct":true,"explanation":"Text 2 says workers who pause often finish more with fewer errors."},{"id":"C","text":"By claiming that working is never necessary for productivity.","is_correct":false,"explanation":"Text 2 treats rest as part of productivity, not a replacement for work."},{"id":"D","text":"By insisting that the longest breaks always produce the best work.","is_correct":false,"explanation":"Text 2 praises short breaks, not the longest possible ones."}]'::jsonb, 'B', 'Step 1 — Find the claim
Text 1 says workers who {{yellow:never take breaks}} accomplish the most.
Step 2 — Apply Text 2
Text 2 says workers who pause briefly {{yellow:often finish more, and with fewer errors}}, so breaks help productivity, giving B.
Distractor analysis:
- A: Contradicts Text 2''s finding that pauses raise output.
- C: Text 2 calls rest part of productivity, not a substitute for work.
- D: Text 2 endorses short, not longest, breaks.', 'Find Text 2''s claim about how workers who pause briefly perform.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b566468e-9bb3-4285-93c9-743092463716', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the library was "an engine of character"?', 'Text 1
The expansion of public libraries in the nineteenth century was driven chiefly by industrialists who funded them. These benefactors believed that giving workers access to books would cultivate self-discipline and moral improvement, transforming idle hours into productive study. The library, in their view, was an engine of character.

Text 2
Wealthy donors did endow many libraries, but their stated motives should not be mistaken for the institutions'' actual effect. Once opened, libraries were shaped by the readers who flooded them, who borrowed novels and newspapers far more than improving tracts. The public, not the patron, defined what the library became.', NULL, '[{"id":"A","text":"It accurately captures both the donors'' intentions and the way readers ultimately used libraries.","is_correct":false,"explanation":"Text 2 explicitly separates donors'' motives from libraries'' actual use, so it would not say the claim captures both."},{"id":"B","text":"It reflects the donors'' aims but not what libraries became in the hands of readers.","is_correct":true,"explanation":"Text 2 grants the donors'' character-building motive while arguing readers'' actual borrowing defined the institution."},{"id":"C","text":"It overstates the role of industrialists, who in fact funded very few libraries.","is_correct":false,"explanation":"Text 2 concedes donors endowed many libraries, so it does not dispute their funding role."},{"id":"D","text":"It is correct because readers borrowed improving tracts more than any other material.","is_correct":false,"explanation":"Text 2 says the opposite, that readers borrowed novels and newspapers far more than improving tracts."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s concession and turn
Text 2 admits donors funded libraries but insists {{yellow:their stated motives should not be mistaken for the institutions'' actual effect}}.
Step 2 — Apply to the claim
So Text 2 would say the "engine of character" idea describes the donors'' aims but not what readers actually made libraries into.
Distractor analysis:
- A: Text 2 separates intention from effect rather than endorsing both.
- C: Text 2 concedes donors endowed many libraries, not few.
- D: Reverses Text 2, which says novels and newspapers were borrowed far more than improving tracts.', 'Text 2 distinguishes what donors intended from what readers actually did with the libraries.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a48809de-46c8-4a57-a784-f459cfb8fed9', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that "the migratory route is encoded entirely in their genes"?', 'Text 1
Monarch butterflies navigate thousands of miles to a single Mexican forest they have never seen. This astonishing feat proves that the migratory route is encoded entirely in their genes; no learning is possible, since each generation that completes the journey has died before the next departs. Instinct alone carries them home.

Text 2
A purely genetic explanation underestimates the environment''s role. Experiments show monarchs calibrate their inherited compass against the sun''s position and the day''s length, adjusting course as conditions shift. The genes supply a starting program, but the insects continuously correct it using cues from the world around them.', NULL, '[{"id":"A","text":"It is essentially right, because monarchs cannot learn from earlier generations.","is_correct":false,"explanation":"Text 2 challenges the \"entirely genetic\" claim, so it would not call it essentially right."},{"id":"B","text":"It is too absolute, because monarchs also adjust their route using environmental cues.","is_correct":true,"explanation":"Text 2 argues genes provide a starting program that insects correct using cues like the sun and day length."},{"id":"C","text":"It is wrong because the route is learned anew by each generation.","is_correct":false,"explanation":"Text 2 never claims the route is learned; it says genes supply a starting program that is then adjusted."},{"id":"D","text":"It is correct that instinct matters but mistaken about the destination''s location.","is_correct":false,"explanation":"Text 2 does not dispute the Mexican forest destination; it disputes the all-genetic mechanism."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s correction
Text 2 states {{yellow:The genes supply a starting program, but the insects continuously correct it using cues from the world around them}}.
Step 2 — Apply to the claim
Text 2 would call Text 1''s "entirely genetic" claim too absolute, since the environment shapes the route too.
Distractor analysis:
- A: Text 2 disputes the all-genetic view rather than endorsing it.
- C: Text 2 says genes supply a starting program, not that the route is learned fresh each generation.
- D: Text 2 never challenges the destination, only the mechanism.', 'Text 2 adds a factor that Text 1''s word ''entirely'' leaves out.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('45240213-a89c-415f-af74-8028790a098a', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that "a single invading force toppled a civilization"?', 'Text 1
The sudden collapse of the Bronze Age empires around 1200 BCE was the work of the "Sea Peoples," seafaring raiders who descended on coastal cities and burned them. Egyptian inscriptions record their attacks, and the destruction layers in the ruins line up with these accounts. A single invading force toppled a civilization.

Text 2
The Sea Peoples make a vivid villain, but blaming them alone ignores what the ground reveals. Excavations show drought, famine, and earthquakes weakening these cities for decades before any raid. The newcomers may have been less a cause of collapse than a symptom of a world already coming apart.', NULL, '[{"id":"A","text":"It is persuasive because Egyptian inscriptions are the most reliable surviving evidence.","is_correct":false,"explanation":"Text 2 prioritizes excavation evidence and disputes the single-cause story, so it would not call the inscription-based claim persuasive."},{"id":"B","text":"It oversimplifies a collapse that internal stresses had already set in motion.","is_correct":true,"explanation":"Text 2 cites drought, famine, and earthquakes weakening the cities for decades before any raid."},{"id":"C","text":"It is correct that raiders caused the collapse but wrong about the date.","is_correct":false,"explanation":"Text 2 does not contest the date; it contests whether raiders alone caused the collapse."},{"id":"D","text":"It is mistaken because the Sea Peoples never actually attacked the coastal cities.","is_correct":false,"explanation":"Text 2 acknowledges the raiders and even calls them a possible symptom; it does not deny the attacks."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s alternative
Text 2 reports that {{yellow:drought, famine, and earthquakes weakening these cities for decades before any raid}}.
Step 2 — Apply to the claim
Text 2 would say a single invading force is an oversimplification, since internal stresses had already destabilized the cities.
Distractor analysis:
- A: Text 2 favors excavation evidence over the inscriptions and rejects the single-cause claim.
- C: The date is never disputed in Text 2.
- D: Text 2 grants the raiders existed and attacked; it questions their role as sole cause.', 'Text 2 points to causes that predate the raiders by decades.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('845c3529-2583-4742-8989-f16f32246f05', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that a wage increase "inevitably reduces employment"?', 'Text 1
A minimum wage increase inevitably reduces employment. When a business must pay each worker more, it can afford fewer workers, so some lose their jobs. The logic is as certain as arithmetic: raise the price of labor, and employers will buy less of it. Higher wages mean fewer paychecks overall.

Text 2
The arithmetic sounds tidy but rests on an assumption rarely tested: that employers cannot absorb higher costs in any other way. In fact, firms facing wage floors often respond by raising prices slightly, reducing turnover, or accepting thinner margins. Whether jobs vanish depends on which response a given market makes possible.', NULL, '[{"id":"A","text":"It is correct, since raising labor costs always forces firms to cut jobs.","is_correct":false,"explanation":"Text 2 disputes inevitability by listing other responses firms can make, so it would not affirm the claim."},{"id":"B","text":"It treats as certain an outcome that actually depends on how firms respond.","is_correct":true,"explanation":"Text 2 says whether jobs vanish depends on which response a given market makes possible."},{"id":"C","text":"It is right about employment but wrong to call the effect arithmetic.","is_correct":false,"explanation":"Text 2 challenges the employment conclusion itself, not merely the label \"arithmetic.\""},{"id":"D","text":"It understates the harm, because firms also raise prices and cut margins.","is_correct":false,"explanation":"Text 2 lists those responses as alternatives to job cuts, not as additional harms confirming the claim."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s qualification
Text 2 concludes that {{yellow:Whether jobs vanish depends on which response a given market makes possible}}.
Step 2 — Apply to the claim
So Text 2 would say Text 1 wrongly treats job loss as certain when the outcome actually varies by firm response.
Distractor analysis:
- A: Text 2 rejects the "always" framing.
- C: Text 2 challenges the employment conclusion, not just the word "arithmetic."
- D: Text 2 offers price increases and thinner margins as ways to avoid job cuts, not extra harms.', 'Text 2 says the result is conditional, not guaranteed.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('498cffc2-57c4-47e2-ac7d-0a5498a67526', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that Shakespeare''s characters "transcend their historical moment"?', 'Text 1
Shakespeare''s enduring greatness lies in his characters'' timeless universality. Hamlet''s doubt and Macbeth''s ambition speak to every age because they capture human nature itself, unbound by the particular world of Elizabethan England. We recognize ourselves in them precisely because they transcend their historical moment.

Text 2
These figures feel universal partly because each era remakes them. Victorians saw in Hamlet a delicate sensibility; modern directors find an anxious skeptic. The plays endure not by escaping history but by absorbing new readings, so what looks like timelessness is really a long succession of timely reinterpretations.', NULL, '[{"id":"A","text":"It is accurate, since the characters mean the same thing to every generation.","is_correct":false,"explanation":"Text 2 argues each era remakes the characters, so they do not mean the same thing across generations."},{"id":"B","text":"It mistakes for timelessness what is really a series of era-specific reinterpretations.","is_correct":true,"explanation":"Text 2 says the plays endure by absorbing new readings, making apparent timelessness a succession of timely readings."},{"id":"C","text":"It is wrong because the plays have lost relevance for modern audiences.","is_correct":false,"explanation":"Text 2 notes modern directors still reinterpret the plays, so it does not claim lost relevance."},{"id":"D","text":"It is correct about Hamlet but not about Macbeth.","is_correct":false,"explanation":"Text 2 makes a general argument about reinterpretation and singles out no character as an exception."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s reframing
Text 2 claims {{yellow:what looks like timelessness is really a long succession of timely reinterpretations}}.
Step 2 — Apply to the claim
So Text 2 would say Text 1''s "transcend their historical moment" mistakes repeated reinterpretation for true timelessness.
Distractor analysis:
- A: Text 2 says each era remakes the characters, denying a fixed meaning.
- C: Text 2 affirms continuing relevance through new readings.
- D: Text 2''s argument is general, not limited to one play.', 'Text 2 reinterprets ''timeless'' as ''repeatedly made timely.''', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('569ba306-eb61-4565-8911-12138fbff96a', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that "the printing press caused the Protestant Reformation"?', 'Text 1
The printing press caused the Protestant Reformation. By mass-producing pamphlets and Bibles, it spread Luther''s ideas faster than the Church could suppress them. Without this technology, his protest would have stayed a local quarrel. The machine, more than the man, broke Rome''s monopoly on faith.

Text 2
Presses printed indulgences and Catholic tracts just as readily as Luther''s. A technology that serves any message cannot by itself favor one. What mattered was the audience already restless under Church authority; the press amplified a demand that existed, rather than creating it.', NULL, '[{"id":"A","text":"It is correct, because the press could spread only reformist ideas.","is_correct":false,"explanation":"Text 2 notes the press printed Catholic material too, so it did not spread only reformist ideas."},{"id":"B","text":"It overstates the press''s role, which amplified an existing demand rather than creating it.","is_correct":true,"explanation":"Text 2 says the press amplified a demand that existed rather than creating it."},{"id":"C","text":"It is mistaken because Luther''s ideas were actually suppressed by the Church.","is_correct":false,"explanation":"Text 2 does not claim Luther''s ideas were suppressed; it disputes the press''s causal role."},{"id":"D","text":"It is right that technology shapes belief but wrong about which technology.","is_correct":false,"explanation":"Text 2 does not propose a different technology; it questions whether the press itself was the cause."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s counterpoint
Text 2 argues the press {{yellow:amplified a demand that existed, rather than creating it}}.
Step 2 — Apply to the claim
So Text 2 would say Text 1 overstates the press as a cause, since it served both sides and only magnified pre-existing discontent.
Distractor analysis:
- A: Text 2 stresses the press printed Catholic tracts too.
- C: Text 2 never says Luther''s ideas were suppressed.
- D: Text 2 does not point to another technology.', 'Text 2 says the press magnified something already present.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('56a020f0-7e61-4fa5-aa15-3eb53544a399', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that adding nature means "well-being will follow"?', 'Text 1
Urban green spaces directly improve residents'' mental health. Studies repeatedly find that people living near parks report lower stress and greater life satisfaction. Planting more trees and building more parks is therefore a reliable prescription: add nature to a city, and well-being will follow.

Text 2
The correlation is real, but the arrow may point the other way. Wealthier, healthier residents can afford homes near parks, so greenery might track well-being rather than produce it. Until a study assigns park access at random, we cannot say the trees are doing the work.', NULL, '[{"id":"A","text":"It is justified, since the studies clearly establish that parks cause well-being.","is_correct":false,"explanation":"Text 2 argues the studies show only correlation, not that parks cause well-being."},{"id":"B","text":"It draws a causal conclusion the correlational evidence cannot yet support.","is_correct":true,"explanation":"Text 2 says we cannot claim trees do the work until a study assigns park access at random."},{"id":"C","text":"It is wrong because residents near parks actually report more stress.","is_correct":false,"explanation":"Text 2 accepts the correlation that nearby residents report lower stress; it questions its cause."},{"id":"D","text":"It is correct in principle but applies only to wealthy neighborhoods.","is_correct":false,"explanation":"Text 2 uses wealth to question causation, not to limit where the prescription works."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s methodological objection
Text 2 warns that {{yellow:Until a study assigns park access at random, we cannot say the trees are doing the work}}.
Step 2 — Apply to the claim
So Text 2 would say Text 1 leaps to causation from evidence that is merely correlational.
Distractor analysis:
- A: Text 2 denies the studies establish causation.
- C: Text 2 accepts the lower-stress correlation rather than reversing it.
- D: Text 2 raises wealth to challenge causality, not to restrict the claim''s scope.', 'Text 2 distinguishes correlation from causation and asks for a randomized test.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e48bc226-2af9-4497-ab79-4d54bf3becdd', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that "one predator repaired a web of life"?', 'Text 1
The wolves reintroduced to the valley restored the whole ecosystem. By preying on elk, they let young willows recover along the streams, which brought back beavers and songbirds. One predator, returned to its place, repaired a web of life that had unraveled in its absence.

Text 2
The willows did rebound after the wolves returned, but those same years were unusually wet. Increased rainfall alone can revive streamside vegetation. To credit the wolves, we would need to separate their effect from the weather''s, and the existing records do not let us do so.', NULL, '[{"id":"A","text":"It is well supported, because the willows recovered immediately after reintroduction.","is_correct":false,"explanation":"Text 2 argues timing alone does not establish the wolves'' effect because rainfall is a competing cause."},{"id":"B","text":"It credits the wolves for a recovery that wetter weather could also explain.","is_correct":true,"explanation":"Text 2 notes the same years were unusually wet and that rainfall alone can revive vegetation."},{"id":"C","text":"It is mistaken because the willows did not actually recover.","is_correct":false,"explanation":"Text 2 concedes the willows did rebound; it questions the cause."},{"id":"D","text":"It is correct about willows but wrong that beavers returned.","is_correct":false,"explanation":"Text 2 says nothing about beavers being absent; it focuses on the willow recovery''s cause."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s confound
Text 2 points out the recovery years were unusually wet and that {{yellow:Increased rainfall alone can revive streamside vegetation}}.
Step 2 — Apply to the claim
So Text 2 would say Text 1 credits the wolves for a change that the weather could equally explain.
Distractor analysis:
- A: Text 2 says immediate timing is not enough given the rainfall confound.
- C: Text 2 agrees the willows rebounded.
- D: Text 2 does not dispute the beavers'' return.', 'Text 2 names a competing cause that occurred at the same time.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fd33ee94-7aef-434a-b88f-22e48f7ef535', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that "putting more police on patrol turned the tide"?', 'Text 1
Violent crime fell sharply in the 1990s because cities hired more police. More officers on the streets deterred would-be offenders and made arrests faster. The timing is clear: where departments grew, crime dropped. Putting more police on patrol is what turned the tide.

Text 2
Crime fell in that decade across nearly every wealthy nation, including those that added no officers at all. A cause confined to American hiring cannot explain a decline that crossed borders. Whatever drove the drop was broad enough to reach places that never changed their policing.', NULL, '[{"id":"A","text":"It is convincing, because crime fell only where police forces expanded.","is_correct":false,"explanation":"Text 2 notes crime fell even where no officers were added, contradicting an \"only where expanded\" pattern."},{"id":"B","text":"It cannot account for the same decline in countries that hired no extra police.","is_correct":true,"explanation":"Text 2 argues a cause confined to American hiring cannot explain a decline that crossed borders."},{"id":"C","text":"It is wrong because crime did not actually fall in the 1990s.","is_correct":false,"explanation":"Text 2 affirms crime fell across wealthy nations; it disputes the cause, not the fact."},{"id":"D","text":"It is correct for the United States but irrelevant to other countries.","is_correct":false,"explanation":"Text 2 uses other countries to undercut the U.S. explanation, not to set them aside as irrelevant."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s cross-national evidence
Text 2 states that {{yellow:A cause confined to American hiring cannot explain a decline that crossed borders}}.
Step 2 — Apply to the claim
So Text 2 would say the policing explanation fails because crime dropped even where no extra police were hired.
Distractor analysis:
- A: Text 2 shows crime also fell where forces did not expand.
- C: Text 2 accepts that crime fell.
- D: Text 2 treats other countries as decisive evidence, not as irrelevant.', 'Text 2 points to places where crime fell without the proposed cause.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7af1c7fa-7e48-4c88-ae04-888fb91ebdd1', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the unreliable narrator is "a modern invention"?', 'Text 1
The novel''s unreliable narrator is a modern invention, born of twentieth-century doubt about whether any single mind can report the truth. Earlier fiction trusted its tellers; only after the certainties of the Victorian age dissolved did writers craft narrators readers were meant to distrust.

Text 2
Readers have always been invited to doubt certain tellers. Eighteenth-century novels feature boastful, self-deceiving narrators whose accounts the author quietly undercuts. The technique was not invented by modern doubt; it was merely named by it. What changed was the label, not the practice.', NULL, '[{"id":"A","text":"It is accurate, since earlier authors always trusted their narrators completely.","is_correct":false,"explanation":"Text 2 cites eighteenth-century self-deceiving narrators, contradicting the idea that earlier authors always trusted their tellers."},{"id":"B","text":"It confuses the recent naming of a technique with its much older practice.","is_correct":true,"explanation":"Text 2 says the technique was not invented by modern doubt but merely named by it."},{"id":"C","text":"It is wrong because modern novels rarely use unreliable narrators.","is_correct":false,"explanation":"Text 2 does not claim modern novels rarely use the technique; it traces the technique to earlier works."},{"id":"D","text":"It is correct that the technique is modern but wrong about its cause.","is_correct":false,"explanation":"Text 2 denies the technique is modern at all, so it would not grant that premise."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s distinction
Text 2 argues the technique {{yellow:was not invented by modern doubt; it was merely named by it}}.
Step 2 — Apply to the claim
So Text 2 would say Text 1 mistakes the recent labeling of unreliable narration for its actual invention.
Distractor analysis:
- A: Text 2 gives earlier examples of distrusted narrators.
- C: Text 2 makes no claim that modern novels rarely use the device.
- D: Text 2 rejects the premise that the technique is modern.', 'Text 2 separates when something was named from when it began.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d5c00752-3841-4ca6-953c-fe7dc8fa1cdf', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that economic opportunity "set the migration in motion"?', 'Text 1
The Great Migration of Black Americans northward was driven above all by the lure of factory jobs. Northern industries, short of labor during the war years, sent agents south promising steady wages. Workers followed the paycheck; economic opportunity, plain and simple, set the migration in motion.

Text 2
Wages mattered, but letters and newspapers from migrants tell another story. Many wrote of fleeing lynching, disenfranchisement, and daily humiliation as much as chasing pay. To call the movement purely economic is to silence the voices that named freedom, not just income, as their goal.', NULL, '[{"id":"A","text":"It is right, since migrants'' own writings emphasize wages above all else.","is_correct":false,"explanation":"Text 2 says migrants'' writings emphasize fleeing violence and seeking freedom, not wages above all."},{"id":"B","text":"It ignores migrants'' own accounts of fleeing violence and seeking freedom.","is_correct":true,"explanation":"Text 2 cites letters describing flight from lynching and disenfranchisement, naming freedom as a goal."},{"id":"C","text":"It is mistaken because factory wages played no role in the migration.","is_correct":false,"explanation":"Text 2 concedes that wages mattered; it argues they were not the only motive."},{"id":"D","text":"It is correct about motives but wrong about the direction of migration.","is_correct":false,"explanation":"Text 2 does not dispute the northward direction; it disputes the purely economic motive."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s added evidence
Text 2 reports migrants {{yellow:wrote of fleeing lynching, disenfranchisement, and daily humiliation as much as chasing pay}}.
Step 2 — Apply to the claim
So Text 2 would say the purely economic account overlooks migrants'' own stated pursuit of freedom and safety.
Distractor analysis:
- A: Text 2 says the writings emphasize freedom and flight, not wages above all.
- C: Text 2 grants that wages mattered.
- D: Text 2 does not challenge the northward direction.', 'Text 2 brings in motives the migrants themselves recorded beyond pay.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('28311b67-44f8-4225-b052-069af9d8cbe9', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that adults'' difficulty "proves there is a fixed critical period"?', 'Text 1
Learning a second language as an adult is far harder than as a child, proving there is a fixed "critical period" after which the brain loses its capacity for fluent acquisition. Once this window closes, native-like mastery becomes essentially impossible, no matter how diligently one studies.

Text 2
Adults do struggle more, but the cause may not be a closed biological window. Adults rarely get the immersive, low-pressure exposure children receive; they study in classrooms while children play in the language all day. Equalize the conditions, and the supposed barrier might look far less fixed.', NULL, '[{"id":"A","text":"It is sound, because adults and children receive identical language exposure.","is_correct":false,"explanation":"Text 2 stresses that adults and children receive very different exposure, contradicting \"identical.\""},{"id":"B","text":"It attributes to biology a difficulty that differing learning conditions might explain.","is_correct":true,"explanation":"Text 2 says adults lack children''s immersive exposure and that equalizing conditions might shrink the barrier."},{"id":"C","text":"It is wrong because adults actually acquire languages more easily than children.","is_correct":false,"explanation":"Text 2 concedes adults do struggle more; it questions why, not whether."},{"id":"D","text":"It is correct that a window closes but wrong about when it closes.","is_correct":false,"explanation":"Text 2 doubts the existence of a fixed window, so it would not merely quibble over its timing."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s alternative explanation
Text 2 notes adults study in classrooms {{yellow:while children play in the language all day}} and suggests equalizing conditions could weaken the barrier.
Step 2 — Apply to the claim
So Text 2 would say Text 1 blames biology for a gap that differing learning conditions might fully account for.
Distractor analysis:
- A: Text 2 emphasizes that exposure differs sharply.
- C: Text 2 agrees adults struggle more.
- D: Text 2 questions whether a fixed window exists at all.', 'Text 2 offers a non-biological reason for the same difficulty.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c713d02b-e33e-4e85-be63-d893607b0f4d', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that cavalry "more than any other factor" explains the rapid expansion of horse-keeping cultures?', 'Text 1
The domestication of the horse on the Eurasian steppe was, above all, a revolution in warfare. Mounted riders gave early steppe peoples a decisive military edge, allowing them to raid settled farming communities and to dominate vast territories. The speed and reach of cavalry, more than any other factor, explain why horse-keeping cultures expanded so rapidly across the ancient world.

Text 2
War may have come later. The earliest horse-keeping peoples seem to have prized the animal first for its milk, meat, and ability to haul loads across grasslands too dry for farming. Only after generations of breeding for tractability did horses become reliable mounts. The economic transformation of steppe life, not the battlefield, drove the first wave of domestication.', NULL, '[{"id":"A","text":"By agreeing, since Text 2 also concludes that mounted raiding dominated steppe life.","is_correct":false,"explanation":"Reverses Text 2''s position, which holds that economic uses, not raiding, drove domestication."},{"id":"B","text":"By arguing that the earliest value of horses was economic, so military uses cannot explain the first expansion.","is_correct":true,"explanation":"Correct: Text 2 attributes the first wave to milk, meat, and hauling rather than the battlefield."},{"id":"C","text":"By noting that horses were never used in warfare on the steppe at all.","is_correct":false,"explanation":"Too extreme; Text 2 says war \"may have come later,\" not that it never occurred."},{"id":"D","text":"By pointing out that farming communities domesticated the horse before steppe peoples did.","is_correct":false,"explanation":"No evidence; Text 2 never claims farmers domesticated horses first."}]'::jsonb, 'B', 'Step 1 — Locate Text 2''s claim
Text 2 states that early peoples prized the horse "first for its milk, meat, and ability to haul loads" and that {{yellow:The economic transformation of steppe life, not the battlefield, drove the first wave of domestication}}.
Step 2 — Apply to Text 1
Because Text 2 roots the first expansion in economics, it would reject the idea that cavalry was the leading factor in the earliest spread.
Distractor analysis:
- A: Reverses Text 2, which denies that the battlefield drove the first wave.
- C: Too extreme; Text 2 allows that "War may have come later."
- D: No evidence; Text 2 never says farmers domesticated horses first.', 'Find what Text 2 says drove the FIRST wave of domestication.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c2cb5ee8-0e95-47d6-977e-0fd608ba148b', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that "the finest fiction effaces its teller entirely"?', 'Text 1
A novel''s narrator should be a clear window onto events. When a storyteller intrudes with opinions, digressions, and sly winks at the reader, the illusion of a living world collapses. The finest fiction effaces its teller entirely, letting characters and actions speak so that readers forget a hand is guiding them at all.

Text 2
Why pretend the teller isn''t there? A narrator''s voice—its irony, its asides, its open judgments—can be the deepest pleasure a novel offers. Readers are not children fooled by an illusion; they delight in the company of a witty intelligence shaping the tale. To hide the narrator is to discard one of fiction''s richest instruments.', NULL, '[{"id":"A","text":"By contending that an audible, judging narrator is a source of value rather than a flaw.","is_correct":true,"explanation":"Correct: Text 2 calls the narrator''s voice \"one of fiction''s richest instruments.\""},{"id":"B","text":"By agreeing that narrators should remain invisible but for different reasons.","is_correct":false,"explanation":"Contradicts Text 2, which defends a visible narrator, not invisibility."},{"id":"C","text":"By insisting that characters and action have no place in good fiction.","is_correct":false,"explanation":"Too extreme; Text 2 never dismisses characters or action."},{"id":"D","text":"By claiming that readers are easily fooled by a narrator''s illusions.","is_correct":false,"explanation":"Reverses Text 2, which says readers are \"not children fooled by an illusion.\""}]'::jsonb, 'A', 'Step 1 — Identify Text 2''s stance
Text 2 praises the narrator''s voice and warns that {{yellow:To hide the narrator is to discard one of fiction''s richest instruments}}.
Step 2 — Apply to Text 1
Since Text 2 treats the visible teller as a great resource, it would reject Text 1''s call to efface the teller, viewing such voice as valuable.
Distractor analysis:
- B: Contradicts Text 2, which wants the narrator heard, not hidden.
- C: Too extreme; Text 2 never says characters and action have no place.
- D: Reverses Text 2, which says readers are "not children fooled by an illusion."', 'What does Text 2 say is lost when the narrator is hidden?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9baa26c4-87cf-4934-8492-e0c30c065492', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the cave paintings were "surely the work of specialists"?', 'Text 1
The spectacular cave paintings of the last Ice Age were surely the work of specialists. The skill required to render galloping bison in such lifelike motion implies years of training and a recognized class of artists set apart from ordinary foragers. Such mastery does not arise by chance; it is the product of dedicated, professional hands.

Text 2
The handprints stenciled on many cave walls tell a quieter story. Their varied sizes suggest that women, men, and even children all left their marks. Far from being a guild of experts, the painters may have been an entire community taking turns, with skill spread broadly rather than reserved for a select few.', NULL, '[{"id":"A","text":"By agreeing that only a trained class of artists could have produced the images.","is_correct":false,"explanation":"Reverses Text 2, which proposes broad community participation."},{"id":"B","text":"By arguing that evidence of varied participants suggests painting was a shared communal activity.","is_correct":true,"explanation":"Correct: Text 2 cites handprints of varied sizes pointing to an \"entire community.\""},{"id":"C","text":"By concluding that the paintings required no skill whatsoever.","is_correct":false,"explanation":"Too extreme; Text 2 says skill was \"spread broadly,\" not absent."},{"id":"D","text":"By claiming that children alone created all the cave art.","is_correct":false,"explanation":"Too narrow; Text 2 lists women, men, and children, not children alone."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s evidence
Text 2 notes that varied handprint sizes suggest the painters {{yellow:may have been an entire community taking turns, with skill spread broadly rather than reserved for a select few}}.
Step 2 — Apply to Text 1
This communal picture directly opposes Text 1''s claim of a specialist class, so Text 2 would treat the art as a shared activity.
Distractor analysis:
- A: Reverses Text 2''s communal view.
- C: Too extreme; Text 2 says skill was "spread broadly," not absent.
- D: Too narrow; Text 2 names women, men, and children together.', 'What do the varied handprint sizes imply about who painted?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('798e2fa4-ebc9-4ca8-b059-0428f5543a14', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that cities are right to favor "tidy landscapes that the public can plainly enjoy"?', 'Text 1
Urban green spaces should be designed for visible human use: lawns for picnics, paved paths, trimmed beds. A park earns its keep by drawing crowds and offering recreation. Wild, untended patches may look like neglect to taxpayers, and a city is right to favor tidy landscapes that the public can plainly enjoy and that justify their cost.

Text 2
Manicured lawns are biological deserts. A patch of native grasses and "messy" undergrowth, by contrast, shelters pollinators, songbirds, and countless insects that mowed turf cannot. A park''s value lies partly in the life it sustains, much of it unseen by picnickers. Tidiness, prized for its own sake, can quietly impoverish the very ecosystems cities claim to protect.', NULL, '[{"id":"A","text":"By agreeing that recreation should always outweigh other uses of a park.","is_correct":false,"explanation":"Reverses Text 2, which values the unseen life a park sustains."},{"id":"B","text":"By arguing that prizing tidiness can damage the ecological value a park also provides.","is_correct":true,"explanation":"Correct: Text 2 warns that tidiness \"can quietly impoverish\" park ecosystems."},{"id":"C","text":"By insisting that parks should never permit any human recreation.","is_correct":false,"explanation":"Too extreme; Text 2 critiques tidiness, not all recreation."},{"id":"D","text":"By noting that taxpayers refuse to fund any wild park areas.","is_correct":false,"explanation":"No evidence; Text 2 makes no claim about taxpayer funding decisions."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s warning
Text 2 holds that {{yellow:Tidiness, prized for its own sake, can quietly impoverish the very ecosystems cities claim to protect}}.
Step 2 — Apply to Text 1
Because Text 2 sees a cost to favoring tidy landscapes, it would respond that Text 1''s preference overlooks the ecological harm such tidiness causes.
Distractor analysis:
- A: Reverses Text 2, which prizes unseen life over pure recreation.
- C: Too extreme; Text 2 never bans recreation.
- D: No evidence about taxpayer funding refusals.', 'What hidden cost does Text 2 attach to tidiness?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('470e0084-5bad-4f53-a5f2-cc92bdb087a9', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that "the technology itself" was the true engine of religious upheaval?', 'Text 1
The printing press, more than any reformer''s argument, shattered the medieval church''s authority. By flooding Europe with cheap pamphlets, the press let dissenting ideas spread faster than censors could suppress them. The technology itself, not the eloquence of any single thinker, was the true engine of religious upheaval in the sixteenth century.

Text 2
Presses do not print themselves. Printers chose what to set in type, and they chose it because reformers had already built audiences hungry for those words. The hunger came first; the machine merely fed it. To credit the press alone is to mistake a tool for the hand that wields it and the appetite that guides that hand.', NULL, '[{"id":"A","text":"By arguing that demand created by reformers, not the press alone, drove the upheaval.","is_correct":true,"explanation":"Correct: Text 2 says \"The hunger came first; the machine merely fed it.\""},{"id":"B","text":"By agreeing that the press acted entirely on its own.","is_correct":false,"explanation":"Reverses Text 2, which insists \"Presses do not print themselves.\""},{"id":"C","text":"By claiming the printing press played no role in the period.","is_correct":false,"explanation":"Too extreme; Text 2 says the machine \"fed\" the hunger, granting it a role."},{"id":"D","text":"By asserting that censors successfully suppressed all dissent.","is_correct":false,"explanation":"No evidence; Text 2 never discusses censors'' success."}]'::jsonb, 'A', 'Step 1 — Locate Text 2''s argument
Text 2 argues that printers set reformist texts because audiences already existed: {{yellow:The hunger came first; the machine merely fed it}}.
Step 2 — Apply to Text 1
Since Text 2 places demand before technology, it would reject crediting "the technology itself" as the true engine and emphasize the audience reformers built.
Distractor analysis:
- B: Reverses Text 2, which says presses don''t print themselves.
- C: Too extreme; Text 2 grants the press a feeding role.
- D: No evidence about censors succeeding.', 'According to Text 2, what came before the machine?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('06d0c7db-4ac2-4cd2-a2cd-35c4b2843a7e', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that the frogs'' coloration''s "function is unmistakable"?', 'Text 1
The brilliant colors of poison dart frogs are a warning sign evolved to deter predators. A bird that tastes one bitter, toxic frog learns to avoid that vivid pattern forever after. Bright coloration persists because it advertises danger, sparing the frog from attack. Its function is unmistakable: to say, plainly, "Do not eat me."

Text 2
Yet in some species, the same dazzling hues appear brightest during courtship, when males display to watching females. Predators may indeed avoid them, but the colors may have first arisen, or been intensified, to win mates. A signal can serve two audiences at once, and untangling which pressure shaped it first is no simple matter.', NULL, '[{"id":"A","text":"By agreeing that warning off predators is the single, obvious function of the colors.","is_correct":false,"explanation":"Reverses Text 2, which questions whether the function is single or obvious."},{"id":"B","text":"By arguing that the colors may also serve courtship, so their original function is uncertain.","is_correct":true,"explanation":"Correct: Text 2 says the colors may have arisen to win mates and the question \"is no simple matter.\""},{"id":"C","text":"By denying that predators ever avoid the brightly colored frogs.","is_correct":false,"explanation":"Reverses Text 2, which grants \"Predators may indeed avoid them.\""},{"id":"D","text":"By claiming the colors exist only to attract mates and never deter predators.","is_correct":false,"explanation":"Too extreme; Text 2 allows both functions, not mating alone."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s qualification
Text 2 observes that the hues may serve courtship and that {{yellow:untangling which pressure shaped it first is no simple matter}}.
Step 2 — Apply to Text 1
Because Text 2 sees a second possible function and genuine uncertainty, it would reject Text 1''s claim that the function is "unmistakable."
Distractor analysis:
- A: Reverses Text 2''s doubt about a single obvious function.
- C: Reverses Text 2, which grants predators "may indeed avoid them."
- D: Too extreme; Text 2 allows both functions.', 'What second purpose does Text 2 propose for the colors?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2c73131e-6504-44b3-85e0-4d0aa18562fc', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that literacy rates offer "a clear and honest scorecard of educational progress"?', 'Text 1
A nation''s literacy rate is the surest measure of its commitment to education. When more citizens can read and write, schools are evidently doing their work, and the society is investing wisely in its future. Rising literacy figures, tracked over decades, offer governments a clear and honest scorecard of educational progress.

Text 2
Literacy counts only whether a person can read at all, not how well or how deeply. A country may report near-universal literacy while most adults struggle with a bus schedule or a medicine label. A single yes-or-no figure flatters the data; it tells us little about the comprehension that education is meant to build.', NULL, '[{"id":"A","text":"By agreeing that literacy rates fully capture how deeply citizens understand what they read.","is_correct":false,"explanation":"Reverses Text 2, which says literacy ignores depth of comprehension."},{"id":"B","text":"By arguing that a yes-or-no literacy measure hides gaps in real comprehension.","is_correct":true,"explanation":"Correct: Text 2 says the single figure \"flatters the data\" and reveals little about comprehension."},{"id":"C","text":"By claiming that schools have no effect on whether citizens can read.","is_correct":false,"explanation":"No evidence; Text 2 never denies that schools teach reading."},{"id":"D","text":"By insisting that literacy rates should be tracked over even longer periods.","is_correct":false,"explanation":"True-but-irrelevant; Text 2''s concern is the measure''s depth, not its time span."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s critique
Text 2 argues that {{yellow:A single yes-or-no figure flatters the data; it tells us little about the comprehension that education is meant to build}}.
Step 2 — Apply to Text 1
Since Text 2 sees the measure as concealing comprehension gaps, it would deny that literacy rates are an honest scorecard of progress.
Distractor analysis:
- A: Reverses Text 2, which says literacy ignores depth.
- C: No evidence; Text 2 doesn''t deny schools teach reading.
- D: True-but-irrelevant; the issue is depth, not duration of tracking.', 'What does Text 2 say a yes-or-no figure hides?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('faf9b582-6fc2-4c16-9716-7e0fa24c40a0', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the Polynesians'' arrival "was a matter of luck, not navigation"?', 'Text 1
The ancient Polynesians who settled the remote Pacific islands must have voyaged by accident, swept off course by storms into the unknown. No people without compasses or charts could have deliberately found specks of land separated by thousands of miles of open ocean. Their arrival on distant islands was a matter of luck, not navigation.

Text 2
Drift voyages cannot populate islands. Settling a new land requires men, women, food crops, and breeding animals arriving together by design. Polynesian navigators read swells, stars, and the flight of birds with a precision modern sailors have struggled to match. They reached those islands because they knew how to find them.', NULL, '[{"id":"A","text":"By agreeing that storms, not skill, carried the settlers to distant islands.","is_correct":false,"explanation":"Reverses Text 2, which credits deliberate navigation."},{"id":"B","text":"By arguing that successful settlement required deliberate, skilled navigation rather than chance.","is_correct":true,"explanation":"Correct: Text 2 says they reached the islands \"because they knew how to find them.\""},{"id":"C","text":"By claiming the Polynesians used compasses and charts after all.","is_correct":false,"explanation":"No evidence; Text 2 cites swells, stars, and birds, not compasses or charts."},{"id":"D","text":"By conceding that only a few individuals ever reached the islands by drifting.","is_correct":false,"explanation":"Contradicts Text 2, which says drift voyages cannot populate islands at all."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s reasoning
Text 2 contends that settlement needed people, crops, and animals "arriving together by design," concluding that {{yellow:They reached those islands because they knew how to find them}}.
Step 2 — Apply to Text 1
Because Text 2 attributes arrival to deliberate skill, it would reject Text 1''s claim that it was luck rather than navigation.
Distractor analysis:
- A: Reverses Text 2''s emphasis on skill.
- C: No evidence; Text 2 names natural cues, not compasses or charts.
- D: Contradicts Text 2, which says drift cannot populate islands.', 'What does Text 2 say settling an island requires?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6542371b-6954-48e9-b210-efd5dc632b5c', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that the raiders'' "violence is the key that unlocks" the Bronze Age collapse?', 'Text 1
The sudden collapse of the Bronze Age Mediterranean civilizations was triggered by raiding "Sea Peoples" who descended on coastal cities, burning palaces and toppling kingdoms in a single generation. These invaders, recorded in Egyptian inscriptions, swept away a whole interconnected world. Their violence is the key that unlocks one of history''s great mysteries.

Text 2
Invaders rarely arrive into a thriving order. A long drought, failing harvests, and the breakdown of trade routes had already weakened these kingdoms before any raider appeared. The Sea Peoples may have been less a cause than a symptom—desperate migrants set in motion by the same crises that were toppling the palaces from within.', NULL, '[{"id":"A","text":"By agreeing that the Sea Peoples were the original cause of the collapse.","is_correct":false,"explanation":"Reverses Text 2, which calls them a possible symptom, not a cause."},{"id":"B","text":"By arguing that prior crises weakened the kingdoms, making the raiders a symptom more than a cause.","is_correct":true,"explanation":"Correct: Text 2 says the Sea Peoples \"may have been less a cause than a symptom.\""},{"id":"C","text":"By denying that any coastal cities were ever attacked.","is_correct":false,"explanation":"No evidence; Text 2 never disputes that attacks occurred."},{"id":"D","text":"By claiming that drought alone destroyed every palace without any human action.","is_correct":false,"explanation":"Too extreme; Text 2 still involves migrants, not drought acting alone."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s reframing
Text 2 notes prior drought and trade breakdown and proposes the Sea Peoples {{yellow:may have been less a cause than a symptom}}.
Step 2 — Apply to Text 1
Because Text 2 sees the collapse as already underway, it would reject the raiders'' violence as the single key and recast them as a result of deeper crises.
Distractor analysis:
- A: Reverses Text 2''s symptom view.
- C: No evidence; Text 2 doesn''t deny the attacks.
- D: Too extreme; Text 2 still involves migrants, not drought alone.', 'Does Text 2 call the Sea Peoples a cause or a symptom?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7b4e195a-acfd-4453-b3b6-684fcfeff1aa', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that music training "sharpens general intelligence"?', 'Text 1
Early childhood music lessons make children smarter. Studies show that children who take piano lessons score higher on tests of reasoning than peers who do not. Music training, by exercising the brain in disciplined ways, evidently sharpens general intelligence. Parents who want brighter children should put them at the keyboard.

Text 2
The children who take piano lessons are seldom chosen at random. They tend to come from families with more money, more books, and more time to spend on a child''s development. Such homes may produce both the lessons and the higher scores. Before crediting the music, one must ask whether the comparison groups were ever truly alike.', NULL, '[{"id":"A","text":"By agreeing that piano lessons directly cause the higher reasoning scores.","is_correct":false,"explanation":"Reverses Text 2, which questions whether lessons cause the scores."},{"id":"B","text":"By arguing that family advantages, not the lessons, may explain both the music and the higher scores.","is_correct":true,"explanation":"Correct: Text 2 says such homes \"may produce both the lessons and the higher scores.\""},{"id":"C","text":"By claiming that music lessons lower children''s test scores.","is_correct":false,"explanation":"No evidence; Text 2 never says lessons reduce scores."},{"id":"D","text":"By insisting that only wealthy children are capable of learning piano.","is_correct":false,"explanation":"Too extreme; Text 2 discusses who tends to take lessons, not who is able to."}]'::jsonb, 'B', 'Step 1 — Locate Text 2''s objection
Text 2 notes that piano students come from advantaged homes and that {{yellow:Such homes may produce both the lessons and the higher scores}}.
Step 2 — Apply to Text 1
Because Text 2 points to a confounding family advantage, it would deny that the lessons themselves sharpen intelligence and question the comparison.
Distractor analysis:
- A: Reverses Text 2''s doubt about causation.
- C: No evidence; Text 2 doesn''t claim lessons lower scores.
- D: Too extreme; Text 2 addresses who tends to take lessons, not who can.', 'What third factor does Text 2 say might explain both the lessons and the scores?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b993d18e-1e28-4305-a24e-6daaf19e24d4', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that a drained wetland is "land redeemed"?', 'Text 1
Wetlands are wastelands awaiting improvement. Drained and filled, a marsh becomes farmland or a building site, turning idle swamp into productive ground. For centuries, progress has meant converting these soggy margins into something useful. A drained wetland is land redeemed, its standing water replaced by harvests and homes.

Text 2
A marsh at work is anything but idle. It filters pollutants from water, buffers coastlines against storms, and cradles fish that feed distant fisheries. These services, performed for free, would cost a fortune to replace with engineering. To drain a wetland is not to redeem idle land but to demolish infrastructure we never had to build.', NULL, '[{"id":"A","text":"By agreeing that wetlands provide nothing until they are drained and built upon.","is_correct":false,"explanation":"Reverses Text 2, which lists valuable services wetlands already provide."},{"id":"B","text":"By arguing that draining destroys valuable natural services, so it is loss rather than redemption.","is_correct":true,"explanation":"Correct: Text 2 says draining is \"to demolish infrastructure we never had to build.\""},{"id":"C","text":"By claiming that wetlands can never be used for farming or building under any circumstances.","is_correct":false,"explanation":"Too extreme; Text 2 stresses costs of draining, not an absolute ban."},{"id":"D","text":"By noting that replacing wetland services with engineering is inexpensive and easy.","is_correct":false,"explanation":"Reverses Text 2, which says replacement \"would cost a fortune.\""}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s claim
Text 2 says wetlands provide free services and concludes that {{yellow:To drain a wetland is not to redeem idle land but to demolish infrastructure we never had to build}}.
Step 2 — Apply to Text 1
Because Text 2 frames draining as destroying valuable services, it would reject Text 1''s view that a drained wetland is land "redeemed."
Distractor analysis:
- A: Reverses Text 2, which lists existing wetland services.
- C: Too extreme; Text 2 stresses cost, not an absolute ban.
- D: Reverses Text 2, which says replacement "would cost a fortune."', 'How does Text 2 describe what draining actually destroys?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c5433525-a627-458a-b706-9e09d4719381', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that the statues are "monuments to a civilization that destroyed itself"?', 'Text 1
The great stone heads of Easter Island prove that its people exhausted their own resources. To move such monuments, the islanders must have felled their forests for rollers and ropes, stripping the land until the soil failed and their society collapsed. The statues stand as monuments to a civilization that destroyed itself through reckless ambition.

Text 2
Rats, not statues, may have doomed the forests. Stowaways in the first canoes, they multiplied and devoured the seeds of palms faster than the trees could regrow. The islanders, meanwhile, adapted with stone gardens and new crops. Their numbers held until outsiders arrived with disease and slavery. The collapse, if any, came from beyond the shore.', NULL, '[{"id":"A","text":"By agreeing that moving the statues was the chief cause of the forests'' loss.","is_correct":false,"explanation":"Reverses Text 2, which blames rats and outside forces rather than statue-moving."},{"id":"B","text":"By arguing that rats and outside contact, not self-destruction, better explain the island''s decline.","is_correct":true,"explanation":"Correct: Text 2 attributes forest loss to rats and says collapse \"came from beyond the shore.\""},{"id":"C","text":"By claiming the islanders never built any large stone statues.","is_correct":false,"explanation":"No evidence; Text 2 doesn''t dispute that the statues were built."},{"id":"D","text":"By conceding that the islanders failed to adapt to their changing environment.","is_correct":false,"explanation":"Reverses Text 2, which says the islanders \"adapted with stone gardens and new crops.\""}]'::jsonb, 'B', 'Step 1 — Find Text 2''s account
Text 2 blames seed-eating rats and outside disease and slavery, concluding that {{yellow:The collapse, if any, came from beyond the shore}}.
Step 2 — Apply to Text 1
Because Text 2 locates the cause in rats and outsiders rather than the islanders'' ambition, it would reject Text 1''s self-destruction narrative.
Distractor analysis:
- A: Reverses Text 2, which blames rats, not statue-moving.
- C: No evidence; Text 2 doesn''t deny the statues were built.
- D: Reverses Text 2, which says the islanders adapted.', 'What does Text 2 blame for the lost forests and decline?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4babd23a-47c0-4b2d-8975-b02b89df221a', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that clocks "freed people from the irregular rhythms of sunlight and seasons"?', 'Text 1
The spread of mechanical clocks across medieval European towns marked a true turning point in human history. By dividing the day into uniform hours, clocks freed people from the irregular rhythms of sunlight and seasons. For the first time, work, prayer, and commerce could be coordinated with precision, and this shared sense of time bound communities together as never before.

Text 2
We should not overstate the clock''s liberating power. The same uniform hours that coordinated commerce also disciplined laborers, who were now fined for arriving a few minutes late. Town bells did not free workers from natural rhythms so much as bind them to the schedules of merchants and magistrates. What looks like shared time was often imposed time.', NULL, '[{"id":"A","text":"Clocks did not actually divide the day into uniform hours as Text 1 suggests.","is_correct":false,"explanation":"Text 2 never disputes that clocks created uniform hours; it disputes who benefited from them."},{"id":"B","text":"What Text 1 calls freedom was for many laborers a new form of imposed control.","is_correct":true,"explanation":"Text 2 reframes the supposed liberation as discipline imposed on workers by merchants and magistrates."},{"id":"C","text":"Clocks spread too slowly across medieval towns to affect daily rhythms.","is_correct":false,"explanation":"Text 2 makes no claim about the speed of the clock''s spread; this is outside its argument."},{"id":"D","text":"Natural rhythms of sunlight were more precise than mechanical clocks.","is_correct":false,"explanation":"Text 2 does not claim natural rhythms were more precise; it questions who the clock served."}]'::jsonb, 'B', 'Step 1 — Locate the rebuttal
Text 2 counters that the clock did not liberate workers but disciplined them, since the same uniform hours that coordinated commerce {{yellow:also disciplined laborers, who were now fined for arriving a few minutes late}}.
Step 2 — Why B follows
Because Text 2 calls this "imposed time" rather than shared freedom, its author would respond that Text 1''s "freedom" was actually a new form of control for laborers.
Distractor analysis:
- A: Text 2 accepts that clocks created uniform hours; it disputes their effect, not their existence.
- C: The pace of the clock''s spread is never mentioned in Text 2.
- D: Text 2 does not compare the precision of natural rhythms to clocks.', 'Text 2 reframes "freedom" using the word "imposed." Who is being controlled?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d289c5d1-e196-4b94-adfc-6801cd7b2edf', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that wherever earthworms arrive "the ground becomes richer and more fertile"?', 'Text 1
The introduction of non-native earthworms into northern forests has been widely welcomed by gardeners. Earthworms aerate compacted soil, break down leaf litter, and recycle nutrients into forms plants can absorb. Wherever these industrious creatures arrive, the ground becomes richer and more fertile, and the visible health of the soil improves dramatically within a few seasons.

Text 2
In gardens, perhaps, but northern forests evolved for thousands of years without earthworms. There, a thick layer of slowly decaying leaf litter shelters tree seedlings and native wildflowers. When introduced worms consume that litter rapidly, they strip away the very layer those plants depend on. A change that enriches a flowerbed can quietly impoverish a forest.', NULL, '[{"id":"A","text":"Earthworms do not actually break down leaf litter as Text 1 claims.","is_correct":false,"explanation":"Text 2 agrees worms consume litter rapidly; that consumption is central to its concern."},{"id":"B","text":"The benefit Text 1 describes does not transfer to forests, where worms can harm native plants.","is_correct":true,"explanation":"Text 2 limits Text 1''s claim to gardens and argues worms strip the litter forest plants depend on."},{"id":"C","text":"Earthworms enrich forest soil even more than they enrich garden soil.","is_correct":false,"explanation":"This reverses Text 2''s argument, which holds that worms impoverish forests."},{"id":"D","text":"Gardeners should introduce even more earthworms into compacted soils.","is_correct":false,"explanation":"Text 2 warns against the spread of worms into forests rather than endorsing more of them."}]'::jsonb, 'B', 'Step 1 — Locate the qualification
Text 2 concedes the garden benefit but warns that in forests worms strip the leaf litter, since {{yellow:A change that enriches a flowerbed can quietly impoverish a forest}}.
Step 2 — Why B follows
Because Text 2 restricts Text 1''s fertility claim to gardens and shows the opposite effect in forests, its author would say the benefit does not transfer to forest ecosystems.
Distractor analysis:
- A: Text 2 accepts that worms break down litter; it sees that as the problem, not a falsehood.
- C: This reverses Text 2, which says worms impoverish, not enrich, forests.
- D: Text 2 cautions against worm spread into forests, not for more introductions.', 'Text 2 grants the claim ''in gardens'' but draws a sharp line at a different setting.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8c405594-c835-4ad2-99e0-0297ae335f16', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that an unresolved ending "betrays" the reader''s investment?', 'Text 1
The novelist''s decision to leave her heroine''s fate unresolved at the story''s end is a flaw. Readers invest hundreds of pages in a character''s struggles, and they deserve the satisfaction of knowing how those struggles conclude. An ending that withholds resolution betrays that investment and leaves the reader frustrated rather than moved.

Text 2
But an open ending need not be a betrayal. By refusing to tie the heroine''s fate into a neat bow, the novelist invites readers to imagine the possibilities themselves, extending the story''s life beyond the final page. The frustration one critic feels may be, for another reader, the lingering ache that makes a novel unforgettable.', NULL, '[{"id":"A","text":"Unresolved endings are appropriate only in short stories, not novels.","is_correct":false,"explanation":"Text 2 makes no distinction between short stories and novels; it defends the open ending generally."},{"id":"B","text":"Readers do not actually invest much in a character''s struggles.","is_correct":false,"explanation":"Text 2 does not deny readers'' investment; it argues the open ending rewards it differently."},{"id":"C","text":"What one reader experiences as betrayal another may experience as a lasting, moving effect.","is_correct":true,"explanation":"Text 2 reframes the open ending as a source of lingering resonance rather than frustration."},{"id":"D","text":"The novelist should have provided a neat, conclusive ending after all.","is_correct":false,"explanation":"This contradicts Text 2, which praises the refusal to tie things into a neat bow."}]'::jsonb, 'C', 'Step 1 — Locate the reframing
Text 2 turns the alleged betrayal into a virtue, noting that {{yellow:The frustration one critic feels may be, for another reader, the lingering ache that makes a novel unforgettable}}.
Step 2 — Why C follows
Because Text 2 treats the same ending as moving rather than frustrating for a different reader, its author would respond that betrayal is only one possible response, not an inherent flaw.
Distractor analysis:
- A: Text 2 never limits open endings to short stories.
- B: Text 2 does not deny readers'' investment; it claims the ending rewards it.
- D: This reverses Text 2''s defense of the open ending.', 'Text 2 keeps the same ending but changes whose reaction we consider.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('148d3b60-6e0e-4f3d-81f9-76c085e3d775', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that remote employees "complete their tasks just as efficiently from home"?', 'Text 1
The surge in remote work proves that the traditional office is obsolete. Employees report higher satisfaction, save hours of commuting, and complete their tasks just as efficiently from home. Companies that cling to mandatory in-person attendance are simply resisting an inevitable and beneficial shift in how modern work is organized.

Text 2
Productivity surveys tell only part of the story. Much of the knowledge that fuels innovation passes informally, in hallway conversations and unplanned encounters that screens cannot replicate. Remote work may suit routine tasks measured by output, yet the creative collisions that drive a company''s long-term invention are precisely what distance erodes most quietly.', NULL, '[{"id":"A","text":"Remote employees are actually far less efficient at routine tasks than Text 1 admits.","is_correct":false,"explanation":"Text 2 concedes remote work may suit routine tasks; it does not dispute their efficiency."},{"id":"B","text":"Such efficiency measures overlook the informal exchanges that drive long-term innovation.","is_correct":true,"explanation":"Text 2 grants task efficiency but argues distance erodes the creative collisions that fuel invention."},{"id":"C","text":"Commuting time saved is the most important benefit of remote work.","is_correct":false,"explanation":"Text 2 does not weigh in on commuting; it focuses on innovation lost."},{"id":"D","text":"Companies should immediately abolish all in-person attendance.","is_correct":false,"explanation":"This aligns with Text 1, not Text 2, which warns about what distance erodes."}]'::jsonb, 'B', 'Step 1 — Locate the limitation
Text 2 accepts task efficiency but warns that {{yellow:the creative collisions that drive a company''s long-term invention are precisely what distance erodes most quietly}}.
Step 2 — Why B follows
Because Text 2 says output measures capture only routine work and miss informal innovation, its author would respond that efficiency at tasks overlooks a deeper loss.
Distractor analysis:
- A: Text 2 grants efficiency on routine tasks rather than denying it.
- C: Text 2 does not discuss commuting savings.
- D: This endorses Text 1''s position, not Text 2''s caution.', 'Text 2 accepts the efficiency point but says it measures only one kind of work.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0c3e3095-5382-45a3-bfef-1420a8451f4a', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that soft tissue finds suggest the fossils "are far younger than conventional dating assumes"?', 'Text 1
The discovery of soft tissue inside certain dinosaur fossils overturns everything we thought about preservation. Proteins and flexible vessels cannot survive tens of millions of years, so these finds suggest the fossils, and perhaps the rocks containing them, are far younger than conventional dating assumes. The textbook timeline of Earth''s history may need wholesale revision.

Text 2
The soft tissue is real, but the conclusion is hasty. Recent laboratory work shows that iron released from blood can cross-link proteins, dramatically slowing their decay and allowing fragile structures to persist for ages once thought impossible. The surprising endurance of these molecules tells us our chemistry was incomplete, not that our calendars were wrong.', NULL, '[{"id":"A","text":"The reported soft tissue is probably a contamination artifact, not genuine.","is_correct":false,"explanation":"Text 2 explicitly states the soft tissue is real, so it does not call it an artifact."},{"id":"B","text":"A newly understood chemical process can explain the tissue''s survival without revising the dates.","is_correct":true,"explanation":"Text 2 cites iron cross-linking to preserve tissue, concluding the chemistry, not the calendar, was wrong."},{"id":"C","text":"Conventional dating methods are even less reliable than Text 1 claims.","is_correct":false,"explanation":"This reverses Text 2, which defends the conventional timeline against revision."},{"id":"D","text":"Soft tissue could never survive under any chemical conditions.","is_correct":false,"explanation":"Text 2 argues the opposite, that iron lets tissue persist for ages."}]'::jsonb, 'B', 'Step 1 — Locate the alternative explanation
Text 2 grants the tissue is real but attributes its survival to chemistry, noting iron can cross-link proteins so that {{yellow:The surprising endurance of these molecules tells us our chemistry was incomplete, not that our calendars were wrong}}.
Step 2 — Why B follows
Because Text 2 supplies a preservation mechanism, its author would respond that the finds require no revision of the dates, only of our chemistry.
Distractor analysis:
- A: Text 2 affirms the tissue is real, not contamination.
- C: This reverses Text 2''s defense of conventional dating.
- D: Text 2 says tissue can survive via iron, contradicting this.', 'Text 2 keeps the data but offers a chemical cause that leaves the dates intact.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a93616b4-ca58-44dc-b953-9ed4b3e798c0', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the Homestead Act "transformed landless citizens into independent farmers"?', 'Text 1
The Homestead Act of 1862, which granted 160 acres of public land to any settler willing to farm it, fulfilled the democratic promise of widely distributed property. By opening the frontier to ordinary families regardless of wealth, the law transformed landless citizens into independent farmers and embodied the nation''s commitment to equal opportunity.

Text 2
The law''s promise looked very different on the ground. Much of the best land was quickly engrossed by railroads and speculators, while the arid plots left to homesteaders often could not support a family. The Act''s generous acreage meant little where rainfall was scarce, and many claimants abandoned their land within a few hard years.', NULL, '[{"id":"A","text":"The Act granted far more than 160 acres to most settlers.","is_correct":false,"explanation":"Text 2 does not dispute the acreage figure; it questions the land''s usefulness."},{"id":"B","text":"For many claimants the promised independence failed because the available land could not sustain a farm.","is_correct":true,"explanation":"Text 2 stresses arid plots and abandonment, undercutting the claim of successful transformation."},{"id":"C","text":"Railroads deserved the land more than ordinary settlers did.","is_correct":false,"explanation":"Text 2 criticizes engrossment by railroads rather than endorsing their claims."},{"id":"D","text":"The Act applied only to settlers who were already wealthy.","is_correct":false,"explanation":"Text 2 does not claim the law excluded the poor; it says the land they got was poor."}]'::jsonb, 'B', 'Step 1 — Locate the counterevidence
Text 2 undercuts the success story by noting that {{yellow:many claimants abandoned their land within a few hard years}}.
Step 2 — Why B follows
Because Text 2 shows the arid plots could not support families, its author would respond that the promised independence often failed in practice.
Distractor analysis:
- A: Text 2 does not challenge the 160-acre figure.
- C: Text 2 criticizes railroad engrossment rather than defending it.
- D: Text 2 says the land was poor, not that poor settlers were excluded.', 'Text 2 doesn''t argue about who got land, but about whether that land could be farmed.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('18a86f5e-fb57-4386-9ec4-a2dfc512c493', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that standardized tests are "untainted by the personal biases" of human judgment?', 'Text 1
Standardized achievement tests offer the fairest way to compare students across schools. Because every test-taker answers the same questions under the same conditions, the results provide an objective yardstick untainted by the personal biases that color teacher grades. A single common measure ensures that talent, wherever it appears, is recognized on equal terms.

Text 2
A shared yardstick is only as fair as what it measures. Test items are written, reviewed, and chosen by people whose assumptions about relevant knowledge shape every question. Students familiar with the vocabulary and examples those writers favor hold a quiet advantage. Uniform conditions cannot make a test neutral if its very content reflects one group''s experience.', NULL, '[{"id":"A","text":"Test conditions are not actually uniform across different schools.","is_correct":false,"explanation":"Text 2 does not dispute uniform conditions; it grants them while challenging the content."},{"id":"B","text":"Teacher grades are in fact more objective than standardized tests.","is_correct":false,"explanation":"Text 2 never defends teacher grades; it questions the test''s neutrality directly."},{"id":"C","text":"Human assumptions still shape the test through the content its writers choose.","is_correct":true,"explanation":"Text 2 argues that the writers'' assumptions embed bias in the very questions."},{"id":"D","text":"Standardized tests should be expanded to cover more subjects.","is_correct":false,"explanation":"Text 2 makes no recommendation about expanding test coverage."}]'::jsonb, 'C', 'Step 1 — Locate the rebuttal
Text 2 argues that bias enters through the test''s content, since {{yellow:Uniform conditions cannot make a test neutral if its very content reflects one group''s experience}}.
Step 2 — Why C follows
Because Text 2 traces the questions to writers'' assumptions, its author would respond that human bias is built in rather than removed.
Distractor analysis:
- A: Text 2 accepts uniform conditions; it targets content instead.
- B: Text 2 does not argue teacher grades are more objective.
- D: Text 2 says nothing about adding subjects.', 'Text 2 grants the ''same conditions'' but moves the bias to a different stage of the test.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('679ace1e-84da-43ae-8dbf-96d5a0d3d7e3', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the "sheer volume of observations" gives scientists an unprecedented window into species'' shifts?', 'Text 1
The rise of citizen science, in which volunteers gather data for researchers, is a boon to ecology. Thousands of amateurs counting birds or photographing insects can cover far more ground than any funded team. The sheer volume of observations these enthusiasts provide gives scientists an unprecedented window into how species are shifting across the globe.

Text 2
Volume is not the same as reliability. Volunteers tend to visit accessible parks and roadsides, not remote terrain, so their sightings cluster where people already are. Common, easily identified species get reported again and again, while rare or cryptic ones are missed. The resulting map may show less about nature than about where the observers happen to walk.', NULL, '[{"id":"A","text":"Volunteers cannot identify even common species accurately.","is_correct":false,"explanation":"Text 2 says common species get reported repeatedly, implying volunteers do identify them."},{"id":"B","text":"Large volumes of data can be biased by where and what volunteers choose to observe.","is_correct":true,"explanation":"Text 2 argues clustered, selective sightings distort the picture despite their volume."},{"id":"C","text":"Funded research teams gather even less reliable data than volunteers.","is_correct":false,"explanation":"Text 2 does not compare volunteers to funded teams in reliability."},{"id":"D","text":"Citizen science should focus only on rare and cryptic species.","is_correct":false,"explanation":"Text 2 notes rare species are missed but does not recommend focusing solely on them."}]'::jsonb, 'B', 'Step 1 — Locate the qualification
Text 2 warns that the data''s volume can mislead, since {{yellow:The resulting map may show less about nature than about where the observers happen to walk}}.
Step 2 — Why B follows
Because Text 2 stresses that sightings cluster by access and familiarity, its author would respond that volume alone does not ensure an accurate window into species shifts.
Distractor analysis:
- A: Text 2 implies common species are reliably identified, contradicting this.
- C: Text 2 does not rate funded teams'' reliability.
- D: Text 2 does not call for focusing only on rare species.', 'Text 2 separates ''how much'' data from ''how representative'' it is.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e33b0c8e-22ef-4464-b41f-566d033d74cd', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that within park borders "nature can flourish undisturbed"?', 'Text 1
The expansion of national parks is conservation''s greatest triumph. By drawing firm boundaries around pristine wilderness and barring development, governments have preserved landscapes that would otherwise have vanished. Within these protected borders, nature can flourish undisturbed, safeguarded for future generations exactly as it was meant to be.

Text 2
The boundaries that protect can also distort. Many parks were created by removing the Indigenous peoples who had shaped those landscapes for millennia through controlled burning and careful harvest. The "undisturbed" wilderness we admire is in part an artifact of that removal, and without the old human tending, some of these ecosystems have grown overgrown and prone to catastrophic fire.', NULL, '[{"id":"A","text":"Parks have failed to bar development within their boundaries.","is_correct":false,"explanation":"Text 2 does not dispute that development is barred; it questions the idea of an untouched wilderness."},{"id":"B","text":"The supposedly undisturbed wilderness was actually shaped, and is harmed by the loss of, human tending.","is_correct":true,"explanation":"Text 2 argues Indigenous management shaped the land and its removal left ecosystems worse off."},{"id":"C","text":"National parks should be opened to commercial logging.","is_correct":false,"explanation":"Text 2 does not advocate logging; it discusses traditional burning and harvest."},{"id":"D","text":"Wilderness areas were never inhabited by any people.","is_correct":false,"explanation":"This contradicts Text 2, which says Indigenous peoples shaped the land for millennia."}]'::jsonb, 'B', 'Step 1 — Locate the critique
Text 2 challenges the idea of untouched nature, stating that {{yellow:The "undisturbed" wilderness we admire is in part an artifact of that removal}}.
Step 2 — Why B follows
Because Text 2 says the land was shaped by Indigenous tending and suffers without it, its author would respond that the "undisturbed" flourishing is a misconception.
Distractor analysis:
- A: Text 2 does not claim development continues inside parks.
- C: Text 2 references traditional harvest, not commercial logging.
- D: Text 2 affirms the land was inhabited and shaped, contradicting this.', 'Text 2 attacks the word ''undisturbed'' by pointing to who used to tend the land.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('64ce9490-ad64-4505-9fa7-cfa231adda48', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that digital payments produce "a cleaner, more efficient, and more honest economy"?', 'Text 1
The replacement of cash with digital payments is an unambiguous good. Electronic transactions are faster, leave a clear record that deters theft and tax evasion, and spare people the inconvenience of carrying bills and coins. As more shops go cashless, society moves toward a cleaner, more efficient, and more honest economy.

Text 2
Efficiency has its costs. A cashless economy quietly excludes those without bank accounts or smartphones, many of them elderly or poor, who suddenly cannot buy a sandwich at a cashless cafe. And every digital trace that deters tax evasion also hands corporations and governments a detailed record of where, when, and how each of us spends.', NULL, '[{"id":"A","text":"Digital payments are actually slower than cash transactions.","is_correct":false,"explanation":"Text 2 does not dispute the speed of digital payments; it raises exclusion and surveillance."},{"id":"B","text":"Those gains come at the cost of excluding some people and eroding everyone''s privacy.","is_correct":true,"explanation":"Text 2 grants the efficiency but cites exclusion of the unbanked and pervasive tracking."},{"id":"C","text":"Cash transactions leave a clearer record than digital ones.","is_correct":false,"explanation":"This reverses the texts; Text 2 worries that digital traces are too detailed, not that cash is clearer."},{"id":"D","text":"Society should abolish digital payments entirely.","is_correct":false,"explanation":"Text 2 weighs costs but does not call for abolishing digital payments."}]'::jsonb, 'B', 'Step 1 — Locate the tradeoff
Text 2 accepts efficiency but warns of hidden costs, noting that a cashless economy {{yellow:quietly excludes those without bank accounts or smartphones}}.
Step 2 — Why B follows
Because Text 2 also flags the detailed records handed to corporations and governments, its author would respond that the gains carry costs in exclusion and privacy.
Distractor analysis:
- A: Text 2 does not deny digital speed.
- C: This reverses the texts'' point about who keeps detailed records.
- D: Text 2 critiques costs but does not call for abolition.', 'Text 2 doesn''t deny the benefits; it names two groups or values that pay a price.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5ba98c71-8799-4cf9-a34a-1a21983a56b1', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that such feats demonstrate "genuine insight into how the world works"?', 'Text 1
Giving wild animals problem-solving puzzles in zoos clearly proves their intelligence. When an octopus opens a sealed jar or a crow bends a wire to retrieve food, it demonstrates reasoning comparable to our own. Such feats reveal minds far richer than science once assumed, capable of genuine insight into how the world works.

Text 2
The puzzles are impressive, but "insight" is a strong word. An animal may solve a jar not by reasoning about its mechanism but by persistently trying movements until one succeeds, then repeating what worked. Without experiments that rule out gradual trial-and-error, a clever solution tells us an animal can learn, not that it understands.', NULL, '[{"id":"A","text":"Animals cannot actually solve the puzzles described in Text 1.","is_correct":false,"explanation":"Text 2 calls the puzzle-solving impressive; it does not deny that animals succeed."},{"id":"B","text":"The successes may reflect gradual trial-and-error learning rather than true understanding.","is_correct":true,"explanation":"Text 2 offers learning by repeated attempts as an alternative to insight unless ruled out."},{"id":"C","text":"Animal intelligence far exceeds even human reasoning.","is_correct":false,"explanation":"Text 2 is skeptical of strong intelligence claims, not eager to extend them."},{"id":"D","text":"Zoos should stop giving animals puzzles to solve.","is_correct":false,"explanation":"Text 2 questions the interpretation of the puzzles, not the practice itself."}]'::jsonb, 'B', 'Step 1 — Locate the alternative
Text 2 proposes a simpler explanation, suggesting an animal may solve a jar by {{yellow:persistently trying movements until one succeeds, then repeating what worked}}.
Step 2 — Why B follows
Because Text 2 insists experiments must rule out trial-and-error before crediting insight, its author would respond that the feats may show learning rather than understanding.
Distractor analysis:
- A: Text 2 grants that animals solve the puzzles.
- C: Text 2 is skeptical of intelligence claims, not inclined to inflate them.
- D: Text 2 critiques the interpretation, not the practice of giving puzzles.', 'Text 2 offers a less flattering explanation for the same successful behavior.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a1ca0393-deca-4251-b871-84b801bc8e3c', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that drought "is best explained" as the cause of the Bronze Age collapse?', 'Text 1
The sudden collapse of the Bronze Age civilizations around 1200 BCE is best explained by a great drought. Pollen records and dried lake beds across the eastern Mediterranean point to decades of failed rains. Starving populations could not sustain their palaces and armies, and one by one the proud kingdoms crumbled into ruin.

Text 2
Drought surely strained these societies, but strain alone rarely topples a kingdom. What made the collapse so total was how tightly the kingdoms were bound together by trade in tin, grain, and bronze. When one link failed, the shock raced through the whole network, so a regional dry spell became a systemic collapse no single kingdom could survive.', NULL, '[{"id":"A","text":"There is no real evidence that any drought occurred at that time.","is_correct":false,"explanation":"Text 2 accepts the drought, saying it ''surely strained'' these societies."},{"id":"B","text":"Drought was a real strain, but the kingdoms'' interdependence turned it into total collapse.","is_correct":true,"explanation":"Text 2 grants the drought yet credits the tightly linked trade network for the scale of collapse."},{"id":"C","text":"The kingdoms collapsed mainly because of invading armies, not drought.","is_correct":false,"explanation":"Text 2 emphasizes trade interdependence, not invasion, as the missing factor."},{"id":"D","text":"Trade between kingdoms protected them from collapse.","is_correct":false,"explanation":"This reverses Text 2, which says trade links spread the shock rather than buffering it."}]'::jsonb, 'B', 'Step 1 — Locate the added factor
Text 2 concedes the drought but stresses interdependence, explaining that {{yellow:a regional dry spell became a systemic collapse no single kingdom could survive}}.
Step 2 — Why B follows
Because Text 2 says strain alone rarely topples a kingdom and points to the trade network, its author would respond that drought was real but insufficient without interdependence.
Distractor analysis:
- A: Text 2 accepts the drought rather than denying it.
- C: Text 2 names trade links, not invading armies, as the key factor.
- D: This reverses Text 2, which says trade spread, not blocked, the shock.', 'Text 2 doesn''t reject the drought; it adds a structural reason the collapse spread so far.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('523da5bf-a117-4a76-bd0a-85b89b0489a8', 'Based on the texts, how would the author of Text 2 most likely respond to the proposal in Text 1 that cities offer tax incentives to bring workers back to offices five days a week?', 'Text 1
The surge in remote work has hollowed out city centers. With offices half-empty, the restaurants, transit systems, and shops that depended on commuters have suffered. To revive downtowns, cities should offer tax incentives that pull workers back into corporate buildings five days a week, restoring the foot traffic that urban economies were built upon.

Text 2
Clinging to the old commuter model misreads the moment. Cities need not refill office towers; they can convert them. Underused buildings can become apartments, drawing residents who shop and dine downtown every day, not just on workdays. A neighborhood of residents sustains local business more reliably than a tide of commuters who vanish each evening.', NULL, '[{"id":"A","text":"It is the most direct way to restore the foot traffic downtown businesses lost.","is_correct":false,"explanation":"This restates Text 1''s view, which Text 2 rejects as misreading the moment."},{"id":"B","text":"It pursues an outdated model when converting offices into housing would support businesses more steadily.","is_correct":true,"explanation":"Correct: Text 2 calls the commuter model a misread and argues residents sustain business more reliably."},{"id":"C","text":"It would succeed only if paired with improvements to city transit systems.","is_correct":false,"explanation":"Text 2 never conditions the plan on transit; this adds an unsupported requirement."},{"id":"D","text":"It correctly identifies commuters as the most dependable source of downtown spending.","is_correct":false,"explanation":"Text 2 says the opposite: commuters vanish each evening while residents are more reliable."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s alternative
Text 2 argues cities {{yellow:need not refill office towers; they can convert them}} into housing for residents.
Step 2 — Apply to Text 1''s claim
Because Text 2 says {{yellow:A neighborhood of residents sustains local business more reliably than a tide of commuters}}, it would treat the office-incentive plan as an outdated fix inferior to conversion.
Distractor analysis:
- A: Restates Text 1''s reasoning, which Text 2 explicitly rejects.
- C: Adds a transit condition Text 2 never mentions.
- D: Reverses Text 2, which calls commuters less reliable than residents.', 'Text 2 offers a different use for the buildings rather than refilling them.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('42f94d44-6e71-4eac-b659-544f03a3cb1e', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that warming climate, not human hunting, drove the mammoth''s extinction?', 'Text 1
The extinction of the woolly mammoth was driven chiefly by climate. As the last Ice Age ended, warming temperatures shrank the cold grasslands the mammoths grazed. Pollen records show these steppe habitats giving way to forests and wetlands the animals could not exploit. The herds dwindled as their food source disappeared, long before human hunting could have mattered.

Text 2
Climate alone cannot explain the timing. Mammoths had survived earlier warm intervals without vanishing. What differed at the close of the last Ice Age was the spread of skilled human hunters into mammoth territory. On isolated islands free of people, small mammoth populations endured for thousands of years after mainland herds were gone.', NULL, '[{"id":"A","text":"Climate change had no measurable effect on mammoth populations at any point.","is_correct":false,"explanation":"Text 2 grants that warm intervals occurred; it disputes climate as sufficient, not as irrelevant."},{"id":"B","text":"Pollen records are too unreliable to establish past habitat changes.","is_correct":false,"explanation":"Text 2 never challenges the pollen evidence; it challenges the inference drawn from climate alone."},{"id":"C","text":"Climate cannot be the whole story, since mammoths survived earlier warming but not the arrival of human hunters.","is_correct":true,"explanation":"Correct: Text 2 cites prior survival of warm intervals and island persistence to implicate humans."},{"id":"D","text":"Mammoths could have adapted to forests and wetlands given more time.","is_correct":false,"explanation":"Text 2 makes no claim about adaptation to new habitats; it points to human presence."}]'::jsonb, 'C', 'Step 1 — Identify Text 2''s evidence
Text 2 notes that {{yellow:Mammoths had survived earlier warm intervals without vanishing}}.
Step 2 — Apply to Text 1''s claim
Since herds persisted {{yellow:On isolated islands free of people}} long after mainland ones vanished, Text 2 would say climate alone is insufficient and humans were decisive.
Distractor analysis:
- A: Overstates Text 2, which accepts that warming occurred.
- B: Text 2 does not attack the pollen data.
- D: No claim about adaptation appears in Text 2.', 'Text 2 uses earlier warm periods and island survivors as counterexamples.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6d49bc4c-039e-4770-b801-309711943252', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that collaborative fiction inevitably dilutes a work''s distinctive voice?', 'Text 1
Great novels demand a single, controlling author whose unified vision shapes every page. Collaborative fiction, written by committee, inevitably dilutes that vision; competing instincts blur the voice until nothing distinctive remains. The masterpieces we revere bear the unmistakable stamp of one mind, which is precisely why we return to them.

Text 2
The lone genius is largely a myth of publishing. Editors reshape structure, suggest cuts, and rewrite passages; spouses and friends supply plots and corrections. What we call a single author''s voice is usually the residue of many hands, expertly hidden. Collaboration does not dilute great fiction—it has quietly produced much of it.', NULL, '[{"id":"A","text":"Distinctive voice matters less to readers than a novel''s plot and structure.","is_correct":false,"explanation":"Text 2 does not rank voice against plot; it argues voice is itself collaborative."},{"id":"B","text":"Truly collaborative novels are too rare to evaluate fairly.","is_correct":false,"explanation":"Text 2 claims collaboration is common and hidden, the opposite of rare."},{"id":"C","text":"Only living authors benefit from editorial collaboration.","is_correct":false,"explanation":"No such restriction appears; this is invented detail."},{"id":"D","text":"Celebrated novels are already collaborative, so collaboration has produced great fiction rather than diluting it.","is_correct":true,"explanation":"Correct: Text 2 says the single voice is the hidden residue of many hands."}]'::jsonb, 'D', 'Step 1 — Find Text 2''s central claim
Text 2 states that {{yellow:What we call a single author''s voice is usually the residue of many hands, expertly hidden}}.
Step 2 — Apply to Text 1''s claim
Because Text 2 concludes {{yellow:Collaboration does not dilute great fiction—it has quietly produced much of it}}, it would reject the inevitability of dilution.
Distractor analysis:
- A: Text 2 does not compare voice to plot in importance.
- B: Text 2 says collaboration is common, not rare.
- C: No limit to living authors is stated.', 'Text 2 says the ''single voice'' was already made by many people.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('43dba03d-73f6-40d9-afe0-8303bafcfdea', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that a universal basic income would erode the incentive to work?', 'Text 1
A universal basic income would erode the incentive to work. If every adult receives a guaranteed monthly sum regardless of effort, many will choose leisure over labor. Productivity will fall, employers will struggle to fill jobs, and the economy that funds the payments will weaken. Guaranteeing income detaches reward from contribution.

Text 2
Field trials tell a quieter story. In communities given guaranteed payments, most recipients kept working; the few who reduced their hours were mainly new mothers and students extending their education. Far from breeding idleness, a stable income floor let people pursue training and better-matched jobs rather than clinging to the first available paycheck.', NULL, '[{"id":"A","text":"The claim is supported, because guaranteed payments detach reward from contribution.","is_correct":false,"explanation":"This endorses Text 1; Text 2 contradicts it with trial data."},{"id":"B","text":"The claim is overstated, since trials show most recipients kept working and the few exceptions had constructive reasons.","is_correct":true,"explanation":"Correct: Text 2 cites continued work and reductions tied to study or new motherhood."},{"id":"C","text":"The claim is correct for students but wrong for everyone else.","is_correct":false,"explanation":"Text 2 treats students'' reduced hours as constructive, not as confirming erosion."},{"id":"D","text":"The claim cannot be tested because no real programs exist.","is_correct":false,"explanation":"Text 2 explicitly draws on field trials, so programs do exist."}]'::jsonb, 'B', 'Step 1 — Identify Text 2''s evidence
Text 2 reports that {{yellow:most recipients kept working}} in communities given guaranteed payments.
Step 2 — Apply to Text 1''s claim
Since a stable floor let people {{yellow:pursue training and better-matched jobs}}, Text 2 would call the erosion claim overstated.
Distractor analysis:
- A: Endorses Text 1, which Text 2 rebuts.
- C: Misreads students'' choice as confirming Text 1.
- D: Text 2 relies on real field trials.', 'Text 2 reports what actually happened in real programs.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('76842ba2-e149-4f13-b9c5-bc06a3e1847e', 'Based on the texts, how would the author of Text 2 most likely respond to the recommendation in Text 1 that governments close ocean zones to all human activity?', 'Text 1
To protect coral reefs, governments should close vast ocean zones to all human activity. Fishing, tourism, and shipping each stress fragile coral; only by sealing off these waters entirely can reefs recover. Half-measures that permit limited use leave reefs exposed to the very pressures driving their decline.

Text 2
Total closures often fail in practice. Coastal communities that depend on reef fishing simply ignore unenforceable bans, and reefs suffer anyway. Programs that grant fishers a managed stake—seasonal limits, protected nurseries, shared monitoring—win cooperation and have restored reefs more durably than sweeping prohibitions that no one on the water accepts.', NULL, '[{"id":"A","text":"It is the only approach that adequately shields fragile coral from human stress.","is_correct":false,"explanation":"This restates Text 1; Text 2 argues such closures often fail."},{"id":"B","text":"It is unnecessary because reef decline has been exaggerated.","is_correct":false,"explanation":"Text 2 does not deny reef decline; it disputes the method of protection."},{"id":"C","text":"It tends to fail because communities ignore unenforceable bans, whereas managed access wins cooperation.","is_correct":true,"explanation":"Correct: Text 2 contrasts ignored bans with durable managed-stake programs."},{"id":"D","text":"It should be expanded to cover shipping lanes as well as fishing grounds.","is_correct":false,"explanation":"Text 2 favors managed access, not broader prohibition."}]'::jsonb, 'C', 'Step 1 — Find Text 2''s objection
Text 2 observes that communities {{yellow:simply ignore unenforceable bans, and reefs suffer anyway}}.
Step 2 — Apply to Text 1''s claim
Since managed-stake programs {{yellow:win cooperation and have restored reefs more durably}}, Text 2 would reject total closures as counterproductive.
Distractor analysis:
- A: Restates Text 1''s position.
- B: Text 2 never denies that reefs are declining.
- D: Text 2 opposes broader bans, not advocates them.', 'Text 2 points to bans being ignored and a cooperative alternative.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('42e1ed6d-de77-4df3-ae55-4fa676bbf734', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that aggressive mandatory sorting steadily shrinks a city''s environmental footprint?', 'Text 1
Mandatory recycling programs are the cornerstone of responsible waste policy. By requiring households to sort glass, paper, and plastic, cities divert enormous volumes from landfills and recover valuable materials. The more aggressively a city mandates sorting, the smaller its environmental footprint becomes.

Text 2
Sorting at the curb addresses the end of the pipeline, not the source. Much of what households dutifully separate—mixed plastics especially—has no buyer and is quietly landfilled or burned anyway. Real gains come earlier: designing products with less packaging and materials that can actually be reused, so less waste is created in the first place.', NULL, '[{"id":"A","text":"Sorting is harmful and should be banned outright.","is_correct":false,"explanation":"Text 2 finds sorting limited, not harmful or worthy of a ban."},{"id":"B","text":"Sorting works well only for glass and paper.","is_correct":false,"explanation":"Text 2 singles out mixed plastics as problematic but does not endorse sorting for glass and paper as the answer."},{"id":"C","text":"Sorting tackles only the pipeline''s end, so reducing waste at the design stage matters more.","is_correct":true,"explanation":"Correct: Text 2 says real gains come from less packaging and reusable materials."},{"id":"D","text":"Sorting succeeds wherever recycling markets are strong.","is_correct":false,"explanation":"Text 2 emphasizes prevention, not improving markets, as the real gain."}]'::jsonb, 'C', 'Step 1 — Identify Text 2''s reframing
Text 2 argues sorting {{yellow:addresses the end of the pipeline, not the source}}.
Step 2 — Apply to Text 1''s claim
Because {{yellow:Real gains come earlier}}—through less packaging and reusable materials—Text 2 would say mandates miss the larger lever.
Distractor analysis:
- A: Text 2 does not call sorting harmful.
- B: Text 2 does not promote glass-and-paper sorting as the solution.
- D: Text 2 stresses prevention, not stronger markets.', 'Text 2 looks before the curb, at how products are made.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('29035c50-3a4a-4e80-b54c-02d171b79af6', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the printing press caused the Reformation?', 'Text 1
The printing press caused the Protestant Reformation. By making Bibles and pamphlets cheap and abundant, the press let reformers'' ideas spread faster than any authority could suppress them. Without movable type, Luther''s arguments would have stayed local. The technology, more than any preacher, lit the fire that split the Church.

Text 2
Presses had been turning for decades before Luther, printing mostly traditional and devotional works that troubled no one. What changed was not the machine but the appetite for reform already simmering in a discontented public. The press amplified a demand that existed; it did not manufacture it. Tools spread movements that people are first willing to embrace.', NULL, '[{"id":"A","text":"The press played no role whatsoever in spreading reformers'' ideas.","is_correct":false,"explanation":"Text 2 grants the press amplified demand, so it had a role."},{"id":"B","text":"The press merely amplified a preexisting public appetite rather than creating the movement.","is_correct":true,"explanation":"Correct: Text 2 says the press spread a demand that already existed."},{"id":"C","text":"Luther''s arguments would have spread just as fast without any printing.","is_correct":false,"explanation":"Text 2 does not claim equal spread without print; it stresses preexisting demand."},{"id":"D","text":"Earlier printed works prove the press always provoked religious conflict.","is_correct":false,"explanation":"Text 2 notes earlier works troubled no one, the opposite of provoking conflict."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s qualification
Text 2 observes presses earlier printed works that {{yellow:troubled no one}}.
Step 2 — Apply to Text 1''s claim
Since {{yellow:The press amplified a demand that existed; it did not manufacture it}}, Text 2 would treat the press as enabler, not cause.
Distractor analysis:
- A: Text 2 credits the press with amplification.
- C: Text 2 does not claim equal spread absent print.
- D: Earlier works are cited as untroubling, not provoking.', 'Text 2 distinguishes amplifying a demand from creating one.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8ea516ff-8636-42eb-9b23-d13d610cb534', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that a single common exam treats every applicant on equal terms?', 'Text 1
Standardized tests are the fairest way to admit students to selective colleges. A single exam applies identical standards to every applicant, immune to the grade inflation and uneven rigor that distort high school transcripts. Numbers on a common scale let admissions officers compare candidates from vastly different schools on equal terms.

Text 2
A common scale is not the same as a fair one. Scores track family income closely: wealthier students afford tutoring and repeated attempts, while others sit the exam once, unprepared. The test measures the same thing everywhere, but what it measures is partly the resources behind each student, not the student''s promise.', NULL, '[{"id":"A","text":"Equal terms are achieved, since the same exam removes the distortion of grade inflation.","is_correct":false,"explanation":"This restates Text 1; Text 2 argues the common scale is not fair."},{"id":"B","text":"The exam is fair only for applicants from the same high school.","is_correct":false,"explanation":"Text 2 ties unfairness to income, not to shared schools."},{"id":"C","text":"A uniform exam can still be unfair because scores reflect family resources, not just promise.","is_correct":true,"explanation":"Correct: Text 2 says what the test measures is partly the resources behind a student."},{"id":"D","text":"Transcripts are a more reliable measure than any exam in every case.","is_correct":false,"explanation":"Text 2 never defends transcripts as universally superior."}]'::jsonb, 'C', 'Step 1 — Find Text 2''s distinction
Text 2 insists that {{yellow:A common scale is not the same as a fair one}}.
Step 2 — Apply to Text 1''s claim
Because scores reflect {{yellow:partly the resources behind each student, not the student''s promise}}, Text 2 would deny the exam delivers equal terms.
Distractor analysis:
- A: Restates Text 1''s view.
- B: Text 2 ties unfairness to income, not same school.
- D: Text 2 does not champion transcripts.', 'Text 2 separates ''same scale'' from ''fair scale.''', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ecd1d62c-4e7f-4ad8-9158-d986d0c11e7e', 'Based on the texts, how would the author of Text 2 most likely respond to the recommendation in Text 1 that ecologists gauge forest health by focusing on the trees?', 'Text 1
Nearly all of a forest''s nutrients flow through its trees. The towering canopy captures sunlight, builds biomass, and drops the leaf litter that feeds the soil. To gauge a forest''s health, ecologists should focus on the trees, since they are the engine on which every other organism ultimately depends.

Text 2
Look beneath the soil. A vast web of fungi threads between roots, ferrying water and nutrients from tree to tree and deciding which seedlings thrive. Trees that appear self-sufficient are sustained by this hidden network. A forest''s health is written less in its canopy than in the fungal connections that knit the whole community together.', NULL, '[{"id":"A","text":"Trees are irrelevant to a forest''s overall health.","is_correct":false,"explanation":"Text 2 says trees are sustained by fungi, not that trees are irrelevant."},{"id":"B","text":"Focusing on trees overlooks the underground fungal network that actually sustains them.","is_correct":true,"explanation":"Correct: Text 2 says trees are sustained by a hidden fungal network."},{"id":"C","text":"Leaf litter is the single best indicator of forest health.","is_correct":false,"explanation":"Leaf litter is part of Text 1''s view; Text 2 points to fungi instead."},{"id":"D","text":"Sunlight capture by the canopy should be measured more precisely.","is_correct":false,"explanation":"Text 2 redirects attention below the soil, not to better canopy measurement."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s redirection
Text 2 reveals that {{yellow:Trees that appear self-sufficient are sustained by this hidden network}}.
Step 2 — Apply to Text 1''s claim
Since forest health is {{yellow:written less in its canopy than in the fungal connections}}, Text 2 would say a tree-only focus misses the true engine.
Distractor analysis:
- A: Text 2 does not call trees irrelevant.
- C: Leaf litter belongs to Text 1''s framing.
- D: Text 2 looks underground, not at the canopy.', 'Text 2 directs attention to what lies beneath the soil.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('eed74dae-2457-452c-a899-41bf24dd8761', 'Based on the texts, how would the author of Text 2 most likely respond to the proposal in Text 1 that foundations and donors fund nonprofit newsrooms?', 'Text 1
The decline of local newspapers harms democracy, and the remedy is clear: foundations and donors should fund nonprofit newsrooms to replace the failing commercial press. Freed from the pressure to chase profits, philanthropy-backed journalists can cover city councils and school boards that advertisers no longer support.

Text 2
Donor money carries its own pressures. Foundations have priorities and favored causes; a newsroom dependent on a handful of benefactors may quietly avoid stories that displease them. Broad public funding, drawn from many small contributors, spreads that influence thin and frees reporters from courting any single patron''s approval.', NULL, '[{"id":"A","text":"It removes all financial pressure from journalism.","is_correct":false,"explanation":"Text 2 argues donor money carries its own pressures, contradicting this."},{"id":"B","text":"It is unworkable because nonprofit newsrooms cannot cover local government.","is_correct":false,"explanation":"Text 2 does not question their capacity to report; it questions donor influence."},{"id":"C","text":"It risks trading advertiser pressure for donor pressure, so broad public funding is preferable.","is_correct":true,"explanation":"Correct: Text 2 warns of donor priorities and favors many small contributors."},{"id":"D","text":"It works only when foundations stay anonymous.","is_correct":false,"explanation":"Text 2 proposes broad funding, not donor anonymity, as the fix."}]'::jsonb, 'C', 'Step 1 — Find Text 2''s concern
Text 2 warns that a newsroom dependent on few benefactors {{yellow:may quietly avoid stories that displease them}}.
Step 2 — Apply to Text 1''s claim
Because {{yellow:Broad public funding, drawn from many small contributors, spreads that influence thin}}, Text 2 would call donor funding a trade of one pressure for another.
Distractor analysis:
- A: Text 2 says donor money carries pressure.
- B: Text 2 does not doubt their reporting ability.
- D: Text 2 favors broad funding, not anonymity.', 'Text 2 finds a new pressure replacing the old one.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('709c5ce7-271b-4737-8a5a-cd98ca62374c', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that drought alone compelled the Anasazi to abandon their dwellings?', 'Text 1
The Anasazi abandoned their cliff dwellings because of a prolonged drought. Tree-ring records reveal decades of failed rains in the late thirteenth century, exactly when the great settlements emptied. With crops withering and reservoirs dry, the people had little choice but to leave a homeland that could no longer feed them.

Text 2
Drought may have pushed, but it did not push everywhere alike. Some communities in equally parched zones stayed put, while others fled regions where water still flowed. Where people went and when often tracks signs of conflict and the pull of new religious centers, suggesting that social forces shaped the migration as much as the climate.', NULL, '[{"id":"A","text":"The tree-ring records have been misdated and show no real drought.","is_correct":false,"explanation":"Text 2 accepts that drought occurred; it disputes drought as the sole cause."},{"id":"B","text":"Drought was only a partial cause, since social forces like conflict and religious draws also shaped who left and when.","is_correct":true,"explanation":"Correct: Text 2 cites uneven departures and signs of conflict and new religious centers."},{"id":"C","text":"No community could survive a drought of that severity.","is_correct":false,"explanation":"Text 2 notes some communities in parched zones stayed, contradicting this."},{"id":"D","text":"The migrations had no connection to climate at all.","is_correct":false,"explanation":"Text 2 says drought may have pushed; it does not deny climate''s role."}]'::jsonb, 'B', 'Step 1 — Find Text 2''s counterpattern
Text 2 notes that {{yellow:Some communities in equally parched zones stayed put, while others fled regions where water still flowed}}.
Step 2 — Apply to Text 1''s claim
Because movement {{yellow:tracks signs of conflict and the pull of new religious centers}}, Text 2 would call social forces as influential as climate.
Distractor analysis:
- A: Text 2 accepts the drought evidence.
- C: Text 2 says some stayed despite drought.
- D: Text 2 still grants climate a pushing role.', 'Text 2 notes the drought affected different communities differently.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4cd64853-2822-456d-a0bc-43c3d179b0be', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that funds are best spent securing significant pieces, with everything else secondary?', 'Text 1
A museum''s first duty is to acquire and display masterpieces. The public comes to stand before great works, and a collection''s prestige rests on the importance of what hangs on its walls. Funds are best spent securing significant pieces; everything else is secondary to the encounter between viewer and art.

Text 2
A painting locked behind glass that no one understands teaches little. The labels, lighting, tours, and programs that frame a work decide whether a visitor leaves moved or merely puzzled. A modest piece well interpreted can stir more than a masterpiece left to speak for itself. Acquisition without interpretation is a half-finished gift.', NULL, '[{"id":"A","text":"Acquisitions should stop entirely so all money goes to programs.","is_correct":false,"explanation":"Text 2 calls acquisition a ''half-finished gift,'' not something to halt."},{"id":"B","text":"Only masterpieces are worth interpreting for the public.","is_correct":false,"explanation":"Text 2 says a modest piece well interpreted can stir more, contradicting this."},{"id":"C","text":"Interpretation is what determines a work''s impact, so it cannot be secondary to acquisition.","is_correct":true,"explanation":"Correct: Text 2 says framing decides whether a visitor leaves moved or puzzled."},{"id":"D","text":"Prestige is the only legitimate goal a museum should pursue.","is_correct":false,"explanation":"Text 2 emphasizes visitor understanding, not prestige."}]'::jsonb, 'C', 'Step 1 — Find Text 2''s priority
Text 2 argues the framing of a work {{yellow:decide whether a visitor leaves moved or merely puzzled}}.
Step 2 — Apply to Text 1''s claim
Because {{yellow:Acquisition without interpretation is a half-finished gift}}, Text 2 would deny that interpretation is secondary.
Distractor analysis:
- A: Text 2 does not call for ending acquisitions.
- B: Text 2 values interpreting modest works too.
- D: Text 2 stresses understanding over prestige.', 'Text 2 argues what surrounds the art is not optional.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b33e3500-c9c4-40c1-8a1f-e8566f53989a', 'Based on the texts, how would the author of Text 2 most likely respond to the assumption, described in Text 1, that Crale''s letters are "transparent windows onto Crale''s true feelings"?', 'Text 1
For decades, biographers of the poet Hester Crale relied on her published letters to reconstruct her inner life. Because those letters are vivid and self-aware, scholars have treated them as transparent windows onto Crale''s true feelings, confidently asserting what she privately believed about her rivals and her art.

Text 2
Crale composed her letters knowing they would circulate among literary acquaintances and, very likely, survive her. A writer so attuned to audience does not confide; she performs. The letters tell us precisely what Crale wished posterity to think she felt—a curated self, not a candid one—and should be read as artifacts of self-fashioning rather than as evidence of private conviction.', NULL, '[{"id":"A","text":"It is plausible, because writers who are vivid and self-aware tend to be more honest than guarded ones.","is_correct":false,"explanation":"Reverses the logic of Text 2, which treats self-awareness as a reason for suspicion, not trust."},{"id":"B","text":"It mistakes a self-conscious performance for spontaneous disclosure, since Crale wrote with an audience and posterity in mind.","is_correct":true,"explanation":"Correct: Text 2 argues the audience-awareness makes the letters curated performance, not candid evidence."},{"id":"C","text":"It is unverifiable, because none of Crale''s private thoughts about her rivals were ever recorded anywhere.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 never claims her thoughts went entirely unrecorded, only that the letters are curated."},{"id":"D","text":"It is largely correct, provided biographers also consult Crale''s drafts alongside the published letters.","is_correct":false,"explanation":"Text 2 rejects the assumption outright and proposes no draft-based remedy."}]'::jsonb, 'B', 'Step 1 — Locate the divergence
Text 2 insists that a writer aware of an audience does not confide but {{yellow:performs}}, calling the letters a "curated self, not a candid one."
Step 2 — Apply it to the claim
Because Text 2 reads the very self-awareness Text 1 trusts as evidence of staging, it would say Text 1 mistakes performance for genuine disclosure.
Distractor analysis:
- A: Reverses Text 2''s logic, which treats self-awareness as grounds for doubt, not honesty.
- C: No-evidence synthesis; Text 2 never says her private thoughts were unrecorded.
- D: Text 2 rejects the windows view entirely and offers no draft-consultation compromise.', 'Text 2 treats Crale''s awareness of her audience as a reason to distrust, not trust, the letters.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2e9d5177-1f59-4692-9fdb-46c99fd16303', 'Based on the texts, how would the author of Text 2 most likely respond to the conclusion in Text 1 that reintroducing beavers "reliably regenerates degraded river systems"?', 'Text 1
Ecologists studying the recovery of the Marn River have credited the return of beavers with restoring wetland diversity. After beavers recolonized, dam-building slowed the current, ponds formed, and dozens of species reappeared within a decade. The straightforward conclusion is that reintroducing beavers reliably regenerates degraded river systems.

Text 2
The Marn''s recovery coincided with the beavers'' return, but it also followed three unusually wet years and the closure of an upstream tannery that had leached toxins for generations. Until we can disentangle these simultaneous changes, attributing the rebound to beavers alone risks confusing a vivid agent with a sufficient cause.', NULL, '[{"id":"A","text":"It is sound, since the wetland species reappeared within a single decade of the beavers'' return.","is_correct":false,"explanation":"Speed of recovery is not the issue Text 2 raises; it questions causal attribution."},{"id":"B","text":"It overstates a causal role, because other concurrent changes could equally explain the river''s rebound.","is_correct":true,"explanation":"Correct: Text 2 cites wet years and the tannery closure as confounds undermining a beaver-only cause."},{"id":"C","text":"It is false, because beavers actually slowed rather than aided the wetland''s recovery.","is_correct":false,"explanation":"Reverse/contradiction; Text 2 never claims beavers harmed recovery."},{"id":"D","text":"It is correct for the Marn but cannot be generalized to rivers without tanneries upstream.","is_correct":false,"explanation":"Text 2 questions causation even for the Marn, not merely the generalization."}]'::jsonb, 'B', 'Step 1 — Identify the methodological worry
Text 2 warns against {{yellow:confusing a vivid agent with a sufficient cause}}, noting wet years and a tannery closure occurred simultaneously.
Step 2 — Apply it to the claim
Since co-occurring factors could explain the rebound, Text 2 would say Text 1 wrongly credits beavers alone with a reliable causal power.
Distractor analysis:
- A: Recovery speed is irrelevant to Text 2''s causal critique.
- C: Reverse; Text 2 never says beavers slowed recovery.
- D: Text 2 doubts causation even within the Marn, not just its generality.', 'Text 2 lists events that happened at the same time as the beavers'' return.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b87c6922-5b87-4e2c-bf80-412b2d539e5b', 'Based on the texts, how would the author of Text 2 most likely respond to the standard, stated in Text 1, that "lasting institutions...are the proper measure of a reformer''s achievement"?', 'Text 1
Historians have long judged the reformer Aldous Penn a failure because the labor council he founded dissolved within two years of its creation. Lasting institutions, the reasoning goes, are the proper measure of a reformer''s achievement, and by that standard Penn accomplished nothing of consequence.

Text 2
Penn''s council collapsed, true. Yet the demands it first articulated—shorter shifts, accident insurance, a grievance board—were enacted piecemeal over the following generation by bodies that never credited him. To measure reform only by the survival of the founder''s own organization is to miss the slow migration of ideas into institutions he never controlled.', NULL, '[{"id":"A","text":"It is too narrow, because a reformer''s ideas may succeed through later institutions he did not found or control.","is_correct":true,"explanation":"Correct: Text 2 traces Penn''s demands into later bodies, showing influence beyond his own organization."},{"id":"B","text":"It is correct, since Penn''s council did in fact survive long enough to enact his demands.","is_correct":false,"explanation":"Contradicts the text; both passages agree the council collapsed."},{"id":"C","text":"It is acceptable only for reformers who, unlike Penn, sought permanent institutions.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 never distinguishes reformers by their intentions about permanence."},{"id":"D","text":"It is sound, but it should also weigh how many members the council attracted at its peak.","is_correct":false,"explanation":"Membership size is never mentioned and is not Text 2''s criterion."}]'::jsonb, 'A', 'Step 1 — Find the competing measure
Text 2 objects to measuring reform only by {{yellow:the survival of the founder''s own organization}}, pointing to demands enacted later by other bodies.
Step 2 — Apply it to the standard
Because Penn''s ideas migrated into institutions he never controlled, Text 2 would call Text 1''s survival standard too narrow.
Distractor analysis:
- B: Both texts agree the council collapsed, so this contradicts the passages.
- C: Text 2 never sorts reformers by their intentions about permanence.
- D: Membership size is irrelevant to Text 2''s argument.', 'Text 2 follows Penn''s demands after his council was gone.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c53c4fd3-4201-4b2c-96bf-d2ba1e1bee3e', 'Based on the texts, how would the author of Text 2 most likely respond to the team''s conclusion in Text 1 that "the app itself produced the gains"?', 'Text 1
Researchers testing a new tutoring app reported that students who used it scored higher on year-end exams than those who did not. Because the gap was large and statistically significant, the team concluded that the app itself produced the gains and recommended districts adopt it widely.

Text 2
Students were not assigned to use the app; they chose to. The most motivated learners, already likely to score well, are precisely those who seek out extra tools. A significant difference between self-selected groups tells us who used the app, not what the app did. Only random assignment could license the team''s causal claim.', NULL, '[{"id":"A","text":"It is justified, because the score gap between users and nonusers was statistically significant.","is_correct":false,"explanation":"Text 2 explicitly says significance among self-selected groups cannot license the causal claim."},{"id":"B","text":"It is unwarranted, because students chose whether to use the app, so preexisting differences may explain the gap.","is_correct":true,"explanation":"Correct: Text 2 cites self-selection by motivated students as the flaw and demands random assignment."},{"id":"C","text":"It is unwarranted, because the app likely lowered scores for unmotivated students.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 never claims the app lowered anyone''s scores."},{"id":"D","text":"It is correct, but only if the districts adopting the app also offer it to motivated students.","is_correct":false,"explanation":"Reverses Text 2''s point; motivation is the confound, not a deployment tip."}]'::jsonb, 'B', 'Step 1 — Name the design flaw
Text 2 stresses that {{yellow:a significant difference between self-selected groups tells us who used the app, not what the app did}}.
Step 2 — Apply it to the claim
Because motivated students self-selected into using the app, Text 2 would say preexisting differences, not the app, may explain the gap.
Distractor analysis:
- A: Text 2 denies that significance among self-selected groups proves causation.
- C: Text 2 never asserts the app lowered scores.
- D: Reverses the argument; motivation is the confound, not an adoption tip.', 'Text 2 emphasizes that students chose the app rather than being assigned to it.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0713fc71-66df-43ea-8d04-f4e002842b4b', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the imported pottery is "proof of a thriving long-distance trade network"?', 'Text 1
Archaeologists excavating the coastal village of Tre interpreted its imported pottery as proof of a thriving long-distance trade network. The presence of foreign wares in domestic refuse, they argued, demonstrates that Tre''s inhabitants regularly exchanged goods with distant partners across the sea.

Text 2
Foreign objects can travel without commerce. The Tre wares cluster in a single ceremonial deposit, not in everyday refuse, and bear no signs of the wear that daily use leaves. Gifts exchanged among elites, dowries, or plunder could produce the same pattern. Imported things prove contact of some kind, not trade in particular.', NULL, '[{"id":"A","text":"It is convincing, because foreign wares appear throughout Tre''s domestic refuse.","is_correct":false,"explanation":"Contradicts Text 2, which says the wares cluster in a ceremonial deposit, not domestic refuse."},{"id":"B","text":"It overreaches, because the same objects could have arrived through non-commercial means such as gifts or plunder.","is_correct":true,"explanation":"Correct: Text 2 offers gifts, dowries, and plunder as alternatives to trade."},{"id":"C","text":"It is mistaken, because the pottery was actually manufactured locally rather than imported.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 accepts the wares are foreign."},{"id":"D","text":"It is correct, since contact of some kind clearly occurred between Tre and distant peoples.","is_correct":false,"explanation":"Too broad; Text 2 concedes contact but denies that contact establishes trade specifically."}]'::jsonb, 'B', 'Step 1 — Separate contact from trade
Text 2 concludes that imported things {{yellow:prove contact of some kind, not trade in particular}}, listing gifts, dowries, and plunder.
Step 2 — Apply it to the claim
Since non-commercial channels could explain foreign wares, Text 2 would say Text 1 overreaches by inferring trade specifically.
Distractor analysis:
- A: Text 2 says the wares were in a ceremonial deposit, not domestic refuse.
- C: Text 2 grants that the wares are foreign, not locally made.
- D: Too broad; Text 2 accepts contact but rejects the leap to trade.', 'Text 2 distinguishes mere contact from commerce specifically.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d1b81f93-c315-457e-ac70-c02ec9d5267b', 'Based on the texts, how would the author of Text 2 most likely respond to the critics'' reading, in Text 1, of Mira''s silence as "the author''s verdict that Mira has at last achieved freedom"?', 'Text 1
In her novel''s celebrated final chapter, the protagonist Mira walks away from the city without a word of farewell. Critics read this silence as the author''s verdict that Mira has at last achieved freedom, shedding the relationships that constrained her throughout the book.

Text 2
Nothing in the prose endorses Mira''s departure. The narrator, elsewhere so quick to judge, falls conspicuously quiet here, withholding the moral coloring readers expect. That refusal is not approval; it is an invitation to weigh Mira''s exit ourselves. To call the silence a verdict is to supply a judgment the text deliberately declines to make.', NULL, '[{"id":"A","text":"It is persuasive, because the narrator consistently approves of characters who shed constraining relationships.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 says the narrator withholds approval here, not that it endorses such characters."},{"id":"B","text":"It imposes a judgment the text withholds, mistaking the narrator''s deliberate silence for endorsement.","is_correct":true,"explanation":"Correct: Text 2 says the silence declines to judge and is an invitation, not a verdict."},{"id":"C","text":"It is accurate, since the narrator''s silence is the strongest possible form of approval.","is_correct":false,"explanation":"Reverse; Text 2 explicitly denies the silence signals approval."},{"id":"D","text":"It is incomplete, because it ignores the farewells Mira offers earlier in the chapter.","is_correct":false,"explanation":"Contradicts Text 1, which says Mira leaves without a word of farewell."}]'::jsonb, 'B', 'Step 1 — Read the silence differently
Text 2 argues the narrator''s quiet is {{yellow:an invitation to weigh Mira''s exit ourselves}}, not a moral pronouncement.
Step 2 — Apply it to the reading
Because the text declines to judge, Text 2 would say the critics supply a verdict the prose deliberately avoids.
Distractor analysis:
- A: Text 2 says the narrator withholds judgment here, not that it favors such characters.
- C: Reverse; Text 2 denies the silence means approval.
- D: Text 1 states Mira leaves without any farewell.', 'Text 2 reads the narrator''s silence as a refusal to judge.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7bce7cf5-9e48-4c57-9301-fd52e77d113e', 'Based on the texts, how would the author of Text 2 most likely respond to the nutritionists'' conclusion in Text 1 that chocolate "helps preserve cognitive function"?', 'Text 1
A survey found that adults who eat dark chocolate weekly report better memory than those who never do. Given dark chocolate''s known flavanols, which improve blood flow, nutritionists concluded that regular chocolate consumption helps preserve cognitive function as people age.

Text 2
The survey measured memory by self-report. People who believe chocolate is healthful—and chocolate eaters surely do—may rate their own memory more generously, regardless of actual performance. Without an objective test administered blind, the study captures a difference in self-assessment, which a known belief about chocolate could itself create.', NULL, '[{"id":"A","text":"It is well founded, because flavanols are known to improve blood flow.","is_correct":false,"explanation":"Text 2 sidesteps flavanols and challenges the memory measurement itself."},{"id":"B","text":"It is premature, because the self-reported memory difference may reflect eaters'' beliefs rather than real cognition.","is_correct":true,"explanation":"Correct: Text 2 argues belief in chocolate''s benefits could inflate self-rated memory."},{"id":"C","text":"It is wrong, because flavanols have been shown to impair memory in some adults.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 makes no claim about flavanols harming memory."},{"id":"D","text":"It is correct, as long as chocolate eaters are also given an objective memory test.","is_correct":false,"explanation":"Reverses Text 2; the absence of an objective blind test is the very flaw, not a fix that validates the conclusion."}]'::jsonb, 'B', 'Step 1 — Target the measurement
Text 2 notes the study {{yellow:captures a difference in self-assessment}} that a belief about chocolate could itself create.
Step 2 — Apply it to the conclusion
Since self-reported memory may track belief rather than cognition, Text 2 would call the cognitive-preservation conclusion premature.
Distractor analysis:
- A: Text 2 doesn''t dispute flavanols; it disputes the memory measure.
- C: Text 2 never claims flavanols impair memory.
- D: The missing blind test is the flaw, not a condition that rescues the claim.', 'Text 2 focuses on how memory was measured in the survey.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a51ca0d8-f5d7-4875-b792-cc4543d60119', 'Based on the texts, how would the author of Text 2 most likely respond to the recommendation in Text 1 that "other towns...lobby for similar bypasses"?', 'Text 1
Economists examining the town of Veldt noted that after a new highway opened, local shop revenues rose sharply. They concluded the highway boosted the local economy by bringing in passing motorists, and they urged other towns to lobby for similar bypasses.

Text 2
Veldt''s revenue rose, but the new highway diverted traffic that once passed directly through neighboring Holt, whose shops lost almost exactly what Veldt gained. A bypass does not create commerce; in this case it relocated it. Recommending the policy broadly ignores that one town''s windfall was another''s loss.', NULL, '[{"id":"A","text":"It is wise, because passing motorists reliably generate new commerce wherever highways are built.","is_correct":false,"explanation":"Reverse; Text 2 argues the highway relocated rather than created commerce."},{"id":"B","text":"It is misguided, because the gains may merely transfer commerce from one town to another rather than create it.","is_correct":true,"explanation":"Correct: Text 2 shows Veldt''s gain matched Holt''s loss, so the policy redistributes rather than generates revenue."},{"id":"C","text":"It is sound for Veldt but should be limited to towns that lack any neighbors.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 never proposes restricting the policy to isolated towns."},{"id":"D","text":"It is correct, since Holt''s losses were caused by factors unrelated to the highway.","is_correct":false,"explanation":"Contradicts Text 2, which ties Holt''s losses directly to diverted traffic."}]'::jsonb, 'B', 'Step 1 — Reframe the gain
Text 2 insists a bypass {{yellow:does not create commerce; in this case it relocated it}}, with Holt losing what Veldt gained.
Step 2 — Apply it to the recommendation
If the policy merely shifts revenue between towns, Text 2 would call recommending it broadly misguided.
Distractor analysis:
- A: Reverse; Text 2 denies highways reliably create commerce.
- C: Text 2 never limits the policy to neighborless towns.
- D: Text 2 attributes Holt''s losses directly to the diverted traffic.', 'Text 2 compares Veldt''s gain to what happened in Holt.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('256e8961-0ae8-427d-a978-3d8cd5206989', 'Based on the texts, how would the author of Text 2 most likely respond to the conclusion in Text 1 that Kuran is "effectively beyond rescue"?', 'Text 1
Linguists have argued that the Kuran language is dying because almost no children now learn it as a first language. Since intergenerational transmission to infants is the standard benchmark of linguistic vitality, the absence of native-speaking children means Kuran is effectively beyond rescue.

Text 2
Kuran''s young people are not infants acquiring it at home but teenagers and adults reclaiming it through schools, apps, and weekend immersion camps. Such learners can become fluent, raise the next generation in the language, and reverse the decline. A benchmark built solely on cradle transmission cannot see a revival that begins in the classroom.', NULL, '[{"id":"A","text":"It is correct, because a language with no native-speaking children can never recover.","is_correct":false,"explanation":"Reverse; Text 2 argues such a language can recover through adult reclamation."},{"id":"B","text":"It relies on a benchmark too narrow to detect revival driven by older learners outside the home.","is_correct":true,"explanation":"Correct: Text 2 says cradle-transmission metrics cannot see a classroom-based revival."},{"id":"C","text":"It is accurate now but ignores that infants may again learn Kuran at home next year.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 points to adult learners, not a near-term return of infant acquisition."},{"id":"D","text":"It is sound, provided the immersion camps eventually produce native-speaking infants.","is_correct":false,"explanation":"Reverses Text 2, which rejects the conclusion rather than conditionally accepting it."}]'::jsonb, 'B', 'Step 1 — Question the benchmark
Text 2 says a metric built solely on cradle transmission {{yellow:cannot see a revival that begins in the classroom}}.
Step 2 — Apply it to the conclusion
Because older learners can become fluent and pass Kuran on, Text 2 would call the ''beyond rescue'' verdict a product of too narrow a measure.
Distractor analysis:
- A: Reverse; Text 2 argues recovery is possible.
- C: Text 2 emphasizes adult learners, not a return of infant acquisition.
- D: Text 2 rejects the conclusion outright rather than accepting it conditionally.', 'Text 2 challenges what counts as a sign of linguistic vitality.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('60341ec0-c3e5-48d1-965c-a981507d5bf9', 'Based on the texts, how would the author of Text 2 most likely respond to the museum''s reasoning, in Text 1, that the matching script is "strong evidence the document was written then"?', 'Text 1
A museum dated a disputed manuscript to the twelfth century chiefly because its handwriting matches scripts known from that era. Since scribes were trained in the dominant styles of their day, the experts reasoned, a script characteristic of the 1100s is strong evidence the document was written then.

Text 2
Script can be imitated. A skilled forger or a later antiquarian copyist studies period hands precisely in order to reproduce them, and a deliberate imitation will, by design, match its model. Handwriting that looks twelfth-century is therefore consistent with a twelfth-century original and with a later imitation alike; it cannot, by itself, distinguish them.', NULL, '[{"id":"A","text":"It is compelling, because scribes could only write in the styles they were trained in.","is_correct":false,"explanation":"Reverse; Text 2 notes that later copyists can deliberately reproduce period styles."},{"id":"B","text":"It is inconclusive, because a later imitator could deliberately reproduce a twelfth-century hand.","is_correct":true,"explanation":"Correct: Text 2 says imitation makes the script consistent with both an original and a forgery."},{"id":"C","text":"It is mistaken, because the manuscript''s script does not actually match twelfth-century examples.","is_correct":false,"explanation":"Contradicts Text 1; Text 2 accepts the script matches and disputes the inference."},{"id":"D","text":"It is valid only for manuscripts whose authors were formally trained as scribes.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 never limits its point to trained scribes."}]'::jsonb, 'B', 'Step 1 — Note the imitation problem
Text 2 argues the matching hand {{yellow:cannot, by itself, distinguish}} a twelfth-century original from a later imitation.
Step 2 — Apply it to the reasoning
Since a copyist can deliberately reproduce a period script, Text 2 would call the dating evidence inconclusive.
Distractor analysis:
- A: Reverse; Text 2 stresses that later copyists can imitate period hands.
- C: Text 2 accepts that the script matches; it disputes what the match proves.
- D: Text 2 never restricts its point to formally trained scribes.', 'Text 2 considers what a deliberate imitator could produce.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8dd12cc6-1c40-4805-819e-a255689c3893', 'Based on the texts, how would the author of Text 2 most likely respond to the attribution, in Text 1, of lower crime to the gardens themselves?', 'Text 1
Sociologists found that neighborhoods with more community gardens have lower crime rates, and they attributed the difference to the gardens. By giving residents a shared space to gather and a stake in their surroundings, the reasoning goes, gardens build the social ties that deter wrongdoing.

Text 2
Gardens require land, permits, volunteer labor, and municipal goodwill—resources that tend to accumulate in already cohesive, well-organized neighborhoods. The very communities able to establish a garden are those whose strong social fabric would lower crime regardless. The garden may be a symptom of cohesion, not its source.', NULL, '[{"id":"A","text":"It is justified, because shared green spaces directly deter wrongdoing in any neighborhood.","is_correct":false,"explanation":"Reverse; Text 2 doubts that the gardens themselves cause the lower crime."},{"id":"B","text":"It may reverse cause and effect, since cohesive neighborhoods are the ones able to build gardens in the first place.","is_correct":true,"explanation":"Correct: Text 2 argues preexisting cohesion produces both the garden and the lower crime."},{"id":"C","text":"It is wrong, because community gardens have been shown to increase crime in some areas.","is_correct":false,"explanation":"No-evidence synthesis; Text 2 never claims gardens raise crime."},{"id":"D","text":"It is correct, provided the neighborhoods also obtained the permits and land their gardens required.","is_correct":false,"explanation":"Misreads Text 2; the resource requirements are evidence of preexisting cohesion, not a condition that validates the claim."}]'::jsonb, 'B', 'Step 1 — Spot the reversed causation
Text 2 proposes that the garden {{yellow:may be a symptom of cohesion, not its source}}, since organized neighborhoods are the ones that can build one.
Step 2 — Apply it to the attribution
Because preexisting cohesion could cause both the garden and the low crime, Text 2 would say Text 1 may have cause and effect backward.
Distractor analysis:
- A: Reverse; Text 2 doubts the gardens themselves lower crime.
- C: Text 2 never claims gardens increase crime.
- D: The resource needs signal preexisting cohesion; they don''t validate the causal claim.', 'Text 2 asks which kinds of neighborhoods are able to build gardens.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e134dc23-aa92-4aaa-8519-3d5d98041f7f', 'Based on the texts, how would the author of Text 2 most likely respond to the historians'' claim, in Text 1, that the diary lets us "explain why he ordered the cautious maneuvers"?', 'Text 1
When a long-buried diary surfaced revealing a general''s private doubts before a famous battle, historians hailed it as the key to his decisions. Now that we know what he truly feared, they argued, we can finally explain why he ordered the cautious maneuvers that won the day.

Text 2
The diary tells us what the general felt, not why he acted. Commanders weigh terrain, supply, and the enemy''s position, and a cautious order may follow from any of these whatever the writer''s private mood. Knowing his fear enriches the story; it does not, on its own, establish that fear, rather than cold calculation, dictated the maneuver.', NULL, '[{"id":"A","text":"It is correct, because a commander''s private feelings are always the true cause of his battlefield decisions.","is_correct":false,"explanation":"Reverse; Text 2 denies that feeling alone establishes the cause of an action."},{"id":"B","text":"It overreaches, because knowing the general''s feelings does not by itself show those feelings, rather than strategic factors, drove his orders.","is_correct":true,"explanation":"Correct: Text 2 distinguishes felt emotion from the reasons that actually dictate a command."},{"id":"C","text":"It is mistaken, because the diary actually records the general''s confidence, not his fear.","is_correct":false,"explanation":"Contradicts Text 1; Text 2 accepts the diary reveals fear."},{"id":"D","text":"It is sound, but only because the cautious maneuvers ultimately won the battle.","is_correct":false,"explanation":"True-but-irrelevant; the battle''s outcome does not bear on Text 2''s point about motive."}]'::jsonb, 'B', 'Step 1 — Separate feeling from cause
Text 2 stresses that the diary {{yellow:tells us what the general felt, not why he acted}}, since strategic factors could equally explain a cautious order.
Step 2 — Apply it to the claim
Because fear and cold calculation both fit the cautious maneuver, Text 2 would say the diary alone cannot establish why he acted.
Distractor analysis:
- A: Reverse; Text 2 denies feelings are always the true cause.
- C: Text 2 accepts the diary reveals fear, not confidence.
- D: True-but-irrelevant; the victory doesn''t address the question of motive.', 'Text 2 distinguishes what the general felt from why he acted.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('37e8eb57-eac0-4e90-904e-375747caac92', 'Based on the texts, how would the author of Text 2 most likely respond to the claim in Text 1 that the Burgess Shale specimens reveal body plans "that natural selection later pruned away"?', 'Text 1
The extraordinary preservation of Burgess Shale fossils, with soft tissues intact, demonstrates that Cambrian ecosystems were far more anatomically diverse than later faunas. Many specimens defy classification into any modern phylum. The fairest reading is that evolution experimented wildly at the outset, generating body plans that natural selection later pruned away. Disparity, in short, peaked early and has only narrowed since.

Text 2
The "weird wonders" of the Burgess Shale have shrunk under scrutiny. As researchers reexamined the flattened, distorted slabs and compared them with intact specimens from China, creature after creature was reassigned to known arthropod or lobopodian lineages. What once looked like failed experiments now slot into recognizable groups. The apparent strangeness, it turns out, tracked the limits of preservation and our own taxonomic categories, not any vanished anatomical extravagance.', NULL, '[{"id":"A","text":"The claim mistakes an artifact of fossil distortion and classification for genuine evolutionary loss.","is_correct":true,"explanation":"Correct: Text 2 argues the apparent strangeness \"tracked the limits of preservation and our own taxonomic categories,\" not real lost anatomy."},{"id":"B","text":"The claim is plausible but cannot be tested without additional soft-tissue specimens from China.","is_correct":false,"explanation":"No-evidence synthesis: Text 2 uses the Chinese specimens as evidence the reassignment is already possible, not as something still needed."},{"id":"C","text":"The claim correctly identifies early disparity but underestimates how much survived into modern phyla.","is_correct":false,"explanation":"Reverse: Text 2 disputes that the early disparity was ever real, rather than affirming it."},{"id":"D","text":"The claim overlooks that natural selection acts on populations rather than on individual specimens.","is_correct":false,"explanation":"True-but-irrelevant: Text 2 never raises the population-versus-individual distinction; its objection is about preservation and taxonomy."}]'::jsonb, 'A', 'Step 1 — Identify Text 2''s mechanism
Text 2 concludes the apparent oddity {{yellow:tracked the limits of preservation and our own taxonomic categories, not any vanished anatomical extravagance}}.
Step 2 — Apply to Text 1''s claim
Since Text 2 attributes the strangeness to distortion and category limits rather than real lost body plans, it would treat Text 1''s "pruned away" claim as a misreading of artifacts.
Distractor analysis:
- B: Text 2 treats the Chinese specimens as already-sufficient evidence, not as a future requirement.
- C: Text 2 denies the early disparity was genuine, so it would not affirm it.
- D: The population-versus-individual point appears nowhere in Text 2.', 'Text 2 explains the apparent strangeness by something other than real evolution. Find that cause.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3e9260d9-9419-4654-aaa7-919521cef920', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that recovering "countless deliberate acts" can explain a famine''s particular shape?', 'Text 1
To understand why a medieval famine struck when it did, the historian must reconstruct the choices of those who lived through it: which fields a lord enclosed, which grain a village hoarded, which roads a merchant closed. Climate and harvest set the stage, but human decisions wrote the script. A famine is, at bottom, the sum of countless deliberate acts, and only by recovering those acts can we explain its particular shape.

Text 2
The documents that survive from the fourteenth century record the doings of lords, monasteries, and town councils—the literate few. To build an explanation from such decisions is to mistake the visible for the decisive. The peasant who altered no record still planted, ate, and starved by rhythms no charter captured. A history assembled only from preserved choices reconstructs the archive''s biases, not the famine''s causes.', NULL, '[{"id":"A","text":"Such a reconstruction privileges the documented decisions of elites and therefore distorts rather than explains the famine.","is_correct":true,"explanation":"Correct: Text 2 warns that building from preserved choices reconstructs \"the archive''s biases, not the famine''s causes.\""},{"id":"B","text":"Deliberate acts matter, but climate and harvest are ultimately the only recoverable causes.","is_correct":false,"explanation":"No-evidence/reverse: Text 2 stresses undocumented human acts (the peasant), not a turn to climate as the sole recoverable cause."},{"id":"C","text":"The approach is sound provided historians weight each surviving decision by its economic importance.","is_correct":false,"explanation":"No-evidence: Text 2 objects to relying on surviving records at all, not to how they are weighted."},{"id":"D","text":"Famines cannot be explained historically because their causes leave no trace in any source.","is_correct":false,"explanation":"Too broad: Text 2 says the literate few''s records are biased, not that no explanation is possible."}]'::jsonb, 'A', 'Step 1 — Locate Text 2''s objection
Text 2 holds that a history from preserved choices {{yellow:reconstructs the archive''s biases, not the famine''s causes}}.
Step 2 — Apply to Text 1
Because Text 1 wants to recover deliberate acts—which survive mainly for elites—Text 2 would say such a method distorts the famine by capturing only the documented few.
Distractor analysis:
- B: Text 2 emphasizes the undocumented peasant, not a retreat to climate alone.
- C: Text 2 rejects reliance on surviving records, not merely their weighting.
- D: Text 2 critiques the archive''s bias, not the possibility of explanation as such.', 'What does Text 2 say a history built only from surviving records actually reconstructs?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a5eed074-4a30-419e-925a-1b7f99c43166', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that the body''s reactions are "only its echo, a downstream consequence" of a feeling formed in the mind?', 'Text 1
When we feel an emotion, the body responds—the racing heart, the flushed face—and these reactions are merely the readout of a feeling already formed in the mind. The brain registers fear, and the heart obediently quickens. The sensation we call emotion is thus a mental event first; the trembling hand is only its echo, a downstream consequence with no part in producing the experience itself.

Text 2
Ask a person to hold a pencil crosswise in their teeth, forcing the muscles of a smile, and they will rate cartoons as funnier. Adopt an upright, expansive posture and reported confidence rises. Such findings are hard to square with the notion that the body merely transcribes a finished feeling. The arrow, at least sometimes, points the other way: arrange the body, and the feeling follows.', NULL, '[{"id":"A","text":"Experiments in which manipulating the body alters the feeling show the causal arrow can run the opposite way.","is_correct":true,"explanation":"Correct: Text 2 concludes \"arrange the body, and the feeling follows,\" reversing Text 1''s direction of causation."},{"id":"B","text":"Bodily reactions are echoes of emotion, but only for fear and not for amusement or confidence.","is_correct":false,"explanation":"Reverse: Text 2 uses amusement and confidence precisely to deny the echo model, not to limit it."},{"id":"C","text":"The mind forms feelings first, yet the body can intensify feelings already present.","is_correct":false,"explanation":"Too narrow/concession: Text 2 claims the body can produce, not merely intensify, the feeling—''the feeling follows.''"},{"id":"D","text":"Emotions are entirely physical, so there is no mental event for the body to echo.","is_correct":false,"explanation":"Too broad: Text 2 says the arrow runs the other way ''at least sometimes,'' not that mind plays no role at all."}]'::jsonb, 'A', 'Step 1 — Find Text 2''s key reversal
Text 2 states, {{yellow:arrange the body, and the feeling follows}}.
Step 2 — Apply to Text 1
Text 1 calls the body a downstream echo; Text 2''s evidence that bodily manipulation changes feeling shows causation can flow body-to-mind, contradicting Text 1.
Distractor analysis:
- B: Text 2 cites amusement and confidence to refute the echo view, not to preserve it.
- C: ''The feeling follows'' claims production, not mere intensification.
- D: Text 2 hedges with ''at least sometimes,'' avoiding the all-physical claim.', 'Text 2 talks about the direction of an ''arrow.'' Which way does it point?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('33a5966f-0e68-4b10-888b-f6fd9188a740', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that the unreliable narrator teaches a lesson "felt, not stated, and that is why it lasts"?', 'Text 1
The novel''s unreliable narrator is its great moral instrument. By trusting a voice that slowly betrays its own blindness, the reader is implicated, having extended sympathy where it was undeserved. We learn humility about our own judgment precisely because the book first deceives us and then exposes the deception. The lesson is felt, not stated, and that is why it lasts.

Text 2
The celebrated effect depends on a reader naive enough to be fooled in the first place—and on reading the book only once. A second pass, knowing the narrator''s blindness from the start, dissolves the deception entirely; the reader watches the manipulation rather than undergoing it. Whatever moral instruction survives rereading must come from somewhere other than the trick that critics praise.', NULL, '[{"id":"A","text":"The felt lesson cannot be what lasts, since rereading dissolves the deception that supposedly delivers it.","is_correct":true,"explanation":"Correct: Text 2 notes a knowing reader \"watches the manipulation rather than undergoing it,\" so the felt deception does not persist."},{"id":"B","text":"The lesson lasts, but only for readers sophisticated enough to detect the narrator immediately.","is_correct":false,"explanation":"Reverse: Text 2 says such readers are not deceived at all, so they never receive the felt lesson Text 1 describes."},{"id":"C","text":"Unreliable narration has no moral value of any kind for any reader.","is_correct":false,"explanation":"Too broad: Text 2 allows that some moral instruction may survive, just not from the trick."},{"id":"D","text":"The lesson is stated rather than felt, contrary to Text 1''s description.","is_correct":false,"explanation":"No-evidence: Text 2 never reclassifies the lesson as stated; it questions whether the felt version endures."}]'::jsonb, 'A', 'Step 1 — Pinpoint Text 2''s condition
Text 2 observes that on rereading the reader {{yellow:watches the manipulation rather than undergoing it}}.
Step 2 — Apply to Text 1
Text 1 claims the felt deception is why the lesson lasts; Text 2 replies that the deception cannot be felt twice, so its endurance must come from elsewhere.
Distractor analysis:
- B: A reader who detects the narrator at once is never fooled, so gets no felt lesson.
- C: Text 2 concedes some moral instruction may survive.
- D: Text 2 does not call the lesson ''stated''; it doubts the felt lesson''s permanence.', 'What happens to the deception, per Text 2, the second time through?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('44ff7a79-e337-4ae4-b8ae-f9c3b2ab60f9', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that the near-simultaneity of the tool record is "the signature of biology, not the slow accumulation of culture"?', 'Text 1
The sudden appearance of complex tools across distant Paleolithic sites within a few millennia points to a single cognitive leap—a genetic change that rewired the brain for symbolic thought. Once that capacity arose, innovation spread rapidly through populations already equipped to receive it. The near-simultaneity of the record is the signature of biology, not the slow accumulation of culture.

Text 2
What looks simultaneous at the resolution of stone and carbon dating may span thirty generations. And dense, connected populations can transmit an invention across a continent within a single human lifetime, no neural rewiring required. Before invoking a mutation to explain a pattern, one should ask whether ordinary demography and exchange, operating over centuries the dating cannot resolve, would produce the very same picture.', NULL, '[{"id":"A","text":"The apparent simultaneity may be coarse dating masking a centuries-long cultural spread, making a biological cause unnecessary.","is_correct":true,"explanation":"Correct: Text 2 says what ''looks simultaneous'' could ''span thirty generations'' and asks whether demography and exchange ''would produce the very same picture.''"},{"id":"B","text":"A genetic change did occur, but it spread through populations faster than Text 1 estimates.","is_correct":false,"explanation":"No-evidence: Text 2 proposes cultural transmission as an alternative to a mutation, not a faster-spreading one."},{"id":"C","text":"Symbolic thought is impossible without the neural rewiring Text 1 describes.","is_correct":false,"explanation":"Reverse: Text 2 argues the rewiring may be unnecessary to explain the pattern."},{"id":"D","text":"Stone and carbon dating are too unreliable to support any claim about Paleolithic tools.","is_correct":false,"explanation":"Too broad: Text 2 notes the resolution limit, not that dating is useless for all claims."}]'::jsonb, 'A', 'Step 1 — Identify Text 2''s alternative
Text 2 warns that the pattern, if produced by demography and exchange, would yield {{yellow:the very same picture}} without a mutation.
Step 2 — Apply to Text 1
Since Text 1 treats simultaneity as biology''s signature, Text 2 responds that coarse dating could hide a slow cultural spread, removing the need for a genetic cause.
Distractor analysis:
- B: Text 2 offers culture instead of, not in addition to, a mutation.
- C: Text 2 says the rewiring may be unnecessary, the opposite of required.
- D: Text 2 cites a resolution limit, not wholesale unreliability.', 'Text 2 questions what the word ''simultaneous'' really means at that time scale.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bc9b6dc7-96e1-4385-89a6-11fc40055bf9', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that offering payment will reliably expand the blood supply?', 'Text 1
Introducing a wage for blood donation would expand the supply. People respond to incentives; offer payment, and more units arrive when hospitals need them. The squeamishness about commercializing donation is sentimental. A larger, steadier supply saves lives, and that practical good outweighs vague misgivings about putting a price on a civic act.

Text 2
The economist''s tidy prediction assumes that adding a payment leaves the existing motive untouched, simply stacking a new reason atop the old. But evidence suggests the price can crowd out the gift: once donating is a transaction, those who gave from duty may withdraw, and the squeamish may stay home. Whether supply rises or falls is therefore an empirical question, not a deduction from the premise that incentives work.', NULL, '[{"id":"A","text":"The prediction wrongly assumes payment adds to existing motives rather than possibly displacing them, so the outcome is uncertain.","is_correct":true,"explanation":"Correct: Text 2 says the price ''can crowd out the gift'' and that whether supply rises ''is therefore an empirical question.''"},{"id":"B","text":"Payment will reduce supply in every case because duty-driven donors always withdraw.","is_correct":false,"explanation":"Too broad: Text 2 says donors ''may'' withdraw and the result is uncertain, not that supply always falls."},{"id":"C","text":"Incentives do not influence human behavior, so the prediction rests on a false premise.","is_correct":false,"explanation":"Reverse: Text 2 does not deny incentives work; it denies they simply stack atop the old motive."},{"id":"D","text":"The moral objection to commercializing donation is the decisive reason to reject payment.","is_correct":false,"explanation":"True-but-irrelevant: Text 2 argues about supply effects empirically, not about the moral case Text 1 dismisses."}]'::jsonb, 'A', 'Step 1 — Find Text 2''s mechanism
Text 2 warns the price {{yellow:can crowd out the gift}}, so paid donation may shrink rather than grow.
Step 2 — Apply to Text 1
Text 1 deduces more supply from ''incentives work''; Text 2 replies that payment may replace the donating motive, making the net effect empirical and uncertain.
Distractor analysis:
- B: Text 2 uses ''may,'' leaving the outcome open, not guaranteed decline.
- C: Text 2 accepts that incentives matter; it rejects the stacking assumption.
- D: Text 2''s reply is empirical, not the moral objection.', 'Text 2 says payment might not simply add to the old motive. What might it do instead?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e760885a-5e7a-4a1d-b061-a6b69c4039f6', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that the novel''s digressions are "the growing pains of a genre not yet sure of its purpose"?', 'Text 1
The meandering digressions of an eighteenth-century novel—its essays on hobby-horses, its typographic jokes—are flaws of an immature form still learning discipline. Readers must forgive the author''s inability to stay on course. A mature novel subordinates every part to the forward motion of plot; these wandering interludes are the growing pains of a genre not yet sure of its purpose.

Text 2
To call the digressions failures is to judge the book by a standard it openly refuses. Its narrator insists that digression is the sunshine of reading, the life of the story; the wandering is the design, not a defect in executing some other design. One may dislike the method, but one cannot fault a work for failing to do what it never set out to do.', NULL, '[{"id":"A","text":"The digressions are the book''s deliberate method, so calling them growing pains judges it against a goal it never adopted.","is_correct":true,"explanation":"Correct: Text 2 says ''the wandering is the design, not a defect'' and that one cannot fault a work for not doing ''what it never set out to do.''"},{"id":"B","text":"The digressions are indeed flaws, but ones the immature genre could not yet avoid.","is_correct":false,"explanation":"Reverse: Text 2 denies they are flaws at all, calling them the design."},{"id":"C","text":"Every reader will enjoy the digressions once their purpose is explained.","is_correct":false,"explanation":"No-evidence: Text 2 grants ''one may dislike the method,'' so it does not claim universal enjoyment."},{"id":"D","text":"Plot-driven novels are inferior to digressive ones as a matter of literary principle.","is_correct":false,"explanation":"Too broad: Text 2 defends judging by the right standard, not the superiority of digression generally."}]'::jsonb, 'A', 'Step 1 — Locate Text 2''s reframe
Text 2 insists {{yellow:the wandering is the design, not a defect}}.
Step 2 — Apply to Text 1
Text 1 treats the digressions as the genre''s immaturity; Text 2 responds that, being deliberate, they cannot be faulted by a plot standard the book never embraced.
Distractor analysis:
- B: Text 2 rejects the ''flaw'' label outright.
- C: Text 2 concedes a reader may dislike the method.
- D: Text 2 argues about the proper standard, not digression''s general superiority.', 'Does Text 2 think the wandering is a defect or the plan?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9a0f6783-52ca-4df1-8953-84e83bf71404', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that the dose-response shape of the data is "exactly what a genuine biochemical effect would produce"?', 'Text 1
The striking correlation across nations—higher chocolate consumption tracks more Nobel laureates per capita—invites a real explanation. Flavanols in cocoa are known to improve cognitive function, and a population that ingests more of them may, over time, sharpen the collective mind from which prizewinners emerge. The dose-response shape of the data is exactly what a genuine biochemical effect would produce.

Text 2
A single hidden variable—national wealth—can manufacture such a pattern effortlessly. Rich countries buy more chocolate and also fund the universities and laboratories where laureates are trained. Neither variable need touch the other; both simply rise with affluence. A smooth dose-response curve is no proof of causation, for any third factor that drives both quantities will trace the same elegant line.', NULL, '[{"id":"A","text":"A shared cause such as national wealth would produce the same curve without any biochemical link, so the shape proves nothing.","is_correct":true,"explanation":"Correct: Text 2 says any third factor driving both quantities ''will trace the same elegant line,'' so the curve is ''no proof of causation.''"},{"id":"B","text":"Flavanols improve cognition, but the effect is too small to generate the observed curve.","is_correct":false,"explanation":"No-evidence: Text 2 proposes a confounder, not a weak-but-real flavanol effect."},{"id":"C","text":"Chocolate consumption causes national wealth, which in turn produces laureates.","is_correct":false,"explanation":"No-evidence/distortion: Text 2 says neither variable need touch the other, not that chocolate drives wealth."},{"id":"D","text":"Correlations between nations are always meaningless and should never be studied.","is_correct":false,"explanation":"Too broad: Text 2 challenges this inference, not the value of all cross-national correlation."}]'::jsonb, 'A', 'Step 1 — Find Text 2''s confounder argument
Text 2 explains that any third factor driving both quantities {{yellow:will trace the same elegant line}}.
Step 2 — Apply to Text 1
Text 1 treats the dose-response shape as a fingerprint of biochemistry; Text 2 replies that wealth could generate the identical curve with no causal link, so the shape is not evidence.
Distractor analysis:
- B: Text 2 raises a confounder, not a small real effect.
- C: Text 2 says the variables need not touch, not that chocolate causes wealth.
- D: Text 2 critiques this inference, not all such correlations.', 'Text 2 names a ''third factor.'' What can it do to a smooth curve?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('54ac32a4-1ec8-4db4-aac1-7a33af67a878', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that a binding rule "removes the guesswork from the economy''s most consequential decisions"?', 'Text 1
A central bank should announce a fixed rule for adjusting interest rates and follow it without deviation. Markets crave predictability; when everyone can forecast the bank''s next move, businesses plan and investment flows smoothly. Discretion breeds uncertainty, and uncertainty is itself a drag on growth. The disciplined virtue of a binding rule is that it removes the guesswork from the economy''s most consequential decisions.

Text 2
A rule is only as good as the world it was written for. The crises that most demand a central bank''s response are precisely the ones no rule anticipated—a sudden bank run, a collapse with no precedent. A bank that has publicly bound itself must then either break its word, forfeiting the credibility the rule was meant to build, or honor it into catastrophe. The promised predictability is hostage to the next surprise.', NULL, '[{"id":"A","text":"An unforeseen crisis forces the bank to abandon the rule or follow it disastrously, so the promised certainty fails when it matters most.","is_correct":true,"explanation":"Correct: Text 2 says the bank must ''break its word'' or ''honor it into catastrophe,'' so ''the promised predictability is hostage to the next surprise.''"},{"id":"B","text":"Rules remove guesswork in crises but increase it during ordinary times.","is_correct":false,"explanation":"Reverse: Text 2 says the rule fails in crises, the unforeseen situations, not in ordinary times."},{"id":"C","text":"Central banks should never announce their intentions to markets under any circumstances.","is_correct":false,"explanation":"Too broad: Text 2 critiques binding rules, not all communication of intentions."},{"id":"D","text":"Predictability matters less than the bank''s independence from political pressure.","is_correct":false,"explanation":"True-but-irrelevant: Text 2 says nothing about political pressure; its concern is unforeseen crises."}]'::jsonb, 'A', 'Step 1 — Locate Text 2''s dilemma
Text 2 concludes that {{yellow:the promised predictability is hostage to the next surprise}}.
Step 2 — Apply to Text 1
Text 1 says a rule removes guesswork from the biggest decisions; Text 2 replies that the biggest decisions are crises no rule anticipated, forcing the bank to break or ruinously keep its word.
Distractor analysis:
- B: Text 2 locates the failure in crises, not ordinary times.
- C: Text 2 targets binding rules, not all communication.
- D: Political independence is never mentioned.', 'Text 2 focuses on a kind of event no rule foresaw. What does it do to the bank''s promise?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ae90a40b-df4a-4e7a-bb9c-3f81c78e19c3', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that the wing''s permanence "shows that natural selection prefers the durable solution over the perishable one"?', 'Text 1
The brilliant blue of the Morpho butterfly''s wing teaches a clear lesson: structure can replace pigment. The wing contains no blue dye; microscopic ridges scatter light to produce the color. Evolution favored this trick because structural color, unlike pigment, never fades. The wing''s permanence shows that natural selection, given the choice, prefers the durable solution over the perishable one.

Text 2
Durability is one pressure among many, and rarely the deciding one. A butterfly that lives a few weeks has no use for color that outlasts it by centuries; selection optimizes for the lifespan that matters to reproduction, not for permanence in a museum drawer. That structural color happens to persist after the insect dies is a byproduct, not the trait selection was reading when it built the wing.', NULL, '[{"id":"A","text":"The lasting color is an incidental byproduct, since selection optimizes for the butterfly''s brief reproductive lifespan, not for permanence.","is_correct":true,"explanation":"Correct: Text 2 says persistence after death is ''a byproduct, not the trait selection was reading,'' and selection targets ''the lifespan that matters to reproduction.''"},{"id":"B","text":"Durability did drive selection, but only because the butterfly''s lifespan is unusually long.","is_correct":false,"explanation":"Reverse: Text 2 stresses the butterfly''s short life and denies durability was the selected trait."},{"id":"C","text":"Structural color is inferior to pigment because it cannot be inherited reliably.","is_correct":false,"explanation":"No-evidence: Text 2 makes no claim about heritability or pigment''s superiority."},{"id":"D","text":"Natural selection never produces traits that outlast an organism''s life.","is_correct":false,"explanation":"Reverse/too broad: Text 2 grants the color does persist, calling it a byproduct, not impossible."}]'::jsonb, 'A', 'Step 1 — Identify Text 2''s reframe
Text 2 calls the lasting color {{yellow:a byproduct, not the trait selection was reading}}.
Step 2 — Apply to Text 1
Text 1 infers a preference for durability from the wing''s permanence; Text 2 replies that selection optimized for the insect''s short reproductive life, so the durability is incidental, not the target.
Distractor analysis:
- B: Text 2 emphasizes the short lifespan and denies durability was selected.
- C: Heritability and pigment superiority are not discussed.
- D: Text 2 admits the color persists; it just calls it a byproduct.', 'Text 2 distinguishes what selection ''reads'' from a side effect. Which is permanence?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8b6bb70f-b17b-44a3-9817-95fed02cbd66', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that "the map of printing predicts the map of upheaval almost exactly"?', 'Text 1
The spread of printed pamphlets caused the religious upheavals of the sixteenth century. Where presses operated, dissent took hold; where they were absent, the old order endured. The new technology placed arguments into thousands of hands at once, and a population that could read the case for reform inevitably embraced it. The map of printing predicts the map of upheaval almost exactly.

Text 2
Presses were costly ventures that clustered in cities already rich, literate, and connected to trade—the same places where new ideas would have found a hearing regardless. The press may have ridden the wave of dissent rather than raised it, settling where receptive audiences and capital already were. A map showing printing and upheaval together cannot tell us which arrived first, or whether one summoned the other at all.', NULL, '[{"id":"A","text":"The overlap may reflect presses settling where receptive, prosperous audiences already existed, so it cannot establish that printing caused the upheaval.","is_correct":true,"explanation":"Correct: Text 2 suggests the press ''rode the wave of dissent rather than raised it'' and the map ''cannot tell us which arrived first.''"},{"id":"B","text":"Printing prevented upheaval in wealthy cities by satisfying the desire for new ideas.","is_correct":false,"explanation":"Reverse: Text 2 does not claim printing suppressed upheaval; it questions the direction of causation."},{"id":"C","text":"Literacy, not printing, was the sole cause of the religious upheavals.","is_correct":false,"explanation":"No-evidence/too narrow: Text 2 lists several shared conditions and leaves causation open, not pinned to literacy alone."},{"id":"D","text":"Maps are inherently unreliable tools for studying historical change.","is_correct":false,"explanation":"Too broad: Text 2 questions this map''s causal reading, not all maps."}]'::jsonb, 'A', 'Step 1 — Find Text 2''s reversal of direction
Text 2 proposes the press {{yellow:rode the wave of dissent rather than raised it}}.
Step 2 — Apply to Text 1
Text 1 reads the spatial overlap as printing causing upheaval; Text 2 replies that presses clustered where receptive, wealthy audiences already were, so the overlap cannot show which came first.
Distractor analysis:
- B: Text 2 never claims printing suppressed upheaval.
- C: Text 2 leaves causation open rather than naming literacy as sole cause.
- D: Text 2 questions this causal inference, not maps generally.', 'Text 2 asks which came first. What does that do to the ''printing caused it'' reading?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cfd765f8-6079-4bc6-8f02-eab450c411ef', 'Based on the texts, how would the author of Text 2 most likely respond to Text 1''s claim that persistent mispricing is "essentially impossible in a functioning market"?', 'Text 1
The rationality of markets is best shown by the law of one price: identical assets trading in different places quickly converge to a single value. Any gap invites arbitrageurs to buy low and sell high until the gap vanishes. The mechanism is automatic and reliable, which is why we can treat persistent mispricing as essentially impossible in a functioning market.

Text 2
Arbitrage corrects a gap only if a trader can borrow the cheap asset, sell the dear one, and wait out the convergence without being forced to close the position first. When borrowing is restricted or capital is scarce, a mispricing can widen before it narrows, bankrupting the very traders meant to erase it. The textbook mechanism assumes frictionless conditions that real markets routinely violate.', NULL, '[{"id":"A","text":"Real-world limits on borrowing and capital can let a mispricing persist or widen, since the correcting traders may be wiped out first.","is_correct":true,"explanation":"Correct: Text 2 notes a mispricing ''can widen before it narrows, bankrupting the very traders meant to erase it.''"},{"id":"B","text":"Mispricing is impossible only for assets that are genuinely identical.","is_correct":false,"explanation":"Too narrow/no-evidence: Text 2''s objection is about borrowing and capital frictions, not the identity of the assets."},{"id":"C","text":"Arbitrageurs always succeed but take longer than Text 1 assumes.","is_correct":false,"explanation":"Reverse: Text 2 says arbitrageurs can be bankrupted and fail, not merely delayed."},{"id":"D","text":"Markets are entirely irrational and prices carry no information.","is_correct":false,"explanation":"Too broad: Text 2 identifies specific frictions, not total irrationality."}]'::jsonb, 'A', 'Step 1 — Locate Text 2''s friction
Text 2 warns a mispricing {{yellow:can widen before it narrows, bankrupting the very traders meant to erase it}}.
Step 2 — Apply to Text 1
Text 1 calls persistent mispricing essentially impossible because arbitrage is automatic; Text 2 replies that borrowing limits and scarce capital can destroy arbitrageurs before convergence, so mispricing can persist.
Distractor analysis:
- B: Text 2''s point concerns frictions, not asset identity.
- C: Text 2 says arbitrageurs can fail, not just take longer.
- D: Text 2 names specific frictions, not total irrationality.', 'Text 2 says something can happen to the arbitrageurs themselves before prices converge. What?', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('43b2a20d-39c4-467f-980c-925cb009ec48', 'Based on the texts, how would the author of Text 2 most likely respond to the claim about Monks Mound made in Text 1?', 'Text 1
The ruins at Cahokia testify to a single, centralized authority. Only a paramount chief, commanding tribute and labor across the floodplain, could have marshaled the thousands of workers needed to raise Monks Mound. The scale of the earthwork itself is decisive proof of coercive, top-down political power.

Text 2
Monumental does not mean monarchical. Ethnographic parallels show that festival labor, organized through kinship feasts and reciprocal obligation, can pile earth as readily as any king''s decree. Until we find palaces or royal burials, the mound proves only that many hands gathered, not that one will compelled them.', NULL, '[{"id":"A","text":"By conceding that a paramount chief existed but denying that he controlled labor across the entire floodplain.","is_correct":false,"explanation":"Text 2 does not concede a chief existed; it argues the mound alone cannot establish that one did."},{"id":"B","text":"By arguing that the sheer size of the earthwork could be achieved through voluntary, kinship-based cooperation rather than proving coercive authority.","is_correct":true,"explanation":"Correct: Text 2 offers reciprocal feast labor as an alternative explanation, severing scale from coercion."},{"id":"C","text":"By maintaining that no large-scale labor was needed because the mound was built gradually over many generations.","is_correct":false,"explanation":"Text 2 grants that ''many hands gathered''; it disputes the source of organization, not the scale of effort."},{"id":"D","text":"By insisting that the absence of written records makes any claim about Cahokian politics impossible to evaluate.","is_correct":false,"explanation":"Text 2 cites positive evidence (palaces, burials) that would settle the question, so it does not call evaluation impossible."}]'::jsonb, 'B', 'Step 1 — Locate the contested inference
Text 1 holds that ''The scale of the earthwork itself is decisive proof of coercive, top-down political power.''
Step 2 — Apply Text 2''s alternative
Text 2 says {{yellow:festival labor, organized through kinship feasts and reciprocal obligation, can pile earth as readily as any king''s decree}}, so it would respond that scale can arise from voluntary cooperation, not coercion. This matches B.
Distractor analysis:
- A: Text 2 never concedes a chief existed; it withholds that conclusion pending palaces or burials.
- C: Text 2 accepts that ''many hands gathered''; it contests organization, not scale.
- D: Text 2 names evidence that could decide the issue, so it does not deem the question unanswerable.', 'Text 2''s key move is supplying a non-coercive mechanism that produces the same large-scale result.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4c838884-0752-4261-9ab0-662904d2e866', 'Based on the texts, how would the author of Text 2 most likely respond to the claim about restricted viewpoint made in Text 1?', 'Text 1
Novelists who narrate from a single character''s mind sacrifice the truth of social life. Consciousness is not sealed in one skull; it is woven among many. Only an omniscient narrator, ranging freely from heart to heart, can render the web of mutual influence that actually constitutes a community. Restricted viewpoint is therefore an aesthetic retreat from reality.

Text 2
What we call mutual understanding is mostly inference and misreading. The single perspective, fenced in by one limited mind, is not a retreat but a fidelity: it reproduces the very opacity through which we meet others. The omniscient narrator flatters us with an access to other minds that no one in life ever possesses.', NULL, '[{"id":"A","text":"By agreeing that single-perspective narration is a retreat, but praising retreat as a valid artistic goal.","is_correct":false,"explanation":"Text 2 explicitly denies the technique is a retreat, calling it a ''fidelity'' instead."},{"id":"B","text":"By contending that limited viewpoint is more realistic because it mirrors the partial, error-prone way people actually know one another.","is_correct":true,"explanation":"Correct: Text 2 redefines realism around opacity and inference, making restriction faithful, not evasive."},{"id":"C","text":"By claiming that omniscient narration is impossible to execute convincingly in modern fiction.","is_correct":false,"explanation":"Text 2 says omniscience ''flatters us,'' i.e., it works but misleads; it never calls it impossible to execute."},{"id":"D","text":"By asserting that community life is irrelevant to the proper aims of the novel.","is_correct":false,"explanation":"Text 2 still concerns how we ''meet others''; it does not dismiss social life as irrelevant."}]'::jsonb, 'B', 'Step 1 — Identify Text 1''s standard
Text 1 treats access to many minds as realism, branding restricted viewpoint an ''aesthetic retreat from reality.''
Step 2 — Reverse the standard
Text 2 counters that the single perspective {{yellow:reproduces the very opacity through which we meet others}}, making limitation the more faithful rendering of real social knowledge. This supports B.
Distractor analysis:
- A: Text 2 rejects the ''retreat'' label outright rather than reinterpreting retreat positively.
- C: Text 2 says omniscience flatters readers, conceding it can be done, not that it is impossible.
- D: Text 2 still cares about how we ''meet others,'' so community is not dismissed.', 'Notice that Text 2 keeps the word ''realism'' but relocates it to partial, fallible knowing.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c6831c4a-96bb-407d-b9f4-741f04fd0e0e', 'Based on the texts, how would the author of Text 2 most likely respond to the claim that banning neonicotinoids would restore pollinator health?', 'Text 1
The collapse of the honeybee colony is plainly the work of neonicotinoid pesticides. Where these chemicals saturate the landscape, hives fail; where farmers abandon them, bees recover. The correlation is so consistent across regions that banning the compounds should, on its own, restore pollinator health.

Text 2
Colonies weakened by the Varroa mite and by viral loads it carries are precisely the ones that succumb when any added stressor, pesticide included, arrives. Strip out the mite and the same pesticide doses are often survivable. To credit the chemical alone is to mistake the final straw for the whole burden.', NULL, '[{"id":"A","text":"By denying that neonicotinoids harm bees under any circumstances.","is_correct":false,"explanation":"Text 2 grants the pesticide is a ''stressor'' and ''the final straw,'' so it does not deny harm."},{"id":"B","text":"By arguing that a ban would address only one contributing stressor while leaving the mite-driven vulnerability that makes colonies collapse.","is_correct":true,"explanation":"Correct: Text 2 frames the pesticide as the final straw atop a mite-caused burden a ban would not remove."},{"id":"C","text":"By claiming that the regional correlation cited in Text 1 was fabricated or measured incorrectly.","is_correct":false,"explanation":"Text 2 never disputes the correlation''s accuracy; it reinterprets its cause."},{"id":"D","text":"By recommending that pesticide use be increased to outcompete the mite.","is_correct":false,"explanation":"This is absurd and unsupported; Text 2 treats pesticide as a stressor, not a remedy."}]'::jsonb, 'B', 'Step 1 — Pin Text 1''s remedy
Text 1 asserts that banning the compounds ''should, on its own, restore pollinator health.''
Step 2 — Introduce the prior cause
Text 2 says removing the mite makes the same doses ''often survivable'' and that {{yellow:To credit the chemical alone is to mistake the final straw for the whole burden}}, so a ban would leave the underlying mite vulnerability intact. This yields B.
Distractor analysis:
- A: Text 2 concedes the pesticide is a real added stressor.
- C: Text 2 reinterprets the correlation rather than denying it occurred.
- D: Increasing pesticide use contradicts Text 2''s treatment of it as harmful.', 'Text 2 accepts the pesticide matters but insists it is not the root cause a ban must reach.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9bff0fea-ffb5-4f2a-b665-761c2105f5b3', 'Based on the texts, how would the author of Text 2 most likely respond to the claim that more arrests produce safer streets?', 'Text 1
The steep drop in violent crime during the 1990s followed directly from aggressive, high-arrest policing. Cities that flooded their streets with officers and pursued minor offenses saw the sharpest declines. The lesson for policymakers is unambiguous: more arrests produce safer streets.

Text 2
The decline appeared simultaneously in cities that expanded arrests and in cities that did not. When an effect shows up regardless of the supposed cause, a shared background condition is the likelier driver. Demography, economic recovery, and falling lead exposure moved together everywhere, and policing tactics rode that tide rather than creating it.', NULL, '[{"id":"A","text":"By arguing that crime actually rose in cities with aggressive policing.","is_correct":false,"explanation":"Text 2 agrees the decline was widespread, including in arrest-heavy cities; it does not claim crime rose."},{"id":"B","text":"By noting that the decline occurred even where arrests did not increase, pointing to common background factors as the real cause.","is_correct":true,"explanation":"Correct: Text 2 uses the parallel decline in non-arrest cities to attribute the trend to shared conditions."},{"id":"C","text":"By conceding that arrests caused the decline but warning that the social costs were too high.","is_correct":false,"explanation":"Text 2 disputes causation itself, not the policy''s costs."},{"id":"D","text":"By insisting that no reliable crime data from the 1990s exists.","is_correct":false,"explanation":"Text 2 relies on the data to compare cities, so it does not call the data nonexistent."}]'::jsonb, 'B', 'Step 1 — State Text 1''s causal claim
Text 1 concludes ''more arrests produce safer streets.''
Step 2 — Break the link with a controlled comparison
Text 2 observes the drop appeared in cities that did not expand arrests and reasons that {{yellow:When an effect shows up regardless of the supposed cause, a shared background condition is the likelier driver}}, crediting demography, recovery, and lead. This gives B.
Distractor analysis:
- A: Text 2 accepts crime fell broadly, not that it rose.
- C: Text 2 denies the causal link rather than weighing costs.
- D: Text 2 uses cross-city data, so it does not deny data exist.', 'Text 2''s argument hinges on the effect appearing even without the supposed cause.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2dd6c78a-15fc-4956-badf-cddea0a56a86', 'Based on the texts, how would the author of Text 2 most likely respond to the claim that returning a single top predator can, by itself, heal a damaged ecosystem?', 'Text 1
Reintroducing wolves to the valley restored the whole river. By preying on elk, the wolves let willows regrow, which stabilized the banks and brought back beaver and songbirds. This cascade shows that returning a single top predator can, by itself, heal a damaged ecosystem.

Text 2
The willows rebounded only where the water table had already risen after a run of wet years. On dry terraces, elk browsed as heavily as ever and willows stayed stunted despite the wolves. The predators helped, but they reaped a recovery that climate had first made possible.', NULL, '[{"id":"A","text":"By denying that wolves had any measurable effect on the willows.","is_correct":false,"explanation":"Text 2 states ''The predators helped,'' so it does not deny their effect."},{"id":"B","text":"By contending that the recovery depended on a favorable change in water conditions that the wolves alone could not have produced.","is_correct":true,"explanation":"Correct: Text 2 makes the rising water table the enabling condition, so the predator did not heal the system by itself."},{"id":"C","text":"By arguing that elk populations were never high enough to damage the willows.","is_correct":false,"explanation":"Text 2 notes elk ''browsed as heavily as ever'' on dry terraces, affirming their impact."},{"id":"D","text":"By claiming that beaver and songbirds returned for reasons wholly unrelated to vegetation.","is_correct":false,"explanation":"Text 2 does not address beaver and songbirds or sever them from vegetation; this is unsupported."}]'::jsonb, 'B', 'Step 1 — Isolate Text 1''s ''by itself'' claim
Text 1 says the wolf cascade shows a predator can ''by itself, heal a damaged ecosystem.''
Step 2 — Add the necessary precondition
Text 2 shows willows rebounded only where the water table had risen and concludes the wolves {{yellow:reaped a recovery that climate had first made possible}}, denying the predator acted alone. This is B.
Distractor analysis:
- A: Text 2 says wolves ''helped,'' acknowledging an effect.
- C: Text 2 affirms heavy elk browsing on dry terraces.
- D: Text 2 makes no claim about beaver and songbirds'' unrelated return.', 'Look for the condition Text 2 says had to be in place before the wolves'' effect could appear.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('909d73d7-a38f-4875-bc25-f5272a74da92', 'Based on the texts, how would the author of Text 2 most likely respond to the claim that cave art erupted from a biological rewiring of the brain?', 'Text 1
The sudden flowering of cave art across distant regions reflects a cognitive leap: around forty thousand years ago, the human brain itself was rewired for symbolic thought, and art erupted as the inevitable expression of that new capacity. The simultaneity across continents points to a biological cause within the species.

Text 2
The pigments and engraved shells now dated far earlier suggest the capacity was always present. What changed was not the brain but the population: denser, better-connected groups passed techniques along instead of letting them die with their makers. Apparent suddenness is the signature of transmission, not of a new mind.', NULL, '[{"id":"A","text":"By arguing that the capacity for symbolic art existed earlier and that its visible flourishing reflects social transmission rather than a new mental ability.","is_correct":true,"explanation":"Correct: Text 2 cites earlier pigments and credits denser, connected populations, replacing biology with transmission."},{"id":"B","text":"By denying that any meaningful increase in artistic production occurred around forty thousand years ago.","is_correct":false,"explanation":"Text 2 explains the ''apparent suddenness'' rather than denying the flourishing happened."},{"id":"C","text":"By conceding the brain was rewired but dating the change much earlier than forty thousand years ago.","is_correct":false,"explanation":"Text 2 says ''not the brain but the population'' changed, so it does not concede a rewiring."},{"id":"D","text":"By claiming that cave art appeared in only one region rather than across continents.","is_correct":false,"explanation":"Text 2 does not dispute the geographic spread; it reinterprets the timing''s cause."}]'::jsonb, 'A', 'Step 1 — Name Text 1''s biological cause
Text 1 attributes the art to the brain being ''rewired for symbolic thought.''
Step 2 — Substitute a social cause
Text 2 holds the capacity ''was always present'' and that {{yellow:Apparent suddenness is the signature of transmission, not of a new mind}}, crediting denser, connected populations. This is A.
Distractor analysis:
- B: Text 2 explains the flourishing rather than denying it.
- C: Text 2 explicitly says the brain did not change.
- D: Text 2 leaves the cross-continental spread intact.', 'Text 2 keeps the timing but swaps a biological explanation for a demographic one.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3fe6bded-24df-4a07-8a8a-59f962709709', 'Based on the texts, how would the author of Text 2 most likely respond to the claim that the sonnets'' power lies in a surrender of control?', 'Text 1
The poet''s late sonnets, with their broken meter and unfinished lines, record a mind disintegrating under grief. We read in their roughness the direct imprint of suffering too great for craft. Their power lies precisely in this surrender of control, this raw overflow of feeling onto the page.

Text 2
The surviving drafts tell a different story: line after line revised, the "broken" meter painstakingly engineered across successive versions. What looks like collapse is a calculated effect, an artist staging spontaneity. The roughness moves us, but it is the achievement of control, not its surrender.', NULL, '[{"id":"A","text":"By agreeing that the sonnets surrender control but denying that this makes them powerful.","is_correct":false,"explanation":"Text 2 denies any surrender of control occurred, so it cannot agree to that premise."},{"id":"B","text":"By arguing that the roughness was deliberately crafted through revision, so its effect demonstrates control rather than its surrender.","is_correct":true,"explanation":"Correct: Text 2 uses the revised drafts to recast the roughness as engineered, an achievement of control."},{"id":"C","text":"By contending that the sonnets do not in fact move readers at all.","is_correct":false,"explanation":"Text 2 says ''The roughness moves us,'' affirming the emotional effect."},{"id":"D","text":"By claiming the sonnets were written by someone other than the grieving poet.","is_correct":false,"explanation":"Text 2 never disputes authorship; it disputes how the roughness arose."}]'::jsonb, 'B', 'Step 1 — Identify the disputed source of power
Text 1 locates the sonnets'' power in ''this surrender of control, this raw overflow of feeling.''
Step 2 — Reattribute the roughness
Text 2 shows the meter was revised across versions and concludes the roughness {{yellow:is the achievement of control, not its surrender}}, so the power reflects craft, not collapse. This is B.
Distractor analysis:
- A: Text 2 rejects the premise of surrender entirely.
- C: Text 2 grants the roughness ''moves us.''
- D: Text 2 raises no authorship question.', 'Text 2 accepts the emotional effect but flips its cause from loss of control to mastery.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a76dfdcb-e838-4ce2-ba71-01ec88c5bbbc', 'Based on the texts, how would the author of Text 2 most likely respond to the recommendation that other companies flatten their hierarchies?', 'Text 1
The firm''s flat structure explains its remarkable innovation. With no managers to gatekeep ideas, engineers act on their own judgment, and good proposals move fast. Other companies should flatten their hierarchies if they wish to match this creative output. The organizational chart is the engine of invention.

Text 2
Flatness works here because the firm hires only seasoned experts who have already internalized its standards. A flat chart laid over inexperienced staff yields not freedom but chaos, as decisions made without shared judgment must be endlessly relitigated. It is the caliber of the people, not the shape of the chart, that does the work.', NULL, '[{"id":"A","text":"By warning that flattening would backfire for firms lacking the seasoned, standards-sharing staff that makes flatness function.","is_correct":true,"explanation":"Correct: Text 2 conditions flatness on expert staff, so it cautions that the recommendation fails without them."},{"id":"B","text":"By agreeing that flattening drives innovation but adding that it also lowers costs.","is_correct":false,"explanation":"Text 2 denies the chart itself drives the result, so it would not simply agree."},{"id":"C","text":"By arguing that hierarchies should be made even steeper at all firms.","is_correct":false,"explanation":"Text 2 does not advocate steeper hierarchy universally; it emphasizes staff caliber."},{"id":"D","text":"By claiming the innovative firm is actually less productive than its rivals.","is_correct":false,"explanation":"Text 2 accepts the firm''s success and explains it differently; it does not call it unproductive."}]'::jsonb, 'A', 'Step 1 — State the recommendation
Text 1 urges that other companies ''flatten their hierarchies if they wish to match this creative output.''
Step 2 — Expose the hidden condition
Text 2 argues {{yellow:A flat chart laid over inexperienced staff yields not freedom but chaos}}, so the recommendation backfires without expert staff. This is A.
Distractor analysis:
- B: Text 2 denies the chart drives innovation, so mere agreement misreads it.
- C: Text 2 stresses staff caliber, not universally steeper hierarchy.
- D: Text 2 accepts the firm''s success and reattributes its cause.', 'Text 2 says the recommendation only works under a condition most companies will not meet.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0f577fed-34ca-4ebb-953b-ebe05e1247db', 'Based on the texts, how would the author of Text 2 most likely respond to the claim that the street grid proves deliberate central planning?', 'Text 1
The ancient city''s grid of streets proves deliberate central planning. Such regularity cannot arise by accident; a single authority must have surveyed the land and dictated the layout before the first house rose. Order on this scale is always the fingerprint of a planner.

Text 2
Grids can grow as readily from rule as from ruler. When each household builds along the same customary setbacks and orientations, regularity accumulates house by house, with no master plan anywhere. The pattern records a shared convention, and a convention needs no single author to enforce it.', NULL, '[{"id":"A","text":"By denying that the street layout is actually regular when examined closely.","is_correct":false,"explanation":"Text 2 accepts the regularity and explains how it accumulated; it does not deny the pattern."},{"id":"B","text":"By proposing that the regularity could emerge from households following shared building conventions, requiring no central planner.","is_correct":true,"explanation":"Correct: Text 2 offers convention-driven, house-by-house accumulation as an alternative to a planner."},{"id":"C","text":"By conceding a planner existed but doubting the planner had legal authority.","is_correct":false,"explanation":"Text 2 argues no single author was needed at all, not that the planner lacked authority."},{"id":"D","text":"By arguing that grids are too rare in the ancient world to support any general conclusion.","is_correct":false,"explanation":"Text 2 makes no claim about the rarity of grids; it explains how one can form."}]'::jsonb, 'B', 'Step 1 — Identify Text 1''s inference
Text 1 claims ''Order on this scale is always the fingerprint of a planner.''
Step 2 — Supply a decentralized mechanism
Text 2 counters that {{yellow:regularity accumulates house by house, with no master plan anywhere}} when households follow shared conventions, so order need not imply a planner. This is B.
Distractor analysis:
- A: Text 2 accepts the regularity rather than denying it.
- C: Text 2 says no single author was needed, not that an existing one lacked authority.
- D: Text 2 says nothing about grids being rare.', 'Text 2 keeps the orderly pattern but derives it from convention instead of command.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0ecac56f-f8d5-4782-ab2f-05651801c4d2', 'Based on the texts, how would the author of Text 2 most likely respond to the claim that belief itself triggers physiological repair?', 'Text 1
The placebo response shows the mind can directly heal the body. Patients given inert pills report real relief, which means belief itself triggers physiological repair. Medicine should harness this power deliberately, prescribing expectation as a treatment in its own right.

Text 2
Much of what we label placebo is the disease simply running its course while we happen to be watching. Many conditions wax and wane; measure patients at their worst and they will tend to improve no matter what we give them. Before crediting belief, we must rule out the regression that would have happened anyway.', NULL, '[{"id":"A","text":"By cautioning that apparent placebo improvement may reflect the natural course of illness rather than any effect of belief.","is_correct":true,"explanation":"Correct: Text 2 attributes the reported relief to regression and waxing-and-waning disease, not to belief."},{"id":"B","text":"By agreeing that belief heals the body but denying that doctors can ethically exploit it.","is_correct":false,"explanation":"Text 2 questions whether belief heals at all; it does not raise ethics."},{"id":"C","text":"By insisting that inert pills cause measurable physical harm.","is_correct":false,"explanation":"Text 2 makes no claim that placebos harm patients."},{"id":"D","text":"By arguing that patients who report relief are deliberately lying about their symptoms.","is_correct":false,"explanation":"Text 2 invokes natural recovery, not patient dishonesty."}]'::jsonb, 'A', 'Step 1 — State the causal claim
Text 1 holds that ''belief itself triggers physiological repair.''
Step 2 — Offer a confound
Text 2 warns that {{yellow:Many conditions wax and wane; measure patients at their worst and they will tend to improve no matter what we give them}}, so improvement may be natural recovery, not belief. This is A.
Distractor analysis:
- B: Text 2 disputes whether belief heals; it raises no ethical objection.
- C: Text 2 never claims placebos cause harm.
- D: Text 2 cites regression, not patient lying.', 'Text 2 names a statistical pattern that mimics healing without any mind-body effect.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3223a125-1d96-4787-a48c-23efd555ba6d', 'Based on the texts, how would the author of Text 2 most likely respond to the claim that the trade language spread through political conquest?', 'Text 1
The trade language that spread along the river valley must have been imposed by a conquering state. A tongue does not blanket hundreds of villages unless an army and a tax collector carry it. The uniform vocabulary across the region is the residue of a single political conquest.

Text 2
Merchants, not soldiers, are the great spreaders of speech. A useful language travels wherever goods do, adopted freely because it lets strangers strike a bargain. The very fact that the vocabulary is densest along trade routes, and thin away from them, fits commerce far better than conquest.', NULL, '[{"id":"A","text":"By arguing that the language''s concentration along trade routes points to voluntary commercial adoption rather than military imposition.","is_correct":true,"explanation":"Correct: Text 2 uses the route-tied distribution to favor commerce-driven, voluntary spread over conquest."},{"id":"B","text":"By denying that the language spread beyond a single village.","is_correct":false,"explanation":"Text 2 accepts wide spread and explains it through trade, not denying the spread."},{"id":"C","text":"By conceding that an army spread the language but disputing the size of the empire.","is_correct":false,"explanation":"Text 2 rejects the army explanation, attributing the spread to merchants instead."},{"id":"D","text":"By claiming that languages never spread through trade in the ancient world.","is_correct":false,"explanation":"Text 2 asserts the opposite, that merchants are ''the great spreaders of speech.''"}]'::jsonb, 'A', 'Step 1 — Identify the conquest claim
Text 1 says the uniform vocabulary ''is the residue of a single political conquest.''
Step 2 — Use the distribution as counter-evidence
Text 2 notes the vocabulary is {{yellow:densest along trade routes, and thin away from them}}, a pattern that ''fits commerce far better than conquest,'' supporting voluntary commercial spread. This is A.
Distractor analysis:
- B: Text 2 accepts the wide spread and reattributes its cause.
- C: Text 2 rejects the army account rather than resizing an empire.
- D: Text 2 affirms that trade spreads languages.', 'Text 2''s strongest evidence is where the language is dense versus thin.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('70fb209a-11a9-4e82-924b-12a3fe199b6d', 'Based on the texts, how would the author of Text 2 most likely respond to the claim that any non-chronological arrangement leaves the public confused?', 'Text 1
The museum should arrange its galleries strictly by chronology. Walking visitors forward through time lets them see how each style grew from the one before, so that the history of art becomes a single legible story. Any other arrangement scrambles cause and effect and leaves the public confused.

Text 2
A timeline teaches that art marches in one inevitable direction, which is precisely the lesson we should resist. Hang a medieval panel beside a modern abstraction and the unexpected kinship jolts the eye into thought. Juxtaposition by theme sacrifices tidy sequence, but it returns to the viewer the freedom to compare.', NULL, '[{"id":"A","text":"By agreeing that thematic arrangement confuses viewers but accepting confusion as the price of novelty.","is_correct":false,"explanation":"Text 2 reframes the disorder as productive thought, not as confusion it merely tolerates."},{"id":"B","text":"By arguing that breaking chronological sequence productively provokes comparison rather than merely confusing the public.","is_correct":true,"explanation":"Correct: Text 2 recasts the loss of sequence as jolting the viewer into thought and restoring freedom to compare."},{"id":"C","text":"By contending that chronological order is impossible to establish for most artworks.","is_correct":false,"explanation":"Text 2 does not claim dating is impossible; it objects to what a timeline teaches."},{"id":"D","text":"By insisting that museums should display only modern art.","is_correct":false,"explanation":"Text 2 pairs medieval and modern works, so it does not favor modern art alone."}]'::jsonb, 'B', 'Step 1 — Identify the charge against alternatives
Text 1 warns that any other arrangement ''leaves the public confused.''
Step 2 — Reframe disorder as insight
Text 2 argues that juxtaposition makes {{yellow:the unexpected kinship jolts the eye into thought}} and returns to the viewer the freedom to compare, so the break in sequence stimulates rather than confuses. This is B.
Distractor analysis:
- A: Text 2 treats the effect as productive thought, not tolerated confusion.
- C: Text 2 never claims chronology cannot be established.
- D: Text 2 endorses pairing eras, not showing only modern art.', 'Text 2 accepts the loss of tidy sequence but recasts its effect as thought, not confusion.', 'Craft and Structure', 'Cross-Text Connections', 'reading_writing', 'craft', 'CTC', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e58f6ac3-8ddc-445b-867a-703678034254', 'Which choice best states the main idea of the text?', 'The mantis shrimp possesses one of the most remarkable visual systems in the animal kingdom. While humans perceive color using three types of light-detecting cells, the mantis shrimp has as many as sixteen. Scientists initially assumed this meant the creature could distinguish an extraordinary range of subtle colors. However, recent experiments suggest that the shrimp is actually worse than humans at telling similar colors apart. Researchers now propose that its many receptors allow it to recognize colors quickly without the brain having to compare signals, a trade of fine accuracy for rapid processing.', NULL, '[{"id":"A","text":"The mantis shrimp''s unusual eyes likely favor fast color recognition over the ability to distinguish subtle shades.","is_correct":true,"explanation":"Correct: it captures the text''s central claim that the many receptors enable speed at the cost of fine discrimination."},{"id":"B","text":"The mantis shrimp can distinguish a far greater range of colors than any other animal studied.","is_correct":false,"explanation":"This reverses the text, which says the shrimp is actually worse at telling similar colors apart."},{"id":"C","text":"Humans and mantis shrimp rely on entirely different organs to detect light.","is_correct":false,"explanation":"No-evidence synthesis: the text compares numbers of cells, not different organs."},{"id":"D","text":"Scientists have abandoned the study of animal vision in favor of human vision.","is_correct":false,"explanation":"No evidence: the text describes ongoing research on the shrimp, not abandonment."}]'::jsonb, 'A', 'Step 1 — Find the conclusion
The text states {{yellow:its many receptors allow it to recognize colors quickly without the brain having to compare signals, a trade of fine accuracy for rapid processing}}.
Step 2 — Match the choice
That sentence directly supports a main idea about favoring speed over subtle discrimination, so A follows.
Distractor analysis:
- B: Reverses the text, which says the shrimp is worse at distinguishing similar colors.
- C: No evidence of different organs; the comparison is about counts of cells.
- D: No evidence; research is described as continuing, not abandoned.', 'Look at the final sentence, which restates what the many receptors actually do.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2f7d9a0b-813d-4954-b655-3c0e4db9b7d2', 'Which choice best states the main idea of the text?', 'In nineteenth-century Britain, the practice of keeping detailed weather diaries was largely an amateur pursuit. Clergy, farmers, and retired naval officers recorded daily temperatures and rainfall in personal notebooks, often for decades. At the time, these records were considered little more than private hobbies. Today, however, climate scientists treasure them. Because instruments and observation methods were remarkably consistent, the diaries provide reliable data about past weather that no other source can supply, helping researchers reconstruct climate patterns from before official records began.', NULL, '[{"id":"A","text":"Amateur weather diaries once seen as mere hobbies have become valuable scientific resources.","is_correct":true,"explanation":"Correct: it captures the shift from private hobby to treasured scientific data."},{"id":"B","text":"Nineteenth-century clergy were more skilled observers than trained scientists.","is_correct":false,"explanation":"No evidence: the text never compares clergy to scientists in skill."},{"id":"C","text":"Official weather records in Britain began in the nineteenth century.","is_correct":false,"explanation":"Too narrow and contradicted: the diaries cover the period before official records began."},{"id":"D","text":"Modern climate scientists rely entirely on amateur diaries for their research.","is_correct":false,"explanation":"Too broad: the text says no other source supplies this particular data, not that scientists rely entirely on diaries."}]'::jsonb, 'A', 'Step 1 — Locate the turn
The text says the diaries were once a hobby, but {{yellow:Today, however, climate scientists treasure them}}.
Step 2 — Match the choice
This contrast between past dismissal and present value is exactly what A states.
Distractor analysis:
- B: No comparison of observational skill is made.
- C: The diaries predate official records, so this contradicts the text.
- D: Overstates; the text says the diaries are uniquely useful, not the sole basis of all research.', 'Notice the contrast signaled by ''Today, however.''', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('97cd06d9-cc4f-45ec-a1f3-be20ff308296', 'Which choice best states the main idea of the text?', 'Amara had always loved the old lighthouse at the edge of town, though it had not guided a ship in years. Its lamp was dark, its keeper long gone, and the path to its door was thick with weeds. Yet every evening she climbed the hill to sit on its cold stone steps. From there she could see the whole harbor, the boats settling for the night, the lights of houses winking on one by one. The lighthouse no longer served sailors, but it still served her.', NULL, '[{"id":"A","text":"Though the lighthouse has lost its original purpose, it remains personally meaningful to Amara.","is_correct":true,"explanation":"Correct: the closing line directly states it no longer serves sailors but still serves her."},{"id":"B","text":"Amara hopes to restore the lighthouse to working order someday.","is_correct":false,"explanation":"No evidence: the text never mentions any plan to restore it."},{"id":"C","text":"The townspeople have forgotten the lighthouse entirely.","is_correct":false,"explanation":"No evidence and partly contradicted: Amara clearly has not forgotten it."},{"id":"D","text":"The harbor has become too dangerous for boats without the lighthouse.","is_correct":false,"explanation":"No evidence: boats are described settling peacefully, with no danger mentioned."}]'::jsonb, 'A', 'Step 1 — Find the key statement
The text concludes, {{yellow:The lighthouse no longer served sailors, but it still served her}}.
Step 2 — Match the choice
This directly establishes that the lighthouse keeps a personal value for Amara despite losing its function, which A states.
Distractor analysis:
- B: No mention of restoring it.
- C: Amara plainly remembers and visits it, so it isn''t forgotten.
- D: The boats are settling calmly; no danger is described.', 'Focus on the last sentence''s contrast between sailors and ''her.''', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0abf6dd1-7b7e-4f77-b835-3bdd8dfba015', 'Which choice best states the main idea of the text?', 'Honeybees communicate the location of food through a behavior called the waggle dance. A returning forager moves in a figure-eight pattern on the honeycomb, and the angle of its dance relative to vertical signals the direction of the food in relation to the sun. The duration of the waggle portion indicates how far away the food lies. Remarkably, other bees in the dark hive interpret these movements by touch and vibration, then fly directly to the source. This silent code lets a colony share precise information without sight or sound.', NULL, '[{"id":"A","text":"Honeybees use a coded dance to communicate the direction and distance of food to their colony.","is_correct":true,"explanation":"Correct: it captures both the direction and distance information the dance conveys."},{"id":"B","text":"Honeybees rely mainly on smell to locate flowers near the hive.","is_correct":false,"explanation":"No evidence: the text describes the dance, not smell."},{"id":"C","text":"The angle of the waggle dance indicates the direction of food relative to the sun.","is_correct":false,"explanation":"Too narrow: this is one detail, not the main idea covering distance too."},{"id":"D","text":"Honeybees can see clearly inside the dark hive.","is_correct":false,"explanation":"Contradiction: the text says other bees interpret the dance by touch and vibration in the dark."}]'::jsonb, 'A', 'Step 1 — Identify the summary
The text ends, {{yellow:This silent code lets a colony share precise information without sight or sound}}, after explaining direction and distance.
Step 2 — Match the choice
A combines both the direction and distance functions of the dance, matching the overall point.
Distractor analysis:
- B: Smell is never mentioned.
- C: True but only one detail, not the whole main idea.
- D: Contradicts the text''s statement that bees interpret by touch in the dark.', 'The main idea should cover both what the angle and the duration signal.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('529ba39c-55ba-4fe0-b51b-44d016b502d1', 'Which choice best states the main idea of the text?', 'When the Roman Empire built its vast network of roads, the primary purpose was not trade but the movement of armies. Straight and durable, these roads let legions march swiftly to distant frontiers. Merchants and travelers certainly used them too, and over time commerce flourished along the routes. Yet historians emphasize that the engineering choices, such as the roads'' remarkable straightness, reflected military priorities. A road that bent to ease a merchant''s wagon would have slowed a marching column, and the empire chose speed for its soldiers above all.', NULL, '[{"id":"A","text":"Roman roads were designed chiefly to move armies quickly, even though they also aided trade.","is_correct":true,"explanation":"Correct: it captures the military priority while acknowledging the secondary commercial use."},{"id":"B","text":"Roman roads were built primarily to encourage commerce between cities.","is_correct":false,"explanation":"Reverses the text, which says the primary purpose was not trade but moving armies."},{"id":"C","text":"Merchants disliked Roman roads because they were too straight.","is_correct":false,"explanation":"No evidence: merchants are said to have used the roads, not disliked them."},{"id":"D","text":"Roman engineers were unable to build curved roads.","is_correct":false,"explanation":"No evidence: the text says straightness was a choice, not a limitation."}]'::jsonb, 'A', 'Step 1 — Find the priority
The text states {{yellow:the primary purpose was not trade but the movement of armies}}.
Step 2 — Match the choice
A reflects this military priority while noting trade as a secondary benefit, matching the passage.
Distractor analysis:
- B: Reverses the stated priority.
- C: Merchants used the roads; no dislike is mentioned.
- D: Straightness was a deliberate choice, not an inability.', 'The opening sentence states the roads'' main purpose directly.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2c753cc6-cad3-49e7-8587-8b454df6b619', 'According to the text, how do some plants in the Atacama Desert obtain water?', 'The Atacama Desert in Chile is among the driest places on Earth, with some weather stations never recording a single drop of rain. For most plants, such conditions would be fatal. Yet a number of hardy species survive there by drawing moisture not from rainfall but from coastal fog. Thin droplets of fog drift inland each morning, and the plants'' specially adapted leaves capture this water before it evaporates. In this way, life persists in a landscape that receives almost no rain at all.', NULL, '[{"id":"A","text":"By capturing moisture from coastal fog with adapted leaves.","is_correct":true,"explanation":"Correct: the text states plants draw moisture from fog using specially adapted leaves."},{"id":"B","text":"By absorbing the rare rainfall that reaches the desert.","is_correct":false,"explanation":"Contradiction: the text says they survive on fog rather than rainfall, which almost never falls."},{"id":"C","text":"By storing water carried inland by rivers.","is_correct":false,"explanation":"No evidence: rivers are never mentioned in the text."},{"id":"D","text":"By extracting water from deep underground reserves.","is_correct":false,"explanation":"No evidence: underground water is not discussed."}]'::jsonb, 'A', 'Step 1 — Locate the detail
The text says plants survive {{yellow:by drawing moisture not from rainfall but from coastal fog}}.
Step 2 — Match the choice
A restates this fog-capturing mechanism, supported by the adapted leaves detail.
Distractor analysis:
- B: Contradicts the text, which says not from rainfall.
- C: Rivers are never mentioned.
- D: Underground reserves are never mentioned.', 'Find the phrase contrasting rainfall with another moisture source.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('924448e4-1b52-43cc-8bce-fb4a65b9a70a', 'Which choice best states the main idea of the text?', 'The composer Florence Price faced steep barriers as a Black woman in early twentieth-century America. For years her orchestral works went unperformed, and many of her manuscripts were nearly lost. In 1933, however, the Chicago Symphony Orchestra premiered her First Symphony, making her the first Black woman to have a composition played by a major American orchestra. Though her music faded from concert halls for decades afterward, recent recordings and performances have brought renewed attention to her achievements, securing her place in the history of American music.', NULL, '[{"id":"A","text":"Despite significant obstacles, Florence Price achieved a historic milestone and has gained renewed recognition.","is_correct":true,"explanation":"Correct: it captures both her barrier-breaking premiere and the recent revival of attention."},{"id":"B","text":"Florence Price''s First Symphony was the most performed work of the 1930s.","is_correct":false,"explanation":"No evidence: the text doesn''t compare its popularity to other works."},{"id":"C","text":"The Chicago Symphony Orchestra rarely premiered new works.","is_correct":false,"explanation":"No evidence: the orchestra''s general practices aren''t described."},{"id":"D","text":"Florence Price''s music has never received public attention.","is_correct":false,"explanation":"Contradiction: the text says recent recordings brought renewed attention."}]'::jsonb, 'A', 'Step 1 — Find the achievement and revival
The text notes her premiere made her {{yellow:the first Black woman to have a composition played by a major American orchestra}}, then describes renewed attention.
Step 2 — Match the choice
A combines the historic milestone with the modern revival, capturing the passage''s arc.
Distractor analysis:
- B: No claim about being the most performed work.
- C: The orchestra''s habits aren''t discussed.
- D: Contradicts the renewed attention described.', 'The main idea spans both her 1933 milestone and the recent revival.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fa3438b2-20fc-4cc2-8b39-e074bc44fd7f', 'Which choice best states the main idea of the text?', 'Octopuses are known for their problem-solving abilities, but a stranger feature is how their bodies are organized. Roughly two-thirds of an octopus''s neurons are located not in its brain but in its arms. Each arm can taste, touch, and even react to objects somewhat independently, without waiting for instructions from the central brain. This arrangement means that an octopus''s arm can begin exploring a crevice or grasping food on its own. In a sense, an octopus thinks not only with its head but throughout its limbs.', NULL, '[{"id":"A","text":"Much of an octopus''s nervous processing happens in its arms, which can act with some independence.","is_correct":true,"explanation":"Correct: it captures the distributed nervous system and the arms'' partial independence."},{"id":"B","text":"Octopuses solve problems more quickly than any other invertebrate.","is_correct":false,"explanation":"No evidence: no comparison to other invertebrates is made."},{"id":"C","text":"An octopus''s brain controls every movement of its arms directly.","is_correct":false,"explanation":"Contradiction: the arms react somewhat independently of the central brain."},{"id":"D","text":"Octopuses use their arms mainly to taste food.","is_correct":false,"explanation":"Too narrow: tasting is one of several functions mentioned."}]'::jsonb, 'A', 'Step 1 — Identify the central fact
The text states {{yellow:Roughly two-thirds of an octopus''s neurons are located not in its brain but in its arms}}.
Step 2 — Match the choice
A reflects this distributed processing and the arms'' independent action, the passage''s point.
Distractor analysis:
- B: No comparison to other invertebrates.
- C: Contradicts the arms'' independence.
- D: Tasting is only one of several arm functions.', 'Notice where most of the octopus''s neurons are located.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('af63b307-75dd-4fdc-a4be-d6bcc21f7a99', 'Which choice best states the main idea of the text?', 'During the Great Depression, a federal program sent photographers across rural America to document the lives of struggling farmers. The government''s goal was practical: to build public support for relief programs by showing the hardships people faced. The photographers, however, produced images of unexpected artistic power. Their portraits of weathered faces and dusty fields are now regarded as some of the most important works of American photography. What began as government paperwork became, in time, a lasting record of both suffering and dignity during a difficult era.', NULL, '[{"id":"A","text":"A government documentation program produced photographs that became enduring works of art.","is_correct":true,"explanation":"Correct: it captures the shift from practical paperwork to lasting artistic record."},{"id":"B","text":"The Great Depression mainly affected photographers and artists.","is_correct":false,"explanation":"No evidence: the text focuses on farmers'' hardships, not on artists being affected."},{"id":"C","text":"The government program failed to build support for relief efforts.","is_correct":false,"explanation":"No evidence: the text doesn''t say whether it succeeded or failed at that goal."},{"id":"D","text":"Rural farmers took the photographs themselves.","is_correct":false,"explanation":"Contradiction: federal photographers were sent to document the farmers."}]'::jsonb, 'A', 'Step 1 — Find the transformation
The text states {{yellow:What began as government paperwork became, in time, a lasting record of both suffering and dignity}}.
Step 2 — Match the choice
A captures this evolution from a practical program into enduring art.
Distractor analysis:
- B: The Depression''s broad effects on artists aren''t the focus.
- C: The text doesn''t evaluate whether relief support was built.
- D: Federal photographers, not farmers, took the images.', 'The last sentence describes what the program ''became.''', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8a22cc0b-ea25-4201-85b0-0e3534752d4b', 'According to the text, how do tardigrades survive extreme conditions?', 'Tardigrades, often called water bears, are microscopic animals famous for surviving extreme conditions. They can endure boiling heat, freezing cold, intense radiation, and even the vacuum of space. Their secret lies in a process called cryptobiosis, in which the animal expels most of the water from its body and curls into a dried, dormant ball. In this state, its metabolism nearly stops, and it can remain inactive for years. When water returns, the tardigrade revives and resumes its normal life as if no time had passed.', NULL, '[{"id":"A","text":"By entering a dried, dormant state in which their metabolism nearly stops.","is_correct":true,"explanation":"Correct: the text describes cryptobiosis, in which the animal dries out and its metabolism nearly stops."},{"id":"B","text":"By rapidly speeding up their metabolism to fight harsh conditions.","is_correct":false,"explanation":"Contradiction: the text says metabolism nearly stops, not speeds up."},{"id":"C","text":"By absorbing extra water to protect their cells.","is_correct":false,"explanation":"Contradiction: the text says they expel most of their water."},{"id":"D","text":"By forming protective shells around their bodies.","is_correct":false,"explanation":"No evidence: shells are never mentioned; they curl into a dried ball."}]'::jsonb, 'A', 'Step 1 — Locate the mechanism
The text explains cryptobiosis, in which {{yellow:its metabolism nearly stops, and it can remain inactive for years}}.
Step 2 — Match the choice
A restates the dried, dormant, low-metabolism state described.
Distractor analysis:
- B: Contradicts; metabolism nearly stops.
- C: Contradicts; they expel water rather than absorb it.
- D: No shells are mentioned.', 'Find the description of what happens to the tardigrade''s metabolism.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c5396eb1-fbc0-4ce1-989c-1e114a5accd4', 'Which choice best states the main idea of the text?', 'In many medieval towns, the ringing of bells did far more than call people to worship. Bells marked the hours of the workday, warned of approaching fire or enemies, and announced births, deaths, and public gatherings. Because few people owned clocks, the pattern and timing of the bells told residents what was happening and what they should do. A single bell tower thus served as a town''s shared voice, organizing daily life for everyone within earshot, whether or not they could read or tell time on their own.', NULL, '[{"id":"A","text":"In medieval towns, bells served many practical functions that helped organize community life.","is_correct":true,"explanation":"Correct: it captures the bells'' wide range of roles in coordinating town life."},{"id":"B","text":"Medieval bells were used only to call people to religious services.","is_correct":false,"explanation":"Too narrow and contradicted: the text says bells did far more than call people to worship."},{"id":"C","text":"Most medieval townspeople owned their own clocks.","is_correct":false,"explanation":"Contradiction: the text says few people owned clocks."},{"id":"D","text":"Medieval towns competed to build the tallest bell towers.","is_correct":false,"explanation":"No evidence: competition over tower height is never mentioned."}]'::jsonb, 'A', 'Step 1 — Find the unifying claim
The text says a bell tower {{yellow:served as a town''s shared voice, organizing daily life for everyone within earshot}}.
Step 2 — Match the choice
A captures the bells'' many practical, community-organizing functions.
Distractor analysis:
- B: Too narrow; bells did far more than call to worship.
- C: Contradicts; few owned clocks.
- D: No mention of competition over tower height.', 'Look for the sentence describing the bell tower as the town''s ''shared voice.''', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('96fc3c92-f705-4d8e-9f58-0501e41cd998', 'Which choice best states the main idea of the text?', 'When Diego first joined the community garden, he expected to grow a few vegetables and little else. He knew nothing about his neighbors and rarely spoke to anyone on his street. But tending the soil beside others changed that. Over weeks of shared work, he traded seeds and advice with the gardener next to him, learned recipes from an elderly woman down the row, and found himself laughing with strangers who soon became friends. The tomatoes he harvested were welcome, but the connections he grew mattered far more.', NULL, '[{"id":"A","text":"For Diego, the garden''s greatest reward was the friendships it fostered rather than the produce.","is_correct":true,"explanation":"Correct: the final sentence states the connections mattered far more than the harvest."},{"id":"B","text":"Diego became the most skilled gardener in his community.","is_correct":false,"explanation":"No evidence: the text never claims he became the most skilled."},{"id":"C","text":"Diego grew more vegetables than he had expected to.","is_correct":false,"explanation":"True-but-irrelevant and unsupported as the main point; the focus is on connections, not quantity."},{"id":"D","text":"Diego preferred to garden alone and avoid his neighbors.","is_correct":false,"explanation":"Contradiction: he came to enjoy working beside and befriending others."}]'::jsonb, 'A', 'Step 1 — Find the central statement
The text concludes, {{yellow:The tomatoes he harvested were welcome, but the connections he grew mattered far more}}.
Step 2 — Match the choice
A restates that the friendships, not the produce, were the greatest reward.
Distractor analysis:
- B: No claim about being the most skilled gardener.
- C: Vegetable quantity isn''t the point and isn''t supported.
- D: Contradicts; he came to value working with others.', 'Compare what the last sentence says about tomatoes versus connections.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3ab90a70-4d5a-4ae9-9a49-f19bfaed5136', 'Which choice best states the main idea of the text?', 'The axolotl, a salamander native to lakes near Mexico City, has long fascinated biologists. Unlike most amphibians, it does not undergo a full metamorphosis; instead, it keeps its feathery external gills and aquatic lifestyle throughout its adult life. Even more striking is its capacity for regeneration. An axolotl that loses a limb, part of its heart, or even a section of its brain can grow the missing tissue back with remarkable completeness. Because of these abilities, the animal has become a favored subject for scientists studying how bodies repair themselves.', NULL, '[{"id":"A","text":"The axolotl''s unusual biological traits make it a valuable animal for scientific study.","is_correct":true,"explanation":"Correct: the text describes the axolotl''s traits and states it has become a favored subject for scientists."},{"id":"B","text":"The axolotl is the only amphibian capable of regrowing lost body parts.","is_correct":false,"explanation":"The text never claims the axolotl is the only amphibian that can regenerate."},{"id":"C","text":"Most amphibians complete a full metamorphosis as they reach adulthood.","is_correct":false,"explanation":"This detail is mentioned only as a contrast and is too narrow to be the main idea."},{"id":"D","text":"The lakes near Mexico City are an ideal habitat for many salamander species.","is_correct":false,"explanation":"The habitat is mentioned in passing and many species are never discussed."}]'::jsonb, 'A', 'Step 1 — Find the focusing statement
The passage ends by noting that {{yellow:the animal has become a favored subject for scientists studying how bodies repair themselves}}.
Step 2 — Match the choice
The text first lists the axolotl''s unusual traits and then explains they make it valuable for study, which choice A captures.
Distractor analysis:
- B: The passage never says the axolotl is the only amphibian that regenerates; that is a no-evidence overstatement.
- C: The metamorphosis point is a narrow contrasting detail, not the overall point.
- D: The habitat is mentioned only in the opening line and is too narrow.', 'Look at the sentence that explains why scientists care about this animal.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7c567808-08d6-49ed-b497-f3d763f4dfff', 'Which choice best states the main idea of the text?', 'In her 1925 novel, the narrator describes her childhood summers on the coast with quiet affection. "The mornings," she writes, "belonged to the gulls and to me, for no one else rose before the tide turned." She recalls collecting smooth stones and arranging them in patterns only she could understand, then watching the sea erase them by evening. She does not lament this loss. Instead, she explains that the daily disappearance of her work taught her to value the making of a thing far more than its keeping.', NULL, '[{"id":"A","text":"The narrator regrets that the sea destroyed the stone patterns she made each day.","is_correct":false,"explanation":"The text says she does not lament the loss, contradicting this choice."},{"id":"B","text":"The narrator''s solitary seaside mornings taught her to prize the act of creating over the result.","is_correct":true,"explanation":"Correct: she explains the daily disappearance taught her to value making over keeping."},{"id":"C","text":"The narrator preferred the company of gulls to that of other people on the coast.","is_correct":false,"explanation":"The gulls appear in one image and her preferences for company are not the point."},{"id":"D","text":"The narrator believes early rising is the key to a productive and happy life.","is_correct":false,"explanation":"Rising early is a detail of the scene, not a general claim the text makes."}]'::jsonb, 'B', 'Step 1 — Locate the lesson
The narrator says the daily disappearance of her work {{yellow:taught her to value the making of a thing far more than its keeping}}.
Step 2 — Match the choice
That statement directly supports choice B, which frames her mornings as teaching her to prize creating over the result.
Distractor analysis:
- A: The text explicitly says she does not lament the loss, so this reverses the meaning.
- C: The gulls are a single image; no preference for them over people is stated.
- D: Early rising is scene detail, not a broad life claim.', 'Find the sentence stating what the disappearing patterns taught her.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('69fe2407-42b5-40c3-82b3-b92bffbfdb1f', 'Which choice best states the main idea of the text?', 'When the printing press spread across Europe in the late fifteenth century, the cost of producing a book dropped sharply. A text that once required months of careful copying by hand could be reproduced in days. As a result, books that had been rare treasures owned mostly by churches and wealthy families became affordable to a much wider public. Literacy rates began to climb in the cities where presses operated, and new ideas could travel farther and faster than before. The press did not merely change how books were made; it changed who could read them.', NULL, '[{"id":"A","text":"Before the printing press, only churches were permitted to own books in Europe.","is_correct":false,"explanation":"The text says books were owned mostly by churches and wealthy families, not that only churches could own them."},{"id":"B","text":"Copying a book by hand took several months to complete in the fifteenth century.","is_correct":false,"explanation":"This is a supporting detail, not the overall point of the passage."},{"id":"C","text":"By lowering the cost of books, the printing press widened access to reading and ideas.","is_correct":true,"explanation":"Correct: the text shows cheaper books reached a wider public and changed who could read."},{"id":"D","text":"Literacy rates rose at the same pace in every region that adopted the printing press.","is_correct":false,"explanation":"The text notes rising literacy in press cities but never claims an equal pace everywhere."}]'::jsonb, 'C', 'Step 1 — Find the summarizing claim
The passage concludes that the press {{yellow:changed who could read them}} after explaining that cheaper books reached a wider public.
Step 2 — Match the choice
Choice C ties the lower cost to broader access to reading and ideas, matching the text''s overall argument.
Distractor analysis:
- A: The text says "mostly" churches and wealthy families, not that only churches could own books.
- B: The months-of-copying figure is a supporting detail, too narrow to be the main idea.
- D: No claim of equal literacy growth across regions is made.', 'The last sentence states what the press changed beyond book-making.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a0fc77ef-6a20-489d-9ff5-0e85c0696f2d', 'According to the text, what does the angle of a bee''s central run during the waggle dance indicate?', 'Honeybees communicate the location of food through a behavior known as the waggle dance. A returning forager moves in a figure-eight pattern on the honeycomb, and the angle of the central run signals the direction of the food relative to the sun. The length of the waggling portion tells other bees how far away the food lies. Nearby workers crowd close to feel the vibrations and follow the dancer''s movements. Through this remarkably precise signaling, a single bee can guide its hivemates to a flower patch hundreds of meters away.', NULL, '[{"id":"A","text":"How far the food source is from the hive","is_correct":false,"explanation":"The text says the length of the waggling portion, not the angle, signals distance."},{"id":"B","text":"The direction of the food relative to the sun","is_correct":true,"explanation":"Correct: the text states the angle of the central run signals direction relative to the sun."},{"id":"C","text":"The number of bees needed to gather the food","is_correct":false,"explanation":"The text never connects the dance angle to how many bees are required."},{"id":"D","text":"The type of flower where the food can be found","is_correct":false,"explanation":"The dance conveys direction and distance, not the flower type."}]'::jsonb, 'B', 'Step 1 — Locate the detail
The text states that {{yellow:the angle of the central run signals the direction of the food relative to the sun}}.
Step 2 — Match the choice
This directly supports choice B, which names direction relative to the sun.
Distractor analysis:
- A: Distance is signaled by the length of the waggling portion, not the angle.
- C: The number of bees is never tied to the angle.
- D: Flower type is not conveyed by the dance in the text.', 'Find the sentence describing what the angle of the central run signals.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('59cd43ac-afef-40d2-acd1-c0c007b0ee22', 'Which choice best states the main idea of the text?', 'The old man in the story keeps a single worn chair on his porch and refuses every offer of a second. His neighbors, puzzled, assume he is unfriendly or set in his ways. But the narrator reveals a gentler reason: years ago the man shared that porch with his late wife, and a second chair would only mark the place where she no longer sat. By keeping just one, he spares himself a daily reminder of her absence. What looks like stubbornness, the narrator suggests, is in fact a quiet form of grief.', NULL, '[{"id":"A","text":"The old man refuses a second chair because he dislikes the company of his neighbors.","is_correct":false,"explanation":"The unfriendly explanation is the neighbors'' mistaken assumption, which the text corrects."},{"id":"B","text":"The narrator criticizes the neighbors for failing to help the lonely old man.","is_correct":false,"explanation":"The text explains the man''s behavior; it does not criticize the neighbors."},{"id":"C","text":"The old man''s single chair, seen as stubbornness, actually reflects his grief over his wife.","is_correct":true,"explanation":"Correct: the narrator says what looks like stubbornness is a quiet form of grief."},{"id":"D","text":"The old man''s porch was once a popular gathering place for the whole neighborhood.","is_correct":false,"explanation":"The text mentions only the man and his late wife, not neighborhood gatherings."}]'::jsonb, 'C', 'Step 1 — Find the reframing statement
The narrator concludes that what looks like stubbornness {{yellow:is in fact a quiet form of grief}}.
Step 2 — Match the choice
Choice C captures that the single chair, misread as stubbornness, actually reflects grief over his wife.
Distractor analysis:
- A: Unfriendliness is the neighbors'' mistaken guess, which the text overturns.
- B: The text explains, rather than criticizes, and the neighbors are not faulted.
- D: No neighborhood gathering is described; only the man and his wife shared the porch.', 'The final sentence contrasts how the behavior looks with what it really is.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('49ea3350-8c49-4635-adab-ddcc94f90a16', 'Which choice best states the main idea of the text?', 'Coral reefs cover less than one percent of the ocean floor, yet they support roughly a quarter of all marine species. Fish, crabs, sponges, and countless other creatures find food and shelter among the reef''s branching structures. The corals themselves are tiny animals that build hard skeletons over generations, gradually forming the vast formations divers explore today. Because so much ocean life depends on these structures, scientists often describe healthy reefs as the rainforests of the sea, hubs of biodiversity whose loss would ripple far beyond the reef itself.', NULL, '[{"id":"A","text":"Coral reefs occupy less than one percent of the ocean floor.","is_correct":false,"explanation":"This is a supporting statistic, not the central point of the passage."},{"id":"B","text":"Despite their small area, coral reefs are vital hubs supporting a large share of marine life.","is_correct":true,"explanation":"Correct: the text contrasts the reefs'' small size with the many species they support."},{"id":"C","text":"Corals are tiny animals that build hard skeletons over many generations.","is_correct":false,"explanation":"This explains how reefs form but is too narrow to be the main idea."},{"id":"D","text":"Rainforests and coral reefs face the same environmental threats today.","is_correct":false,"explanation":"The rainforest comparison is figurative; shared threats are not discussed."}]'::jsonb, 'B', 'Step 1 — Find the central contrast
The text notes reefs cover less than one percent of the ocean floor {{yellow:yet they support roughly a quarter of all marine species}}.
Step 2 — Match the choice
Choice B states that despite their small area, reefs are vital hubs for much marine life, matching that contrast and the "rainforests of the sea" framing.
Distractor analysis:
- A: The one-percent figure is a supporting statistic, not the whole point.
- C: How corals build skeletons is a narrow detail.
- D: The rainforest comparison is figurative; shared threats are never claimed.', 'The main idea links the reefs'' small size to their large importance.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3176e948-6826-4eb7-840a-76ec3fe1acd3', 'Which choice best states the main idea of the text?', 'During the 1930s, photographers hired by a United States government agency traveled across rural America to document the effects of economic hardship. Their assignment was practical: to show officials and the public why relief programs were needed. Yet the images they produced—weathered farmers, dusty fields, families on the move—did more than report conditions. They shaped how a generation remembered the era, turning statistics into faces. Decades later, these photographs hang in museums, valued not only as records but as art that gave the period its lasting visual identity.', NULL, '[{"id":"A","text":"Government photographers of the 1930s created images that became both historical records and enduring art.","is_correct":true,"explanation":"Correct: the text says the photos served as records and are now valued as art that defined the era."},{"id":"B","text":"The government hired photographers mainly to make relief programs appear more successful.","is_correct":false,"explanation":"The text says the goal was to show why relief was needed, not to make programs look successful."},{"id":"C","text":"Museums today display more photographs than paintings from the 1930s.","is_correct":false,"explanation":"The text never compares the number of photographs and paintings in museums."},{"id":"D","text":"Most rural American families were forced to move during the economic hardship of the 1930s.","is_correct":false,"explanation":"Families on the move is one image; the text makes no claim about most families."}]'::jsonb, 'A', 'Step 1 — Find the summarizing claim
The text says the photographs are valued {{yellow:not only as records but as art that gave the period its lasting visual identity}}.
Step 2 — Match the choice
Choice A captures that the images became both historical records and enduring art.
Distractor analysis:
- B: The aim was to show why relief was needed, not to make programs look successful.
- C: No comparison of photo and painting counts is made.
- D: "Families on the move" is a single image, not a claim about most families.', 'The main idea names two roles the photographs came to play.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a6af33d6-9621-4008-9f1a-5fd3c57b30e9', 'According to the text, what lesson does the apprentice eventually learn?', 'The young apprentice had expected the master clockmaker to praise his finished gear, polished and perfectly round. Instead, the old man set it aside and handed him a rough, half-finished piece. "Anyone can admire what is done," he said. "The skill is in seeing what a thing might still become." The apprentice frowned, but as the weeks passed he began to understand. He learned to study unfinished work for its possibilities rather than its flaws, and in time he came to find more satisfaction in shaping a piece than in displaying a completed one.', NULL, '[{"id":"A","text":"Finished work always deserves more praise than unfinished work.","is_correct":false,"explanation":"This reverses the master''s point, which favors seeing potential in unfinished pieces."},{"id":"B","text":"A clockmaker''s gears must be polished and perfectly round to be useful.","is_correct":false,"explanation":"The polished gear is set aside; the text does not make usefulness depend on polish."},{"id":"C","text":"To value the potential in unfinished work and the act of shaping it.","is_correct":true,"explanation":"Correct: he learns to study work for its possibilities and to enjoy shaping over displaying."},{"id":"D","text":"Mastering clockmaking requires many years of difficult apprenticeship.","is_correct":false,"explanation":"The length of apprenticeship is not the lesson the text emphasizes."}]'::jsonb, 'C', 'Step 1 — Locate the lesson
The text says he learned to study unfinished work {{yellow:for its possibilities rather than its flaws}} and found more satisfaction in shaping a piece.
Step 2 — Match the choice
Choice C names valuing potential in unfinished work and the act of shaping it.
Distractor analysis:
- A: This reverses the master''s point about admiring what is done.
- B: The polished gear is set aside; polish is not made a requirement.
- D: The years-long difficulty is not the stated lesson.', 'Find what the apprentice learns to study unfinished work for.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e93a2789-7495-4f9e-ba73-e07d4b19f04d', 'According to the text, how does an octopus''s nervous system differ from a human''s?', 'Octopuses are among the most intelligent invertebrates known to science. In laboratory settings, they have learned to open jars to reach food inside, navigated simple mazes, and even appeared to recognize individual human keepers. Their problem-solving does not rely on a single central brain in the way ours does; instead, much of their nervous system is distributed through their arms, allowing each arm a degree of independent control. This unusual arrangement helps explain how an octopus can explore several objects at once, a feat that continues to intrigue researchers studying animal cognition.', NULL, '[{"id":"A","text":"It is concentrated entirely within a single central brain.","is_correct":false,"explanation":"The text says octopuses do not rely on a single central brain the way humans do."},{"id":"B","text":"It is largely distributed through the arms, giving each some independent control.","is_correct":true,"explanation":"Correct: the text says much of their nervous system is distributed through their arms."},{"id":"C","text":"It allows octopuses to recognize every animal they encounter.","is_correct":false,"explanation":"The text mentions recognizing human keepers, not every animal, and not as a system difference."},{"id":"D","text":"It prevents octopuses from solving problems as quickly as humans do.","is_correct":false,"explanation":"The text presents the arrangement as an advantage, not a limitation on speed."}]'::jsonb, 'B', 'Step 1 — Locate the comparison
The text states that much of their nervous system {{yellow:is distributed through their arms, allowing each arm a degree of independent control}}.
Step 2 — Match the choice
Choice B restates that the system is distributed through the arms with independent control, unlike a human''s central brain.
Distractor analysis:
- A: This is the human arrangement the octopus is contrasted against.
- C: Recognizing keepers is a behavior example, not the system difference.
- D: The text frames the arrangement as an advantage, not a hindrance.', 'Find the sentence contrasting the octopus''s nervous system with ours.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6b9cb876-76c6-4c2f-aed1-875d8c9bfd86', 'Which choice best states the main idea of the text?', 'The Silk Road was not a single paved road but a sprawling network of trade routes linking China, Central Asia, and the Mediterranean. Along these paths, merchants carried silk, spices, and precious metals, exchanging them at bustling market towns. Yet goods were not the only things that traveled. Religions, languages, artistic styles, and technologies moved with the caravans, spreading from one culture to another. In this way, the Silk Road served as a channel for the exchange of ideas as much as merchandise, weaving distant societies into a shared web of contact.', NULL, '[{"id":"A","text":"The Silk Road was a single paved road connecting China to the Mediterranean.","is_correct":false,"explanation":"The text says it was a network of routes, not a single paved road."},{"id":"B","text":"Silk was the most valuable item traded along the Silk Road''s market towns.","is_correct":false,"explanation":"Silk is one example among the goods; the text does not rank its value."},{"id":"C","text":"The Silk Road carried not only goods but also ideas, linking distant cultures.","is_correct":true,"explanation":"Correct: the text states it was a channel for the exchange of ideas as much as merchandise."},{"id":"D","text":"Merchants on the Silk Road faced constant dangers during their long journeys.","is_correct":false,"explanation":"The text never discusses dangers faced by merchants."}]'::jsonb, 'C', 'Step 1 — Find the summarizing claim
The text says the Silk Road served as {{yellow:a channel for the exchange of ideas as much as merchandise}}.
Step 2 — Match the choice
Choice C states it carried both goods and ideas, linking distant cultures, matching that conclusion.
Distractor analysis:
- A: The text explicitly says it was a network, not a single paved road.
- B: Silk is one example; its value is never ranked highest.
- D: Dangers to merchants are never mentioned.', 'The last sentence says the road exchanged more than just merchandise.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9e628574-dc2f-4f84-bd2c-2e0c894b7a2d', 'Which choice best states the main idea of the text?', 'Bioluminescence—the production of light by living organisms—is surprisingly common in the deep ocean, where sunlight cannot reach. Many creatures there use their glow for specific purposes. Some anglerfish dangle a lighted lure to draw prey within striking distance. Certain squid release clouds of glowing fluid to confuse predators and escape. Still other animals flash patterns of light to find mates in the dark. Far from being a mere curiosity, this self-made light is a practical tool that helps deep-sea organisms hunt, hide, and reproduce in an environment without sun.', NULL, '[{"id":"A","text":"Deep-sea creatures use bioluminescence as a practical tool for hunting, defense, and reproduction.","is_correct":true,"explanation":"Correct: the text says the light helps organisms hunt, hide, and reproduce."},{"id":"B","text":"Anglerfish are the only deep-sea animals capable of producing their own light.","is_correct":false,"explanation":"The text describes squid and other animals producing light too."},{"id":"C","text":"Sunlight is unable to reach the deepest parts of the ocean.","is_correct":false,"explanation":"This is a supporting detail explaining the setting, not the main idea."},{"id":"D","text":"Glowing fluid released by squid is the most effective defense in the deep sea.","is_correct":false,"explanation":"The squid example is one use among several; the text does not rank it as most effective."}]'::jsonb, 'A', 'Step 1 — Find the summarizing claim
The text concludes that bioluminescence is {{yellow:a practical tool that helps deep-sea organisms hunt, hide, and reproduce}}.
Step 2 — Match the choice
Choice A restates those three practical uses, capturing the overall point.
Distractor analysis:
- B: Squid and other animals also produce light, so anglerfish are not the only ones.
- C: The unreachable sunlight is setting detail, not the main idea.
- D: The squid example is one use, never ranked as most effective.', 'The final sentence lists the practical purposes the light serves.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7cab8291-604c-446c-ba35-cc94faf64e0a', 'Which choice best states the main idea of the text?', 'In the novel''s opening, Mara returns to the farmhouse she inherited from her grandmother, expecting to sell it quickly and leave. The rooms are cold and the garden overgrown, and at first she sees only a burden to be unloaded. But as she sorts through old letters and mends a broken fence, memories she had buried begin to surface. By the end of the first chapter, she is no longer counting the days until the sale; she is wondering, almost against her will, whether this place might still be a home.', NULL, '[{"id":"A","text":"Mara discovers that the farmhouse is worth far more money than she had expected.","is_correct":false,"explanation":"The text concerns her feelings about the house, not its monetary value."},{"id":"B","text":"Mara''s attitude toward the inherited farmhouse shifts from wanting to sell it to wondering if it could be home.","is_correct":true,"explanation":"Correct: she begins counting days to the sale but ends wondering if the place might be home."},{"id":"C","text":"Mara decides to repair the entire farmhouse before placing it on the market.","is_correct":false,"explanation":"She mends one fence; a full repair plan is not described."},{"id":"D","text":"Mara''s grandmother had hoped Mara would one day live in the farmhouse.","is_correct":false,"explanation":"The grandmother''s hopes are never stated in the text."}]'::jsonb, 'B', 'Step 1 — Track the change
By the chapter''s end Mara is {{yellow:wondering, almost against her will, whether this place might still be a home}} rather than counting days to the sale.
Step 2 — Match the choice
Choice B captures this shift from wanting to sell to seeing the house as a possible home.
Distractor analysis:
- A: The text addresses feelings, not the house''s monetary value.
- C: She mends one fence; no full renovation is planned.
- D: The grandmother''s hopes are never mentioned.', 'Compare how Mara feels about the house at the start versus the end.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3d7a03b8-c71d-45ee-8b72-6ab52649ebdc', 'Which choice best states the main idea of the text?', 'The axolotl, a salamander native to lakes near Mexico City, is unusual among amphibians because it never fully matures into a land-dwelling adult. While most salamanders lose their gills and leave the water as they grow, the axolotl keeps its feathery external gills and remains aquatic for its entire life. This permanent juvenile form, called neoteny, allows the axolotl to thrive in its cool, deep-water habitat. Scientists are especially interested in the species because it can regrow lost limbs, tissues, and even parts of its heart, a regenerative ability that remains rare in the animal kingdom.', NULL, '[{"id":"A","text":"The axolotl is unusual because it stays aquatic and retains juvenile features its whole life, and it has a notable ability to regenerate body parts.","is_correct":true,"explanation":"Correct: it captures both the axolotl''s lifelong juvenile, aquatic form and its regenerative ability, the two points the text develops."},{"id":"B","text":"Most salamanders lose their gills and move onto land as they grow into adults.","is_correct":false,"explanation":"Too narrow: this describes other salamanders as a contrast, not the main point about the axolotl."},{"id":"C","text":"The axolotl lives only in cool, deep lakes near Mexico City and nowhere else.","is_correct":false,"explanation":"Too narrow and no-evidence: habitat is a supporting detail, and the text does not claim it lives nowhere else."},{"id":"D","text":"Scientists have fully explained how the axolotl is able to regrow its limbs and heart.","is_correct":false,"explanation":"No evidence: the text says scientists are interested in the ability, not that they have explained it."}]'::jsonb, 'A', 'Step 1 — Find the focus
The text says the axolotl is unusual because it {{yellow:never fully matures into a land-dwelling adult}} and notes that {{yellow:it can regrow lost limbs, tissues, and even parts of its heart}}.
Step 2 — Match the choice
Choice A combines both of these central points, the lifelong juvenile aquatic form and the regeneration, without adding unsupported claims.
Distractor analysis:
- B: Too narrow; it describes other salamanders, used only as contrast.
- C: Too narrow and adds the unsupported claim that it lives nowhere else.
- D: No evidence; the text says scientists are interested, not that they have explained the ability.', 'Look for the choice that covers both things the text says make the axolotl unusual, not just one detail.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f88e1ee4-a896-44ae-8f38-bae8f0bcc13f', 'Which choice best states the main idea of the text?', 'In 1849, the engineer Ellen Swallow walked the riverbanks of her town with a notebook, recording the color and smell of the water near each factory. At the time, few people connected illness in a neighborhood to the waste that mills poured into nearby streams. Swallow argued that a clean water supply was not a luxury but a public necessity, and she pressed local officials to test the rivers regularly. Her careful measurements, dismissed by some as unladylike fussiness, eventually persuaded the town council to require factories to filter their wastewater before releasing it.', NULL, '[{"id":"A","text":"Through careful measurement and persistent argument, Swallow helped convince officials to regulate factory wastewater.","is_correct":true,"explanation":"Correct: it captures Swallow''s method (measurement and argument) and her result (the new filtering requirement)."},{"id":"B","text":"Swallow enjoyed taking long walks along the river with her notebook each day.","is_correct":false,"explanation":"Too narrow and trivial: the walks are a detail, not the point of the passage."},{"id":"C","text":"Most people in the 1840s already understood that factory waste caused illness.","is_correct":false,"explanation":"Contradiction: the text says few people made that connection."},{"id":"D","text":"Town councils in the 1840s generally welcomed advice from women engineers.","is_correct":false,"explanation":"No evidence and contradiction: some dismissed her work as unladylike fussiness."}]'::jsonb, 'A', 'Step 1 — Identify the through-line
The text shows Swallow''s method and her outcome: her measurements {{yellow:eventually persuaded the town council to require factories to filter their wastewater before releasing it}}.
Step 2 — Match the choice
Choice A states that through measurement and argument she helped bring about wastewater regulation, which is exactly the text''s arc.
Distractor analysis:
- B: Too narrow; the walks are a detail, not the main idea.
- C: Contradicts the text, which says few people made the connection.
- D: No evidence; some dismissed her as unladylike fussiness.', 'The right answer should tie Swallow''s methods to what they accomplished.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('717796ac-c2f4-45cd-9b96-f00634454ea5', 'Which choice best states the main idea of the text?', 'Honeybees communicate the location of food through a movement scientists call the waggle dance. When a foraging bee returns to the hive after finding flowers, it runs in a straight line while shaking its body, then circles back to repeat the run. The angle of the straight run signals the direction of the food relative to the sun, while the length of the run indicates how far away the flowers are. Other bees crowd around the dancer, following its movements closely, and then fly out to gather nectar from the place the dance describes.', NULL, '[{"id":"A","text":"The waggle dance is how a honeybee tells other bees both the direction and the distance of a food source.","is_correct":true,"explanation":"Correct: it captures that the dance conveys both direction (angle) and distance (length) to other bees."},{"id":"B","text":"Honeybees gather nectar from flowers and bring it back to the hive.","is_correct":false,"explanation":"Too broad: this general fact is not the focus, which is the communication of location."},{"id":"C","text":"The angle of a bee''s straight run shows the direction of food relative to the sun.","is_correct":false,"explanation":"Too narrow: this is only one part of what the dance communicates."},{"id":"D","text":"Foraging bees prefer flowers that are close to the hive over distant ones.","is_correct":false,"explanation":"No evidence: the text does not discuss any preference for nearby flowers."}]'::jsonb, 'A', 'Step 1 — Locate the dual signal
The text says {{yellow:The angle of the straight run signals the direction of the food relative to the sun, while the length of the run indicates how far away the flowers are}}.
Step 2 — Match the choice
Choice A states that the dance communicates both direction and distance, capturing the central point.
Distractor analysis:
- B: Too broad; gathering nectar is general background, not the focus.
- C: Too narrow; it names only the direction signal.
- D: No evidence; the text says nothing about preferring nearby flowers.', 'The main idea should include both kinds of information the dance conveys.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('33aca43f-4edc-4602-85e6-2c1335108d53', 'According to the text, what helped María finally write about the orchard effectively?', 'The poet María set down her pen and looked at the unfinished page. For weeks she had tried to describe the orchard where she had grown up, but every line felt flat, as if the words were photographs of fruit rather than the fruit itself. That evening she stopped trying to capture the orchard exactly. Instead she wrote about the single afternoon she had climbed the oldest tree and dropped an apple to her younger brother below. To her surprise, that one small memory made the whole orchard rise up vivid in the reader''s mind.', NULL, '[{"id":"A","text":"Focusing on one specific memory rather than trying to describe the whole orchard exactly.","is_correct":true,"explanation":"Correct: she stopped trying to capture the orchard exactly and wrote about a single afternoon, which worked."},{"id":"B","text":"Spending several more weeks revising her flat opening lines.","is_correct":false,"explanation":"Contradiction: weeks of trying to describe the orchard exactly had failed; she changed approach instead."},{"id":"C","text":"Asking her younger brother to describe the orchard for her.","is_correct":false,"explanation":"No evidence: the brother appears only inside the memory, not as a source of description."},{"id":"D","text":"Taking photographs of the fruit to study before writing.","is_correct":false,"explanation":"No evidence and reverse: ''photographs of fruit'' is a metaphor for what felt flat, not something she did."}]'::jsonb, 'A', 'Step 1 — Find the turning point
The text says {{yellow:she stopped trying to capture the orchard exactly. Instead she wrote about the single afternoon}} when she dropped an apple to her brother.
Step 2 — Match the choice
Choice A restates this shift to a single specific memory, which the text says made the orchard vivid for readers.
Distractor analysis:
- B: Contradicts the text; revising the exact description had failed.
- C: No evidence; the brother is part of the memory, not a describer.
- D: No evidence; ''photographs of fruit'' is a metaphor for flatness, not an action she took.', 'Look at what María did differently the evening her writing finally worked.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ee73648e-e9a9-44c1-ac84-ce70cbb2e190', 'Which choice best states the main idea of the text?', 'For centuries, mapmakers left blank spaces or imaginary monsters in regions they had never visited. The mathematician Nadia argued that these gaps were not signs of ignorance but honest admissions of the limits of knowledge. A map that pretended to know everything, she wrote, was more dangerous than one that openly marked what remained unknown, because a confident false map could send travelers into deserts that did not exist or past rivers that did. The best maps, in her view, told the truth about their own uncertainty.', NULL, '[{"id":"A","text":"Nadia argued that maps honestly showing the limits of knowledge are more valuable than maps that falsely claim to know everything.","is_correct":true,"explanation":"Correct: it captures her claim that honest acknowledgment of uncertainty beats false confidence."},{"id":"B","text":"Early mapmakers often drew imaginary monsters in unexplored regions.","is_correct":false,"explanation":"Too narrow: this is the opening detail, not Nadia''s central argument."},{"id":"C","text":"A confident map can send travelers past rivers that do not exist.","is_correct":false,"explanation":"Too narrow: this is one example supporting the larger point, not the main idea."},{"id":"D","text":"Nadia believed mapmakers should fill in blank spaces with their best guesses.","is_correct":false,"explanation":"Contradiction: she valued marking the unknown, not filling it with guesses."}]'::jsonb, 'A', 'Step 1 — Find Nadia''s thesis
The text says {{yellow:The best maps, in her view, told the truth about their own uncertainty}}, and a false confident map was more dangerous.
Step 2 — Match the choice
Choice A states that honest maps marking the unknown are more valuable than falsely confident ones, capturing her view.
Distractor analysis:
- B: Too narrow; the monsters are just the opening detail.
- C: Too narrow; it is one supporting example.
- D: Contradicts her view; she favored marking the unknown, not guessing.', 'Find the broad claim Nadia is making about what makes a map good, not a single example.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bef7c7ef-af3f-4d87-a31f-4182b1307ac4', 'Which choice best states the main idea of the text?', 'The Roman aqueduct relied on a principle so simple that it is easy to overlook: water flows downhill. To carry water from distant mountain springs into a city, engineers built channels that descended at a very slight, steady slope across many miles. If the slope was too steep, the water rushed and damaged the channel; if too gentle, the water grew stagnant. Maintaining this delicate gradient over hills and valleys, sometimes by routing the channel underground or atop tall stone arches, was the central challenge of aqueduct design.', NULL, '[{"id":"A","text":"The main challenge of building a Roman aqueduct was keeping a slight, steady downhill slope across long, uneven distances.","is_correct":true,"explanation":"Correct: it identifies maintaining the delicate gradient over varied terrain as the central challenge."},{"id":"B","text":"Roman engineers sometimes routed aqueduct channels underground.","is_correct":false,"explanation":"Too narrow: undergrounding is one method, not the main idea."},{"id":"C","text":"Water that flows too quickly through a channel will become stagnant.","is_correct":false,"explanation":"Contradiction: the text says too gentle a slope makes water stagnant, while too steep makes it rush."},{"id":"D","text":"Roman cities depended entirely on mountain springs for all of their water.","is_correct":false,"explanation":"No evidence: the text does not say springs supplied all of a city''s water."}]'::jsonb, 'A', 'Step 1 — Name the central problem
The text states that {{yellow:Maintaining this delicate gradient over hills and valleys}} was the central challenge of aqueduct design.
Step 2 — Match the choice
Choice A restates that keeping a slight, steady slope across uneven distances was the main challenge.
Distractor analysis:
- B: Too narrow; undergrounding is one technique among several.
- C: Contradicts the text; stagnation comes from too gentle, not too quick, flow.
- D: No evidence; the text never says springs supplied all the water.', 'The main idea names the overall difficulty engineers faced, not a single technique.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('84fb470b-6dba-49af-aace-9676961c1be8', 'Which choice best states the main idea of the text?', 'When a star much larger than our sun runs out of fuel, it can collapse and then explode in a burst called a supernova. For a few weeks, a single supernova can shine brighter than all the other stars in its galaxy combined. But these explosions do more than dazzle: they forge heavy elements such as iron and gold and scatter them across space. The carbon in living things and the calcium in human bones were created in such stellar explosions long before the Earth formed.', NULL, '[{"id":"A","text":"Supernovas are powerful stellar explosions that also create and spread the heavy elements found in living things.","is_correct":true,"explanation":"Correct: it captures both the explosion''s power and its role in forging and scattering elements like those in our bodies."},{"id":"B","text":"A supernova can briefly outshine all the other stars in its galarxy combined.","is_correct":false,"explanation":"Too narrow: brightness is one detail, while the passage emphasizes the creation of elements too."},{"id":"C","text":"The Earth formed before stars began producing heavy elements like iron.","is_correct":false,"explanation":"Contradiction: the text says these elements were created long before the Earth formed."},{"id":"D","text":"Stars the size of our sun regularly explode as supernovas.","is_correct":false,"explanation":"Contradiction: the text specifies stars much larger than our sun, not sun-sized stars."}]'::jsonb, 'A', 'Step 1 — Spot the larger point
The text says supernovas do more than dazzle: {{yellow:they forge heavy elements such as iron and gold and scatter them across space}}.
Step 2 — Match the choice
Choice A combines the explosion''s power with its element-creating role, the two ideas the text develops.
Distractor analysis:
- B: Too narrow; brightness is only one detail.
- C: Contradicts the text; elements formed before Earth.
- D: Contradicts the text; it specifies stars much larger than the sun.', 'Look for the choice that covers both how powerful supernovas are and what they produce.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3fea80eb-dccb-4239-b7c6-c6d96abdf5ea', 'According to the text, why did Tomás''s city bees produce more honey than many rural bees?', 'The naturalist Tomás kept bees on the flat roof of his apartment building in the center of the city. Friends warned that bees could never thrive among concrete and traffic, far from open meadows. Yet Tomás found that his urban hives produced more honey than many rural ones. City parks, balcony gardens, and street trees bloomed at different times throughout the year, so his bees almost always had flowers to visit. In the countryside, by contrast, vast fields of a single crop offered a brief feast followed by long stretches of bare ground.', NULL, '[{"id":"A","text":"The varied city plantings bloomed at different times, giving the bees flowers throughout the year.","is_correct":true,"explanation":"Correct: the text attributes the success to staggered blooming across parks, gardens, and trees."},{"id":"B","text":"City bees face less danger from traffic than from predators in meadows.","is_correct":false,"explanation":"No evidence: the text does not compare predators or traffic danger."},{"id":"C","text":"Rural fields of a single crop provided a steady food supply all year.","is_correct":false,"explanation":"Contradiction: the text says single crops gave a brief feast then bare ground."},{"id":"D","text":"Tomás kept far more hives on his roof than rural beekeepers did.","is_correct":false,"explanation":"No evidence: the text never compares the number of hives."}]'::jsonb, 'A', 'Step 1 — Find the cause
The text says city plants {{yellow:bloomed at different times throughout the year, so his bees almost always had flowers to visit}}.
Step 2 — Match the choice
Choice A restates this staggered bloom as the reason for the greater honey production.
Distractor analysis:
- B: No evidence; the text compares no dangers.
- C: Contradicts the text; single crops gave brief feasts, not steady supply.
- D: No evidence; hive counts are never compared.', 'Look for the detail about when city flowers bloomed compared with rural crops.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('796efb43-3e34-41fc-b013-eac514464ff6', 'Which choice best states the main idea of the text?', 'In many languages, the words for family members reveal what a culture treats as important. Some languages use a single word for both ''brother'' and ''sister,'' while others have separate words for an older brother and a younger brother, signaling that birth order carries social weight. Still others distinguish relatives on the mother''s side from those on the father''s side. Linguists note that these patterns are not random: a language tends to mark the distinctions that matter for how its speakers organize duties, inheritance, and respect within a household.', NULL, '[{"id":"A","text":"The distinctions a language makes in family words tend to reflect the social relationships its speakers consider important.","is_correct":true,"explanation":"Correct: it captures the linguists'' point that kinship terms mark socially significant distinctions."},{"id":"B","text":"Some languages use a single word for both ''brother'' and ''sister.''","is_correct":false,"explanation":"Too narrow: this is one example illustrating the broader claim."},{"id":"C","text":"Birth order determines inheritance in every culture that has a written language.","is_correct":false,"explanation":"No evidence: the text makes no claim about every culture or written languages."},{"id":"D","text":"The patterns in family words across languages are essentially random.","is_correct":false,"explanation":"Contradiction: the text explicitly says these patterns are not random."}]'::jsonb, 'A', 'Step 1 — Find the general claim
The text says {{yellow:a language tends to mark the distinctions that matter for how its speakers organize duties, inheritance, and respect within a household}}.
Step 2 — Match the choice
Choice A restates that family-word distinctions reflect socially important relationships.
Distractor analysis:
- B: Too narrow; it is one illustrative example.
- C: No evidence; the text never claims this for every culture.
- D: Contradicts the text, which says the patterns are not random.', 'The main idea is the general conclusion the linguists draw from the examples.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('30f7f45b-7433-4bf4-8cfd-49cd00030215', 'According to the text, what did Adaeze learn from the costly mistake?', 'The young clerk Adaeze had been told that the surest path to advancement was to agree with her supervisor in every meeting. For months she said nothing when she spotted errors in the office''s accounts, fearing she would seem disrespectful. One afternoon, however, a small mistake she had quietly noticed grew into a costly one. Afterward, she resolved to speak up about problems while they were still minor. To her relief, her supervisor came to value her honesty, and the office''s records grew far more accurate than before.', NULL, '[{"id":"A","text":"That it is better to point out small problems early than to stay silent to avoid seeming disrespectful.","is_correct":true,"explanation":"Correct: she resolved to speak up about problems while still minor, and it proved beneficial."},{"id":"B","text":"That agreeing with her supervisor in every meeting was the surest path to advancement.","is_correct":false,"explanation":"Reverse: this is the advice she had been given, which the experience led her to reject."},{"id":"C","text":"That keeping accurate accounts is impossible in a busy office.","is_correct":false,"explanation":"Contradiction: the records grew far more accurate after she changed her behavior."},{"id":"D","text":"That her supervisor disliked employees who pointed out errors.","is_correct":false,"explanation":"Contradiction: the supervisor came to value her honesty."}]'::jsonb, 'A', 'Step 1 — Find the lesson
After the costly mistake, the text says {{yellow:she resolved to speak up about problems while they were still minor}}.
Step 2 — Match the choice
Choice A restates this resolution to raise small problems early rather than stay silent.
Distractor analysis:
- B: Reverse; this is the old advice she came to reject.
- C: Contradicts the text; records became more accurate.
- D: Contradicts the text; the supervisor valued her honesty.', 'Focus on what Adaeze decided to do differently after the mistake.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6a0f041c-5728-41f6-9084-85375c894e13', 'Which choice best states the main idea of the text?', 'The Sahara Desert was not always a sea of sand. About six thousand years ago, much of it was green grassland dotted with lakes, where hippos wallowed and people herded cattle. Rock paintings left by these inhabitants show swimmers and large animals that could never survive in today''s dry climate. Gradually, a slow shift in the Earth''s orbit changed the pattern of seasonal rains, and the region dried out over many generations. The desert we know today is the result of that long transformation, not a landscape that has always existed.', NULL, '[{"id":"A","text":"The Sahara was once a green, watery region that slowly dried into desert because of a gradual change in seasonal rains.","is_correct":true,"explanation":"Correct: it captures both the Sahara''s wet past and the gradual drying that produced today''s desert."},{"id":"B","text":"Ancient rock paintings in the Sahara show swimmers and large animals.","is_correct":false,"explanation":"Too narrow: the paintings are evidence for the larger point, not the main idea."},{"id":"C","text":"The Sahara has always been a dry, sandy desert throughout its history.","is_correct":false,"explanation":"Contradiction: the text says it was once green and is not a landscape that always existed."},{"id":"D","text":"People today still herd cattle across the grasslands of the Sahara.","is_correct":false,"explanation":"Contradiction: the herding and grasslands belong to the distant past."}]'::jsonb, 'A', 'Step 1 — Find the central claim
The text says today''s desert {{yellow:is the result of that long transformation, not a landscape that has always existed}}.
Step 2 — Match the choice
Choice A states the Sahara was once green and dried gradually due to changing rains, capturing the full arc.
Distractor analysis:
- B: Too narrow; the paintings are supporting evidence.
- C: Contradicts the text; it was once green.
- D: Contradicts the text; the herding was thousands of years ago.', 'The main idea covers both what the Sahara used to be and how it changed.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('71e210f1-3fee-45d3-a0e9-45064c0f242f', 'Which choice best states the main idea of the text?', 'Octopuses can change the color and texture of their skin almost instantly, a skill that serves more than one purpose. Special cells in the skin expand or shrink to flash bands of color, while tiny muscles raise bumps that mimic rough coral or stone. An octopus may use this ability to vanish against the seafloor, hiding from a passing shark. But it can also use the same skin to put on a bold display, warning a rival away or signaling alarm. The same tool, then, allows the animal both to disappear and to stand out.', NULL, '[{"id":"A","text":"An octopus''s ability to change its skin lets it serve opposite purposes: hiding from danger and boldly signaling to others.","is_correct":true,"explanation":"Correct: it captures the text''s point that one skill enables both concealment and conspicuous display."},{"id":"B","text":"Special cells in an octopus''s skin expand and shrink to flash bands of color.","is_correct":false,"explanation":"Too narrow: this describes the mechanism, not the central point about its dual uses."},{"id":"C","text":"Octopuses change color mainly to hide from sharks on the seafloor.","is_correct":false,"explanation":"Too narrow: hiding is only one of the two purposes the text stresses."},{"id":"D","text":"An octopus can change its color but not the texture of its skin.","is_correct":false,"explanation":"Contradiction: the text says it can also mimic rough coral or stone in texture."}]'::jsonb, 'A', 'Step 1 — Find the unifying idea
The text concludes that {{yellow:The same tool, then, allows the animal both to disappear and to stand out}}.
Step 2 — Match the choice
Choice A restates that the skin-changing ability serves the opposite purposes of hiding and signaling.
Distractor analysis:
- B: Too narrow; it describes only the mechanism.
- C: Too narrow; hiding is just one of two purposes.
- D: Contradicts the text; it also changes texture.', 'Look for the choice that captures both opposite ways the octopus uses the same ability.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ba19a115-cfb0-44b5-88fe-adb6579edf23', 'Which choice best states the main idea of the text?', 'When the harpist Eda began her apprenticeship, she assumed mastery meant flawless technique. Her teacher, however, kept interrupting note-perfect runs to ask what Eda imagined the music describing. At first the questions irritated her; she had practiced the passages until her fingers no longer faltered. Only after a year did she notice that audiences leaned forward not during her cleanest performances but during the pieces she had learned to picture as small stories. Technique, she finally understood, was a doorway rather than a destination. The cleanliness she had prized was necessary, but it was the imagined narrative behind each phrase that made strangers stop talking and listen.', NULL, '[{"id":"A","text":"Eda comes to realize that technical precision alone is insufficient and that imaginative interpretation is what truly moves listeners.","is_correct":true,"explanation":"Correct: it captures both that precision is necessary but insufficient and that imagined narrative is what engages audiences."},{"id":"B","text":"Eda''s teacher was wrong to interrupt her flawless runs with distracting questions.","is_correct":false,"explanation":"Contradicts the text, which shows the questions ultimately helped Eda."},{"id":"C","text":"Audiences prefer harp music to other kinds of instrumental performance.","is_correct":false,"explanation":"No evidence; the text never compares the harp to other instruments."},{"id":"D","text":"Eda practiced her passages until her fingers no longer faltered.","is_correct":false,"explanation":"Too narrow; this is a supporting detail, not the main idea."}]'::jsonb, 'A', 'Step 1 — Locate the turn
Eda first equated mastery with flawless technique, but later saw that {{yellow:it was the imagined narrative behind each phrase that made strangers stop talking and listen}}.
Step 2 — Synthesize
The passage moves from valuing precision alone to recognizing imaginative interpretation as the source of impact, so A states both halves of that idea.
Distractor analysis:
- B: Reverses the text; the interruptions proved valuable, not wrongheaded.
- C: No-evidence synthesis; no other instruments are compared.
- D: True but too narrow, capturing only a single detail.', 'Notice what Eda valued at first versus what she concluded by the end.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8b15ecbd-6dcc-4f96-bbba-12a2a54462fc', 'Which choice best states the main idea of the text?', 'Mangrove forests grow where rivers meet the sea, in salty, oxygen-poor mud that would kill most trees. Their tangled roots arch above the waterline, taking in air through tiny pores and trapping sediment that would otherwise wash away. Ecologists once measured a mangrove''s worth mainly by the fish that sheltered among its roots. Newer studies, however, weigh another service: the dense root networks blunt the force of storm surges, sparing coastal villages behind them. In some regions, replanting mangroves now costs less than building concrete seawalls and protects shorelines that engineered barriers cannot. The trees, it turns out, defend the very communities that long overlooked them.', NULL, '[{"id":"A","text":"Mangroves are valued not only as fish habitat but increasingly as cost-effective natural protection against storm surges.","is_correct":true,"explanation":"Correct: it joins the older fish-habitat view with the newer storm-protection value the text emphasizes."},{"id":"B","text":"Mangroves grow in salty, oxygen-poor mud that would kill most other trees.","is_correct":false,"explanation":"Too narrow; this opening detail is not the central point."},{"id":"C","text":"Concrete seawalls are always more expensive than replanting mangrove forests.","is_correct":false,"explanation":"Overstates the text, which says ''in some regions,'' not always."},{"id":"D","text":"Ecologists no longer believe mangroves provide any habitat for fish.","is_correct":false,"explanation":"Contradicts the text, which still acknowledges the fish-sheltering role."}]'::jsonb, 'A', 'Step 1 — Identify the added value
Beyond sheltering fish, newer studies show the roots {{yellow:blunt the force of storm surges, sparing coastal villages behind them}}.
Step 2 — Synthesize
The passage combines the traditional habitat value with the emerging protective value, which A captures fully.
Distractor analysis:
- B: Too narrow; describes only where mangroves grow.
- C: Overgeneralizes ''in some regions'' into ''always.''
- D: Contradicts the text, which retains the fish-habitat role.', 'The text adds a new function to an older one; the main idea includes both.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4af64353-cd5b-4a74-bb11-5c3127b027fb', 'Which choice best states the main idea of the text?', 'In 1789, the citizens of a small French town drafted a list of grievances to send to the king. Historians long read such documents as straightforward demands for lower taxes. A closer look at this town''s list complicates that picture. Alongside complaints about the salt tax sit requests for a village schoolmaster, repairs to a crumbling bridge, and a fairer system for distributing common pastureland. The grievances reveal townspeople thinking less about overthrowing a distant monarch than about the daily machinery of their own community. Their list, read carefully, is a portrait of local life as much as a political protest.', NULL, '[{"id":"A","text":"A close reading of one town''s grievance list shows that it reflected everyday local concerns, not merely demands to reduce taxes.","is_correct":true,"explanation":"Correct: it captures the contrast between the traditional tax-focused reading and the broader local concerns revealed."},{"id":"B","text":"French townspeople in 1789 were primarily focused on overthrowing the monarchy.","is_correct":false,"explanation":"Contradicts the text, which says they thought ''less about overthrowing a distant monarch.''"},{"id":"C","text":"The town''s list included a complaint about the salt tax.","is_correct":false,"explanation":"Too narrow; one item is not the main idea."},{"id":"D","text":"Historians have always understood grievance lists as portraits of local life.","is_correct":false,"explanation":"Contradicts the text, which says historians ''long read'' them as tax demands."}]'::jsonb, 'A', 'Step 1 — Find the reinterpretation
The list reveals townspeople {{yellow:thinking less about overthrowing a distant monarch than about the daily machinery of their own community}}.
Step 2 — Synthesize
The passage overturns the tax-only reading to show the list as a portrait of local life, which A states.
Distractor analysis:
- B: Reverses the text; they thought less about overthrow.
- C: Too narrow; a single grievance.
- D: Contradicts the historians'' long-held view described.', 'Compare what historians long assumed with what this list actually contained.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bac6bfeb-8ca6-4a00-85aa-cf4689bc913a', 'Which choice best states the main idea of the text?', 'Bee colonies face a decision each time a scout returns dancing about a new nest site. No single bee compares all the options; none could. Instead, scouts who have found better sites dance longer and more vigorously, recruiting more followers, while support for poorer sites fades. Over hours, the competing dances tilt the swarm toward the strongest candidate, and the colony moves as one. Researchers note that this resembles how flocks of birds turn without a leader: each individual responds only to local information, yet a coherent group choice emerges. Intelligence, in such systems, belongs to the collective rather than to any member of it.', NULL, '[{"id":"A","text":"Bee swarms and similar groups reach sound collective decisions through many local interactions rather than through any single decision-maker.","is_correct":true,"explanation":"Correct: it captures the central claim that group intelligence emerges from local interactions without a leader."},{"id":"B","text":"Scout bees that find better nest sites dance longer and more vigorously.","is_correct":false,"explanation":"Too narrow; this mechanism is a detail supporting the broader idea."},{"id":"C","text":"Flocks of birds make better decisions than bee colonies do.","is_correct":false,"explanation":"No evidence; the text compares the two without ranking them."},{"id":"D","text":"A single experienced bee evaluates every nest option before the swarm moves.","is_correct":false,"explanation":"Contradicts the text, which says ''No single bee compares all the options.''"}]'::jsonb, 'A', 'Step 1 — Identify the unifying claim
The text concludes that {{yellow:Intelligence, in such systems, belongs to the collective rather than to any member of it}}.
Step 2 — Synthesize
Both the bee and bird examples illustrate leaderless decisions from local information, which A generalizes correctly.
Distractor analysis:
- B: Too narrow; one mechanism only.
- C: No-evidence comparison; no ranking is given.
- D: Contradicts ''No single bee compares all the options.''', 'What do the bees and birds have in common about how choices arise?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3f3180b8-903d-4d01-99e9-d787349b244d', 'Which choice best states the main idea of the text?', 'The novelist Clara Vey rarely traveled, yet her books teemed with foreign harbors and crowded bazaars. Reviewers praised her vivid settings, assuming firsthand experience. In truth, Vey haunted the local library, copying sailors'' diaries, customs records, and merchants'' letters into notebooks she kept for decades. She once remarked that a single ship''s manifest, with its lists of cargo and ports, told her more about a place than a brief visit ever could. Her imagined cities were assembled from documents, not memories. What readers took for the fruit of adventure was instead the patient harvest of a reader who never left her town.', NULL, '[{"id":"A","text":"Vey''s richly detailed settings came not from travel but from her painstaking study of documents.","is_correct":true,"explanation":"Correct: it captures the contrast between the assumed travel and the documentary research that actually produced her settings."},{"id":"B","text":"Reviewers praised Vey''s settings for their vividness.","is_correct":false,"explanation":"Too narrow; this is one detail, not the central point."},{"id":"C","text":"Vey believed brief visits to a place were more useful than reading documents.","is_correct":false,"explanation":"Reverses the text; she said a manifest told her more than a visit."},{"id":"D","text":"Few novelists of Vey''s era did any research before writing.","is_correct":false,"explanation":"No evidence; the text discusses only Vey."}]'::jsonb, 'A', 'Step 1 — Pin the source
Vey''s cities were built from records, since {{yellow:Her imagined cities were assembled from documents, not memories}}.
Step 2 — Synthesize
The text overturns the assumption of firsthand travel, revealing documentary research as the real source, which A states.
Distractor analysis:
- B: Too narrow; reviewers'' praise is a setup detail.
- C: Reverses her stated preference for the manifest.
- D: No evidence about other novelists.', 'Where did the vivid detail actually come from, according to the text?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f5e13106-dd50-46a2-8ecd-ab50acd60b34', 'Which choice best states the main idea of the text?', 'Glassmakers in medieval Venice guarded their techniques so jealously that the city confined them to a single island and forbade them to emigrate. This secrecy is often cited as the reason Venetian glass dominated Europe for centuries. Yet records suggest the isolation cut both ways. Cut off from foreign workshops, Venetian artisans grew slow to adopt innovations developed elsewhere, and rivals who lured away even one defecting craftsman could leapfrog generations of guarded progress. The very walls meant to protect the trade eventually helped it stagnate. What looked like an unbreakable advantage carried, within it, the seeds of decline.', NULL, '[{"id":"A","text":"The secrecy that protected Venetian glassmaking also isolated it, eventually contributing to its decline.","is_correct":true,"explanation":"Correct: it captures the double-edged effect of secrecy that the text develops."},{"id":"B","text":"Venice confined its glassmakers to a single island and forbade them to emigrate.","is_correct":false,"explanation":"Too narrow; this is the opening detail, not the main idea."},{"id":"C","text":"Secrecy was the sole reason Venetian glass dominated Europe for centuries.","is_correct":false,"explanation":"Captures only the view the text complicates, ignoring the downside."},{"id":"D","text":"Rival workshops never managed to lure away Venetian craftsmen.","is_correct":false,"explanation":"Contradicts the text, which mentions ''a defecting craftsman.''"}]'::jsonb, 'A', 'Step 1 — Find the reversal
The isolation backfired, as {{yellow:The very walls meant to protect the trade eventually helped it stagnate}}.
Step 2 — Synthesize
The passage shows secrecy as both a protection and a cause of decline, which A unifies.
Distractor analysis:
- B: Too narrow; one historical detail.
- C: States only the view the text qualifies.
- D: Contradicts the mention of a defecting craftsman.', 'Secrecy helped at first, but the text shows another consequence.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5db0acb6-baa1-4183-ba60-0fb3a1395eda', 'Which choice best states the main idea of the text?', 'A common gardening belief holds that watering plants at midday harms them, because droplets on leaves act like lenses that focus sunlight and scorch the tissue. Botanists tested this by misting leaves under bright sun and examining them afterward. On smooth, flat leaves, the water spread too thin and evaporated before any damage occurred. Only on a few hairy-leaved species, where droplets perched high above the surface like beads, did faint burns appear. The researchers concluded that the warning is not wholly false but vastly overstated: for most garden plants, midday watering wastes water through evaporation far more than it ever endangers the leaves.', NULL, '[{"id":"A","text":"Testing showed that leaf scorching from midday watering is rare and the common warning is exaggerated for most plants.","is_correct":true,"explanation":"Correct: it captures the qualified finding that the warning is overstated though not entirely false."},{"id":"B","text":"Water droplets never cause any damage to plant leaves in sunlight.","is_correct":false,"explanation":"Overstates the text, which found faint burns on hairy-leaved species."},{"id":"C","text":"Hairy-leaved species are more common in gardens than smooth-leaved ones.","is_correct":false,"explanation":"No evidence; the text makes no claim about how common each type is."},{"id":"D","text":"Botanists misted leaves under bright sun and examined them afterward.","is_correct":false,"explanation":"Too narrow; this describes the method, not the conclusion."}]'::jsonb, 'A', 'Step 1 — Read the conclusion
The researchers found the warning {{yellow:not wholly false but vastly overstated}}.
Step 2 — Synthesize
The evidence (damage only on a few hairy-leaved species) supports a qualified verdict, which A states without overreaching.
Distractor analysis:
- B: Overstates ''never,'' ignoring the hairy-leaf burns.
- C: No evidence about prevalence of leaf types.
- D: Too narrow; describes the method only.', 'The botanists neither fully confirm nor fully reject the belief.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4902c01a-87d3-4cb7-b500-150b04b61db3', 'Which choice best states the main idea of the text?', 'When archaeologists unearthed a 3,000-year-old kitchen in the Andes, they expected to find traces of a single staple crop. Instead, residue scraped from cooking pots revealed a surprising mix: potatoes, quinoa, beans, and wild seeds, often combined in one vessel. Such variety suggests the household was not relying on any one food but spreading risk across many. In a region prone to frost, drought, and blight, a failure of one crop need not mean famine if several others filled the pot. The pots, in other words, record not just a menu but a strategy for surviving an unpredictable mountain climate.', NULL, '[{"id":"A","text":"The mixed food residue suggests the household diversified its crops as a way to survive an unpredictable climate.","is_correct":true,"explanation":"Correct: it links the varied residue to the risk-spreading survival strategy the text emphasizes."},{"id":"B","text":"Archaeologists expected to find traces of a single staple crop.","is_correct":false,"explanation":"Too narrow; this is the setup expectation, not the conclusion."},{"id":"C","text":"Andean households preferred potatoes above all other foods.","is_correct":false,"explanation":"No evidence; the text lists several foods without ranking them."},{"id":"D","text":"Frost, drought, and blight rarely affected Andean crops.","is_correct":false,"explanation":"Contradicts the text, which calls the region ''prone to'' these hazards."}]'::jsonb, 'A', 'Step 1 — Tie residue to purpose
The pots show that {{yellow:the household was not relying on any one food but spreading risk across many}}.
Step 2 — Synthesize
The variety plus the harsh climate point to diversification as a survival strategy, which A captures.
Distractor analysis:
- B: Too narrow; only the initial expectation.
- C: No evidence ranking potatoes highest.
- D: Contradicts ''prone to frost, drought, and blight.''', 'Connect the variety of foods to the harsh climate the text describes.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3acc2c41-add9-4196-9ecc-ba4f918dbdd7', 'Which choice best states the main idea of the text?', 'Early film critics dismissed close-ups as a crude trick, a way to startle audiences with a giant face. The director Lena Marsh argued otherwise. A close-up, she insisted, was not louder but quieter: by removing the surrounding room, it forced viewers to read a flicker of doubt or a held breath they would miss in a wide shot. Her films lingered on hands twisting a glove, on eyes glancing away. Reviewers who had called the technique vulgar began to describe her work as unusually intimate. The close-up, in Marsh''s hands, became a tool not for spectacle but for revealing what characters tried to hide.', NULL, '[{"id":"A","text":"Marsh reconceived the close-up as a subtle means of revealing hidden emotion rather than a device for spectacle.","is_correct":true,"explanation":"Correct: it captures Marsh''s redefinition of the close-up against the dismissive early view."},{"id":"B","text":"Early critics were correct that close-ups were merely a crude trick.","is_correct":false,"explanation":"Contradicts the text, which sides with Marsh against that view."},{"id":"C","text":"Marsh''s films often lingered on hands twisting a glove.","is_correct":false,"explanation":"Too narrow; an example, not the main idea."},{"id":"D","text":"Wide shots reveal a character''s emotions better than close-ups do.","is_correct":false,"explanation":"Reverses the text, which says viewers miss subtle cues in a wide shot."}]'::jsonb, 'A', 'Step 1 — Find Marsh''s claim
Marsh held that a close-up {{yellow:forced viewers to read a flicker of doubt or a held breath they would miss in a wide shot}}.
Step 2 — Synthesize
The text contrasts the ''crude trick'' view with Marsh''s use of the close-up to reveal hidden feeling, which A states.
Distractor analysis:
- B: Contradicts the text''s endorsement of Marsh.
- C: Too narrow; one example shot.
- D: Reverses the claim about wide shots.', 'How did Marsh redefine a technique others dismissed?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a07e08ec-d51a-4ae1-8b2d-ee0dd7ae467d', 'Which choice best states the main idea of the text?', 'For decades, economists assumed that giving rural families cash would simply be spent on immediate needs, leaving no lasting gain. A long-term study in one province tells a more nuanced story. Families who received small unconditional grants did spend much on food and medicine at first. But many also bought tools, seeds, or a single animal that, over years, generated steadier income. By the study''s end, recipient households earned more on average than non-recipients, though the gap varied widely and a minority saw no improvement at all. The data neither confirm the old skepticism nor support sweeping promises, urging instead a measured view.', NULL, '[{"id":"A","text":"A long-term study found that cash grants often produced lasting income gains, though results varied, supporting a measured rather than extreme view.","is_correct":true,"explanation":"Correct: it captures both the overall gains and the variation, matching the text''s call for a measured view."},{"id":"B","text":"Cash grants improved the income of every recipient household.","is_correct":false,"explanation":"Overstates the text, which notes a minority saw no improvement."},{"id":"C","text":"Recipient families spent much of their grants on food and medicine at first.","is_correct":false,"explanation":"Too narrow; one detail of how funds were initially used."},{"id":"D","text":"Economists'' old assumption that grants yield no lasting gain was fully confirmed.","is_correct":false,"explanation":"Contradicts the text, which says the data do not confirm the old skepticism."}]'::jsonb, 'A', 'Step 1 — Read the balanced verdict
The text states the data {{yellow:neither confirm the old skepticism nor support sweeping promises, urging instead a measured view}}.
Step 2 — Synthesize
With average gains but wide variation, A reflects both the positive effect and its limits.
Distractor analysis:
- B: Overstates; a minority saw no gain.
- C: Too narrow; initial spending only.
- D: Contradicts the rejection of the old skepticism.', 'The findings fall between full confirmation and sweeping success.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cfaa4347-82e5-4496-b120-7e540c84b51b', 'Which choice best states the main idea of the text?', 'The poet Idris Okonkwo wrote almost entirely at dawn, claiming the half-light suited his subjects. His poems return again and again to thresholds: a door left ajar, a tide neither rising nor falling, a child no longer young but not yet grown. Critics first read these images as mere mood. Later scholars argued they form the core of his vision, a fascination with moments of transition when one state has not quite ended and the next has not begun. To Okonkwo, such in-between moments were not empty waiting but the truest part of any change, the hinge on which everything turns.', NULL, '[{"id":"A","text":"Okonkwo''s poetry centers on moments of transition, which he saw as the most meaningful part of any change.","is_correct":true,"explanation":"Correct: it captures the recurring threshold imagery and Okonkwo''s view of its importance."},{"id":"B","text":"Okonkwo wrote almost entirely at dawn because the half-light suited his subjects.","is_correct":false,"explanation":"Too narrow; this habit is a detail, not the central idea."},{"id":"C","text":"Critics have always agreed about the meaning of Okonkwo''s images.","is_correct":false,"explanation":"Contradicts the text, which contrasts early and later readings."},{"id":"D","text":"Okonkwo regarded in-between moments as empty periods of waiting.","is_correct":false,"explanation":"Reverses the text, which says they were ''not empty waiting.''"}]'::jsonb, 'A', 'Step 1 — Identify the recurring subject
Okonkwo prized {{yellow:moments of transition when one state has not quite ended and the next has not begun}}.
Step 2 — Synthesize
The threshold imagery plus his valuing of these moments make transition the core of his vision, which A states.
Distractor analysis:
- B: Too narrow; his writing schedule.
- C: Contradicts the early-versus-later critical shift.
- D: Reverses ''not empty waiting.''', 'What do the door, the tide, and the child have in common for Okonkwo?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('75fd8a77-2ced-4fa4-a272-12dd2f939ba4', 'According to the text, how does a desert ant find its way directly back to the nest?', 'When a desert ant leaves its nest to forage, it wanders a twisting path in search of food. Yet once it finds a crumb, it heads almost straight home. Scientists wondered how the ant tracks its position without landmarks on the bare sand. Experiments revealed two tools working together. The ant counts its steps, giving a rough sense of distance, and reads the pattern of polarized light in the sky to keep its bearings. Neither cue alone would suffice, but combined they let the ant calculate a direct return. The insect, in effect, carries a built-in navigator stitched together from its legs and its eyes.', NULL, '[{"id":"A","text":"By combining a count of its steps with readings of polarized light in the sky.","is_correct":true,"explanation":"Correct: the text says both cues work together to enable a direct return."},{"id":"B","text":"By memorizing landmarks scattered across the desert sand.","is_correct":false,"explanation":"Contradicts the text, which notes the sand has no landmarks."},{"id":"C","text":"By counting its steps alone to measure the distance traveled.","is_correct":false,"explanation":"Too narrow; the text says neither cue alone would suffice."},{"id":"D","text":"By retracing the exact twisting path it followed while foraging.","is_correct":false,"explanation":"Contradicts the text, which says it heads almost straight home."}]'::jsonb, 'A', 'Step 1 — Find the mechanism
The text explains the ant {{yellow:counts its steps, giving a rough sense of distance, and reads the pattern of polarized light in the sky to keep its bearings}}.
Step 2 — Synthesize
Because the text adds that neither cue alone suffices, the direct return depends on both together, which A states.
Distractor analysis:
- B: Contradicts the absence of landmarks on bare sand.
- C: Too narrow; step-counting alone is insufficient.
- D: Contradicts the ''almost straight home'' return.', 'The text names two cues and stresses that one alone is not enough.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9702d639-a93d-48f9-9b74-86b43b7e2f8f', 'Which choice best states the main idea of the text?', 'In many coral reefs, certain small fish known as cleaner wrasses set up stations where larger fish gather to have parasites removed from their skin. Researchers once assumed the larger fish simply tolerated this service. Recent observation, however, suggests the relationship is more deliberate: client fish appear to remember which wrasses provide thorough cleanings and return preferentially to those individuals, while wrasses, in turn, sometimes give favored clients faster service to keep them coming back. The arrangement, then, resembles less a passive convenience than an ongoing negotiation in which both partners adjust their behavior based on the other''s reliability.', NULL, '[{"id":"A","text":"The cleaning relationship between wrasses and larger fish involves active, mutual adjustment rather than passive tolerance.","is_correct":true,"explanation":"Correct: it captures the text''s synthesis that both partners deliberately adjust behavior, not merely tolerate one another."},{"id":"B","text":"Cleaner wrasses remove parasites from larger fish at stations within coral reefs.","is_correct":false,"explanation":"Too narrow: this states only one factual detail and omits the central point about mutual negotiation."},{"id":"C","text":"Researchers frequently revise their assumptions about marine animal behavior.","is_correct":false,"explanation":"Too broad: the text concerns one specific relationship, not a general claim about research revisions."},{"id":"D","text":"Larger fish dominate cleaner wrasses by demanding faster service at cleaning stations.","is_correct":false,"explanation":"Contradiction: the text describes reciprocal adjustment, not domination by larger fish."}]'::jsonb, 'A', 'Step 1 — Locate the synthesis
The text concludes that the arrangement {{yellow:resembles less a passive convenience than an ongoing negotiation in which both partners adjust their behavior based on the other''s reliability}}.
Step 2 — Match the main idea
Because both partners adjust behavior reciprocally, the main idea is mutual, active adjustment rather than passive tolerance, which matches A.
Distractor analysis:
- B: Too narrow; it restates a single setup detail and ignores the negotiation theme.
- C: Too broad; it generalizes to all research rather than this specific relationship.
- D: Contradiction; the text emphasizes mutual adjustment, not domination.', 'Look at the final sentence''s contrast between ''passive convenience'' and ''negotiation.''', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('03b1aa99-73c3-4725-9b06-2baa983bb262', 'Which choice best states the main idea of the text?', 'The novelist Edith Vance kept two desks. At one, near the window, she drafted quickly, filling pages with scenes she would later call "noise"—dialogue, weather, the clatter of incident. At the second desk, set in a windowless alcove, she revised in near silence, cutting whatever did not serve the book''s quiet center. Friends who visited assumed the bright desk was where the real work happened. Vance disagreed. The window desk, she said, only gathered raw material; the book itself was made in the dark room, where she decided what the noise had been about.', NULL, '[{"id":"A","text":"For Vance, the essential creative work lay in revision, where raw drafting acquired its meaning.","is_correct":true,"explanation":"Correct: it synthesizes Vance''s claim that the dark revising desk, not the drafting desk, was where the book was truly made."},{"id":"B","text":"Vance preferred working near windows because natural light improved her drafting.","is_correct":false,"explanation":"Contradiction: Vance valued the windowless room more, calling the window desk merely a gatherer of raw material."},{"id":"C","text":"Vance''s friends frequently misunderstood the routines of professional novelists.","is_correct":false,"explanation":"No-evidence synthesis: the text mentions one assumption by friends, not a general pattern of misunderstanding."},{"id":"D","text":"Vance produced an unusually large quantity of dialogue and descriptive detail in her drafts.","is_correct":false,"explanation":"True but irrelevant: the volume of drafted ''noise'' is a detail, not the central contrast the text develops."}]'::jsonb, 'A', 'Step 1 — Find Vance''s distinction
Vance says the window desk only gathered raw material, while {{yellow:the book itself was made in the dark room, where she decided what the noise had been about}}.
Step 2 — Derive the main idea
That statement locates the essential work in revision, where drafting gains meaning, which matches A.
Distractor analysis:
- B: Contradiction; she downplays the window desk rather than preferring it.
- C: No-evidence; one assumption by friends does not support a general claim.
- D: True but irrelevant; the amount of drafting is incidental to the revision point.', 'Where does Vance say the book is actually ''made''?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4fc89b06-3205-41f7-83e4-215bf16d13a3', 'Which choice best states the main idea of the text?', 'When archaeologists excavated the ancient port of Tharros, they found warehouses stocked with goods from across the Mediterranean: Egyptian glass, Iberian metals, Greek pottery. Earlier scholars treated such finds as proof that Tharros was simply a wealthy consumer of foreign luxuries. A reexamination of the warehouse records, inscribed on clay tags, tells a different story. Many goods were logged as inbound and then, weeks later, logged as outbound to other ports. Tharros, it appears, was less a destination for these items than a hinge—a place where cargoes were gathered, sorted, and sent onward.', NULL, '[{"id":"A","text":"Evidence from clay tags indicates Tharros functioned mainly as a hub redistributing goods rather than consuming them.","is_correct":true,"explanation":"Correct: it synthesizes the warehouse records showing goods moving onward, recasting Tharros as a transshipment hinge."},{"id":"B","text":"Tharros imported Egyptian glass, Iberian metals, and Greek pottery from across the Mediterranean.","is_correct":false,"explanation":"Too narrow: this lists imported goods but misses the central reinterpretation of the city''s role."},{"id":"C","text":"Earlier scholars were correct that Tharros was a wealthy consumer of foreign luxuries.","is_correct":false,"explanation":"Contradiction: the text overturns the earlier view by showing goods were sent onward."},{"id":"D","text":"Clay tags are among the most reliable sources for reconstructing ancient trade.","is_correct":false,"explanation":"No-evidence synthesis: the text uses one set of tags as evidence but makes no general claim about tag reliability."}]'::jsonb, 'A', 'Step 1 — Identify the revised role
The records show goods logged inbound then outbound, so Tharros was {{yellow:less a destination for these items than a hinge—a place where cargoes were gathered, sorted, and sent onward}}.
Step 2 — Connect to main idea
That establishes Tharros as a redistribution hub rather than a consumer, matching A.
Distractor analysis:
- B: Too narrow; it lists imports without the reinterpretation.
- C: Contradiction; the text refutes the consumer view.
- D: No-evidence; reliability of tags in general is never claimed.', 'Trace what the clay tags reveal about goods leaving Tharros.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7fe007f0-76bc-406c-a305-05e7859ce81a', 'Which choice best states the main idea of the text?', 'A common assumption holds that plants compete relentlessly for sunlight, each leaf angling to overshadow its neighbors. Studies of certain forest canopies complicate this picture. In some species, the outermost branches of neighboring trees stop growing just short of touching, leaving thin channels of sky between crowns—a pattern called crown shyness. Researchers propose that by halting growth at these boundaries, trees reduce the abrasion of branches rubbing in wind and limit the spread of leaf-eating insects between crowns. The gaps, then, may reflect not failed competition but a restraint that benefits each tree.', NULL, '[{"id":"A","text":"Crown shyness suggests that some trees benefit by limiting their own growth rather than competing for every bit of light.","is_correct":true,"explanation":"Correct: it synthesizes the proposed benefits of restraint that complicate the relentless-competition assumption."},{"id":"B","text":"Plants compete relentlessly for sunlight, with each leaf overshadowing its neighbors.","is_correct":false,"explanation":"Contradiction: the text presents crown shyness as a complication to this very assumption."},{"id":"C","text":"Leaf-eating insects spread easily between the crowns of neighboring forest trees.","is_correct":false,"explanation":"Reverse: the text says crown shyness limits, not eases, the spread of such insects."},{"id":"D","text":"Researchers have fully explained why gaps form between the crowns of neighboring trees.","is_correct":false,"explanation":"Too strong: the text says researchers ''propose'' explanations and uses ''may,'' not a settled account."}]'::jsonb, 'A', 'Step 1 — Find the reframing
The text concludes the gaps {{yellow:may reflect not failed competition but a restraint that benefits each tree}}.
Step 2 — State the main idea
That reframes growth-limiting behavior as beneficial, complicating pure competition, which matches A.
Distractor analysis:
- B: Contradiction; this is the assumption the text complicates.
- C: Reverse; crown shyness limits insect spread.
- D: Too strong; explanations are proposed and tentative.', 'What does the last sentence say the gaps ''may reflect''?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e07dc0cb-cdb8-42b0-adad-933f6eb5a67a', 'Which choice best states the main idea of the text?', 'During the 1850s, the city of Manchester faced repeated outbreaks of disease traced to its crowded districts. The council''s first response was to widen a few central streets, reasoning that better air circulation would improve health. The outbreaks continued. A young engineer named Hartley argued that the real problem lay underground, in shared cesspools that leaked into wells. His proposal to build separate drainage met resistance: it was costly and invisible, unlike a grand boulevard. Only after a particularly severe outbreak did the council fund the drains. Within a few years, the recurring epidemics had largely subsided.', NULL, '[{"id":"A","text":"Manchester''s health problems eased only once the city addressed hidden drainage rather than visible street improvements.","is_correct":true,"explanation":"Correct: it synthesizes the contrast between ineffective street-widening and the eventually funded drainage that ended outbreaks."},{"id":"B","text":"The Manchester council widened several central streets to improve air circulation.","is_correct":false,"explanation":"Too narrow: this is the failed first response, not the text''s overall point about what actually worked."},{"id":"C","text":"Engineer Hartley faced resistance because his drainage plan was costly and invisible.","is_correct":false,"explanation":"True but partial: it captures one obstacle but misses the resolution and main contrast."},{"id":"D","text":"Severe disease outbreaks were common in industrial cities throughout the 1850s.","is_correct":false,"explanation":"Too broad: the text concerns Manchester specifically, not industrial cities generally."}]'::jsonb, 'A', 'Step 1 — Trace the resolution
After the council funded the drains, {{yellow:the recurring epidemics had largely subsided}}, whereas street-widening had failed.
Step 2 — Build the main idea
The contrast shows the problem eased only when hidden drainage, not visible streets, was addressed, matching A.
Distractor analysis:
- B: Too narrow; this is the failed first step.
- C: True but partial; it names one obstacle, not the outcome.
- D: Too broad; the passage is about Manchester.', 'Compare what the council tried first with what finally worked.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ebac5899-3ed8-4954-8203-5f15d2dff7f9', 'According to the text, what does the waggle dance communicate beyond a food source''s location?', 'Honeybees returning to the hive perform looping movements often called a "waggle dance," long understood to encode the direction and distance of food. Yet not every dance leads nestmates to fly out. In recent experiments, bees that had recently found a rich source danced vigorously, while those reporting a meager or distant source danced briefly or stopped early. Observers within the hive appeared to weigh these differences, following energetic dances more readily. The dance, researchers conclude, conveys not only where food is but also how strongly the dancer recommends pursuing it.', NULL, '[{"id":"A","text":"How strongly the dancing bee recommends that nestmates pursue the food.","is_correct":true,"explanation":"Correct: the text states the dance conveys how strongly the dancer recommends pursuing the food."},{"id":"B","text":"The exact species of flower the food was gathered from.","is_correct":false,"explanation":"No evidence: the text never mentions flower species being encoded."},{"id":"C","text":"The number of bees already gathered at the food source.","is_correct":false,"explanation":"No evidence: the text addresses dance vigor, not counts of bees at the source."},{"id":"D","text":"Whether predators are present near the food source.","is_correct":false,"explanation":"No evidence: predators are not discussed anywhere in the text."}]'::jsonb, 'A', 'Step 1 — Locate the added information
The text concludes the dance conveys {{yellow:not only where food is but also how strongly the dancer recommends pursuing it}}.
Step 2 — Match the detail
That directly states the dance signals the strength of the dancer''s recommendation, matching A.
Distractor analysis:
- B: No evidence; flower species is never mentioned.
- C: No evidence; the text discusses vigor, not bee counts.
- D: No evidence; predators are not referenced.', 'Read the final sentence for what the dance conveys ''also.''', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f0fe3e34-fe0a-41d3-a10a-4328f0503682', 'Which choice best states the main idea of the text?', 'The poet Mara Olin distrusted the word "inspiration." In interviews she described her composing process as a kind of patient assembling: she would collect overheard phrases, odd facts, and broken images in notebooks for months, rarely knowing what they were for. Only when she noticed two unrelated fragments resonating—a line about tide tables beside one about a grandmother''s debts—would a poem begin to form. The image of the poet struck by sudden vision, she insisted, misrepresented her work, which depended far less on lightning than on the slow accumulation of materials waiting to be connected.', NULL, '[{"id":"A","text":"Olin viewed her poems as products of slow accumulation and connection rather than sudden inspiration.","is_correct":true,"explanation":"Correct: it synthesizes her rejection of ''lightning'' in favor of patient assembling and connecting fragments."},{"id":"B","text":"Olin filled notebooks with overheard phrases, odd facts, and broken images.","is_correct":false,"explanation":"Too narrow: this is one step in her process, not the central contrast she draws."},{"id":"C","text":"Olin believed poets are most productive when struck by sudden vision.","is_correct":false,"explanation":"Contradiction: she insisted that image misrepresented her work."},{"id":"D","text":"Olin avoided discussing her creative process in interviews.","is_correct":false,"explanation":"Contradiction: the text says she described her process in interviews."}]'::jsonb, 'A', 'Step 1 — Find the rejected image
Olin said her work depended {{yellow:far less on lightning than on the slow accumulation of materials waiting to be connected}}.
Step 2 — State the main idea
That frames her poems as products of accumulation and connection, not inspiration, matching A.
Distractor analysis:
- B: Too narrow; collecting is just one step.
- C: Contradiction; she rejects the sudden-vision image.
- D: Contradiction; she described her process in interviews.', 'Note the contrast between ''lightning'' and ''slow accumulation.''', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a96b0354-e1ee-4e24-8b19-6aed686b81c1', 'Which choice best states the main idea of the text?', 'Economists studying nineteenth-century railway towns have often credited a town''s growth to its position on a main line. The town of Aldermere complicates that view. Though it sat on a busy route, it grew slowly for decades. Records show that nearly all trains passed through without stopping, since the line''s owners had placed Aldermere''s station at an awkward grade where stopping was costly. Only after a rival company built a flatter spur did regular stops begin, and the town expanded. Mere position on a line, the case suggests, mattered less than whether trains had reason to halt.', NULL, '[{"id":"A","text":"Aldermere''s growth depended less on lying on a main line than on whether trains actually stopped there.","is_correct":true,"explanation":"Correct: it synthesizes the case showing position mattered less than the practical reason for trains to halt."},{"id":"B","text":"Aldermere sat on a busy nineteenth-century railway route.","is_correct":false,"explanation":"Too narrow: this single fact ignores the central point about stopping versus mere position."},{"id":"C","text":"A town''s position on a main railway line reliably determined its growth.","is_correct":false,"explanation":"Contradiction: Aldermere is offered as a case that complicates this view."},{"id":"D","text":"Rival railway companies frequently competed by building flatter spurs.","is_correct":false,"explanation":"No-evidence synthesis: one rival''s spur is mentioned, not a general pattern of competition."}]'::jsonb, 'A', 'Step 1 — Find the conclusion
The case suggests that {{yellow:Mere position on a line, the case suggests, mattered less than whether trains had reason to halt}}.
Step 2 — State the main idea
That establishes stopping, not position, as the key to Aldermere''s growth, matching A.
Distractor analysis:
- B: Too narrow; being on a busy route is just setup.
- C: Contradiction; the text complicates this claim.
- D: No-evidence; one spur is not a general pattern.', 'What does the final sentence say ''mattered less'' than what?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('854503af-a13d-4348-a333-af97aa461ebf', 'Which choice best states the main idea of the text?', 'In the high deserts of the Andes, certain plants called yaretas grow in dense, dome-shaped cushions that can be centuries old. To a casual eye, a yareta looks like a single mossy boulder. In fact, the cushion is made of thousands of tiny stems pressed so tightly together that wind cannot penetrate and heat is trapped within. This packing lets the plant survive temperatures that would kill its scattered relatives. What appears to be one solid mass, then, is really a multitude of stems whose crowding is the very thing that keeps them alive.', NULL, '[{"id":"A","text":"The yareta survives harsh conditions because its many tightly packed stems trap heat and block wind.","is_correct":true,"explanation":"Correct: it synthesizes that the crowded multitude of stems, not a single mass, enables survival."},{"id":"B","text":"A yareta looks like a single mossy boulder to a casual observer.","is_correct":false,"explanation":"True but partial: this appearance is contrasted with the reality, which is the actual point."},{"id":"C","text":"Yaretas can live for several centuries in the high Andes.","is_correct":false,"explanation":"True but irrelevant: longevity is a detail, not the central mechanism the text explains."},{"id":"D","text":"The yareta''s scattered relatives are better adapted to extreme cold.","is_correct":false,"explanation":"Contradiction: the text says scattered relatives would be killed by such temperatures."}]'::jsonb, 'A', 'Step 1 — Find the explanation
The text says the cushion''s stems are so tightly packed that {{yellow:wind cannot penetrate and heat is trapped within}}, enabling survival.
Step 2 — State the main idea
That crowding of many stems is what keeps the plant alive, matching A.
Distractor analysis:
- B: True but partial; the boulder look is the appearance, not the point.
- C: True but irrelevant; longevity is incidental.
- D: Contradiction; scattered relatives would die.', 'Why does the packing of stems matter for survival?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0832fbfa-692b-43cb-86aa-392e9183e60f', 'Which choice best states the main idea of the text?', 'When the composer Lavinia Reyes premiered her symphony, critics praised its dramatic final movement and largely ignored the quiet opening. Reyes found this frustrating. In her notes, she explained that the opening''s hushed, repetitive figures were not an introduction to be hurried past but the seed from which every later theme grew, including the celebrated finale. To hear the ending as the work''s true achievement, she argued, was to mistake the harvest for the planting. The loud movement that audiences remembered owed its power entirely to the soft material they overlooked.', NULL, '[{"id":"A","text":"Reyes maintained that her symphony''s admired finale depended on the quiet opening that listeners overlooked.","is_correct":true,"explanation":"Correct: it synthesizes her claim that the soft opening was the seed for the powerful finale."},{"id":"B","text":"Critics praised the dramatic final movement of Reyes''s symphony.","is_correct":false,"explanation":"True but partial: this is the situation Reyes pushes back against, not her central point."},{"id":"C","text":"Reyes believed audiences should ignore a symphony''s opening movements.","is_correct":false,"explanation":"Contradiction: she argued the opening was essential, not something to ignore."},{"id":"D","text":"Most critics misjudge the symphonies composers consider their finest work.","is_correct":false,"explanation":"Too broad: the text concerns one work, not a general pattern of critical misjudgment."}]'::jsonb, 'A', 'Step 1 — Find Reyes''s claim
Reyes said the loud finale {{yellow:owed its power entirely to the soft material they overlooked}}.
Step 2 — State the main idea
That ties the admired finale to the overlooked quiet opening, matching A.
Distractor analysis:
- B: True but partial; critics'' praise is the setup she resists.
- C: Contradiction; she values the opening.
- D: Too broad; only one work is discussed.', 'What does the last sentence say the loud movement ''owed its power'' to?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f996482c-3ed8-4ae0-95fb-0c878ed03083', 'Which choice best states the main idea of the text?', 'Historians once described the medieval guild chiefly as a body that fixed prices and restricted who could practice a trade. Documents from the weavers'' guild of Lille suggest a fuller role. Alongside rules on pricing, the records detail funds set aside for members who fell ill, dowries provided for the daughters of deceased weavers, and payments for the funerals of the poor. The guild, these records imply, was not only an instrument of economic control but also a network of mutual support, binding its members through obligations that reached well beyond the workshop.', NULL, '[{"id":"A","text":"Records from Lille suggest the weavers'' guild served as a mutual-support network, not merely a tool of economic control.","is_correct":true,"explanation":"Correct: it synthesizes the social-welfare records that broaden the guild''s role beyond price-fixing."},{"id":"B","text":"The weavers'' guild of Lille fixed prices and restricted who could practice the trade.","is_correct":false,"explanation":"Too narrow: this is the older view the text expands, not the main point."},{"id":"C","text":"Medieval guilds provided dowries for the daughters of all townspeople.","is_correct":false,"explanation":"Too broad: dowries were provided for daughters of deceased weavers, not all townspeople."},{"id":"D","text":"Historical records of medieval trade are usually incomplete and unreliable.","is_correct":false,"explanation":"No-evidence synthesis: the text never comments on the general reliability of such records."}]'::jsonb, 'A', 'Step 1 — Find the fuller role
The records imply the guild was {{yellow:not only an instrument of economic control but also a network of mutual support}}.
Step 2 — State the main idea
That broadens the guild''s role to include social support, matching A.
Distractor analysis:
- B: Too narrow; this is the older, partial view.
- C: Too broad; dowries went to weavers'' daughters specifically.
- D: No-evidence; record reliability is never discussed.', 'What does the closing sentence add beyond ''economic control''?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8130c2ec-f3ef-4db2-8b47-0485b72b5041', 'Which choice best states the main idea of the text?', 'Sleep researchers studying migratory songbirds noticed something puzzling: during long flights over open water, the birds never landed, yet they did not collapse from exhaustion. Tracking devices revealed that the birds slept in brief bursts of seconds, often with one half of the brain at a time. While one hemisphere rested, the other stayed alert enough to keep the bird aloft and on course. Far from forgoing sleep entirely during migration, the birds had simply divided it into fragments so small and so unevenly distributed that, from the outside, they appeared never to rest at all.', NULL, '[{"id":"A","text":"Migrating songbirds appear sleepless only because they sleep in tiny bursts, often resting one brain hemisphere at a time.","is_correct":true,"explanation":"Correct: it synthesizes the finding that fragmented, half-brain sleep explains their apparent sleeplessness."},{"id":"B","text":"Tracking devices have improved researchers'' understanding of bird migration generally.","is_correct":false,"explanation":"Too broad: the text concerns a specific sleep finding, not migration research overall."},{"id":"C","text":"Migrating songbirds forgo sleep entirely during long flights over open water.","is_correct":false,"explanation":"Contradiction: the text says they do not forgo sleep but divide it into fragments."},{"id":"D","text":"Songbirds keep both brain hemispheres fully alert throughout migration.","is_correct":false,"explanation":"Contradiction: the text says one hemisphere rests while the other stays alert."}]'::jsonb, 'A', 'Step 1 — Find the explanation
The text says the birds had {{yellow:divided it into fragments so small and so unevenly distributed that, from the outside, they appeared never to rest at all}}.
Step 2 — State the main idea
That fragmented, often half-brain sleep explains their apparent sleeplessness, matching A.
Distractor analysis:
- B: Too broad; the focus is the sleep finding.
- C: Contradiction; they do not forgo sleep.
- D: Contradiction; one hemisphere rests at a time.', 'Why do the birds only ''appear'' never to rest?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('eb82cef6-a433-4dd4-8142-0447f8d9e5c9', 'Which choice best states the main idea of the text?', 'Marine biologist Dr. Lena Ortiz studies bioluminescent plankton, organisms that emit light when disturbed. For years, scientists assumed this glow served only to startle predators. Ortiz''s recent work complicates that view. She found that the light also attracts larger predators, which then consume the plankton''s original attacker. In other words, the glow does not merely frighten an enemy; it summons a more powerful ally. This finding suggests that a single trait can function in multiple, even surprising, ways within an ecosystem, and that scientists must remain cautious about assigning a single purpose to any biological feature.', NULL, '[{"id":"A","text":"Ortiz''s research reveals that a biological trait once thought to have one purpose may actually serve more than one function.","is_correct":true,"explanation":"Correct: it captures the synthesis that the glow both startles attackers and summons allies, leading to the broader claim about multiple functions."},{"id":"B","text":"Bioluminescent plankton emit light only as a way to startle the predators that threaten them.","is_correct":false,"explanation":"Reverse: the text explicitly complicates and goes beyond this earlier assumption."},{"id":"C","text":"Dr. Ortiz has spent many years studying the behavior of various marine organisms.","is_correct":false,"explanation":"Too narrow and true-but-irrelevant; it ignores the central finding about multiple functions."},{"id":"D","text":"Larger predators in the ocean rely primarily on plankton''s glow to locate their prey.","is_correct":false,"explanation":"No-evidence overstatement; the text never claims this is how large predators primarily hunt."}]'::jsonb, 'A', 'Step 1 — Find the synthesis
The passage states that the glow does not merely frighten an enemy but instead {{yellow:summons a more powerful ally}}, showing the trait has more than one role.
Step 2 — Match the main idea
Because a single trait both startles and recruits help, the text concludes scientists must avoid assigning one purpose to a feature, which choice A captures.
Distractor analysis:
- B: Reverses the point by restating the outdated single-purpose assumption the text corrects.
- C: Too narrow; it describes Ortiz''s career rather than the discovery''s significance.
- D: No evidence; the text never says large predators primarily hunt via the glow.', 'Look for the sentence that generalizes beyond the single experiment about traits having multiple functions.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('16264841-9abc-4196-ba8d-562d80952913', 'Which choice best states the main idea of the text?', 'In the 1850s, the city of London faced repeated cholera outbreaks that most officials blamed on "miasma," or foul air. Physician John Snow doubted this explanation. By mapping the homes of victims, he traced one outbreak to a single contaminated water pump. Yet authorities resisted his conclusion for years, partly because the miasma theory aligned with longstanding beliefs and partly because accepting a waterborne cause demanded costly changes to the city''s infrastructure. Snow''s careful evidence eventually prevailed, but the delay illustrates how entrenched assumptions and practical costs can slow the acceptance of a correct scientific idea.', NULL, '[{"id":"A","text":"Snow''s mapping proved that cholera spread through foul air rather than contaminated water.","is_correct":false,"explanation":"Contradiction: Snow''s evidence pointed to water, not air."},{"id":"B","text":"Even a well-supported scientific conclusion can face delayed acceptance because of established beliefs and practical costs.","is_correct":true,"explanation":"Correct: it synthesizes Snow''s correct finding with the two stated reasons for resistance."},{"id":"C","text":"London suffered from many cholera outbreaks during the 1850s.","is_correct":false,"explanation":"Too narrow; it states only background context, not the central point."},{"id":"D","text":"John Snow created the first map ever used to study the spread of disease.","is_correct":false,"explanation":"No evidence; the text never claims this was the first such map."}]'::jsonb, 'B', 'Step 1 — Identify the resistance
The text says authorities resisted Snow''s conclusion because the miasma theory aligned with longstanding beliefs and accepting a waterborne cause {{yellow:demanded costly changes to the city''s infrastructure}}.
Step 2 — Match the main idea
Pairing Snow''s correct finding with these two obstacles yields the general lesson in choice B about delayed acceptance.
Distractor analysis:
- A: Contradicts the text; Snow argued for water, not air.
- C: Too narrow; outbreaks are setup, not the main point.
- D: No evidence; the text does not call it the first disease map.', 'The final sentence states the lesson the example is meant to illustrate.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1ca58339-fcab-431d-ada0-90e69f2f21e5', 'Which choice best states the main idea of the text?', 'The narrator had always pictured her grandmother''s village as a place of quiet poverty, a notion built from sepia photographs and her mother''s clipped stories. When she finally visited, the reality unsettled this image. The market hummed with color and argument; neighbors traded jokes she could not follow but whose warmth she felt. She realized that the silence she had imagined was not the village''s but her mother''s—a private grief that had nothing to do with the lively place itself. The village had never been what she thought; it had simply been described by someone carrying her own sorrow.', NULL, '[{"id":"A","text":"The narrator discovers that her impression of the village reflected her mother''s grief rather than the village''s actual character.","is_correct":true,"explanation":"Correct: it synthesizes the contrast between the imagined silence and the lively reality attributed to the mother''s sorrow."},{"id":"B","text":"The narrator finds that her grandmother''s village is exactly as poor and quiet as she had imagined.","is_correct":false,"explanation":"Contradiction: the visit unsettles and overturns that image."},{"id":"C","text":"The narrator enjoys visiting busy markets in unfamiliar places.","is_correct":false,"explanation":"Too narrow and irrelevant to the realization about her mother."},{"id":"D","text":"The narrator''s mother deliberately lied about the village to protect her daughter.","is_correct":false,"explanation":"No evidence; grief, not deliberate deception, is described."}]'::jsonb, 'A', 'Step 1 — Locate the realization
The narrator concludes the silence she imagined was not the village''s but {{yellow:her mother''s—a private grief that had nothing to do with the lively place itself}}.
Step 2 — Match the main idea
This shows her impression came from her mother''s sorrow rather than the real village, which choice A states.
Distractor analysis:
- B: Contradicts the text, which overturns the quiet-poverty image.
- C: Too narrow; it ignores the emotional discovery.
- D: No evidence; the mother carried grief, not a deliberate lie.', 'Notice what the narrator decides the imagined silence actually belonged to.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cbd12498-43c3-453b-88ed-cede23097eee', 'Which choice best states the main idea of the text?', 'Researchers studying urban crows have documented a striking ability: the birds recognize individual human faces and remember which people have treated them badly. More surprising, crows that never personally encountered a threatening person can still react with alarm to that face, apparently having learned of the danger from other crows. This suggests that information about specific threats can spread through a crow population socially, without each bird needing a direct experience. The finding pushes scientists to reconsider how complex social learning can be in animals once dismissed as merely clever scavengers.', NULL, '[{"id":"A","text":"Crows are skilled at finding food in cities because they scavenge in groups.","is_correct":false,"explanation":"True-but-irrelevant detail not supported as the main point; scavenging is mentioned only dismissively."},{"id":"B","text":"Crows can socially transmit knowledge of specific human threats, revealing unexpectedly complex social learning.","is_correct":true,"explanation":"Correct: it synthesizes face recognition and second-hand alarm into the broader claim about social learning."},{"id":"C","text":"Individual crows must personally experience a threat before they will react to a dangerous person.","is_correct":false,"explanation":"Contradiction: the text says crows react even without personal encounters."},{"id":"D","text":"Crows can remember human faces for the entirety of their long lives.","is_correct":false,"explanation":"No evidence; the text never specifies how long the memory lasts."}]'::jsonb, 'B', 'Step 1 — Identify the key transmission
Crows that never met a threatening person still react, {{yellow:apparently having learned of the danger from other crows}}.
Step 2 — Match the main idea
This second-hand learning supports the conclusion about unexpectedly complex social learning, which choice B captures.
Distractor analysis:
- A: True-but-irrelevant; scavenging is mentioned only to be reconsidered.
- C: Contradicts the finding that direct experience is unnecessary.
- D: No evidence about lifelong memory duration.', 'Focus on how crows learn about threats they never personally faced.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5efc8074-d37a-418e-b1fe-00778583373c', 'Which choice best states the main idea of the text?', 'During the Renaissance, the patronage system shaped what artists could create. A wealthy patron commissioned a work, specified its subject, and often dictated its size and materials. Some historians have portrayed artists as mere employees with little creative freedom. Yet surviving contracts and letters complicate this picture: many artists negotiated terms, subtly altered requested subjects, and built reputations that gave them leverage over future patrons. The relationship, then, was not simply one of master and servant but an ongoing negotiation in which both parties exercised influence, even if unequally.', NULL, '[{"id":"A","text":"Renaissance artists had no influence over the works they were commissioned to produce.","is_correct":false,"explanation":"Contradiction: the text shows artists exercised influence through negotiation."},{"id":"B","text":"Wealthy patrons during the Renaissance preferred large works made from expensive materials.","is_correct":false,"explanation":"Too narrow; this detail is not the central claim."},{"id":"C","text":"The patron-artist relationship was a two-way negotiation rather than simple control by patrons.","is_correct":true,"explanation":"Correct: it synthesizes patron demands with artists'' leverage into the negotiated-relationship claim."},{"id":"D","text":"Surviving contracts from the Renaissance are the most reliable source for studying art history.","is_correct":false,"explanation":"No evidence; the text uses contracts as evidence but makes no claim about their superiority."}]'::jsonb, 'C', 'Step 1 — Find the corrected view
The text concludes the relationship was {{yellow:not simply one of master and servant but an ongoing negotiation}} with mutual influence.
Step 2 — Match the main idea
This directly supports choice C''s description of a two-way negotiation rather than one-sided control.
Distractor analysis:
- A: Contradicts the evidence that artists negotiated and altered subjects.
- B: Too narrow; patron preferences are setup, not the point.
- D: No evidence ranking contracts as the most reliable source.', 'Look at how the final sentence redefines the patron-artist relationship.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b5350df7-4df7-4757-8785-290fb04e0edf', 'Which choice best states the main idea of the text?', 'A common assumption holds that adding more lanes to a congested highway will reduce traffic. Transportation researchers have repeatedly observed the opposite effect. When a highway is widened, the added capacity makes driving more convenient, which encourages more people to drive and to take longer trips. Within a few years, the expanded road often carries just as much congestion as before. This phenomenon, called induced demand, shows that the supply of road space can itself generate the very demand it was meant to relieve, frustrating efforts to engineer congestion away through expansion alone.', NULL, '[{"id":"A","text":"Expanding highways tends to attract additional driving, so the added lanes often fail to relieve congestion.","is_correct":true,"explanation":"Correct: it synthesizes the cause (convenience) and effect (more driving) into the induced-demand conclusion."},{"id":"B","text":"Drivers prefer to take longer trips whenever new highways are built.","is_correct":false,"explanation":"Too narrow; longer trips are one mechanism, not the overall point."},{"id":"C","text":"Widening a congested highway is the most effective way to reduce traffic.","is_correct":false,"explanation":"Contradiction: the text says the opposite effect occurs."},{"id":"D","text":"Transportation researchers disagree about whether congestion can be measured accurately.","is_correct":false,"explanation":"No evidence; no such disagreement about measurement is mentioned."}]'::jsonb, 'A', 'Step 1 — Identify induced demand
The text explains that road space {{yellow:can itself generate the very demand it was meant to relieve}}, undermining expansion as a fix.
Step 2 — Match the main idea
This means added lanes attract driving and fail to relieve congestion, exactly as choice A states.
Distractor analysis:
- B: Too narrow; longer trips are just one mechanism.
- C: Contradicts the documented opposite effect.
- D: No evidence of a measurement dispute.', 'The term ''induced demand'' summarizes why widening backfires.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bf9a92ce-243f-4b3a-be7f-0572a4ae3191', 'Which choice best states the main idea of the text?', 'The poet''s early notebooks reveal an artist at war with his own talent. He filled pages with vivid images, then crossed them out, scrawling in the margins that they were "too easy" or "merely pretty." Critics later praised the polished restraint of his published work, assuming it came naturally. The notebooks tell a different story: that restraint was hard-won, achieved only by suppressing a lush, instinctive style he distrusted. What readers admired as effortless simplicity was in fact the residue of a long struggle against his own first impulses.', NULL, '[{"id":"A","text":"The poet''s notebooks contain many vivid images he chose not to publish.","is_correct":false,"explanation":"Too narrow; this detail supports but does not state the main point."},{"id":"B","text":"The poet''s admired restraint resulted from a deliberate struggle against his natural lush style.","is_correct":true,"explanation":"Correct: it synthesizes the notebook evidence with the critics'' mistaken assumption."},{"id":"C","text":"Critics correctly recognized that the poet''s simple style came to him naturally.","is_correct":false,"explanation":"Contradiction: the notebooks show restraint was hard-won, not natural."},{"id":"D","text":"The poet preferred lush, ornate imagery over any kind of restraint.","is_correct":false,"explanation":"Reverse: he distrusted that style and suppressed it."}]'::jsonb, 'B', 'Step 1 — Find the contrast
The text says the admired restraint was {{yellow:hard-won, achieved only by suppressing a lush, instinctive style he distrusted}}.
Step 2 — Match the main idea
This shows the simplicity readers praised came from struggle, not nature, which choice B states.
Distractor analysis:
- A: Too narrow; unpublished images are evidence, not the point.
- C: Contradicts the notebooks'' revelation.
- D: Reverses his actual distrust of the lush style.', 'Compare what critics assumed with what the notebooks reveal.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8fb346f6-1961-42b2-b176-3f86546c9c0d', 'Which choice best states the main idea of the text?', 'For decades, economists treated farmers in developing regions as slow to adopt new technologies, attributing this to ignorance or resistance to change. Field studies have since revised that judgment. Researchers found that farmers frequently understood new seed varieties well but declined them because the seeds required expensive inputs, carried unfamiliar risks, or did not suit local soils. Far from being irrational holdouts, these farmers were making careful calculations about uncertainty and cost. The lesson is that behavior that looks like stubbornness from the outside may reflect rational responses to conditions outsiders fail to see.', NULL, '[{"id":"A","text":"Farmers in developing regions reject new technologies because they do not understand them.","is_correct":false,"explanation":"Contradiction: the text says farmers often understood the technologies well."},{"id":"B","text":"New seed varieties usually require expensive inputs that farmers cannot afford.","is_correct":false,"explanation":"Too narrow; cost is one factor, not the central claim."},{"id":"C","text":"What appears to be irrational resistance among farmers often reflects rational responses to real conditions.","is_correct":true,"explanation":"Correct: it synthesizes the field findings into the broader corrective lesson."},{"id":"D","text":"Economists have always understood the reasoning behind farmers'' technology choices.","is_correct":false,"explanation":"Contradiction: economists'' earlier judgment had to be revised."}]'::jsonb, 'C', 'Step 1 — Identify the corrected view
The text states that behavior looking like stubbornness {{yellow:may reflect rational responses to conditions outsiders fail to see}}.
Step 2 — Match the main idea
This generalizes the field findings into choice C''s claim that apparent resistance is often rational.
Distractor analysis:
- A: Contradicts the finding that farmers understood the technologies.
- B: Too narrow; cost is one of several factors.
- D: Contradicts the need to revise earlier judgments.', 'The closing sentence states the general lesson drawn from the field studies.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f0769757-6669-43b7-ba3d-a3c60c0f1d4c', 'According to the text, why do biologists call the desert tortoise a "keystone" species?', 'The desert tortoise survives brutal summers by digging burrows that stay cool and humid far below the surface. But these burrows do more than shelter their builders. Snakes, lizards, burrowing owls, and dozens of insect species shelter in abandoned or shared tortoise burrows, escaping heat they could not otherwise endure. Biologists therefore call the tortoise a "keystone" species: its survival strategy, evolved for its own benefit, inadvertently sustains a whole community. Protecting the tortoise, they argue, means protecting far more than a single animal.', NULL, '[{"id":"A","text":"Because the tortoise can survive summers hotter than any other desert animal can tolerate.","is_correct":false,"explanation":"No evidence; the text does not rank the tortoise''s heat tolerance against all others."},{"id":"B","text":"Because the burrows it builds for itself also enable many other species to survive.","is_correct":true,"explanation":"Correct: it links the tortoise''s self-serving strategy to sustaining a whole community."},{"id":"C","text":"Because the tortoise depends on snakes, lizards, and owls to dig its burrows.","is_correct":false,"explanation":"Reverse: the tortoise digs the burrows that others use."},{"id":"D","text":"Because the tortoise lives longer than the other animals that share its burrow.","is_correct":false,"explanation":"No evidence; lifespan comparisons are not discussed."}]'::jsonb, 'B', 'Step 1 — Find the keystone reasoning
The text says the tortoise''s survival strategy, evolved for its own benefit, {{yellow:inadvertently sustains a whole community}}.
Step 2 — Match the detail
Because its self-built burrows let many species survive, biologists call it keystone, exactly as choice B states.
Distractor analysis:
- A: No evidence ranking its heat tolerance above all animals.
- C: Reverses the relationship; the tortoise digs the burrows.
- D: No evidence about comparative lifespans.', 'Find what the tortoise''s burrows provide for other animals.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('43b31dd7-f882-48bd-a24d-8228e69da38f', 'Which choice best states the main idea of the text?', 'When the printing press spread across Europe, many scholars feared it would corrupt learning by flooding the world with cheap, error-filled books. In some ways their fears were justified: early printed editions did contain mistakes, and sensational pamphlets proliferated. Yet the same technology allowed errors to be identified and corrected more quickly, since many readers could now compare copies of the same text. Over time, print did not lower the reliability of knowledge but raised it, precisely because its wide circulation exposed mistakes to broader scrutiny.', NULL, '[{"id":"A","text":"The printing press flooded Europe with sensational pamphlets that corrupted learning.","is_correct":false,"explanation":"Too narrow and one-sided; it ignores the text''s main turn toward improved reliability."},{"id":"B","text":"Despite early fears, the printing press ultimately improved the reliability of knowledge through wider scrutiny.","is_correct":true,"explanation":"Correct: it synthesizes the justified fears with the eventual increase in reliability."},{"id":"C","text":"Early printed books were entirely free of the errors found in handwritten manuscripts.","is_correct":false,"explanation":"Contradiction: the text says early editions did contain mistakes."},{"id":"D","text":"Scholars who feared the printing press were proven completely correct over time.","is_correct":false,"explanation":"Contradiction: the text says print raised reliability, contrary to the fears."}]'::jsonb, 'B', 'Step 1 — Find the reversal
The text concludes that print {{yellow:did not lower the reliability of knowledge but raised it}} because circulation exposed mistakes to scrutiny.
Step 2 — Match the main idea
This balances the justified early fears with the eventual benefit, which choice B captures.
Distractor analysis:
- A: Too narrow and one-sided, missing the corrective turn.
- C: Contradicts the admission that early editions had mistakes.
- D: Contradicts the conclusion that print raised reliability.', 'Track how the text moves from justified fears to an opposite outcome.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1859722a-4c42-4ea8-9570-9221401b70e3', 'Which choice best states the main idea of the text?', 'In her later essays, the philosopher argued that forgetting is not simply the failure of memory but one of its essential functions. A mind that retained every detail, she claimed, would be paralyzed, unable to distinguish the important from the trivial. Healthy remembering depends on a constant, mostly invisible process of discarding. Critics who equate a good memory with total recall, she suggested, misunderstand what memory is for. Its purpose is not to preserve the past intact but to shape a usable sense of it.', NULL, '[{"id":"A","text":"A person with total recall would have the healthiest possible memory.","is_correct":false,"explanation":"Contradiction: the text says total recall would be paralyzing."},{"id":"B","text":"The philosopher wrote many essays about the nature of memory late in her career.","is_correct":false,"explanation":"Too narrow; this is context, not the central claim."},{"id":"C","text":"Forgetting is an essential function of memory because selectively discarding information makes the past usable.","is_correct":true,"explanation":"Correct: it synthesizes the discarding process with memory''s purpose of shaping a usable past."},{"id":"D","text":"Critics of the philosopher have shown that her view of memory is mistaken.","is_correct":false,"explanation":"Reverse: she argues the critics misunderstand memory, not the other way around."}]'::jsonb, 'C', 'Step 1 — Find the core claim
The philosopher argues memory''s purpose is {{yellow:not to preserve the past intact but to shape a usable sense of it}}, with forgetting as essential.
Step 2 — Match the main idea
This ties selective discarding to making the past usable, exactly choice C.
Distractor analysis:
- A: Contradicts the claim that total recall is paralyzing.
- B: Too narrow; it states only context.
- D: Reverses who is said to misunderstand memory.', 'Notice what the philosopher says memory''s real purpose is.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('da05a08a-e4f5-4aa6-99b3-a1cb69457da0', 'Which choice best states the main idea of the text?', 'Historians once described the medieval guild solely as a force that stifled competition, since guilds set fixed prices and limited who could practice a trade. Newer research presents a fuller picture. Guilds also trained apprentices, enforced quality standards that protected buyers, and provided support to members who fell ill. While they did restrict the market, they simultaneously supplied services that no other institution then offered. To judge guilds only by their limits on competition, this research suggests, is to overlook the stabilizing roles they played in their communities.', NULL, '[{"id":"A","text":"Medieval guilds existed only to set fixed prices and limit who could practice a trade.","is_correct":false,"explanation":"Too narrow and one-sided; it reflects the older view the text revises."},{"id":"B","text":"Guilds offered training, quality standards, and member support that newer research praises above all institutions.","is_correct":false,"explanation":"Overstatement; the text says no other institution offered these services, not that guilds were the best at everything."},{"id":"C","text":"Newer research shows guilds both restricted competition and provided valuable, stabilizing community services.","is_correct":true,"explanation":"Correct: it synthesizes the restrictive and supportive roles into the fuller picture."},{"id":"D","text":"Historians now agree that guilds had no negative effects on medieval markets.","is_correct":false,"explanation":"Contradiction: the text affirms guilds did restrict the market."}]'::jsonb, 'C', 'Step 1 — Find the fuller picture
The text says that while guilds restricted the market, they {{yellow:simultaneously supplied services that no other institution then offered}}.
Step 2 — Match the main idea
This balanced view of restriction plus valuable services is exactly choice C.
Distractor analysis:
- A: Too narrow; it restates only the older one-sided view.
- B: Overstates by implying guilds surpassed all institutions.
- D: Contradicts the text''s admission that guilds restricted competition.', 'The text revises a one-sided view into a both-sides picture.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c1391289-7461-4fe7-b8d3-b53764ee5839', 'Which choice best states the main idea of the text?', 'When the lighthouse keeper Mara first arrived on the island, she dismissed the fog as a nuisance that obscured the beam she tended. Over the years, though, she came to read its moods. A low mist that clung to the rocks meant calm seas; a fog that rolled in fast from the west warned of squalls. The sailors who once cursed the haze learned to trust her signals, which translated the weather''s silent language into warnings they could act on. Mara never abandoned her belief that the fog was an obstacle, yet she had also made it an ally.', NULL, '[{"id":"A","text":"Mara grew to understand the fog well enough to use it as a tool, even while still regarding it as a hindrance.","is_correct":true,"explanation":"Correct: it captures both that she read the fog''s signs to warn sailors and that she still saw it as an obstacle."},{"id":"B","text":"Mara eventually decided that the fog posed no real danger to passing sailors.","is_correct":false,"explanation":"Contradiction: the fast western fog still ''warned of squalls,'' so danger remained."},{"id":"C","text":"Mara''s main duty as a lighthouse keeper was to tend the beam through difficult weather.","is_correct":false,"explanation":"Too narrow: tending the beam is mentioned only in passing and is not the focus."},{"id":"D","text":"The sailors near the island distrusted Mara until she proved her warnings were accurate.","is_correct":false,"explanation":"No evidence: the text says sailors learned to trust her, not that they distrusted her first."}]'::jsonb, 'A', 'Step 1 — Find the tension
The text says sailors ''learned to trust her signals, which translated the weather''s silent language into warnings they could act on,'' showing she made the fog useful, while {{yellow:she had also made it an ally}} sits beside her continued belief it was an obstacle.
Step 2 — Match the synthesis
Choice A combines both ideas: the fog as a tool and the fog as a hindrance.
Distractor analysis:
- B: Contradicts the text, which still calls fast fog a warning of squalls.
- C: Too narrow; tending the beam is incidental.
- D: No evidence sailors initially distrusted Mara herself.', 'Look for the choice that holds together both how Mara still views the fog and how she now uses it.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('13368b3f-4afd-4389-8688-5d24772deccb', 'Which choice best states the main idea of the text?', 'Tardigrades, microscopic animals often called water bears, survive conditions that kill nearly every other organism. When their environment dries out, they expel almost all the water from their bodies and curl into a dormant state called a tun. In this form they have endured boiling heat, the vacuum of space, and radiation doses lethal to humans. Researchers have found that tardigrades produce special proteins that replace lost water, forming a glassy matrix that shields delicate cell structures. The animals are not invulnerable while active, but their ability to suspend life itself allows them to wait out catastrophes that would otherwise destroy them.', NULL, '[{"id":"A","text":"Tardigrades endure extreme conditions chiefly by entering a protective dormant state rather than by being tough while active.","is_correct":true,"explanation":"Correct: it synthesizes the tun state and the proteins with the clarification that they are not invulnerable when active."},{"id":"B","text":"Tardigrades are completely indestructible organisms that no environment can harm.","is_correct":false,"explanation":"Contradiction: the text states they are ''not invulnerable while active.''"},{"id":"C","text":"Tardigrades produce proteins that form a glassy matrix inside their cells.","is_correct":false,"explanation":"Too narrow: the protein detail supports the broader point about dormancy but is not the whole idea."},{"id":"D","text":"Tardigrades have been observed surviving in the vacuum of space.","is_correct":false,"explanation":"Too narrow: this is one example offered to illustrate the larger claim about dormancy."}]'::jsonb, 'A', 'Step 1 — Locate the central mechanism
The text explains survival through the tun state and adds {{yellow:their ability to suspend life itself allows them to wait out catastrophes}}.
Step 2 — Balance the qualification
Choice A captures dormancy as the key and respects the note that they are not invulnerable when active.
Distractor analysis:
- B: Contradicts ''not invulnerable while active.''
- C: Too narrow; the protein is a supporting detail.
- D: Too narrow; space survival is just one example.', 'The passage names the real reason for survival and adds a limit on it; find the choice that respects both.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7f75bb64-7f03-40ff-a36f-eead13fcda79', 'Which choice best states the main idea of the text?', 'In nineteenth-century Britain, the spread of railways did more than shorten travel times. Before the rails, each town kept its own local time, set by the sun, so noon in one city might differ by many minutes from noon in another. This patchwork made printing reliable train schedules nearly impossible. To solve the problem, railway companies adopted a single standardized time across their lines. Communities resisted at first, reluctant to abandon their familiar local clocks, but the convenience of coordinated schedules gradually won out. The railways, built to move goods and people, ended up reshaping how an entire nation measured the day.', NULL, '[{"id":"A","text":"By requiring coordinated schedules, railways drove Britain to replace varied local times with a single standard.","is_correct":true,"explanation":"Correct: it links the scheduling problem to the adoption of standardized time across the nation."},{"id":"B","text":"Nineteenth-century British towns set their clocks by the position of the sun.","is_correct":false,"explanation":"Too narrow: local solar time is background context, not the main point."},{"id":"C","text":"Communities in Britain refused to give up their local time despite the railways'' demands.","is_correct":false,"explanation":"Contradiction: the text says ''the convenience of coordinated schedules gradually won out.''"},{"id":"D","text":"Railways were primarily built to transport goods and people across Britain.","is_correct":false,"explanation":"True but irrelevant: that purpose is mentioned only to contrast with the railways'' unexpected effect on timekeeping."}]'::jsonb, 'A', 'Step 1 — Identify the driving cause
The passage notes the patchwork of local times made schedules impossible, then says {{yellow:railway companies adopted a single standardized time across their lines}}.
Step 2 — Trace the outcome
Choice A ties the railways'' need to the nationwide shift in timekeeping.
Distractor analysis:
- B: Too narrow; solar time is just setup.
- C: Contradicts the text, where convenience won out.
- D: True but irrelevant to the main claim about time standardization.', 'Find the choice that connects why railways needed coordinated time to what changed across the nation.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5a515528-4834-4cc4-9dec-2dc81a7a08fb', 'Which choice best states the main idea of the text?', 'The novelist Idris kept two notebooks. In the first he recorded what he observed: overheard conversations, the color of a winter sky, the way a stranger paused before answering a question. In the second he wrote only what he imagined those observations might mean. For years he believed the two notebooks were separate kingdoms, one bound to fact and the other free to invent. But when he began his final novel, he found himself flipping constantly between them, unable to tell where memory ended and imagination began. The book that resulted, critics agreed, was his truest, precisely because it refused to keep the two apart.', NULL, '[{"id":"A","text":"Idris''s best work emerged when he stopped treating observation and imagination as separate and let them blend.","is_correct":true,"explanation":"Correct: it synthesizes his earlier separation of the notebooks with the merged approach that produced his truest book."},{"id":"B","text":"Idris recorded careful observations of the world in one of his two notebooks.","is_correct":false,"explanation":"Too narrow: the first notebook is one detail, not the central idea."},{"id":"C","text":"Idris always understood that memory and imagination were inseparable in his writing.","is_correct":false,"explanation":"Contradiction: he ''believed the two notebooks were separate kingdoms'' for years."},{"id":"D","text":"Critics generally disliked Idris''s final novel for blurring fact and invention.","is_correct":false,"explanation":"Contradiction: critics agreed it was ''his truest'' book."}]'::jsonb, 'A', 'Step 1 — Track the shift
Idris first kept the notebooks as separate kingdoms but later was {{yellow:unable to tell where memory ended and imagination began}}.
Step 2 — Connect to the result
Choice A captures that merging the two produced his finest novel.
Distractor analysis:
- B: Too narrow; the observation notebook is one element.
- C: Contradicts his years of believing they were separate.
- D: Contradicts critics calling the novel his truest.', 'The passage describes a change in how Idris saw two notebooks; pick the choice that captures both the before and after.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bc7bb6c9-ae9c-489b-ba62-0228e17eef2a', 'According to the text, what is the relationship between coral polyps and the algae in their tissues?', 'Coral reefs appear to be solid stone, but they are living cities built by tiny animals called polyps. Each polyp secretes a hard skeleton of calcium carbonate, and over centuries these skeletons accumulate into vast structures. The living polyps survive in part because of algae that live inside their tissues, converting sunlight into food the polyps share. When ocean temperatures rise too high, the polyps expel these algae, losing both their color and their main food source. This event, called bleaching, does not instantly kill the reef, but a bleached colony is weakened and may starve if cool conditions do not return.', NULL, '[{"id":"A","text":"The algae supply food to the polyps using sunlight, so losing the algae deprives the polyps of a key food source.","is_correct":true,"explanation":"Correct: it joins the algae''s food-making role with the consequence of expelling them during bleaching."},{"id":"B","text":"The algae build the calcium carbonate skeletons that form the reef structure.","is_correct":false,"explanation":"No evidence: the text says the polyps, not the algae, secrete the skeletons."},{"id":"C","text":"The polyps provide the algae with shelter but receive nothing in return.","is_correct":false,"explanation":"Contradiction: the algae convert sunlight into food the polyps share."},{"id":"D","text":"The algae cause bleaching by leaving the polyps when temperatures rise.","is_correct":false,"explanation":"Reverse: the text says the polyps expel the algae, not that the algae leave on their own."}]'::jsonb, 'A', 'Step 1 — Find the exchange
The text states the algae live inside the polyps'' tissues, {{yellow:converting sunlight into food the polyps share}}.
Step 2 — Trace the loss
When polyps expel the algae, they lose their main food source, which choice A states.
Distractor analysis:
- B: No evidence; polyps secrete the skeleton.
- C: Contradicts the shared-food relationship.
- D: Reverses agency; polyps expel the algae.', 'Look for what the algae give the polyps and what happens when that supply is lost.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2b9f2293-a363-46bd-bf3d-aba56121869b', 'Which choice best states the main idea of the text?', 'The archaeologist Lena had expected the buried settlement to reveal a society of warriors. Instead, the artifacts told a quieter story. She found grinding stones worn smooth from preparing grain, clay figurines shaped like nursing mothers, and pottery decorated with images of seeds and rain. Weapons were scarce, and the few she uncovered showed little sign of use. Lena did not conclude that the people had never fought; the surrounding hills bore old defensive walls. Yet the objects they chose to make, decorate, and bury suggested a community whose daily life and deepest values centered on farming and the nurturing of new life.', NULL, '[{"id":"A","text":"The settlement''s artifacts pointed to a people centered on agriculture and nurturing, even if they were not wholly peaceful.","is_correct":true,"explanation":"Correct: it synthesizes the farming-focused objects with the qualification about the defensive walls."},{"id":"B","text":"The settlement Lena studied had never engaged in any kind of warfare.","is_correct":false,"explanation":"Contradiction: the surrounding hills ''bore old defensive walls'' and she did not conclude they never fought."},{"id":"C","text":"Lena found grinding stones worn smooth from preparing grain at the site.","is_correct":false,"explanation":"Too narrow: the grinding stones are one of several supporting details."},{"id":"D","text":"Archaeologists usually expect buried settlements to belong to warrior societies.","is_correct":false,"explanation":"No evidence: the text describes Lena''s single expectation, not a general rule among archaeologists."}]'::jsonb, 'A', 'Step 1 — Read the artifacts
The objects suggested {{yellow:a community whose daily life and deepest values centered on farming and the nurturing of new life}}.
Step 2 — Honor the caveat
Choice A keeps that emphasis while noting they were not entirely peaceful, matching the defensive walls.
Distractor analysis:
- B: Contradicts the defensive walls and Lena''s caution.
- C: Too narrow; one detail among many.
- D: No evidence for a general expectation among archaeologists.', 'Find the choice that captures what the objects reveal while not erasing the hint that the people could fight.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9ac51b3d-b7ab-4275-b5f5-b3b319a6f48f', 'Which choice best states the main idea of the text?', 'For decades, economists assumed that people always make choices that maximize their own financial benefit. Behavioral research has complicated that picture. In experiments where participants divide a sum of money, many reject offers they consider unfair, even when rejecting means walking away with nothing. By the older model, accepting any amount is the rational move, since some money beats none. The repeated refusals suggest that fairness can outweigh pure self-interest in human decision-making. Economists have not discarded the idea that people respond to incentives, but they increasingly recognize that those incentives include social values, not just dollars.', NULL, '[{"id":"A","text":"Behavioral findings show that concerns like fairness, not just financial gain, shape how people make economic decisions.","is_correct":true,"explanation":"Correct: it synthesizes the rejection experiments with the conclusion that incentives include social values."},{"id":"B","text":"Economists have completely abandoned the idea that people respond to incentives.","is_correct":false,"explanation":"Contradiction: they ''have not discarded the idea that people respond to incentives.''"},{"id":"C","text":"In money-division experiments, accepting any nonzero offer is always the rational choice.","is_correct":false,"explanation":"True but irrelevant: this states the old model the text moves beyond, not the main idea."},{"id":"D","text":"Participants in experiments reject unfair offers and walk away with nothing.","is_correct":false,"explanation":"Too narrow: this detail is evidence for the broader point, not the point itself."}]'::jsonb, 'A', 'Step 1 — Read the evidence
Many participants reject unfair offers, and the text says {{yellow:fairness can outweigh pure self-interest in human decision-making}}.
Step 2 — State the revised view
Choice A captures that incentives now include social values, not just money.
Distractor analysis:
- B: Contradicts the statement that incentives still matter.
- C: True but irrelevant; it is the old model.
- D: Too narrow; it is supporting evidence.', 'The passage updates an old assumption with new evidence; pick the choice that states the new, broader view.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('07e0cf3f-4e24-4f1e-a6d3-8686b933dcae', 'Which choice best states the main idea of the text?', 'The poet Dao wrote almost entirely at night. She claimed that darkness stripped the world of its distractions, leaving only the few things bright enough to insist on attention: a streetlamp, a moth, a single lit window across the courtyard. Critics often described her poems as narrow, focused on small and ordinary objects. Dao did not disagree, but she rejected the idea that smallness meant insignificance. To her, a moth circling a lamp held the whole drama of longing and risk. Her aim, she explained, was not to shrink the world but to look at one piece of it until it opened.', NULL, '[{"id":"A","text":"Dao deliberately concentrated on small, ordinary subjects because she believed close attention could reveal their larger meaning.","is_correct":true,"explanation":"Correct: it joins her focus on small objects with her belief that smallness is not insignificance."},{"id":"B","text":"Dao agreed with critics that her poems about small objects were ultimately insignificant.","is_correct":false,"explanation":"Contradiction: she ''rejected the idea that smallness meant insignificance.''"},{"id":"C","text":"Dao wrote almost all of her poems during the nighttime hours.","is_correct":false,"explanation":"Too narrow: her night writing is context for, not the substance of, her artistic aim."},{"id":"D","text":"Dao wanted her poems to capture the entire world in a single sweeping view.","is_correct":false,"explanation":"Contradiction: her aim was ''not to shrink the world but to look at one piece of it.''"}]'::jsonb, 'A', 'Step 1 — Define her method
Dao focused on small objects but insisted {{yellow:a moth circling a lamp held the whole drama of longing and risk}}.
Step 2 — Connect aim to belief
Choice A links her narrow focus to the conviction that close attention reveals larger meaning.
Distractor analysis:
- B: Contradicts her rejection of smallness as insignificance.
- C: Too narrow; night writing is context.
- D: Contradicts her stated aim to look at one piece.', 'Find the choice that explains both what Dao focused on and why she thought it mattered.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cbb63d88-35fc-4b44-a708-9aaec84f242f', 'Which choice best states the main idea of the text?', 'When the Dutch began draining their wetlands in the seventeenth century, they created fertile farmland, but they also set a slow problem in motion. Drained peat soil compacts and oxidizes, sinking lower each decade. Land that once sat above the sea gradually dropped below it, so the very pumps and dikes built to reclaim the land became permanent necessities to keep it dry. Each new effort to control the water created conditions that demanded still more control. The Dutch mastery of water, often celebrated as a triumph, was also the beginning of an obligation that could never be set down.', NULL, '[{"id":"A","text":"Draining the wetlands gave the Dutch farmland but committed them to endless water management to maintain it.","is_correct":true,"explanation":"Correct: it synthesizes the benefit of farmland with the self-perpetuating need for pumps and dikes."},{"id":"B","text":"Drained peat soil compacts and oxidizes, causing the land to sink over time.","is_correct":false,"explanation":"Too narrow: the soil mechanism supports the larger point about ongoing obligation."},{"id":"C","text":"The Dutch eventually abandoned their efforts to control the water on reclaimed land.","is_correct":false,"explanation":"No evidence: the text says control became a permanent necessity, not that they gave up."},{"id":"D","text":"The Dutch reclamation of land is celebrated purely as an unqualified triumph.","is_correct":false,"explanation":"Contradiction: the text calls it ''also the beginning of an obligation that could never be set down.''"}]'::jsonb, 'A', 'Step 1 — Note the trade-off
Draining created farmland, but {{yellow:each new effort to control the water created conditions that demanded still more control}}.
Step 2 — State the lasting obligation
Choice A captures the benefit and the permanent maintenance it required.
Distractor analysis:
- B: Too narrow; the soil detail is mechanism, not main idea.
- C: No evidence of abandonment.
- D: Contradicts the text''s qualification of the triumph.', 'Look for the choice that pairs the gain from draining with the lasting cost it created.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1bd33805-185b-4fd9-942a-f6fb31d75ac9', 'Which choice best states the main idea of the text?', 'The composer Sefu was praised for his orchestral works, yet he spent his final years writing music for a single instrument. Friends worried that he was retreating from ambition. Sefu saw it differently. With an orchestra, he said, a flaw in one part could hide behind the sound of fifty others; with one instrument, every note stood exposed, accountable to nothing but itself. He found this exposure not limiting but clarifying. The pieces he produced were brief and spare, far from the grandeur that had made his name, but he considered them the most honest music he had ever managed to write.', NULL, '[{"id":"A","text":"Sefu turned to solo writing because its exposure forced an honesty he valued more than orchestral grandeur.","is_correct":true,"explanation":"Correct: it synthesizes his reason for the shift with his judgment that the spare pieces were his most honest."},{"id":"B","text":"Sefu''s friends correctly recognized that he was abandoning his musical ambition.","is_correct":false,"explanation":"Contradiction: ''Sefu saw it differently,'' valuing the new work as more honest."},{"id":"C","text":"Sefu earned his reputation by composing grand orchestral works.","is_correct":false,"explanation":"True but irrelevant: his earlier fame is background to the main point about his later choice."},{"id":"D","text":"Sefu believed that orchestral music was incapable of expressing genuine emotion.","is_correct":false,"explanation":"No evidence: the text never claims orchestras cannot express emotion, only that solo work exposes each note."}]'::jsonb, 'A', 'Step 1 — Find his reasoning
With one instrument, Sefu said, {{yellow:every note stood exposed, accountable to nothing but itself}}.
Step 2 — Connect to his judgment
Choice A links that exposure to the honesty he prized over grandeur.
Distractor analysis:
- B: Contradicts ''Sefu saw it differently.''
- C: True but irrelevant; earlier fame is background.
- D: No evidence orchestras can''t express emotion.', 'Find the choice that ties why Sefu chose solo work to what he believed it gave him.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d855a098-3953-4eda-ba0f-b2b193d93064', 'Which choice best states the main idea of the text?', 'Early maps of the deep ocean floor showed a flat, featureless plain, mainly because the tools used to measure depth were too crude to detect anything else. In the mid-twentieth century, new sonar techniques revealed a hidden landscape of towering ridges, deep trenches, and vast underwater mountain ranges. The discovery did more than redraw maps. The long chain of ridges, it turned out, marked places where the seafloor itself was spreading apart, providing crucial evidence for the theory that Earth''s surface is divided into moving plates. What had seemed an empty void became a key to understanding the planet''s restless structure.', NULL, '[{"id":"A","text":"Improved sonar exposed a rugged seafloor whose ridges helped confirm that Earth''s surface is made of moving plates.","is_correct":true,"explanation":"Correct: it synthesizes the discovery of seafloor features with their role as evidence for moving plates."},{"id":"B","text":"Early maps depicted the deep ocean floor as a flat, featureless plain.","is_correct":false,"explanation":"Too narrow: this is the starting point the text moves beyond, not the main idea."},{"id":"C","text":"Sonar techniques were first developed in the mid-twentieth century.","is_correct":false,"explanation":"No evidence: the text says new sonar was used then, not that sonar was first invented then."},{"id":"D","text":"The deep ocean floor is best understood as an empty void with little structure.","is_correct":false,"explanation":"Contradiction: the text reveals a rugged landscape, not an empty void."}]'::jsonb, 'A', 'Step 1 — Identify the discovery
New sonar revealed ridges and trenches, and the ridges marked {{yellow:places where the seafloor itself was spreading apart}}.
Step 2 — State the significance
Choice A connects the rugged seafloor to evidence for moving plates.
Distractor analysis:
- B: Too narrow; it is the outdated starting view.
- C: No evidence sonar was first invented then.
- D: Contradicts the revealed rugged landscape.', 'The passage moves from an old view to a discovery with big consequences; pick the choice that captures the discovery and its importance.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5ba3c080-5424-46ec-9390-b863d11c821f', 'According to the text, what was the central point of Adaeze''s argument for public libraries?', 'The reformer Adaeze campaigned for public libraries in a city that already had several private reading clubs. Critics asked why the city needed libraries when books were available to club members. Adaeze answered that availability was not the same as access. The clubs charged dues that working families could not afford, and they admitted members by invitation. A public library, by contrast, would open its doors to anyone, regardless of income or connection. Her argument was not that books were scarce but that the chance to use them was unevenly distributed, and that a shared institution could spread that chance more fairly across the city.', NULL, '[{"id":"A","text":"Existing reading clubs limited who could use books, so a public library would distribute access more fairly.","is_correct":true,"explanation":"Correct: it synthesizes the clubs'' barriers with Adaeze''s claim that a public library would spread the chance to use books."},{"id":"B","text":"The city suffered from a severe shortage of available books.","is_correct":false,"explanation":"Contradiction: ''Her argument was not that books were scarce.''"},{"id":"C","text":"Private reading clubs admitted new members only by invitation.","is_correct":false,"explanation":"Too narrow: the invitation policy is one supporting detail, not the central point."},{"id":"D","text":"Public libraries would offer a wider selection of books than the reading clubs.","is_correct":false,"explanation":"No evidence: the text addresses access and cost, not the size of the collections."}]'::jsonb, 'A', 'Step 1 — Find the distinction
Adaeze argued that {{yellow:availability was not the same as access}}, since the clubs charged dues and admitted members by invitation.
Step 2 — State the remedy
Choice A captures that a public library would spread access more fairly.
Distractor analysis:
- B: Contradicts her point that books were not scarce.
- C: Too narrow; one supporting detail.
- D: No evidence about collection size.', 'Adaeze drew a distinction between two things; find the choice built on that distinction and her proposed solution.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8a238ad5-58b3-4345-8710-0123e5273342', 'Which choice best states the main idea of the text?', 'Historians once portrayed the medieval guild as a fraternal refuge from market competition, a body that capped prices and shielded craftsmen from ruinous rivalry. Recent economic studies complicate this image. By restricting who could practice a trade and how many apprentices a master could train, guilds did blunt competition—but chiefly to the advantage of incumbent masters, whose protected monopolies often raised consumer prices and slowed the spread of new techniques. The same institution that offered members mutual aid thus imposed costs on outsiders and on the wider economy. To read guilds solely as benevolent collectives, these scholars argue, is to mistake the perspective of those they enriched for the perspective of everyone they touched.', NULL, '[{"id":"A","text":"Recent scholarship contends that the guild''s protections, while genuinely benefiting its members, came at a cost to outsiders and the broader economy that the older benevolent image obscures.","is_correct":true,"explanation":"Correct: it captures both the members'' benefit and the costs to outsiders that the older view obscured."},{"id":"B","text":"Medieval guilds functioned primarily as fraternal refuges that protected craftsmen from the ruinous effects of market competition.","is_correct":false,"explanation":"This restates the older view the text is complicating, contradicting its argument."},{"id":"C","text":"Guilds slowed the spread of new techniques because masters refused to train more than a fixed number of apprentices.","is_correct":false,"explanation":"Too narrow: one detail, not the passage''s overall claim about competing perspectives."},{"id":"D","text":"Historians have reversed their earlier judgments and now regard medieval guilds as purely exploitative institutions.","is_correct":false,"explanation":"Overstated: the text affirms guilds offered real mutual aid, not pure exploitation."}]'::jsonb, 'A', 'Step 1 — Locate the dual claim
The text says guilds did blunt competition {{yellow:chiefly to the advantage of incumbent masters, whose protected monopolies often raised consumer prices and slowed the spread of new techniques}}.
Step 2 — Why A follows
The passage holds together two perspectives—real benefit to members and real cost to outsiders—and warns against reducing guilds to one; A states exactly this balance.
Distractor analysis:
- B: It restates the older benevolent image the text sets out to complicate.
- C: True but too narrow—a single detail, not the main idea.
- D: Overstated reversal; the text grants that guilds offered genuine mutual aid.', 'The text holds two perspectives in tension—don''t pick one that erases the other.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e8490750-2063-418e-ba2e-891158e97c3f', 'Which choice best states the main idea of the text?', 'In her field notebooks, the naturalist Anya Petrov records the wood thrush not as a single voice but as an argument. The male''s song, she writes, is produced by two independent sides of the syrinx, each capable of a distinct pitch, so that a lone bird can sound two notes at once that rise and fall against each other. Listeners hear a flutelike sweetness, but Petrov insists the sweetness is incidental: what the harmony advertises is physiological control, a feat of timing that a weaker bird could not sustain. The beauty we perceive, she concludes, is the audible trace of a difficulty we do not.', NULL, '[{"id":"A","text":"Petrov argues that the wood thrush''s pleasing harmony is essentially a display of demanding physiological control, with its beauty a byproduct of that difficulty.","is_correct":true,"explanation":"Correct: it captures her claim that the perceived beauty signals underlying physical control."},{"id":"B","text":"Petrov demonstrates that the wood thrush produces its song using two independent sides of the syrinx.","is_correct":false,"explanation":"Too narrow: this mechanism is evidence for her larger claim, not the claim itself."},{"id":"C","text":"Petrov maintains that the wood thrush''s song is valued by listeners chiefly for its flutelike sweetness.","is_correct":false,"explanation":"Contradicts the text, which calls the sweetness incidental."},{"id":"D","text":"Petrov suggests that listeners would enjoy the wood thrush more if they understood the physiology behind its song.","is_correct":false,"explanation":"No evidence: the text never claims understanding would increase enjoyment."}]'::jsonb, 'A', 'Step 1 — Find the thesis
Petrov says the sweetness is incidental and that {{yellow:what the harmony advertises is physiological control, a feat of timing that a weaker bird could not sustain}}.
Step 2 — Why A follows
She reframes the song''s beauty as the audible sign of a hard-won physical feat, which A states precisely.
Distractor analysis:
- B: The syrinx mechanism is supporting evidence, not the main idea.
- C: Directly contradicts her claim that sweetness is incidental.
- D: No evidence; the text makes no claim about increasing listeners'' enjoyment.', 'What does Petrov say the harmony actually ''advertises''?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('af265a40-6f53-4340-aae5-0257b1d9d757', 'Which choice best states the main idea of the text?', 'When the city installed sensors to ease traffic, engineers expected the data to reveal where to widen roads. Instead the patterns suggested the opposite remedy. Drivers, the records showed, did not distribute themselves to minimize their own travel time; they crowded familiar arterials even when parallel streets sat empty, because the cost of learning an alternate route felt larger than the delay itself. Adding lanes to the crowded arterials, the analysts warned, would merely make those routes more attractive and pull still more drivers onto them, leaving total congestion unchanged. The bottleneck, they concluded, lay less in the pavement than in the habits the pavement had taught.', NULL, '[{"id":"A","text":"Sensor data led analysts to conclude that the city''s congestion stemmed largely from drivers'' route habits rather than insufficient road capacity, so widening roads would not relieve it.","is_correct":true,"explanation":"Correct: it joins the behavioral cause and the failure of the road-widening fix."},{"id":"B","text":"The city installed traffic sensors in order to determine which roads most needed to be widened.","is_correct":false,"explanation":"Too narrow and outdated: this is the initial expectation the data overturned."},{"id":"C","text":"Drivers crowd familiar arterials because the perceived cost of learning a new route exceeds the delay they endure.","is_correct":false,"explanation":"True but narrow: one detail, not the passage''s overall conclusion."},{"id":"D","text":"Adding lanes to congested arterials is the most reliable way to reduce a city''s total congestion.","is_correct":false,"explanation":"Reverses the text, which says added lanes would leave congestion unchanged."}]'::jsonb, 'A', 'Step 1 — Identify the conclusion
The analysts concluded {{yellow:The bottleneck, they concluded, lay less in the pavement than in the habits the pavement had taught}}.
Step 2 — Why A follows
The behavioral diagnosis and the warning that widening fails are two halves of one argument; A unites them.
Distractor analysis:
- B: This is the discarded initial expectation, not the finding.
- C: True but only a single supporting detail.
- D: Reverses the analysts'' warning that added lanes would not help.', 'The analysts trace congestion to something other than the pavement itself.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6ecad54e-06de-4109-a3c7-07475816c9a8', 'Which choice best states the main idea of the text?', 'The poet Du Fu has long been celebrated for verses of stoic public duty, and anthologies favor his laments for a war-torn empire. Yet a translator working through his complete corpus notices a quieter, recurring move: in poem after poem, the grand civic sorrow narrows, in the final lines, to a domestic image—a child''s torn coat, a neighbor''s wine, a single lamp. Far from undercutting the public grief, the translator argues, these endings ground it: Du Fu measures the scale of empire-wide loss precisely by what it costs one household. The political and the intimate, often read as separate registers in his work, turn out to depend on each other.', NULL, '[{"id":"A","text":"The translator argues that Du Fu''s intimate, domestic closings do not diminish his public grief but anchor it, showing the political and personal as interdependent.","is_correct":true,"explanation":"Correct: it captures the interdependence the translator emphasizes."},{"id":"B","text":"Du Fu is best known for stoic verses of public duty and laments for a war-torn empire.","is_correct":false,"explanation":"This is the conventional view the translator complicates, not the main idea."},{"id":"C","text":"Du Fu frequently ends his poems with domestic images such as a child''s torn coat or a single lamp.","is_correct":false,"explanation":"True but narrow: the observed pattern, not the interpretive claim built on it."},{"id":"D","text":"The translator concludes that Du Fu''s domestic images undercut and ultimately weaken the public grief his poems express.","is_correct":false,"explanation":"Contradicts the text, which says the endings ground rather than undercut the grief."}]'::jsonb, 'A', 'Step 1 — Find the interpretive claim
The translator argues these endings ground the public grief: {{yellow:Du Fu measures the scale of empire-wide loss precisely by what it costs one household}}.
Step 2 — Why A follows
The closing sentence states the political and intimate depend on each other; A names that interdependence.
Distractor analysis:
- B: The conventional reputation the translator moves beyond.
- C: True but merely the pattern, not the argument about it.
- D: Contradicts ''Far from undercutting the public grief.''', 'Does the translator say the domestic images weaken or support the public grief?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('eaa14d8b-e1e4-4d42-9fce-1fbf492fbb1c', 'Which choice best states the main idea of the text?', 'Conservation biologists prizing genetic diversity have urged that small, isolated populations be linked by corridors so individuals can interbreed. A study of island lizards offers a caution. The isolated populations had, over generations, purged many harmful recessive genes and adapted finely to local conditions; when migrants from other islands arrived, their incoming genes diluted these local adaptations and reintroduced variants the population had shed, lowering survival in the first generations. The authors do not reject connectivity outright. Rather, they argue that mixing helps populations facing inbreeding decline but can harm those already well adapted, so the value of gene flow depends on the state of the population receiving it.', NULL, '[{"id":"A","text":"The study argues that the benefit of connecting isolated populations through gene flow is conditional, helping inbred populations but potentially harming those already locally adapted.","is_correct":true,"explanation":"Correct: it captures the conditional, two-sided conclusion the authors draw."},{"id":"B","text":"The study shows that linking isolated populations with corridors reliably increases their survival by restoring genetic diversity.","is_correct":false,"explanation":"Contradicts the text, which shows mixing lowered survival in well-adapted populations."},{"id":"C","text":"Isolated island lizard populations had purged harmful recessive genes and adapted finely to local conditions.","is_correct":false,"explanation":"True but narrow: a supporting premise, not the overall argument."},{"id":"D","text":"The authors conclude that conservation efforts should abandon habitat corridors as a strategy for protecting wildlife.","is_correct":false,"explanation":"Overstated: the text says the authors do not reject connectivity outright."}]'::jsonb, 'A', 'Step 1 — Locate the qualified claim
The authors argue {{yellow:mixing helps populations facing inbreeding decline but can harm those already well adapted}}.
Step 2 — Why A follows
That sentence makes the value of gene flow depend on the receiving population''s state—exactly A''s conditional framing.
Distractor analysis:
- B: Contradicts the finding that mixing lowered survival in adapted populations.
- C: True but only a supporting premise.
- D: Overstated; the authors explicitly do not reject connectivity.', 'The authors don''t simply praise or condemn gene flow—on what does its value depend?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('facc12e4-55e4-4736-bf8c-9c325254dc26', 'Which choice best states the main idea of the text?', 'Economic historians have debated why the printing press spread so unevenly across early modern Europe. One account credits literacy: presses clustered where readers already existed. A competing account credits political fragmentation, arguing that rival jurisdictions could not coordinate censorship, leaving printers room to operate. A recent quantitative study finds both forces at work but assigns them different roles. Literacy, it shows, predicted where presses first appeared; fragmentation predicted where they survived and multiplied once established, by giving banned printers nearby havens. The two explanations, long treated as rivals, describe successive stages of a single process rather than competing answers to one question.', NULL, '[{"id":"A","text":"A recent study reconciles two rival explanations for the press''s uneven spread by showing that literacy and political fragmentation governed different stages—emergence and survival—of the same process.","is_correct":true,"explanation":"Correct: it captures the reconciliation and the stage-based division of roles."},{"id":"B","text":"Literacy was the single decisive factor determining where printing presses spread in early modern Europe.","is_correct":false,"explanation":"Too narrow: the text gives fragmentation a distinct, essential role."},{"id":"C","text":"Political fragmentation mattered because rival jurisdictions could not coordinate censorship against printers.","is_correct":false,"explanation":"True but narrow: explains one factor, not the study''s synthesizing claim."},{"id":"D","text":"The study concludes that the two earlier explanations are mutually incompatible and that only one can be correct.","is_correct":false,"explanation":"Reverses the text, which says they describe stages of a single process."}]'::jsonb, 'A', 'Step 1 — Find the synthesis
The study finds {{yellow:Literacy, it shows, predicted where presses first appeared; fragmentation predicted where they survived and multiplied once established}}.
Step 2 — Why A follows
The closing line recasts the rivals as successive stages of one process, which A states.
Distractor analysis:
- B: Too narrow; ignores fragmentation''s essential role.
- C: True but explains only one factor.
- D: Reverses the conclusion that the accounts are complementary, not incompatible.', 'The study doesn''t pick a winner between the two accounts—what does it do instead?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('42a5f66a-3445-4131-a91e-8d6717db4ed8', 'Which choice best states the main idea of the text?', 'The reformer Ida Wells understood that a moral argument alone would not move her audience, and her pamphlets reflect a calculated method. Rather than appeal first to her readers'' conscience, she opened with their own institutions'' records—court documents, newspaper reports, the very sources her opponents trusted—and let the contradictions within those sources do the indicting. Only after the factual ground was secured did she turn to ethical appeal. Critics who praise Wells chiefly for her passion, a biographer notes, miss the discipline beneath it: her power lay not in feeling more deeply than her readers but in compelling them, through evidence they had themselves endorsed, to feel at all.', NULL, '[{"id":"A","text":"Wells''s persuasive force came less from emotional intensity than from a deliberate strategy of grounding her case in sources her opponents already trusted before making any moral appeal.","is_correct":true,"explanation":"Correct: it foregrounds the evidence-first method the biographer highlights over passion."},{"id":"B","text":"Wells relied chiefly on the depth of her own passion to persuade readers of her moral arguments.","is_correct":false,"explanation":"Contradicts the biographer, who says her power lay in discipline, not feeling more deeply."},{"id":"C","text":"Wells drew on court documents and newspaper reports in composing her pamphlets.","is_correct":false,"explanation":"True but narrow: a detail of method, not the overall claim about its basis."},{"id":"D","text":"Wells avoided ethical appeals entirely, relying solely on factual evidence to make her case.","is_correct":false,"explanation":"Contradicts the text, which says she turned to ethical appeal after securing facts."}]'::jsonb, 'A', 'Step 1 — Identify the thesis
The biographer notes her power lay in {{yellow:compelling them, through evidence they had themselves endorsed, to feel at all}}.
Step 2 — Why A follows
The passage credits a disciplined, evidence-first strategy over raw passion, exactly A''s emphasis.
Distractor analysis:
- B: Contradicts the claim that her power was discipline, not passion.
- C: A true detail, but not the central argument.
- D: Contradicts the statement that she did turn to ethical appeal afterward.', 'The biographer corrects a common praise of Wells—what does he say her real power was?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d921763c-eee7-43d0-b13d-d2ae374651cf', 'Which choice best states the main idea of the text?', 'A common story holds that the Sahara''s expansion forced ancient herders southward in a simple flight from drought. Sediment cores tell a more tangled tale. As the green Sahara dried over centuries, the change was not steady but lurching—wet decades interrupting the long desiccation. These reprieves, paradoxically, may have prolonged human presence rather than hastening departure, drawing communities back to refilled lakes only to strand them when aridity resumed. The eventual migration, archaeologists now suggest, was less a single retreat than a series of returns and losses, shaped as much by the desert''s false promises as by its advance.', NULL, '[{"id":"A","text":"New evidence reframes the herders'' departure from the drying Sahara not as a simple flight from drought but as a halting process shaped by intermittent wet periods that repeatedly drew communities back.","is_correct":true,"explanation":"Correct: it captures the revised, non-linear account driven by the wet reprieves."},{"id":"B","text":"The expansion of the Sahara forced ancient herders into a single, steady retreat southward away from drought.","is_correct":false,"explanation":"This is the common story the text revises, not its conclusion."},{"id":"C","text":"Sediment cores show that the Sahara''s drying was interrupted by occasional wet decades.","is_correct":false,"explanation":"True but narrow: the evidence, not the interpretive claim built on it."},{"id":"D","text":"Archaeologists now believe ancient herders never left the Sahara despite its increasing aridity.","is_correct":false,"explanation":"No evidence: the text affirms an eventual migration occurred."}]'::jsonb, 'A', 'Step 1 — Find the revised claim
The text says the migration was {{yellow:less a single retreat than a series of returns and losses}}.
Step 2 — Why A follows
It attributes that halting pattern to the wet reprieves that drew people back, exactly A''s framing.
Distractor analysis:
- B: The simple story the passage overturns.
- C: True but only the supporting evidence.
- D: No evidence; an eventual migration is affirmed.', 'The wet decades complicate the ''simple flight'' story—how?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3208fe52-2758-4adf-856d-a9393fc57607', 'Which choice best states the main idea of the text?', 'In the novel, the steward Halloran narrates the estate''s decline with unbroken composure, never once blaming the absent earl whose neglect ruins it. Early readers took his loyalty at face value. A later critic, however, points to the gaps: Halloran records every failed harvest and unpaid wage but never connects them, and his refusal to assign blame begins to read not as devotion but as a man protecting himself from a conclusion he cannot afford to reach. The novel''s irony, the critic argues, works through what its narrator withholds; Halloran''s calm is the measure of how much he must not understand.', NULL, '[{"id":"A","text":"A critic argues that Halloran''s composed, blame-free narration is not simple loyalty but a self-protective evasion, making the novel''s irony depend on what the narrator withholds.","is_correct":true,"explanation":"Correct: it captures the reinterpretation of his calm as evasion driving the irony."},{"id":"B","text":"Halloran narrates the estate''s decline calmly and remains loyal to the absent earl throughout the novel.","is_correct":false,"explanation":"This is the surface reading the critic complicates, not the main idea."},{"id":"C","text":"Halloran records every failed harvest and unpaid wage on the declining estate.","is_correct":false,"explanation":"True but narrow: a detail used as evidence, not the interpretive claim."},{"id":"D","text":"The critic concludes that Halloran fully understands the earl''s guilt but deliberately conceals it from the reader.","is_correct":false,"explanation":"Contradicts the text, which says Halloran must not understand, protecting himself from the conclusion."}]'::jsonb, 'A', 'Step 1 — Find the reinterpretation
The critic argues Halloran''s refusal to assign blame reads as {{yellow:a man protecting himself from a conclusion he cannot afford to reach}}.
Step 2 — Why A follows
The irony works through what the narrator withholds, recasting his calm as evasion—A''s claim.
Distractor analysis:
- B: The face-value reading the critic overturns.
- C: A true detail offered as evidence.
- D: Contradicts ''how much he must not understand''—he evades, not knowingly conceals.', 'The critic rereads Halloran''s calm—as loyalty, or as something he''s avoiding?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('405fc786-3c6e-44ff-9d18-71932911b09c', 'Which choice best states the main idea of the text?', 'Public-health campaigns often assume that informing people of a risk will change their behavior. A trial of flood-zone homeowners suggests the link is weaker and stranger than assumed. Residents given detailed maps of their flood exposure did update their beliefs—they rated their risk as higher afterward—yet were no more likely to buy insurance or elevate their utilities. Interviews revealed why: accurate information also sharpened their sense that the threat was beyond individual remedy, breeding a fatalism that canceled the spur to act. Knowledge moved belief without moving conduct, the researchers note, because the same facts that alarmed residents also persuaded them that action was futile.', NULL, '[{"id":"A","text":"The trial found that accurate risk information raised residents'' sense of danger but not their protective action, because the same facts also convinced them that action was futile.","is_correct":true,"explanation":"Correct: it pairs the belief change with the inaction and its fatalistic cause."},{"id":"B","text":"Public-health campaigns succeed because informing people of a risk reliably changes their behavior.","is_correct":false,"explanation":"Contradicts the text, whose findings undercut this assumption."},{"id":"C","text":"Residents given flood maps rated their personal flood risk as higher than they had before.","is_correct":false,"explanation":"True but narrow: one half of the result, omitting the failure to act and its cause."},{"id":"D","text":"Residents refused to accept the flood maps'' information and did not update their beliefs about risk.","is_correct":false,"explanation":"Contradicts the text, which says residents did update their beliefs."}]'::jsonb, 'A', 'Step 1 — Locate the paradox
The researchers note knowledge moved belief without moving conduct {{yellow:because the same facts that alarmed residents also persuaded them that action was futile}}.
Step 2 — Why A follows
It joins the heightened belief, the unchanged action, and the fatalistic cause—the full finding.
Distractor analysis:
- B: Contradicts the trial, which undercuts the inform-and-act assumption.
- C: True but only half the result, missing the inaction.
- D: Contradicts the finding that residents did update their beliefs.', 'The information changed one thing but not another—and for a surprising reason.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c02c532e-a7f3-43c0-a273-d4602036c594', 'Which choice best states the main idea of the text?', 'Scholars of the Industrial Revolution once treated rising wages as proof that workers shared in new prosperity. A study of factory account books unsettles this measure. Nominal wages did climb, but so did the length and intensity of the working day, and much of the pay increase compensated for hours and effort previously spent on self-directed domestic production now surrendered to the factory clock. When earnings are weighed against the labor and autonomy given up to obtain them, the apparent gain narrows sharply. The author stops short of denying any improvement, but insists that wage figures, read alone, flatter a transformation whose costs they were never designed to record.', NULL, '[{"id":"A","text":"The study argues that rising factory wages overstate workers'' gains because they ignore the increased labor and lost autonomy required to earn them.","is_correct":true,"explanation":"Correct: it captures the critique that wage figures omit the offsetting costs."},{"id":"B","text":"Rising nominal wages during the Industrial Revolution prove that factory workers fully shared in the era''s new prosperity.","is_correct":false,"explanation":"This is the view the study unsettles, contradicting its argument."},{"id":"C","text":"Nominal wages rose during the Industrial Revolution as recorded in factory account books.","is_correct":false,"explanation":"True but narrow: one premise, not the author''s critical conclusion."},{"id":"D","text":"The author concludes that factory workers experienced no improvement at all from the rise in wages.","is_correct":false,"explanation":"Overstated: the author stops short of denying any improvement."}]'::jsonb, 'A', 'Step 1 — Find the critique
The author insists that {{yellow:wage figures, read alone, flatter a transformation whose costs they were never designed to record}}.
Step 2 — Why A follows
The gain narrows once lost labor and autonomy are counted, so wages overstate workers'' gains—A''s claim.
Distractor analysis:
- B: The view the study unsettles.
- C: True but merely a premise.
- D: Overstated; the author does not deny all improvement.', 'The author criticizes wages ''read alone''—what do they leave out?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2bfa1f90-574b-4fe7-851f-60c97a6a73f0', 'Which choice best states the main idea of the text?', 'Astronomers searching for habitable worlds have leaned on the ''habitable zone,'' the orbital band where a planet''s surface could hold liquid water. A modeling team argues the concept can mislead. A planet in that zone, they show, may still freeze if its atmosphere is thin or boil if its greenhouse gases run high, while a world outside the zone might host subsurface oceans warmed from within. The team does not discard the habitable zone but recasts it: orbital distance sets a rough boundary condition, yet whether a planet is actually livable depends on properties—atmosphere, internal heat—that distance alone cannot reveal.', NULL, '[{"id":"A","text":"The team argues that a planet''s orbital position within the habitable zone is only a rough starting point, since actual livability depends on factors like atmosphere and internal heat that distance cannot capture.","is_correct":true,"explanation":"Correct: it captures the recasting of the zone as insufficient on its own."},{"id":"B","text":"A planet''s location within the habitable zone reliably determines whether it can support liquid water on its surface.","is_correct":false,"explanation":"Contradicts the text, which shows zone planets may freeze or boil."},{"id":"C","text":"Some worlds outside the habitable zone might host subsurface oceans warmed by internal heat.","is_correct":false,"explanation":"True but narrow: one illustrative example, not the central argument."},{"id":"D","text":"The team concludes that the habitable-zone concept is useless and should be abandoned by astronomers.","is_correct":false,"explanation":"Overstated: the text says the team does not discard the zone but recasts it."}]'::jsonb, 'A', 'Step 1 — Find the recast claim
The team holds that {{yellow:whether a planet is actually livable depends on properties—atmosphere, internal heat—that distance alone cannot reveal}}.
Step 2 — Why A follows
Orbital distance is a rough boundary, not a verdict, exactly A''s framing.
Distractor analysis:
- B: Contradicts the examples of zone planets freezing or boiling.
- C: True but a single illustrative case.
- D: Overstated; the team recasts rather than discards the concept.', 'The team keeps the habitable zone but downgrades its role—to what?', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('851db332-d637-4470-809e-169ada48217b', 'Which choice best states the main idea of the text?', 'Historians once portrayed the medieval guild as a brake on innovation, its rules suppressing the ambition of individual craftsmen. Recent scholarship complicates this view. Guild statutes did fix prices and standardize techniques, yet the same regulations funded shared workshops, underwrote apprentices'' training, and pooled the risk of importing costly raw materials. A weaver who could never have afforded foreign dye alone gained access to it through collective purchase. The guild thus did not merely restrain its members; by distributing both cost and knowledge, it created conditions under which experimentation became affordable for those who would otherwise have lacked the means.', NULL, '[{"id":"A","text":"Medieval guilds suppressed individual ambition by fixing prices and standardizing techniques.","is_correct":false,"explanation":"This restates only the older view the text explicitly complicates and rejects."},{"id":"B","text":"Although guilds imposed restrictive rules, those same rules made innovation accessible to members who could not have afforded it independently.","is_correct":true,"explanation":"It captures the text''s central claim that regulation and shared resources together enabled experimentation."},{"id":"C","text":"Guilds existed primarily to import costly foreign raw materials such as dyes.","is_correct":false,"explanation":"The dye is one illustrative example, not the guild''s primary purpose; this is too narrow."},{"id":"D","text":"Modern historians have reached a firm consensus that medieval guilds were beneficial.","is_correct":false,"explanation":"The text says scholarship ''complicates'' the view; it asserts no firm consensus that guilds were simply beneficial."}]'::jsonb, 'B', 'Step 1 — Locate the pivot
The text concedes guilds ''fix prices and standardize techniques,'' yet stresses the same rules {{yellow:created conditions under which experimentation became affordable for those who would otherwise have lacked the means}}.
Step 2 — Synthesize both sides
The main idea holds both halves together: restriction and enablement are two faces of the same regulation, which is exactly what B states.
Distractor analysis:
- A: Reverses the argument by endorsing only the older view the text rejects.
- C: Too narrow; the dye is a single example, not the guild''s purpose.
- D: No-evidence overreach; ''complicates'' is not a ''firm consensus'' that guilds were beneficial.', 'The correct answer should hold together both the restriction and the benefit the text describes.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('02f99f1a-294f-4c75-bf02-a9621a9da9f9', 'Which choice best states the main idea of the text?', 'In Helena Voss''s novel, the lighthouse keeper Aldous keeps a meticulous ledger of every ship he guides to harbor, reciting the tally to visitors as proof of a life well spent. Yet the narrator lingers not on the rescued vessels but on the unrecorded nights when fog swallowed the beam and Aldous could only listen, helpless, to bells fading into rock. His pride in the ledger, the narrator suggests, is less a measure of what he has accomplished than a wall he has built against the memory of what he could not prevent.', NULL, '[{"id":"A","text":"Aldous''s ledger accurately records the many ships he has successfully guided to harbor.","is_correct":false,"explanation":"True but irrelevant to the narrator''s point about why Aldous clings to the ledger."},{"id":"B","text":"Aldous''s pride in his record of rescues functions chiefly to shield him from guilt over the losses he could not prevent.","is_correct":true,"explanation":"This matches the narrator''s claim that the ledger is ''a wall'' against painful memory."},{"id":"C","text":"Aldous is a careless keeper whose negligence caused ships to wreck on the rocks.","is_correct":false,"explanation":"The text shows him ''helpless,'' not negligent; this contradicts the passage."},{"id":"D","text":"Visitors to the lighthouse are impressed by the length of Aldous''s tally of rescues.","is_correct":false,"explanation":"The text does not describe visitors'' reactions; this is unsupported and beside the point."}]'::jsonb, 'B', 'Step 1 — Find the interpretive turn
The narrator reframes the ledger as {{yellow:a wall he has built against the memory of what he could not prevent}}.
Step 2 — Identify the central claim
The pride is psychological defense, not genuine self-assessment, which is exactly what B states.
Distractor analysis:
- A: True but irrelevant; the accuracy of the ledger is not the narrator''s concern.
- C: Contradicts the text, which shows Aldous ''helpless,'' not negligent.
- D: No evidence; visitors'' impressions are never described.', 'Focus on what the narrator says the ledger really does for Aldous, not what it literally records.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('365e7052-d1b5-4777-be30-4a8801e72b1d', 'Which choice best states the main idea of the text?', 'Ecologists studying coral reefs long assumed that the brightest, most diverse reefs were the healthiest. Surveys of reefs recovering from a 2016 heat wave unsettled that assumption. Some vividly colored reefs were dominated by a few fast-growing, heat-sensitive species poised to collapse in the next warm spell, while drabber reefs harbored slower-growing corals with broader thermal tolerance. Visual splendor, the researchers concluded, can signal not resilience but fragility: a reef''s appearance reflects which species happen to be thriving now, not which are equipped to endure the conditions that lie ahead.', NULL, '[{"id":"A","text":"A coral reef''s striking appearance may reflect a fragile dominance by vulnerable species rather than genuine resilience.","is_correct":true,"explanation":"This captures the researchers'' conclusion that splendor can signal fragility, not health."},{"id":"B","text":"The 2016 heat wave destroyed most of the world''s brightly colored coral reefs.","is_correct":false,"explanation":"The text discusses reefs recovering from the heat wave, not their wholesale destruction."},{"id":"C","text":"Slower-growing corals are always healthier than fast-growing corals.","is_correct":false,"explanation":"The text claims thermal tolerance varies, not that slow growth is universally healthier; too absolute."},{"id":"D","text":"Ecologists can reliably judge reef health from color and species diversity.","is_correct":false,"explanation":"This reverses the text''s argument, which undermines appearance as a reliable indicator."}]'::jsonb, 'A', 'Step 1 — Locate the reversal
The researchers conclude that {{yellow:visual splendor, the researchers concluded, can signal not resilience but fragility}}.
Step 2 — Generalize correctly
The main idea is that appearance reflects present thriving, not future endurance, exactly as A states.
Distractor analysis:
- B: Misreads ''recovering'' as destroyed; no claim of wholesale loss.
- C: Too absolute; the text ties health to thermal tolerance, not growth speed alone.
- D: Reverses the conclusion the text builds against.', 'The answer should reflect the surprising link the researchers draw between beauty and vulnerability.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('01551666-cdc1-41cc-bbfc-590ef53483c0', 'Which choice best states the main idea of the text?', 'When the printing press spread through sixteenth-century Europe, contemporaries praised it for preserving knowledge against the ravages of time. Yet print could also entrench error. A manuscript copyist might silently correct an obvious mistake, but once a flawed text was set in type and run off in a thousand identical copies, the error acquired the durability and apparent authority of all the rest. Print did not simply fix knowledge in place; it fixed whatever happened to be printed, true or false, with equal and unprecedented permanence.', NULL, '[{"id":"A","text":"The printing press preserved valuable knowledge that would otherwise have been lost to time.","is_correct":false,"explanation":"This captures only the praise the text qualifies, not its central, complicating point."},{"id":"B","text":"The printing press preserved both accurate and erroneous texts alike, giving errors the same durability as truths.","is_correct":true,"explanation":"This matches the claim that print fixed ''whatever happened to be printed, true or false.''"},{"id":"C","text":"Manuscript copyists were more reliable than printers at producing accurate texts.","is_correct":false,"explanation":"The text notes copyists could correct errors but does not rank overall reliability; too broad."},{"id":"D","text":"Sixteenth-century readers distrusted printed books because of their frequent errors.","is_correct":false,"explanation":"The text says contemporaries praised print; it offers no evidence of distrust."}]'::jsonb, 'B', 'Step 1 — Find the qualifying claim
The text states print {{yellow:fixed whatever happened to be printed, true or false, with equal and unprecedented permanence}}.
Step 2 — State the balanced idea
The main idea is that print''s permanence applied indiscriminately to truth and error, exactly as B says.
Distractor analysis:
- A: Only the praise, ignoring the text''s complicating turn.
- C: Too broad; the text doesn''t rank overall reliability of copyists versus printers.
- D: No evidence; contemporaries praised, not distrusted, print.', 'The text complicates the praise for print; the answer should reflect both sides of that durability.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('70b1e993-7bf3-4782-82d4-796e4b4829e8', 'Which choice best states the main idea of the text?', 'Economists debating the minimum wage often assume firms respond to a mandated raise in only one way: by cutting jobs. A study of fast-food franchises across a state border, where one side raised its wage and the other did not, found a more tangled picture. Some franchises did trim hours, but others raised prices slightly, reduced employee turnover, or absorbed the cost through thinner profits. The lesson, the authors argue, is not that wage increases never reduce employment but that the response varies so widely that any single predicted outcome obscures more than it reveals.', NULL, '[{"id":"A","text":"Raising the minimum wage never reduces employment at fast-food franchises.","is_correct":false,"explanation":"The text explicitly denies this, saying increases sometimes do reduce hours."},{"id":"B","text":"Firms respond to minimum-wage increases in such varied ways that any single predicted outcome is misleading.","is_correct":true,"explanation":"This matches the authors'' argument that responses vary too widely for one prediction."},{"id":"C","text":"Fast-food franchises typically respond to wage increases by raising their prices.","is_correct":false,"explanation":"Price increases are one of several responses listed, not the typical one; too narrow."},{"id":"D","text":"A wage increase on one side of a state border eliminated cross-border competition.","is_correct":false,"explanation":"Competition is not discussed; this is an unsupported synthesis."}]'::jsonb, 'B', 'Step 1 — Identify the authors'' conclusion
They argue {{yellow:the response varies so widely that any single predicted outcome obscures more than it reveals}}.
Step 2 — Match the balanced idea
The central point is the diversity of firm responses defeats single predictions, exactly as B states.
Distractor analysis:
- A: Reverses the text, which says increases sometimes do cut hours.
- C: Too narrow; price hikes are just one of several listed responses.
- D: No evidence; cross-border competition is never mentioned.', 'The authors resist any single prediction; the answer should reflect that variety, not pick one response.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a9851816-8cae-4169-9612-a362636aed8c', 'Which choice best states the main idea of the text?', 'Anthropologists studying gift exchange in several societies once treated generosity as the opposite of self-interest. Closer fieldwork has blurred that line. In the communities described, a lavish gift obligates its recipient to reciprocate, often more grandly, so that giving becomes a way of accruing status and binding others into ongoing debt. This does not mean the giver feels no real warmth; rather, warmth and calculation coexist, and the same act can express affection while advancing the giver''s standing. To call such exchange purely altruistic, the researchers note, is to miss half of what it accomplishes.', NULL, '[{"id":"A","text":"Gift exchange in these societies is a purely calculated strategy for gaining status, devoid of genuine feeling.","is_correct":false,"explanation":"The text says warmth and calculation coexist; this erases the warmth and overstates the calculation."},{"id":"B","text":"In these societies, gift exchange blends genuine generosity with the pursuit of status and obligation.","is_correct":true,"explanation":"This matches the claim that warmth and calculation coexist in the same act."},{"id":"C","text":"Recipients of lavish gifts resent the obligation to reciprocate them.","is_correct":false,"explanation":"Resentment is never mentioned; this is unsupported."},{"id":"D","text":"Anthropologists have abandoned the study of gift exchange as unproductive.","is_correct":false,"explanation":"The text describes ongoing fieldwork, the opposite of abandonment; this contradicts the passage."}]'::jsonb, 'B', 'Step 1 — Find the both/and claim
The text states {{yellow:warmth and calculation coexist, and the same act can express affection while advancing the giver''s standing}}.
Step 2 — State the blended idea
The main idea fuses generosity and self-interest, exactly as B does.
Distractor analysis:
- A: One-sided; it deletes the genuine warmth the text affirms.
- C: No evidence; recipient resentment is never raised.
- D: Contradicts the text''s account of active ''closer fieldwork.''', 'The text refuses to separate generosity from self-interest; the answer should keep both.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ee5f229a-89f3-4539-8fc4-dadb87446bc2', 'Which choice best states the main idea of the text?', 'Biographers of the chemist Rosalind Frame have disagreed sharply over a gap in her published output between 1931 and 1935. One camp reads the silence as evidence of a crisis of confidence following a public dispute with a rival. Another points to her surviving notebooks, dense with calculations, and argues she was simply working on problems too unfinished to publish. A recent study reconciles the two: the notebooks show not paralysis but a deliberate retreat from publication, a choice to refine her ideas in private precisely because the earlier dispute had taught her the cost of premature claims.', NULL, '[{"id":"A","text":"Frame''s four-year silence reflected a crisis of confidence brought on by a public dispute.","is_correct":false,"explanation":"This is only one earlier camp''s view, which the recent study revises."},{"id":"B","text":"Frame''s silent years reflected a deliberate, dispute-informed choice to refine her ideas privately before publishing.","is_correct":true,"explanation":"This matches the recent study''s reconciliation of the two camps."},{"id":"C","text":"Frame stopped doing chemistry entirely between 1931 and 1935.","is_correct":false,"explanation":"Her notebooks were ''dense with calculations,'' contradicting any claim she stopped working."},{"id":"D","text":"Biographers agree that Frame''s rival was responsible for her later breakthroughs.","is_correct":false,"explanation":"The text shows disagreement, not agreement, and never credits the rival with breakthroughs."}]'::jsonb, 'B', 'Step 1 — Identify the reconciling claim
The recent study finds the notebooks show {{yellow:a deliberate retreat from publication, a choice to refine her ideas in private}}.
Step 2 — State the synthesis
The main idea is that the silence was a purposeful, dispute-shaped strategy, exactly as B states.
Distractor analysis:
- A: Only the first camp''s view, which the study revises.
- C: Contradicts notebooks ''dense with calculations.''
- D: No evidence and overstates agreement among biographers.', 'The recent study merges the two camps; the answer should capture that combined, intentional explanation.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a97a8d39-8209-470a-876b-bbe0f98b1f79', 'Which choice best states the main idea of the text?', 'Urban planners in the early twentieth century championed the wide boulevard as an instrument of public health, reasoning that broad avenues would let in light and disperse the bad air blamed for disease. The reasoning rested on a mistaken theory of contagion, yet the boulevards often did improve health, though not for the imagined reason. By easing congestion and separating dwellings from open sewers, the avenues reduced exposure to genuine pathogens. The planners, in short, were right about the outcome and wrong about the mechanism, achieving a real benefit through a flawed chain of logic.', NULL, '[{"id":"A","text":"Early planners'' boulevards improved public health, but for reasons different from the flawed theory that inspired them.","is_correct":true,"explanation":"This matches ''right about the outcome and wrong about the mechanism.''"},{"id":"B","text":"Wide boulevards failed to improve public health because they were based on a mistaken theory of contagion.","is_correct":false,"explanation":"The text says the boulevards ''often did improve health''; this reverses the outcome."},{"id":"C","text":"Early twentieth-century planners correctly understood how diseases spread.","is_correct":false,"explanation":"The text says their theory of contagion was mistaken; this contradicts the passage."},{"id":"D","text":"Open sewers were the single greatest cause of urban disease in this period.","is_correct":false,"explanation":"Sewers are one factor mentioned; the text makes no claim ranking them as the greatest cause."}]'::jsonb, 'A', 'Step 1 — Find the paradox
The text concludes the planners were {{yellow:right about the outcome and wrong about the mechanism}}.
Step 2 — State the balanced idea
The main idea is a real benefit achieved through flawed reasoning, exactly as A states.
Distractor analysis:
- B: Reverses the outcome; the boulevards did improve health.
- C: Contradicts the ''mistaken theory of contagion.''
- D: No evidence ranking sewers as the single greatest cause.', 'The text separates the correct result from the wrong reasoning; the answer should keep both.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2bd0221e-add7-4ce3-81d3-9449aa9e508f', 'Which choice best states the main idea of the text?', 'In Tomas Reyes''s short story, an aging translator named Pilar is hired to render a celebrated poet''s final, unfinished manuscript into a new language. She discovers passages so fragmentary that any faithful rendering would require her to invent connective lines the poet never wrote. Pilar agonizes: to leave the gaps is to betray the reader, but to fill them is to betray the poet. The story withholds her final decision. What it dramatizes instead is the impossibility of a translation that is at once wholly faithful to the text and wholly intelligible to its audience.', NULL, '[{"id":"A","text":"Pilar ultimately decides to fill the manuscript''s gaps with lines of her own invention.","is_correct":false,"explanation":"The story ''withholds her final decision''; this asserts an outcome the text denies."},{"id":"B","text":"The story dramatizes the impossibility of a translation that is fully faithful to the original and fully clear to readers at once.","is_correct":true,"explanation":"This matches the text''s stated focus on that dual impossibility."},{"id":"C","text":"Pilar lacks the skill needed to translate the poet''s difficult manuscript.","is_correct":false,"explanation":"Her dilemma stems from the text''s fragmentation, not her incompetence; this is unsupported."},{"id":"D","text":"The poet deliberately left the manuscript unfinished to challenge future translators.","is_correct":false,"explanation":"The poet''s intent is never stated; this is an unsupported synthesis."}]'::jsonb, 'B', 'Step 1 — Locate the thematic statement
The text says it dramatizes {{yellow:the impossibility of a translation that is at once wholly faithful to the text and wholly intelligible to its audience}}.
Step 2 — State the central idea
The story''s point is this irreconcilable tension, exactly as B states.
Distractor analysis:
- A: Contradicts that the story ''withholds her final decision.''
- C: No evidence; the problem is the fragments, not Pilar''s skill.
- D: No evidence about the poet''s intent.', 'The story refuses to resolve Pilar''s choice; the answer should name the tension it illustrates instead.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8d36c509-72f0-4891-95ba-3d7ca08d292a', 'Which choice best states the main idea of the text?', 'Scholars of the Industrial Revolution have asked why mechanized cotton spinning took hold in Britain rather than in regions with comparable technical skill. A familiar answer credits cheap coal. A competing account stresses high British wages, which made labor-saving machines worth their cost. The most persuasive recent argument refuses to choose: cheap energy and expensive labor were each insufficient alone, but together they made mechanization profitable in Britain in a way it was not elsewhere. Neither factor explains the outcome; their particular combination does.', NULL, '[{"id":"A","text":"Cheap coal was the decisive factor that allowed mechanized spinning to take hold in Britain.","is_correct":false,"explanation":"The text says coal alone was insufficient; this isolates one factor the argument rejects as decisive."},{"id":"B","text":"Mechanized spinning took hold in Britain because cheap energy and high wages together, not either alone, made it profitable.","is_correct":true,"explanation":"This matches the claim that the ''particular combination'' explains the outcome."},{"id":"C","text":"High British wages alone explain why mechanization succeeded in Britain.","is_correct":false,"explanation":"The text states wages were ''insufficient alone''; this isolates one factor improperly."},{"id":"D","text":"Regions outside Britain lacked the technical skill to mechanize cotton spinning.","is_correct":false,"explanation":"The text says those regions had ''comparable technical skill''; this contradicts the passage."}]'::jsonb, 'B', 'Step 1 — Find the synthesis
The text argues {{yellow:Neither factor explains the outcome; their particular combination does}}.
Step 2 — State the combined idea
The main idea credits the joint effect of cheap energy and high wages, exactly as B states.
Distractor analysis:
- A: Isolates coal, which the text calls insufficient alone.
- C: Isolates wages, also called insufficient alone.
- D: Contradicts ''comparable technical skill.''', 'The strongest argument refuses to pick one cause; the answer should reflect the combination.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0a95137d-9e11-459e-8b05-554f44e62ead', 'Which choice best states the main idea of the text?', 'Researchers studying birdsong have debated whether a young bird''s song is shaped more by inheritance or by what it hears. Experiments raising chicks in isolation suggested both factors operate, but in an unexpected partnership. Isolated chicks produced a crude, simplified version of their species'' song, proof that some template is innate; yet only birds exposed to adult song refined that template into the full, locally varying melody. The innate template, the researchers argue, is not a finished song but a scaffold that experience must complete.', NULL, '[{"id":"A","text":"A young bird''s song is determined entirely by the inherited template it is born with.","is_correct":false,"explanation":"The text says experience must complete the template; inheritance alone is insufficient."},{"id":"B","text":"A bird''s full song arises from an innate template that learning from adult song must refine and complete.","is_correct":true,"explanation":"This matches the ''scaffold that experience must complete'' conclusion."},{"id":"C","text":"Birds raised in isolation produce no song at all.","is_correct":false,"explanation":"Isolated chicks produced a ''crude, simplified version,'' not no song; this contradicts the text."},{"id":"D","text":"A bird''s song depends solely on hearing the local songs of adult birds.","is_correct":false,"explanation":"This ignores the innate template the experiments demonstrate; it isolates experience improperly."}]'::jsonb, 'B', 'Step 1 — Identify the partnership
The researchers argue the innate template is {{yellow:not a finished song but a scaffold that experience must complete}}.
Step 2 — State the joint idea
The main idea combines inheritance and learning, exactly as B states.
Distractor analysis:
- A: Isolates inheritance, ignoring the needed refinement by experience.
- C: Contradicts the ''crude, simplified version'' isolated chicks produced.
- D: Isolates experience, ignoring the innate template.', 'The experiments show neither nature nor learning alone suffices; the answer should keep both.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7427c39d-88f3-4dfe-878a-f7bf30337f8b', 'Which choice best states the main idea of the text?', 'Critics of the Romantic poet Clara Wynn long treated her late nature poems as a retreat from the political concerns of her youth. A reconsideration challenges this reading. Wynn''s depictions of eroding coastlines and failing harvests, the critic argues, encode the same anxieties about an unjust social order that her early verse stated outright; the politics did not vanish but went underground, disguised as landscape. To read the late poems as apolitical is to mistake a change in method for a change in conviction.', NULL, '[{"id":"A","text":"Wynn''s late nature poems mark a retreat from the political concerns of her youth.","is_correct":false,"explanation":"This is the older reading the text explicitly challenges."},{"id":"B","text":"Wynn''s late poems express her enduring political convictions through landscape imagery rather than abandoning them.","is_correct":true,"explanation":"This matches the claim that politics ''went underground, disguised as landscape.''"},{"id":"C","text":"Wynn''s early verse was less effective than her late nature poems.","is_correct":false,"explanation":"The text compares method, not effectiveness; this ranking is unsupported."},{"id":"D","text":"Wynn abandoned poetry entirely after her politically explicit early period.","is_correct":false,"explanation":"The text discusses her late poems, so she clearly continued writing; this contradicts the passage."}]'::jsonb, 'B', 'Step 1 — Find the reinterpretation
The critic argues the politics {{yellow:did not vanish but went underground, disguised as landscape}}.
Step 2 — State the central idea
Wynn''s convictions persisted in altered form, exactly as B states; the change was method, not conviction.
Distractor analysis:
- A: Restates the reading the text rejects.
- C: No evidence ranking early versus late poems'' effectiveness.
- D: Contradicts the existence of the late poems under discussion.', 'The text says her method changed but her convictions did not; the answer should reflect that distinction.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('50a45399-7211-46e2-9bf1-795fbc22b4cf', 'Which choice best states the main idea of the text?', 'Historians once portrayed the medieval guild as a brake on innovation, a cartel that fixed prices and suppressed ambitious craftsmen. Recent scholarship complicates this picture. Guilds did restrict who could sell goods, yet they also financed the long apprenticeships through which technical knowledge was transmitted, knowledge that no single master could have afforded to teach for free. Where guilds collapsed early, certain trades lost not their competition but their accumulated expertise. The institution that constrained the market, it seems, may also have been the institution that preserved the very skills the market depended on.', NULL, '[{"id":"A","text":"Medieval guilds fixed prices and deliberately suppressed talented craftsmen who threatened established masters.","is_correct":false,"explanation":"This restates only the older view the text says recent scholarship complicates."},{"id":"B","text":"Although guilds limited market competition, they may also have safeguarded technical expertise that competition alone would not have preserved.","is_correct":true,"explanation":"It captures the text''s reconciliation of the guild''s restrictive and preservative functions."},{"id":"C","text":"Trades that lost their guilds early became more competitive than trades that retained them.","is_correct":false,"explanation":"The text says such trades lost expertise, not that they gained competitiveness as a main point."},{"id":"D","text":"Apprenticeships were too expensive for any single master to fund without assistance.","is_correct":false,"explanation":"This is a supporting detail, not the central claim about the guild''s dual role."}]'::jsonb, 'B', 'Step 1 — Find the pivot
The text reframes guilds with {{yellow:The institution that constrained the market, it seems, may also have been the institution that preserved the very skills the market depended on.}}
Step 2 — Match the dual claim
The main idea unites restriction and preservation, which is exactly what B states.
Distractor analysis:
- A: Restates only the discarded older view, which the text says is complicated.
- C: Reverses the text; lost guilds meant lost expertise, not gained competitiveness.
- D: A true supporting detail, too narrow to be the main idea.', 'The main idea must reconcile both halves of the guild''s role, not just the negative one.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('160428d1-813b-4cec-a735-a12e1abd3c3f', 'Which choice best states the main idea of the text?', 'In Toni Cade Bambara''s story, the narrator Sylvia resents Miss Moore''s lesson trip to an expensive toy store. She mocks the woman''s教 earnestness and the absurd prices, insisting she has learned nothing. Yet by the closing pages, Sylvia lingers behind the others, refusing to race her cousin home, and admits that something is gnawing at her she cannot name. Her bravado has not vanished, but it now coexists with a private arithmetic about who can afford a thirty-five-dollar toy and who cannot.', NULL, '[{"id":"A","text":"Sylvia openly thanks Miss Moore for teaching her an important lesson about money.","is_correct":false,"explanation":"The text shows resistance, not open gratitude; her change is unspoken."},{"id":"B","text":"Sylvia''s outward defiance persists even as an unsettling new awareness begins to take hold in her.","is_correct":true,"explanation":"It captures the coexistence of her bravado and her dawning, unnamed realization."},{"id":"C","text":"Sylvia is unaffected by the trip and dismisses Miss Moore''s lesson entirely.","is_correct":false,"explanation":"Her lingering and unnamed gnawing feeling contradict total dismissal."},{"id":"D","text":"Miss Moore intends the trip to humiliate the children with prices they cannot afford.","is_correct":false,"explanation":"The text never states Miss Moore''s intent to humiliate; it focuses on Sylvia."}]'::jsonb, 'B', 'Step 1 — Locate the tension
The close shows mixed feeling: {{yellow:Her bravado has not vanished, but it now coexists with a private arithmetic about who can afford a thirty-five-dollar toy and who cannot.}}
Step 2 — Read both states together
Defiance lingers while awareness grows, which is precisely B.
Distractor analysis:
- A: Overstates change; her realization is private and unspoken, not open thanks.
- C: Ignores the gnawing feeling and her lingering behind, signs she is affected.
- D: Introduces an intent the text never assigns to Miss Moore.', 'Notice the word ''coexists''; the answer should hold two opposed states at once.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3e535d85-6c98-4bff-ab13-c95eb94bf13b', 'Which choice best states the main idea of the text?', 'Astronomers detecting exoplanet atmospheres often celebrate the discovery of water vapor as a sign of habitability. But water''s spectral signature can appear on worlds far too hot for liquid oceans, where it exists only as scalding gas. A planet may also possess abundant water yet lack the carbon chemistry or stable temperatures life seems to require. Detecting one favorable ingredient, researchers caution, says little about whether the others are present. The headline-friendly molecule is necessary for life as we know it, but it is a poor stand-in for the full set of conditions life demands.', NULL, '[{"id":"A","text":"Water vapor in an exoplanet''s atmosphere reliably indicates that the planet can support life.","is_correct":false,"explanation":"This is the assumption the text works to undercut."},{"id":"B","text":"Detecting water vapor is encouraging but insufficient evidence of habitability, since other necessary conditions may be absent.","is_correct":true,"explanation":"It balances water''s importance against its inadequacy as a sole indicator."},{"id":"C","text":"Water vapor is irrelevant to assessing whether a planet might host life.","is_correct":false,"explanation":"The text calls water necessary, not irrelevant."},{"id":"D","text":"Most exoplanets with water vapor are too hot to hold liquid oceans.","is_correct":false,"explanation":"This is one supporting example, not a claim about most planets or the main point."}]'::jsonb, 'B', 'Step 1 — Find the qualifier
The text concludes: {{yellow:it is a poor stand-in for the full set of conditions life demands.}}
Step 2 — Hold both halves
Water matters but is not enough on its own, exactly B''s balance.
Distractor analysis:
- A: States the reliable-indicator view the text explicitly rejects.
- C: Overcorrects; the text calls water necessary, not irrelevant.
- D: Generalizes a single example into an unsupported claim about most planets.', 'Reject options that make water either fully sufficient or fully useless.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d4df0ae2-0f57-4e30-a090-37c05facde54', 'Which choice best states the main idea of the text?', 'After the 1923 earthquake devastated Tokyo, planners drafted ambitious blueprints to widen streets, create parks, and impose a rational grid on the rebuilt city. Property owners, however, resisted ceding land, and the national treasury balked at the cost. The reconstruction that actually occurred preserved much of the old, crooked street pattern even as it introduced scattered fireproof buildings and a few broad avenues. The modern Tokyo that emerged was thus neither the visionaries'' clean slate nor a simple restoration of what had stood before, but a negotiated compromise written into the map itself.', NULL, '[{"id":"A","text":"Planners successfully imposed a rational grid on Tokyo after the 1923 earthquake.","is_correct":false,"explanation":"The text says the grand plans were largely thwarted, not realized."},{"id":"B","text":"Postearthquake Tokyo was rebuilt as a compromise between sweeping redesign and faithful restoration, reflecting competing pressures.","is_correct":true,"explanation":"It captures the negotiated middle outcome the text emphasizes."},{"id":"C","text":"Property owners and the treasury together prevented any rebuilding of Tokyo.","is_correct":false,"explanation":"Rebuilding did occur, including avenues and fireproof buildings; they only limited the grand plan."},{"id":"D","text":"The 1923 earthquake caused widespread fires that destroyed Tokyo''s older neighborhoods.","is_correct":false,"explanation":"The text addresses reconstruction politics, not the fire damage''s extent."}]'::jsonb, 'B', 'Step 1 — Find the synthesis
The passage ends: {{yellow:neither the visionaries'' clean slate nor a simple restoration of what had stood before, but a negotiated compromise written into the map itself.}}
Step 2 — Name the outcome
That compromise between extremes is exactly B.
Distractor analysis:
- A: Contradicts the text; the grid was largely resisted, not imposed.
- B: Correct.
- C: Overstates resistance; rebuilding clearly happened.
- D: Introduces fire damage the text does not discuss.', 'The ''neither... nor... but'' structure points to a middle-path main idea.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('989ee5f9-9bc0-410f-b63c-cde9ac573935', 'Which choice best states the main idea of the text?', 'Economists studying minimum-wage increases long assumed that raising the wage floor must reduce employment, as employers would hire fewer workers at higher costs. A wave of studies comparing neighboring counties across state lines challenged that certainty, finding little employment loss after modest increases. Skeptics replied that large or rapid hikes might still cost jobs, and that local conditions vary. The debate has shifted: the question is no longer whether minimum wages always destroy jobs, but under what specific magnitudes and circumstances they might, an admission that the old blanket rule no longer holds.', NULL, '[{"id":"A","text":"Raising the minimum wage always reduces employment, as employers cut hiring.","is_correct":false,"explanation":"This is the blanket rule the text says no longer holds."},{"id":"B","text":"Minimum-wage increases never affect employment under any circumstances.","is_correct":false,"explanation":"The text allows that large hikes might still cost jobs, so ''never'' overreaches."},{"id":"C","text":"Evidence has replaced a blanket rule about minimum wages with a conditional question about when increases might cost jobs.","is_correct":true,"explanation":"It captures the shift from certainty to context-dependent inquiry."},{"id":"D","text":"Studies comparing neighboring counties are the only valid way to measure wage effects.","is_correct":false,"explanation":"The text never claims this method is uniquely valid."}]'::jsonb, 'C', 'Step 1 — Track the reframing
The text states the question is now {{yellow:no longer whether minimum wages always destroy jobs, but under what specific magnitudes and circumstances they might}}.
Step 2 — Match the shift
That move from absolute rule to conditional inquiry is C.
Distractor analysis:
- A: Restates the old rule the evidence overturned.
- B: Goes too far; the text concedes large hikes might still cost jobs.
- C: Correct.
- D: Overstates the method''s status, which the text does not assert.', 'The answer should describe a shift, not pick a side in the original debate.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a6cb8433-8baf-4c1c-9703-be5d40714580', 'Which choice best states the main idea of the text?', 'In Edith Wharton''s novel, Lily Bart is admired for a beauty that seems effortless, yet the narrator reveals the labor behind it: the careful debts incurred for gowns, the calculated invitations, the fatigue she hides beneath composure. Lily understands that her charm is also her livelihood, a currency she must spend wisely in a marriage market that offers women like her no other capital. Her grace is genuine, but it is never free; each appearance of ease is purchased with a vigilance that the society admiring her refuses to see.', NULL, '[{"id":"A","text":"Lily''s beauty is entirely natural and requires no effort on her part.","is_correct":false,"explanation":"The text exposes the hidden labor behind her apparent ease."},{"id":"B","text":"Lily''s seemingly effortless charm is in fact carefully and costly maintained labor within a market that gives her no other resource.","is_correct":true,"explanation":"It unites the appearance of ease with the concealed effort and economic necessity."},{"id":"C","text":"Lily openly resents the society that admires her and refuses to participate in it.","is_correct":false,"explanation":"She participates strategically; the text shows calculation, not refusal."},{"id":"D","text":"The society around Lily fully understands the work behind her elegance.","is_correct":false,"explanation":"The text says that society refuses to see this work."}]'::jsonb, 'B', 'Step 1 — Expose the hidden cost
The narrator notes that {{yellow:each appearance of ease is purchased with a vigilance that the society admiring her refuses to see.}}
Step 2 — Combine ease and labor
The main idea joins surface grace with hidden, necessary effort, which is B.
Distractor analysis:
- A: Contradicts the revealed labor and debts.
- B: Correct.
- C: Misreads strategy as open refusal.
- D: Reverses the text, which says society refuses to see the work.', 'The decisive line stresses that ease is ''purchased''; the answer must reflect that cost.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('00d98c51-e818-4433-bc95-566fd11fd58a', 'Which choice best states the main idea of the text?', 'Conservationists have debated whether to fight invasive species or accept them. On one Pacific island, removing introduced rats restored native seabird colonies, whose droppings in turn fertilized coral reefs offshore. Yet on the same island, an introduced tree now shelters several endemic insects whose original host plants are extinct. Eradicating it would doom them. The lesson emerging from such cases is not that invasives are uniformly harmful or harmless, but that each newcomer''s effects ripple through a particular web of relationships that must be traced before any verdict is reached.', NULL, '[{"id":"A","text":"Invasive species are uniformly harmful and should always be eradicated.","is_correct":false,"explanation":"The introduced-tree example shows an invasive providing benefit, contradicting this."},{"id":"B","text":"Removing introduced rats is the most effective conservation strategy available.","is_correct":false,"explanation":"One example cannot support a claim about the single best strategy."},{"id":"C","text":"An invasive species'' impact depends on its specific ecological relationships, which must be examined before judging it.","is_correct":true,"explanation":"It captures the case-by-case, web-tracing lesson the text draws."},{"id":"D","text":"Endemic insects on the Pacific island depend entirely on an introduced tree.","is_correct":false,"explanation":"This is one supporting detail, not the general principle the text advances."}]'::jsonb, 'C', 'Step 1 — Find the principle
The text concludes that {{yellow:each newcomer''s effects ripple through a particular web of relationships that must be traced before any verdict is reached.}}
Step 2 — Generalize correctly
Impact is context-specific and must be traced, exactly C.
Distractor analysis:
- A: Contradicted by the beneficial introduced tree.
- B: Overgeneralizes a single rat-removal example.
- C: Correct.
- D: A narrow detail mistaken for the broad lesson.', 'Two opposite examples signal a ''it depends, examine each case'' main idea.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('98ac5f4c-05b6-4440-b644-849230f3dbc2', 'Which choice best states the main idea of the text?', 'Eighteenth-century mapmakers prided themselves on filling blank spaces, and empty regions on a chart were taken as confessions of ignorance. Some cartographers therefore inked in speculative rivers and mountains rather than admit they knew nothing. A reformist current eventually argued the opposite: that an honest blank was more useful than a confident fabrication, since a fiction could mislead an explorer to his death while a void at least warned him to proceed with care. The prestige of the full map, these critics held, had quietly become an enemy of the accurate one.', NULL, '[{"id":"A","text":"Eighteenth-century maps were generally more accurate than earlier maps because they contained fewer blanks.","is_correct":false,"explanation":"The text says filled-in detail was often fabricated, undermining accuracy."},{"id":"B","text":"Reformers argued that the prestige of completeness in mapmaking had come to undermine accuracy, making honest blanks preferable to fabrications.","is_correct":true,"explanation":"It captures the critics'' claim that fullness conflicted with truth."},{"id":"C","text":"Explorers always died when they relied on maps with blank spaces.","is_correct":false,"explanation":"The text says blanks warned explorers, while fictions could mislead them to death."},{"id":"D","text":"Cartographers invented rivers and mountains to make their maps more beautiful.","is_correct":false,"explanation":"The motive given is avoiding the appearance of ignorance, not beauty."}]'::jsonb, 'B', 'Step 1 — Find the critics'' claim
The text reports: {{yellow:The prestige of the full map, these critics held, had quietly become an enemy of the accurate one.}}
Step 2 — Restate the tension
Completeness undermined accuracy, so honest blanks were better, which is B.
Distractor analysis:
- A: Reverses the point; fuller maps were often less accurate.
- B: Correct.
- C: Misassigns the danger; fictions, not blanks, could be fatal.
- D: Substitutes beauty for the actual motive of hiding ignorance.', 'The key line calls fullness an ''enemy'' of accuracy; let that drive the answer.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7d18316d-328a-4c57-b33a-0ac87bc73c45', 'Which choice best states the main idea of the text?', 'Neuroscientists once treated forgetting as the brain''s failure, a leak in an otherwise reliable vessel. Newer models propose that controlled forgetting is an active and useful process. By discarding outdated or trivial details, the brain keeps general patterns from being buried under particulars, allowing it to generalize and adapt. People who remember everything, rare cases suggest, can struggle to abstract or to let go of painful specifics. Forgetting, on this view, is not the breakdown of memory but one of the systems by which memory remains flexible and serviceable.', NULL, '[{"id":"A","text":"Forgetting is a malfunction that newer research has confirmed harms cognition.","is_correct":false,"explanation":"The text argues the opposite, that forgetting can be beneficial and active."},{"id":"B","text":"People who remember everything have superior cognitive abilities in every respect.","is_correct":false,"explanation":"The text notes such people may struggle to abstract, contradicting universal superiority."},{"id":"C","text":"Controlled forgetting is an active process that helps keep memory flexible rather than a mere failure of recall.","is_correct":true,"explanation":"It captures the reframing of forgetting as functional rather than defective."},{"id":"D","text":"The brain stores general patterns in a different region than specific details.","is_correct":false,"explanation":"The text makes no claim about separate storage regions."}]'::jsonb, 'C', 'Step 1 — Find the redefinition
The text states forgetting is {{yellow:not the breakdown of memory but one of the systems by which memory remains flexible and serviceable.}}
Step 2 — Restate the new view
Forgetting is active and adaptive, exactly C.
Distractor analysis:
- A: Restates the discarded failure view the text overturns.
- B: Contradicted by the noted difficulty such people have abstracting.
- C: Correct.
- D: Invents a storage claim the text never makes.', 'The contrast ''not the breakdown but one of the systems'' frames the main idea.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2f0dbf4a-7884-4636-8721-969385a8f54d', 'Which choice best states the main idea of the text?', 'When archaeologists unearthed a Bronze Age settlement with no defensive walls, some concluded its people had lived in peace. Others noted that the absence of walls proves only the absence of walls: the community might have relied on alliances, on distance from rivals, or on weapons that left little trace. Buried spearheads later recovered nearby complicated the peaceful reading further. The site, the excavators concluded, could not be made to confess tranquility merely because one familiar marker of conflict happened to be missing from its ruins.', NULL, '[{"id":"A","text":"The Bronze Age settlement was certainly a peaceful community because it had no walls.","is_correct":false,"explanation":"The text rejects inferring peace from missing walls."},{"id":"B","text":"The absence of defensive walls does not by itself establish that the settlement was peaceful.","is_correct":true,"explanation":"It captures the excavators'' caution against the easy inference."},{"id":"C","text":"The recovered spearheads prove the settlement was frequently at war.","is_correct":false,"explanation":"The spearheads complicate the peaceful reading but are not said to prove frequent war."},{"id":"D","text":"Bronze Age communities generally avoided building defensive walls.","is_correct":false,"explanation":"The text discusses one site, not a general pattern across communities."}]'::jsonb, 'B', 'Step 1 — Find the caution
The excavators concluded the site {{yellow:could not be made to confess tranquility merely because one familiar marker of conflict happened to be missing from its ruins.}}
Step 2 — Restate the limit
Missing walls cannot establish peace, which is B.
Distractor analysis:
- A: Draws exactly the inference the text rejects.
- B: Correct.
- C: Overstates the spearheads, which complicate but do not prove frequent war.
- D: Generalizes one site into a claim about all communities.', 'The answer hinges on what an absence of evidence can and cannot prove.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5debbf2c-4ca9-42a1-9988-8148a6234341', 'Which choice best states the main idea of the text?', 'Translators of poetry face a dilemma often framed as fidelity versus beauty: stay literal and lose the music, or recreate the music and stray from the words. A subtler view rejects the choice as false. A translation too literal to move a reader, this view holds, is unfaithful to what made the original poetry in the first place, while a beautiful version that abandons the poem''s argument betrays it differently. True fidelity, then, is not to the dictionary nor to mere prettiness, but to the original''s particular fusion of sound and sense.', NULL, '[{"id":"A","text":"Faithful poetry translation requires staying as literal to the original words as possible.","is_correct":false,"explanation":"The text says a too-literal version is itself unfaithful."},{"id":"B","text":"Beauty should always take priority over accuracy when translating poems.","is_correct":false,"explanation":"The text says prettiness that abandons the argument betrays the poem."},{"id":"C","text":"Translating poetry is impossible because no version can capture the original.","is_correct":false,"explanation":"The text defines what fidelity is, implying good translation is possible."},{"id":"D","text":"True fidelity in translating poetry means honoring the original''s fusion of sound and sense, not literal words or mere beauty alone.","is_correct":true,"explanation":"It captures the rejection of the false choice in favor of an integrated fidelity."}]'::jsonb, 'D', 'Step 1 — Find the redefinition
The text states true fidelity is {{yellow:not to the dictionary nor to mere prettiness, but to the original''s particular fusion of sound and sense.}}
Step 2 — Restate the third path
Fidelity unites sound and sense, exactly D.
Distractor analysis:
- A: The text calls too-literal translation unfaithful.
- B: The text says beauty alone can betray the poem.
- C: The text presumes good translation is possible by defining fidelity.
- D: Correct.', 'Both halves of the ''fidelity versus beauty'' framing are rejected for a third option.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('82bcbe27-57c9-4806-9d33-70794b358849', 'Which choice best states the main idea of the text?', 'Reformers of the Progressive Era are often remembered as champions of ordinary people against corporate power. Their record, however, was double-edged. The same faith in expert administration that produced food-safety laws also produced policies that disenfranchised voters deemed unfit and imposed narrow standards of respectability on immigrants. Progressives expanded the state''s capacity to protect citizens and, with the same instruments, to police them. To call the movement simply democratic or simply paternalistic is to miss how thoroughly its protective and controlling impulses were bound together in a single reforming ambition.', NULL, '[{"id":"A","text":"Progressive Era reformers were straightforward champions of ordinary people against corporate power.","is_correct":false,"explanation":"The text says this familiar memory misses the movement''s controlling side."},{"id":"B","text":"Progressive reform fused protective and controlling impulses, so it can be reduced to neither democratic nor paternalistic alone.","is_correct":true,"explanation":"It captures the intertwining of protection and control the text emphasizes."},{"id":"C","text":"Progressive reformers were primarily concerned with policing immigrants and disenfranchising voters.","is_correct":false,"explanation":"This overweights the controlling side, ignoring the protective achievements the text credits."},{"id":"D","text":"Food-safety laws were the most important achievement of the Progressive Era.","is_correct":false,"explanation":"The text uses food-safety laws as one example, not as a ranked top achievement."}]'::jsonb, 'B', 'Step 1 — Find the fusion
The text warns that to call the movement simply one thing {{yellow:is to miss how thoroughly its protective and controlling impulses were bound together in a single reforming ambition.}}
Step 2 — Restate the duality
Protection and control were intertwined, so neither label alone fits, which is B.
Distractor analysis:
- A: Restates the one-sided memory the text complicates.
- B: Correct.
- C: Overweights control and drops the protective achievements.
- D: Treats one example as a ranked top achievement.', 'The answer must bind the protective and controlling sides together, not pick one.', 'Information and Ideas', 'Central Ideas and Details', 'reading_writing', 'information', 'CID', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0e27add2-6a80-4733-8fc5-76245b0c32eb', 'Which finding, if true, would most directly support Dr. Renn''s hypothesis about the function of the squid''s light organs?', 'Marine biologist Dr. Asha Renn studies the bioluminescent firefly squid of Toyama Bay. She hypothesizes that the squid use their glowing light organs primarily to startle and confuse predators that approach from below, rather than to attract mates. Renn notes that the squid live in deep, dark water where vision is limited, and she has observed that the light flashes occur most often during sudden movements. She now wants to gather evidence from the field that would confirm her predator-defense explanation over the mate-attraction alternative.', NULL, '[{"id":"A","text":"Firefly squid produce their brightest flashes at the exact moment a hunting fish lunges toward them from beneath.","is_correct":true,"explanation":"Correct: a bright flash timed to a predator''s attack from below directly matches the predator-defense, startle explanation."},{"id":"B","text":"Firefly squid gather in enormous numbers near the shore during their spring breeding season.","is_correct":false,"explanation":"True-but-irrelevant: breeding aggregations say nothing about whether the light is used for defense versus mating."},{"id":"C","text":"Female firefly squid glow more brightly than males during courtship displays.","is_correct":false,"explanation":"Reverse: stronger glowing during courtship supports the mate-attraction alternative Renn is arguing against."},{"id":"D","text":"Many deep-sea animals besides squid are capable of producing their own light.","is_correct":false,"explanation":"Too broad: that other animals can glow does not address why this squid flashes."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Renn thinks the squid glow to {{yellow:startle and confuse predators that approach from below, rather than to attract mates}}.
Step 2 — Match the finding
A flash produced exactly when a predator lunges from beneath confirms a defensive, anti-predator timing, supporting her hypothesis over mate attraction.
Distractor analysis:
- B: True-but-irrelevant; breeding crowds do not reveal the light''s function.
- C: Reverse; brighter courtship glow supports the mating explanation she rejects.
- D: Too broad; other glowing animals do not explain this squid''s behavior.', 'Find the option whose timing matches a predator attack from below, not mating.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1b0bfdfd-c9e0-405d-bc98-640505b48026', 'Which finding, if true, would most directly support Dr. Ruiz''s hypothesis about the cause of Lucca''s growth?', 'Historian Dr. Mateo Ruiz argues that the rapid growth of the medieval Italian city of Lucca in the twelfth century was driven mainly by its silk industry rather than by its position on a pilgrimage road. Ruiz points out that Lucca grew far faster than other towns along the same road. He believes that if silk manufacturing was the true engine of growth, then evidence about workshops, exports, and skilled workers should align with the city''s population boom. He is now reviewing archival records to test this claim.', NULL, '[{"id":"A","text":"City tax rolls show that the number of silk workshops in Lucca tripled during the same decades its population surged.","is_correct":true,"explanation":"Correct: a parallel surge in silk workshops and population directly links the silk industry to the city''s growth."},{"id":"B","text":"Pilgrims traveling the road frequently stopped in Lucca to rest before continuing their journey.","is_correct":false,"explanation":"Reverse: pilgrim traffic supports the road explanation Ruiz argues against."},{"id":"C","text":"Lucca''s medieval cathedral was admired by visitors from across Europe.","is_correct":false,"explanation":"True-but-irrelevant: cathedral fame does not connect growth to silk manufacturing."},{"id":"D","text":"Several Italian cities expanded during the twelfth century for a variety of reasons.","is_correct":false,"explanation":"Too broad: general regional growth says nothing about Lucca''s specific cause."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Ruiz argues Lucca''s growth was {{yellow:driven mainly by its silk industry rather than by its position on a pilgrimage road}}.
Step 2 — Match the finding
Workshops tripling exactly as population surged ties the silk industry directly to the growth, supporting his hypothesis.
Distractor analysis:
- B: Reverse; pilgrim stops support the road explanation he rejects.
- C: True-but-irrelevant; cathedral fame is unrelated to silk.
- D: Too broad; other cities'' growth does not explain Lucca.', 'Look for evidence that silk activity rose at the same time the population did.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('da5464f6-89b8-4231-8f29-883bec791c82', 'Which finding, if true, would most directly support Dr. Nair''s hypothesis about beavers and young salmon?', 'Ecologist Dr. Priya Nair proposes that beavers improve the survival of young salmon in mountain streams. She reasons that the ponds beavers create by building dams slow the water and provide calm, sheltered places where small fish can rest and hide from fast currents. Nair suspects that streams with beaver dams will support more young salmon than similar streams without them. She plans a field study comparing salmon numbers across many streams to find evidence for or against her idea.', NULL, '[{"id":"A","text":"Streams with active beaver dams contain noticeably more surviving young salmon than nearby streams without dams.","is_correct":true,"explanation":"Correct: higher salmon survival in dammed streams directly matches her claim that beaver ponds help young salmon."},{"id":"B","text":"Beavers also build dams in streams that contain no salmon at all.","is_correct":false,"explanation":"True-but-irrelevant: dams in salmon-free streams do not address salmon survival."},{"id":"C","text":"Young salmon in streams with beaver dams grow to the same size as those without dams.","is_correct":false,"explanation":"No-evidence synthesis: equal growth size is not about survival numbers, the claim at issue."},{"id":"D","text":"Adult beavers prefer to chew on aspen and willow trees near the water.","is_correct":false,"explanation":"Too narrow/irrelevant: beaver feeding habits do not bear on salmon survival."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Nair suspects {{yellow:streams with beaver dams will support more young salmon than similar streams without them}}.
Step 2 — Match the finding
Finding more surviving young salmon in dammed streams than in undammed ones directly confirms her prediction.
Distractor analysis:
- B: True-but-irrelevant; salmon-free streams say nothing about survival.
- C: No-evidence synthesis; growth size is not the survival measure claimed.
- D: Too narrow; beaver diet is unrelated to salmon.', 'Pick the option that compares salmon numbers in streams with versus without dams.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('76b81f0a-2fbd-4a20-8aae-c6858dc28d1d', 'Which finding, if true, would most directly support Dr. Cho''s hypothesis about the origin of the fictional town of Marlowe?', 'Literary scholar Dr. Helen Cho argues that the nineteenth-century novelist Clara Whitfield deliberately based her fictional seaside town of Marlowe on the real fishing village where she spent her childhood summers. Cho notes that Whitfield rarely discussed her sources in public. She believes that if Marlowe was modeled on the real village, then specific, unusual details from that village should appear in the novels. Cho is examining Whitfield''s private letters and the geography of the village to test the connection.', NULL, '[{"id":"A","text":"Whitfield''s novels describe a rare crescent-shaped harbor and a red lighthouse that match unusual features of her childhood village exactly.","is_correct":true,"explanation":"Correct: specific, unusual matching details directly link the fictional town to the real village, as Cho predicts."},{"id":"B","text":"Whitfield set several of her other novels in large, busy cities.","is_correct":false,"explanation":"True-but-irrelevant: settings of other novels do not address Marlowe''s origin."},{"id":"C","text":"Many nineteenth-century novelists drew on real places for their fictional settings.","is_correct":false,"explanation":"Too broad: a general trend does not show this specific connection."},{"id":"D","text":"Whitfield once said in a letter that she preferred inventing places entirely from imagination.","is_correct":false,"explanation":"Reverse: a stated preference for invention contradicts the hypothesis."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Cho says specific, unusual details from the village should appear if {{yellow:Marlowe was modeled on the real village}}.
Step 2 — Match the finding
A rare harbor shape and lighthouse matching the real village exactly are precisely the unusual details that support the connection.
Distractor analysis:
- B: True-but-irrelevant; other novels'' settings are beside the point.
- C: Too broad; a general trend proves nothing about this case.
- D: Reverse; preferring invention contradicts the claim.', 'Find the option giving specific, unusual details shared by both town and village.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('231084d7-6a88-4b1c-be3e-550fa3b29877', 'Which finding, if true, would most directly support Dr. Faris''s hypothesis about spaced study?', 'Psychologist Dr. Omar Faris hypothesizes that students remember vocabulary words better when they study them in short sessions spread across several days rather than in one long session. He reasons that spacing study over time gives the brain repeated chances to strengthen memory. Faris predicts that students who use spaced sessions will recall more words on a later test than students who cram all their study into a single day. He designs an experiment to compare the two study methods.', NULL, '[{"id":"A","text":"On a test given one week later, students who studied in short sessions across several days recalled more words than students who studied everything in one day.","is_correct":true,"explanation":"Correct: better later recall for the spaced group directly confirms his prediction."},{"id":"B","text":"Students who crammed reported feeling more confident immediately after studying.","is_correct":false,"explanation":"True-but-irrelevant: immediate confidence is not later recall, the measure that matters."},{"id":"C","text":"Both groups of students spent the same total number of minutes studying.","is_correct":false,"explanation":"No-evidence synthesis: equal total time is a control, not evidence for spacing''s benefit."},{"id":"D","text":"Students generally enjoy studying vocabulary more than studying mathematics.","is_correct":false,"explanation":"Irrelevant: study preferences across subjects do not address recall."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Faris predicts {{yellow:students who use spaced sessions will recall more words on a later test than students who cram all their study into a single day}}.
Step 2 — Match the finding
A later test showing the spaced group recalled more words is exactly the outcome that supports his hypothesis.
Distractor analysis:
- B: True-but-irrelevant; confidence is not recall.
- C: No-evidence synthesis; equal total time is just a control.
- D: Irrelevant; subject preferences do not bear on recall.', 'Look for a later test where the spaced-study group outperformed the cramming group.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5a113eaf-ec80-42ae-a98d-6831d9fe371d', 'Which finding, if true, would most directly support Dr. Kowalski''s hypothesis about the planet''s atmosphere?', 'Astronomer Dr. Lena Kowalski proposes that a faint, distant planet orbiting a nearby star has a thick atmosphere rich in water vapor. She argues that such an atmosphere would leave a distinctive fingerprint in the starlight passing through it as the planet crosses in front of its star. Kowalski expects that careful measurements of this filtered starlight will reveal the chemical signature of water. She is preparing to analyze data from a space telescope to test her prediction.', NULL, '[{"id":"A","text":"Starlight passing through the planet''s atmosphere shows the specific pattern of absorption that water vapor is known to produce.","is_correct":true,"explanation":"Correct: detecting water vapor''s absorption signature in the filtered starlight directly confirms a water-rich atmosphere."},{"id":"B","text":"The planet completes one orbit around its star in just under ten days.","is_correct":false,"explanation":"True-but-irrelevant: orbital period does not reveal atmospheric composition."},{"id":"C","text":"The star the planet orbits is slightly cooler than Earth''s Sun.","is_correct":false,"explanation":"True-but-irrelevant: the star''s temperature does not show water in the planet''s air."},{"id":"D","text":"Many planets beyond our solar system have now been discovered.","is_correct":false,"explanation":"Too broad: the count of known planets says nothing about this atmosphere."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Kowalski expects measurements to {{yellow:reveal the chemical signature of water}} in the planet''s atmosphere.
Step 2 — Match the finding
Filtered starlight showing water vapor''s known absorption pattern is exactly that chemical signature, supporting her hypothesis.
Distractor analysis:
- B: True-but-irrelevant; orbital period is unrelated to composition.
- C: True-but-irrelevant; the star''s temperature does not detect water.
- D: Too broad; planet counts are beside the point.', 'Find the option detecting water vapor''s signature in the starlight.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f890a3fa-4dc7-47a4-8915-8fd4fc2d5e71', 'Which finding, if true, would most directly support Dr. Otieno''s hypothesis about long-distance trade?', 'Anthropologist Dr. Samuel Otieno argues that a group of ancient farmers living in East Africa three thousand years ago traded regularly with distant coastal communities. He bases this on the unusual variety of objects found at their inland settlement. Otieno reasons that if long-distance trade truly occurred, then materials that could only have come from the coast should appear at the inland site. He is now cataloguing artifacts excavated from the settlement to evaluate his claim.', NULL, '[{"id":"A","text":"Seashells found only along the distant coast were uncovered among the everyday objects at the inland settlement.","is_correct":true,"explanation":"Correct: coast-only seashells appearing inland directly demonstrate the long-distance trade he claims."},{"id":"B","text":"The inland farmers grew several crops that were common throughout the region.","is_correct":false,"explanation":"True-but-irrelevant: locally common crops do not indicate coastal trade."},{"id":"C","text":"The settlement was home to several hundred people at its peak.","is_correct":false,"explanation":"Irrelevant: settlement size does not show trade with the coast."},{"id":"D","text":"Ancient peoples around the world often exchanged goods with their neighbors.","is_correct":false,"explanation":"Too broad: a worldwide generalization does not prove this group''s trade."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Otieno reasons that {{yellow:materials that could only have come from the coast should appear at the inland site}}.
Step 2 — Match the finding
Seashells found only along the distant coast turning up inland are precisely such coast-only materials, supporting his trade claim.
Distractor analysis:
- B: True-but-irrelevant; regional crops are local, not coastal.
- C: Irrelevant; population size does not show trade.
- D: Too broad; a global trend proves nothing here.', 'Pick the find that could only have come from the distant coast.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4c0ffd4d-48be-4627-b559-00133266bdc0', 'Which finding, if true, would most directly support Dr. Tanaka''s hypothesis about why the flower opens only at night?', 'Botanist Dr. Yuki Tanaka hypothesizes that a certain desert wildflower opens its petals only at night to avoid losing water in the daytime heat. She reasons that staying closed during the hottest, driest hours would help the plant conserve precious moisture. Tanaka predicts that the flowers will lose less water on days when they remain closed than they would if forced to stay open. She sets up a greenhouse study to measure water loss under different conditions.', NULL, '[{"id":"A","text":"Flowers kept artificially open during the hot daytime hours lost far more water than flowers allowed to stay closed.","is_correct":true,"explanation":"Correct: greater water loss when forced open in the heat directly supports the water-conservation explanation."},{"id":"B","text":"The wildflower''s petals are a pale yellow color that reflects some sunlight.","is_correct":false,"explanation":"True-but-irrelevant: petal color does not test the opening-timing claim."},{"id":"C","text":"Several night-blooming plants are pollinated by moths.","is_correct":false,"explanation":"Too broad/irrelevant: a general fact about other plants does not address water loss."},{"id":"D","text":"The desert where the flower grows receives almost no rain during summer.","is_correct":false,"explanation":"True-but-irrelevant: dry climate explains the need to conserve but does not show the flower does so by closing."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Tanaka predicts flowers {{yellow:will lose less water on days when they remain closed than they would if forced to stay open}}.
Step 2 — Match the finding
Flowers forced open in the heat losing far more water than closed ones directly matches that prediction, supporting water conservation.
Distractor analysis:
- B: True-but-irrelevant; petal color is not about water loss.
- C: Too broad; other plants'' pollinators are unrelated.
- D: True-but-irrelevant; a dry climate does not show the closing behavior conserves water.', 'Find the option directly comparing water loss between open and closed flowers in the heat.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7ed8512d-cb03-4748-a355-3d2db833e44b', 'Which finding, if true, would most directly support Dr. Mbeki''s hypothesis about the library''s effect on teen reading?', 'Sociologist Dr. Grace Mbeki proposes that a new community library in a small town increased reading among local teenagers. She reasons that easy, free access to books encourages young people to read more often. Mbeki expects that if the library had this effect, then teenagers in the town should be reading more after the library opened than they did before. She is gathering survey data from before and after the opening to assess her claim.', NULL, '[{"id":"A","text":"Surveys show that local teenagers reported reading noticeably more books in the year after the library opened than in the year before.","is_correct":true,"explanation":"Correct: a before-and-after rise in teen reading directly matches her predicted effect of the library."},{"id":"B","text":"The library also offers free internet access and meeting rooms for residents.","is_correct":false,"explanation":"True-but-irrelevant: other services do not show an effect on teen reading."},{"id":"C","text":"Adults in the town visit the library more often than teenagers do.","is_correct":false,"explanation":"Irrelevant: adult visits do not address teen reading habits."},{"id":"D","text":"Libraries are popular institutions in many towns across the country.","is_correct":false,"explanation":"Too broad: general popularity does not show this library changed teen reading."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Mbeki expects that teenagers {{yellow:should be reading more after the library opened than they did before}}.
Step 2 — Match the finding
Surveys showing teens read noticeably more in the year after opening than before is exactly that before-and-after increase, supporting her claim.
Distractor analysis:
- B: True-but-irrelevant; other services are not teen reading.
- C: Irrelevant; adult visits do not address teens.
- D: Too broad; general popularity proves nothing here.', 'Look for a before-versus-after comparison of how much teenagers read.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e6be68fc-b82a-49d2-af04-823b408191a3', 'Which finding, if true, would most directly support Dr. Menon''s hypothesis about how the valley formed?', 'Geologist Dr. Ravi Menon argues that a wide valley in the mountains was carved long ago by a massive glacier rather than by a flowing river. He notes that glaciers and rivers leave behind different shapes and deposits. Menon reasons that if a glacier formed the valley, then it should have the broad, U-shaped cross-section and scattered boulders that glaciers are known to produce. He is surveying the valley''s shape and rocks to test his interpretation.', NULL, '[{"id":"A","text":"The valley has a broad, U-shaped cross-section and is strewn with large boulders dropped far from their original bedrock.","is_correct":true,"explanation":"Correct: a U-shaped profile and scattered far-traveled boulders are the exact glacial signatures he predicted."},{"id":"B","text":"A small stream currently flows along the floor of the valley.","is_correct":false,"explanation":"Reverse/weakening: a present-day stream points toward a river origin, not a glacier."},{"id":"C","text":"The mountains surrounding the valley are made mostly of granite.","is_correct":false,"explanation":"True-but-irrelevant: the surrounding rock type does not show how the valley was carved."},{"id":"D","text":"Many valleys around the world were shaped by natural forces over long periods.","is_correct":false,"explanation":"Too broad: a vague generalization does not identify a glacier here."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Menon reasons the valley should have {{yellow:the broad, U-shaped cross-section and scattered boulders that glaciers are known to produce}}.
Step 2 — Match the finding
A U-shaped valley strewn with far-traveled boulders is exactly those glacial features, supporting a glacier origin.
Distractor analysis:
- B: Reverse; a flowing stream suggests a river origin.
- C: True-but-irrelevant; surrounding rock type is not the carving process.
- D: Too broad; a generalization names no glacier.', 'Find the option describing the U-shape and scattered boulders glaciers leave behind.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('da5419b3-0d1f-4773-9af0-9acd850158f6', 'Which finding, if true, would most directly support Dr. Nunes''s hypothesis that Vidal composed the symphony?', 'Music historian Dr. Carla Nunes argues that a famous unsigned symphony from the 1700s was actually composed by the little-known musician Tomas Vidal. She observes that the symphony uses an unusual rhythmic pattern. Nunes reasons that if Vidal wrote it, then this same distinctive pattern should appear in the works he is definitely known to have composed. She is comparing the symphony with Vidal''s signed pieces to support her attribution.', NULL, '[{"id":"A","text":"The same unusual rhythmic pattern in the symphony appears throughout the pieces Vidal is known to have signed.","is_correct":true,"explanation":"Correct: the distinctive pattern shared with Vidal''s signed works directly supports attributing the symphony to him."},{"id":"B","text":"The symphony was first performed in a city where Vidal once lived.","is_correct":false,"explanation":"No-evidence synthesis: a shared city does not show Vidal composed the work."},{"id":"C","text":"Many composers of the 1700s left some of their works unsigned.","is_correct":false,"explanation":"Too broad: a general fact does not point to Vidal specifically."},{"id":"D","text":"Vidal earned little money from music during his lifetime.","is_correct":false,"explanation":"True-but-irrelevant: his income has no bearing on authorship of the symphony."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Nunes reasons that {{yellow:this same distinctive pattern should appear in the works he is definitely known to have composed}}.
Step 2 — Match the finding
The unusual rhythm appearing throughout Vidal''s signed pieces is exactly that shared distinctive pattern, supporting her attribution.
Distractor analysis:
- B: No-evidence synthesis; a shared city does not prove authorship.
- C: Too broad; unsigned works in general point to no one.
- D: True-but-irrelevant; income is unrelated to authorship.', 'Pick the option matching the symphony''s unusual rhythm to Vidal''s known works.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5b31efa5-5898-4479-a7f0-224d962cd30b', 'Which finding, if true, would most directly support Dr. Holm''s hypothesis about why the birds sing loudly?', 'Wildlife biologist Dr. Ingrid Holm hypothesizes that a species of mountain bird sings more loudly in noisy areas near rushing rivers so that its song can still be heard. She reasons that louder singing would help the birds communicate over the background roar of the water. Holm predicts that birds living beside loud rivers will sing more loudly than the same species living in quiet meadows. She records and measures bird songs in both settings to test her idea.', NULL, '[{"id":"A","text":"Recordings show that birds living beside roaring rivers sing measurably louder than members of the same species in quiet meadows.","is_correct":true,"explanation":"Correct: louder songs beside noisy rivers than in quiet meadows directly confirm her predicted pattern."},{"id":"B","text":"The birds beside the rivers tend to have slightly brighter feathers than those in meadows.","is_correct":false,"explanation":"True-but-irrelevant: feather color does not address song loudness."},{"id":"C","text":"Rushing mountain rivers produce a steady, low roaring sound.","is_correct":false,"explanation":"True-but-irrelevant: describing the river noise does not show the birds respond by singing louder."},{"id":"D","text":"Many bird species use song to defend their territory from rivals.","is_correct":false,"explanation":"Too broad: a general fact about song does not address loudness near rivers."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Holm predicts that {{yellow:birds living beside loud rivers will sing more loudly than the same species living in quiet meadows}}.
Step 2 — Match the finding
Recordings showing river birds singing measurably louder than meadow birds of the same species are exactly that predicted contrast, supporting her hypothesis.
Distractor analysis:
- B: True-but-irrelevant; feather color is not loudness.
- C: True-but-irrelevant; river noise alone does not show the bird''s response.
- D: Too broad; song''s general purpose is not about loudness.', 'Find the option comparing song loudness between river birds and meadow birds.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ce678242-6972-4eab-9730-e71cd1557177', 'Which finding, if true, would most directly support the critic''s claim?', 'In her novel set aboard a long-distance sailing ship, author Mira Halloway wants readers to feel that the cramped quarters slowly strain the crew''s friendships. A literary critic argues that Halloway achieves this effect mainly by repeatedly describing how the characters'' small daily habits begin to irritate one another over the course of the voyage. The critic claims this accumulation of minor annoyances, rather than any single dramatic conflict, is what conveys the gradual breakdown of the crew''s relationships.', NULL, '[{"id":"A","text":"Several scenes show characters growing increasingly annoyed by small habits, such as a sailor''s constant humming or another''s slow eating, until they stop speaking warmly to one another.","is_correct":true,"explanation":"Correct: it matches the claim that repeated minor annoyances, not one big conflict, drive the friendships apart."},{"id":"B","text":"The novel includes a single, intense argument between two officers that nearly ends in a fistfight on deck.","is_correct":false,"explanation":"This describes one dramatic conflict, which is the opposite of the accumulation of minor annoyances the critic credits."},{"id":"C","text":"Halloway spends many pages describing the appearance of the ship and the surrounding ocean in vivid detail.","is_correct":false,"explanation":"Setting description is true-but-irrelevant; it does not show daily habits straining friendships."},{"id":"D","text":"Reviewers praised the novel for its historically accurate depiction of nineteenth-century sailing techniques.","is_correct":false,"explanation":"Historical accuracy is irrelevant to how the strained relationships are conveyed."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The critic says the effect comes from how {{yellow:the characters'' small daily habits begin to irritate one another over the course of the voyage}}.
Step 2 — Match the finding
Choice A shows exactly that pattern: repeated small habits annoy the crew until their warmth fades, directly supporting the claim.
Distractor analysis:
- B: describes a single dramatic conflict, which the critic explicitly contrasts with the accumulation of minor annoyances.
- C: vivid setting description is true-but-irrelevant to strained friendships.
- D: historical accuracy of sailing techniques has no bearing on the relationships.', 'Look for repeated small irritations, not one big fight.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('48c268c9-a982-4a5a-a508-fffbed1e6e2a', 'Which finding, if true, would most directly support the biologists'' hypothesis?', 'A team of marine biologists hypothesizes that a certain reef fish changes its skin color mainly to communicate with other fish of its own species, rather than to hide from predators. They reason that if the color change were primarily for hiding, the fish would shift colors most often when predators are near. Instead, they suspect the fish change color most when interacting socially with members of their own kind, regardless of whether predators are present.', NULL, '[{"id":"A","text":"The fish change color most frequently during social encounters with other members of their species, even when no predators are nearby.","is_correct":true,"explanation":"Correct: color change tied to same-species social encounters, independent of predators, matches the communication hypothesis."},{"id":"B","text":"The fish change color most dramatically in the seconds before a predator attacks.","is_correct":false,"explanation":"This supports the hiding explanation the biologists reject, not communication."},{"id":"C","text":"The fish are able to perceive a wider range of colors than most other reef species.","is_correct":false,"explanation":"Color perception is true-but-irrelevant to why the fish change color."},{"id":"D","text":"The fish live in reefs that contain many brightly colored corals.","is_correct":false,"explanation":"The colorful habitat says nothing about the purpose of the fish''s color change."}]'::jsonb, 'A', 'Step 1 — Identify the hypothesis
The biologists suspect the fish change color most {{yellow:when interacting socially with members of their own kind, regardless of whether predators are present}}.
Step 2 — Match the finding
Choice A reports exactly that: frequent color change during same-species social encounters with no predators near, supporting communication over hiding.
Distractor analysis:
- B: color change just before a predator attacks supports the hiding explanation they reject.
- C: superior color perception is irrelevant to the function of color change.
- D: a colorful habitat does not indicate the purpose of color changes.', 'The right finding ties color change to social, not predator, situations.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d9efd706-d3af-4870-94ab-ab348a4a422a', 'Which finding, if true, would most directly support the historian''s hypothesis?', 'A historian studying a medieval town hypothesizes that the town grew wealthy mainly because it sat at the meeting point of two trade roads, not because of nearby farmland. She reasons that if road trade drove the wealth, the town''s richest records and buildings should cluster near the marketplace where the roads crossed. If farming drove the wealth, the signs of riches would instead cluster near the agricultural fields outside the town.', NULL, '[{"id":"A","text":"The town''s wealthiest households and grandest buildings were concentrated around the marketplace at the crossing of the two roads.","is_correct":true,"explanation":"Correct: wealth clustered at the road-crossing marketplace matches the trade-road hypothesis."},{"id":"B","text":"The largest and most valuable homes were found in the farming districts at the town''s edge.","is_correct":false,"explanation":"Wealth near the fields supports the farming explanation the historian contrasts with her own."},{"id":"C","text":"The town''s population grew steadily over two centuries before declining.","is_correct":false,"explanation":"Population trends are true-but-irrelevant to the source of the wealth."},{"id":"D","text":"The town was governed by a council that met in a stone hall.","is_correct":false,"explanation":"The form of government has no bearing on whether trade or farming created the wealth."}]'::jsonb, 'A', 'Step 1 — Identify the hypothesis
The historian predicts that if road trade drove the wealth, {{yellow:the town''s richest records and buildings should cluster near the marketplace where the roads crossed}}.
Step 2 — Match the finding
Choice A reports wealth concentrated at the marketplace where the roads cross, fulfilling her prediction.
Distractor analysis:
- B: wealth in the farming districts supports the rival farming explanation.
- C: population trends do not address the source of wealth.
- D: the town''s government is irrelevant to trade versus farming.', 'Where is the wealth located if roads, not farms, caused it?', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8465b6db-db5a-4b7a-801e-5a661e198b34', 'Which finding, if true, would most directly support the researcher''s proposal?', 'An educational researcher proposes that students remember vocabulary words better when they write their own sentences using each word than when they simply reread the definitions. She predicts that if writing original sentences truly helps, students who use that method should score higher on a later spelling-and-meaning test than students who only reread definitions, even when both groups study for the same amount of time.', NULL, '[{"id":"A","text":"Students who wrote their own sentences scored higher on the later test than students who only reread definitions, despite studying for equal amounts of time.","is_correct":true,"explanation":"Correct: higher scores for the sentence-writing group with equal study time exactly matches the prediction."},{"id":"B","text":"Students who only reread definitions reported enjoying their study sessions more than the sentence-writing students did.","is_correct":false,"explanation":"Enjoyment is true-but-irrelevant; the proposal is about test performance, not preference."},{"id":"C","text":"Students who wrote their own sentences spent far more time studying than the rereading group.","is_correct":false,"explanation":"Unequal study time undermines the comparison rather than supporting the method itself."},{"id":"D","text":"Both groups scored about the same on the later test.","is_correct":false,"explanation":"Equal scores contradict the prediction that sentence-writing improves recall."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
The researcher predicts the sentence-writing students should {{yellow:score higher on a later spelling-and-meaning test than students who only reread definitions, even when both groups study for the same amount of time}}.
Step 2 — Match the finding
Choice A reports exactly that outcome, supporting the proposal.
Distractor analysis:
- B: enjoyment is irrelevant to memory and test performance.
- C: unequal study time breaks the controlled comparison rather than supporting it.
- D: equal scores directly contradict the prediction.', 'Find the result that holds study time equal and shows the writing group winning.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f0f90d2a-2ddf-4be5-aa88-4cab954a3335', 'Which finding, if true, would most directly support the botanist''s hypothesis?', 'A botanist hypothesizes that a desert shrub survives droughts mainly by storing water in its thick roots rather than in its leaves. She reasons that if the roots are the main water store, then during a long dry spell the roots should lose far more of their water content than the leaves do. If the leaves were the main store, the leaves would instead show the greatest loss of water during drought.', NULL, '[{"id":"A","text":"During an extended drought, the shrub''s roots lost a much greater share of their water content than its leaves did.","is_correct":true,"explanation":"Correct: roots losing more water than leaves matches the prediction that roots are the main store."},{"id":"B","text":"During an extended drought, the shrub''s leaves lost a much greater share of their water content than its roots did.","is_correct":false,"explanation":"Greater loss from leaves supports the leaf-storage explanation she rejects."},{"id":"C","text":"The shrub''s flowers bloom only after the first heavy rain of the season.","is_correct":false,"explanation":"Flowering timing is true-but-irrelevant to where water is stored."},{"id":"D","text":"The shrub grows more slowly than nearby grasses during wet years.","is_correct":false,"explanation":"Growth rate compared to grasses says nothing about water storage location."}]'::jsonb, 'A', 'Step 1 — Identify the hypothesis
The botanist predicts that if the roots are the main store, {{yellow:the roots should lose far more of their water content than the leaves do}}.
Step 2 — Match the finding
Choice A reports roots losing a greater share of water than leaves during drought, fulfilling the prediction.
Distractor analysis:
- B: leaves losing more water supports the rival leaf-storage explanation.
- C: flowering timing is irrelevant to water storage.
- D: growth rate versus grasses does not address storage location.', 'Which part loses the most water if the roots hold the reserve?', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b76353a2-181b-4b10-9e71-5bdb24f916b1', 'Which finding, if true, would most directly support the sociologist''s claim?', 'A sociologist claims that a neighborhood''s new community garden increased friendships among neighbors mainly because it gave people a shared place to meet regularly, not simply because it made the area look nicer. She reasons that if the shared meeting space caused the friendships, then residents who actually spent time working in the garden should report more new friendships than residents who only walked past it.', NULL, '[{"id":"A","text":"Residents who regularly worked in the garden reported making more new friends than residents who merely passed by it.","is_correct":true,"explanation":"Correct: more friendships among active gardeners than passersby matches the shared-meeting-space claim."},{"id":"B","text":"Residents agreed that the neighborhood looked more attractive after the garden was built.","is_correct":false,"explanation":"Improved appearance is the explanation she sets aside, and it does not show friendships forming."},{"id":"C","text":"The garden produced large amounts of vegetables that residents shared.","is_correct":false,"explanation":"Vegetable yield is true-but-irrelevant to whether shared meeting time built friendships."},{"id":"D","text":"Residents who only walked past the garden reported just as many new friends as those who worked in it.","is_correct":false,"explanation":"Equal friendships regardless of participation contradicts the meeting-space claim."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The sociologist predicts that {{yellow:residents who actually spent time working in the garden should report more new friendships than residents who only walked past it}}.
Step 2 — Match the finding
Choice A reports exactly that contrast, supporting the shared-meeting-space explanation.
Distractor analysis:
- B: improved appearance is the alternative she rejects and shows no friendships.
- C: vegetable yield is irrelevant to friendship formation.
- D: equal friendships for passersby contradicts the prediction.', 'Compare active gardeners with people who just walked by.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('260c5148-28ff-4e04-88f8-63090536f165', 'Which finding, if true, would most directly support the scholar''s argument?', 'A film scholar argues that early silent comedies relied on physical action to make audiences laugh because they could not use spoken dialogue. He claims that the most successful silent comedians built their humor around exaggerated body movements, such as elaborate falls and chases, rather than around clever wordplay shown on title cards. According to the scholar, it is the visual physical comedy, not the written jokes, that defined the era''s most popular films.', NULL, '[{"id":"A","text":"The era''s most popular comedies were filled with elaborate stunts, pratfalls, and chases, while their title cards contained few jokes.","is_correct":true,"explanation":"Correct: humor built on physical stunts rather than written jokes matches the scholar''s argument."},{"id":"B","text":"The most popular silent comedies were celebrated mainly for the witty jokes printed on their title cards.","is_correct":false,"explanation":"Praising written jokes reverses the scholar''s claim that physical comedy defined the films."},{"id":"C","text":"Silent films were usually accompanied by live piano music in theaters.","is_correct":false,"explanation":"Musical accompaniment is true-but-irrelevant to whether humor was physical or verbal."},{"id":"D","text":"Silent comedies were generally shorter than the dramas of the same period.","is_correct":false,"explanation":"Film length does not address the source of the comedy''s humor."}]'::jsonb, 'A', 'Step 1 — Identify the argument
The scholar claims the comedians built humor around {{yellow:exaggerated body movements, such as elaborate falls and chases, rather than around clever wordplay shown on title cards}}.
Step 2 — Match the finding
Choice A reports popular comedies full of stunts and chases with few jokes on the cards, supporting the physical-comedy argument.
Distractor analysis:
- B: crediting witty title-card jokes reverses the scholar''s claim.
- C: live music is irrelevant to the type of humor.
- D: film length does not address the humor''s source.', 'Look for evidence that the laughs came from movement, not the title-card text.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('183da8c4-5c50-4b8d-a291-a50db8295814', 'Which finding, if true, would most directly support the ornithologist''s hypothesis?', 'An ornithologist hypothesizes that a songbird sings more in the early morning mainly to defend its territory from rival males, not to attract mates. She reasons that if territorial defense drives the morning singing, then males should sing most intensely when a rival male is detected nearby, regardless of whether females are present. If attracting mates were the cause, the males would instead sing most when unpaired females are nearby.', NULL, '[{"id":"A","text":"Males sang most intensely whenever a rival male was detected nearby, whether or not any females were present.","is_correct":true,"explanation":"Correct: peak singing triggered by rival males independent of females matches the territorial-defense hypothesis."},{"id":"B","text":"Males sang most intensely when unpaired females were nearby and largely ignored rival males.","is_correct":false,"explanation":"Singing peaking around females supports the mate-attraction explanation she rejects."},{"id":"C","text":"The songbirds build their nests in dense shrubs to hide them from predators.","is_correct":false,"explanation":"Nest placement is true-but-irrelevant to why the birds sing in the morning."},{"id":"D","text":"The species migrates to warmer regions each winter.","is_correct":false,"explanation":"Migration patterns have no bearing on the function of morning singing."}]'::jsonb, 'A', 'Step 1 — Identify the hypothesis
The ornithologist predicts that males should sing most intensely {{yellow:when a rival male is detected nearby, regardless of whether females are present}}.
Step 2 — Match the finding
Choice A reports peak singing triggered by rival males even without females, supporting territorial defense.
Distractor analysis:
- B: singing peaking around females supports the mate-attraction rival explanation.
- C: nest placement is irrelevant to singing behavior.
- D: migration does not address why the birds sing in the morning.', 'What triggers the loudest singing if the goal is defending territory?', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5e75fb5a-70bd-45b0-b8ab-5c2af29f23da', 'Which finding, if true, would most directly support the historian''s argument?', 'A historian of technology argues that a nineteenth-century factory adopted a new weaving machine mainly to produce cloth faster, not to lower the cost of labor. He reasons that if speed was the goal, the factory''s records should show that the amount of cloth produced per day rose sharply after the machine was installed. If cutting labor costs was the goal, the records would instead emphasize a reduction in the number of workers employed.', NULL, '[{"id":"A","text":"Factory records show that daily cloth output rose sharply in the weeks after the new machine was installed.","is_correct":true,"explanation":"Correct: a sharp rise in daily output matches the historian''s speed-focused prediction."},{"id":"B","text":"Factory records show that the number of workers employed dropped sharply after the machine was installed.","is_correct":false,"explanation":"A drop in workers supports the labor-cost explanation the historian contrasts with his own."},{"id":"C","text":"The factory was located beside a river that powered its machinery.","is_correct":false,"explanation":"The factory''s location is true-but-irrelevant to why the machine was adopted."},{"id":"D","text":"The cloth produced by the factory was sold in markets across the country.","is_correct":false,"explanation":"Where the cloth was sold does not address whether speed or labor savings motivated the machine."}]'::jsonb, 'A', 'Step 1 — Identify the argument
The historian predicts that if speed was the goal, {{yellow:the amount of cloth produced per day rose sharply after the machine was installed}}.
Step 2 — Match the finding
Choice A reports exactly that sharp rise in daily output, supporting the speed argument.
Distractor analysis:
- B: a drop in workers supports the rival labor-cost explanation.
- C: the factory''s riverside location is irrelevant.
- D: where the cloth was sold does not address the motive.', 'Which record shows the goal was making cloth faster?', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f7037502-3f14-4bdf-a8dc-4bcc671fa520', 'Which finding, if true, would most directly support the psychologist''s proposal?', 'A psychologist proposes that people are more likely to keep a New Year''s resolution when they tell a friend about it than when they keep it private. She predicts that if telling a friend helps, then people who shared their resolution with someone should still be following it after three months at a higher rate than people who told no one, assuming the resolutions were equally difficult.', NULL, '[{"id":"A","text":"People who told a friend about their resolution were still following it after three months more often than those who kept it private, even though the resolutions were equally hard.","is_correct":true,"explanation":"Correct: a higher follow-through rate for the sharing group with equally difficult resolutions matches the prediction."},{"id":"B","text":"People who kept their resolutions private said they felt less pressure than those who told a friend.","is_correct":false,"explanation":"Feelings of pressure are true-but-irrelevant to whether the resolution was kept."},{"id":"C","text":"People who told a friend tended to choose much easier resolutions than those who told no one.","is_correct":false,"explanation":"Unequal difficulty undermines the comparison rather than supporting sharing itself."},{"id":"D","text":"People who told a friend abandoned their resolutions sooner than those who kept them private.","is_correct":false,"explanation":"Earlier abandonment by sharers contradicts the prediction."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
The psychologist predicts the sharing group should still be {{yellow:following it after three months at a higher rate than people who told no one, assuming the resolutions were equally difficult}}.
Step 2 — Match the finding
Choice A reports exactly that higher follow-through with equally hard resolutions, supporting the proposal.
Distractor analysis:
- B: reported pressure is irrelevant to whether resolutions were kept.
- C: unequal difficulty breaks the controlled comparison.
- D: earlier abandonment by sharers contradicts the prediction.', 'Find the result holding difficulty equal where the sharers stick with it longer.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
