(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e0448e7d-b891-4ef0-b22c-65eb6ed0e678', 'Which finding, if true, would most directly support the scholar''s argument?', 'A literary scholar argues that a poet uses images of changing seasons to mirror the speaker''s shifting emotions throughout a long poem. The scholar claims that whenever the speaker feels hopeful, the poem describes spring or summer scenes, and whenever the speaker feels sorrowful, it describes autumn or winter scenes. According to the scholar, this consistent pairing of season and mood is the central way the poem conveys the speaker''s emotional journey.', NULL, '[{"id":"A","text":"In every stanza, the speaker''s hopeful moments are set in spring or summer, while every sorrowful moment is set in autumn or winter.","is_correct":true,"explanation":"Correct: a consistent pairing of hopeful moods with warm seasons and sorrow with cold seasons matches the claim."},{"id":"B","text":"The poem describes seasonal scenes in vivid detail but the speaker''s mood stays cheerful throughout.","is_correct":false,"explanation":"A constant mood breaks the season-mood pairing the scholar describes."},{"id":"C","text":"The poem is written in a strict rhyme scheme that the poet never breaks.","is_correct":false,"explanation":"The rhyme scheme is true-but-irrelevant to the season-mood connection."},{"id":"D","text":"The poet wrote the poem during a single winter while living in the countryside.","is_correct":false,"explanation":"The poem''s composition setting does not show seasons mirroring the speaker''s emotions."}]'::jsonb, 'A', 'Step 1 — Identify the argument
The scholar claims that {{yellow:whenever the speaker feels hopeful, the poem describes spring or summer scenes, and whenever the speaker feels sorrowful, it describes autumn or winter scenes}}.
Step 2 — Match the finding
Choice A reports exactly this consistent pairing across every stanza, supporting the argument.
Distractor analysis:
- B: an unchanging cheerful mood breaks the proposed pairing.
- C: the rhyme scheme is irrelevant to the season-mood link.
- D: when the poem was written does not show seasons mirroring emotion.', 'Look for a steady match between warm seasons and hope, cold seasons and sorrow.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c28c2213-d367-4715-8940-70690d399229', 'Which finding, if true, would most directly support the archaeologist''s hypothesis?', 'An archaeologist hypothesizes that an ancient village traded with distant coastal communities mainly by sea, not over land. She reasons that if sea trade was the main route, then the foreign goods found at the village should be items that were heavy and bulky, which are far easier to move by boat than to carry overland. If land routes were used, the foreign goods would instead be small, lightweight items easy to carry on foot.', NULL, '[{"id":"A","text":"The foreign goods recovered at the village were mostly heavy, bulky items that would have been difficult to carry overland.","is_correct":true,"explanation":"Correct: heavy, bulky foreign goods point to sea transport, matching the hypothesis."},{"id":"B","text":"The foreign goods recovered at the village were almost all small, lightweight objects easy to carry on foot.","is_correct":false,"explanation":"Small, light goods point to land routes, the explanation she contrasts with her own."},{"id":"C","text":"The village was surrounded by a wall built from local stone.","is_correct":false,"explanation":"A defensive wall is true-but-irrelevant to how trade goods arrived."},{"id":"D","text":"The village''s houses were arranged around a central open square.","is_correct":false,"explanation":"The village layout does not indicate whether trade came by sea or land."}]'::jsonb, 'A', 'Step 1 — Identify the hypothesis
The archaeologist predicts that with sea trade, the goods should be {{yellow:items that were heavy and bulky, which are far easier to move by boat than to carry overland}}.
Step 2 — Match the finding
Choice A reports mostly heavy, bulky foreign goods, supporting sea transport.
Distractor analysis:
- B: small, lightweight goods support the rival land-route explanation.
- C: a stone wall is irrelevant to trade routes.
- D: house arrangement does not indicate the trade route.', 'Heavy goods favor boats; light goods favor walking.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('39584811-3098-42ef-8b05-152dce4bf6ee', 'Which quotation from "The Lantern Keeper," if genuine, would most directly support the critics'' interpretation of Oslo?', 'In her novel "The Lantern Keeper," author Mireille Devaux portrays the elderly lighthouse keeper Oslo as a man who values solitude above all else. Some critics, however, argue that beneath this preference for isolation lies a deep, unspoken longing for human companionship that Oslo refuses to acknowledge even to himself.', NULL, '[{"id":"A","text":"\"Oslo climbed the spiral stairs each dawn, checking the great lamp with the same patient care he had shown for forty years.\"","is_correct":false,"explanation":"This describes Oslo''s routine diligence, not a hidden longing for companionship."},{"id":"B","text":"\"He told the supply boat captain he needed no one, yet that night he set two cups on the table and stared a long while at the empty chair.\"","is_correct":true,"explanation":"Setting a second cup and staring at the empty chair reveals an unacknowledged longing for company beneath his stated need for none."},{"id":"C","text":"\"The storms off the cape were fierce that winter, hurling spray against the glass until the panes rattled in their frames.\"","is_correct":false,"explanation":"This describes the weather and is irrelevant to Oslo''s inner desire for companionship."},{"id":"D","text":"\"Oslo had chosen the lighthouse precisely because it stood farther from the mainland than any other post in the district.\"","is_correct":false,"explanation":"This confirms his preference for isolation but contradicts the claim of a hidden longing for company."}]'::jsonb, 'B', 'Step 1 — Identify the claim
The critics argue that beneath Oslo''s love of solitude lies {{yellow:a deep, unspoken longing for human companionship that Oslo refuses to acknowledge even to himself}}.
Step 2 — Match the evidence
Choice B shows Oslo insisting he needs no one while secretly setting a second cup and gazing at an empty chair, which reveals exactly the hidden, unacknowledged longing the critics describe.
Distractor analysis:
- A: Shows routine diligence, not any longing for companionship.
- C: Describes weather, which is irrelevant to Oslo''s inner desires.
- D: Confirms his preference for isolation, contradicting the idea of a hidden longing for company.', 'Look for a quotation where Oslo''s actions quietly contradict his stated love of being alone.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('08cfc213-a599-4d69-b51a-94fd5898cb90', 'Which finding, if true, would most directly support the biologists'' hypothesis?', 'A team of marine biologists hypothesized that the bright coloration of the cleaner wrasse, a small reef fish, functions as a signal that allows larger fish to recognize it as a helper rather than as prey. If the hypothesis is correct, larger predatory fish should treat brightly colored wrasse differently from how they treat similarly sized fish that lack the distinctive coloring.', NULL, '[{"id":"A","text":"Cleaner wrasse remove parasites more efficiently when the water temperature on the reef is higher.","is_correct":false,"explanation":"This concerns feeding efficiency, not whether coloration signals helper status to predators."},{"id":"B","text":"Predatory fish frequently ate small dull-colored fish but almost never attacked the brightly colored cleaner wrasse swimming nearby.","is_correct":true,"explanation":"Predators sparing the bright wrasse while eating dull-colored fish shows the coloring is recognized as a helper signal."},{"id":"C","text":"Cleaner wrasse tend to gather at fixed locations on the reef that other fish visit regularly.","is_correct":false,"explanation":"This describes where wrasse gather, not whether their color affects how predators treat them."},{"id":"D","text":"Brightly colored cleaner wrasse are slightly larger on average than dull-colored reef fish of the same species.","is_correct":false,"explanation":"A difference in size does not address whether coloration signals helper status to predators."}]'::jsonb, 'B', 'Step 1 — Identify the prediction
The hypothesis predicts that {{yellow:larger predatory fish should treat brightly colored wrasse differently from how they treat similarly sized fish that lack the distinctive coloring}}.
Step 2 — Match the evidence
Choice B reports that predators ate dull-colored fish but spared the bright wrasse, exactly the differential treatment the hypothesis predicts.
Distractor analysis:
- A: Concerns parasite-removal efficiency, not predator recognition of color.
- C: Describes where wrasse gather, irrelevant to how predators respond to color.
- D: A size difference does not show that color functions as a helper signal.', 'Find the result showing predators react to the bright color, not to anything else.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1ecf3a07-7be5-4b0f-be86-dc5cfdae96c8', 'Which finding, if true, would most directly support Rao''s hypothesis about Verlaine''s prosperity?', 'Historian Padma Rao studied the rapid growth of the medieval city of Verlaine and proposed that its prosperity stemmed mainly from its position at the junction of two major river trade routes rather than from its textile industry, as earlier scholars had assumed. Rao argued that goods passing through, rather than products made locally, drove the city''s wealth.', NULL, '[{"id":"A","text":"Surviving tax records show that most of Verlaine''s revenue came from tolls charged on goods being shipped through the city to other destinations.","is_correct":true,"explanation":"Revenue coming chiefly from transit tolls shows pass-through trade, not local textiles, drove the city''s wealth."},{"id":"B","text":"Verlaine''s weavers were renowned across the region for the fine quality of their dyed cloth.","is_correct":false,"explanation":"This supports the textile-industry view that Rao argues against, contradicting her hypothesis."},{"id":"C","text":"Verlaine''s population grew steadily during the two centuries that historians have studied.","is_correct":false,"explanation":"Population growth alone does not identify trade routes rather than textiles as the source of wealth."},{"id":"D","text":"The rivers near Verlaine occasionally flooded, damaging buildings along the waterfront.","is_correct":false,"explanation":"Flood damage is irrelevant to whether transit trade or textiles produced the city''s prosperity."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Rao proposed that the city''s prosperity stemmed from its trade-route junction and that {{yellow:goods passing through, rather than products made locally, drove the city''s wealth}}.
Step 2 — Match the evidence
Choice A shows most revenue came from tolls on goods shipped through to other destinations, directly confirming that pass-through trade rather than local textiles created the wealth.
Distractor analysis:
- B: Praises local weaving, supporting the rival textile view Rao rejects.
- C: Population growth does not pinpoint the source of the wealth.
- D: Flooding is irrelevant to the cause of prosperity.', 'Look for evidence that money came from goods moving through the city, not from things made there.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('27aa2201-d4f8-4ee5-a182-726981f22e49', 'Which quotation from "The Glass Orchard," if genuine, would most directly support the reader''s interpretation of Junie?', 'In his short story "The Glass Orchard," writer Tomas Beale presents the character Junie as someone who appears confident and carefree to her schoolmates. A reader argues that Junie''s outward cheerfulness is actually a performance she puts on to hide how anxious she feels about being judged by others.', NULL, '[{"id":"A","text":"\"Junie laughed loudest at lunch, but in the bathroom afterward she pressed a hand to her chest, willing her racing heart to slow before anyone noticed.\"","is_correct":true,"explanation":"Junie''s loud laughter giving way to a hidden racing heart shows her cheerfulness masks anxiety about being noticed."},{"id":"B","text":"\"The orchard behind the school had not borne fruit in years, its branches bare against the gray sky.\"","is_correct":false,"explanation":"This sets a scene and says nothing about Junie''s emotions or performance."},{"id":"C","text":"\"Junie had transferred to the school in autumn, after her family moved across the county.\"","is_correct":false,"explanation":"This gives background but reveals nothing about her hidden anxiety."},{"id":"D","text":"\"Her friends agreed that Junie was the most relaxed person any of them had ever met.\"","is_correct":false,"explanation":"This reports her confident surface and contradicts the claim that it hides anxiety."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The reader argues that Junie''s cheerfulness is a performance hiding {{yellow:how anxious she feels about being judged by others}}.
Step 2 — Match the evidence
Choice A shows Junie laughing loudest in public but privately calming a racing heart before anyone noticed, revealing the anxiety beneath her cheerful performance.
Distractor analysis:
- B: Describes the setting, not Junie''s emotions.
- C: Gives biographical background unrelated to hidden anxiety.
- D: Reports only her confident surface, contradicting the interpretation.', 'Find the line where Junie''s public cheer covers private nervousness.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('92eda3cc-aba2-4796-bc2c-fcc49b75426a', 'Which finding, if true, would most directly support the ecologists'' hypothesis?', 'Ecologists studying a mountain meadow proposed that the recent decline in a native wildflower was caused by the spread of an introduced grass that crowds out the wildflower by blocking sunlight. They predicted that wherever the introduced grass grows densely, the native wildflower should be scarce, while it should remain common where the grass is absent.', NULL, '[{"id":"A","text":"Meadow plots thick with the introduced grass contained few wildflowers, while plots free of the grass still had abundant wildflowers.","is_correct":true,"explanation":"Scarce wildflowers under dense grass and abundant ones without it match the predicted pattern of competition."},{"id":"B","text":"The introduced grass produces seeds that can survive in the soil for several years.","is_correct":false,"explanation":"Seed survival explains the grass''s persistence but not its effect on the wildflower''s abundance."},{"id":"C","text":"The native wildflower is pollinated mainly by a single species of bee.","is_correct":false,"explanation":"Pollination details do not address whether the grass causes the wildflower''s decline."},{"id":"D","text":"The introduced grass was first recorded in the meadow about a decade ago.","is_correct":false,"explanation":"The arrival date does not show that the grass crowds out the wildflower."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
The ecologists predicted that {{yellow:wherever the introduced grass grows densely, the native wildflower should be scarce, while it should remain common where the grass is absent}}.
Step 2 — Match the evidence
Choice A reports few wildflowers in grass-thick plots and abundant wildflowers where grass is absent, exactly the contrast the hypothesis predicts.
Distractor analysis:
- B: Seed survival explains persistence, not the wildflower''s decline.
- C: Pollination by one bee is irrelevant to the grass''s effect.
- D: The arrival date does not show crowding out.', 'Look for the result that compares wildflower numbers where grass is dense versus absent.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1f785de5-ddff-4be2-a67b-7ac8e427c6ff', 'Which finding, if true, would most directly support the psychologist''s hypothesis?', 'A psychologist hypothesized that people remember information better when they explain it aloud to someone else than when they simply reread it silently. To test this, she compared two groups of students who studied the same passage, one group rereading it and the other explaining it to a partner, and predicted that the explaining group would later recall more of the material.', NULL, '[{"id":"A","text":"Students who explained the passage to a partner scored higher on a later recall test than students who reread it silently.","is_correct":true,"explanation":"Higher recall scores for explainers over rereaders directly match the predicted memory advantage."},{"id":"B","text":"Students in both groups reported enjoying the study session about equally.","is_correct":false,"explanation":"Equal enjoyment says nothing about which method improved memory."},{"id":"C","text":"Students who reread the passage finished studying in less time than those who explained it.","is_correct":false,"explanation":"Study time differences do not show that explaining improves recall."},{"id":"D","text":"Students who explained the passage said they felt more confident about the material afterward.","is_correct":false,"explanation":"Feeling confident is not the same as actually recalling more, so this does not test the hypothesis."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
The psychologist predicted that {{yellow:the explaining group would later recall more of the material}}.
Step 2 — Match the evidence
Choice A reports that explainers scored higher than rereaders on a recall test, directly confirming the predicted advantage in memory.
Distractor analysis:
- B: Equal enjoyment is unrelated to memory performance.
- C: Study time does not measure recall.
- D: Confidence is not the same as actual recall.', 'Find the result that compares how much each group later remembered.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ef6e7f37-e75b-487d-8df9-fe4eb3431d43', 'Which stage direction or line from "Wintering," if genuine, would most directly support the scholar''s interpretation of Aldous?', 'In the play "Wintering," dramatist Cordelia Hines depicts the businessman Mr. Aldous as ruthless in public dealings. One scholar contends that, despite this public hardness, Aldous is privately generous, quietly helping people in ways he takes pains to keep hidden from everyone around him.', NULL, '[{"id":"A","text":"Aldous slams the ledger shut and dismisses the pleading clerk without a glance.","is_correct":false,"explanation":"This shows his public ruthlessness, contradicting the claim of hidden generosity."},{"id":"B","text":"Late at night, Aldous slips an envelope of money under the widow''s door, then hurries away before she can open it.","is_correct":true,"explanation":"Secretly leaving money and fleeing before being seen shows the hidden private generosity the scholar describes."},{"id":"C","text":"Aldous announces to the boardroom that profits have doubled since he took control.","is_correct":false,"explanation":"This shows his public business success, not any concealed kindness."},{"id":"D","text":"Aldous keeps a meticulous record of every debt he is owed.","is_correct":false,"explanation":"Tracking debts reinforces his hardness and does not reveal hidden generosity."}]'::jsonb, 'B', 'Step 1 — Identify the claim
The scholar contends that Aldous is privately generous, {{yellow:quietly helping people in ways he takes pains to keep hidden from everyone around him}}.
Step 2 — Match the evidence
Choice B shows Aldous secretly slipping money under a widow''s door and fleeing before he can be seen, exactly the concealed generosity the scholar describes.
Distractor analysis:
- A: Depicts public ruthlessness, contradicting hidden generosity.
- C: Shows business success, not concealed kindness.
- D: Tracking debts reinforces his hardness instead.', 'Look for a moment where Aldous helps someone but hides that he did it.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fd341985-d80a-483a-bf04-1bee56e88d2f', 'Which finding, if true, would most directly support the archaeologist''s hypothesis?', 'An archaeologist studying an ancient farming village proposed that its inhabitants traded with distant coastal communities, rather than living in isolation as earlier researchers believed. She reasoned that if such trade occurred, the village should contain materials or objects that could only have originated from the distant coast.', NULL, '[{"id":"A","text":"Excavations at the village uncovered seashell ornaments made from a species found only along the distant coast.","is_correct":true,"explanation":"Coastal-only seashells at the inland village show contact with the distant coast, supporting the trade claim."},{"id":"B","text":"The village''s houses were built from clay and timber available in the surrounding hills.","is_correct":false,"explanation":"Locally sourced building materials say nothing about contact with the distant coast."},{"id":"C","text":"The village was inhabited for several centuries before it was abandoned.","is_correct":false,"explanation":"How long the village lasted does not indicate whether it traded with the coast."},{"id":"D","text":"Skeletons found at the site showed the villagers ate mostly grains and legumes.","is_correct":false,"explanation":"A grain-based diet does not reveal contact with distant coastal communities."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
The archaeologist reasoned that if trade occurred, {{yellow:the village should contain materials or objects that could only have originated from the distant coast}}.
Step 2 — Match the evidence
Choice A reports seashell ornaments from a species found only on the distant coast, exactly the kind of coast-only material the hypothesis predicts.
Distractor analysis:
- B: Local building materials show no coastal contact.
- C: Length of habitation does not indicate trade.
- D: Diet of local grains does not show coastal contact.', 'Find the object that could only have come from the far-off coast.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('da4b6577-0e9f-45f3-acac-b125d4ea4409', 'Which finding, if true, would most directly support the researcher''s hypothesis?', 'A nutrition researcher hypothesized that adding a short walk after dinner helps lower the spike in blood sugar that typically follows a meal. She arranged for volunteers to eat identical dinners on two evenings, taking a walk on one evening and resting on the other, and predicted that blood sugar would rise less on the evenings the volunteers walked.', NULL, '[{"id":"A","text":"On evenings when volunteers walked after dinner, their blood sugar rose less than on evenings when they rested.","is_correct":true,"explanation":"A smaller blood-sugar rise on walking evenings directly matches the predicted effect of the after-dinner walk."},{"id":"B","text":"Volunteers reported feeling more relaxed on the evenings they took a walk.","is_correct":false,"explanation":"Feeling relaxed is not the same as a reduced blood-sugar spike."},{"id":"C","text":"The dinners the volunteers ate contained the same number of calories each evening.","is_correct":false,"explanation":"This describes the controlled meal, not the outcome the hypothesis predicts."},{"id":"D","text":"Volunteers who exercised regularly had lower blood sugar overall than those who did not.","is_correct":false,"explanation":"General fitness differences do not test whether the after-dinner walk reduces the meal-time spike."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
The researcher predicted that {{yellow:blood sugar would rise less on the evenings the volunteers walked}}.
Step 2 — Match the evidence
Choice A reports a smaller blood-sugar rise on walking evenings than on resting evenings, directly confirming the predicted effect.
Distractor analysis:
- B: Feeling relaxed is not a measure of the blood-sugar spike.
- C: Equal calories describes the setup, not the result.
- D: Overall fitness differences do not test the after-dinner walk.', 'Look for the result comparing blood sugar on walking evenings versus resting evenings.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('73b62376-48e7-41cd-a915-df435a0420d1', 'Which quotation from "River of Salt," if genuine, would most directly support the critic''s interpretation of Bram?', 'In the novel "River of Salt," author Hadley Quinn writes about a young sailor named Bram who claims he is eager to leave his small fishing town and see the world. A critic suggests that, in truth, Bram is afraid to leave and feels a strong attachment to the home he says he wants to escape.', NULL, '[{"id":"A","text":"\"Bram boasted to the dockhands that he would sail farther than any of them had ever dared.\"","is_correct":false,"explanation":"This restates his stated eagerness to leave and does not reveal hidden fear or attachment."},{"id":"B","text":"\"On the morning his ship was to depart, Bram lingered at the harbor wall, tracing the worn stones and finding excuses to delay until the tide had nearly turned.\"","is_correct":true,"explanation":"Lingering and inventing delays at the moment of departure reveals fear of leaving and attachment to home."},{"id":"C","text":"\"The fishing town had stood at the river''s mouth for as long as anyone could remember.\"","is_correct":false,"explanation":"This describes the town''s history, not Bram''s feelings about leaving it."},{"id":"D","text":"\"Bram had spent his boyhood mending nets alongside his father on the docks.\"","is_correct":false,"explanation":"This is background about his past and does not show present fear or attachment."}]'::jsonb, 'B', 'Step 1 — Identify the claim
The critic suggests that Bram is afraid to leave and {{yellow:feels a strong attachment to the home he says he wants to escape}}.
Step 2 — Match the evidence
Choice B shows Bram lingering at the harbor and inventing excuses to delay his departure, revealing the fear and attachment the critic describes beneath his eager words.
Distractor analysis:
- A: Repeats his stated eagerness, the opposite of hidden fear.
- C: Describes the town''s history, not Bram''s feelings.
- D: Gives background about his past, not present reluctance.', 'Find the line where Bram''s actions show reluctance to actually leave.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d6b905c8-4047-4ca9-abe5-73ba52fc2cea', 'Which finding, if true, would most directly support the researchers'' hypothesis?', 'A team of researchers proposed that songbirds in noisy urban areas sing at a higher pitch than the same species living in quiet rural areas, because higher pitches carry better over low-frequency city noise. They predicted that recordings would show city birds singing at higher pitches than their rural counterparts of the same species.', NULL, '[{"id":"A","text":"Recordings showed that birds of the species living in noisy city parks sang at consistently higher pitches than those in quiet rural fields.","is_correct":true,"explanation":"City birds singing higher than rural birds of the same species directly matches the prediction."},{"id":"B","text":"City birds were found to sing more often during the early morning hours.","is_correct":false,"explanation":"Timing of singing does not address whether city birds sing at a higher pitch."},{"id":"C","text":"Rural birds of the species tended to build their nests in taller trees.","is_correct":false,"explanation":"Nest height is unrelated to the pitch of the birds'' songs."},{"id":"D","text":"The species was found in roughly equal numbers in both city and rural habitats.","is_correct":false,"explanation":"Equal population sizes do not show a difference in song pitch."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
The researchers predicted that {{yellow:recordings would show city birds singing at higher pitches than their rural counterparts of the same species}}.
Step 2 — Match the evidence
Choice A reports city-park birds singing at consistently higher pitches than rural-field birds of the same species, exactly the difference the hypothesis predicts.
Distractor analysis:
- B: Timing of song does not address pitch.
- C: Nest height is unrelated to song pitch.
- D: Equal population sizes say nothing about pitch.', 'Look for the result comparing the pitch of city birds with that of rural birds.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c23bb8a9-6cd3-4cb9-97f1-fe6ff37e4816', 'Which finding, if true, would most directly support the historians'' hypothesis?', 'Historians examining a nineteenth-century town proposed that the opening of a new railway station, rather than the founding of its college, was the main reason the town''s population grew so quickly. They argued that if the railway was the chief cause, the sharpest rise in population should align with the year the station opened.', NULL, '[{"id":"A","text":"Census records show the town''s population grew most sharply in the same year the railway station opened.","is_correct":true,"explanation":"The steepest population rise coinciding with the station''s opening matches the predicted timing for the railway as the cause."},{"id":"B","text":"The college admitted its first class of students several years after the town was founded.","is_correct":false,"explanation":"When the college began does not show that the railway, rather than the college, drove growth."},{"id":"C","text":"The railway station was built from stone quarried in a neighboring county.","is_correct":false,"explanation":"The station''s building material is irrelevant to the cause of population growth."},{"id":"D","text":"The town''s college eventually became one of the largest in the region.","is_correct":false,"explanation":"The college''s later size supports the rival explanation, not the railway hypothesis."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
The historians argued that if the railway was the chief cause, {{yellow:the sharpest rise in population should align with the year the station opened}}.
Step 2 — Match the evidence
Choice A shows the population grew most sharply in the same year the station opened, exactly the timing the hypothesis predicts for the railway as the main cause.
Distractor analysis:
- B: The college''s start date does not establish the railway as the cause.
- C: The station''s building material is irrelevant.
- D: The college''s later size supports the rival explanation.', 'Find the evidence that the biggest population jump matched the year the station opened.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('bc9cf9fe-16f1-4bd6-bf68-aadcb61f95e8', 'Which finding, if true, would most directly support the historian''s hypothesis?', 'A historian studying medieval guilds in northern Europe proposes that guilds primarily functioned to limit competition among established artisans rather than to ensure product quality for consumers. She notes that guild records frequently set maximum numbers of new members admitted each decade, and that prices for guild-made goods rose steadily even in years when raw materials grew cheaper. If her hypothesis is correct, she predicts a particular pattern would emerge from a fuller survey of surviving guild documents across several towns.', NULL, '[{"id":"A","text":"Towns where guilds capped membership most strictly showed the highest artisan profits and the fewest competing newcomers, even when their goods were no better made than goods elsewhere.","is_correct":true,"explanation":"This directly links membership caps to artisan profit and reduced competition without improved quality, matching the competition-limiting claim."},{"id":"B","text":"Guild-made goods were on average more durable than goods produced by non-guild artisans in the same region.","is_correct":false,"explanation":"This supports a quality-ensuring purpose, contradicting the hypothesis that guilds chiefly limited competition."},{"id":"C","text":"Several guilds maintained written standards describing how their goods should be inspected before sale.","is_correct":false,"explanation":"Existence of quality standards does not address the competition-limiting motive and points toward the rival explanation."},{"id":"D","text":"Guild membership records survive in greater numbers from larger towns than from smaller villages.","is_correct":false,"explanation":"This concerns record survival, not the function of guilds, so it is true-but-irrelevant."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The historian argues guilds existed to {{yellow:limit competition among established artisans rather than to ensure product quality for consumers}}.
Step 2 — Match the finding
Choice A ties strict membership caps to higher profits and fewer competitors while quality stays equal, which is exactly what limiting competition (not ensuring quality) would produce.
Distractor analysis:
- B: Better durability supports the quality explanation she rejects, so it weakens her claim.
- C: Inspection standards point to a quality purpose and are irrelevant to the competition motive.
- D: Record survival rates say nothing about why guilds operated.', 'Look for evidence that ties the membership caps to profit and reduced competition rather than to better goods.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f250627f-f4d2-4186-bf2f-d1e8a6aa771e', 'Which finding, if true, would most directly support the ecologist''s hypothesis?', 'An ecologist studying coral reefs argues that fish which graze on algae are essential to reef recovery after bleaching events. She reasons that when bleaching kills coral, fast-growing algae quickly colonize the bare skeletons, and without grazers to remove this algae, young coral larvae cannot find clean surfaces to settle on. She therefore expects that the presence of grazing fish, more than any other single factor, determines whether a bleached reef regrows.', NULL, '[{"id":"A","text":"Bleached reefs with abundant grazing fish were recolonized by young coral far more often than otherwise similar reefs where grazing fish had been removed.","is_correct":true,"explanation":"This isolates grazer presence as the factor driving recolonization, directly matching the claim."},{"id":"B","text":"Grazing fish on healthy reefs consume a wider variety of algae species than previously documented.","is_correct":false,"explanation":"Diet breadth on healthy reefs does not address recovery of bleached reefs, so it is irrelevant."},{"id":"C","text":"Coral larvae are able to settle on surfaces coated with thick mats of algae as readily as on clean ones.","is_correct":false,"explanation":"This contradicts the mechanism that algae blocks larvae, weakening rather than supporting the hypothesis."},{"id":"D","text":"Water temperature is the primary trigger of the bleaching events themselves.","is_correct":false,"explanation":"What causes bleaching is true but separate from what enables recovery afterward."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The ecologist holds that {{yellow:the presence of grazing fish, more than any other single factor, determines whether a bleached reef regrows}}.
Step 2 — Match the finding
Choice A compares similar reefs differing only in grazer presence and shows grazers drive recolonization, which is precisely the predicted pattern.
Distractor analysis:
- B: Diet variety on healthy reefs is unrelated to bleached-reef recovery.
- C: If larvae settle equally on algae, the proposed mechanism collapses, weakening the claim.
- D: The cause of bleaching is a different question from recovery.', 'Find the option that compares reefs differing mainly in whether grazers are present.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('97d3c3ad-0dce-4408-84c2-5ae732d414ca', 'Which finding, if true, would most directly support the critic''s claim?', 'In her novel, the author repeatedly describes the protagonist''s childhood home in warm, glowing language while rendering his adult apartment in cold, gray terms. A critic claims this contrast is not merely decorative but signals the author''s central theme: that the protagonist measures every later experience against an idealized memory of childhood that no present reality can match. The critic expects other features of the novel to reinforce this reading.', NULL, '[{"id":"A","text":"Throughout the novel, the protagonist rejects new opportunities by comparing them unfavorably to remembered moments from his childhood home.","is_correct":true,"explanation":"This shows the protagonist actually measuring present experiences against an idealized past, confirming the theme."},{"id":"B","text":"The author uses warm and cold color imagery in several of her other novels as well.","is_correct":false,"explanation":"A stylistic habit across books does not show the contrast carries this specific theme here."},{"id":"C","text":"The protagonist''s apartment is described in greater physical detail than his childhood home.","is_correct":false,"explanation":"Relative detail does not bear on whether he idealizes the past; it is irrelevant."},{"id":"D","text":"The protagonist eventually sells his childhood home without hesitation or regret.","is_correct":false,"explanation":"Selling without regret undercuts the idea that he clings to an idealized memory, weakening the claim."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The critic argues the protagonist {{yellow:measures every later experience against an idealized memory of childhood that no present reality can match}}.
Step 2 — Match the finding
Choice A shows him rejecting present opportunities by comparing them to remembered childhood moments, which is exactly that measuring-against-an-ideal behavior.
Distractor analysis:
- B: Reusing imagery elsewhere says nothing about the theme within this novel.
- C: Which space gets more detail is irrelevant to idealization.
- D: Letting the home go without regret contradicts the clinging-to-the-past reading.', 'Look for the protagonist actively comparing present experiences against the idealized past.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('52b82085-318f-4009-a8ae-7af4a38df751', 'Which finding, if true, would most directly support the psychologist''s hypothesis?', 'A psychologist hypothesizes that people remember tasks they failed to finish better than tasks they completed, because an unfinished task keeps producing low-level mental tension that keeps it active in memory. She predicts that if participants are interrupted partway through several puzzles and allowed to complete several others, the interrupted ones will be recalled more accurately later, and that this effect should fade once the interrupted task is finally allowed to be completed.', NULL, '[{"id":"A","text":"Participants recalled details of interrupted puzzles more accurately than completed ones, but this advantage disappeared for interrupted puzzles they were later permitted to finish.","is_correct":true,"explanation":"This matches both the better recall of unfinished tasks and the predicted fading once they are completed."},{"id":"B","text":"Participants reported finding the interrupted puzzles more frustrating than the completed ones.","is_correct":false,"explanation":"Frustration ratings do not establish the predicted memory advantage and its disappearance."},{"id":"C","text":"Participants who were better at puzzles overall recalled all of them more accurately.","is_correct":false,"explanation":"This attributes recall to skill, not to interruption, missing the hypothesis."},{"id":"D","text":"Participants recalled completed and interrupted puzzles equally well regardless of whether they finished them.","is_correct":false,"explanation":"Equal recall directly contradicts the predicted memory advantage."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The psychologist predicts interrupted tasks are recalled better but that {{yellow:this effect should fade once the interrupted task is finally allowed to be completed}}.
Step 2 — Match the finding
Choice A reports both the recall advantage for interrupted puzzles and its disappearance after completion, matching both halves of the prediction.
Distractor analysis:
- B: Frustration is a feeling, not the memory effect being tested.
- C: Linking recall to puzzle skill is an alternative explanation, not support.
- D: Equal recall contradicts the core prediction.', 'The right finding must show both better recall of unfinished tasks and that it fades after completion.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9b8cbea4-91fa-47af-8a54-afebc89b7297', 'Which finding, if true, would most directly support the historian''s argument?', 'A historian of technology argues that the spread of the mechanical clock in late-medieval cities reshaped daily life by replacing flexible, task-based schedules with rigid, time-based ones. He contends that as public clocks appeared, work and markets increasingly began and ended at fixed hours rather than when a task was done or when the sun reached a certain point. He expects records from clock-equipped cities to reveal this shift.', NULL, '[{"id":"A","text":"After public clocks were installed, town ordinances increasingly specified exact hours for opening markets and beginning labor, replacing earlier rules tied to completing a task or to sunrise.","is_correct":true,"explanation":"This shows the predicted shift from task- and sun-based timing to fixed clock hours."},{"id":"B","text":"Public clocks were expensive and often funded by wealthy merchants and town councils.","is_correct":false,"explanation":"Funding details do not show that clocks changed how time structured daily life."},{"id":"C","text":"Some rural villages without clocks continued to organize work around the completion of seasonal tasks.","is_correct":false,"explanation":"This concerns places without clocks and does not demonstrate change within clock-equipped cities."},{"id":"D","text":"Mechanical clocks in this period frequently lost or gained several minutes per day.","is_correct":false,"explanation":"Clock inaccuracy is true but irrelevant to whether schedules became time-based."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The historian argues clocks replaced {{yellow:flexible, task-based schedules with rigid, time-based ones}}.
Step 2 — Match the finding
Choice A documents ordinances switching from task- and sunrise-based rules to fixed hours after clocks arrived, exactly the predicted shift.
Distractor analysis:
- B: Who paid for clocks does not show a change in scheduling.
- C: Clockless villages keeping old habits says nothing about clock-equipped cities.
- D: Clock inaccuracy is unrelated to the move toward fixed hours.', 'Look for evidence that scheduling rules changed from task/sun-based to fixed hours after clocks appeared.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6c468bee-801c-4ebe-9945-7639b5bdb7fd', 'Which finding, if true, would most directly support the biologist''s hypothesis?', 'A biologist studying a species of songbird proposes that males sing more complex songs not to attract mates but to warn rival males away from their territory. She notes that the most elaborate songs occur at territory boundaries and that singing increases sharply when a strange male approaches. She predicts that if her hypothesis is right, song complexity should track territorial defense rather than the presence of available females.', NULL, '[{"id":"A","text":"Males sang their most complex songs when rival males intruded, but song complexity did not rise when unpaired females were nearby.","is_correct":true,"explanation":"This shows complexity tracking territorial defense and not female presence, exactly as predicted."},{"id":"B","text":"Males with more complex songs tended to attract mates earlier in the breeding season.","is_correct":false,"explanation":"This supports the mate-attraction explanation the biologist rejects, weakening her claim."},{"id":"C","text":"Female songbirds of this species do not sing at all.","is_correct":false,"explanation":"That females don''t sing is true but does not distinguish defense from attraction as the male''s motive."},{"id":"D","text":"Song complexity varies among males of different ages.","is_correct":false,"explanation":"Age variation does not address whether singing serves territorial defense versus attracting females."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The biologist predicts {{yellow:song complexity should track territorial defense rather than the presence of available females}}.
Step 2 — Match the finding
Choice A shows complexity rising with rival intrusion but not with nearby females, matching defense over attraction.
Distractor analysis:
- B: Earlier mating with complex songs supports the rejected mate-attraction view.
- C: Females not singing is irrelevant to the male''s purpose.
- D: Age-based variation does not separate the two competing explanations.', 'The supporting finding must separate response to rivals from response to females.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1f7438de-8390-4ab1-87f9-4e0adf95d08e', 'Which finding, if true, would most directly support the economist''s claim?', 'An economist studying small island economies claims that communities highly dependent on a single export crop are more vulnerable to lasting poverty than those with diverse exports, because a single bad harvest or price collapse can devastate the whole economy with no other sector to cushion the blow. She expects that comparing islands over several decades will reveal a clear difference in economic stability between the two types.', NULL, '[{"id":"A","text":"Islands relying on one export crop suffered longer and deeper economic downturns after price shocks than islands with several export sectors.","is_correct":true,"explanation":"This shows single-crop islands harmed more severely and lastingly, matching the vulnerability claim."},{"id":"B","text":"Single-crop islands often produced higher volumes of that crop than diversified islands produced of any one good.","is_correct":false,"explanation":"Higher output of one crop does not address vulnerability to downturns."},{"id":"C","text":"Diversified islands tended to have larger populations than single-crop islands.","is_correct":false,"explanation":"Population size is true but irrelevant to the stability comparison."},{"id":"D","text":"Single-crop islands recovered from price shocks just as quickly as diversified islands did.","is_correct":false,"explanation":"Equally quick recovery contradicts the prediction that single-crop islands are more vulnerable."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The economist argues single-crop communities are {{yellow:more vulnerable to lasting poverty than those with diverse exports}}.
Step 2 — Match the finding
Choice A shows single-crop islands enduring longer, deeper downturns after shocks, directly demonstrating greater vulnerability.
Distractor analysis:
- B: Higher crop volume does not address resilience to shocks.
- C: Population size is irrelevant to economic stability here.
- D: Equal recovery speed contradicts the claim of greater vulnerability.', 'Look for evidence that single-crop islands fared worse after economic shocks.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a7cb2d9b-6155-4462-9e07-182daa1478d2', 'Which finding, if true, would most directly support the linguist''s hypothesis?', 'A linguist hypothesizes that children learn the meanings of new words faster when adults follow the child''s existing focus of attention than when adults try to redirect it. She reasons that when an adult names an object the child is already looking at, the child can link word and object effortlessly, whereas redirecting attention forces the child to guess which object the new word refers to. She predicts a measurable difference in vocabulary growth.', NULL, '[{"id":"A","text":"Children whose caregivers most often named objects the children were already attending to learned new words faster than children whose caregivers more often redirected their attention.","is_correct":true,"explanation":"This links naming within the child''s attention to faster learning, exactly as predicted."},{"id":"B","text":"Children produced their first words at roughly the same age regardless of caregiver style.","is_correct":false,"explanation":"Same age of first words does not show a difference in learning rate and may weaken the claim."},{"id":"C","text":"Caregivers who redirected attention tended to use a larger total vocabulary themselves.","is_correct":false,"explanation":"Caregiver vocabulary size is a separate factor and does not test the attention hypothesis."},{"id":"D","text":"Children looked at named objects longer when the objects were brightly colored.","is_correct":false,"explanation":"Color-driven attention is true but does not address following versus redirecting attention."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The linguist predicts children learn words faster {{yellow:when adults follow the child''s existing focus of attention than when adults try to redirect it}}.
Step 2 — Match the finding
Choice A directly compares the two caregiver styles and shows faster learning when adults follow the child''s attention.
Distractor analysis:
- B: Same age of first words shows no rate difference, undercutting the claim.
- C: Caregiver vocabulary size is a confound, not support.
- D: Brightness-driven looking does not test following versus redirecting.', 'Find the option that contrasts caregivers following attention with caregivers redirecting it.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2029132a-6f2a-41bb-b1ad-515a337f4074', 'Which finding, if true, would most directly support the geologist''s proposal?', 'A geologist proposes that a now-dry lakebed in the desert was once filled by a large lake fed by rivers, rather than by occasional rainfall pooling in a low spot. She argues that a river-fed lake would have persisted long enough to leave thick layered sediments and distinct shoreline terraces at consistent elevations, whereas brief rain pools would leave only thin, irregular deposits. She plans to examine the basin for these features.', NULL, '[{"id":"A","text":"The basin contains thick, finely layered sediments and well-defined shoreline terraces at the same elevation around its rim.","is_correct":true,"explanation":"Thick layered sediments and consistent terraces are exactly the signs of a lasting river-fed lake she described."},{"id":"B","text":"The desert surrounding the basin receives almost no rainfall today.","is_correct":false,"explanation":"Current dryness does not indicate how the ancient lake was fed."},{"id":"C","text":"Thin, irregular mineral crusts are scattered unevenly across the basin floor.","is_correct":false,"explanation":"Thin irregular deposits are the signature of brief rain pools, contradicting the proposal."},{"id":"D","text":"The basin is surrounded by hills composed of volcanic rock.","is_correct":false,"explanation":"Surrounding rock type is true but irrelevant to how the lake was filled."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The geologist argues a river-fed lake would leave {{yellow:thick layered sediments and distinct shoreline terraces at consistent elevations}}.
Step 2 — Match the finding
Choice A reports exactly thick layered sediments and consistent-elevation terraces, the features she predicted for a persistent river-fed lake.
Distractor analysis:
- B: Today''s dryness says nothing about the ancient water source.
- C: Thin irregular deposits match the rain-pool alternative she rejects.
- D: Surrounding rock type does not bear on the lake''s source.', 'Look for the sediment and shoreline features she said a lasting river-fed lake would leave.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5a062ea3-0d7d-401a-a195-68023476364f', 'Which finding, if true, would most directly support the historian''s argument?', 'A political historian argues that a nineteenth-century reform movement succeeded mainly because it built alliances with groups outside its original membership, not because of the charisma of its founder. She notes that the movement grew slowly while led by its founder alone but expanded rapidly after it began partnering with labor unions and religious societies. She expects archival records to confirm that these alliances, rather than the founder''s leadership, drove its success.', NULL, '[{"id":"A","text":"The movement''s membership and legislative victories surged only after it formed partnerships with outside groups, and continued to grow even after its founder withdrew from leadership.","is_correct":true,"explanation":"Growth tied to alliances and continuing after the founder left shows alliances, not the founder, drove success."},{"id":"B","text":"The founder was widely praised in newspapers for his persuasive public speaking.","is_correct":false,"explanation":"Praise for the founder''s charisma supports the explanation the historian rejects."},{"id":"C","text":"The labor unions that allied with the movement had themselves grown rapidly in the same decade.","is_correct":false,"explanation":"The unions'' own growth is true but does not show the alliances drove the movement''s success."},{"id":"D","text":"The movement''s founder had previously led an unrelated charitable organization.","is_correct":false,"explanation":"The founder''s earlier career is irrelevant to what caused this movement''s success."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The historian argues the movement succeeded because of {{yellow:alliances with groups outside its original membership, not because of the charisma of its founder}}.
Step 2 — Match the finding
Choice A shows success surging after alliances formed and continuing after the founder left, pointing to alliances rather than the founder.
Distractor analysis:
- B: Praise for the founder supports the charisma explanation she rejects.
- C: The unions'' separate growth does not show the alliances caused the movement''s gains.
- D: The founder''s prior charity work is irrelevant.', 'The supporting finding should tie success to alliances and show it persisted without the founder.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6d6cd162-d062-4e9a-91f1-41c0d4388920', 'Which finding, if true, would most directly support the researcher''s hypothesis?', 'A nutrition researcher hypothesizes that eating meals at consistent times each day, independent of total calories, helps regulate body weight by keeping the body''s internal clock stable. He reasons that irregular meal timing disrupts the rhythms that govern metabolism, leading the body to store more fat even when the same amount is eaten. He predicts that comparing groups with regular versus irregular meal schedules will show a difference tied to timing alone.', NULL, '[{"id":"A","text":"Among people eating identical total calories, those on consistent daily meal schedules gained less weight than those whose meal times varied widely.","is_correct":true,"explanation":"This holds calories constant and isolates timing, showing regular timing reduces weight gain as predicted."},{"id":"B","text":"People on regular meal schedules tended to eat fewer total calories overall.","is_correct":false,"explanation":"If regular eaters consume fewer calories, the effect is not isolated to timing, undercutting the claim."},{"id":"C","text":"Irregular meal timing is more common among people who work night shifts.","is_correct":false,"explanation":"Who eats irregularly is true but does not test timing''s effect on weight independent of calories."},{"id":"D","text":"People on regular schedules reported feeling hungrier between meals.","is_correct":false,"explanation":"Hunger reports do not establish a weight difference driven by timing."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The researcher hypothesizes that consistent meal timing helps regulate weight {{yellow:independent of total calories}}.
Step 2 — Match the finding
Choice A compares people eating identical calories and finds regular timing yields less weight gain, isolating timing as predicted.
Distractor analysis:
- B: Differing calorie intake confounds the timing effect, weakening the claim.
- C: Who eats irregularly does not test the timing-weight link.
- D: Hunger between meals is not a weight outcome tied to timing.', 'The supporting finding must hold calories equal so only timing differs.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6fdaff9f-77c4-4978-b271-a25c0cfe9dc6', 'Which finding, if true, would most directly support the scholar''s claim?', 'A literary scholar examining an anonymous eighteenth-century pamphlet claims it was written by a particular well-known essayist of the period. She bases this on the pamphlet''s distinctive habit of opening arguments with rhetorical questions and its frequent use of an unusual punctuation pattern, both traits she associates strongly with that essayist''s signed works. She expects further textual comparison to strengthen the attribution.', NULL, '[{"id":"A","text":"A statistical comparison found that the pamphlet''s rhetorical-question openings and unusual punctuation pattern match the essayist''s signed works far more closely than they match any other writer of the era.","is_correct":true,"explanation":"This shows the very stylistic traits she cited matching the essayist uniquely, strengthening the attribution."},{"id":"B","text":"The pamphlet was printed by a press that the essayist had never been known to use.","is_correct":false,"explanation":"An unfamiliar printer weakens rather than supports the attribution."},{"id":"C","text":"The pamphlet addresses a political topic that many writers of the period discussed.","is_correct":false,"explanation":"A widely shared topic does not point to any single author."},{"id":"D","text":"The essayist''s signed works were popular and widely reprinted during his lifetime.","is_correct":false,"explanation":"His popularity is true but does not connect him specifically to this pamphlet."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The scholar attributes the pamphlet to the essayist based on its {{yellow:distinctive habit of opening arguments with rhetorical questions and its frequent use of an unusual punctuation pattern}}.
Step 2 — Match the finding
Choice A shows those exact traits matching the essayist''s signed works more closely than any other writer, directly supporting the attribution.
Distractor analysis:
- B: An unfamiliar printer argues against his authorship.
- C: A common topic does not single out one author.
- D: His general popularity does not tie him to this specific pamphlet.', 'Look for the option that matches the specific stylistic traits she named to the essayist''s known works.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8fd7b8e8-9340-4384-9526-19373408abc7', 'Which finding, if true, would most directly support Okafor''s "burglar alarm" hypothesis?', 'Marine biologist Dr. Imani Okafor studies bioluminescent plankton that glow when disturbed by predators. She hypothesizes that the glow is not merely a byproduct of stress but a defensive alarm: the sudden light attracts larger predators that then attack the plankton''s original attacker. According to this "burglar alarm" hypothesis, the flash should benefit the plankton only when a second, larger predator is nearby to respond. Okafor plans further observations in coastal waters where multiple predator levels coexist, hoping to confirm that the glow functions strategically rather than as a simple involuntary reaction to physical contact.', NULL, '[{"id":"A","text":"Small fish that prey on the plankton are eaten by larger fish significantly more often when the plankton they attack are glowing than when they are not.","is_correct":true,"explanation":"Correct: it shows the glow draws a larger predator to attack the original attacker, exactly the strategic defense the hypothesis predicts."},{"id":"B","text":"The plankton glow with equal intensity whether or not any predators are present in the surrounding water.","is_correct":false,"explanation":"This suggests the glow is an involuntary reaction, contradicting the strategic alarm hypothesis."},{"id":"C","text":"Plankton placed in tanks without water movement still occasionally emit faint light.","is_correct":false,"explanation":"True but irrelevant; it addresses spontaneous glow, not the predator-attracting defensive function."},{"id":"D","text":"Larger predators in the region consume a wide variety of small fish regardless of whether those fish are attacking plankton.","is_correct":false,"explanation":"Too broad; it does not link the glow to increased predation on the plankton''s specific attacker."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Okafor argues the glow is a strategic defense: {{yellow:the sudden light attracts larger predators that then attack the plankton''s original attacker}}.
Step 2 — Match the finding
Observing that the plankton''s attackers are eaten by larger fish more often when the plankton glow directly confirms the glow summons a second predator against the attacker.
Distractor analysis:
- B: Equal glow regardless of predators implies an involuntary reaction, which weakens the hypothesis.
- C: Faint spontaneous light in still water is true but irrelevant to the predator-attracting function.
- D: General predation on small fish is too broad and never ties the glow to the attacker''s increased risk.', 'Look for evidence that the glow specifically increases danger to the plankton''s own attacker.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8d6bd754-1649-47de-be91-105f9a8bd1ec', 'Which finding, if true, would most directly support Marchetti''s hypothesis?', 'Historian Lucia Marchetti examined account books from a sixteenth-century Italian printing house. She proposes that the firm survived a regional economic downturn not by cutting costs but by shifting its output toward cheap, single-sheet pamphlets that ordinary buyers could afford. Marchetti argues that while rival presses kept producing expensive bound volumes and went bankrupt, this firm deliberately repositioned itself toward a mass market. She believes the surviving ledgers, if read carefully, will show that the firm''s revenue during the downturn came increasingly from inexpensive print runs rather than from its earlier luxury editions.', NULL, '[{"id":"A","text":"During the downturn, the firm''s ledgers record a steadily rising share of income from low-priced pamphlets and a falling share from bound luxury volumes.","is_correct":true,"explanation":"Correct: it shows the deliberate revenue shift toward cheap mass-market print that the hypothesis claims kept the firm alive."},{"id":"B","text":"Several rival presses that produced only luxury volumes closed during the same downturn.","is_correct":false,"explanation":"This fits the rivals'' fate but says nothing about the surviving firm''s own shift to pamphlets."},{"id":"C","text":"The firm employed fewer skilled engravers after the downturn than before it.","is_correct":false,"explanation":"Reducing staff points toward cost-cutting, which the hypothesis explicitly rejects as the survival strategy."},{"id":"D","text":"Single-sheet pamphlets were popular among urban readers across many Italian cities in the period.","is_correct":false,"explanation":"Too broad; general pamphlet popularity does not show this firm''s revenue came to depend on them."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Marchetti contends the firm survived by repositioning toward cheap print, expecting ledgers to show {{yellow:the firm''s revenue during the downturn came increasingly from inexpensive print runs rather than from its earlier luxury editions}}.
Step 2 — Match the finding
Ledger records of rising pamphlet income and falling luxury income are exactly the documentary evidence the hypothesis predicts.
Distractor analysis:
- B: Rivals closing supports the contrast but not the firm''s own revenue shift.
- C: Fewer engravers implies cost-cutting, the strategy Marchetti rejects.
- D: General pamphlet popularity is too broad to show this firm''s dependence on them.', 'The claim is about where this firm''s revenue came from during the downturn.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1e294736-bbdb-4d43-8f1c-3e9d17961fff', 'Which detail from the novel, if present, would most directly support the critic''s reading?', 'In a novel, the narrator insists that her aloof grandmother never truly cared for the family, citing the old woman''s silence at gatherings and her refusal to discuss the past. A literary critic, however, advances a different reading: the grandmother''s reserve masks a deep, protective love shaped by early hardships she cannot bear to revisit. The critic suggests that the grandmother''s apparent coldness is a defense rather than indifference, and that careful attention to the grandmother''s actions, rather than the narrator''s interpretations, would reveal genuine devotion beneath the silence.', NULL, '[{"id":"A","text":"The grandmother quietly pays off the family''s debts for years without ever mentioning it or seeking thanks.","is_correct":true,"explanation":"Correct: an unspoken sacrificial action reveals devotion beneath silence, exactly the protective love the critic describes."},{"id":"B","text":"The grandmother often tells long, warm stories about her childhood at family dinners.","is_correct":false,"explanation":"This contradicts the text, which describes her silence and refusal to discuss the past."},{"id":"C","text":"The narrator admits she rarely spoke to her grandmother and knew little about her life.","is_correct":false,"explanation":"This questions the narrator''s reliability but offers no positive evidence of the grandmother''s devotion."},{"id":"D","text":"Other relatives also found the grandmother difficult to talk to at gatherings.","is_correct":false,"explanation":"This merely confirms her reserve without showing the hidden love the critic claims."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The critic reads the grandmother''s coldness as love, expecting that {{yellow:careful attention to the grandmother''s actions, rather than the narrator''s interpretations, would reveal genuine devotion beneath the silence}}.
Step 2 — Match the finding
A silent, selfless act like secretly paying the family''s debts is the kind of action that reveals devotion behind reserve.
Distractor analysis:
- B: Warm storytelling contradicts the established silence and the critic''s premise of reserve.
- C: The narrator''s ignorance undercuts her view but adds no evidence of devotion.
- D: Others finding her difficult only restates her reserve, not hidden love.', 'The critic points to actions, not words; find a caring action done silently.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1c5be702-21fb-4476-aa66-d48896b5c18f', 'Which finding, if true, would most directly support Nwosu''s hypothesis?', 'Ecologist Theo Nwosu studies a desert shrub whose seeds germinate only after wildfires. He hypothesizes that the seeds detect not heat itself but a specific chemical compound found in smoke, which signals that competing vegetation has been cleared and conditions are favorable for sprouting. Nwosu argues that if heat were the trigger, seeds would germinate near any source of high temperature. His hypothesis instead predicts that the chemical cue in smoke, independent of temperature, is what breaks the seeds'' dormancy and prompts them to grow.', NULL, '[{"id":"A","text":"Seeds exposed to smoke-derived chemicals at ordinary temperatures germinate, while seeds exposed only to high heat without smoke do not.","is_correct":true,"explanation":"Correct: it isolates the smoke chemical as the trigger and rules out heat, exactly as the hypothesis predicts."},{"id":"B","text":"Seeds buried deep in soil during a wildfire experience lower temperatures than seeds near the surface.","is_correct":false,"explanation":"True but irrelevant; it concerns temperature variation, not whether the smoke chemical breaks dormancy."},{"id":"C","text":"After a wildfire, far fewer competing plants surround the germinating shrub seeds.","is_correct":false,"explanation":"This describes the favorable conditions but does not show what cue the seeds actually detect."},{"id":"D","text":"Seeds exposed to very high heat germinate at the same rate as seeds exposed to smoke.","is_correct":false,"explanation":"Reverse evidence; equal germination from heat alone would support heat, not the smoke-chemical, as the trigger."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Nwosu predicts that {{yellow:the chemical cue in smoke, independent of temperature, is what breaks the seeds'' dormancy and prompts them to grow}}.
Step 2 — Match the finding
Germination from smoke chemicals at ordinary temperatures, but none from heat alone, isolates the chemical cue and excludes heat.
Distractor analysis:
- B: Soil temperature variation is irrelevant to the chemical-versus-heat question.
- C: Fewer competitors describes the favorable result, not the detection mechanism.
- D: Equal germination from heat alone reverses the hypothesis, supporting heat as the trigger.', 'Find evidence that separates the smoke chemical from heat as the actual signal.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('df12dd8c-989d-419d-b434-2809b600246a', 'Which finding, if true, would most directly support Raman''s hypothesis?', 'Economist Priya Raman studies why some small towns recover quickly after a major factory closes while others decline for decades. She proposes that recovery depends less on attracting a single large replacement employer and more on whether the town already has many small, diverse businesses. According to Raman, towns with varied small enterprises can absorb laid-off workers across many sectors, whereas towns dependent on one industry struggle when it vanishes. She expects that, comparing towns after factory closures, those with greater pre-existing business diversity will show faster employment recovery.', NULL, '[{"id":"A","text":"Among towns that lost a major factory, those that had a wide range of small businesses beforehand returned to pre-closure employment levels much sooner than towns dominated by one industry.","is_correct":true,"explanation":"Correct: it directly links pre-existing business diversity to faster employment recovery, the heart of the hypothesis."},{"id":"B","text":"A few towns recovered quickly after persuading another large company to open a new plant.","is_correct":false,"explanation":"This supports the single-large-employer route Raman downplays, not the diversity explanation."},{"id":"C","text":"Towns with diverse small businesses tend to have larger populations than single-industry towns.","is_correct":false,"explanation":"True but irrelevant; population size is not the recovery factor the hypothesis identifies."},{"id":"D","text":"Factory closures typically cause an immediate spike in local unemployment regardless of the town.","is_correct":false,"explanation":"Too broad; it describes the shock all towns share, not why recovery speeds differ."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Raman predicts that {{yellow:those with greater pre-existing business diversity will show faster employment recovery}}.
Step 2 — Match the finding
Observing that diverse-business towns returned to pre-closure employment sooner than single-industry towns confirms exactly this prediction.
Distractor analysis:
- B: Recovery via a new large employer supports the explanation Raman minimizes.
- C: Population differences are irrelevant to the diversity-recovery link.
- D: A universal unemployment spike is too broad to explain differing recovery speeds.', 'Match evidence directly to diversity causing faster recovery.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9beb8948-c5e8-4ea2-a695-94f219193621', 'Which finding, if true, would most directly support Cho''s planetary-transit hypothesis?', 'Astronomer Daniel Cho studies a distant star whose brightness dims at regular intervals. He hypothesizes that the dimming is caused by a large planet passing in front of the star, blocking part of its light. A competing idea holds that the star itself pulses, growing dimmer and brighter on its own. Cho notes that a transiting planet would block the same fraction of light each time and would not change the star''s color, whereas an internally pulsing star would shift slightly in color as its surface temperature varied. He plans to test which pattern the data reveal.', NULL, '[{"id":"A","text":"During each dimming, the star loses the same fraction of its light and shows no change in color.","is_correct":true,"explanation":"Correct: constant light loss with no color shift is precisely the transit signature Cho describes, ruling out pulsation."},{"id":"B","text":"The star grows slightly redder each time it dims and bluer as it brightens.","is_correct":false,"explanation":"A color shift with brightness matches the pulsing-star alternative, contradicting the transit hypothesis."},{"id":"C","text":"The intervals between dimmings vary unpredictably from one cycle to the next.","is_correct":false,"explanation":"Irregular timing argues against a planet on a fixed orbit, weakening rather than supporting the transit idea."},{"id":"D","text":"The star is among the brightest objects in its region of the sky.","is_correct":false,"explanation":"True but irrelevant; overall brightness says nothing about the cause of the periodic dimming."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Cho notes that {{yellow:a transiting planet would block the same fraction of light each time and would not change the star''s color}}.
Step 2 — Match the finding
Observing identical light loss with no color change matches the transit signature and excludes the pulsing-star alternative.
Distractor analysis:
- B: Color shifts with brightness fit the pulsing-star idea, contradicting the transit hypothesis.
- C: Irregular intervals undercut a planet on a regular orbit.
- D: Overall brightness is irrelevant to the cause of dimming.', 'Cho gives two transit signatures: constant light loss and no color change.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('197d4783-3ded-4290-bd9d-261f5cc90f1d', 'Which finding, if true, would most directly support Vargas''s hypothesis?', 'Anthropologist Sofia Vargas studies a mountain community famous for its elaborate gift-giving feasts. She argues that these feasts are not simply celebrations of wealth but a system for redistributing surplus food so that no household goes hungry during lean winters. In Vargas''s view, families who host lavish feasts in good years gain prestige but also obligate guests to share their own surpluses later, creating a cycle that buffers the whole community against scarcity. She predicts that the feasting tradition functions chiefly as insurance against hard times rather than mere displays of status.', NULL, '[{"id":"A","text":"Households that host feasts in abundant years routinely receive food gifts from former guests during later seasons of poor harvest.","is_correct":true,"explanation":"Correct: it shows the reciprocal sharing cycle that buffers against scarcity, the core of the insurance interpretation."},{"id":"B","text":"The most lavish feast hosts are widely admired and hold respected positions in the community.","is_correct":false,"explanation":"This supports the status-display reading Vargas argues against, not the insurance function."},{"id":"C","text":"Feasts feature rare delicacies that take great skill to prepare.","is_correct":false,"explanation":"True but irrelevant; the elaborateness of the food does not show redistribution buffers scarcity."},{"id":"D","text":"Neighboring communities without feasting traditions also survive lean winters.","is_correct":false,"explanation":"This weakens the claim that feasting is necessary for surviving scarcity rather than supporting it."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Vargas predicts the tradition {{yellow:functions chiefly as insurance against hard times rather than mere displays of status}}.
Step 2 — Match the finding
Feast hosts later receiving food from former guests during poor harvests demonstrates the reciprocal buffering cycle she describes.
Distractor analysis:
- B: Admiration for hosts supports the status reading she rejects.
- C: Elaborate food is irrelevant to redistribution.
- D: Other communities surviving without feasts weakens the insurance claim.', 'Look for the give-now, receive-later cycle that protects against lean times.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('44ad81ae-30c0-41bd-b68a-df50c91a8691', 'Which finding, if true, would most directly support Bell''s hypothesis?', 'Psychologist Aaron Bell studies how people remember lists of words. He hypothesizes that items are easier to recall when a person links them into a vivid mental story rather than repeating them silently. Bell reasons that storytelling forces the brain to connect items with meaning and imagery, building stronger pathways than bare repetition. He acknowledges that repetition can produce short-term recall, but predicts that participants who build a story around a word list will remember more items after a long delay than those who simply rehearse the words over and over.', NULL, '[{"id":"A","text":"A day later, participants who created a story linking the words recalled noticeably more of them than participants who only repeated the words.","is_correct":true,"explanation":"Correct: superior long-delay recall for the story group matches Bell''s exact prediction over rehearsal."},{"id":"B","text":"Immediately after studying, the repetition group and the story group recalled about the same number of words.","is_correct":false,"explanation":"Bell concedes repetition aids short-term recall, so equal immediate scores do not test his long-delay claim."},{"id":"C","text":"Participants generally enjoyed building stories more than repeating words.","is_correct":false,"explanation":"True but irrelevant; enjoyment is not the memory outcome the hypothesis concerns."},{"id":"D","text":"Longer word lists were harder to remember for both groups.","is_correct":false,"explanation":"Too broad; list difficulty affects both methods and does not favor storytelling."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Bell predicts that {{yellow:participants who build a story around a word list will remember more items after a long delay than those who simply rehearse the words over and over}}.
Step 2 — Match the finding
The story group recalling more words a day later directly confirms superior long-delay memory from storytelling.
Distractor analysis:
- B: Equal immediate recall does not test the long-delay claim Bell makes; he grants repetition helps short-term.
- C: Enjoyment is irrelevant to recall performance.
- D: General list difficulty affects both groups and favors neither method.', 'His prediction is specifically about recall after a long delay.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c4ea1323-423d-4625-a677-7d4599d020c7', 'Which finding, if true, would most directly support Lindgren''s single-eruption hypothesis?', 'Geologist Mara Lindgren studies a layer of unusual sediment found at many sites worldwide. She hypothesizes that the layer was deposited by a single massive volcanic eruption rather than by gradual local processes. Lindgren reasons that a single eruption would leave chemically identical ash across all the sites and would date to the same narrow window of time everywhere, whereas separate local events would produce varied chemistry and a range of ages. She intends to compare the composition and dating of the sediment from distant locations to determine which scenario fits.', NULL, '[{"id":"A","text":"Sediment samples from widely separated sites share nearly identical chemistry and date to the same narrow time interval.","is_correct":true,"explanation":"Correct: matching chemistry and ages across distant sites is exactly the single-eruption signature she describes."},{"id":"B","text":"The sediment layer is thicker at sites closer to known ancient volcanoes.","is_correct":false,"explanation":"Thickness near volcanoes is plausibly consistent with several scenarios and is not the test Lindgren specifies."},{"id":"C","text":"Each site''s sediment has a distinct chemical makeup and a different estimated age.","is_correct":false,"explanation":"Reverse evidence; varied chemistry and ages point to separate local events, contradicting the hypothesis."},{"id":"D","text":"Volcanic eruptions can scatter ash across great distances under the right winds.","is_correct":false,"explanation":"True but irrelevant; the general possibility does not show these specific deposits share one source."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Lindgren reasons that {{yellow:a single eruption would leave chemically identical ash across all the sites and would date to the same narrow window of time everywhere}}.
Step 2 — Match the finding
Identical chemistry and matching narrow ages across distant sites is precisely the predicted single-eruption signature.
Distractor analysis:
- B: Thickness near volcanoes is not the chemistry-and-dating test she set.
- C: Distinct chemistry and ages reverse the hypothesis toward separate local events.
- D: The general reach of ash does not establish a shared source for these deposits.', 'She names two single-eruption signatures: same chemistry and same age everywhere.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5568025d-204b-482c-9189-7646ba626e83', 'Which feature of the poem, if present, would most directly support the scholar''s reading?', 'A poet writes verses that, on the surface, celebrate a triumphant military parade. A scholar argues that the poem is actually a quiet protest against the war it seems to honor. The scholar contends that the poet buried critical meaning in word choices that an inattentive reader would miss, so that praise and condemnation coexist. According to this reading, the poem''s true stance becomes clear only when one notices how its imagery undercuts the celebratory tone. The scholar believes a close look at the poem''s specific images will reveal disapproval beneath the apparent praise.', NULL, '[{"id":"A","text":"The marching soldiers are repeatedly described with imagery of withering flowers and fading light.","is_correct":true,"explanation":"Correct: imagery of decay undercutting the celebratory tone reveals the buried disapproval the scholar claims."},{"id":"B","text":"The poem uses a strict, regular rhythm throughout its stanzas.","is_correct":false,"explanation":"True but irrelevant; meter alone carries no critical attitude toward the war."},{"id":"C","text":"The poem names the specific city where the parade took place.","is_correct":false,"explanation":"A factual detail does not reveal any hidden disapproval beneath the praise."},{"id":"D","text":"Crowds in the poem cheer the soldiers with bright banners and loud horns.","is_correct":false,"explanation":"This reinforces the celebratory surface rather than undercutting it, contradicting the scholar''s reading."}]'::jsonb, 'A', 'Step 1 — Identify the claim
The scholar argues the poem''s protest emerges from how {{yellow:its imagery undercuts the celebratory tone}}.
Step 2 — Match the finding
Describing soldiers with withering, fading imagery is exactly the kind of image that undercuts celebration and reveals buried disapproval.
Distractor analysis:
- B: Regular rhythm carries no critical stance.
- C: Naming the city is a neutral fact, not hidden criticism.
- D: Cheering crowds reinforce the celebratory surface, contradicting the protest reading.', 'Find imagery whose mood clashes with the parade''s celebration.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('794f4a98-a2b3-41c6-a226-c187b258c980', 'Which finding, if true, would most directly support Karimi''s hypothesis?', 'Biologist Reza Karimi studies a species of songbird in which males sing complex songs. He hypothesizes that females prefer males with larger song repertoires because a varied repertoire signals that a male has survived long enough to learn many songs, making him a healthier mate. A rival explanation holds that females simply respond to whichever song is loudest. Karimi notes that under his view, repertoire size, not volume, should predict mating success. He plans to observe which males attract the most mates and compare their repertoires and song volumes.', NULL, '[{"id":"A","text":"Males with the largest song repertoires attract the most mates even when their songs are no louder than those of other males.","is_correct":true,"explanation":"Correct: repertoire size predicting mating success independent of volume matches Karimi''s prediction and excludes loudness."},{"id":"B","text":"The loudest-singing males attract the most mates regardless of how many songs they know.","is_correct":false,"explanation":"This supports the rival volume explanation, contradicting Karimi''s repertoire hypothesis."},{"id":"C","text":"Older males tend to sing more frequently during the breeding season.","is_correct":false,"explanation":"True but irrelevant; song frequency is not repertoire size and does not establish female preference."},{"id":"D","text":"Males of this species sing more in the early morning than at other times of day.","is_correct":false,"explanation":"Too broad; timing of singing says nothing about whether repertoire size drives mating success."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Karimi holds that {{yellow:repertoire size, not volume, should predict mating success}}.
Step 2 — Match the finding
Large-repertoire males attracting the most mates even without singing louder confirms repertoire, not volume, drives success.
Distractor analysis:
- B: Loudest males succeeding supports the rival volume explanation.
- C: Song frequency among older males is irrelevant to repertoire-based preference.
- D: Time-of-day singing is too broad to address mating success.', 'Look for repertoire predicting mates while volume is held equal.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8775673a-ced0-427e-aaa0-cc4b5d9c73a9', 'Which finding, if true, would most directly support Pratt''s hypothesis?', 'Historian Owen Pratt studies why a medieval port city grew rapidly while a neighboring inland town stagnated. He argues that the port''s growth stemmed mainly from its access to long-distance sea trade, not from any advantage in farmland or local resources. Pratt contends that goods arriving by ship gave the port merchants wealth and connections the inland town could not match, despite the two settlements sharing similar soil and climate. He expects that records of the port''s commerce will show that its prosperity rose chiefly alongside the volume of seaborne goods passing through its harbor.', NULL, '[{"id":"A","text":"City records show that the port''s wealth grew in close step with increases in the volume of goods shipped through its harbor.","is_correct":true,"explanation":"Correct: prosperity tracking seaborne trade volume is exactly the link Pratt''s hypothesis predicts."},{"id":"B","text":"The inland town had slightly poorer soil than the port city.","is_correct":false,"explanation":"This conflicts with Pratt''s premise that the two shared similar soil and shifts the cause to farmland, not sea trade."},{"id":"C","text":"The port city held a large religious festival each summer that drew visitors.","is_correct":false,"explanation":"True but irrelevant; a festival is not the sea-trade mechanism the hypothesis identifies."},{"id":"D","text":"Both the port and the inland town had grown modestly during an earlier century.","is_correct":false,"explanation":"Too broad; earlier shared growth does not explain the later divergence Pratt attributes to sea trade."}]'::jsonb, 'A', 'Step 1 — Identify the claim
Pratt expects records to show {{yellow:its prosperity rose chiefly alongside the volume of seaborne goods passing through its harbor}}.
Step 2 — Match the finding
Records showing wealth growing in step with shipping volume directly confirm sea trade as the engine of growth.
Distractor analysis:
- B: Poorer inland soil contradicts Pratt''s shared-soil premise and credits farmland instead.
- C: A summer festival is irrelevant to the sea-trade mechanism.
- D: Earlier shared growth is too broad to explain the later divergence.', 'Pratt ties prosperity specifically to the volume of seaborne goods.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f3d50890-ed32-4653-8210-90394dc00d24', 'Which finding, if true, would most directly support Dr. Okafor''s hypothesis that cleaner shrimp recognize returning individual fish?', 'Marine biologist Dr. Okafor studies cleaner shrimp, which remove parasites from larger reef fish. She hypothesizes that the shrimp maintain long-term relationships with specific fish, recognizing returning individuals rather than treating every visitor as a stranger. If this were true, Okafor reasons, a shrimp''s behavior toward a fish should depend on their shared history. She plans to observe how shrimp respond to fish they have serviced repeatedly compared with fish encountered for the first time, expecting the two situations to produce measurably different shrimp behavior.', NULL, '[{"id":"A","text":"Shrimp begin cleaning familiar fish more quickly and with less hesitation than fish they have never serviced before.","is_correct":true,"explanation":"Faster, less hesitant service for familiar fish shows the shrimp''s behavior depends on shared history, exactly what the hypothesis predicts."},{"id":"B","text":"Shrimp remove a similar number of parasites per minute regardless of which fish they are cleaning.","is_correct":false,"explanation":"Equal cleaning rates across all fish show no dependence on history, contradicting the hypothesis."},{"id":"C","text":"Larger reef fish visit cleaning stations more often during the warmer months of the year.","is_correct":false,"explanation":"Seasonal visit frequency is true-but-irrelevant to whether shrimp recognize specific individuals."},{"id":"D","text":"Cleaner shrimp are themselves sometimes eaten by predatory fish that approach the station.","is_correct":false,"explanation":"Predation on shrimp says nothing about recognition of returning fish, so it is irrelevant."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
Okafor expects that {{yellow:a shrimp''s behavior toward a fish should depend on their shared history}}, with familiar and new fish producing different behavior.
Step 2 — Match the finding
Servicing familiar fish faster and with less hesitation than new fish is a behavioral difference tied to shared history, directly supporting recognition.
Distractor analysis:
- B: Equal cleaning rates show no behavioral difference, contradicting the hypothesis.
- C: Seasonal visit frequency is true-but-irrelevant to individual recognition.
- D: Predation on shrimp does not bear on whether shrimp recognize returning fish.', 'Look for a behavioral difference that depends on whether the shrimp and fish have a shared history.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f33d9d0d-224b-451e-a09d-06bf95251664', 'Which finding, if true, would most directly support Vasquez''s argument that factory workers drove the spread of the libraries?', 'Historian Lena Vasquez argues that the rapid spread of public lending libraries in a 19th-century industrial city was driven mainly by factory workers seeking self-education, not by wealthy philanthropists wanting to display generosity. She notes that the city''s libraries multiplied fastest in working-class districts. Vasquez contends that if workers drove the movement, the libraries'' collections and hours should reflect workers'' needs rather than donors'' tastes. She plans to examine borrowing records, opening times, and the kinds of books each branch stocked across different neighborhoods.', NULL, '[{"id":"A","text":"Branches in working-class districts stayed open in the evenings and stocked practical trade manuals most borrowed by laborers.","is_correct":true,"explanation":"Evening hours and trade manuals heavily borrowed by laborers show collections and hours reflecting workers'' needs, exactly as the argument predicts."},{"id":"B","text":"The city''s wealthiest residents donated the largest single sums toward constructing new library buildings.","is_correct":false,"explanation":"Large donations from the wealthy point toward philanthropists, the explanation Vasquez rejects."},{"id":"C","text":"Libraries in every district kept identical daytime hours and stocked mostly classical literature favored by donors.","is_correct":false,"explanation":"Donor-favored collections and daytime-only hours reflect donors'' tastes, contradicting the argument."},{"id":"D","text":"Several nearby cities also built public libraries during the same decade.","is_correct":false,"explanation":"Regional library growth is true-but-irrelevant to who drove this city''s movement."}]'::jsonb, 'A', 'Step 1 — Identify the test
Vasquez claims that if workers drove the movement, {{yellow:the libraries'' collections and hours should reflect workers'' needs rather than donors'' tastes}}.
Step 2 — Match the finding
Evening hours suited to working shifts and trade manuals most borrowed by laborers show collections and hours serving workers, supporting the argument.
Distractor analysis:
- B: Large gifts from the wealthy support the philanthropist explanation she rejects.
- C: Donor-favored books and daytime hours reflect donors'' tastes, the opposite of her claim.
- D: Library growth in other cities is irrelevant to who drove this city''s movement.', 'Find evidence that library hours and book choices matched workers'' needs rather than donors'' preferences.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ca0260b8-e214-468f-8d37-f9918730d11f', 'Which finding, if true, would most directly support Nair''s hypothesis that the wildflower blooms in response to snowmelt?', 'Ecologist Priya Nair proposes that a certain alpine wildflower times its blooming to the retreat of snow rather than to the calendar date, since snow cover varies widely from year to year. She reasons that if the flower tracks snowmelt, then in years when snow lingers late, blooming should be correspondingly delayed, and in years of early melt, blooming should advance. Nair intends to compare bloom dates and snowmelt timing across many seasons and elevations, looking for whether the two move together.', NULL, '[{"id":"A","text":"Across many seasons, bloom dates fell later in years of late snowmelt and earlier in years of early snowmelt.","is_correct":true,"explanation":"Bloom dates shifting in step with snowmelt timing is exactly the co-variation the hypothesis predicts."},{"id":"B","text":"The wildflower bloomed on nearly the same calendar date every year regardless of snow conditions.","is_correct":false,"explanation":"A fixed calendar date independent of snow contradicts the hypothesis that blooming tracks snowmelt."},{"id":"C","text":"The wildflower''s petals are a deeper blue at higher elevations than at lower ones.","is_correct":false,"explanation":"Petal color by elevation is true-but-irrelevant to bloom timing and snowmelt."},{"id":"D","text":"Pollinating insects visit the wildflower more often on sunny days than on cloudy days.","is_correct":false,"explanation":"Pollinator activity by weather says nothing about whether blooming tracks snowmelt."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
Nair reasons that if the flower tracks snowmelt, {{yellow:in years when snow lingers late, blooming should be correspondingly delayed, and in years of early melt, blooming should advance}}.
Step 2 — Match the finding
Bloom dates falling later after late snowmelt and earlier after early snowmelt is the predicted co-movement, supporting the hypothesis.
Distractor analysis:
- B: A fixed calendar date independent of snow directly contradicts the hypothesis.
- C: Petal color by elevation is irrelevant to timing.
- D: Pollinator activity by weather does not address snowmelt-driven blooming.', 'Look for bloom dates moving up or back in step with how early or late the snow melts.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('393c1e0c-a439-4356-adbf-11e4cc050e3f', 'Which finding, if true, would most directly support Reyes''s claim that a woman wrote the novel?', 'Literary scholar Daniel Reyes claims that an anonymous 18th-century novel was written by a woman, despite its publication under a man''s name. He argues that the novel devotes unusual attention to the legal and financial constraints faced by women of the period, detailing inheritance rules and marriage contracts with a precision he attributes to lived experience. Reyes maintains that if a woman wrote it, surviving evidence should connect the manuscript to a female author rather than to the man credited on the title page, and he searches archives for letters, contracts, and payment records.', NULL, '[{"id":"A","text":"A publisher''s payment ledger records the novel''s fee being paid to a woman who signed the receipt herself.","is_correct":true,"explanation":"A payment record tying the novel''s fee to a woman connects the manuscript to a female author, exactly the evidence Reyes seeks."},{"id":"B","text":"The novel sold more copies in its first year than most other novels published that decade.","is_correct":false,"explanation":"Sales figures are true-but-irrelevant to the author''s identity."},{"id":"C","text":"The man named on the title page had previously published two other successful novels.","is_correct":false,"explanation":"A track record for the credited man points away from a female author, weakening the claim."},{"id":"D","text":"Several novels of the era described inheritance law in similar detail.","is_correct":false,"explanation":"Similar detail elsewhere undercuts Reyes''s reasoning that the precision signals a female author."}]'::jsonb, 'A', 'Step 1 — Identify the test
Reyes maintains that if a woman wrote it, {{yellow:surviving evidence should connect the manuscript to a female author rather than to the man credited on the title page}}.
Step 2 — Match the finding
A payment ledger recording the fee paid to a woman who signed for it directly links the manuscript to a female author, supporting the claim.
Distractor analysis:
- B: Sales figures are irrelevant to authorship.
- C: A track record for the credited man points toward him, weakening the claim.
- D: Similar legal detail in other novels undercuts his precision-based reasoning.', 'Find archival evidence that ties the actual manuscript or payment to a woman.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('812e6ea9-8d6c-4f73-b4c4-f85005d78122', 'Which finding, if true, would most directly support Bello''s hypothesis as she has framed it?', 'Psychologist Aisha Bello hypothesizes that people remember a story better when they expect to retell it to someone than when they expect only to be tested on it. She reasons that anticipating an audience leads people to organize a story around its main events, and that this organization, not extra effort, is what aids memory. Bello plans to have two groups read the same story under different expectations, then measure not only how much each group recalls but also how their recollections are structured.', NULL, '[{"id":"A","text":"The group expecting to retell the story recalled it better and organized their accounts tightly around main events.","is_correct":true,"explanation":"Better recall combined with organization around main events matches Bello''s specific claim that audience-driven organization aids memory."},{"id":"B","text":"The group expecting to retell the story spent far more total time studying the passage.","is_correct":false,"explanation":"Extra study time points to effort, the explanation Bello explicitly sets aside."},{"id":"C","text":"Both groups recalled roughly the same number of details from the story.","is_correct":false,"explanation":"Equal recall contradicts the hypothesized memory advantage."},{"id":"D","text":"Participants who enjoyed the story rated it as more interesting afterward.","is_correct":false,"explanation":"Ratings of interest are true-but-irrelevant to the memory-and-organization claim."}]'::jsonb, 'A', 'Step 1 — Identify the mechanism
Bello argues that anticipating an audience leads people to organize a story around main events, and that {{yellow:this organization, not extra effort, is what aids memory}}.
Step 2 — Match the finding
The retell group recalling more and structuring accounts around main events shows organization accompanying better memory, supporting her framing.
Distractor analysis:
- B: More study time points to effort, the explanation she rules out.
- C: Equal recall contradicts the predicted memory advantage.
- D: Interest ratings are irrelevant to memory and organization.', 'The support must show both better memory and the organization-around-main-events mechanism she specifies.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7ded2958-f0d0-4d48-9050-74661ef10ea7', 'Which finding, if true, would most directly support Lind''s argument that the coastal villages traded with inland settlements?', 'Archaeologist Tomas Lind argues that a cluster of ancient coastal villages traded actively with distant inland settlements rather than living in isolation. He notes that the villages sit at the mouths of rivers that reach far inland. Lind reasons that if such trade occurred, the villages should contain materials that could only have come from inland regions, and inland sites should likewise hold coastal goods. He plans to analyze the origins of stone tools, pottery clay, and ornaments recovered from both the coastal villages and the inland settlements.', NULL, '[{"id":"A","text":"Tools made from a stone found only in inland quarries were recovered in the coastal villages, and seashell ornaments appeared at inland sites.","is_correct":true,"explanation":"Inland-only stone at the coast and coastal shells inland are exactly the two-way material exchange Lind predicts."},{"id":"B","text":"The coastal villages were larger and more populous than the inland settlements.","is_correct":false,"explanation":"Relative population size is true-but-irrelevant to whether trade occurred."},{"id":"C","text":"Every artifact found in the coastal villages was made from locally available materials.","is_correct":false,"explanation":"Purely local materials would indicate isolation, contradicting the trade argument."},{"id":"D","text":"The rivers near the villages were prone to seasonal flooding.","is_correct":false,"explanation":"River flooding says nothing about exchange of goods between regions."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
Lind reasons that if trade occurred, {{yellow:the villages should contain materials that could only have come from inland regions, and inland sites should likewise hold coastal goods}}.
Step 2 — Match the finding
Inland-only stone tools at the coast plus seashell ornaments inland is precisely the predicted two-way exchange of materials, supporting the argument.
Distractor analysis:
- B: Population size is irrelevant to whether trade happened.
- C: Entirely local materials indicate isolation, contradicting the claim.
- D: River flooding does not bear on inter-regional exchange.', 'Look for goods that crossed in both directions between coastal and inland sites.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('68846f81-30aa-4c88-ad59-55fa89c6eeb8', 'Which finding, if true, would most directly support Solis''s hypothesis that the songbirds learn their song from nearby older males?', 'Biologist Carmen Solis suspects that a species of songbird learns its complex song from older males nearby rather than inheriting it fully formed. She observes that birds in different valleys sing slightly different versions of the song, like regional dialects. Solis reasons that if young birds learn from neighbors, then a youngster raised among singers from a distant valley should grow up singing that valley''s version, not its parents'' version. She plans to raise some young birds among adults from a different valley and compare their adult songs with both groups.', NULL, '[{"id":"A","text":"Young birds raised among adults from a distant valley grew up singing that valley''s version rather than their parents'' version.","is_correct":true,"explanation":"Adopting the foster valley''s song instead of the parents'' version is exactly the learning outcome Solis predicts."},{"id":"B","text":"Young birds raised among distant-valley adults sang their parents'' version despite their surroundings.","is_correct":false,"explanation":"Singing the parents'' version regardless of surroundings supports inheritance, contradicting the hypothesis."},{"id":"C","text":"Adult males sing more frequently at dawn than at any other time of day.","is_correct":false,"explanation":"Time-of-day singing is true-but-irrelevant to how the song is acquired."},{"id":"D","text":"Females tend to nest in the same valley where they themselves hatched.","is_correct":false,"explanation":"Female nesting site fidelity does not address how males acquire their song."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
Solis reasons that if learning occurs, {{yellow:a youngster raised among singers from a distant valley should grow up singing that valley''s version, not its parents'' version}}.
Step 2 — Match the finding
Fostered birds singing the distant valley''s version rather than their parents'' version is precisely that predicted result, supporting learning.
Distractor analysis:
- B: Singing the parents'' version regardless supports inheritance, contradicting the hypothesis.
- C: Time-of-day singing is irrelevant to acquisition.
- D: Female nesting fidelity does not concern male song learning.', 'The supporting result is the fostered birds taking on the song of the valley where they were raised.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0558499f-7698-4c29-b748-64ca30c4144d', 'Which finding, if true, would most directly support Aoki''s contention that the weekly market drove the town''s prosperity?', 'Economic historian Grace Aoki contends that a medieval town''s prosperity came chiefly from its weekly market, which drew buyers and sellers from surrounding farms, rather than from a single wealthy noble''s estate. She points out that the town grew most rapidly in the decades after the market charter was granted. Aoki reasons that if the market drove growth, then the town''s wealth should be widely distributed among many merchant households, not concentrated in the noble''s holdings. She plans to study tax rolls, property records, and the timing of new construction.', NULL, '[{"id":"A","text":"Tax rolls show wealth spread across many independent merchant households whose holdings grew after the charter.","is_correct":true,"explanation":"Wealth distributed among many merchants, growing after the charter, matches Aoki''s prediction of widely shared prosperity from the market."},{"id":"B","text":"The noble''s estate held the great majority of the town''s taxable wealth throughout the period.","is_correct":false,"explanation":"Wealth concentrated in the noble''s holdings supports the estate explanation Aoki rejects."},{"id":"C","text":"The town''s market was held on the same day of the week as those in two neighboring towns.","is_correct":false,"explanation":"The market''s scheduling relative to neighbors is true-but-irrelevant to what drove prosperity."},{"id":"D","text":"The town''s defensive walls were rebuilt in stone during the same century.","is_correct":false,"explanation":"Wall construction does not indicate whether the market or the estate produced the wealth."}]'::jsonb, 'A', 'Step 1 — Identify the test
Aoki reasons that if the market drove growth, {{yellow:the town''s wealth should be widely distributed among many merchant households, not concentrated in the noble''s holdings}}.
Step 2 — Match the finding
Tax rolls showing wealth spread across many merchant households that grew after the charter is exactly that distributed prosperity, supporting the market explanation.
Distractor analysis:
- B: Wealth concentrated in the noble supports the estate explanation she rejects.
- C: The market''s scheduling versus neighbors is irrelevant.
- D: Rebuilding the walls does not distinguish market from estate as the wealth source.', 'Find evidence that wealth was shared among many merchants rather than held by the noble.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('56f5b5f7-4298-4cc7-b783-c735cb8f1299', 'Which finding, if true, would most directly support Cruz''s proposal that the tree''s rings reliably record past drought?', 'Climate scientist Mateo Cruz proposes that a particular tree species could serve as a reliable record of past drought because its growth rings narrow sharply in dry years. He reasons that if the rings truly track rainfall, then ring widths measured for recent decades should correspond closely to rainfall amounts already recorded by weather stations. Only if recent rings match known rainfall, Cruz argues, can older rings be trusted to reveal droughts from centuries before measurements began. He plans to compare ring widths with the modern rainfall record.', NULL, '[{"id":"A","text":"For recent decades, the trees'' ring widths matched the rainfall amounts recorded by weather stations year by year.","is_correct":true,"explanation":"Recent ring widths closely matching the measured rainfall record is exactly the validation Cruz says the proposal requires."},{"id":"B","text":"The trees can live for more than five hundred years, giving an unusually long record.","is_correct":false,"explanation":"Longevity affects record length but is true-but-irrelevant to whether rings track rainfall."},{"id":"C","text":"The trees'' ring widths showed no relationship to recorded rainfall in recent decades.","is_correct":false,"explanation":"No relationship to known rainfall contradicts the proposal that rings track drought."},{"id":"D","text":"The trees grow in soils that retain moisture longer than surrounding soils.","is_correct":false,"explanation":"Soil moisture retention does not show that ring widths reflect rainfall."}]'::jsonb, 'A', 'Step 1 — Identify the test
Cruz reasons that {{yellow:ring widths measured for recent decades should correspond closely to rainfall amounts already recorded by weather stations}}.
Step 2 — Match the finding
Recent ring widths matching the station rainfall record year by year is precisely that correspondence, validating the rings as a drought record.
Distractor analysis:
- B: Tree longevity affects record length, not whether rings track rainfall.
- C: No relationship to known rainfall directly contradicts the proposal.
- D: Soil moisture retention does not demonstrate that rings reflect rainfall.', 'The key test is whether recent rings line up with rainfall that was actually measured.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('06c33b73-d57c-46c5-ab2e-bab3743f8b01', 'Which finding, if true, would most directly support Khan''s argument that local shops fostered the neighborhood''s sense of community?', 'Sociologist Nadia Khan argues that a neighborhood''s strong sense of community grew out of its many small, locally owned shops, where residents met and talked daily, rather than out of any shared ethnic background. She observes that residents come from varied origins yet describe close ties. Khan reasons that if the shops fostered community, then ties should be strongest among residents who frequent the shops and weaker among those who rarely do, regardless of background. She plans to survey residents about their shopping habits and their connections to neighbors.', NULL, '[{"id":"A","text":"Residents who shopped at local stores daily reported the closest ties to neighbors, while infrequent shoppers reported the weakest, regardless of background.","is_correct":true,"explanation":"Ties strongest among frequent shoppers and weakest among rare ones, independent of background, is exactly Khan''s predicted pattern."},{"id":"B","text":"Residents who shared the same ethnic background reported the closest ties to one another.","is_correct":false,"explanation":"Ties tracking shared background supports the explanation Khan rejects."},{"id":"C","text":"The neighborhood''s local shops sold a wider variety of goods than chain stores elsewhere.","is_correct":false,"explanation":"The shops'' product variety is true-but-irrelevant to whether they built community."},{"id":"D","text":"Frequent and infrequent shoppers reported equally strong ties to their neighbors.","is_correct":false,"explanation":"Equal ties regardless of shopping habits contradict the predicted shop-based pattern."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
Khan reasons that if the shops fostered community, {{yellow:ties should be strongest among residents who frequent the shops and weaker among those who rarely do, regardless of background}}.
Step 2 — Match the finding
Daily shoppers reporting the closest ties and infrequent shoppers the weakest, independent of background, is exactly that pattern, supporting the argument.
Distractor analysis:
- B: Ties tracking shared ethnicity supports the explanation she rejects.
- C: The shops'' product variety is irrelevant to community building.
- D: Equal ties regardless of shopping habits contradict her prediction.', 'Look for ties that rise with shop visits and stay independent of shared background.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9865f0d5-d26b-4dac-86ef-e5caad6d5308', 'Which finding, if true, would most directly support Petrov''s hypothesis that the dinosaur was a fast runner?', 'Paleontologist Ivan Petrov hypothesizes that a small dinosaur was a fast runner rather than a slow forager. He notes that its leg bones are long and slender. Petrov reasons that if the animal ran quickly, its skeleton should show further features associated with speed in living animals, such as a long lower leg relative to the thigh and tendons arranged to store and release energy. He plans to compare the fossil''s limb proportions and muscle attachment points with those of fast and slow modern animals of similar size.', NULL, '[{"id":"A","text":"The fossil''s lower leg is long relative to its thigh, and its tendon attachment points match those of fast modern runners.","is_correct":true,"explanation":"A long lower leg and runner-like tendon attachments are precisely the speed features Petrov predicts a fast runner would show."},{"id":"B","text":"The dinosaur''s teeth were suited to grinding tough plant material.","is_correct":false,"explanation":"Grinding teeth suggest foraging diet, not running speed, and lean toward the forager explanation."},{"id":"C","text":"The fossil was found alongside the remains of several other dinosaur species.","is_correct":false,"explanation":"The other remains nearby are true-but-irrelevant to the animal''s running ability."},{"id":"D","text":"The dinosaur''s lower leg is short relative to its thigh, like that of slow modern animals.","is_correct":false,"explanation":"Short-lower-leg proportions resembling slow animals contradict the fast-runner hypothesis."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
Petrov reasons that a fast runner''s skeleton should show speed features {{yellow:such as a long lower leg relative to the thigh and tendons arranged to store and release energy}}.
Step 2 — Match the finding
A long lower leg and tendon attachments matching fast modern runners are exactly those predicted speed features, supporting the hypothesis.
Distractor analysis:
- B: Grinding teeth suggest foraging, leaning toward the explanation he rejects.
- C: Other remains found nearby are irrelevant to running ability.
- D: A short lower leg like slow animals contradicts the fast-runner claim.', 'Match the fossil features to the specific speed traits Petrov lists in modern fast animals.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c22c6905-35e4-4c4a-83db-4b46dde9d6b7', 'Which finding, if true, would most directly support Tan''s proposal that spacing produces more durable vocabulary learning?', 'Education researcher Olivia Tan proposes that students learn vocabulary more durably when they encounter each new word spaced across several days rather than all in one sitting, even when total study time is held equal. She reasons that if spacing aids durable learning, then students who study words over several days should remember more on a delayed test weeks later than students who studied the same words in a single block. Tan plans to assign two groups equal total study time, differing only in spacing, and test both after a delay.', NULL, '[{"id":"A","text":"On a test weeks later, students who had spread their study across several days remembered more words than those who studied in one block.","is_correct":true,"explanation":"Better delayed-test recall for the spaced group, with study time held equal, is exactly the durable-learning advantage Tan predicts."},{"id":"B","text":"Students who studied in a single block finished their session and felt more confident immediately afterward.","is_correct":false,"explanation":"Immediate confidence is true-but-irrelevant to durable learning measured weeks later."},{"id":"C","text":"Both groups remembered the same number of words on the delayed test.","is_correct":false,"explanation":"Equal delayed recall contradicts the predicted advantage of spacing."},{"id":"D","text":"Students generally preferred studying in a single block rather than across several days.","is_correct":false,"explanation":"Study preferences say nothing about which method produces more durable learning."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
Tan reasons that if spacing aids durable learning, {{yellow:students who study words over several days should remember more on a delayed test weeks later than students who studied the same words in a single block}}.
Step 2 — Match the finding
The spaced group remembering more words on the delayed test, with equal study time, is precisely that outcome, supporting the proposal.
Distractor analysis:
- B: Immediate confidence is irrelevant to durable learning weeks later.
- C: Equal delayed recall contradicts the predicted advantage.
- D: Study preferences do not show which method is more durable.', 'The support is the spaced group outperforming the block group on the delayed test.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7f27ee2e-0920-4f82-acd2-de83ed480f3c', 'Which finding, if true, would most directly support Voss''s argument about Okoro''s narrative choice?', 'In her 1979 novel, the writer Adaeze Okoro depicts the fictional coastal town of Brightwater entirely through the eyes of children, never allowing an adult narrator to intervene. Scholar Lina Voss argues that this choice was not merely stylistic but political: by restricting the narrative to a child''s limited understanding, Okoro forced readers to notice the gaps between what the children observe and what the adults around them are concealing, thereby exposing the town''s quiet complicity in injustice that an omniscient narrator might have stated too plainly.', NULL, '[{"id":"A","text":"Readers report that the children''s misunderstandings repeatedly hint at adult wrongdoing the children themselves cannot name, prompting readers to infer the town''s hidden injustice.","is_correct":true,"explanation":"Correct: readers inferring hidden injustice from the gaps between child observation and adult concealment is exactly what Voss claims the technique accomplishes."},{"id":"B","text":"Okoro''s later novels also feature coastal settings and were praised for their vivid descriptions of the sea.","is_correct":false,"explanation":"True-but-irrelevant: settings in other novels say nothing about the political effect of child narration in this novel."},{"id":"C","text":"Okoro stated in a letter that she found omniscient narrators easier to write than child narrators.","is_correct":false,"explanation":"Irrelevant to the claim: ease of writing does not bear on whether the child viewpoint exposed complicity to readers."},{"id":"D","text":"Most reviewers of the novel praised its plot while ignoring its narrative perspective entirely.","is_correct":false,"explanation":"Weakens rather than supports: if readers ignored the perspective, the political effect Voss describes did not register."}]'::jsonb, 'A', 'Step 1 — Locate the claim
Voss says the child viewpoint forced readers to {{yellow:notice the gaps between what the children observe and what the adults around them are concealing, thereby exposing the town''s quiet complicity in injustice}}.
Step 2 — Match the finding
Option A shows readers actually inferring hidden injustice from those gaps, directly confirming the claimed effect.
Distractor analysis:
- B: True-but-irrelevant; other novels'' settings do not test this novel''s political effect.
- C: Irrelevant; ease of writing has no bearing on reader inference.
- D: Reverses the claim; ignored perspective means the effect failed.', 'Look for evidence that readers actually inferred hidden injustice from what the children could not understand.', 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
