INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('81c30e17-7c49-4de7-94e4-53b5e8ae3a49', 'Which choice completes the text with the most logical transition?', 'The composer wrote the symphony quickly, finishing the entire score in just six weeks. Critics expected such a rushed work to feel unfinished or careless. ______ the symphony was praised for its remarkable polish and emotional depth.', NULL, '[{"id":"A","text":"Therefore,","is_correct":false,"explanation":"Implies the result matched expectations, but the outcome defied them."},{"id":"B","text":"Instead,","is_correct":true,"explanation":"Correctly contrasts the expected careless work with the actual polished, praised result."},{"id":"C","text":"Indeed,","is_correct":false,"explanation":"Emphasizes the prior idea, but the sentence reverses the expectation rather than confirming it."},{"id":"D","text":"For example,","is_correct":false,"explanation":"Introduces an illustration, yet the sentence overturns the critics'' expectation."}]'::jsonb, 'B', 'Step 1 — Find the relationship
The text says critics {{yellow:expected such a rushed work to feel unfinished or careless}}, and the final sentence reports the opposite result.
Step 2 — Match the transition
Because the actual praise contradicts what was expected, a contrast transition that signals the opposite outcome fits.
Distractor analysis:
- A: "Therefore" implies the result followed expectations, but it defied them.
- C: "Indeed" would confirm the expectation, yet the sentence reverses it.
- D: "For example" introduces an illustration, not a reversal of the expectation.', 'Compare what critics expected with what actually happened to the symphony.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
