INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('68df4be3-a24a-4ce1-9b1b-51d39865eff2', 'Which choice completes the text with the most logical transition?', 'Marine biologist Dr. Reyes spent years studying the migration of sea turtles along the Pacific coast. Her early observations suggested the turtles followed warm ocean currents. ______ later data revealed they also relied on Earth''s magnetic field to navigate.', NULL, '[{"id":"A","text":"However,","is_correct":true,"explanation":"Correct: it signals that the new data adds a surprising contrast to her early belief that currents alone guided the turtles."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Incorrect: the second finding does not result from the first observation; it qualifies it."},{"id":"C","text":"For example,","is_correct":false,"explanation":"Incorrect: magnetic-field navigation is not an example of following warm currents."},{"id":"D","text":"Likewise,","is_correct":false,"explanation":"Incorrect: ''Likewise'' signals similarity, but the sentence introduces a contrasting new factor."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The early observations {{yellow:suggested the turtles followed warm ocean currents}}, but the later data adds a different navigational factor.
Step 2 — Choose the transition
Because the new finding contrasts with and complicates the earlier conclusion, a contrast transition like ''However'' fits.
Distractor analysis:
- B: ''Therefore'' implies the second fact is caused by the first, which the text does not support.
- C: ''For example'' wrongly frames magnetic navigation as an instance of current-following.
- D: ''Likewise'' signals agreement, but the two findings differ rather than match.', 'Does the final sentence add a surprising new factor that complicates the earlier belief?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
