INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('32bba819-c9d3-4984-b786-3dca99369425', 'Which choice completes the text with the most logical transition?', 'For decades, doctors believed stomach ulcers were caused mainly by stress and spicy food. In the 1980s, two researchers discovered that a bacterium often triggered the ulcers instead. ______ the standard treatment shifted from bland diets to antibiotics.', NULL, '[{"id":"A","text":"Consequently,","is_correct":true,"explanation":"Correct: the change in treatment is the direct result of the new bacterial discovery."},{"id":"B","text":"Nonetheless,","is_correct":false,"explanation":"Incorrect: the treatment changed because of the discovery, not despite it."},{"id":"C","text":"Similarly,","is_correct":false,"explanation":"Incorrect: ''Similarly'' signals likeness, but this is a cause-and-effect shift."},{"id":"D","text":"For example,","is_correct":false,"explanation":"Incorrect: the new treatment is a consequence, not an example of the discovery."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
Researchers found that {{yellow:a bacterium often triggered the ulcers instead}}, which caused medicine to change its approach.
Step 2 — Choose the transition
Because the new treatment follows logically from the discovery, a cause-effect transition like ''Consequently'' fits.
Distractor analysis:
- B: ''Nonetheless'' implies the change happened in spite of the finding, reversing the logic.
- C: ''Similarly'' wrongly suggests two parallel ideas rather than a result.
- D: ''For example'' frames the treatment shift as an illustration, but it is an outcome.', 'Did the treatment change because of the bacterial discovery?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0d5b0a7a-024c-4dc4-840c-5d05541da0a2', 'Which choice completes the text with the most logical transition?', 'The Great Migration saw millions of African Americans move from the rural South to northern cities in the early twentieth century. Many sought factory jobs and an escape from harsh discrimination. ______ they often faced new forms of segregation in the North as well.', NULL, '[{"id":"A","text":"However,","is_correct":true,"explanation":"Correct: facing new segregation contrasts with the hope of escaping discrimination."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Incorrect: the northern segregation does not result from their motives for moving."},{"id":"C","text":"In addition,","is_correct":false,"explanation":"Incorrect: ''In addition'' merely adds; it misses the contrast between the goal and the outcome."},{"id":"D","text":"For example,","is_correct":false,"explanation":"Incorrect: northern segregation is not an example of seeking factory jobs."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The migrants sought {{yellow:an escape from harsh discrimination}}, yet the final sentence reveals they still met segregation up North.
Step 2 — Choose the transition
Because the outcome undercuts their goal, a contrast transition like ''However'' fits.
Distractor analysis:
- B: ''Therefore'' implies the segregation was caused by their search for work, which is unsupported.
- C: ''In addition'' adds information but ignores the ironic contrast.
- D: ''For example'' wrongly treats the segregation as an instance of job-seeking.', 'Does the final sentence undercut the hope of escaping discrimination?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0e219dde-ffef-463a-aa51-b806df64838b', 'Which choice completes the text with the most logical transition?', 'Solar panels convert sunlight directly into electricity using layers of silicon. Because they have no moving parts, they require very little maintenance. ______ they can keep generating power for twenty-five years or more.', NULL, '[{"id":"A","text":"As a result,","is_correct":true,"explanation":"Correct: the long lifespan follows from the panels having no moving parts and low maintenance."},{"id":"B","text":"Still,","is_correct":false,"explanation":"Incorrect: the long lifespan agrees with the low-maintenance point rather than contrasting it."},{"id":"C","text":"In contrast,","is_correct":false,"explanation":"Incorrect: there is no opposition; the durability is a consequence."},{"id":"D","text":"For instance,","is_correct":false,"explanation":"Incorrect: the lifespan is an effect of the design, not an example of low maintenance."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The panels {{yellow:require very little maintenance}}, which leads to their decades-long working life.
Step 2 — Choose the transition
Because the long lifespan is an outcome of the low-maintenance design, a cause-effect transition like ''As a result'' fits.
Distractor analysis:
- B: ''Still'' implies a concession or contrast that the sentences do not contain.
- C: ''In contrast'' wrongly signals opposition between consistent ideas.
- D: ''For instance'' frames the lifespan as an example rather than a result.', 'Is the long lifespan a consequence of having no moving parts?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
