INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fdc3e27d-90af-4c02-8c8a-0944d2021d28', 'Which choice completes the text with the most logical transition?', 'The city council proposed building a new bike lane along Main Street to reduce traffic. Supporters argued it would make commuting safer and cleaner. ______ some shop owners worried that removing parking spaces would drive away customers.', NULL, '[{"id":"A","text":"However,","is_correct":true,"explanation":"Correct: the shop owners'' concern opposes the supporters'' positive view of the plan."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Incorrect: the owners'' worry is not a consequence of the supporters'' argument."},{"id":"C","text":"Likewise,","is_correct":false,"explanation":"Incorrect: ''Likewise'' signals agreement, but the two groups disagree."},{"id":"D","text":"For example,","is_correct":false,"explanation":"Incorrect: the owners'' concern is not an example of the supporters'' reasoning."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
Supporters claimed the lane {{yellow:would make commuting safer and cleaner}}, while the shop owners voice an opposing worry.
Step 2 — Choose the transition
Because the two viewpoints conflict, a contrast transition like ''However'' fits.
Distractor analysis:
- B: ''Therefore'' implies the owners'' concern results from the supporters'' view, which is unsupported.
- C: ''Likewise'' wrongly signals that both sides agree.
- D: ''For example'' treats the disagreement as an illustration of the supporters'' claim.', 'Do the shop owners agree with or oppose the supporters?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
