INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('935e49ca-6207-4a0c-8365-a20058db6511', 'Which choice completes the text with the most logical transition?', 'The Atacama Desert in Chile is one of the driest places on Earth, with some weather stations having never recorded a single drop of rain. ______ a surprising variety of microbial life survives in its soil, drawing moisture from the thin coastal fog.', NULL, '[{"id":"A","text":"Nevertheless,","is_correct":true,"explanation":"Correct: it signals that life surviving contrasts with the expectation set by the extreme dryness."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Wrong: ''Therefore'' signals a result, but life surviving is not caused by the dryness."},{"id":"C","text":"For example,","is_correct":false,"explanation":"Wrong: the microbial life is not an example of the desert being dry."},{"id":"D","text":"Likewise,","is_correct":false,"explanation":"Wrong: ''Likewise'' signals similarity, but the two sentences contrast rather than match."}]'::jsonb, 'A', 'Step 1 — Spot the tension
The first sentence stresses extreme dryness, noting stations have {{yellow:never recorded a single drop of rain}}, yet the second says life survives there.
Step 2 — Choose the contrast
Because survival is unexpected given such dryness, a contrast word like ''Nevertheless'' fits.
Distractor analysis:
- B: ''Therefore'' marks a result, but dryness does not cause life to thrive.
- C: ''For example'' needs the second sentence to illustrate the first, which it does not.
- D: ''Likewise'' marks similarity, but the ideas oppose each other.', 'Does the second sentence agree with or push against the picture of total dryness?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d9e03284-0470-4afa-9f6d-89020e767227', 'Which choice completes the text with the most logical transition?', 'Honeybees communicate the location of food through a movement scientists call the waggle dance. The angle of the dance relative to the hive shows direction, while the duration of the waggle reveals distance. ______ a single dance can tell other bees exactly where to fly.', NULL, '[{"id":"A","text":"In contrast,","is_correct":false,"explanation":"Wrong: nothing in the final sentence opposes the prior information."},{"id":"B","text":"As a result,","is_correct":true,"explanation":"Correct: it presents the precise directions as the outcome of encoding direction and distance."},{"id":"C","text":"However,","is_correct":false,"explanation":"Wrong: ''However'' signals contrast, but the final sentence continues the same idea."},{"id":"D","text":"Meanwhile,","is_correct":false,"explanation":"Wrong: ''Meanwhile'' marks simultaneous events, not a consequence."}]'::jsonb, 'B', 'Step 1 — Identify what the dance encodes
The text explains the dance shows direction and {{yellow:the duration of the waggle reveals distance}}.
Step 2 — Choose the result
Because both direction and distance are conveyed, the bees knowing exactly where to fly is a consequence, so ''As a result'' fits.
Distractor analysis:
- A: ''In contrast'' needs opposing ideas, but the final sentence agrees.
- C: ''However'' marks contrast that is not present.
- D: ''Meanwhile'' marks simultaneous action, not a result.', 'Is the last sentence a consequence of the encoded information or a contrast to it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('00da07c2-4b7f-4743-82af-6de790417381', 'Which choice completes the text with the most logical transition?', 'In the nineteenth century, lighthouse keepers often lived in complete isolation for months at a time. They tended the lamp through every night and kept detailed logs of passing ships and storms. ______ many keepers kept gardens, raised animals, and taught themselves new skills to fill the long days.', NULL, '[{"id":"A","text":"By contrast,","is_correct":false,"explanation":"Wrong: the gardening sentence does not oppose the description of their duties."},{"id":"B","text":"In addition,","is_correct":true,"explanation":"Correct: it adds further activities to the list of what keepers did during their isolation."},{"id":"C","text":"Consequently,","is_correct":false,"explanation":"Wrong: gardening is not a direct result of tending the lamp or keeping logs."},{"id":"D","text":"Instead,","is_correct":false,"explanation":"Wrong: ''Instead'' replaces one idea with another, but these activities are added, not substituted."}]'::jsonb, 'B', 'Step 1 — Note the listed duties
The second sentence describes keepers who {{yellow:kept detailed logs of passing ships and storms}}, and the final sentence names still more activities.
Step 2 — Choose the additive transition
Because gardening and teaching themselves are extra things keepers did, ''In addition'' fits.
Distractor analysis:
- A: ''By contrast'' needs opposition, but the ideas accumulate.
- C: ''Consequently'' marks a result, but these are separate pastimes, not effects.
- D: ''Instead'' replaces the prior idea, but nothing is being replaced.', 'Are the new activities replacing the duties or piling on top of them?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fed04c54-2ec8-4049-9156-4a5f4ee033ec', 'Which choice completes the text with the most logical transition?', 'Some plants release chemical signals into the air when insects begin eating their leaves. These airborne signals warn neighboring plants of the threat. ______ the neighbors begin producing bitter compounds before any insect even reaches them.', NULL, '[{"id":"A","text":"In response,","is_correct":true,"explanation":"Correct: it shows the neighbors'' defensive reaction follows directly from receiving the warning."},{"id":"B","text":"Nonetheless,","is_correct":false,"explanation":"Wrong: ''Nonetheless'' marks contrast, but the neighbors act in line with the warning."},{"id":"C","text":"For instance,","is_correct":false,"explanation":"Wrong: the neighbors'' reaction is not an example of the warning signal."},{"id":"D","text":"In comparison,","is_correct":false,"explanation":"Wrong: nothing is being compared between two like things here."}]'::jsonb, 'A', 'Step 1 — Identify the warning
The text states the signals {{yellow:warn neighboring plants of the threat}}, and the final sentence describes what those neighbors then do.
Step 2 — Choose the reaction transition
Because the neighbors make bitter compounds after being warned, ''In response'' captures the cause-and-reaction link.
Distractor analysis:
- B: ''Nonetheless'' signals contrast, but the action follows logically.
- C: ''For instance'' needs an example, but a reaction is described.
- D: ''In comparison'' needs two compared items, which are absent.', 'What do the neighbors do after they receive the warning?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('49dfda3d-739c-4510-85d4-0349ba07d9aa', 'Which choice completes the text with the most logical transition?', 'Ancient Roman roads were engineered with multiple layers of stone, gravel, and sand to ensure durability. Builders also gave the surfaces a slight curve so that rainwater would drain off to the sides. ______ some of these roads remain usable nearly two thousand years after they were built.', NULL, '[{"id":"A","text":"Otherwise,","is_correct":false,"explanation":"Wrong: ''Otherwise'' introduces an alternative outcome, not the actual result described."},{"id":"B","text":"However,","is_correct":false,"explanation":"Wrong: the roads lasting agrees with their careful construction rather than contrasting it."},{"id":"C","text":"As a result,","is_correct":true,"explanation":"Correct: the roads'' long survival is the outcome of the durable layered construction."},{"id":"D","text":"Similarly,","is_correct":false,"explanation":"Wrong: the final sentence is a consequence, not a parallel comparison."}]'::jsonb, 'C', 'Step 1 — Identify the careful design
The text explains roads were built with {{yellow:multiple layers of stone, gravel, and sand to ensure durability}}.
Step 2 — Choose the result
Because durable building explains the roads still working, the consequence transition ''As a result'' fits.
Distractor analysis:
- A: ''Otherwise'' marks a hypothetical alternative, not the real outcome.
- B: ''However'' marks contrast, but durability and longevity agree.
- D: ''Similarly'' marks comparison, but a result is described.', 'Does the roads'' long life follow from the way they were built?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('496821ea-31db-44fc-9739-edf52a2f2316', 'Which choice completes the text with the most logical transition?', 'Many people assume that bats are blind, repeating the old phrase "blind as a bat." In fact, all bat species can see, and some have excellent vision. ______ certain fruit bats rely largely on their eyes rather than on echolocation to find food.', NULL, '[{"id":"A","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: the fruit bat sentence supports, rather than contrasts with, the claim that bats see."},{"id":"B","text":"For example,","is_correct":true,"explanation":"Correct: the fruit bats serve as a specific illustration that bats can see well."},{"id":"C","text":"On the other hand,","is_correct":false,"explanation":"Wrong: there is no opposing idea introduced by the final sentence."},{"id":"D","text":"Therefore,","is_correct":false,"explanation":"Wrong: the fruit bats are an example, not a conclusion drawn from the prior claim."}]'::jsonb, 'B', 'Step 1 — Identify the claim
The text corrects a myth, stating that {{yellow:all bat species can see, and some have excellent vision}}.
Step 2 — Choose the illustrative transition
Because fruit bats relying on their eyes is a concrete case proving that point, ''For example'' fits.
Distractor analysis:
- A: ''Nevertheless'' marks contrast, but the example agrees.
- C: ''On the other hand'' marks opposition that is absent.
- D: ''Therefore'' marks a conclusion, but a supporting example is given.', 'Is the last sentence proving the point or arguing against it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c7c1f3ea-8dcd-4e40-8806-d0e166a9ed89', 'Which choice completes the text with the most logical transition?', 'During the Great Depression, many families could no longer afford store-bought goods. To stretch their budgets, they mended worn clothing and reused materials whenever possible. ______ flour companies began printing their sacks in colorful patterns so the cloth could be sewn into dresses.', NULL, '[{"id":"A","text":"Recognizing this,","is_correct":true,"explanation":"Correct: it links the companies'' action to their awareness of families reusing materials."},{"id":"B","text":"In contrast,","is_correct":false,"explanation":"Wrong: the companies'' action supports the trend of reuse rather than opposing it."},{"id":"C","text":"Even so,","is_correct":false,"explanation":"Wrong: ''Even so'' signals a concession, but the final sentence flows naturally from the prior idea."},{"id":"D","text":"By coincidence,","is_correct":false,"explanation":"Wrong: the companies acted deliberately because of the reuse trend, not by chance."}]'::jsonb, 'A', 'Step 1 — Identify the behavior
The text says families {{yellow:reused materials whenever possible}}, and companies responded to that habit.
Step 2 — Choose the responsive transition
Because the companies acted with awareness of the reuse trend, ''Recognizing this'' connects the cause to their response.
Distractor analysis:
- B: ''In contrast'' needs opposition, but the action supports reuse.
- C: ''Even so'' signals concession that is not present.
- D: ''By coincidence'' implies chance, but the action was deliberate.', 'Did the companies print patterns because they knew people were reusing the sacks?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a4a7a100-1a44-4117-991c-c54f58b1cce9', 'Which choice completes the text with the most logical transition?', 'The painter Vincent van Gogh sold very few works during his lifetime and struggled with poverty. Today, his paintings are among the most valuable and beloved in the world. ______ his style, once dismissed by critics, is now studied in art schools everywhere.', NULL, '[{"id":"A","text":"Therefore,","is_correct":false,"explanation":"Wrong: his style being studied is not a result of his earlier poverty."},{"id":"B","text":"Conversely,","is_correct":false,"explanation":"Wrong: the final sentence reinforces his current fame rather than reversing it."},{"id":"C","text":"Indeed,","is_correct":true,"explanation":"Correct: it emphasizes and reinforces the point that his work is now highly esteemed."},{"id":"D","text":"Instead,","is_correct":false,"explanation":"Wrong: ''Instead'' replaces an idea, but the final sentence extends the previous one."}]'::jsonb, 'C', 'Step 1 — Identify the current view
The text says his paintings are now {{yellow:among the most valuable and beloved in the world}}, and the final sentence strengthens that point.
Step 2 — Choose the emphasizing transition
Because his once-dismissed style now being studied underscores his present acclaim, ''Indeed'' fits.
Distractor analysis:
- A: ''Therefore'' marks a result not caused by the prior sentence.
- B: ''Conversely'' marks reversal, but the idea is reinforced.
- D: ''Instead'' replaces an idea, but the sentence builds on the last one.', 'Does the last sentence reinforce his modern fame or flip it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d5b90c7f-918f-45d9-8943-96515e511c9a', 'Which choice completes the text with the most logical transition?', 'Coral reefs cover less than one percent of the ocean floor. Yet they provide shelter and food for roughly a quarter of all marine species. ______ scientists often call them the rainforests of the sea.', NULL, '[{"id":"A","text":"For this reason,","is_correct":true,"explanation":"Correct: the nickname follows from reefs supporting so much life despite their small size."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: the nickname agrees with the reefs'' richness rather than contrasting it."},{"id":"C","text":"In the meantime,","is_correct":false,"explanation":"Wrong: ''In the meantime'' marks a time gap, not a logical consequence."},{"id":"D","text":"Admittedly,","is_correct":false,"explanation":"Wrong: ''Admittedly'' concedes a point, but no concession is being made."}]'::jsonb, 'A', 'Step 1 — Identify the key fact
The text notes reefs support {{yellow:roughly a quarter of all marine species}} despite their tiny area.
Step 2 — Choose the causal transition
Because that richness explains the nickname, ''For this reason'' links the fact to the name.
Distractor analysis:
- B: ''Nevertheless'' marks contrast, but the nickname agrees with the richness.
- C: ''In the meantime'' marks time, not cause.
- D: ''Admittedly'' concedes a point, but none is conceded.', 'Why would scientists give reefs that nickname?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f3df05c4-9555-4e29-b642-05f2d2feb649', 'Which choice completes the text with the most logical transition?', 'For decades, astronomers believed the universe''s expansion must be slowing down because of gravity. Then, in the late 1990s, careful measurements of distant supernovae revealed something unexpected. ______ the expansion is actually speeding up over time.', NULL, '[{"id":"A","text":"Likewise,","is_correct":false,"explanation":"Wrong: ''Likewise'' signals agreement, but the finding overturns the prior belief."},{"id":"B","text":"In fact,","is_correct":true,"explanation":"Correct: it reveals the surprising truth that the measurements uncovered."},{"id":"C","text":"For example,","is_correct":false,"explanation":"Wrong: the speeding-up is the discovery itself, not an example of the measurements."},{"id":"D","text":"Therefore,","is_correct":false,"explanation":"Wrong: the result contradicts, rather than logically follows from, the old assumption."}]'::jsonb, 'B', 'Step 1 — Set up the surprise
The text says the measurements {{yellow:revealed something unexpected}}, then states what that was.
Step 2 — Choose the revealing transition
Because the final sentence delivers the surprising truth, ''In fact'' introduces it well.
Distractor analysis:
- A: ''Likewise'' marks agreement, but the finding reverses the old belief.
- C: ''For example'' needs an illustration, but this is the discovery itself.
- D: ''Therefore'' marks a logical result, but the finding contradicts the assumption.', 'The last sentence delivers the unexpected truth the measurements showed.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('65d32e7f-4dc9-4d0b-934d-6d418d1877b0', 'Which choice completes the text with the most logical transition?', 'Octopuses can change the color and texture of their skin almost instantly. They use this ability to blend into rocks, coral, and sand to avoid predators. ______ some species can also flash bright warning colors to startle an attacker.', NULL, '[{"id":"A","text":"As a result,","is_correct":false,"explanation":"Wrong: flashing warning colors is another use of the skill, not a consequence of camouflage."},{"id":"B","text":"In contrast,","is_correct":false,"explanation":"Wrong: while warning differs from hiding, the sentence chiefly adds a further use rather than opposing the prior one."},{"id":"C","text":"Furthermore,","is_correct":true,"explanation":"Correct: it adds a second use of the color-changing ability to the one already described."},{"id":"D","text":"In conclusion,","is_correct":false,"explanation":"Wrong: ''In conclusion'' signals a summary, but the sentence introduces new information."}]'::jsonb, 'C', 'Step 1 — Identify the first use
The text describes octopuses using color change to {{yellow:blend into rocks, coral, and sand to avoid predators}}.
Step 2 — Choose the additive transition
Because flashing warning colors is a further use of the same ability, ''Furthermore'' adds it.
Distractor analysis:
- A: ''As a result'' marks a consequence, but this is an added ability, not an effect.
- B: ''In contrast'' overstates the opposition; the sentence mainly adds a use.
- D: ''In conclusion'' marks a summary, but new information appears.', 'Is the warning-color sentence a new added use or a result of camouflage?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('568f2679-0dbe-4a0d-bccf-9899668ff22c', 'Which choice completes the text with the most logical transition?', 'The ancient city of Pompeii was buried under volcanic ash when Mount Vesuvius erupted in 79 CE. The ash sealed the city off from air and moisture for centuries. ______ buildings, frescoes, and even loaves of bread were preserved in remarkable detail.', NULL, '[{"id":"A","text":"Thus,","is_correct":true,"explanation":"Correct: the preservation is the direct outcome of the ash sealing the city from air and moisture."},{"id":"B","text":"Still,","is_correct":false,"explanation":"Wrong: ''Still'' signals contrast, but preservation follows naturally from the sealing."},{"id":"C","text":"For example,","is_correct":false,"explanation":"Wrong: the preserved items are a result of the sealing, not an example of it."},{"id":"D","text":"Meanwhile,","is_correct":false,"explanation":"Wrong: ''Meanwhile'' marks simultaneous events, not a consequence."}]'::jsonb, 'A', 'Step 1 — Identify the cause
The text says the ash {{yellow:sealed the city off from air and moisture for centuries}}.
Step 2 — Choose the result
Because that sealing explains why objects survived intact, the consequence transition ''Thus'' fits.
Distractor analysis:
- B: ''Still'' marks contrast, but preservation agrees with the sealing.
- C: ''For example'' needs an illustration, but a result is described.
- D: ''Meanwhile'' marks simultaneous time, not cause.', 'Did the sealing cause the remarkable preservation?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d6c3dd81-e595-497e-a1ce-948081ad81ed', 'Which choice completes the text with the most logical transition?', 'Many gardeners assume that all bees they see hovering near flowers belong to a single hive of honeybees. In reality, North America is home to thousands of native bee species, most of which live alone rather than in colonies. ______ a single backyard may host dozens of distinct kinds of bee, even though they all look superficially similar.', NULL, '[{"id":"A","text":"Consequently,","is_correct":true,"explanation":"Correct: the wide variety of solitary native species logically leads to the conclusion that one yard can host many distinct kinds."},{"id":"B","text":"However,","is_correct":false,"explanation":"Wrong: ''However'' signals contrast, but the final sentence extends rather than opposes the prior point."},{"id":"C","text":"For instance,","is_correct":false,"explanation":"Wrong: the final sentence states a result, not a specific example of a stated category."},{"id":"D","text":"In contrast,","is_correct":false,"explanation":"Wrong: nothing in the final sentence contrasts with the diversity just described."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The text establishes that {{yellow:North America is home to thousands of native bee species, most of which live alone rather than in colonies}}.
Step 2 — Match the transition
Because so many solitary species exist, it logically follows that one yard hosts many kinds, so a cause-effect transition fits.
Distractor analysis:
- B: ''However'' signals contrast, but the last sentence continues the idea rather than opposing it.
- C: ''For instance'' would introduce an example, yet the sentence states a consequence, not an instance of a category.
- D: ''In contrast'' is a reversal that the content does not support.', 'Does the last sentence draw a result from the diversity described, or push against it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('23c7064d-f088-4be7-a4c7-7c9f621c9696', 'Which choice completes the text with the most logical transition?', 'Early film studios believed that audiences would never accept color movies, fearing the bright hues would distract from the story. Test screenings in the 1930s revealed the opposite reaction: viewers found color more immersive, not less. ______ studios that had resisted the technology began racing to adopt it within a few years.', NULL, '[{"id":"A","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: ''Nevertheless'' marks concession, but the studios'' rush follows naturally from the positive test results."},{"id":"B","text":"As a result,","is_correct":true,"explanation":"Correct: the favorable audience reaction directly caused studios to adopt color quickly."},{"id":"C","text":"Similarly,","is_correct":false,"explanation":"Wrong: ''Similarly'' adds a parallel point, but this sentence reports an outcome, not a comparison."},{"id":"D","text":"In contrast,","is_correct":false,"explanation":"Wrong: the studios'' behavior matches the favorable findings rather than contrasting with them."}]'::jsonb, 'B', 'Step 1 — Identify the relationship
The screenings showed that {{yellow:viewers found color more immersive, not less}}.
Step 2 — Match the transition
That positive evidence caused resistant studios to adopt the technology, so a cause-effect transition is needed.
Distractor analysis:
- A: ''Nevertheless'' implies the outcome defied expectation, but adopting color logically follows from the good results.
- C: ''Similarly'' would link two parallel ideas, yet here the final sentence is a consequence.
- D: ''In contrast'' wrongly suggests opposition between the findings and the studios'' response.', 'The last sentence reports what studios did because of the test results.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6081d231-fe7b-4914-91b2-1ebdd9149003', 'Which choice completes the text with the most logical transition?', 'Historians once treated the diaries of ordinary soldiers as unreliable footnotes to official military records. Recent scholarship argues that these personal accounts capture details, such as morale and daily hardship, that formal reports omit entirely. ______ many researchers now consult soldiers'' diaries alongside, rather than beneath, government documents.', NULL, '[{"id":"A","text":"For example,","is_correct":false,"explanation":"Wrong: the final sentence is a result of the reassessment, not an example of it."},{"id":"B","text":"Still,","is_correct":false,"explanation":"Wrong: ''Still'' signals contrast, but researchers'' new practice agrees with the new scholarship."},{"id":"C","text":"Therefore,","is_correct":true,"explanation":"Correct: because diaries are now valued for unique detail, researchers logically treat them as equal sources."},{"id":"D","text":"Meanwhile,","is_correct":false,"explanation":"Wrong: ''Meanwhile'' marks simultaneity, but the relationship here is cause and effect."}]'::jsonb, 'C', 'Step 1 — Identify the relationship
New scholarship shows diaries {{yellow:capture details, such as morale and daily hardship, that formal reports omit entirely}}.
Step 2 — Match the transition
Because diaries offer unique value, researchers now treat them as equal sources, which is a logical result.
Distractor analysis:
- A: ''For example'' would introduce an instance, but the sentence states a consequence.
- B: ''Still'' implies contrast, yet the new practice aligns with the new view.
- D: ''Meanwhile'' suggests a parallel event in time, not the causal link present here.', 'Researchers changed their habits because of what scholarship revealed.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4c69191e-7f86-4fa9-8aa0-4430f71281d2', 'Which choice completes the text with the most logical transition?', 'Desert plants face a constant trade-off: opening their pores to absorb carbon dioxide also lets precious water escape. Some cacti solve this by opening their pores only at night, when the cooler air slows evaporation. ______ they can gather the carbon they need while losing far less moisture than daytime plants do.', NULL, '[{"id":"A","text":"In this way,","is_correct":true,"explanation":"Correct: the final sentence explains the result achieved by the night-opening method just described."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: the outcome supports the strategy rather than running counter to it."},{"id":"C","text":"By contrast,","is_correct":false,"explanation":"Wrong: nothing is being contrasted; the sentence describes how the method pays off."},{"id":"D","text":"Admittedly,","is_correct":false,"explanation":"Wrong: ''Admittedly'' concedes a drawback, but the sentence states a benefit."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The cacti {{yellow:open their pores only at night, when the cooler air slows evaporation}}.
Step 2 — Match the transition
The final sentence explains the favorable outcome of that method, so a manner/result transition fits.
Distractor analysis:
- B: ''Nevertheless'' implies the outcome defies the strategy, but it confirms it.
- C: ''By contrast'' would set up an opposition that the text lacks.
- D: ''Admittedly'' concedes a weakness, yet the sentence describes a benefit.', 'The last sentence tells how the night strategy succeeds.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('398085ab-cf3f-4308-a738-ab4144e3132e', 'Which choice completes the text with the most logical transition?', 'The novelist drafted her chapters out of order, writing whichever scene most interested her on a given day. Critics expected the finished book to feel disjointed and hard to follow. ______ readers praised the novel for its seamless flow, unaware of the scattered way it had been composed.', NULL, '[{"id":"A","text":"Therefore,","is_correct":false,"explanation":"Wrong: praise for flow is the opposite of what the critics'' expectation would cause."},{"id":"B","text":"Likewise,","is_correct":false,"explanation":"Wrong: ''Likewise'' adds agreement, but the readers'' reaction opposes the prediction."},{"id":"C","text":"Instead,","is_correct":true,"explanation":"Correct: readers'' praise replaces and contradicts the expected disjointedness."},{"id":"D","text":"Indeed,","is_correct":false,"explanation":"Wrong: ''Indeed'' confirms the prior claim, but the result reverses it."}]'::jsonb, 'C', 'Step 1 — Identify the relationship
Critics expected the book {{yellow:to feel disjointed and hard to follow}}.
Step 2 — Match the transition
Readers instead praised its flow, so a reversal transition that substitutes the opposite outcome is required.
Distractor analysis:
- A: ''Therefore'' would make the praise a result of the expectation, but it contradicts it.
- B: ''Likewise'' signals similarity, yet the outcome is opposite.
- D: ''Indeed'' intensifies a prior point, but the sentence overturns the prediction.', 'The actual reaction is the reverse of what critics predicted.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ffd2aabd-7d5d-4fd5-a3ed-4271ba4c13cb', 'Which choice completes the text with the most logical transition?', 'City planners often assume that adding more lanes to a congested highway will ease traffic. Studies of expanded roads show a puzzling pattern instead: wider highways tend to attract additional drivers until congestion returns to its former level. ______ the very improvement meant to reduce delays can end up encouraging the behavior that causes them.', NULL, '[{"id":"A","text":"In other words,","is_correct":true,"explanation":"Correct: the final sentence restates the puzzling pattern in plainer terms."},{"id":"B","text":"However,","is_correct":false,"explanation":"Wrong: the sentence clarifies the prior point rather than opposing it."},{"id":"C","text":"For example,","is_correct":false,"explanation":"Wrong: it summarizes the pattern, not gives a specific instance of it."},{"id":"D","text":"Earlier,","is_correct":false,"explanation":"Wrong: ''Earlier'' marks time sequence, which the relationship does not involve."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
Studies show {{yellow:wider highways tend to attract additional drivers until congestion returns to its former level}}.
Step 2 — Match the transition
The final sentence restates that idea in simpler language, so a restatement transition fits.
Distractor analysis:
- B: ''However'' implies contrast, but the sentence rephrases the prior claim.
- C: ''For example'' would give an instance, yet this is a summary of the whole pattern.
- D: ''Earlier'' indicates sequence in time, irrelevant here.', 'The last sentence says the same idea again, more plainly.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4b2464e0-bc07-40eb-b558-3a9b9c1e2bd7', 'Which choice completes the text with the most logical transition?', 'Volcanic eruptions are usually associated with destruction, burying land under ash and lava. Over centuries, however, that same volcanic ash breaks down into some of the most fertile soil on Earth. ______ regions near active volcanoes often support unusually productive farms despite the obvious dangers.', NULL, '[{"id":"A","text":"Nonetheless,","is_correct":false,"explanation":"Wrong: the productive farms follow logically from the fertile soil, not against it."},{"id":"B","text":"For this reason,","is_correct":true,"explanation":"Correct: fertile volcanic soil is the cause of the productive farms near volcanoes."},{"id":"C","text":"In contrast,","is_correct":false,"explanation":"Wrong: the farms align with the soil fertility rather than contrasting with it."},{"id":"D","text":"Granted,","is_correct":false,"explanation":"Wrong: ''Granted'' concedes a point, but the sentence states a consequence."}]'::jsonb, 'B', 'Step 1 — Identify the relationship
The text explains that volcanic ash {{yellow:breaks down into some of the most fertile soil on Earth}}.
Step 2 — Match the transition
That fertility causes the productive farms near volcanoes, so a cause-effect transition fits.
Distractor analysis:
- A: ''Nonetheless'' implies the farms defy the soil, but they result from it.
- C: ''In contrast'' wrongly suggests opposition.
- D: ''Granted'' concedes, yet the sentence states an effect.', 'Why would farms near volcanoes be productive? The fertile soil is the cause.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7124650c-9344-4e64-8e74-63f111ae9bf5', 'Which choice completes the text with the most logical transition?', 'When researchers introduced wolves back into a national park, they expected the predators to affect only the deer population. The wolves did reduce deer numbers, but the changes rippled much further than anyone predicted. ______ riverbanks once stripped bare by grazing deer grew lush with returning vegetation, altering the very course of the streams.', NULL, '[{"id":"A","text":"By contrast,","is_correct":false,"explanation":"Wrong: the riverbank change is an example of the wider rippling, not a contrast."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: the lush growth supports the claim of far-reaching effects rather than opposing it."},{"id":"C","text":"For example,","is_correct":true,"explanation":"Correct: the riverbank transformation is a concrete instance of the wider ripple just mentioned."},{"id":"D","text":"Therefore,","is_correct":false,"explanation":"Wrong: the sentence illustrates the claim rather than drawing a conclusion from it."}]'::jsonb, 'C', 'Step 1 — Identify the relationship
The text says the changes {{yellow:rippled much further than anyone predicted}}.
Step 2 — Match the transition
The final sentence gives a specific instance of those far-reaching effects, so an example transition fits.
Distractor analysis:
- A: ''By contrast'' implies opposition, but the riverbank case supports the claim.
- B: ''Nevertheless'' marks concession the text does not need.
- D: ''Therefore'' would draw a conclusion, but the sentence supplies an illustration.', 'The last sentence gives one concrete case of the ''further ripples.''', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9dad9427-1775-47b1-b563-e285964cc9b1', 'Which choice completes the text with the most logical transition?', 'Ancient Roman engineers built roads designed primarily to move soldiers quickly across the empire. These same roads, however, also let merchants, ideas, and even diseases travel farther than ever before. ______ a network created for military control became one of the great engines of cultural exchange.', NULL, '[{"id":"A","text":"Thus,","is_correct":true,"explanation":"Correct: the broad movement of people and ideas leads to the conclusion that the roads enabled cultural exchange."},{"id":"B","text":"Otherwise,","is_correct":false,"explanation":"Wrong: ''Otherwise'' describes an alternative scenario, not the actual outcome."},{"id":"C","text":"In contrast,","is_correct":false,"explanation":"Wrong: the conclusion follows from the prior sentence rather than opposing it."},{"id":"D","text":"Specifically,","is_correct":false,"explanation":"Wrong: the sentence broadens to a general conclusion rather than narrowing to a detail."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The roads let {{yellow:merchants, ideas, and even diseases travel farther than ever before}}.
Step 2 — Match the transition
That wide movement leads to the conclusion that a military network became a cultural engine, so a result transition fits.
Distractor analysis:
- B: ''Otherwise'' introduces a hypothetical alternative, not the real result.
- C: ''In contrast'' wrongly signals opposition.
- D: ''Specifically'' would add a precise detail, but the sentence draws a general conclusion.', 'The final sentence sums up the consequence of all that travel.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5ad2e34c-6f34-478d-ab88-710b643a5a97', 'Which choice completes the text with the most logical transition?', 'Composer Clara Schumann performed across Europe for decades and was celebrated as one of the finest pianists of her era. Yet her own compositions were rarely published during her lifetime, dismissed by some who doubted a woman could write serious music. ______ modern scholars increasingly rank her works among the most inventive of the Romantic period.', NULL, '[{"id":"A","text":"Consequently,","is_correct":false,"explanation":"Wrong: the modern praise reverses the old dismissal rather than resulting from it."},{"id":"B","text":"Today,","is_correct":true,"explanation":"Correct: ''Today'' sets the modern reassessment against the lifetime dismissal, marking the contrast in time."},{"id":"C","text":"Indeed,","is_correct":false,"explanation":"Wrong: ''Indeed'' would confirm the dismissal, but the sentence overturns it."},{"id":"D","text":"Likewise,","is_correct":false,"explanation":"Wrong: ''Likewise'' adds agreement, yet modern scholars disagree with the old judgment."}]'::jsonb, 'B', 'Step 1 — Identify the relationship
In her lifetime her works were {{yellow:dismissed by some who doubted a woman could write serious music}}.
Step 2 — Match the transition
The final sentence describes a present-day reversal of that judgment, so a time-contrast transition like ''Today'' fits.
Distractor analysis:
- A: ''Consequently'' would make the praise a result of the dismissal, which is illogical.
- C: ''Indeed'' confirms the prior idea, but the sentence contradicts it.
- D: ''Likewise'' signals similarity, yet the views oppose each other.', 'The last sentence contrasts the present judgment with the lifetime one.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('13984c70-60d9-4265-949c-8b920c9f8245', 'Which choice completes the text with the most logical transition?', 'Most people picture octopuses as solitary creatures that avoid one another entirely. Observations at certain crowded sites off the Australian coast have complicated that picture, revealing octopuses that signal, chase, and even share dens. ______ the long-held image of the lone octopus may apply far less universally than biologists once thought.', NULL, '[{"id":"A","text":"In fact,","is_correct":true,"explanation":"Correct: ''In fact'' presents the surprising conclusion that the lone-octopus image is less universal, strengthening the prior point."},{"id":"B","text":"For instance,","is_correct":false,"explanation":"Wrong: the sentence draws a broad conclusion rather than giving an example."},{"id":"C","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: the conclusion agrees with the observations rather than opposing them."},{"id":"D","text":"Meanwhile,","is_correct":false,"explanation":"Wrong: ''Meanwhile'' marks simultaneous events, not the inferential link present here."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
Observers found {{yellow:octopuses that signal, chase, and even share dens}}.
Step 2 — Match the transition
The final sentence advances a stronger conclusion drawn from that evidence, so an intensifying transition like ''In fact'' fits.
Distractor analysis:
- B: ''For instance'' would add an example, but the sentence states a conclusion.
- C: ''Nevertheless'' implies contrast that the agreement does not support.
- D: ''Meanwhile'' signals concurrent timing, not inference.', 'The last sentence pushes the surprising finding to its broader conclusion.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1742fae6-4c3c-423c-9306-6e03cd623aca', 'Which choice completes the text with the most logical transition?', 'The town council assumed that lowering the speed limit downtown would frustrate drivers and hurt local shops. After the change, however, more pedestrians felt safe enough to stroll and browse the streets. ______ several store owners reported their busiest season in years.', NULL, '[{"id":"A","text":"Nonetheless,","is_correct":false,"explanation":"Wrong: the busy season follows from more pedestrians, not against it."},{"id":"B","text":"In contrast,","is_correct":false,"explanation":"Wrong: the sales boost aligns with the increase in pedestrians rather than contrasting."},{"id":"C","text":"As a result,","is_correct":true,"explanation":"Correct: more strolling pedestrians directly caused the store owners'' booming sales."},{"id":"D","text":"Even so,","is_correct":false,"explanation":"Wrong: ''Even so'' concedes against expectation, but the sales result flows naturally from the foot traffic."}]'::jsonb, 'C', 'Step 1 — Identify the relationship
After the change, {{yellow:more pedestrians felt safe enough to stroll and browse the streets}}.
Step 2 — Match the transition
Those extra browsing pedestrians caused the busy season, so a cause-effect transition is needed.
Distractor analysis:
- A: ''Nonetheless'' implies the sales defied the foot traffic, but they resulted from it.
- B: ''In contrast'' wrongly signals opposition.
- D: ''Even so'' concedes against expectation, yet the outcome follows logically from more pedestrians.', 'Busy shops are the direct result of more people walking by.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('5d5b0410-9587-4c29-9933-96ec292db7a1', 'Which choice completes the text with the most logical transition?', 'Marine biologists once assumed that deep-sea creatures lived in near-total isolation, rarely interacting across vast stretches of ocean floor. Recent tracking studies, ______ have revealed that some species migrate thousands of miles to gather at the same underwater ridges each year.', NULL, '[{"id":"A","text":"however,","is_correct":true,"explanation":"Correct: it signals the contrast between the old assumption of isolation and the new finding of long migrations."},{"id":"B","text":"therefore,","is_correct":false,"explanation":"Incorrect: the new studies do not result from the old assumption; they overturn it."},{"id":"C","text":"likewise,","is_correct":false,"explanation":"Incorrect: the second sentence contradicts rather than parallels the first."},{"id":"D","text":"for instance,","is_correct":false,"explanation":"Incorrect: the studies are not an example of isolation; they disprove it."}]'::jsonb, 'A', 'Step 1 — Spot the reversal
The first sentence says creatures live in {{yellow:near-total isolation, rarely interacting}}, but the second reports long migrations to shared ridges.
Step 2 — Match the contrast
Because the new evidence overturns the old assumption, a contrast transition like ''however'' is needed.
Distractor analysis:
- B: ''therefore'' implies the studies follow from the assumption, but they refute it.
- C: ''likewise'' signals agreement, yet the ideas oppose each other.
- D: ''for instance'' would introduce an example of isolation, which the sentence does not provide.', 'Does the second sentence agree with or contradict the old assumption?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('550e1e9a-c348-4a08-b787-593a8eece08e', 'Which choice completes the text with the most logical transition?', 'The new public library was designed to serve every neighborhood, with bus routes planned to reach its doors from across the city. The transit budget was cut before construction finished, ______ leaving residents in outer districts with no direct way to get there.', NULL, '[{"id":"A","text":"for example,","is_correct":false,"explanation":"Incorrect: the budget cut is not an example of the library''s inclusive design."},{"id":"B","text":"however,","is_correct":true,"explanation":"Correct: it contrasts the inclusive intent with the outcome that excluded outer districts."},{"id":"C","text":"in addition,","is_correct":false,"explanation":"Incorrect: nothing in the first sentence is being added to; the result undercuts the plan."},{"id":"D","text":"as a result,","is_correct":false,"explanation":"Incorrect: the cut did not result from the inclusive design goal."}]'::jsonb, 'B', 'Step 1 — Find the tension
The plan aimed to {{yellow:serve every neighborhood}}, but the cut left outer residents stranded.
Step 2 — Choose contrast
The outcome defeats the stated intent, so a contrast word like ''however'' fits.
Distractor analysis:
- A: ''for example'' would illustrate the design goal, but the cut contradicts it.
- C: ''in addition'' implies a supporting point, yet the second idea undermines the first.
- D: ''as a result'' wrongly makes the cut a consequence of the inclusive plan.', 'Did the result fulfill the design goal or work against it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3ec3f859-dab4-44b3-aa6b-104eccc55a80', 'Which choice completes the text with the most logical transition?', 'Economists noticed that the small town''s bakeries all raised their prices within the same week. None of the owners had spoken to one another; ______ each had simply responded to the same jump in the cost of flour.', NULL, '[{"id":"A","text":"nevertheless,","is_correct":false,"explanation":"Incorrect: the second clause explains the coincidence rather than opposing it."},{"id":"B","text":"instead,","is_correct":true,"explanation":"Correct: it replaces the idea of collusion with the real cause, a shared cost increase."},{"id":"C","text":"similarly,","is_correct":false,"explanation":"Incorrect: the clause does not add a parallel point; it corrects an implied explanation."},{"id":"D","text":"therefore,","is_correct":false,"explanation":"Incorrect: responding to flour costs is not a consequence of not speaking."}]'::jsonb, 'B', 'Step 1 — Identify the rejected idea
The text stresses that {{yellow:None of the owners had spoken to one another}}, hinting collusion is ruled out.
Step 2 — Supply the replacement
''Instead'' swaps the ruled-out explanation for the true one: a shared cost spike.
Distractor analysis:
- A: ''nevertheless'' signals contrast, but the clause completes, not opposes, the thought.
- C: ''similarly'' adds a parallel, yet the clause offers a correction.
- D: ''therefore'' implies causation that the sentences do not support.', 'Is the second clause adding a reason or replacing a wrong one?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ff87c07c-04da-4a24-8cc0-aa75487bc445', 'Which choice completes the text with the most logical transition?', 'Early radio engineers believed that broadcasts could not travel far beyond the horizon because radio waves moved in straight lines. Operators kept receiving signals from stations hundreds of miles away, ______ a puzzle that pointed to an unseen layer of the atmosphere reflecting the waves back to earth.', NULL, '[{"id":"A","text":"yet they kept receiving","is_correct":false,"explanation":"Incorrect: this rewrites the sentence and does not function as a transition phrase in the blank."},{"id":"B","text":"in short,","is_correct":false,"explanation":"Incorrect: the clause introduces new, surprising data rather than summarizing."},{"id":"C","text":"nonetheless,","is_correct":true,"explanation":"Correct: it marks that the far-off signals occurred despite the straight-line prediction."},{"id":"D","text":"consequently,","is_correct":false,"explanation":"Incorrect: receiving distant signals is not a consequence of waves moving in straight lines."}]'::jsonb, 'C', 'Step 1 — Locate the expectation
Engineers expected signals could not travel far because waves {{yellow:moved in straight lines}}.
Step 2 — Signal the surprise
Distant signals defied that expectation, so a concessive contrast like ''nonetheless'' fits.
Distractor analysis:
- A: it is not a standalone transition and breaks the sentence structure.
- B: ''in short'' summarizes, but the clause adds surprising new evidence.
- D: ''consequently'' implies the distant signals followed from straight-line travel, the opposite of the puzzle.', 'Did the distant signals match or defy the straight-line prediction?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d49c206d-8929-4edc-a4e4-3de5d2898f1d', 'Which choice completes the text with the most logical transition?', 'The committee assumed that lowering the entry fee would draw larger crowds to the museum. Attendance did climb after the change, ______ but the lost revenue from each ticket left the museum with less money than before.', NULL, '[{"id":"A","text":"indeed,","is_correct":false,"explanation":"Incorrect: the clause introduces a drawback, not an emphatic confirmation."},{"id":"B","text":"and yet","is_correct":true,"explanation":"Correct: it concedes the rise in attendance while contrasting it with the revenue loss."},{"id":"C","text":"because","is_correct":false,"explanation":"Incorrect: the revenue loss is not the cause of rising attendance."},{"id":"D","text":"in particular,","is_correct":false,"explanation":"Incorrect: the clause does not narrow to a specific case of higher attendance."}]'::jsonb, 'B', 'Step 1 — Note the partial success
The text confirms {{yellow:Attendance did climb after the change}}, but then flags a financial downside.
Step 2 — Pick the concession-contrast
''And yet'' acknowledges the gain while pivoting to the loss, matching the sentence''s tension.
Distractor analysis:
- A: ''indeed'' would intensify the attendance gain, but the clause reveals a problem.
- C: ''because'' wrongly makes lost revenue the reason for higher attendance.
- D: ''in particular'' signals a specific instance, which the clause does not give.', 'The crowd grew, but the money shrank. What links a gain to a setback?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3d7e0ce3-fed4-49d5-a309-bf5881d0ecfb', 'Which choice completes the text with the most logical transition?', 'Historians long credited a single inventor with the spinning jenny that transformed textile work. Recent archival research, ______ shows that several artisans in nearby villages had built nearly identical machines at the same time.', NULL, '[{"id":"A","text":"in fact,","is_correct":true,"explanation":"Correct: it presents a stronger, corrective truth that revises the single-inventor story."},{"id":"B","text":"therefore,","is_correct":false,"explanation":"Incorrect: the multiple inventors are not a result of the single-inventor credit."},{"id":"C","text":"meanwhile,","is_correct":false,"explanation":"Incorrect: ''meanwhile'' marks simultaneous time, not a correction of the historical claim."},{"id":"D","text":"for example,","is_correct":false,"explanation":"Incorrect: the finding does not illustrate the single-inventor claim; it overturns it."}]'::jsonb, 'A', 'Step 1 — Find the claim being revised
Historians credited {{yellow:a single inventor}}, but the research finds several simultaneous builders.
Step 2 — Choose the corrective emphasis
''In fact'' introduces a truer account that sharpens and overturns the prior belief.
Distractor analysis:
- B: ''therefore'' implies the finding follows from the old credit, which it does not.
- C: ''meanwhile'' signals concurrent events, missing the corrective relationship.
- D: ''for example'' would support the single-inventor view rather than refute it.', 'Is the research backing up the single-inventor story or correcting it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1d512278-f289-476d-9d11-a3236e498cfb', 'Which choice completes the text with the most logical transition?', 'Volunteers cleared the invasive vines that had been smothering the riverbank for years. The native willows they had hoped to save were already too weakened to recover, ______ and within a season most had died despite the removal effort.', NULL, '[{"id":"A","text":"so","is_correct":true,"explanation":"Correct: it links the willows'' prior weakness to the resulting deaths over the season."},{"id":"B","text":"however,","is_correct":false,"explanation":"Incorrect: the willows dying agrees with their being weakened, so contrast is wrong."},{"id":"C","text":"otherwise,","is_correct":false,"explanation":"Incorrect: the clause is not an alternative outcome to the weakening."},{"id":"D","text":"in contrast,","is_correct":false,"explanation":"Incorrect: there is no opposing idea; the death follows from the weakness."}]'::jsonb, 'A', 'Step 1 — Trace cause to effect
The willows were {{yellow:already too weakened to recover}}, which leads to most dying within a season.
Step 2 — Choose the consequence link
''So'' connects the weakened state to the resulting deaths.
Distractor analysis:
- B: ''however'' implies the death contradicts the weakness, but it confirms it.
- C: ''otherwise'' would name a different outcome, not the expected result.
- D: ''in contrast'' wrongly sets the two ideas in opposition.', 'Does the willows'' death follow from their weakness or contradict it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b747296d-96d8-4389-82b4-93e5690b41d0', 'Which choice completes the text with the most logical transition?', 'The film''s director shot most scenes in dim, gray light to mirror the bleakness of the story. The producers worried that audiences would find the look too dreary, ______ so they pushed for brighter, warmer tones in the final cut.', NULL, '[{"id":"A","text":"nonetheless,","is_correct":false,"explanation":"Incorrect: the producers'' push follows logically from their worry, not in spite of it."},{"id":"B","text":"for instance,","is_correct":false,"explanation":"Incorrect: pushing for brighter tones is not an example of the dim lighting."},{"id":"C","text":"as a result,","is_correct":true,"explanation":"Correct: the producers'' worry causes their push for a brighter look."},{"id":"D","text":"by contrast,","is_correct":false,"explanation":"Incorrect: the clause continues the producers'' reasoning rather than opposing it."}]'::jsonb, 'C', 'Step 1 — Identify the motivation
The producers {{yellow:worried that audiences would find the look too dreary}}, prompting a change.
Step 2 — Supply the consequence
''As a result'' connects that worry to their push for warmer tones.
Distractor analysis:
- A: ''nonetheless'' implies they acted despite the worry, but the worry drove the action.
- B: ''for instance'' would give an example of the dreary look, which it does not.
- D: ''by contrast'' sets up opposition that the cause-effect link does not need.', 'What does the producers'' worry lead them to do?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b7d67d14-fe99-460e-bb14-1d48868775c0', 'Which choice completes the text with the most logical transition?', 'A psychologist found that students who studied in short, spaced sessions remembered material far better than those who crammed. The same students reported feeling less confident during the spaced sessions, ______ since the slower pace made the work feel harder in the moment.', NULL, '[{"id":"A","text":"even though","is_correct":false,"explanation":"Incorrect: this would invert the logic, as the clause explains rather than concedes."},{"id":"B","text":"however,","is_correct":false,"explanation":"Incorrect: the second clause explains the low confidence rather than contrasting it."},{"id":"C","text":"that is,","is_correct":false,"explanation":"Incorrect: the clause adds a reason, not a restatement of the same point."},{"id":"D","text":"because","is_correct":true,"explanation":"Correct: it introduces the cause of the students'' lower confidence, the harder-feeling slow pace."}]'::jsonb, 'D', 'Step 1 — Find the effect needing a cause
Students {{yellow:reported feeling less confident during the spaced sessions}}, and the clause explains why.
Step 2 — Choose the causal link
''Because'' introduces the reason: the slower pace felt harder in the moment.
Distractor analysis:
- A: ''even though'' would frame the clause as a concession, but it gives a cause.
- B: ''however'' signals contrast, yet the clause supports the prior statement.
- C: ''that is'' restates, but the clause supplies new causal information.', 'Why did the students feel less confident?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('551e9368-034a-4f4f-adfd-3ea13df07f69', 'Which choice completes the text with the most logical transition?', 'City planners installed protected bike lanes hoping to reduce traffic accidents downtown. Crashes involving cyclists fell sharply in the first year. ______ collisions between cars rose on the parallel streets where drivers diverted to avoid the narrowed roads.', NULL, '[{"id":"A","text":"Meanwhile,","is_correct":true,"explanation":"Correct: it marks a parallel development occurring elsewhere at the same time."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Incorrect: the rise in car crashes is not caused by the fall in cyclist crashes."},{"id":"C","text":"In summary,","is_correct":false,"explanation":"Incorrect: the sentence introduces a new effect, not a summary."},{"id":"D","text":"Likewise,","is_correct":false,"explanation":"Incorrect: a fall and a rise are opposite outcomes, not parallel ones."}]'::jsonb, 'A', 'Step 1 — Compare the two outcomes
Cyclist {{yellow:Crashes involving cyclists fell sharply}}, while car collisions rose elsewhere at the same time.
Step 2 — Choose the simultaneous shift
''Meanwhile'' captures a concurrent, contrasting development on nearby streets.
Distractor analysis:
- B: ''therefore'' wrongly makes the car-crash rise a result of fewer cyclist crashes.
- C: ''in summary'' would wrap up, but a new finding is introduced.
- D: ''likewise'' implies the same direction, yet one figure fell and the other rose.', 'The two streets had opposite results at the same time.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a41a8cbc-edcf-423c-a58a-6a918dfb5adf', 'Which choice completes the text with the most logical transition?', 'The novelist claimed she never planned her plots in advance, letting characters lead her wherever they wished. Her handwritten notebooks, ______ are filled with detailed outlines and charts mapping every chapter before she began writing.', NULL, '[{"id":"A","text":"in addition,","is_correct":false,"explanation":"Incorrect: the notebooks do not add to her claim; they undercut it."},{"id":"B","text":"however,","is_correct":true,"explanation":"Correct: it contrasts her claim of spontaneity with the evidence of careful planning."},{"id":"C","text":"accordingly,","is_correct":false,"explanation":"Incorrect: the outlines do not follow from her claim of not planning."},{"id":"D","text":"in other words,","is_correct":false,"explanation":"Incorrect: the notebooks contradict her claim rather than restate it."}]'::jsonb, 'B', 'Step 1 — Spot the contradiction
She claimed she {{yellow:never planned her plots in advance}}, yet her notebooks hold detailed outlines.
Step 2 — Choose the contrast
The evidence opposes her statement, so ''however'' is the right transition.
Distractor analysis:
- A: ''in addition'' implies the notebooks support her, but they refute her.
- C: ''accordingly'' suggests the outlines result from not planning, which is illogical.
- D: ''in other words'' restates, but the notebooks contradict the claim.', 'Do the planning notebooks match her claim of writing without a plan?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4d4460ce-4bf9-4adf-b9df-28b0d2036ea9', 'Which choice completes the text with the most logical transition?', 'Researchers expected the desert plant to wither during the long drought, since it has shallow roots and thin leaves. The plant not only survived but flowered, ______ drawing water from a fog that rolls in along the coast each morning.', NULL, '[{"id":"A","text":"in contrast,","is_correct":false,"explanation":"Incorrect: the clause explains how the plant survived, not an opposing idea."},{"id":"B","text":"nevertheless,","is_correct":false,"explanation":"Incorrect: the clause gives the reason for survival rather than conceding a contrast."},{"id":"C","text":"for","is_correct":true,"explanation":"Correct: it introduces the explanation for the plant''s surprising survival, the morning fog."},{"id":"D","text":"otherwise,","is_correct":false,"explanation":"Incorrect: the fog is the actual cause, not an alternative outcome."}]'::jsonb, 'C', 'Step 1 — Find the surprise to explain
Despite expectations of withering, the plant {{yellow:not only survived but flowered}}, and the clause says why.
Step 2 — Choose the causal explanation
''For'' introduces the reason: it draws water from the coastal fog.
Distractor analysis:
- A: ''in contrast'' would set up opposition, but the clause explains the survival.
- B: ''nevertheless'' marks concession, yet the clause supplies a cause.
- D: ''otherwise'' names an alternative result, not the reason behind the survival.', 'The clause tells you how the plant managed to survive.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ccf3f02f-fa3e-4d88-8a52-18521cdf38b9', 'Which choice completes the text with the most logical transition?', 'Marine biologists once assumed that deep-sea creatures lived in near-total darkness, dependent on food drifting down from sunlit waters above. Recent expeditions, ______ have revealed that many of these animals produce their own light through bioluminescence, creating a hidden ecosystem of signals.', NULL, '[{"id":"A","text":"however,","is_correct":true,"explanation":"Correct: it signals the contrast between the old assumption of darkness and the new finding that the animals make their own light."},{"id":"B","text":"therefore,","is_correct":false,"explanation":"Incorrect: the new findings do not result from the old assumption; they overturn it."},{"id":"C","text":"for example,","is_correct":false,"explanation":"Incorrect: the second sentence does not illustrate the first; it corrects it."},{"id":"D","text":"likewise,","is_correct":false,"explanation":"Incorrect: ''likewise'' signals similarity, but the two sentences are opposed."}]'::jsonb, 'A', 'Step 1 — Spot the reversal
The first sentence says creatures were assumed dependent on sunlit waters, but the second says expeditions {{yellow:have revealed that many of these animals produce their own light through bioluminescence}}.
Step 2 — Match the contrast
Because the discovery overturns the original assumption of total darkness, a contrast word like ''however'' is needed.
Distractor analysis:
- B: ''therefore'' implies the finding is caused by the assumption, a reverse error.
- C: ''for example'' implies illustration, but the second sentence contradicts rather than illustrates.
- D: ''likewise'' implies the ideas agree, contradicting the actual opposition.', 'Does the second sentence confirm or overturn the old assumption of darkness?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('29c830f8-4043-4c1f-ad4c-8c7099add829', 'Which choice completes the text with the most logical transition?', 'The composer Clara Schumann was celebrated across Europe as a brilliant pianist during her lifetime. Her own compositions, ______ were largely ignored until scholars in the late twentieth century began performing and recording them.', NULL, '[{"id":"A","text":"in contrast,","is_correct":true,"explanation":"Correct: it contrasts her celebrated performing career with the neglect of her compositions."},{"id":"B","text":"as a result,","is_correct":false,"explanation":"Incorrect: her fame as a pianist did not cause her compositions to be ignored."},{"id":"C","text":"in addition,","is_correct":false,"explanation":"Incorrect: ''in addition'' adds a like idea, but neglect contrasts with celebration."},{"id":"D","text":"indeed,","is_correct":false,"explanation":"Incorrect: ''indeed'' intensifies a prior point, but the second sentence shifts to an opposite outcome."}]'::jsonb, 'A', 'Step 1 — Identify the two outcomes
Schumann was celebrated as a pianist, yet her compositions {{yellow:were largely ignored until scholars in the late twentieth century}}.
Step 2 — Choose the contrast
Celebration versus neglect requires a contrasting transition such as ''in contrast.''
Distractor analysis:
- B: ''as a result'' wrongly implies her fame caused the neglect of her works.
- C: ''in addition'' signals a parallel addition, but the ideas are opposed.
- D: ''indeed'' would reinforce the first idea, not introduce the reversal.', 'Are her two reputations (performer vs. composer) the same or opposite?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1ecc9ade-9885-4bf9-becf-0acb5e18e59b', 'Which choice completes the text with the most logical transition?', 'Early supporters of the printing press believed it would spread accurate knowledge quickly and uniformly. The same technology, ______ also allowed misinformation and propaganda to circulate faster than ever before, a complication those early supporters had not foreseen.', NULL, '[{"id":"A","text":"however,","is_correct":true,"explanation":"Correct: it marks the unexpected downside that undercuts the supporters'' optimistic belief."},{"id":"B","text":"consequently,","is_correct":false,"explanation":"Incorrect: the spread of misinformation is not a consequence the supporters anticipated or intended."},{"id":"C","text":"similarly,","is_correct":false,"explanation":"Incorrect: ''similarly'' signals agreement, but the second sentence reveals a contrary effect."},{"id":"D","text":"for instance,","is_correct":false,"explanation":"Incorrect: the misinformation point is not an example of spreading accurate knowledge."}]'::jsonb, 'A', 'Step 1 — Find the tension
Supporters believed the press would spread accurate knowledge, but it {{yellow:also allowed misinformation and propaganda to circulate faster than ever before}}.
Step 2 — Select the contrast
The second effect undercuts the first belief, so a contrastive ''however'' fits.
Distractor analysis:
- B: ''consequently'' implies an intended result, but the text calls it an unforeseen complication.
- C: ''similarly'' implies the two effects align, contradicting the contrast.
- D: ''for instance'' implies illustration of the first idea, but it presents an opposing effect.', 'Is the second effect a confirmation of the supporters'' hopes or an unforeseen reversal?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4bb8b262-45ee-45e2-ae56-319f2097b500', 'Which choice completes the text with the most logical transition?', 'Many gardeners pull dandelions on sight, treating them as worthless weeds to be eliminated. Ecologists point out that dandelions bloom early in spring, ______ they provide one of the first reliable food sources for emerging bees when little else is flowering.', NULL, '[{"id":"A","text":"so","is_correct":true,"explanation":"Correct: early blooming is the reason dandelions feed early bees, a cause-and-effect link."},{"id":"B","text":"yet","is_correct":false,"explanation":"Incorrect: there is no contrast; the second clause follows logically from the early bloom."},{"id":"C","text":"meanwhile,","is_correct":false,"explanation":"Incorrect: ''meanwhile'' marks simultaneous unrelated events, not the causal link present here."},{"id":"D","text":"nonetheless,","is_correct":false,"explanation":"Incorrect: ''nonetheless'' concedes a contrast, but the clauses agree."}]'::jsonb, 'A', 'Step 1 — Trace the cause
The ecologists note that dandelions {{yellow:bloom early in spring}}, and this timing is what lets them feed emerging bees.
Step 2 — Pick the result word
Because the early bloom causes the early food supply, a causal ''so'' is correct.
Distractor analysis:
- B: ''yet'' signals contrast, but the two clauses reinforce each other.
- C: ''meanwhile'' suggests parallel timing, not the causal relationship.
- D: ''nonetheless'' concedes opposition that does not exist here.', 'Does blooming early cause the benefit to bees, or contradict it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('71cee8cd-25ed-4957-8f65-bd7c4a223b2f', 'Which choice completes the text with the most logical transition?', 'The Roman emperor Diocletian tried to halt runaway inflation by issuing an edict that fixed maximum prices for hundreds of goods. Merchants simply withdrew their wares from the market rather than sell at a loss, ______ shortages grew worse and the edict was soon abandoned.', NULL, '[{"id":"A","text":"and so","is_correct":true,"explanation":"Correct: the merchants'' withdrawal directly caused the worsening shortages and the edict''s failure."},{"id":"B","text":"even though","is_correct":false,"explanation":"Incorrect: the shortages are a result of the withdrawal, not something it occurred in spite of."},{"id":"C","text":"in particular,","is_correct":false,"explanation":"Incorrect: the second clause is an outcome, not a specific example of the first."},{"id":"D","text":"by comparison,","is_correct":false,"explanation":"Incorrect: nothing is being compared; the clauses form a chain of cause and effect."}]'::jsonb, 'A', 'Step 1 — Locate the trigger
Merchants reacted by choosing to {{yellow:withdrew their wares from the market rather than sell at a loss}}, which then produced worse shortages.
Step 2 — Pick the consequence link
Since the withdrawal causes the shortages and the edict''s collapse, ''and so'' fits.
Distractor analysis:
- B: ''even though'' implies the shortages happened despite the withdrawal, reversing the logic.
- C: ''in particular'' signals an example, but this is an effect.
- D: ''by comparison'' implies a comparison absent from the text.', 'Did withdrawing goods cause the shortages, or happen despite them?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('78d5d5ce-993a-43d7-9dc2-fbddd24e1aaa', 'Which choice completes the text with the most logical transition?', 'Critics initially dismissed the novelist''s experimental punctuation as a careless gimmick that made her prose hard to read. Closer study revealed a deliberate pattern: each omitted comma mirrored a character''s racing thoughts. ______ what looked like sloppiness was in fact a carefully engineered technique.', NULL, '[{"id":"A","text":"Thus,","is_correct":true,"explanation":"Correct: it draws the conclusion that follows from discovering the deliberate pattern."},{"id":"B","text":"Otherwise,","is_correct":false,"explanation":"Incorrect: ''otherwise'' introduces an alternative condition, not a conclusion drawn from the evidence."},{"id":"C","text":"However,","is_correct":false,"explanation":"Incorrect: the final sentence agrees with the closer study rather than contrasting it."},{"id":"D","text":"Meanwhile,","is_correct":false,"explanation":"Incorrect: ''meanwhile'' marks a simultaneous event, not a logical conclusion."}]'::jsonb, 'A', 'Step 1 — Find the basis for the conclusion
The middle sentence reveals that {{yellow:each omitted comma mirrored a character''s racing thoughts}}, showing the punctuation was deliberate.
Step 2 — Draw the inference
The final sentence concludes from that evidence, so a summative ''Thus'' fits.
Distractor analysis:
- B: ''Otherwise'' proposes an alternative scenario, which the text does not offer.
- C: ''However'' signals contrast, but the final sentence confirms the discovery.
- D: ''Meanwhile'' implies concurrent action rather than a conclusion.', 'Is the last sentence a conclusion drawn from the discovery or a contradiction of it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('85878271-ab61-4415-a472-aa9f59cfef72', 'Which choice completes the text with the most logical transition?', 'The new commuter rail line was designed to reduce highway congestion by giving drivers a faster alternative. Ridership surveys found that most passengers had previously taken the bus rather than driven. ______ the rail line drew riders away from public transit instead of pulling cars off the road.', NULL, '[{"id":"A","text":"As a result,","is_correct":true,"explanation":"Correct: the survey finding leads logically to the conclusion that the line shifted bus riders, not drivers."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Incorrect: the final sentence agrees with the survey data rather than conceding a contrast to it."},{"id":"C","text":"For example,","is_correct":false,"explanation":"Incorrect: the final sentence is a conclusion, not an illustrative instance."},{"id":"D","text":"Admittedly,","is_correct":false,"explanation":"Incorrect: ''admittedly'' concedes a point against the writer''s claim, but here the claim follows from the data."}]'::jsonb, 'A', 'Step 1 — Read the evidence
The survey found that {{yellow:most passengers had previously taken the bus rather than driven}}.
Step 2 — Trace the consequence
Because those riders came from buses, the line drew people away from transit, a result that follows directly, so ''As a result'' fits.
Distractor analysis:
- B: ''Nevertheless'' signals contrast, but the conclusion matches the data.
- C: ''For example'' implies illustration, but this sentence states the consequence.
- D: ''Admittedly'' concedes against the argument, which is not happening here.', 'Does the last sentence follow from the survey finding or push against it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4a4a44b6-cc2e-4fa6-8e53-fad167e86b69', 'Which choice completes the text with the most logical transition?', 'Some economists argue that raising the minimum wage forces businesses to cut jobs. A recent study of neighboring counties found employment levels barely changed after one county raised its wage. The study''s authors, ______ caution that local labor markets differ widely and that a single comparison cannot settle the broader debate.', NULL, '[{"id":"A","text":"however,","is_correct":true,"explanation":"Correct: the authors qualify their own finding, contrasting the tidy result with its limited reach."},{"id":"B","text":"therefore,","is_correct":false,"explanation":"Incorrect: the caution is not a consequence of the steady employment figures."},{"id":"C","text":"indeed,","is_correct":false,"explanation":"Incorrect: ''indeed'' would reinforce the finding, but the authors are tempering it."},{"id":"D","text":"likewise,","is_correct":false,"explanation":"Incorrect: ''likewise'' signals agreement, yet the authors introduce a limiting qualification."}]'::jsonb, 'A', 'Step 1 — Note the qualification
Despite finding little change, the authors {{yellow:caution that local labor markets differ widely}} and that one comparison cannot settle the debate.
Step 2 — Choose the contrast
The caution pulls back from the clean result, so a contrastive ''however'' is needed.
Distractor analysis:
- B: ''therefore'' implies the caution results from the data, but it limits the data instead.
- C: ''indeed'' would amplify the finding, opposite of the authors'' tempering.
- D: ''likewise'' implies agreement, contradicting the qualifying tone.', 'Are the authors reinforcing their result or hedging it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e991245f-2dfd-4476-8118-c7aa90aeb1b3', 'Which choice completes the text with the most logical transition?', 'Honeybees communicate the location of food through a precise ''waggle dance'' that encodes direction and distance. Researchers studying a related stingless bee species expected to find the same dance. They discovered instead that these bees mark trails with scent. ______ the two species solve the same problem in entirely different ways.', NULL, '[{"id":"A","text":"In short,","is_correct":true,"explanation":"Correct: it summarizes the contrast just described into a single concluding generalization."},{"id":"B","text":"By contrast,","is_correct":false,"explanation":"Incorrect: the final sentence sums up the difference already shown rather than introducing a new contrasting item."},{"id":"C","text":"Because of this,","is_correct":false,"explanation":"Incorrect: the difference in methods is not caused by the scent discovery; the sentence restates the finding."},{"id":"D","text":"Granted,","is_correct":false,"explanation":"Incorrect: ''Granted'' concedes a counterpoint, but the sentence affirms the main observation."}]'::jsonb, 'A', 'Step 1 — Track the discovery
Instead of a dance, the stingless bees {{yellow:mark trails with scent}}, revealing two different methods.
Step 2 — Pick the summary
The final sentence restates the whole point compactly, so a summarizing ''In short'' fits.
Distractor analysis:
- B: ''By contrast'' would set up one item against another, but the contrast is already stated and now summarized.
- C: ''Because of this'' implies causation, but the sentence is a recap, not an effect.
- D: ''Granted'' concedes a counterpoint that the text does not raise.', 'Is the last sentence summing up the whole comparison or adding a brand-new contrast?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a932739b-523b-4178-a2a3-7416b1d52000', 'Which choice completes the text with the most logical transition?', 'For decades, textbooks credited a single inventor with the light bulb. Historians now emphasize that dozens of researchers contributed key pieces over many years. The famous name on the patent, ______ represents the final step in a long collaborative chain rather than a lone flash of genius.', NULL, '[{"id":"A","text":"then,","is_correct":true,"explanation":"Correct: it draws the resulting interpretation that follows from the historians'' broader view."},{"id":"B","text":"instead","is_correct":false,"explanation":"Incorrect: the sentence already uses ''rather than'' to mark the contrast, so ''instead'' as the transition is redundant and ill-fitting."},{"id":"C","text":"for example,","is_correct":false,"explanation":"Incorrect: the sentence interprets the famous name, not illustrates a prior claim with a case."},{"id":"D","text":"in contrast,","is_correct":false,"explanation":"Incorrect: the sentence extends the historians'' point rather than contrasting with it."}]'::jsonb, 'A', 'Step 1 — Note the shift in credit
Historians stress that {{yellow:dozens of researchers contributed key pieces over many years}}, reframing the single inventor.
Step 2 — Draw the consequence
The final sentence follows from that reframing, so the resultative ''then'' fits.
Distractor analysis:
- B: ''instead'' duplicates the contrast already carried by ''rather than,'' creating redundancy.
- C: ''for example'' implies an illustration, but the sentence draws a conclusion.
- D: ''in contrast'' opposes the historians'' view, yet the sentence supports it.', 'Does the final sentence build on the historians'' view or oppose it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a5120a8d-3585-4f17-ac5c-3ef034037956', 'Which choice completes the text with the most logical transition?', 'The city installed brighter streetlights hoping to make pedestrians feel safer at night. Surveys taken afterward showed that residents did report feeling more secure. Crime statistics for the same blocks, ______ remained essentially unchanged from the previous year.', NULL, '[{"id":"A","text":"however,","is_correct":true,"explanation":"Correct: it contrasts the improved feeling of safety with the unchanged actual crime data."},{"id":"B","text":"accordingly,","is_correct":false,"explanation":"Incorrect: unchanged crime is not an outcome that follows from residents feeling safer."},{"id":"C","text":"furthermore,","is_correct":false,"explanation":"Incorrect: ''furthermore'' adds a supporting point, but the data undercut the perception."},{"id":"D","text":"as a result,","is_correct":false,"explanation":"Incorrect: the flat crime numbers are not a consequence of the increased sense of security."}]'::jsonb, 'A', 'Step 1 — Compare perception and data
Residents felt safer, but the crime statistics {{yellow:remained essentially unchanged from the previous year}}.
Step 2 — Choose the contrast
The gap between feeling and fact calls for a contrastive ''however.''
Distractor analysis:
- B: ''accordingly'' implies the flat crime followed from the feeling, a false cause.
- C: ''furthermore'' adds agreement, but the data oppose the perception.
- D: ''as a result'' wrongly treats unchanged crime as an effect of the survey result.', 'Do the crime numbers confirm the residents'' feeling of safety or clash with it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('803cf2f0-9b29-47d2-b62d-c4f67f3e9a02', 'Which choice completes the text with the most logical transition?', 'Volcanic eruptions can darken skies and lower global temperatures for years by filling the atmosphere with reflective ash and gas. The same eruptions enrich surrounding soils with minerals over time. ______ regions near active volcanoes often become some of the most fertile farmland on Earth.', NULL, '[{"id":"A","text":"Consequently,","is_correct":true,"explanation":"Correct: the mineral enrichment is the cause that leads to the fertile farmland result."},{"id":"B","text":"Nonetheless,","is_correct":false,"explanation":"Incorrect: the fertility follows naturally from the enrichment, so no concession of contrast is needed."},{"id":"C","text":"Similarly,","is_correct":false,"explanation":"Incorrect: ''Similarly'' signals a parallel, but the sentence states an effect of the enrichment."},{"id":"D","text":"In contrast,","is_correct":false,"explanation":"Incorrect: the fertile farmland agrees with the enrichment point rather than contrasting it."}]'::jsonb, 'A', 'Step 1 — Identify the cause
The text says eruptions {{yellow:enrich surrounding soils with minerals over time}}.
Step 2 — Link to the effect
Fertile farmland results directly from that enrichment, so a causal ''Consequently'' fits.
Distractor analysis:
- B: ''Nonetheless'' concedes a contrast, but the fertility flows logically from the enrichment.
- C: ''Similarly'' implies a comparison, but this is a cause-and-effect chain.
- D: ''In contrast'' opposes the enrichment point, which the fertility actually supports.', 'Does the fertile farmland result from the soil enrichment or contradict it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d106b6c1-30d9-4eeb-b053-61827f6c3d15', 'Which choice completes the text with the most logical transition?', 'Marine biologists once assumed that deep-sea creatures lived in near-total isolation, sustained only by debris drifting down from sunlit waters above. Recent expeditions to hydrothermal vents have overturned this view, revealing dense communities of tube worms and crabs nourished by bacteria that convert vent chemicals into energy. ______, the seafloor near these vents teems with life that owes nothing to the distant sun.', NULL, '[{"id":"A","text":"In contrast,","is_correct":true,"explanation":"Correct: it marks the opposition between the old assumption of barren isolation and the newly observed teeming life."},{"id":"B","text":"For example,","is_correct":false,"explanation":"Wrong: the final sentence does not illustrate the vent communities; it states a contrasting conclusion."},{"id":"C","text":"Therefore,","is_correct":false,"explanation":"Wrong: the sentence opposes rather than logically results from the prior expectation of isolation."},{"id":"D","text":"Similarly,","is_correct":false,"explanation":"Wrong: ''Similarly'' signals likeness, but the sentence contrasts with the earlier assumption of barrenness."}]'::jsonb, 'A', 'Step 1 — Identify the two ideas
The passage sets up an old assumption against a discovery: scientists thought the deep sea lived in {{yellow:near-total isolation}}, but vents reveal {{yellow:dense communities of tube worms and crabs}}.
Step 2 — Choose the relationship
The final sentence restates the surprising, opposite reality, so a contrast transition is needed.
Distractor analysis:
- B: ''For example'' would require an illustration of a stated category, not a contrasting summary.
- C: ''Therefore'' implies the life is a logical consequence of the isolation assumption, which reverses the meaning.
- D: ''Similarly'' signals agreement, but the sentence overturns the earlier view.', 'The final sentence overturns the assumption stated in the first sentence.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a324621b-4cdb-43ea-9bf3-7ca4438e35ff', 'Which choice completes the text with the most logical transition?', 'City planners in the 1950s widened roads aggressively, confident that more lanes would permanently ease congestion. Yet studies of these expanded routes found that the new capacity quickly filled with additional drivers, a phenomenon known as induced demand. ______, the wider highways often carried just as much stop-and-go traffic within a few years.', NULL, '[{"id":"A","text":"As a result,","is_correct":true,"explanation":"Correct: the renewed congestion is the direct consequence of induced demand filling the new lanes."},{"id":"B","text":"However,","is_correct":false,"explanation":"Wrong: the sentence agrees with and follows from the prior point rather than opposing it."},{"id":"C","text":"In addition,","is_correct":false,"explanation":"Wrong: it adds nothing new; it states the outcome caused by the preceding mechanism."},{"id":"D","text":"For instance,","is_correct":false,"explanation":"Wrong: the sentence is the consequence of induced demand, not an example of a broader claim."}]'::jsonb, 'A', 'Step 1 — Identify the mechanism
The passage explains that new lanes filled with drivers through {{yellow:a phenomenon known as induced demand}}.
Step 2 — Choose the relationship
The final sentence reports the renewed congestion that results from that filling, so a cause-effect transition fits.
Distractor analysis:
- B: ''However'' signals contrast, but the result agrees with the induced-demand point.
- C: ''In addition'' merely adds, ignoring the cause-effect link.
- D: ''For instance'' would require the sentence to exemplify a category, not report a consequence.', 'The last sentence states what induced demand caused.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c0b7ef48-b139-4ad8-b990-08e5408acc6a', 'Which choice completes the text with the most logical transition?', 'Eleanor distrusted the new neighbor''s friendliness, certain that his constant offers to help concealed some hidden motive. Months passed, and he asked for nothing in return, quietly shoveling her walk and fetching her mail without comment. ______, she began to suspect that his kindness was exactly what it appeared to be.', NULL, '[{"id":"A","text":"Eventually,","is_correct":true,"explanation":"Correct: it marks the gradual passage of time leading to her changed conclusion."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: her new suspicion follows naturally from his behavior, not in spite of it."},{"id":"C","text":"By comparison,","is_correct":false,"explanation":"Wrong: nothing is being compared; the sentence reports an outcome over time."},{"id":"D","text":"In short,","is_correct":false,"explanation":"Wrong: the sentence introduces a developed change, not a summary of preceding points."}]'::jsonb, 'A', 'Step 1 — Track the timeline
The passage notes that {{yellow:Months passed, and he asked for nothing in return}}, signaling a process unfolding over time.
Step 2 — Choose the relationship
Her shift toward trust arrives at the end of that period, so a transition of eventual outcome fits.
Distractor analysis:
- B: ''Nevertheless'' implies contrast, but her new view follows from his consistent kindness.
- C: ''By comparison'' demands two things being weighed, which the sentence does not do.
- D: ''In short'' would summarize, but the sentence advances a new development.', 'Note the phrase about months passing.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('921f7551-ab7f-441d-b22b-fafd71112fb8', 'Which choice completes the text with the most logical transition?', 'Honeybees communicate the location of food through an intricate ''waggle dance'' that encodes both direction and distance. Researchers long debated whether other bees truly read this dance or simply followed the scent of the discovered flowers. Robotic-bee experiments settled the question: hives directed by mechanical dancers flew to empty fields with no scent at all. ______, the dance itself carries the information that guides the colony.', NULL, '[{"id":"A","text":"Thus,","is_correct":true,"explanation":"Correct: the conclusion that the dance carries information follows logically from the robotic-bee result."},{"id":"B","text":"Still,","is_correct":false,"explanation":"Wrong: the sentence is a conclusion drawn from the evidence, not a concession against it."},{"id":"C","text":"Meanwhile,","is_correct":false,"explanation":"Wrong: it suggests simultaneous events, but the sentence states a deduced result."},{"id":"D","text":"Likewise,","is_correct":false,"explanation":"Wrong: ''Likewise'' signals parallel similarity, not a conclusion from the experiment."}]'::jsonb, 'A', 'Step 1 — Locate the decisive evidence
The robotic-bee test showed bees {{yellow:flew to empty fields with no scent at all}}, ruling out scent as the cue.
Step 2 — Choose the relationship
The final sentence states the logical conclusion that the dance carries the information, so a consequence transition fits.
Distractor analysis:
- B: ''Still'' marks concession, but the sentence affirms the evidence rather than resisting it.
- C: ''Meanwhile'' implies a parallel event, not a deduction.
- D: ''Likewise'' signals similarity between two like cases, absent here.', 'The final sentence is the conclusion the experiment proves.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('517fc056-a811-4972-a7d5-027ccb2deb9c', 'Which choice completes the text with the most logical transition?', 'The Roman aqueducts are often praised as engineering marvels that delivered fresh water across vast distances. Their gentle, precise downhill gradient allowed gravity alone to move millions of gallons each day without a single pump. ______, some channels descended only a few inches over the course of a mile, a tolerance that taxes even modern surveyors.', NULL, '[{"id":"A","text":"Indeed,","is_correct":true,"explanation":"Correct: the tiny gradient intensifies and confirms the prior claim of precise engineering."},{"id":"B","text":"Otherwise,","is_correct":false,"explanation":"Wrong: it signals an alternative outcome, but the sentence reinforces the preceding point."},{"id":"C","text":"In contrast,","is_correct":false,"explanation":"Wrong: the sentence agrees with and amplifies the claim of precision rather than opposing it."},{"id":"D","text":"Conversely,","is_correct":false,"explanation":"Wrong: ''Conversely'' demands an opposite idea, but this detail supports the same idea."}]'::jsonb, 'A', 'Step 1 — Identify the claim being supported
The passage praises the aqueducts'' {{yellow:gentle, precise downhill gradient}} that moved water by gravity alone.
Step 2 — Choose the relationship
The final sentence offers a striking detail that confirms and emphasizes that precision, so an emphatic transition fits.
Distractor analysis:
- B: ''Otherwise'' introduces an alternative scenario, which is not present.
- C: ''In contrast'' signals opposition, but the detail reinforces the claim.
- D: ''Conversely'' requires an opposite point, contradicting the supporting nature of the detail.', 'The last sentence drives home how precise the gradient was.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
