INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('398f1346-763e-41a6-9a8b-038ece51d0d3', 'Which choice completes the text with the most logical transition?', 'Advocates of the new four-day workweek point to trials in which output held steady even as hours fell. Critics counter that these trials were brief and concentrated in office jobs where tasks can be compressed. ______, a hospital or a factory cannot simply shorten its week without leaving shifts uncovered.', NULL, '[{"id":"A","text":"For example,","is_correct":true,"explanation":"Correct: the hospital and factory illustrate the critics'' point about jobs that cannot compress tasks."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Wrong: the sentence is an illustration, not a conclusion drawn from the critics'' claim."},{"id":"C","text":"Nonetheless,","is_correct":false,"explanation":"Wrong: it signals concession, but the sentence supports the critics rather than countering them."},{"id":"D","text":"Admittedly,","is_correct":false,"explanation":"Wrong: ''Admittedly'' concedes a point to the other side, but this example backs the critics."}]'::jsonb, 'A', 'Step 1 — Identify the claim being illustrated
Critics note the trials were {{yellow:concentrated in office jobs where tasks can be compressed}}.
Step 2 — Choose the relationship
The hospital and factory are concrete cases of jobs that cannot compress, so an exemplifying transition fits.
Distractor analysis:
- B: ''Therefore'' implies a deduction, but the sentence gives an example.
- C: ''Nonetheless'' signals contrast, yet the sentence supports the critics'' point.
- D: ''Admittedly'' concedes ground to opponents, which this example does not do.', 'The hospital and factory are instances of the critics'' claim.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1ee56800-b4b6-4d2e-82bf-ff53e1e0bbe9', 'Which choice completes the text with the most logical transition?', 'For decades, the small mill town''s economy depended entirely on a single textile factory that employed most of its residents. When the factory closed, many predicted that the town would empty out within a generation. ______, a cluster of artisans and remote workers gradually moved into the cheap, spacious buildings the mill had left behind.', NULL, '[{"id":"A","text":"Instead,","is_correct":true,"explanation":"Correct: the town''s revival replaces the predicted emptying-out, marking a turn from expectation."},{"id":"B","text":"Consequently,","is_correct":false,"explanation":"Wrong: the influx of newcomers contradicts the prediction rather than resulting from it."},{"id":"C","text":"Furthermore,","is_correct":false,"explanation":"Wrong: it merely adds, but the sentence reverses the expected outcome."},{"id":"D","text":"In particular,","is_correct":false,"explanation":"Wrong: ''In particular'' narrows to a detail, but the sentence contradicts the forecast."}]'::jsonb, 'A', 'Step 1 — Identify the prediction
Observers expected that {{yellow:the town would empty out within a generation}}.
Step 2 — Choose the relationship
The final sentence describes newcomers arriving instead of departure, so a substitution-contrast transition fits.
Distractor analysis:
- B: ''Consequently'' implies the influx followed from the prediction, reversing the logic.
- C: ''Furthermore'' adds a point rather than overturning the forecast.
- D: ''In particular'' specifies a detail of a stated idea, not a reversal.', 'The outcome is the opposite of what was predicted.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ec6bd28d-0bbf-425a-8ec1-207823c004ec', 'Which choice completes the text with the most logical transition?', 'Vincent van Gogh sold almost no paintings during his lifetime and was widely dismissed as an eccentric failure. His brother Theo, however, kept meticulous records and preserved hundreds of canvases that buyers had ignored. ______, the very works the public once rejected now hang in the world''s most celebrated museums.', NULL, '[{"id":"A","text":"Today,","is_correct":true,"explanation":"Correct: it marks the present-day reversal of the artist''s earlier obscurity."},{"id":"B","text":"In summary,","is_correct":false,"explanation":"Wrong: the sentence introduces a new time-based reversal, not a recap of prior points."},{"id":"C","text":"Because of this,","is_correct":false,"explanation":"Wrong: the museums'' acclaim is not caused by the public''s earlier rejection."},{"id":"D","text":"Granted,","is_correct":false,"explanation":"Wrong: ''Granted'' concedes a point, but the sentence asserts a triumphant outcome."}]'::jsonb, 'A', 'Step 1 — Establish the contrast across time
The passage notes the works were ones {{yellow:buyers had ignored}} during his life.
Step 2 — Choose the relationship
The final sentence shifts to the present, where those works are celebrated, so a present-time transition fits.
Distractor analysis:
- B: ''In summary'' would recap, but the sentence adds a new contrasting development.
- C: ''Because of this'' implies causation from rejection, which does not hold.
- D: ''Granted'' concedes to an opposing view, not present here.', 'The final sentence jumps to the present-day reputation of the works.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('c9d9a031-9721-460b-98c3-4b82a6c32050', 'Which choice completes the text with the most logical transition?', 'Geologists studying ancient climate rely on layers of mud at the bottom of lakes, where each year deposits a distinct band of sediment. By counting these bands, much as one counts tree rings, they can reconstruct rainfall patterns stretching back thousands of years. ______, a single core of lakebed mud can serve as a detailed calendar of a region''s vanished weather.', NULL, '[{"id":"A","text":"In effect,","is_correct":true,"explanation":"Correct: it restates the method''s upshot, casting the mud core as a weather calendar."},{"id":"B","text":"On the other hand,","is_correct":false,"explanation":"Wrong: the sentence summarizes the same idea rather than presenting an opposing one."},{"id":"C","text":"By chance,","is_correct":false,"explanation":"Wrong: the calendar-like value comes from method, not coincidence."},{"id":"D","text":"Even so,","is_correct":false,"explanation":"Wrong: ''Even so'' signals concession, but the sentence affirms what precedes it."}]'::jsonb, 'A', 'Step 1 — Identify the method
Scientists reconstruct climate {{yellow:By counting these bands, much as one counts tree rings}}.
Step 2 — Choose the relationship
The final sentence recasts that method''s result as a calendar, so a restatement transition fits.
Distractor analysis:
- B: ''On the other hand'' signals contrast, but the sentence agrees with the prior idea.
- C: ''By chance'' implies coincidence, contradicting the deliberate counting method.
- D: ''Even so'' concedes against the prior point rather than affirming it.', 'The last sentence restates the method''s payoff in plainer terms.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9b9fd92e-a970-4eea-8a7e-698c5898f376', 'Which choice completes the text with the most logical transition?', 'The committee designing the new park assumed that residents wanted more open lawn for picnics and sports. Surveys returned a different picture: most neighbors asked for shaded benches, walking paths, and quiet corners for reading. ______, the final blueprint traded several acres of grass for groves of trees and winding trails.', NULL, '[{"id":"A","text":"Accordingly,","is_correct":true,"explanation":"Correct: the redesign follows directly from what the surveys revealed residents wanted."},{"id":"B","text":"However,","is_correct":false,"explanation":"Wrong: the blueprint responds to the survey results rather than opposing them."},{"id":"C","text":"For instance,","is_correct":false,"explanation":"Wrong: the sentence is the planners'' response, not an example of the survey findings."},{"id":"D","text":"Regardless,","is_correct":false,"explanation":"Wrong: ''Regardless'' implies the design ignored the surveys, but it was shaped by them."}]'::jsonb, 'A', 'Step 1 — Identify what residents wanted
The surveys showed neighbors asked for {{yellow:shaded benches, walking paths, and quiet corners for reading}}.
Step 2 — Choose the relationship
The final blueprint changes the design in response to that feedback, so a consequence transition fits.
Distractor analysis:
- B: ''However'' signals contrast, but the design aligns with the surveys.
- C: ''For instance'' would mark an example, not a responsive action.
- D: ''Regardless'' implies the feedback was ignored, contradicting the redesign.', 'The blueprint changed because of what the surveys said.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('8fa50096-af51-4c28-bf82-77eae260e9e4', 'Which choice completes the text with the most logical transition?', 'Some economists argue that raising the minimum wage forces small businesses to cut staff to control costs. Studies of cities that recently raised their wage floors, however, found little change in overall employment. ______, several of those same cities reported that worker turnover dropped sharply, saving employers the expense of constant hiring.', NULL, '[{"id":"A","text":"Moreover,","is_correct":true,"explanation":"Correct: the drop in turnover adds a further point supporting the studies'' favorable findings."},{"id":"B","text":"In contrast,","is_correct":false,"explanation":"Wrong: the turnover finding reinforces rather than opposes the preceding employment result."},{"id":"C","text":"Therefore,","is_correct":false,"explanation":"Wrong: lower turnover is an additional finding, not a conclusion deduced from stable employment."},{"id":"D","text":"Initially,","is_correct":false,"explanation":"Wrong: ''Initially'' marks a first stage in a sequence, which the sentence does not begin."}]'::jsonb, 'A', 'Step 1 — Identify the supporting findings
The studies first found {{yellow:little change in overall employment}} after wage increases.
Step 2 — Choose the relationship
The final sentence adds a second favorable finding about turnover, so an additive transition fits.
Distractor analysis:
- B: ''In contrast'' signals opposition, but both findings point the same way.
- C: ''Therefore'' implies deduction, yet turnover is a separate observed result.
- D: ''Initially'' starts a sequence, which the sentence does not.', 'The last sentence piles on a second point in the same direction.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('65a401eb-25ec-41a1-86fc-827e4cb68185', 'Which choice completes the text with the most logical transition?', 'The young inventor was convinced that her folding solar panel would sell instantly once people saw how light and portable it was. At the trade show, crowds admired the design but balked at the steep price and walked away empty-handed. ______, she returned home with a notebook full of orders that never materialized.', NULL, '[{"id":"A","text":"As a result,","is_correct":true,"explanation":"Correct: the absence of real orders results directly from buyers balking at the price."},{"id":"B","text":"Surprisingly,","is_correct":false,"explanation":"Wrong: the empty result is the expected outcome of shoppers walking away, not a surprise."},{"id":"C","text":"Likewise,","is_correct":false,"explanation":"Wrong: ''Likewise'' signals similarity between parallel cases, not a consequence."},{"id":"D","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: the outcome follows from the buyers'' reluctance rather than defying it."}]'::jsonb, 'A', 'Step 1 — Identify the cause
At the show, shoppers {{yellow:balked at the steep price and walked away empty-handed}}.
Step 2 — Choose the relationship
The empty notebook of unfulfilled orders is the direct outcome of that reluctance, so a cause-effect transition fits.
Distractor analysis:
- B: ''Surprisingly'' implies an unexpected result, but this outcome follows logically.
- C: ''Likewise'' marks parallel similarity, not consequence.
- D: ''Nevertheless'' signals contrast, but the result aligns with the buyers'' behavior.', 'The empty orders are what the price balking led to.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('524be299-529f-4f8c-81c2-2e26fc8fc74d', 'Which choice completes the text with the most logical transition?', 'Most ecologists once assumed that a forest recovering from a major fire would return to its original mix of species within a few decades. Recent long-term surveys complicate this picture: in several burned regions, fast-colonizing shrubs have so thoroughly dominated the soil that the slower-growing trees cannot reestablish themselves. ______ what looks like a temporary disturbance may instead lock the landscape into a permanently altered state.', NULL, '[{"id":"A","text":"Consequently,","is_correct":true,"explanation":"Correct: the final sentence states the outcome that follows from shrubs preventing trees from reestablishing, a cause-and-effect relationship."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: the final sentence does not contrast with the preceding evidence; it draws a conclusion from it."},{"id":"C","text":"For instance,","is_correct":false,"explanation":"Wrong: the final sentence is not an example of the prior claim but a general inference drawn from it."},{"id":"D","text":"Similarly,","is_correct":false,"explanation":"Wrong: nothing parallel is being added; the sentence states a consequence, not a comparable second case."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence reports that {{yellow:the slower-growing trees cannot reestablish themselves}}, and the final sentence describes the lasting result of that fact.
Step 2 — Match the transition
Because the locked-in altered state follows directly from the shrubs blocking the trees, a cause-and-effect transition like ''Consequently'' is required.
Distractor analysis:
- B: ''Nevertheless'' signals contrast, but the final sentence agrees with and extends the evidence rather than opposing it.
- C: ''For instance'' would introduce an example, yet the sentence states a broad conclusion, not a specific case.
- D: ''Similarly'' would add a parallel instance, but no second comparable situation is presented.', 'Ask whether the last sentence opposes the evidence, exemplifies it, or results from it.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6fe26fcb-35b3-4700-ae92-28569e7216ed', 'Which choice completes the text with the most logical transition?', 'Critics initially dismissed the novelist''s dense, footnote-laden style as a barrier that would keep ordinary readers away. The books became runaway bestsellers anyway, embraced precisely by the general audience the critics had written off. ______ the very feature the reviewers treated as a liability turned out to be the source of the novels'' popular appeal.', NULL, '[{"id":"A","text":"Indeed,","is_correct":true,"explanation":"Correct: the final sentence intensifies and confirms the surprising point that the off-putting style actually drew readers in."},{"id":"B","text":"However,","is_correct":false,"explanation":"Wrong: the final sentence reinforces rather than reverses the preceding sentence about popular embrace."},{"id":"C","text":"By comparison,","is_correct":false,"explanation":"Wrong: no second item is being measured against the first; the sentence restates the same surprise more emphatically."},{"id":"D","text":"In conclusion,","is_correct":false,"explanation":"Wrong: this two-step passage is not a summary of multiple points but an emphatic confirmation of one."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The middle sentence says the books were {{yellow:embraced precisely by the general audience the critics had written off}}, and the final sentence drives that irony home.
Step 2 — Match the transition
Since the last sentence strengthens and confirms the point just made, the emphatic ''Indeed'' fits.
Distractor analysis:
- B: ''However'' marks contrast, but the closing sentence agrees with the prior one.
- C: ''By comparison'' needs two things to compare; only one phenomenon is discussed.
- D: ''In conclusion'' suits a wrap-up of several points, not a single intensifying restatement.', 'Decide whether the final line contradicts, summarizes, or emphatically confirms the surprise.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('17fd639d-a991-4a05-a50b-6191f0d82eb8', 'Which choice completes the text with the most logical transition?', 'Historians long credited the city''s sudden prosperity in the 1300s to its newly built harbor, which welcomed merchant ships from across the sea. Tax records from the period tell a different story: the bulk of the city''s wealth came from inland wool fairs held far from the docks. ______ the harbor, however impressive, was a minor contributor to the boom that made the city famous.', NULL, '[{"id":"A","text":"In other words,","is_correct":true,"explanation":"Correct: the final sentence restates the implication of the tax records in plainer terms."},{"id":"B","text":"Still,","is_correct":false,"explanation":"Wrong: ''Still'' concedes against the prior point, but the final sentence agrees with the tax-record evidence."},{"id":"C","text":"Meanwhile,","is_correct":false,"explanation":"Wrong: no simultaneous separate event is introduced; the sentence interprets the evidence already given."},{"id":"D","text":"On the contrary,","is_correct":false,"explanation":"Wrong: the sentence does not reverse the immediately preceding claim; it clarifies it."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence reveals that {{yellow:the bulk of the city''s wealth came from inland wool fairs held far from the docks}}, and the final sentence puts that finding into simpler, summarizing words.
Step 2 — Match the transition
Because the closing sentence rephrases the implication of the evidence, ''In other words'' is appropriate.
Distractor analysis:
- B: ''Still'' would concede a counterpoint, but the sentence extends rather than resists the evidence.
- C: ''Meanwhile'' signals a parallel event in time, which the passage does not present.
- D: ''On the contrary'' reverses the prior sentence, yet here the sentence agrees with it.', 'Is the last sentence reversing the tax-record finding or restating it more plainly?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('62ea424b-5cc7-4486-9479-390c21e1cb18', 'Which choice completes the text with the most logical transition?', 'Engineers designing the bridge expected that thicker support cables would always make the structure safer under heavy wind loads. Wind-tunnel tests revealed a counterintuitive limit: beyond a certain thickness, the added mass made the cables vibrate more violently in gusts. ______ piling on extra material, far from guaranteeing stability, can actively undermine it.', NULL, '[{"id":"A","text":"Thus,","is_correct":true,"explanation":"Correct: the final sentence states the general lesson that follows from the test result."},{"id":"B","text":"Granted,","is_correct":false,"explanation":"Wrong: ''Granted'' concedes a point to an opposing view, but the sentence draws a conclusion supporting the test data."},{"id":"C","text":"Likewise,","is_correct":false,"explanation":"Wrong: no parallel case is added; the sentence generalizes from the single finding."},{"id":"D","text":"Instead,","is_correct":false,"explanation":"Wrong: ''Instead'' substitutes one option for another, but the sentence summarizes a result rather than offering an alternative."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence shows that {{yellow:the added mass made the cables vibrate more violently in gusts}}, and the final sentence states the principle that follows.
Step 2 — Match the transition
Because the closing sentence is the logical consequence of the test finding, ''Thus'' fits.
Distractor analysis:
- A is correct.
- B: ''Granted'' would concede to a counterargument that is not present.
- C: ''Likewise'' needs a second parallel example, which the passage lacks.
- D: ''Instead'' implies replacing one idea with another, but the sentence draws a conclusion.', 'Does the final sentence offer an alternative action or state the takeaway of the test?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('023c8126-e552-4c1d-a0df-c73d7b696498', 'Which choice completes the text with the most logical transition?', 'Proponents of the new tutoring program pointed to rising test scores as proof that it worked. A skeptic might note that scores were already climbing in the years before the program began. ______ the upward trend continued at an even steeper rate once the program was in place, a pattern hard to attribute to chance alone.', NULL, '[{"id":"A","text":"Even so,","is_correct":true,"explanation":"Correct: the final sentence concedes the skeptic''s point yet supplies evidence that still favors the program."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Wrong: the final sentence does not follow as a result of the skeptic''s objection; it pushes back against it."},{"id":"C","text":"For example,","is_correct":false,"explanation":"Wrong: the steeper rate is not an instance of the skeptic''s point but a rebuttal to it."},{"id":"D","text":"In fact,","is_correct":false,"explanation":"Wrong: ''In fact'' would intensify the skeptic''s claim, but the sentence counters it."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The skeptic observes that {{yellow:scores were already climbing in the years before the program began}}, and the final sentence acknowledges this while introducing data that undercuts the objection.
Step 2 — Match the transition
Because the sentence grants the skeptic''s premise but turns it against the skeptic, the concessive-contrast ''Even so'' fits.
Distractor analysis:
- A is correct.
- B: ''Therefore'' marks a result, but the steeper rate opposes the skeptic rather than following from his claim.
- C: ''For example'' would illustrate the skeptic''s point, yet the sentence refutes it.
- D: ''In fact'' would reinforce the prior claim, but the sentence challenges it.', 'The last sentence admits the skeptic is partly right, then pushes back—what transition does that?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
