INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('899b0fcf-44c2-41ab-9bdc-2ea94bb668ca', 'Which choice completes the text with the most logical transition?', 'The composer claimed she wrote her most famous symphony in a single feverish week, and for decades biographers repeated the romantic tale. Her surviving sketchbooks, recently digitized, contain drafts of the symphony''s themes spread across nearly three years. ______ the legend of effortless inspiration obscures a long, painstaking process of revision.', NULL, '[{"id":"A","text":"In short,","is_correct":true,"explanation":"Correct: the final sentence sums up the implication of the sketchbook evidence concisely."},{"id":"B","text":"Conversely,","is_correct":false,"explanation":"Wrong: the sentence does not present an opposite case; it condenses the point the evidence already makes."},{"id":"C","text":"Additionally,","is_correct":false,"explanation":"Wrong: no new separate fact is added; the sentence distills the existing evidence."},{"id":"D","text":"Admittedly,","is_correct":false,"explanation":"Wrong: ''Admittedly'' concedes to an opposing view, but the sentence affirms the evidence''s conclusion."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence reveals drafts {{yellow:spread across nearly three years}}, and the final sentence states the lesson of that finding in a compact form.
Step 2 — Match the transition
Because the closing sentence summarizes the takeaway of the evidence, ''In short'' fits.
Distractor analysis:
- A is correct.
- B: ''Conversely'' needs an opposite to the prior point, but the sentence agrees with the evidence.
- C: ''Additionally'' would add a new fact; the sentence instead summarizes.
- D: ''Admittedly'' concedes to a counterclaim that is not present here.', 'Is the closing line adding a new fact or boiling down what the sketchbooks show?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fad9131a-0988-4fca-99f7-c3c522700921', 'Which choice completes the text with the most logical transition?', 'Astronomers detected the distant planet only by the faint dimming it caused each time it crossed its star. Such transit signals are easy to confuse with sunspots or instrument noise, so a single observation rarely settles anything. ______ the team confirmed the planet by recording the identical dip at precisely predicted intervals over two full years.', NULL, '[{"id":"A","text":"Accordingly,","is_correct":true,"explanation":"Correct: the repeated, predicted observations are the team''s response to the problem that one observation cannot settle the matter."},{"id":"B","text":"Otherwise,","is_correct":false,"explanation":"Wrong: ''Otherwise'' describes what would happen in the absence of an action, not the confirming action itself."},{"id":"C","text":"Notably,","is_correct":false,"explanation":"Wrong: ''Notably'' merely flags something striking and ignores the logical ''because of this'' link to the prior sentence."},{"id":"D","text":"Regardless,","is_correct":false,"explanation":"Wrong: ''Regardless'' dismisses the prior point, but the team''s method directly responds to the prior point."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence notes that {{yellow:a single observation rarely settles anything}}, and the final sentence describes the team''s deliberate response to that limitation.
Step 2 — Match the transition
Because repeating the measurement over two years is the appropriate action given that one look is insufficient, ''Accordingly'' fits.
Distractor analysis:
- A is correct.
- B: ''Otherwise'' would describe a hypothetical alternative outcome, not the action actually taken.
- C: ''Notably'' only highlights and misses the causal ''in response to this'' link.
- D: ''Regardless'' would brush aside the prior sentence, but the method answers it directly.', 'The team''s two-year check is a direct response to a stated problem—what transition shows ''in response to this''?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7369a214-64dd-496e-8709-5b198bd89c12', 'Which choice completes the text with the most logical transition?', 'Public-health campaigns often assume that simply giving people more information about a risk will change their behavior. Studies of seatbelt use, however, found that knowledge of crash statistics barely budged the habits of drivers who already understood the danger. ______ campaigns that paired the same information with small, automatic reminders produced sharp, lasting increases in compliance.', NULL, '[{"id":"A","text":"By contrast,","is_correct":true,"explanation":"Correct: the final sentence sets the success of reminder-paired campaigns against the failure of information alone."},{"id":"B","text":"As a result,","is_correct":false,"explanation":"Wrong: the reminder campaigns are not a consequence of information failing; they are an opposing approach."},{"id":"C","text":"Furthermore,","is_correct":false,"explanation":"Wrong: the sentence does not add another instance of failure; it presents a contrasting success."},{"id":"D","text":"That is,","is_correct":false,"explanation":"Wrong: the sentence introduces a new, different result rather than restating the prior one."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence reports that information alone {{yellow:barely budged the habits of drivers}}, while the final sentence reports a markedly different outcome when reminders were added.
Step 2 — Match the transition
Because the closing sentence opposes a success against the preceding failure, ''By contrast'' fits.
Distractor analysis:
- A is correct.
- B: ''As a result'' implies the success follows from the failure, which it does not.
- C: ''Furthermore'' would add a similar point, but the sentence is contrasting.
- D: ''That is'' signals restatement, yet a new, different result is given.', 'One approach barely worked; another worked sharply. What relationship is that?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('50b95687-967a-4c58-8f07-f8d435e8b1af', 'Which choice completes the text with the most logical transition?', 'The startup''s founders insisted that their app''s privacy was airtight, citing layers of encryption protecting users'' messages. An independent audit confirmed that the messages themselves were indeed unreadable to outsiders. ______ the app quietly logged the time, location, and recipient of every message, leaving a revealing trail the encryption did nothing to hide.', NULL, '[{"id":"A","text":"Even so,","is_correct":true,"explanation":"Correct: the final sentence grants that the messages were secure yet reveals a privacy gap that undermines the founders'' claim."},{"id":"B","text":"Hence,","is_correct":false,"explanation":"Wrong: the logging is not a consequence of the encryption working; it is a contrasting weakness."},{"id":"C","text":"Specifically,","is_correct":false,"explanation":"Wrong: ''Specifically'' would narrow the prior point, but the sentence introduces a different, contradicting fact."},{"id":"D","text":"To illustrate,","is_correct":false,"explanation":"Wrong: the metadata logging is not an example of message security but evidence against overall privacy."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence concedes the messages were {{yellow:indeed unreadable to outsiders}}, and the final sentence reveals a separate exposure that contradicts the airtight-privacy claim.
Step 2 — Match the transition
Because the sentence acknowledges the secure messages but contrasts them with an unprotected data trail, the concessive ''Even so'' fits.
Distractor analysis:
- A is correct.
- B: ''Hence'' marks a result, but the logging contradicts rather than follows from the encryption.
- C: ''Specifically'' would elaborate the prior point; instead a contrary fact appears.
- D: ''To illustrate'' would give an example of security, but the sentence reveals insecurity.', 'The messages were safe, yet something else leaked—concede then contrast.', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('a1124af6-5ce3-480c-a533-55366fb0c50e', 'Which choice completes the text with the most logical transition?', 'Anthropologists studying the remote valley community noted that its members rarely traded with outsiders and grew nearly all their own food. One might expect such isolation to breed a narrow, unchanging set of customs. ______ the village''s oral traditions were strikingly inventive, absorbing new tales and reworking old ones with each generation.', NULL, '[{"id":"A","text":"Surprisingly,","is_correct":true,"explanation":"Correct: the inventive traditions defy the expectation that isolation produces unchanging customs."},{"id":"B","text":"Predictably,","is_correct":false,"explanation":"Wrong: the outcome contradicts the stated expectation, so it is the opposite of predictable."},{"id":"C","text":"Therefore,","is_correct":false,"explanation":"Wrong: inventiveness does not follow logically from isolation; it cuts against the expected result."},{"id":"D","text":"Likewise,","is_correct":false,"explanation":"Wrong: no parallel case is being added; the sentence overturns the expectation just raised."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence sets up the expectation that isolation would {{yellow:breed a narrow, unchanging set of customs}}, and the final sentence reports the opposite.
Step 2 — Match the transition
Because the inventive traditions defy the stated expectation, ''Surprisingly'' fits.
Distractor analysis:
- A is correct.
- B: ''Predictably'' would suit a confirmed expectation, but this one is overturned.
- C: ''Therefore'' implies the result follows from isolation, which it contradicts.
- D: ''Likewise'' would add a parallel, but the sentence reverses the expectation.', 'The expectation was set up to be broken—what signals that the result defies it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('04e8f3d7-b2fc-46e8-b00b-ad0f871f819c', 'Which choice completes the text with the most logical transition?', 'Economists debating the city''s rent-control law disagree sharply about its long-term effects on housing supply. They agree on one short-term fact, though: in the first years after the law passed, tenants in regulated units paid noticeably less than they would have on the open market. ______ even the policy''s harshest critics concede that, for those particular renters in those particular years, the savings were real.', NULL, '[{"id":"A","text":"Indeed,","is_correct":true,"explanation":"Correct: the final sentence reinforces the agreed-upon short-term fact by noting even critics accept it."},{"id":"B","text":"Nonetheless,","is_correct":false,"explanation":"Wrong: the critics'' concession supports the prior fact rather than contrasting with it."},{"id":"C","text":"In contrast,","is_correct":false,"explanation":"Wrong: no opposing point is introduced; the sentence strengthens the point of agreement."},{"id":"D","text":"Originally,","is_correct":false,"explanation":"Wrong: ''Originally'' marks a time sequence, but the sentence emphasizes agreement, not chronology."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence establishes the agreed fact that {{yellow:tenants in regulated units paid noticeably less than they would have on the open market}}, and the final sentence underscores it by noting even critics concede it.
Step 2 — Match the transition
Because the closing sentence intensifies the agreement, ''Indeed'' fits.
Distractor analysis:
- A is correct.
- B: ''Nonetheless'' signals contrast, but the critics'' concession agrees with the prior fact.
- C: ''In contrast'' needs an opposing point, which is absent.
- D: ''Originally'' marks chronology, not the emphatic agreement the sentence conveys.', 'Even critics agree—does that contrast with or reinforce the shared fact?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('0a70caa5-a7d4-4485-b95b-7a907555004f', 'Which choice completes the text with the most logical transition?', 'When the museum replaced its paper maps with an interactive app, administrators predicted that visitors would move through the galleries more efficiently. Tracking data showed that app users actually lingered longer and doubled back more often than map users had. ______ the designers came to see the slower, wandering paths not as a failure but as a sign of deeper engagement with the exhibits.', NULL, '[{"id":"A","text":"Over time,","is_correct":true,"explanation":"Correct: the transition marks the shift in the designers'' interpretation that developed after the unexpected data appeared."},{"id":"B","text":"However,","is_correct":false,"explanation":"Wrong: the final sentence does not contrast with the tracking data; it builds on it by reinterpreting the behavior positively."},{"id":"C","text":"Consequently,","is_correct":false,"explanation":"Wrong: a changed interpretation is not a strict causal result of the data; it is a gradual reframing, making the temporal transition more precise."},{"id":"D","text":"For instance,","is_correct":false,"explanation":"Wrong: the designers'' new view is not an example of the lingering behavior but a response to it."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence reports that app users {{yellow:lingered longer and doubled back more often}}, and the final sentence describes how the designers'' judgment evolved in light of that.
Step 2 — Match the transition
Because the sentence tracks a gradual change in interpretation following the data, the temporal ''Over time'' fits, while no contrast is signaled.
Distractor analysis:
- A is correct.
- B: ''However'' marks contrast, but the sentence extends and reinterprets the data rather than opposing it.
- C: ''Consequently'' overstates the link as strict cause-and-effect rather than a gradual reframing.
- D: ''For instance'' would make the new view an example of the behavior, which it is not.', 'The designers'' view shifted gradually after the data; does the last sentence contrast or evolve?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e94b0148-85da-4638-b29a-b31e638852c7', 'Which choice completes the text with the most logical transition?', 'Restorers of the Renaissance fresco assumed that the grime darkening its surface was the original artist''s intended shadow, and so for centuries they preserved it untouched. When modern chemical analysis revealed the grime to be nothing more than accumulated candle soot, the conservators faced a dilemma. ______, removing it might expose pigments the painter had never expected viewers to see in full brightness.', NULL, '[{"id":"A","text":"Indeed,","is_correct":false,"explanation":"Indeed intensifies a preceding claim, but the final sentence introduces a new complication rather than reinforcing one."},{"id":"B","text":"Still,","is_correct":true,"explanation":"Still concedes that, even though the grime was merely soot, a genuine difficulty remains, which matches the unresolved dilemma."},{"id":"C","text":"Therefore,","is_correct":false,"explanation":"Therefore signals a clean conclusion, but the final sentence presents a countervailing worry, not a result."},{"id":"D","text":"For instance,","is_correct":false,"explanation":"For instance introduces an example of a prior point, yet the sentence raises a fresh tension instead."}]'::jsonb, 'B', 'Step 1 — Locate the tension
The analysis showed the grime was only soot, yet the conservators still {{yellow:faced a dilemma}}.
Step 2 — Why Still
The blank must concede that despite the reassuring discovery, a real complication persists, so the contrastive concessive ''Still'' fits.
Distractor analysis:
- A: Indeed reinforces a prior assertion, but no assertion is being intensified here.
- C: Therefore marks a result, but the sentence states a lingering problem, not an outcome.
- D: For instance demands an example of an earlier idea, which the sentence does not provide.', 'Does the last sentence resolve the dilemma or extend it despite the new finding?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d8880177-377d-4a14-8888-edee669694b9', 'Which choice completes the text with the most logical transition?', 'Economists once predicted that as a nation''s average income rose, its citizens would report steadily greater life satisfaction. Surveys across several decades of rising prosperity have shown reported satisfaction holding nearly flat. ______, the same surveys reveal that people who feel wealthier than their neighbors do report higher satisfaction, regardless of their absolute income.', NULL, '[{"id":"A","text":"Consequently,","is_correct":false,"explanation":"Consequently signals a result, but the final sentence adds an explanatory finding rather than a consequence of flat satisfaction."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Nevertheless marks contrast, yet the final sentence does not oppose the flat-satisfaction finding; it helps explain it."},{"id":"C","text":"Notably,","is_correct":true,"explanation":"Notably flags an additional, striking finding from the same surveys that sheds light on why absolute income failed to raise satisfaction."},{"id":"D","text":"In contrast,","is_correct":false,"explanation":"In contrast demands an opposition, but relative wealth raising satisfaction is consistent with, not opposed to, the prior result."}]'::jsonb, 'C', 'Step 1 — Identify the relationship
The second sentence reports that satisfaction stayed {{yellow:holding nearly flat}} despite rising income.
Step 2 — Why Notably
The final sentence offers a further, illuminating result from the same data that explains the flatness, so the additive emphatic ''Notably'' fits.
Distractor analysis:
- A: Consequently implies the relative-wealth finding follows as a result, but it is a parallel observation, not an effect.
- B: Nevertheless signals contrast, yet the finding harmonizes with rather than opposes the flat trend.
- D: In contrast requires opposition, but the relative-wealth result complements the earlier data.', 'Does the relative-wealth finding clash with the flat result or help account for it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('7ec6dbbf-03b5-4ee4-aea7-f651d03b5803', 'Which choice completes the text with the most logical transition?', 'The naturalist had argued that the island''s flightless birds lost flight because no predators forced them to flee. Critics countered that the birds'' ancestors arrived already capable of flight, and that flight is metabolically expensive to maintain. ______, abandoning it on a predator-free island would conserve energy rather than reflect mere disuse.', NULL, '[{"id":"A","text":"Thus,","is_correct":true,"explanation":"Thus draws the critics'' conclusion from the premise that flight is costly to maintain, yielding an energy-saving rationale."},{"id":"B","text":"However,","is_correct":false,"explanation":"However signals contrast, but the final sentence follows logically from the critics'' premise rather than opposing it."},{"id":"C","text":"Similarly,","is_correct":false,"explanation":"Similarly marks a parallel case, but the sentence deduces a consequence rather than offering an analogous instance."},{"id":"D","text":"Granted,","is_correct":false,"explanation":"Granted concedes a point to an opponent, but here the sentence completes the critics'' own argument."}]'::jsonb, 'A', 'Step 1 — Find the premise
The critics note that {{yellow:flight is metabolically expensive to maintain}}.
Step 2 — Why Thus
The final sentence draws the inference that shedding a costly trait conserves energy, so the conclusive ''Thus'' fits.
Distractor analysis:
- B: However implies the sentence opposes the critics, but it advances their reasoning.
- C: Similarly needs a parallel example, which is not provided.
- D: Granted concedes to an opponent, but the sentence is the critics'' own conclusion.', 'Does the final sentence follow from the cost-of-flight premise or push against it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4821beff-f75e-4cd9-851d-8f4864b26538', 'Which choice completes the text with the most logical transition?', 'Editors of the poet''s collected works long printed an early lyric exactly as it appeared in her first published volume. A recently uncovered manuscript shows her crossing out three of its stanzas in her own hand, with a marginal note calling them "false starts." ______, the version readers have admired for a century may preserve precisely the lines the poet herself wished to discard.', NULL, '[{"id":"A","text":"By comparison,","is_correct":false,"explanation":"By comparison sets up a parallel contrast between two items, but the sentence states an ironic implication of the manuscript discovery."},{"id":"B","text":"Ironically,","is_correct":true,"explanation":"Ironically captures the reversal: the cherished version retains the very lines the poet rejected."},{"id":"C","text":"Otherwise,","is_correct":false,"explanation":"Otherwise introduces an alternative scenario, but the sentence describes the actual situation revealed by the manuscript."},{"id":"D","text":"Admittedly,","is_correct":false,"explanation":"Admittedly concedes a counterpoint, yet the sentence advances the consequence of the discovery rather than conceding against it."}]'::jsonb, 'B', 'Step 1 — Spot the discovery
The manuscript shows her marginal note calling the stanzas {{yellow:false starts}}.
Step 2 — Why Ironically
The final sentence notes the unexpected reversal that beloved lines are the ones she wanted gone, so ''Ironically'' fits.
Distractor analysis:
- A: By comparison needs two compared items, but the sentence states an outcome, not a comparison.
- C: Otherwise posits a hypothetical alternative, while this is the real situation.
- D: Admittedly concedes a point against the argument, which does not match the ironic implication.', 'What word captures that admired lines turn out to be the rejected ones?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('81639397-7e34-4c41-ba37-db20c2b3f8b2', 'Which choice completes the text with the most logical transition?', 'Public health officials assumed that distributing free mosquito nets would sharply reduce malaria in the region, and they shipped thousands at considerable cost. Follow-up visits found many of the nets repurposed as fishing gear or fencing for vegetable plots. ______, infection rates in the targeted villages declined only modestly in the campaign''s first year.', NULL, '[{"id":"A","text":"Predictably,","is_correct":true,"explanation":"Predictably signals that the modest decline follows naturally from nets being diverted to non-medical uses."},{"id":"B","text":"Surprisingly,","is_correct":false,"explanation":"Surprisingly implies the outcome is unexpected, but given the misused nets, a modest decline is exactly what one would anticipate."},{"id":"C","text":"Nonetheless,","is_correct":false,"explanation":"Nonetheless marks contrast with the preceding point, but the modest decline aligns with, rather than defies, the net misuse."},{"id":"D","text":"Meanwhile,","is_correct":false,"explanation":"Meanwhile signals a simultaneous unrelated event, but the decline is causally tied to the misused nets."}]'::jsonb, 'A', 'Step 1 — Find the cause
Many nets were {{yellow:repurposed as fishing gear or fencing for vegetable plots}}.
Step 2 — Why Predictably
Since the nets were not used as intended, the small drop in infections is an expected result, so ''Predictably'' fits.
Distractor analysis:
- B: Surprisingly would suit an unexpected outcome, but this result was foreseeable.
- C: Nonetheless signals contrast, yet the modest decline agrees with the misuse evidence.
- D: Meanwhile implies an unrelated concurrent event, but the decline stems directly from the misuse.', 'Given that nets were not used for sleeping, is the small decline expected or shocking?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
