INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e4138cd7-0494-4022-99c5-44fcdc57edb5', 'Which choice completes the text with the most logical transition?', 'The committee revising the city charter wanted a document citizens could actually read, so they pruned its dense legal clauses into plain sentences. Legal scholars warned that some pruned phrases had carried precise meanings courts had refined over decades. ______, simplifying the language risked stripping away protections that the original wording had quietly guaranteed.', NULL, '[{"id":"A","text":"Even so,","is_correct":false,"explanation":"Even so concedes despite a prior point, but the final sentence develops the scholars'' warning rather than pushing against it."},{"id":"B","text":"In other words,","is_correct":true,"explanation":"In other words restates the scholars'' warning, spelling out what the loss of refined legal phrasing entails."},{"id":"C","text":"Instead,","is_correct":false,"explanation":"Instead substitutes an alternative, but the sentence clarifies the warning rather than replacing it."},{"id":"D","text":"On the contrary,","is_correct":false,"explanation":"On the contrary contradicts a prior claim, yet the sentence reinforces and explains the scholars'' concern."}]'::jsonb, 'B', 'Step 1 — Identify the warning
Scholars warned that pruned phrases carried {{yellow:precise meanings courts had refined over decades}}.
Step 2 — Why In other words
The final sentence restates that warning in plainer terms, explaining the risk of lost protections, so ''In other words'' fits.
Distractor analysis:
- A: Even so concedes against a point, but the sentence elaborates the warning.
- C: Instead replaces an idea with an alternative, which does not occur here.
- D: On the contrary signals contradiction, yet the sentence agrees with the scholars.', 'Is the last sentence opposing the scholars or restating their point more plainly?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f0a9f124-479f-4cf2-9ef5-06cb193e30ef', 'Which choice completes the text with the most logical transition?', 'Archaeologists dating the settlement relied on charcoal from its hearths, which yielded an age of roughly three thousand years. They later realized the inhabitants had burned ancient driftwood, timber that had died long before it was gathered. ______, the charcoal dates record when the trees perished, not when the settlers lit their fires.', NULL, '[{"id":"A","text":"Likewise,","is_correct":false,"explanation":"Likewise adds a parallel point, but the sentence draws a consequence from the driftwood discovery."},{"id":"B","text":"In short,","is_correct":true,"explanation":"In short distills the implication of burning long-dead driftwood: the dates time the trees'' death, not the settlement."},{"id":"C","text":"Conversely,","is_correct":false,"explanation":"Conversely flags an opposite case, but the sentence states the direct consequence of the prior fact."},{"id":"D","text":"Granted,","is_correct":false,"explanation":"Granted concedes a counterpoint, yet the sentence asserts the conclusion the evidence compels."}]'::jsonb, 'B', 'Step 1 — Find the key fact
The settlers burned driftwood {{yellow:that had died long before it was gathered}}.
Step 2 — Why In short
The final sentence summarizes the upshot that the dates reflect the wood''s death, not the fire, so the summarizing ''In short'' fits.
Distractor analysis:
- A: Likewise needs a parallel claim, but this is a conclusion drawn from the fact.
- C: Conversely requires an opposite, which is absent.
- D: Granted concedes against the point, but the sentence affirms the implication.', 'Is the last sentence summing up the consequence or adding a parallel?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e1fb01e5-77c4-4981-aaea-ba2ae6aa65bf', 'Which choice completes the text with the most logical transition?', 'Reformers in the early factory town believed that installing gaslight would let mills run longer and lift workers'' wages. The longer shifts did raise output, yet owners pocketed the gains while extending the workday past nightfall. ______, the very technology meant to enrich laborers became an instrument for demanding more of their time for the same pay.', NULL, '[{"id":"A","text":"As a result,","is_correct":false,"explanation":"As a result marks a causal outcome, but the sentence underscores an ironic reversal rather than a straightforward effect."},{"id":"B","text":"Specifically,","is_correct":false,"explanation":"Specifically narrows to a detail, yet the sentence broadens to the overarching irony of the situation."},{"id":"C","text":"In effect,","is_correct":true,"explanation":"In effect captures the net upshot: the technology functioned to extract more labor, contrary to its intended purpose."},{"id":"D","text":"Otherwise,","is_correct":false,"explanation":"Otherwise introduces a hypothetical alternative, but the sentence describes what actually happened."}]'::jsonb, 'C', 'Step 1 — Find the reversal
Owners {{yellow:pocketed the gains while extending the workday past nightfall}}.
Step 2 — Why In effect
The final sentence states the practical net result that the technology served to demand more labor, so ''In effect'' fits.
Distractor analysis:
- A: As a result implies a simple consequence, but the sentence stresses an ironic net outcome better signaled by ''In effect.''
- B: Specifically points to a narrower detail, but the sentence generalizes.
- D: Otherwise posits a hypothetical, while this is the actual outcome.', 'Which phrase best states the practical net upshot of the gaslight''s misuse?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('135bf735-4405-4a39-9f2e-cce7559cc2cf', 'Which choice completes the text with the most logical transition?', 'A psychologist proposed that people remember emotionally charged events more accurately than ordinary ones because strong feelings sharpen attention. Subsequent studies found that witnesses to frightening events often recall vivid but mistaken details with great confidence. ______, intense emotion appears to strengthen the feeling of remembering without strengthening the accuracy of the memory itself.', NULL, '[{"id":"A","text":"Accordingly,","is_correct":false,"explanation":"Accordingly signals a result consistent with the psychologist''s claim, but the finding undercuts that claim."},{"id":"B","text":"Thus,","is_correct":false,"explanation":"Thus draws a conclusion supporting the prior reasoning, but the sentence revises rather than confirms the original hypothesis."},{"id":"C","text":"Rather,","is_correct":true,"explanation":"Rather corrects the original hypothesis, replacing ''sharper accuracy'' with ''stronger feeling but not accuracy.''"},{"id":"D","text":"Furthermore,","is_correct":false,"explanation":"Furthermore adds a supporting point, but the sentence overturns the initial proposal instead of bolstering it."}]'::jsonb, 'C', 'Step 1 — Find the contradicting evidence
Witnesses recall {{yellow:vivid but mistaken details with great confidence}}.
Step 2 — Why Rather
The final sentence corrects the psychologist''s claim, asserting emotion boosts the sense of remembering, not accuracy, so the corrective ''Rather'' fits.
Distractor analysis:
- A: Accordingly implies agreement with the original claim, which the evidence refutes.
- B: Thus signals a conclusion confirming prior reasoning, but the sentence revises it.
- D: Furthermore adds support, yet the sentence corrects rather than supplements.', 'Does the last sentence confirm the original claim or replace it with a corrected version?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('142162a1-7c18-44fb-a078-6c132347cc5e', 'Which choice completes the text with the most logical transition?', 'City planners praised the new riverside park for drawing crowds and raising the value of nearby buildings. As property values climbed, longtime residents found their rents rising beyond what they could afford and began moving away. ______, the amenity celebrated for revitalizing the neighborhood was hollowing out the community it was built to serve.', NULL, '[{"id":"A","text":"Paradoxically,","is_correct":true,"explanation":"Paradoxically captures the self-undermining outcome: the park''s success drove out the residents it aimed to benefit."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Therefore marks a plain conclusion, but the sentence highlights a contradictory, self-defeating result."},{"id":"C","text":"For example,","is_correct":false,"explanation":"For example introduces an illustration of a prior point, but the sentence states an overarching irony."},{"id":"D","text":"Likewise,","is_correct":false,"explanation":"Likewise adds a parallel case, yet the sentence presents a single ironic outcome, not a parallel."}]'::jsonb, 'A', 'Step 1 — Find the contradiction
Residents found rents {{yellow:rising beyond what they could afford}} and moved away.
Step 2 — Why Paradoxically
The final sentence names the self-defeating irony that revitalization emptied the community, so ''Paradoxically'' fits.
Distractor analysis:
- B: Therefore signals a straightforward result, missing the contradiction the sentence stresses.
- C: For example needs an illustrative instance, but this is a general irony.
- D: Likewise requires a parallel, which is absent.', 'Which word marks that the park''s success undermined its own purpose?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('de116abc-8b61-44e8-9336-24202f9f219b', 'Which choice completes the text with the most logical transition?', 'Translators of the ancient epic disagreed over a single recurring word that could mean either "cunning" or "resourceful." One scholar argued that the poet, who praised the hero throughout, surely intended the flattering sense. A rival noted that the same poet repeatedly mocked the hero''s habit of lying to allies. ______, the supposedly admiring epithet may have carried a barb its translators had smoothed away.', NULL, '[{"id":"A","text":"Undeniably,","is_correct":false,"explanation":"Undeniably asserts certainty, but the sentence offers a tentative possibility raised by the rival''s evidence."},{"id":"B","text":"If so,","is_correct":true,"explanation":"If so makes the conclusion conditional on the rival''s observation that the poet mocked the hero, suiting the hedged claim."},{"id":"C","text":"Regardless,","is_correct":false,"explanation":"Regardless dismisses the preceding point, but the sentence depends on the rival''s point to draw its inference."},{"id":"D","text":"Even then,","is_correct":false,"explanation":"Even then concedes a point still holds despite a condition, but the sentence builds directly on the condition, not against it."}]'::jsonb, 'B', 'Step 1 — Find the conditional basis
The rival noted the poet {{yellow:repeatedly mocked the hero''s habit of lying to allies}}.
Step 2 — Why If so
The final sentence draws its inference contingent on the rival''s claim being true, so the conditional ''If so'' fits.
Distractor analysis:
- A: Undeniably overstates certainty for a ''may have'' claim.
- C: Regardless brushes aside the rival''s point, but the sentence relies on it.
- D: Even then implies persistence despite the condition, but the sentence follows from the condition.', 'The conclusion uses ''may have'' and rests on the rival''s point — which word makes it conditional?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d2c36c95-b0ed-422c-a8f0-eb0bc3f9998b', 'Which choice completes the text with the most logical transition?', 'A startup claimed its algorithm could screen job applicants more fairly than human recruiters by ignoring names and photographs. Auditors discovered that the system had learned to favor candidates whose hobbies and zip codes correlated with the firm''s mostly affluent past hires. ______, an approach designed to erase bias had merely relocated it to variables that looked neutral on their surface.', NULL, '[{"id":"A","text":"In fact,","is_correct":true,"explanation":"In fact intensifies and confirms the troubling reality the audit exposed, sharpening that the bias was relocated, not removed."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Nevertheless signals contrast, but the sentence reinforces the audit''s finding rather than opposing it."},{"id":"C","text":"By contrast,","is_correct":false,"explanation":"By contrast sets two things in opposition, but the sentence restates and strengthens the same point."},{"id":"D","text":"Hopefully,","is_correct":false,"explanation":"Hopefully expresses a wish, which does not fit a sentence stating an established negative finding."}]'::jsonb, 'A', 'Step 1 — Find the audit finding
The system favored candidates whose {{yellow:hobbies and zip codes correlated with the firm''s mostly affluent past hires}}.
Step 2 — Why In fact
The final sentence drives home the stronger truth that bias was relocated, not erased, so the intensifying ''In fact'' fits.
Distractor analysis:
- B: Nevertheless implies contrast, but the sentence agrees with and amplifies the finding.
- C: By contrast needs opposition, which is absent.
- D: Hopefully voices a wish, inappropriate for a stated negative result.', 'Does the last sentence push back on the audit or drive its point home more forcefully?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('69e6a12a-437b-455c-a537-2e5a34caf57e', 'Which choice completes the text with the most logical transition?', 'Conservators restoring the fresco assumed that its faded blue pigments had simply darkened with age, and they prepared solvents calibrated to lift centuries of grime. When chemical analysis revealed that the artist had used an unstable copper compound that chemically transforms into a near-black mineral, the team realized the murky tones were not surface dirt at all. ______ no amount of cleaning could restore the luminous sky the painter had originally intended.', NULL, '[{"id":"A","text":"Consequently,","is_correct":true,"explanation":"Correct: the discovery that the darkness is intrinsic to the pigment is the cause from which the impossibility of restoration logically follows."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: this signals contrast, but the final sentence is a consequence of the discovery, not a reversal of it."},{"id":"C","text":"For instance,","is_correct":false,"explanation":"Wrong: the final sentence is not an example of the preceding claim but its result."},{"id":"D","text":"Similarly,","is_correct":false,"explanation":"Wrong: ''Similarly'' implies a parallel case, but no second comparable situation is introduced."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The text establishes that {{yellow:the murky tones were not surface dirt at all}} but a chemical transformation within the pigment itself.
Step 2 — Why ''Consequently'' follows
Because the darkness is built into the mineral rather than sitting on top of it, the inability to clean it away is a direct effect; ''Consequently'' marks that cause-to-effect link.
Distractor analysis:
- B: ''Nevertheless'' signals contrast, but the closing sentence agrees with and extends the discovery rather than opposing it.
- C: ''For instance'' would require the final sentence to exemplify a general claim, but it states an outcome.
- D: ''Similarly'' needs a second analogous case, which the passage never supplies.', 'Is the last sentence a result of the discovery, or does it push against it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f498fbb6-e5fa-438e-aecd-c565b10d2bec', 'Which choice completes the text with the most logical transition?', 'Economists once predicted that as households grew wealthier they would inevitably consume more energy, and for decades national data seemed to confirm this tight coupling. In several advanced economies after 2000, however, total energy use flattened or fell even as incomes climbed. ______ the relationship that earlier models treated as a fixed law turned out to depend on policy, technology, and the particular industries a country chose to retain.', NULL, '[{"id":"A","text":"In other words,","is_correct":true,"explanation":"Correct: the final sentence restates and interprets the meaning of the decoupling just described."},{"id":"B","text":"By contrast,","is_correct":false,"explanation":"Wrong: the final sentence elaborates on the same finding rather than contrasting with it."},{"id":"C","text":"Granted,","is_correct":false,"explanation":"Wrong: ''Granted'' concedes a point to an opposing view, but no counterargument is being acknowledged here."},{"id":"D","text":"Meanwhile,","is_correct":false,"explanation":"Wrong: ''Meanwhile'' marks a simultaneous separate event, not a restatement of the same one."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence reports that {{yellow:total energy use flattened or fell even as incomes climbed}}, breaking the assumed coupling.
Step 2 — Why ''In other words'' follows
The final sentence reinterprets that same observation, explaining what the broken coupling means; ''In other words'' signals restatement and clarification.
Distractor analysis:
- B: ''By contrast'' would set the sentences in opposition, but they describe the same phenomenon from a deeper angle.
- C: ''Granted'' concedes ground to a rival claim, yet the passage is not conceding anything.
- D: ''Meanwhile'' implies a distinct concurrent event rather than a clarification.', 'Does the last sentence add a new contrast, or explain what the trend really means?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cf96eea4-570a-4679-93f0-a504dbca133b', 'Which choice completes the text with the most logical transition?', 'Marine biologists had long catalogued the bobtail squid''s glow as a tool for evading predators lurking below, since the light erases the squid''s silhouette against moonlit water. Recent observations show the squid dimming and brightening this same glow in precise rhythms while approaching potential mates. ______ a feature first understood purely as camouflage appears to serve a second, social purpose the early studies overlooked.', NULL, '[{"id":"A","text":"Thus,","is_correct":true,"explanation":"Correct: the new courtship observation leads to the conclusion that the glow has an additional function."},{"id":"B","text":"Even so,","is_correct":false,"explanation":"Wrong: ''Even so'' concedes despite an obstacle, but the final sentence is the straightforward upshot of the observation."},{"id":"C","text":"Conversely,","is_correct":false,"explanation":"Wrong: nothing in the final sentence reverses or opposes the courtship finding."},{"id":"D","text":"Admittedly,","is_correct":false,"explanation":"Wrong: ''Admittedly'' concedes a weakness, but the sentence asserts a positive conclusion."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence notes the squid {{yellow:dimming and brightening this same glow in precise rhythms while approaching potential mates}}.
Step 2 — Why ''Thus'' follows
That behavior is evidence from which the conclusion of a second, social function is drawn; ''Thus'' marks the inference.
Distractor analysis:
- B: ''Even so'' implies the conclusion holds in spite of resistance, but the data point straight toward it.
- C: ''Conversely'' demands an opposite idea, which is absent.
- D: ''Admittedly'' would concede a flaw, yet the sentence states a finding, not a limitation.', 'Is the final sentence the logical takeaway from the rhythmic glowing, or a concession?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ca05e5f2-8737-4800-99cd-77743a8dc7d9', 'Which choice completes the text with the most logical transition?', 'The novelist''s early drafts, recently donated to a university archive, are crowded with elaborate descriptions of weather that never appear in the published book. Some scholars have read their absence as evidence that an editor pressured her to cut them. ______ her own marginal notes show that she struck the passages herself, convinced that the storms distracted from her characters'' quieter turmoil.', NULL, '[{"id":"A","text":"In fact,","is_correct":true,"explanation":"Correct: the marginal notes overturn the editor theory with a stronger, more direct counter-truth."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Wrong: the final sentence contradicts the editor hypothesis rather than following from it."},{"id":"C","text":"Likewise,","is_correct":false,"explanation":"Wrong: ''Likewise'' signals agreement, but the notes refute the scholars'' reading."},{"id":"D","text":"Accordingly,","is_correct":false,"explanation":"Wrong: ''Accordingly'' marks a consequence of the prior claim, yet this sentence opposes it."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
Scholars believe an editor forced the cuts, but the notes reveal {{yellow:she struck the passages herself}} for artistic reasons.
Step 2 — Why ''In fact'' follows
The sentence corrects the speculation with the actual evidence, intensifying the contrast; ''In fact'' introduces this corrective truth.
Distractor analysis:
- B: ''Therefore'' would make the self-editing a consequence of the editor theory, but it disproves that theory.
- C: ''Likewise'' implies the notes echo the scholars, when they contradict them.
- D: ''Accordingly'' signals a result that aligns with the prior claim, which is not the case.', 'Do the marginal notes confirm the editor theory or quietly demolish it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('af708ae6-f497-459d-8e97-0b0b3df4cc1a', 'Which choice completes the text with the most logical transition?', 'Archaeologists excavating the desert outpost expected to find that its inhabitants had abandoned the site abruptly during a drought, leaving food and tools behind in a panic. Instead, the storerooms were swept clean, doorways were sealed with care, and ritual objects had been removed for reuse elsewhere. ______ the departure looks less like flight than like a deliberate, well-planned relocation.', NULL, '[{"id":"A","text":"All in all,","is_correct":true,"explanation":"Correct: the sentence sums up the catalogued clues into a single overarching interpretation."},{"id":"B","text":"However,","is_correct":false,"explanation":"Wrong: the final sentence agrees with and synthesizes the evidence rather than contrasting it."},{"id":"C","text":"For example,","is_correct":false,"explanation":"Wrong: it generalizes from the details rather than offering one instance of them."},{"id":"D","text":"Instead,","is_correct":false,"explanation":"Wrong: ''Instead'' was already used to overturn the original expectation; the closing sentence summarizes, not substitutes."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The middle sentence lists clean storerooms, sealed doorways, and that {{yellow:ritual objects had been removed for reuse elsewhere}}.
Step 2 — Why ''All in all'' follows
The final sentence gathers those separate observations into one summary judgment; ''All in all'' signals that cumulative wrap-up.
Distractor analysis:
- B: ''However'' implies contrast, but the conclusion is consistent with the evidence.
- C: ''For example'' would make the conclusion a single illustration, when it is a synthesis.
- D: ''Instead'' marks substitution of one idea for another, not a summary of multiple clues.', 'Does the last sentence pull the listed clues together, or push against them?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b43afc07-5fc8-42be-9778-d094c50b99f5', 'Which choice completes the text with the most logical transition?', 'A widely cited study reported that students who took handwritten notes outperformed those who typed, and the finding was quickly repackaged into advice to ban laptops in lecture halls. When researchers later attempted to reproduce the effect across larger and more varied classrooms, the gap between the two groups all but vanished. ______ the original result may have reflected the particular students and courses sampled rather than any general advantage of the pen.', NULL, '[{"id":"A","text":"As a result,","is_correct":true,"explanation":"Correct: the failed replication leads to the cautious reinterpretation of the original finding."},{"id":"B","text":"Still,","is_correct":false,"explanation":"Wrong: ''Still'' would defend the original claim, but the sentence undercuts it."},{"id":"C","text":"Notably,","is_correct":false,"explanation":"Wrong: ''Notably'' merely flags emphasis and misses the causal link to the replication."},{"id":"D","text":"In contrast,","is_correct":false,"explanation":"Wrong: the final sentence is an inference from the replication, not a contrast to it."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The second sentence reports that in replication {{yellow:the gap between the two groups all but vanished}}.
Step 2 — Why ''As a result'' follows
Because the effect disappeared, the reasonable consequence is to doubt the generality of the first study; ''As a result'' marks that cause-to-conclusion move.
Distractor analysis:
- B: ''Still'' signals persistence of the original claim against challenge, but the sentence weakens it.
- C: ''Notably'' adds emphasis without expressing the causal relationship the passage requires.
- D: ''In contrast'' would oppose the replication, yet the sentence draws a conclusion from it.', 'Does the disappearing gap cause the doubt in the last sentence, or stand against it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1d6e898c-2e76-4a32-bc03-6461c91d1260', 'Which choice completes the text with the most logical transition?', 'The senator''s biographers tend to portray her landmark labor bill as the product of a sudden moral awakening late in her career. Her correspondence, however, reveals that she had been quietly drafting nearly identical provisions for almost two decades, shelving them whenever the political winds turned. ______ the legislation that observers called a dramatic conversion was in truth the patient harvest of a long-held conviction.', NULL, '[{"id":"A","text":"Indeed,","is_correct":true,"explanation":"Correct: the final sentence affirms and intensifies the point that her conviction was long-standing, not sudden."},{"id":"B","text":"Otherwise,","is_correct":false,"explanation":"Wrong: ''Otherwise'' introduces an alternative condition, which the sentence does not do."},{"id":"C","text":"Nonetheless,","is_correct":false,"explanation":"Wrong: the final sentence reinforces the correspondence evidence rather than conceding against it."},{"id":"D","text":"Conversely,","is_correct":false,"explanation":"Wrong: the sentence does not state the opposite of the prior point but strengthens it."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The correspondence shows she had been {{yellow:quietly drafting nearly identical provisions for almost two decades}}.
Step 2 — Why ''Indeed'' follows
The final sentence drives that same point home with emphatic confirmation, reframing the ''conversion'' as a long conviction; ''Indeed'' signals this affirming intensification.
Distractor analysis:
- B: ''Otherwise'' would introduce a hypothetical alternative, which is irrelevant here.
- C: ''Nonetheless'' signals concession against the evidence, but the sentence agrees with it.
- D: ''Conversely'' requires an opposite idea, while the sentence restates the same one more forcefully.', 'Does the closing sentence echo and strengthen the letters'' evidence, or push against it?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b6f26cc4-8d5d-4926-93eb-53a80fd7c458', 'Which choice completes the text with the most logical transition?', 'Designers of the new transit app assumed riders would prize speed above all, so they built the interface to surface the single fastest route in bold at the top of every screen. User interviews soon complicated that picture: many commuters cared less about saving three minutes than about avoiding crowded transfers and unlit stations after dark. ______ the team did not abandon the fastest-route feature, which a large minority still ranked as their top priority.', NULL, '[{"id":"A","text":"Still,","is_correct":true,"explanation":"Correct: despite the interviews favoring other factors, the team kept the speed feature, a concessive turn."},{"id":"B","text":"Therefore,","is_correct":false,"explanation":"Wrong: keeping the feature is not a logical result of riders preferring other factors."},{"id":"C","text":"Likewise,","is_correct":false,"explanation":"Wrong: ''Likewise'' signals agreement, but the sentence runs counter to the interview trend."},{"id":"D","text":"Hence,","is_correct":false,"explanation":"Wrong: ''Hence'' marks a consequence, yet retaining speed contradicts the stated preference."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The interviews revealed many commuters cared about {{yellow:avoiding crowded transfers and unlit stations after dark}} rather than speed.
Step 2 — Why ''Still'' follows
Even though the data deprioritized speed, the team retained the feature; ''Still'' expresses that concessive persistence against the trend.
Distractor analysis:
- B: ''Therefore'' would make retention a consequence of riders preferring other things, which is backwards.
- C: ''Likewise'' implies the sentence agrees with the interviews, but it pushes the other way.
- D: ''Hence'' signals a result that follows from the prior idea, contradicting the logic here.', 'Does keeping the speed feature follow from the interviews, or hold out against them?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('9fb26b29-64bb-4a27-9a6c-0b2854adf29e', 'Which choice completes the text with the most logical transition?', 'For years, agronomists treated the crumbling structure of the region''s overworked soils as an irreversible loss, a slow death that fertilizer could mask but never cure. A small group of farmers began leaving fields unplowed and seeding them with deep-rooted cover crops between harvests. ______ within a few seasons earthworms returned, water soaked in rather than running off, and the soil that experts had written off began to rebuild itself.', NULL, '[{"id":"A","text":"Remarkably,","is_correct":true,"explanation":"Correct: the soil''s recovery is surprising given that experts had called the damage irreversible."},{"id":"B","text":"Predictably,","is_correct":false,"explanation":"Wrong: the outcome contradicts the prior expectation of irreversibility, so it is not predictable."},{"id":"C","text":"Consequently,","is_correct":false,"explanation":"Wrong: while causal, it ignores the central tension that the result defied the experts'' verdict."},{"id":"D","text":"In summary,","is_correct":false,"explanation":"Wrong: the sentence introduces new outcomes rather than summarizing prior points."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
Agronomists had treated the damage as {{yellow:an irreversible loss}} that nothing could cure.
Step 2 — Why ''Remarkably'' follows
The soil rebuilding itself is unexpected precisely because it overturns that verdict; ''Remarkably'' captures the surprise of the contrast.
Distractor analysis:
- B: ''Predictably'' clashes with the setup, since experts expected no recovery at all.
- C: ''Consequently'' states bare causation but misses the surprising reversal the passage emphasizes.
- D: ''In summary'' would recap earlier content, but the sentence delivers fresh, contrary results.', 'Given that experts called the loss permanent, how should the recovery strike the reader?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b820cc9c-e555-441a-b582-2fb01b5906bd', 'Which choice completes the text with the most logical transition?', 'Historians of early radio often credit a single inventor with creating the technology, framing the breakthrough as one mind''s leap. The surviving patent records tell a messier story of dozens of tinkerers in several countries arriving at overlapping pieces within the same few years. ______ assigning the invention to one person obscures how thoroughly the discovery was woven into the shared technical conversation of its age.', NULL, '[{"id":"A","text":"Thus,","is_correct":true,"explanation":"Correct: the messy patent record leads to the conclusion that single-inventor credit is misleading."},{"id":"B","text":"Nevertheless,","is_correct":false,"explanation":"Wrong: the final sentence follows from the patent evidence rather than contrasting with it."},{"id":"C","text":"For instance,","is_correct":false,"explanation":"Wrong: the sentence is a conclusion, not an example of the patent records."},{"id":"D","text":"Meanwhile,","is_correct":false,"explanation":"Wrong: ''Meanwhile'' marks a concurrent event, not the inference being drawn."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The records describe {{yellow:dozens of tinkerers in several countries arriving at overlapping pieces within the same few years}}.
Step 2 — Why ''Thus'' follows
From that distributed pattern, it follows that crediting one inventor distorts the history; ''Thus'' marks the conclusion drawn from the evidence.
Distractor analysis:
- B: ''Nevertheless'' implies the conclusion holds despite the evidence, but it grows directly out of it.
- C: ''For instance'' would make the sentence an example, when it is an inference.
- D: ''Meanwhile'' signals a simultaneous separate development, not a logical consequence.', 'Does the single-inventor critique follow from the scattered patents, or resist them?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('3f4b1eb7-6cdf-4ff0-8ee9-63f2f5c1d9a5', 'Which choice completes the text with the most logical transition?', 'Critics praised the playwright''s final work for its bleak, minimalist staging, reading the empty set as a bold statement about human isolation. Production records from the original run reveal that the bare stage was a budgetary necessity after the theater''s funding collapsed weeks before opening. ______ what audiences received as a daring aesthetic choice began as a scramble to mount the show with almost nothing.', NULL, '[{"id":"A","text":"In reality,","is_correct":true,"explanation":"Correct: the sentence replaces the interpretive myth with the factual origin of the bare stage."},{"id":"B","text":"As a result,","is_correct":false,"explanation":"Wrong: the budget crisis is not a consequence of critics'' praise; the sentence corrects the praise."},{"id":"C","text":"Similarly,","is_correct":false,"explanation":"Wrong: ''Similarly'' implies agreement, but the records undercut the critics'' reading."},{"id":"D","text":"Furthermore,","is_correct":false,"explanation":"Wrong: ''Furthermore'' adds a supporting point, yet the sentence reverses the critics'' interpretation."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The records show the bare stage was {{yellow:a budgetary necessity after the theater''s funding collapsed}}, not an artistic statement.
Step 2 — Why ''In reality'' follows
The final sentence corrects the critics'' romantic reading with the true cause; ''In reality'' introduces the factual rebuttal.
Distractor analysis:
- B: ''As a result'' would make the funding collapse a consequence of the praise, which is illogical.
- C: ''Similarly'' implies the sentence agrees with the critics, when it contradicts them.
- D: ''Furthermore'' adds reinforcement, but the sentence overturns rather than supports the prior claim.', 'Does the last sentence add to the critics'' praise or reveal what really caused the bare stage?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ae3e6974-6abd-4b38-be87-b324ebec4966', 'Which choice completes the text with the most logical transition?', 'Public health planners assumed that opening more clinics in the underserved district would steadily raise vaccination rates, and for the first year attendance did climb. Then the numbers stalled, even as new clinics kept opening, because the remaining unvaccinated residents distrusted the program rather than lacked access to it. ______ building additional facilities, however well intentioned, could do nothing to close a gap that was rooted in skepticism, not distance.', NULL, '[{"id":"A","text":"Accordingly,","is_correct":true,"explanation":"Correct: because the barrier was trust rather than access, it follows that more buildings cannot help."},{"id":"B","text":"Conversely,","is_correct":false,"explanation":"Wrong: the final sentence is a consequence of the trust finding, not its opposite."},{"id":"C","text":"Granted,","is_correct":false,"explanation":"Wrong: ''Granted'' concedes to a counterclaim, but the sentence draws a conclusion instead."},{"id":"D","text":"By comparison,","is_correct":false,"explanation":"Wrong: ''By comparison'' sets up a parallel, yet no second case is being measured."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
The stall happened because residents {{yellow:distrusted the program rather than lacked access to it}}.
Step 2 — Why ''Accordingly'' follows
Given that the real barrier is skepticism, it logically follows that adding clinics cannot fix it; ''Accordingly'' marks that cause-to-conclusion link.
Distractor analysis:
- B: ''Conversely'' demands an opposing idea, but the sentence follows from the trust diagnosis.
- C: ''Granted'' would concede to a rival view, which is not happening here.
- D: ''By comparison'' needs a second case to compare, which the passage does not provide.', 'If the problem is distrust, not distance, what naturally follows about new buildings?', 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', NULL, 'hard', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('ea380483-fc93-4a6f-bcb4-a828cd00036b', 'The student wants to emphasize the great distance monarch butterflies travel during their fall migration. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Monarch Butterfly Migration
- Monarch butterflies travel up to 3,000 miles each fall.
- They migrate from Canada and the United States to central Mexico.
- No single butterfly completes the entire round trip.
- It takes several generations to finish the full migration cycle.
- Scientists are studying how monarchs navigate over such long distances.', NULL, '[{"id":"A","text":"Monarch butterflies travel up to 3,000 miles each fall during their migration.","is_correct":true,"explanation":"Correct: it directly states the 3,000-mile distance, emphasizing how far the butterflies travel."},{"id":"B","text":"Scientists are studying how monarchs navigate over long distances.","is_correct":false,"explanation":"This focuses on scientific study, not on emphasizing the distance traveled."},{"id":"C","text":"No single monarch butterfly completes the entire round trip.","is_correct":false,"explanation":"This addresses which butterfly finishes the trip, not the great distance itself."},{"id":"D","text":"Monarch butterflies migrate from Canada and the United States to central Mexico.","is_correct":false,"explanation":"This names the locations but does not emphasize the great distance with a measurement."}]'::jsonb, 'A', 'Step 1 — Find the distance detail
The notes state that {{yellow:Monarch butterflies travel up to 3,000 miles each fall}}.
Step 2 — Match the goal
Choice A uses that exact figure to emphasize the great distance, which is exactly the rhetorical goal.
Distractor analysis:
- B: True but irrelevant; it discusses navigation research, not distance.
- C: True but addresses who completes the trip, not the distance traveled.
- D: Names origin and destination but gives no measurement to emphasize great distance.', 'Look for the bullet that gives a specific number of miles.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('67b2fd74-02df-4db4-864a-ad92aec33725', 'The student wants to explain how the printing press changed the speed of producing books. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Invention of the Printing Press
- Johannes Gutenberg developed his printing press around 1440 in Germany.
- Before the press, books were copied slowly by hand.
- The press allowed many copies of a text to be made quickly.
- This made books cheaper and more widely available.
- More people learned to read as books spread across Europe.', NULL, '[{"id":"A","text":"Johannes Gutenberg developed his printing press around 1440 in Germany.","is_correct":false,"explanation":"This gives the inventor and date, not the change in speed of production."},{"id":"B","text":"Before the press, books were copied slowly by hand, but the press allowed many copies to be made quickly.","is_correct":true,"explanation":"Correct: it contrasts the slow hand copying with the fast press, directly explaining the change in speed."},{"id":"C","text":"As books spread across Europe, more people learned to read.","is_correct":false,"explanation":"This addresses literacy, not the speed of producing books."},{"id":"D","text":"The press made books cheaper and more widely available.","is_correct":false,"explanation":"This addresses cost and availability, not the speed of production."}]'::jsonb, 'B', 'Step 1 — Find the speed contrast
The notes state that {{yellow:Before the press, books were copied slowly by hand}} and that the press let copies be made quickly.
Step 2 — Match the goal
Choice B pairs those two notes to show how the speed of book production changed, fulfilling the goal.
Distractor analysis:
- A: Gives inventor and date, not a change in speed.
- C: Focuses on literacy spreading, not production speed.
- D: Focuses on cost and availability, not speed.', 'Look for the note that contrasts slow copying with fast copying.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('fba78dfb-84ec-413f-b431-ecaf870897f1', 'The student wants to highlight how many ocean species rely on coral reefs despite the reefs'' small size. Which choice most effectively uses information from the notes to accomplish this goal?', 'Coral Reefs and Ocean Life
- Coral reefs cover less than one percent of the ocean floor.
- They provide a home for about one quarter of all ocean species.
- Reefs are built by tiny animals called coral polyps.
- Warmer water can cause corals to lose their color, an event called bleaching.
- Many groups are working to protect reefs from damage.', NULL, '[{"id":"A","text":"Coral reefs are built by tiny animals called coral polyps.","is_correct":false,"explanation":"This explains what builds reefs, not how many species depend on them relative to their size."},{"id":"B","text":"Many groups are working to protect coral reefs from damage.","is_correct":false,"explanation":"This addresses conservation efforts, not the contrast between size and number of species."},{"id":"C","text":"Although coral reefs cover less than one percent of the ocean floor, they provide a home for about one quarter of all ocean species.","is_correct":true,"explanation":"Correct: it contrasts the small area with the large share of species, exactly the intended emphasis."},{"id":"D","text":"Warmer water can cause corals to lose their color in an event called bleaching.","is_correct":false,"explanation":"This describes bleaching, not the size-versus-species contrast."}]'::jsonb, 'C', 'Step 1 — Find the two contrasting facts
The notes say reefs {{yellow:cover less than one percent of the ocean floor}} yet host about a quarter of ocean species.
Step 2 — Match the goal
Choice C joins the small size with the large number of species, achieving the contrast the goal requires.
Distractor analysis:
- A: Describes coral polyps, not the size-species contrast.
- B: Discusses protection efforts, not species dependence.
- D: Explains bleaching, unrelated to the goal.', 'Find the note that pairs the reefs'' tiny area with a large fraction of species.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('543e6afc-afc7-4076-a1b0-a690031e1bfb', 'The student wants to introduce Harriet Tubman''s role in the Underground Railroad to an audience unfamiliar with it. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Underground Railroad
- The Underground Railroad was a secret network that helped enslaved people escape to freedom.
- It was most active in the United States during the 1800s.
- Helpers, called conductors, guided travelers along hidden routes.
- Harriet Tubman was one of the most famous conductors.
- Many people reached free states or Canada through the network.', NULL, '[{"id":"A","text":"Many people reached free states or Canada through the Underground Railroad.","is_correct":false,"explanation":"This describes the network''s results, not Harriet Tubman''s role."},{"id":"B","text":"Harriet Tubman was one of the most famous conductors, helpers who guided travelers along hidden routes.","is_correct":true,"explanation":"Correct: it introduces Tubman and explains the conductor role for an unfamiliar audience."},{"id":"C","text":"The Underground Railroad was most active in the United States during the 1800s.","is_correct":false,"explanation":"This gives a time and place but does not mention Tubman''s role."},{"id":"D","text":"The Underground Railroad was a secret network that helped enslaved people escape to freedom.","is_correct":false,"explanation":"This defines the network but does not introduce Harriet Tubman."}]'::jsonb, 'B', 'Step 1 — Find the Tubman detail
The notes state that {{yellow:Harriet Tubman was one of the most famous conductors}}.
Step 2 — Match the goal
Choice B names Tubman and explains what a conductor did, introducing her role clearly for new audiences.
Distractor analysis:
- A: Describes outcomes, not Tubman''s role.
- C: Gives time and place only, no mention of Tubman.
- D: Defines the network but omits Tubman entirely.', 'Look for the note that names Harriet Tubman directly.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2a0c62f6-7bd4-4821-96b5-ddf77027bc06', 'The student wants to explain how the light produced by bioluminescent organisms is created. Which choice most effectively uses information from the notes to accomplish this goal?', 'Bioluminescent Organisms
- Some living things can produce their own light, a trait called bioluminescence.
- Many of these organisms live deep in the ocean where sunlight cannot reach.
- Fireflies use their glow to attract mates.
- Certain deep-sea fish use light to lure prey closer.
- The light is made by a chemical reaction inside the organism''s body.', NULL, '[{"id":"A","text":"The light of bioluminescent organisms is made by a chemical reaction inside the organism''s body.","is_correct":true,"explanation":"Correct: it states the chemical reaction, directly explaining how the light is created."},{"id":"B","text":"Many bioluminescent organisms live deep in the ocean where sunlight cannot reach.","is_correct":false,"explanation":"This describes where they live, not how the light is made."},{"id":"C","text":"Fireflies use their glow to attract mates.","is_correct":false,"explanation":"This explains a use of the light, not how it is produced."},{"id":"D","text":"Certain deep-sea fish use light to lure prey closer.","is_correct":false,"explanation":"This describes a use of the light, not its creation."}]'::jsonb, 'A', 'Step 1 — Find the cause of the light
The notes state that {{yellow:The light is made by a chemical reaction inside the organism''s body}}.
Step 2 — Match the goal
Choice A uses that note to explain how the light is created, exactly the rhetorical goal.
Distractor analysis:
- B: Describes habitat, not how light is produced.
- C: Gives a firefly''s purpose for the glow, not its creation.
- D: Gives a fish''s use of light, not how it is made.', 'Find the note that describes a chemical reaction.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('59932ca8-9f8e-4fbd-aced-4c39c238c1b3', 'The student wants to emphasize the durability of ancient Roman roads. Which choice most effectively uses information from the notes to accomplish this goal?', 'Ancient Roman Roads
- The Romans built a vast network of paved roads across their empire.
- Some Roman roads still exist today, more than 2,000 years later.
- The roads were built in layers to make them strong and long-lasting.
- They allowed armies and traders to move quickly between cities.
- The phrase "all roads lead to Rome" comes from this network.', NULL, '[{"id":"A","text":"The Romans built a vast network of paved roads across their empire.","is_correct":false,"explanation":"This describes the network''s size, not its durability over time."},{"id":"B","text":"Roman roads allowed armies and traders to move quickly between cities.","is_correct":false,"explanation":"This addresses speed of travel, not durability."},{"id":"C","text":"Some Roman roads still exist today, more than 2,000 years later.","is_correct":true,"explanation":"Correct: it shows the roads have lasted thousands of years, directly emphasizing durability."},{"id":"D","text":"The phrase \"all roads lead to Rome\" comes from this network.","is_correct":false,"explanation":"This explains the origin of a phrase, not the roads'' durability."}]'::jsonb, 'C', 'Step 1 — Find the durability detail
The notes state that {{yellow:Some Roman roads still exist today, more than 2,000 years later}}.
Step 2 — Match the goal
Choice C uses the roads'' survival across millennia to emphasize durability, fulfilling the goal.
Distractor analysis:
- A: Emphasizes size, not lasting strength.
- B: Emphasizes travel speed, not durability.
- D: Explains a saying, unrelated to durability.', 'Look for the note showing the roads have lasted thousands of years.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('165454d6-d978-45b0-8a33-e00153e23e6e', 'The student wants to explain how Hurston''s training as an anthropologist influenced her writing. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Author Zora Neale Hurston
- Zora Neale Hurston was an American writer born in 1891.
- She trained as an anthropologist and studied folklore.
- She collected stories and songs from communities across the South.
- Her novel Their Eyes Were Watching God is her best-known work.
- Her writing often included the everyday speech of the people she studied.', NULL, '[{"id":"A","text":"Zora Neale Hurston was an American writer born in 1891.","is_correct":false,"explanation":"This gives biographical facts but does not link her training to her writing."},{"id":"B","text":"Her novel Their Eyes Were Watching God is her best-known work.","is_correct":false,"explanation":"This names her famous novel but does not connect anthropology to her writing."},{"id":"C","text":"Trained as an anthropologist, Hurston collected stories and songs and often included the everyday speech of the people she studied in her writing.","is_correct":true,"explanation":"Correct: it links her anthropological training to the speech she put into her writing."},{"id":"D","text":"Hurston collected stories and songs from communities across the South.","is_correct":false,"explanation":"This describes her fieldwork but does not connect it to how she wrote."}]'::jsonb, 'C', 'Step 1 — Find the link between training and writing
The notes say she trained as an anthropologist and that {{yellow:Her writing often included the everyday speech of the people she studied}}.
Step 2 — Match the goal
Choice C connects her anthropological training to the real speech in her writing, fulfilling the goal.
Distractor analysis:
- A: Gives birth facts, no link to her writing.
- B: Names a novel but draws no connection to anthropology.
- D: Describes fieldwork alone without connecting it to her writing.', 'Find the note connecting the people she studied to the speech in her writing.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('b907b593-773a-42c2-a2ec-7fefa60579ea', 'The student wants to explain a physical feature that helps the cheetah run fast. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Speed of Cheetahs
- The cheetah is the fastest land animal on Earth.
- It can run as fast as 70 miles per hour.
- A cheetah can only keep up its top speed for short bursts.
- Its flexible spine helps it take very long strides.
- Cheetahs use their speed to catch fast-moving prey.', NULL, '[{"id":"A","text":"The cheetah is the fastest land animal on Earth.","is_correct":false,"explanation":"This states its ranking, not a physical feature that aids speed."},{"id":"B","text":"The cheetah''s flexible spine helps it take very long strides.","is_correct":true,"explanation":"Correct: it names a physical feature, the flexible spine, that aids the cheetah''s speed."},{"id":"C","text":"A cheetah can only keep up its top speed for short bursts.","is_correct":false,"explanation":"This describes a limit on its speed, not a feature that helps it run fast."},{"id":"D","text":"Cheetahs use their speed to catch fast-moving prey.","is_correct":false,"explanation":"This explains why they run fast, not a physical feature that enables it."}]'::jsonb, 'B', 'Step 1 — Find the physical feature
The notes state that {{yellow:Its flexible spine helps it take very long strides}}.
Step 2 — Match the goal
Choice B names the flexible spine as the feature aiding the cheetah''s speed, exactly the goal.
Distractor analysis:
- A: States a ranking, not a body feature.
- C: Describes a limitation, not an enabling feature.
- D: Gives a purpose for speed, not a physical feature.', 'Look for the note describing a body part that helps the cheetah move.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('47580cc4-44c3-418b-8d14-d247396b6057', 'The student wants to highlight an environmental benefit of using wind turbines. Which choice most effectively uses information from the notes to accomplish this goal?', 'Wind Power
- Wind turbines turn moving air into electricity.
- They produce no air pollution while running.
- A single large turbine can power hundreds of homes.
- Wind does not blow at a steady speed all the time.
- Many countries are building more wind farms each year.', NULL, '[{"id":"A","text":"Wind turbines turn moving air into electricity.","is_correct":false,"explanation":"This explains how turbines work, not an environmental benefit."},{"id":"B","text":"Wind does not blow at a steady speed all the time.","is_correct":false,"explanation":"This points out a drawback, not an environmental benefit."},{"id":"C","text":"Wind turbines produce no air pollution while running.","is_correct":true,"explanation":"Correct: producing no air pollution is an environmental benefit."},{"id":"D","text":"Many countries are building more wind farms each year.","is_correct":false,"explanation":"This describes a trend, not an environmental benefit of the turbines."}]'::jsonb, 'C', 'Step 1 — Find the environmental benefit
The notes state that turbines {{yellow:produce no air pollution while running}}.
Step 2 — Match the goal
Choice C uses that note to highlight a clear environmental benefit, fulfilling the goal.
Distractor analysis:
- A: Explains the mechanism, not a benefit.
- B: States a drawback, the opposite of a benefit.
- D: Reports a growth trend, not an environmental benefit.', 'Find the note about pollution while the turbine runs.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('cee7b017-1753-42bb-b90a-0806e99c8f3d', 'The student wants to specify the direction in which people moved during the Great Migration. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Great Migration
- The Great Migration was the movement of millions of Black Americans within the United States.
- It took place mainly between 1916 and 1970.
- People moved from the rural South to cities in the North and West.
- Many sought better jobs and an escape from harsh laws.
- The movement reshaped the populations of cities like Chicago and Detroit.', NULL, '[{"id":"A","text":"The Great Migration took place mainly between 1916 and 1970.","is_correct":false,"explanation":"This gives the time period, not the direction of movement."},{"id":"B","text":"During the Great Migration, people moved from the rural South to cities in the North and West.","is_correct":true,"explanation":"Correct: it states the direction of movement, from South to North and West."},{"id":"C","text":"Many people sought better jobs and an escape from harsh laws.","is_correct":false,"explanation":"This gives reasons for moving, not the direction."},{"id":"D","text":"The movement reshaped the populations of cities like Chicago and Detroit.","is_correct":false,"explanation":"This describes the effect on cities, not the direction of movement."}]'::jsonb, 'B', 'Step 1 — Find the direction detail
The notes state that {{yellow:People moved from the rural South to cities in the North and West}}.
Step 2 — Match the goal
Choice B uses that note to specify the direction of movement, fulfilling the goal.
Distractor analysis:
- A: Gives dates, not direction.
- C: Gives motives, not direction.
- D: Describes effects on cities, not direction.', 'Look for the note that names where people moved from and to.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2f567949-cf53-4bd1-b381-633ee4f1d162', 'The student wants to explain why honeybees are important to food crops. Which choice most effectively uses information from the notes to accomplish this goal?', 'Honeybees and Pollination
- Honeybees gather nectar from flowers to make honey.
- As they move between flowers, they carry pollen on their bodies.
- This pollen helps many plants produce fruits and seeds.
- A large share of the crops people eat depend on bee pollination.
- Farmers sometimes rent hives to pollinate their fields.', NULL, '[{"id":"A","text":"Honeybees gather nectar from flowers to make honey.","is_correct":false,"explanation":"This explains honey making, not the bees'' importance to food crops."},{"id":"B","text":"A large share of the crops people eat depend on bee pollination.","is_correct":true,"explanation":"Correct: it states that many food crops rely on bee pollination, explaining the bees'' importance."},{"id":"C","text":"Farmers sometimes rent hives to pollinate their fields.","is_correct":false,"explanation":"This describes a farming practice, not why bees are important to crops."},{"id":"D","text":"As honeybees move between flowers, they carry pollen on their bodies.","is_correct":false,"explanation":"This describes how bees move pollen, not their importance to food crops."}]'::jsonb, 'B', 'Step 1 — Find the importance to crops
The notes state that {{yellow:A large share of the crops people eat depend on bee pollination}}.
Step 2 — Match the goal
Choice B uses that note to explain why honeybees matter to food crops, fulfilling the goal.
Distractor analysis:
- A: Explains honey making, not crop importance.
- C: Describes a practice, not the underlying importance.
- D: Describes the mechanism of carrying pollen, not the importance to crops.', 'Find the note linking the crops people eat to bee pollination.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('d500a071-1f89-4286-8a15-2211dccc9f8c', 'The student wants to describe a feature of the original Globe Theatre''s design. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Globe Theatre
- The Globe Theatre was a famous playhouse in London.
- It was built in 1599 for William Shakespeare''s acting company.
- The original building had no roof over its central area.
- Audiences standing in that open space were exposed to the weather.
- A modern copy of the theatre was opened near the original site in 1997.', NULL, '[{"id":"A","text":"The Globe Theatre was a famous playhouse in London.","is_correct":false,"explanation":"This gives its fame and location, not a feature of its design."},{"id":"B","text":"It was built in 1599 for William Shakespeare''s acting company.","is_correct":false,"explanation":"This gives the date and owner, not a design feature."},{"id":"C","text":"The original Globe Theatre had no roof over its central area.","is_correct":true,"explanation":"Correct: the missing roof over the central area is a feature of the building''s design."},{"id":"D","text":"A modern copy of the theatre was opened near the original site in 1997.","is_correct":false,"explanation":"This describes the modern replica, not the original theatre''s design."}]'::jsonb, 'C', 'Step 1 — Find the design feature
The notes state that {{yellow:The original building had no roof over its central area}}.
Step 2 — Match the goal
Choice C uses that note to describe a feature of the original Globe''s design, fulfilling the goal.
Distractor analysis:
- A: Gives location and fame, not a design feature.
- B: Gives date and owner, not a design feature.
- D: Describes the modern copy, not the original design.', 'Look for the note about the central area of the building''s structure.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('2a4c5a5f-d47b-460c-b84a-01363d142c0d', 'The student wants to emphasize the great distance the monarchs travel. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Monarch Butterfly Migration
- Monarch butterflies travel up to 3,000 miles each fall.
- They fly from Canada and the northern United States to central Mexico.
- They spend the winter in oyamel fir forests.
- No single butterfly completes the entire round trip.', NULL, '[{"id":"A","text":"Monarch butterflies travel up to 3,000 miles each fall, flying from Canada and the northern United States to central Mexico.","is_correct":true,"explanation":"Correct: it foregrounds the 3,000-mile distance, directly emphasizing how far the monarchs travel."},{"id":"B","text":"Monarch butterflies spend the winter in oyamel fir forests in central Mexico.","is_correct":false,"explanation":"True but irrelevant: it describes where they winter, not the distance traveled."},{"id":"C","text":"No single monarch butterfly completes the entire round trip of the migration.","is_correct":false,"explanation":"True but off-goal: it stresses individual butterflies'' limits, not the distance covered."},{"id":"D","text":"Monarch butterflies travel each fall to spend the winter in fir forests.","is_correct":false,"explanation":"Too vague: it omits the specific 3,000-mile figure needed to emphasize distance."}]'::jsonb, 'A', 'Step 1 — Find the distance clue
The notes state monarchs {{yellow:travel up to 3,000 miles each fall}}.
Step 2 — Match the goal
Choice A names the 3,000-mile figure and the Canada-to-Mexico route, directly emphasizing how far they travel.
Distractor analysis:
- B: True but focuses on the wintering location, not distance.
- C: True but emphasizes that no single butterfly finishes, not the distance.
- D: Omits the specific mileage, so it fails to emphasize the great distance.', 'Look for the choice that includes the specific number of miles traveled.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('e77d97c2-13e3-4614-a45b-7f59a5056727', 'The student wants to explain how the printing press changed the speed of book production. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Invention of the Printing Press
- Johannes Gutenberg built a printing press around 1440.
- The press used movable metal type.
- Before the press, books were copied by hand, which was slow.
- The press allowed books to be made much faster and in greater numbers.', NULL, '[{"id":"A","text":"Gutenberg built his printing press around 1440, near the middle of the fifteenth century.","is_correct":false,"explanation":"True but off-goal: it states when the press was built, not how it changed production speed."},{"id":"B","text":"Before the press, books were copied by hand slowly, but the press allowed books to be made much faster.","is_correct":true,"explanation":"Correct: it contrasts the slow hand-copying with the faster press, directly addressing speed."},{"id":"C","text":"Gutenberg''s printing press used movable metal type to print pages.","is_correct":false,"explanation":"True but irrelevant: it describes the mechanism, not the change in speed."},{"id":"D","text":"The printing press allowed books to be made in greater numbers than before.","is_correct":false,"explanation":"Partly relevant but focuses on quantity, not the change in speed the goal asks for."}]'::jsonb, 'B', 'Step 1 — Find the speed clue
The notes say books were once {{yellow:copied by hand, which was slow}} and the press let books be made faster.
Step 2 — Match the goal
Choice B contrasts slow hand-copying with the faster press, directly explaining the change in speed.
Distractor analysis:
- A: Gives the date, not the change in production speed.
- C: Describes the movable type mechanism, not speed.
- D: Focuses on greater numbers (quantity), not speed.', 'Find the choice that contrasts the old slow method with the new faster one.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('14b57c32-3c61-46bb-a308-55070aba57c6', 'The student wants to highlight how many marine species depend on coral reefs. Which choice most effectively uses information from the notes to accomplish this goal?', 'Coral Reefs as Habitats
- Coral reefs cover less than one percent of the ocean floor.
- They are home to about 25 percent of all marine species.
- Reefs provide food and shelter for fish.
- Many reefs are found in warm, shallow waters.', NULL, '[{"id":"A","text":"Coral reefs are often found in warm, shallow ocean waters.","is_correct":false,"explanation":"True but irrelevant: it describes where reefs are located, not how many species rely on them."},{"id":"B","text":"Coral reefs cover less than one percent of the ocean floor.","is_correct":false,"explanation":"True but off-goal: it stresses how little area reefs cover, not the species that depend on them."},{"id":"C","text":"Coral reefs are home to about 25 percent of all marine species.","is_correct":true,"explanation":"Correct: it states the share of marine species living in reefs, highlighting how many depend on them."},{"id":"D","text":"Coral reefs provide both food and shelter for many fish.","is_correct":false,"explanation":"Partly relevant but names only fish, not the broad number of marine species."}]'::jsonb, 'C', 'Step 1 — Find the species clue
The notes say reefs are {{yellow:home to about 25 percent of all marine species}}.
Step 2 — Match the goal
Choice C reports that one quarter of marine species live in reefs, highlighting how many depend on them.
Distractor analysis:
- A: Describes the reefs'' location, not the dependent species.
- B: Emphasizes the small area reefs cover, not species numbers.
- D: Mentions only fish, not the full share of marine species.', 'Look for the percentage of marine species that live in reefs.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('08445c3a-f7f8-4734-8274-2ea5aa14640c', 'The student wants to describe the main purpose of the Underground Railroad. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Underground Railroad
- The Underground Railroad was a network of secret routes and safe houses.
- It helped enslaved people escape to free states and Canada.
- Harriet Tubman led many people to freedom along these routes.
- The network was active mainly in the early to mid-1800s.', NULL, '[{"id":"A","text":"The Underground Railroad was a network of secret routes that helped enslaved people escape to free states and Canada.","is_correct":true,"explanation":"Correct: it states the network''s purpose of helping enslaved people escape to freedom."},{"id":"B","text":"The Underground Railroad was active mainly during the early to mid-1800s.","is_correct":false,"explanation":"True but off-goal: it gives the time period, not the purpose."},{"id":"C","text":"Harriet Tubman led many people to freedom along the Underground Railroad''s routes.","is_correct":false,"explanation":"True but narrow: it focuses on one leader, not the network''s overall purpose."},{"id":"D","text":"The Underground Railroad used secret routes and safe houses across the country.","is_correct":false,"explanation":"Partly relevant but describes the means, not the purpose of escape to freedom."}]'::jsonb, 'A', 'Step 1 — Find the purpose clue
The notes say the network {{yellow:helped enslaved people escape to free states and Canada}}.
Step 2 — Match the goal
Choice A names that purpose directly, describing what the Underground Railroad was for.
Distractor analysis:
- B: Gives the time period, not the purpose.
- C: Focuses on Harriet Tubman, not the network''s overall aim.
- D: Describes routes and safe houses (means), not the purpose.', 'Find the choice that says what the network was meant to do.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f0884d2f-1479-4694-9ec8-d1c35af3a5dd', 'The student wants to explain why fireflies produce light. Which choice most effectively uses information from the notes to accomplish this goal?', 'Bioluminescent Organisms
- Some organisms can produce their own light through a chemical reaction.
- This ability is called bioluminescence.
- Fireflies use light to attract mates.
- Certain deep-sea fish use light to lure prey.', NULL, '[{"id":"A","text":"Fireflies produce light through a chemical reaction inside their bodies.","is_correct":false,"explanation":"True but off-goal: it explains how fireflies make light, not why they do."},{"id":"B","text":"Fireflies use their light to attract mates.","is_correct":true,"explanation":"Correct: it states the reason fireflies produce light, matching the goal."},{"id":"C","text":"Certain deep-sea fish use their light to lure prey.","is_correct":false,"explanation":"True but irrelevant: it concerns deep-sea fish, not fireflies."},{"id":"D","text":"The ability to produce light is called bioluminescence.","is_correct":false,"explanation":"True but off-goal: it defines the term rather than giving the fireflies'' reason."}]'::jsonb, 'B', 'Step 1 — Find the reason clue
The notes say {{yellow:Fireflies use light to attract mates}}.
Step 2 — Match the goal
Choice B reports that fireflies'' light attracts mates, explaining why they produce it.
Distractor analysis:
- A: Explains how (chemical reaction), not why.
- C: Discusses deep-sea fish, not fireflies.
- D: Defines bioluminescence rather than giving the reason.', 'Look for the choice that names what fireflies'' light is for.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('1ebf3c31-959d-49dd-9910-2c5b0a84b711', 'The student wants to emphasize how few of Dickinson''s poems were published during her life. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Poet Emily Dickinson
- Emily Dickinson lived in Amherst, Massachusetts, in the 1800s.
- She wrote nearly 1,800 poems during her lifetime.
- Fewer than a dozen of her poems were published while she was alive.
- Most of her work became famous only after her death.', NULL, '[{"id":"A","text":"Emily Dickinson lived in Amherst, Massachusetts, during the 1800s.","is_correct":false,"explanation":"True but irrelevant: it states where she lived, not how few poems were published."},{"id":"B","text":"Emily Dickinson wrote nearly 1,800 poems during her lifetime.","is_correct":false,"explanation":"True but off-goal: it counts her total output, not the few that were published."},{"id":"C","text":"Although Dickinson wrote nearly 1,800 poems, fewer than a dozen were published while she was alive.","is_correct":true,"explanation":"Correct: it contrasts her large output with the few published, emphasizing how few appeared in her lifetime."},{"id":"D","text":"Most of Dickinson''s work became famous only after her death.","is_correct":false,"explanation":"True but off-goal: it stresses later fame, not the number published during her life."}]'::jsonb, 'C', 'Step 1 — Find the publication clue
The notes say {{yellow:Fewer than a dozen of her poems were published while she was alive}}.
Step 2 — Match the goal
Choice C sets her nearly 1,800 poems against the fewer than a dozen published, emphasizing how few were published during her life.
Distractor analysis:
- A: States her hometown, not publication numbers.
- B: Counts her total poems, not the few published.
- D: Emphasizes posthumous fame, not the few published in life.', 'Find the choice that highlights the very small number published while she lived.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'easy', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
