INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('be4a22e0-fc28-443e-8f7b-20cb2e3abe94', 'The student wants to explain how the printing press affected book ownership. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Spread of the Printing Press
- Johannes Gutenberg introduced movable-type printing to Europe around 1440.
- Before the press, books were copied by hand, a slow and costly process.
- Within fifty years, printing presses operated in over 250 European cities.
- The lower cost of printed books allowed more people to own and read them.
- Rising literacy contributed to the rapid spread of new ideas.', NULL, '[{"id":"A","text":"Johannes Gutenberg introduced movable-type printing to Europe around 1440.","is_correct":false,"explanation":"This gives the origin date but says nothing about book ownership."},{"id":"B","text":"Because printed books cost less than hand-copied ones, more people were able to own and read them.","is_correct":true,"explanation":"This connects the lower cost to increased ownership, matching the goal."},{"id":"C","text":"Within fifty years, printing presses operated in over 250 European cities.","is_correct":false,"explanation":"This describes the spread of presses, not the effect on ownership."},{"id":"D","text":"Rising literacy contributed to the rapid spread of new ideas across Europe.","is_correct":false,"explanation":"This addresses literacy and ideas, not book ownership specifically."}]'::jsonb, 'B', 'Step 1 — Find the ownership link
The notes state that {{yellow:The lower cost of printed books allowed more people to own and read them}}.
Step 2 — Match the goal
Choice B contrasts printed and hand-copied cost to explain increased ownership.
Distractor analysis:
- A: Gives origin date, not ownership effects.
- C: Describes spread of presses, not ownership.
- D: Focuses on literacy and ideas, not ownership.', 'The goal is about who could own books, so the answer must mention ownership.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('add6fc1c-76a3-4cf2-93cb-a7c01a8211e2', 'The student wants to describe the restoration method scientists are using. Which choice most effectively uses information from the notes to accomplish this goal?', 'Coral Reef Restoration
- Coral reefs support roughly a quarter of all marine species.
- Warming oceans cause corals to expel the algae that give them color and food.
- This expulsion, called bleaching, can kill corals if it lasts too long.
- Scientists are growing heat-resistant corals in underwater nurseries.
- These nurseries are then transplanted onto damaged reefs to help them recover.', NULL, '[{"id":"A","text":"Coral reefs support roughly a quarter of all marine species despite covering little ocean area.","is_correct":false,"explanation":"The area detail is unsupported, and this describes importance, not the restoration method."},{"id":"B","text":"Bleaching occurs when warming oceans cause corals to expel their algae.","is_correct":false,"explanation":"This explains the threat, not the restoration method."},{"id":"C","text":"Scientists grow heat-resistant corals in underwater nurseries and then transplant them onto damaged reefs to aid recovery.","is_correct":true,"explanation":"This synthesizes the nursery and transplant steps to describe the method."},{"id":"D","text":"Corals expel the algae that give them color, which can kill them if it lasts too long.","is_correct":false,"explanation":"This describes bleaching''s danger, not the restoration approach."}]'::jsonb, 'C', 'Step 1 — Locate the method
The notes say scientists are {{yellow:growing heat-resistant corals in underwater nurseries}} and that {{yellow:These nurseries are then transplanted onto damaged reefs to help them recover}}.
Step 2 — Match the goal
Choice C joins both steps to describe the restoration method.
Distractor analysis:
- A: Adds an unsupported area claim and discusses importance.
- B: Explains bleaching, not the method.
- D: Describes the threat, not restoration.', 'The goal is the method, so look for what scientists actually do to restore reefs.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('f6ccaf5a-3061-41a6-9d39-aa7a0cc5a4e4', 'The student wants to highlight the contrast between Dickinson''s published output during her life and what was found afterward. Which choice most effectively uses information from the notes to accomplish this goal?', 'Emily Dickinson''s Manuscripts
- The poet Emily Dickinson lived in Amherst, Massachusetts, in the nineteenth century.
- She published fewer than a dozen poems during her lifetime.
- After her death, nearly 1,800 poems were found among her papers.
- Many were bound by hand into small booklets called fascicles.
- Editors later altered her unusual punctuation and capitalization for early printings.', NULL, '[{"id":"A","text":"Emily Dickinson lived in Amherst, Massachusetts, during the nineteenth century.","is_correct":false,"explanation":"This gives biographical setting but no contrast in output."},{"id":"B","text":"Although Dickinson published fewer than a dozen poems in her lifetime, nearly 1,800 were found among her papers after her death.","is_correct":true,"explanation":"This directly contrasts the small lifetime output with the large posthumous discovery."},{"id":"C","text":"Editors later altered Dickinson''s unusual punctuation and capitalization for early printings.","is_correct":false,"explanation":"This concerns editorial changes, not the output contrast."},{"id":"D","text":"Many of Dickinson''s poems were bound by hand into small booklets called fascicles.","is_correct":false,"explanation":"This describes the fascicles, not the contrast in output."}]'::jsonb, 'B', 'Step 1 — Find the two quantities
The notes state she {{yellow:published fewer than a dozen poems during her lifetime}} while after her death {{yellow:nearly 1,800 poems were found among her papers}}.
Step 2 — Match the goal
Choice B juxtaposes the small published number with the large found number.
Distractor analysis:
- A: Biographical setting, no contrast.
- C: Editorial alterations, not output.
- D: Describes fascicles, not the contrast.', 'The goal needs both numbers, what she published and what was found, in contrast.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('4ae9efe7-e35d-4cc1-8e39-ecbcc2cb584c', 'The student wants to explain the engineering principle that kept water moving through the aqueducts. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Roman Aqueducts
- Ancient Rome relied on aqueducts to bring water from distant sources into the city.
- The aqueducts used a gentle, continuous downward slope to keep water flowing.
- Engineers built arched bridges to carry channels across valleys.
- The system delivered enough water for public baths, fountains, and homes.
- Some aqueducts stretched for more than fifty miles.', NULL, '[{"id":"A","text":"Some Roman aqueducts stretched for more than fifty miles to reach the city.","is_correct":false,"explanation":"This gives length, not the principle that kept water moving."},{"id":"B","text":"The aqueducts relied on a gentle, continuous downward slope to keep water flowing toward the city.","is_correct":true,"explanation":"This identifies the slope as the principle that kept water moving, matching the goal."},{"id":"C","text":"The system delivered enough water for public baths, fountains, and homes.","is_correct":false,"explanation":"This describes what the water supplied, not the engineering principle."},{"id":"D","text":"Engineers built arched bridges to carry water channels across valleys.","is_correct":false,"explanation":"Arched bridges are a structure, not the principle keeping water flowing."}]'::jsonb, 'B', 'Step 1 — Identify the principle
The notes state the aqueducts {{yellow:used a gentle, continuous downward slope to keep water flowing}}.
Step 2 — Match the goal
Choice B names the slope as what kept water moving.
Distractor analysis:
- A: Gives length, not the principle.
- C: Describes uses of the water.
- D: Describes bridges, a structure rather than the flow principle.', 'The goal is the principle that kept water moving, so look for what caused the flow.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6fcf614f-d98a-4097-ba5d-d8edeab88f47', 'The student wants to explain how horse domestication increased human mobility. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Domestication of the Horse
- Horses were first domesticated on the grasslands of Central Asia thousands of years ago.
- Early domesticated horses were smaller than many modern breeds.
- Domestication allowed people to travel farther and faster than on foot.
- Horses also let herders manage larger flocks across wide territories.
- This mobility transformed trade and warfare among early societies.', NULL, '[{"id":"A","text":"Horses were first domesticated on the grasslands of Central Asia thousands of years ago.","is_correct":false,"explanation":"This gives the location and timing, not the mobility effect."},{"id":"B","text":"Early domesticated horses were smaller than many modern breeds.","is_correct":false,"explanation":"This describes size, irrelevant to mobility."},{"id":"C","text":"By domesticating horses, people could travel farther and faster than on foot and manage larger flocks across wide territories.","is_correct":true,"explanation":"This combines two mobility benefits to explain how domestication increased mobility."},{"id":"D","text":"This new mobility transformed trade and warfare among early societies.","is_correct":false,"explanation":"This states a consequence of mobility rather than how domestication increased it."}]'::jsonb, 'C', 'Step 1 — Find the mobility gains
The notes say domestication allowed people to {{yellow:travel farther and faster than on foot}} and to {{yellow:manage larger flocks across wide territories}}.
Step 2 — Match the goal
Choice C synthesizes both to explain increased mobility.
Distractor analysis:
- A: Location and timing, not mobility.
- B: Size detail, irrelevant.
- D: A downstream consequence, not how mobility increased.', 'The goal is how mobility increased, so look for travel and range benefits.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('96e2abd7-a7bc-457b-9408-2c68a66631cf', 'The student wants to emphasize why the monarchs'' navigation is especially remarkable. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Mystery of Migrating Monarchs
- Monarch butterflies in eastern North America migrate thousands of miles to Mexico each fall.
- No single butterfly completes the entire round trip.
- It takes several generations to return north the following spring.
- The butterflies that fly south have never visited their winter destination.
- Scientists believe the monarchs navigate using the sun and an internal sense of time.', NULL, '[{"id":"A","text":"Monarch butterflies migrate thousands of miles to Mexico each fall using the sun.","is_correct":false,"explanation":"This notes the distance and the sun but omits the striking fact that the butterflies have never been there before."},{"id":"B","text":"It takes several generations for the monarchs to return north the following spring.","is_correct":false,"explanation":"This describes the return journey, not why the navigation is remarkable."},{"id":"C","text":"Remarkably, the butterflies that fly south navigate to a winter destination they have never visited before.","is_correct":true,"explanation":"This pairs navigation with the fact that the butterflies have never been there, emphasizing the wonder."},{"id":"D","text":"Scientists believe the monarchs navigate using the sun and an internal sense of time.","is_correct":false,"explanation":"This states the method but not what makes it remarkable."}]'::jsonb, 'C', 'Step 1 — Find the remarkable detail
The notes state that {{yellow:The butterflies that fly south have never visited their winter destination}}.
Step 2 — Match the goal
Choice C links navigating to a place never visited, conveying why the feat is remarkable.
Distractor analysis:
- A: Mentions distance and sun but omits the never-visited fact.
- B: Describes the return trip.
- D: States the method, not the wonder.', 'The goal is what makes the navigation astonishing, so find the surprising fact about the route.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('38db5253-9966-42fe-ad01-7cfd7999c7b0', 'The student wants to explain how Braille improved upon the military code. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Invention of Braille
- Louis Braille lost his sight in a childhood accident in early-nineteenth-century France.
- As a student, he learned of a military code using raised dots read by touch.
- The military code was too complex for quick reading.
- Braille simplified the system into a six-dot cell representing each letter.
- His system let blind readers read and write efficiently for the first time.', NULL, '[{"id":"A","text":"Louis Braille lost his sight in a childhood accident in early-nineteenth-century France.","is_correct":false,"explanation":"This gives biographical background, not the improvement on the code."},{"id":"B","text":"Because the military code was too complex for quick reading, Braille simplified it into a six-dot cell representing each letter.","is_correct":true,"explanation":"This contrasts the code''s complexity with Braille''s simpler six-dot cell, explaining the improvement."},{"id":"C","text":"As a student, Braille learned of a military code using raised dots read by touch.","is_correct":false,"explanation":"This states the source but not how he improved it."},{"id":"D","text":"Braille''s system let blind readers read and write efficiently for the first time.","is_correct":false,"explanation":"This describes the outcome but not the comparison to the military code."}]'::jsonb, 'B', 'Step 1 — Find the flaw and the fix
The notes state the military code {{yellow:was too complex for quick reading}} and that Braille {{yellow:simplified the system into a six-dot cell representing each letter}}.
Step 2 — Match the goal
Choice B contrasts the complex code with the simpler cell, showing the improvement.
Distractor analysis:
- A: Biographical background only.
- C: Names the source without the improvement.
- D: States the result, not the comparison.', 'The goal compares Braille''s system to the military code, so include both.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('65db921a-9de2-4623-bbac-1f159a963d42', 'The student wants to explain why people continue to farm near active volcanoes despite the danger. Which choice most effectively uses information from the notes to accomplish this goal?', 'Volcanic Soil and Agriculture
- Volcanic eruptions can devastate nearby farms in the short term.
- Over time, volcanic ash breaks down into highly fertile soil.
- This soil is rich in minerals such as potassium and phosphorus.
- Crops grown in volcanic soil often produce high yields.
- As a result, many people farm on the slopes of active volcanoes.', NULL, '[{"id":"A","text":"Volcanic eruptions can devastate nearby farms in the short term.","is_correct":false,"explanation":"This states only the danger, not the reason people farm there anyway."},{"id":"B","text":"Volcanic ash is rich in minerals such as potassium and phosphorus.","is_correct":false,"explanation":"This names minerals but does not connect them to why people farm despite danger."},{"id":"C","text":"Despite the danger of eruptions, people farm near active volcanoes because volcanic ash forms fertile soil that produces high crop yields.","is_correct":true,"explanation":"This pairs the danger with the fertile soil and high yields, explaining the motivation."},{"id":"D","text":"Many people farm on the slopes of active volcanoes.","is_correct":false,"explanation":"This states the behavior without explaining the reason behind it."}]'::jsonb, 'C', 'Step 1 — Find the danger and the payoff
The notes say eruptions {{yellow:can devastate nearby farms in the short term}} yet {{yellow:Crops grown in volcanic soil often produce high yields}}.
Step 2 — Match the goal
Choice C joins the danger with the fertile, high-yield soil to explain why people farm there.
Distractor analysis:
- A: States only the danger.
- B: Names minerals without the motivation link.
- D: States the behavior without the reason.', 'The goal needs both the danger and the benefit that outweighs it.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('6eebe218-eaa7-4246-9b40-a83dcaf95196', 'The student wants to emphasize the accidental nature of the discovery. Which choice most effectively uses information from the notes to accomplish this goal?', 'The Discovery of Penicillin
- In 1928, Alexander Fleming was studying bacteria in his laboratory.
- He noticed that a mold had accidentally contaminated one of his bacterial dishes.
- The bacteria near the mold had been killed.
- The mold produced a substance Fleming named penicillin.
- Penicillin later became one of the first widely used antibiotics.', NULL, '[{"id":"A","text":"Penicillin later became one of the first widely used antibiotics.","is_correct":false,"explanation":"This describes penicillin''s later importance, not the accidental discovery."},{"id":"B","text":"Fleming discovered penicillin when he noticed that a mold had accidentally contaminated a dish and killed the nearby bacteria.","is_correct":true,"explanation":"This stresses the accidental contamination and the killed bacteria, capturing the unplanned discovery."},{"id":"C","text":"In 1928, Alexander Fleming was studying bacteria in his laboratory.","is_correct":false,"explanation":"This sets the scene but omits the accident itself."},{"id":"D","text":"The mold produced a substance Fleming named penicillin.","is_correct":false,"explanation":"This states the naming but not the accidental discovery."}]'::jsonb, 'B', 'Step 1 — Find the accident
The notes state that {{yellow:a mold had accidentally contaminated one of his bacterial dishes}} and that {{yellow:The bacteria near the mold had been killed}}.
Step 2 — Match the goal
Choice B foregrounds the accidental contamination and its effect, emphasizing chance.
Distractor analysis:
- A: Describes later importance, not the accident.
- B is correct.
- C: Sets the scene without the accident.
- D: States the naming, not the accidental nature.', 'The goal stresses that the discovery was unplanned, so look for the word accidentally and its result.', 'Expression of Ideas', 'Rhetorical Synthesis', 'reading_writing', 'expression', 'SYN', NULL, 'medium', false, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_ai_v1","model":"gemma-4-26b-a4b-it","original":true,"explanation_v2":true}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
COMMIT;
